def _get_data_root() -> Path:
    raw = (os.environ.get("EIDAT_DATA_ROOT") or "").strip()
    if not raw:
        return ROOT
    try:
        p = Path(raw).expanduser()
        if not p.is_absolute():
            p = ROOT / p
        return p.resolve()
    except Exception:
        return Path(raw).expanduser().absolute()


