def parse_scanner_env(path: Path = SCANNER_ENV) -> Dict[str, str]:
    env: Dict[str, str] = {}
    try:
        if not path.exists():
            return env
        for raw in path.read_text(encoding="utf-8", errors="ignore").splitlines():
            line = raw.strip()
            if not line or line.startswith("#") or line.startswith(";"):
                continue
            if "=" not in line:
                continue
            k, v = line.split("=", 1)
            k = k.strip()
            v = v.strip()
            if "#" in v:
                v = v.split("#", 1)[0].strip()
            if ";" in v:
                v = v.split(";", 1)[0].strip()
            if not k:
                continue
            if v == "":
                continue
            env[k] = v
    except Exception:
        pass
    return env


def project_scanner_env_path(project_dir: Path) -> Path:
    return Path(project_dir).expanduser() / PROJECT_SCANNER_ENV_NAME


def load_project_scanner_env(project_dir: Path) -> Dict[str, str]:
    """Load per-project overrides from `<project>/scanner.project.env` (if present)."""
    return parse_scanner_env(project_scanner_env_path(project_dir))


def delete_project_scanner_env(project_dir: Path) -> None:
    """Delete the per-project env override file, if it exists."""
    p = project_scanner_env_path(project_dir)
    try:
        if p.exists():
            p.unlink()
    except Exception:
        pass


def load_scanner_env(project_dir: Optional[Path] = None) -> Dict[str, str]:
    """Load effective scanner config from all supported env files (last wins)."""
    env: Dict[str, str] = {}
    # Precedence (last wins):
    #   1) Legacy user_inputs/ocr_force.env (deprecated; fallback only)
    #   2) user_inputs/scanner.env (shared template/docs)
    #   3) user_inputs/scanner.local.env (machine-specific overrides)
    #   4) repo-local .env overrides (DATA_ROOT/.env, DATA_ROOT/user_inputs/.env)
    #   5) per-project overrides (<project>/scanner.project.env)
    env.update(parse_scanner_env(OCR_FORCE_ENV))
    env.update(parse_scanner_env(SCANNER_ENV))
    env.update(parse_scanner_env(SCANNER_ENV_LOCAL))
    for path in DOTENV_FILES:
        env.update(parse_scanner_env(path))
    if project_dir:
        env.update(load_project_scanner_env(Path(project_dir)))
    # Remove deprecated force flags (no longer used)
    for key in (
        "EIDAT_FORCE_NUMERIC_RESCUE",
        "EIDAT_FORCE_NUMERIC_STRICT",
        "EIDAT_FORCE_CELL_INTERIOR",
    ):
        env.pop(key, None)
    return env


def _env_truthy(val: object) -> bool:
    if val is None:
        return False
    s = str(val).strip().lower()
    if not s:
        return False
    return s in {"1", "true", "yes", "on", "enable", "enabled"}


def save_scanner_env(
    env_map: Dict[str, str],
    path: Path = SCANNER_ENV_LOCAL,
    *,
    order: Optional[list[str]] = None,
    header_lines: Optional[list[str]] = None,
) -> None:
    if order is None:
        order = [
        "QUIET",
        "force_background_processes",
        "REPO_ROOT",
        "EIDAT_TRENDING_COMBINED_ONLY",
        "OCR_MODE",
        "OCR_DPI",
        "FORCE_OCR",
        "XY_LOG",
        "OCR_ROW_EPS",
        "VENV_DIR",
        ]
    if header_lines is None:
        header_lines = [
            "# Scanner configuration (KEY=VALUE)",
            "# Edited via new GUI",
            "# EIDAT_TRENDING_COMBINED_ONLY=1 forces trending extraction to use combined.txt only",
        ]

    # Normalize input (preserve original key case for new lines)
    env_norm: dict[str, tuple[str, str]] = {}
    for k, v in (env_map or {}).items():
        k_raw = str(k or "").strip()
        v_raw = str(v or "").strip()
        if not k_raw or not v_raw:
            continue
        env_norm[k_raw.upper()] = (k_raw, v_raw)

    path.parent.mkdir(parents=True, exist_ok=True)

    existing_lines: list[str] = []
    try:
        if path.exists():
            existing_lines = path.read_text(encoding="utf-8", errors="ignore").splitlines()
    except Exception:
        existing_lines = []

    if existing_lines:
        seen: set[str] = set()
        new_lines: list[str] = []
        for line in existing_lines:
            stripped = line.strip()
            if not stripped or stripped.startswith("#") or stripped.startswith(";") or "=" not in line:
                new_lines.append(line)
                continue
            k_raw, _ = line.split("=", 1)
            k_key = k_raw.strip()
            if not k_key:
                new_lines.append(line)
                continue
            k_norm = k_key.upper()
            if k_norm in env_norm:
                new_lines.append(f"{k_key}={env_norm[k_norm][1]}")
                seen.add(k_norm)
            else:
                new_lines.append(line)

        # Append any missing keys in preferred order, then remaining keys.
        for k in order:
            k_norm = k.upper()
            if k_norm in env_norm and k_norm not in seen:
                new_lines.append(f"{k}={env_norm[k_norm][1]}")
                seen.add(k_norm)
        for k_norm, (k_raw, v_raw) in sorted(env_norm.items(), key=lambda kv: kv[0]):
            if k_norm in seen:
                continue
            new_lines.append(f"{k_raw}={v_raw}")
            seen.add(k_norm)

        path.write_text("\n".join(new_lines) + "\n", encoding="utf-8")
        return

    # No existing file: create a clean template with defaults ordering.
    lines = list(header_lines or [])
    written = set()
    for k in order:
        k_norm = k.upper()
        if k_norm in env_norm:
            lines.append(f"{k}={env_norm[k_norm][1]}")
            written.add(k_norm)
    for k_norm, (k_raw, v_raw) in sorted(env_norm.items(), key=lambda kv: kv[0]):
        if k_norm in written:
            continue
        lines.append(f"{k_raw}={v_raw}")
    path.write_text("\n".join(lines) + "\n", encoding="utf-8")


def save_project_scanner_env(env_map: Dict[str, str], project_dir: Path) -> Path:
    """
    Save per-project overrides into `<project>/scanner.project.env`.

    This file is intended to hold only overrides that apply to that project (last-wins vs scanner.env).
    """
    proj_dir = Path(project_dir).expanduser()
    p = project_scanner_env_path(proj_dir)
    save_scanner_env(
        env_map,
        path=p,
        order=[
            "EIDAT_TRENDING_COMBINED_ONLY",
            "EIDAT_FUZZY_HEADER_STICK",
            "EIDAT_FUZZY_HEADER_MIN_RATIO",
            "EIDAT_FUZZY_TERM_STICK",
            "EIDAT_FUZZY_TERM_MIN_RATIO",
        ],
        header_lines=[
            "# Project scanner overrides (KEY=VALUE)",
            "# This file overrides user_inputs/scanner.env + user_inputs/scanner.local.env for THIS project only.",
            "# Delete this file to revert to inherited scanner.env values.",
        ],
    )
    return p


def get_repo_root() -> Path:
    """Return repository root from node env, scanner env, or DEFAULT_REPO_ROOT."""
    ensure_repo_root_name_file()
    node_root = (os.environ.get("EIDAT_NODE_ROOT") or "").strip()
    if node_root:
        # In node mode the active repository is always the node root. Node-local
        # `.env` files may be seeded from a shared runtime config and can contain
        # a stale REPO_ROOT that must not override the live node binding.
        try:
            return Path(node_root).expanduser().resolve()
        except Exception:
            return Path(node_root).expanduser().absolute()
    # Repo root is a global setting, not tied to any specific workbook/project.
    env = load_scanner_env()
    val = env.get("REPO_ROOT", "").strip()
    try:
        if val:
            p = Path(val).expanduser()
            if not p.is_absolute():
                p = ROOT / p
            return p
    except Exception:
        pass
    return DEFAULT_REPO_ROOT


def set_repo_root(p: Path) -> None:
    _validate_repo_root_name()
    target = Path(p).expanduser()
    if not target.is_absolute():
        target = ROOT / target
    env = parse_scanner_env(SCANNER_ENV_LOCAL)
    try:
        if DATA_ROOT != ROOT:
            env["REPO_ROOT"] = str(target.resolve())
        else:
            rel = target.resolve().relative_to(ROOT.resolve())
            env["REPO_ROOT"] = str(rel)
    except Exception:
        env["REPO_ROOT"] = str(target)
    save_scanner_env(env, path=SCANNER_ENV_LOCAL)


_WINDOWS_RESERVED_NAMES = {
    "CON",
    "PRN",
    "AUX",
    "NUL",
    *(f"COM{i}" for i in range(1, 10)),
    *(f"LPT{i}" for i in range(1, 10)),
}


def _safe_windows_path_name(value: object, *, fallback: str = "Untitled") -> str:
    raw = str(value or "").replace("\t", " ").replace("\r", " ").replace("\n", " ").strip()
    cleaned = "".join((" " if ch in '<>:"/\\|?*' else ch) for ch in raw)
    cleaned = re.sub(r"\s+", " ", cleaned).strip(" .")
    if not cleaned:
        cleaned = str(fallback or "Untitled").strip() or "Untitled"
    if cleaned.upper() in _WINDOWS_RESERVED_NAMES:
        cleaned = f"{cleaned}_"
    return cleaned


def edin_program_folder_name(program_title: object, *, fallback: str = "Unknown Program") -> str:
    return _safe_windows_path_name(program_title, fallback=fallback)


def edin_program_folders_root(global_repo: Path | None = None) -> Path:
    repo = Path(global_repo or get_repo_root()).expanduser()
    if not repo.is_absolute():
        repo = (ROOT / repo).expanduser()
    return repo / EDIN_PROGRAM_FOLDERS_DIRNAME


_EIDAT_CONTAINER_DIR_NAMES = ("EIDAT", "EDAT")
_EIDAT_SUPPORT_DIR_NAMES = ("EIDAT Support", "EDAT Support")
_EIDAT_SUPPORT_MAX_DEPTH = 5


def _candidate_eidat_support_dirs(global_repo: Path) -> list[Path]:
    repo = Path(global_repo).expanduser()
    candidates: list[Path] = []
    seen: set[str] = set()

    def _append(path: Path) -> None:
        key = str(path).casefold()
        if key in seen:
            return
        seen.add(key)
        candidates.append(path)

    for support_name in _EIDAT_SUPPORT_DIR_NAMES:
        _append(repo / support_name)

    chain_bases = [repo]
    for _ in range(_EIDAT_SUPPORT_MAX_DEPTH):
        next_bases: list[Path] = []
        for base in chain_bases:
            for dirname in _EIDAT_CONTAINER_DIR_NAMES:
                child = base / dirname
                next_bases.append(child)
                for support_name in _EIDAT_SUPPORT_DIR_NAMES:
                    _append(child / support_name)
        chain_bases = next_bases
    return candidates


def _default_eidat_support_dir(global_repo: Path) -> Path:
    repo = Path(global_repo).expanduser()
    deepest_base = repo
    chain_bases = [repo]
    for _ in range(_EIDAT_SUPPORT_MAX_DEPTH):
        next_bases: list[Path] = []
        for base in chain_bases:
            for dirname in _EIDAT_CONTAINER_DIR_NAMES:
                child = base / dirname
                try:
                    if child.is_dir():
                        next_bases.append(child)
                except Exception:
                    continue
        if not next_bases:
            break
        deepest_base = max(next_bases, key=lambda path: (len(path.parts), str(path).casefold()))
        chain_bases = next_bases
    return deepest_base / _EIDAT_SUPPORT_DIR_NAMES[0]


def _eidat_support_dir_score(path: Path) -> tuple[int, int]:
    score = 0
    markers = (
        ("eidat_index.sqlite3", 12),
        ("eidat_support.sqlite3", 12),
        ("projects/projects_registry.sqlite3", 10),
        (TD_SERIAL_SOURCES_DIRNAME, 4),
        ("projects", 3),
        ("debug/ocr", 3),
        ("excel_sqlite", 2),
        ("logs", 1),
        ("staging", 1),
    )
    for rel_path, weight in markers:
        try:
            if (path / rel_path).exists():
                score += weight
        except Exception:
            continue
    return score, len(path.parts)


def _first_support_segment_index(parts: Sequence[object]) -> int | None:
    names = {name.casefold() for name in _EIDAT_SUPPORT_DIR_NAMES}
    for idx, part in enumerate(parts):
        if str(part or "").strip().casefold() in names:
            return idx
    return None


def _node_root_from_support_dir(support_dir: Path) -> Path:
    cur = Path(support_dir).expanduser()
    if cur.name.strip().casefold() in {name.casefold() for name in _EIDAT_SUPPORT_DIR_NAMES}:
        cur = cur.parent
    while cur.name.strip().casefold() in {name.casefold() for name in _EIDAT_CONTAINER_DIR_NAMES}:
        cur = cur.parent
    return cur


def _read_index_program_titles(global_repo: Path) -> list[str]:
    repo = Path(global_repo).expanduser()
    db_path = eidat_support_dir(repo) / "eidat_index.sqlite3"
    if not db_path.exists():
        return []
    with closing(sqlite3.connect(str(db_path))) as conn:
        conn.row_factory = sqlite3.Row
        docs_table = conn.execute(
            "SELECT name FROM sqlite_master WHERE type='table' AND name='documents'"
        ).fetchone()
        if docs_table is None:
            return []
        rows = conn.execute(
            """
            SELECT DISTINCT TRIM(program_title) AS program_title
            FROM documents
            WHERE TRIM(COALESCE(program_title, '')) <> ''
            ORDER BY LOWER(TRIM(program_title)), TRIM(program_title)
            """
        ).fetchall()
    return [str(row["program_title"]).strip() for row in rows if str(row["program_title"] or "").strip()]


def _fallback_eidat_program_titles(global_repo: Path) -> list[str]:
    support_dir = eidat_support_dir(global_repo)
    titles: list[str] = []
    seen: set[str] = set()
    candidate_patterns: list[tuple[Path, tuple[str, ...]]] = [
        (
            support_dir / UI_VISIBLE_FILES_DIRNAME,
            (
                "*/metadata.json",
                "*/*/metadata.json",
                "*/*/*/metadata.json",
                "*/*/*/*/metadata.json",
                "*/*/*/*/*/metadata.json",
            ),
        ),
        (
            support_dir / "debug" / "ocr",
            (
                "*/*_metadata.json",
                "*/*.metadata.json",
                "*/metadata.json",
            ),
        ),
        (
            support_dir / "projects",
            (
                "*/project.json",
            ),
        ),
    ]
    for root, patterns in candidate_patterns:
        try:
            if not root.exists():
                continue
        except Exception:
            continue
        for pattern in patterns:
            try:
                paths = sorted(root.glob(pattern))
            except Exception:
                paths = []
            for path in paths:
                try:
                    if not path.is_file():
                        continue
                    payload = json.loads(path.read_text(encoding="utf-8"))
                except Exception:
                    continue
                title = str((payload or {}).get("program_title") or "").strip()
                if not title or title.casefold() in seen:
                    continue
                seen.add(title.casefold())
                titles.append(title)
    return sorted(titles, key=lambda value: value.casefold())


def list_eidat_program_titles(global_repo: Path | None = None) -> list[str]:
    repo = Path(global_repo or get_repo_root()).expanduser()
    try:
        titles = _read_index_program_titles(repo)
    except Exception:
        titles = []
    if titles:
        return titles
    return _fallback_eidat_program_titles(repo)


def sync_edin_program_folders(global_repo: Path | None = None) -> dict[str, object]:
    repo = Path(global_repo or get_repo_root()).expanduser()
    root = edin_program_folders_root(repo)
    root.mkdir(parents=True, exist_ok=True)

    titles = list_eidat_program_titles(repo)
    programs: list[dict[str, str]] = []
    created_program_dirs = 0
    created_report_dirs = 0
    for title in titles:
        folder_name = edin_program_folder_name(title)
        program_dir = root / folder_name
        reports_dir = program_dir / EDIN_PROGRAM_REPORTS_DIRNAME
        if not program_dir.exists():
            program_dir.mkdir(parents=True, exist_ok=True)
            created_program_dirs += 1
        if not reports_dir.exists():
            reports_dir.mkdir(parents=True, exist_ok=True)
            created_report_dirs += 1
        programs.append(
            {
                "program_title": title,
                "folder_name": folder_name,
                "program_dir": str(program_dir),
                "reports_dir": str(reports_dir),
            }
        )
    return {
        "root": str(root),
        "programs": programs,
        "created_program_dirs": created_program_dirs,
        "created_report_dirs": created_report_dirs,
    }


def edin_program_report_dir(
    global_repo: Path | None,
    program_title: object,
    *,
    create: bool = False,
) -> Path:
    root = edin_program_folders_root(global_repo or get_repo_root())
    title = str(program_title or "").strip()
    if not title:
        if create:
            root.mkdir(parents=True, exist_ok=True)
        return root
    report_dir = root / edin_program_folder_name(title) / EDIN_PROGRAM_REPORTS_DIRNAME
    if create:
        report_dir.mkdir(parents=True, exist_ok=True)
    return report_dir


def _td_display_label_parts(value: object) -> list[str]:
    raw = str(value or "").strip()
    if not raw:
        return []
    return [part.strip() for part in re.split(r"\s*\|\s*|\s+/\s+", raw) if part.strip()]


def _td_display_serial_candidate(value: object) -> str:
    text = str(value or "").strip()
    if not text:
        return ""
    match = re.match(r"(?i)^(?:serial(?: number)?|s/?n)\s*[:#]\s*(.+)$", text)
    if match:
        text = str(match.group(1) or "").strip()
    if not text or any(sep in text for sep in ("\\", "/")):
        return ""
    if re.search(r"\.(?:json|sqlite|sqlite3|pdf|xlsx|xls|xlsm|mat)$", text, flags=re.IGNORECASE):
        return ""
    token = text.casefold()
    if token in {
        "source",
        "aggregate",
        "unknown serial",
        "unknown type",
        "unknown asset",
        "unknown program",
    }:
        return ""
    has_alpha = any(ch.isalpha() for ch in text)
    has_digit = any(ch.isdigit() for ch in text)
    if has_alpha and has_digit:
        return text
    if text.lower().startswith("sn") and (has_alpha or has_digit):
        return text
    if has_digit and " " not in text and len(text) <= 40:
        return text
    return ""


def _td_display_serial_from_text(value: object) -> str:
    raw = str(value or "").strip()
    if not raw:
        return ""
    parts = _td_display_label_parts(raw)
    if not parts:
        return raw
    for part in reversed(parts):
        candidate = _td_display_serial_candidate(part)
        if candidate:
            return candidate
    if len(parts) >= 2:
        tail = str(parts[-1]).strip().casefold()
        if tail.startswith("source") or re.search(
            r"\.(?:json|sqlite|sqlite3|pdf|xlsx|xls|xlsm|mat)$",
            str(parts[-1]).strip(),
            flags=re.IGNORECASE,
        ):
            return str(parts[-2]).strip() or str(parts[-1]).strip()
    if len(parts) == 4:
        return str(parts[3]).strip()
    return str(parts[-1]).strip()


def td_display_serial_label(value: object | Mapping[str, object]) -> str:
    if isinstance(value, Mapping):
        for key in ("serial_number", "source_serial_number"):
            txt = str(value.get(key) or "").strip()
            if txt:
                return txt
        raw = str(value.get("serial") or value.get("source_key") or "").strip()
    else:
        raw = str(value or "").strip()
    return _td_display_serial_from_text(raw)


def td_auto_report_serial_token(serials: Sequence[object] | None) -> str:
    cleaned: list[str] = []
    seen: set[str] = set()
    for value in (serials or []):
        if not str(value or "").strip():
            continue
        serial = _safe_windows_path_name(td_display_serial_label(value), fallback="")
        if not serial or serial.casefold() in seen:
            continue
        seen.add(serial.casefold())
        cleaned.append(serial)
    if not cleaned:
        return "No_Serials"
    if len(cleaned) <= 3:
        return "__".join(cleaned)
    return "__".join(cleaned[:3]) + f"__plus_{len(cleaned) - 3}_more"


def td_auto_report_default_filename(
    program_title: object,
    certification_serials: Sequence[object] | None,
    *,
    when: datetime | None = None,
) -> str:
    serial_token = td_auto_report_serial_token(certification_serials)
    return f"{serial_token}_Test Data Report.pdf"


def td_auto_report_default_output_pdf(
    global_repo: Path | None,
    program_title: object,
    certification_serials: Sequence[object] | None,
    *,
    when: datetime | None = None,
    create: bool = False,
) -> Path:
    out_dir = edin_program_report_dir(global_repo or get_repo_root(), program_title, create=create)
    return out_dir / td_auto_report_default_filename(program_title, certification_serials, when=when)


def _run_eidat_manager(global_repo: Path, cmd: str, extra_args: Optional[list[str]] = None) -> Dict[str, object]:
    target = Path(global_repo).expanduser()
    if not target.is_absolute():
        target = (ROOT / target).expanduser()
    if not target.exists():
        raise RuntimeError(f"Global repo does not exist: {target}")
    if not EIDAT_MANAGER_ENTRY.exists():
        raise RuntimeError(f"EDAT Manager not found: {EIDAT_MANAGER_ENTRY}")
    argv = [sys.executable, str(EIDAT_MANAGER_ENTRY), "--global-repo", str(target), cmd]
    if extra_args:
        argv.extend([str(a) for a in extra_args if str(a).strip()])
    env = _base_env()
    proc = subprocess.run(
        argv,
        capture_output=True,
        text=True,
        check=False,
        env=env,
    )
    if proc.returncode != 0:
        err = (proc.stderr or proc.stdout or "").strip()
        raise RuntimeError(err or f"EDAT Manager failed with exit code {proc.returncode}")
    out = (proc.stdout or "").strip()
    try:
        payload = json.loads(out) if out else {}
        if not isinstance(payload, dict):
            raise RuntimeError("EDAT Manager output was not an object")
        if cmd in ("scan", "process"):
            try:
                mirror = mirror_global_debug_ocr_to_local(target)
                payload["debug_ocr_mirror_root"] = mirror.get("dest")
                payload["debug_ocr_mirror_copied"] = mirror.get("copied", 0)
            except Exception:
                pass
        return payload
    except Exception as exc:
        raise RuntimeError(f"Unable to parse EDAT Manager output as JSON: {exc}") from exc


def eidat_manager_init(global_repo: Path) -> Dict[str, object]:
    return _run_eidat_manager(global_repo, "init")


def eidat_manager_scan(global_repo: Path) -> Dict[str, object]:
    return _run_eidat_manager(global_repo, "scan")


def eidat_manager_process(
    global_repo: Path,
    *,
    limit: int = 0,
    dpi: int = 0,
    force: bool = False,
    only_candidates: bool = False,
    file_paths: Sequence[str | Path] | None = None,
) -> Dict[str, object]:
    args: list[str] = []
    if limit and int(limit) > 0:
        args.extend(["--limit", str(int(limit))])
    if dpi and int(dpi) > 0:
        args.extend(["--dpi", str(int(dpi))])
    if force:
        args.append("--force")
    if only_candidates:
        args.append("--only-candidates")
    for file_path in file_paths or []:
        text = str(file_path or "").strip()
        if text:
            args.extend(["--file", text])
    result = _run_eidat_manager(global_repo, "process", args)
    # Auto-rebuild index after processing
    if result.get("processed_ok", 0) > 0 and "index" not in result:
        try:
            index_result = eidat_manager_index(global_repo)
            result["index"] = index_result
        except Exception:
            pass  # Index failure shouldn't fail the whole process
    return result


def eidat_manager_force_single_file(global_repo: Path, file_path: str | Path, *, dpi: int = 0) -> Dict[str, object]:
    repo = Path(global_repo).expanduser()
    source = resolve_path_within_global_repo(repo, Path(file_path), "Source file")
    if not source.exists():
        raise FileNotFoundError(f"Source file not found: {source}")
    if not source.is_file():
        raise RuntimeError(f"Source path is not a file: {source}")
    if source.suffix.lower() not in ({".pdf"} | set(EXCEL_EXTENSIONS)):
        raise RuntimeError("Select a PDF, Excel, or MAT source file.")

    try:
        rel_path = source.resolve().relative_to(repo.resolve()).as_posix()
    except Exception:
        rel_path = source.as_posix()

    scan_payload = eidat_manager_scan(repo)
    result = eidat_manager_process(repo, dpi=dpi, force=True, file_paths=[source])
    result["scan"] = scan_payload
    result["source_file"] = str(source)
    result["source_rel_path"] = rel_path

    processed_ok = int(result.get("processed_ok") or 0)
    processed_failed = int(result.get("processed_failed") or 0)
    if processed_failed > 0 or processed_ok <= 0:
        errors: list[str] = []
        try:
            for item in list(result.get("results") or []):
                if not bool((item or {}).get("ok")):
                    err = str((item or {}).get("error") or "").strip()
                    if err:
                        errors.append(err)
        except Exception:
            pass
        detail = f": {'; '.join(errors[:3])}" if errors else ""
        raise RuntimeError(f"Single-file force update did not complete for {rel_path}{detail}")
    return result


def eidat_manager_index(global_repo: Path, *, similarity: float = 0.86) -> Dict[str, object]:
    args: list[str] = []
    if similarity:
        args.extend(["--similarity", str(similarity)])
    return _run_eidat_manager(global_repo, "index", args)


def _load_eidat_metadata_module():
    try:
        from Application import eidat_manager_metadata as emd  # type: ignore
        return emd
    except Exception:
        mod_path = APP_ROOT / "Application" / "eidat_manager_metadata.py"
        spec = importlib.util.spec_from_file_location("eidat_manager_metadata", mod_path)
        if spec is None or spec.loader is None:
            raise RuntimeError(f"Unable to load metadata module: {mod_path}")
        mod = importlib.util.module_from_spec(spec)
        spec.loader.exec_module(mod)  # type: ignore[attr-defined]
        return mod


def _merge_metadata(primary: Optional[Mapping[str, object]], fallback: Optional[Mapping[str, object]]) -> dict:
    out: dict = {}
    if isinstance(fallback, Mapping):
        out.update({k: v for k, v in fallback.items()})
    if isinstance(primary, Mapping):
        for k, v in primary.items():
            if v is None:
                continue
            if isinstance(v, str) and not v.strip():
                continue
            out[k] = v
    return out


def _load_eidat_index_module():
    try:
        from Application import eidat_manager_index as emi  # type: ignore
        return emi
    except Exception:
        mod_path = APP_ROOT / "Application" / "eidat_manager_index.py"
        spec = importlib.util.spec_from_file_location("eidat_manager_index", mod_path)
        if spec is None or spec.loader is None:
            raise RuntimeError(f"Unable to load index module: {mod_path}")
        mod = importlib.util.module_from_spec(spec)
        spec.loader.exec_module(mod)  # type: ignore[attr-defined]
        return mod


def _ui_visible_root(repo: Path) -> Path:
    return eidat_support_dir(Path(repo).expanduser()) / UI_VISIBLE_FILES_DIRNAME


def _bundle_rel_from_metadata_rel(metadata_rel: object) -> str:
    rel = str(metadata_rel or "").strip().replace("\\", "/")
    if not rel:
        return ""
    path_obj = Path(rel)
    if path_obj.name.casefold() == UI_VISIBLE_METADATA_FILENAME.casefold():
        return str(path_obj.parent).replace("\\", "/")
    return rel


def _parse_json_list(value: object) -> list[str]:
    raw = value
    if isinstance(raw, str):
        try:
            raw = json.loads(raw)
        except Exception:
            raw = []
    if not isinstance(raw, list):
        return []
    return [str(v).strip() for v in raw if str(v).strip()]


def _read_json_file(path: Path) -> dict[str, object] | None:
    try:
        payload = json.loads(Path(path).read_text(encoding="utf-8"))
    except Exception:
        return None
    return dict(payload) if isinstance(payload, dict) else None


def _write_json_file(path: Path, payload: Mapping[str, object]) -> None:
    Path(path).parent.mkdir(parents=True, exist_ok=True)
    Path(path).write_text(json.dumps(dict(payload), indent=2, ensure_ascii=True), encoding="utf-8")


def _visible_bundle_doc_maps(docs: Sequence[Mapping[str, object]]) -> tuple[dict[str, dict[str, object]], dict[str, dict[str, object]]]:
    by_bundle_rel: dict[str, dict[str, object]] = {}
    by_metadata_rel: dict[str, dict[str, object]] = {}
    for item in docs:
        row = dict(item or {})
        metadata_rel = str(row.get("metadata_rel") or "").strip().replace("\\", "/")
        bundle_rel = _bundle_rel_from_metadata_rel(metadata_rel)
        if metadata_rel and metadata_rel not in by_metadata_rel:
            by_metadata_rel[metadata_rel] = row
        if bundle_rel and bundle_rel not in by_bundle_rel:
            by_bundle_rel[bundle_rel] = row
    return by_bundle_rel, by_metadata_rel


def _clear_manual_override_fields(payload: Mapping[str, object]) -> dict[str, object]:
    out = dict(payload or {})
    out["manual_override_fields"] = []
    out["manual_override_updated_at"] = ""
    return out


METADATA_EDITOR_FIELDS = (
    "program_title",
    "asset_type",
    "asset_specific_type",
    "vendor",
    "part_number",
    "revision",
    "test_date",
    "report_date",
    "acceptance_test_plan_number",
    "document_type",
    "document_type_acronym",
)


def _sync_projects_for_metadata_rels(repo: Path, updated_metadata_rels: set[str]) -> tuple[list[dict], list[dict]]:
    projects_synced: list[dict] = []
    projects_sync_failed: list[dict] = []
    if not updated_metadata_rels:
        return projects_synced, projects_sync_failed
    try:
        projects = list_eidat_projects(repo)
    except Exception:
        projects = []
    for pr in projects:
        try:
            raw_dir = str(pr.get("project_dir") or "").strip()
            proj_dir = Path(raw_dir).expanduser()
            if not proj_dir.is_absolute():
                proj_dir = repo / proj_dir

            selected = _project_selected_metadata_rels(proj_dir)
            if not selected or not selected.intersection(updated_metadata_rels):
                continue

            raw_wb = str(pr.get("workbook") or "").strip()
            wb_path = Path(raw_wb).expanduser()
            if not wb_path.is_absolute():
                wb_path = repo / wb_path

            res = sync_project_workbook_metadata(repo, wb_path)
            projects_synced.append(
                {
                    "name": pr.get("name"),
                    "type": pr.get("type"),
                    "workbook": str(wb_path),
                    "result": res,
                }
            )
        except Exception as exc:
            projects_sync_failed.append(
                {
                    "name": pr.get("name"),
                    "type": pr.get("type"),
                    "error": str(exc),
                }
            )
    return projects_synced, projects_sync_failed


def refresh_metadata_only(
    global_repo: Path,
    rel_paths: list[str],
    *,
    overwrite_manual_fields: bool = False,
) -> Dict[str, object]:
    """Refresh metadata JSONs from existing artifacts without re-OCR."""
    repo = Path(global_repo).expanduser()
    if not repo.exists():
        raise RuntimeError(f"Global repo does not exist: {repo}")

    emd = _load_eidat_metadata_module()
    results: list[dict] = []
    updated = 0
    failed = 0
    skipped = 0
    updated_metadata_rels: set[str] = set()
    support_dir = eidat_support_dir(repo)
    emi = _load_eidat_index_module()
    try:
        docs_for_visible = read_eidat_index_documents(repo)
    except Exception:
        docs_for_visible = []
    docs_by_bundle_rel, docs_by_metadata_rel = _visible_bundle_doc_maps(docs_for_visible)

    clean_rel_paths = [str(p).strip() for p in (rel_paths or []) if str(p).strip()]
    for rel_path in clean_rel_paths:
        try:
            rel_norm = str(rel_path or "").strip().replace("\\", "/")
            visible_doc = docs_by_bundle_rel.get(rel_norm) or docs_by_metadata_rel.get(rel_norm)
            if visible_doc is not None:
                metadata_rel = str(visible_doc.get("metadata_rel") or "").strip()
                if not metadata_rel:
                    raise FileNotFoundError(f"Visible metadata file not found for: {rel_path}")
                metadata_path = support_dir / metadata_rel
                if not metadata_path.exists():
                    raise FileNotFoundError(f"Visible metadata file not found for: {rel_path}")
                if overwrite_manual_fields:
                    raw_visible = _read_json_file(metadata_path) or {}
                    _write_json_file(metadata_path, _clear_manual_override_fields(raw_visible))
                updated_metadata_rels.add(metadata_rel)
                results.append(
                    {
                        "rel_path": rel_path,
                        "ok": True,
                        "metadata_path": str(metadata_path),
                    }
                )
                updated += 1
                continue
            abs_path = (repo / rel_path).expanduser()
            if not abs_path.exists():
                raise FileNotFoundError(f"Missing file: {abs_path}")
            artifacts_dir = get_file_artifacts_path(repo, rel_path)
            if not artifacts_dir or not artifacts_dir.exists():
                raise FileNotFoundError(f"Artifacts folder not found for: {rel_path}")

            existing_meta = None
            try:
                existing_meta = emd.load_metadata_from_artifacts(artifacts_dir, abs_path)
            except Exception:
                existing_meta = None
            if not existing_meta:
                try:
                    existing_meta = _load_metadata_from_artifacts_dir(artifacts_dir)
                except Exception:
                    existing_meta = None

            extracted_meta = None
            is_excel = abs_path.suffix.lower() in EXCEL_EXTENSIONS
            if is_excel:
                try:
                    extracted_meta = emd.extract_metadata_from_excel(abs_path)
                except Exception:
                    extracted_meta = None
            else:
                combined_path = artifacts_dir / "combined.txt"
                combined_text = ""
                if combined_path.exists():
                    try:
                        combined_text = combined_path.read_text(encoding="utf-8", errors="ignore")
                    except Exception:
                        combined_text = ""
                if combined_text.strip():
                    try:
                        extracted_meta = emd.extract_metadata_from_text(combined_text, pdf_path=abs_path)
                    except Exception:
                        extracted_meta = None

            default_doc_type = "Unknown"
            clean_meta = emd.canonicalize_metadata_for_file(
                abs_path,
                existing_meta=existing_meta,
                extracted_meta=extracted_meta,
                default_document_type=default_doc_type,
                overwrite_manual_fields=overwrite_manual_fields,
            )
            metadata_path = emd.write_metadata(Path(artifacts_dir), abs_path, clean_meta)

            # Remove stale metadata files in this artifacts folder (keep the new one if present)
            if metadata_path:
                keep = Path(metadata_path)
                for pat in ("*_metadata.json", "*.metadata.json"):
                    for p in artifacts_dir.glob(pat):
                        try:
                            if p.resolve() == keep.resolve():
                                continue
                            p.unlink()
                        except Exception:
                            continue
                # Track updated metadata rel for project syncing.
                try:
                    rel = str(Path(metadata_path).resolve().relative_to(eidat_support_dir(repo).resolve()))
                    if rel:
                        updated_metadata_rels.add(rel)
                except Exception:
                    pass

            results.append(
                {
                    "rel_path": rel_path,
                    "ok": True,
                    "metadata_path": str(metadata_path) if metadata_path else None,
                }
            )
            updated += 1
        except Exception as exc:
            results.append(
                {
                    "rel_path": rel_path,
                    "ok": False,
                    "error": str(exc),
                }
            )
            failed += 1

    try:
        from Application.eidat_manager_db import support_paths as _support_paths  # type: ignore

        emi.publish_visible_bundles(_support_paths(repo))
    except Exception:
        pass

    index_result = None
    index_error = None
    try:
        index_result = eidat_manager_index(repo)
    except Exception as exc:
        index_error = str(exc)

    projects_synced, projects_sync_failed = _sync_projects_for_metadata_rels(repo, updated_metadata_rels)

    return {
        "updated": updated,
        "failed": failed,
        "skipped": skipped,
        "results": results,
        "index": index_result,
        "index_error": index_error,
        "updated_metadata_rel": sorted(updated_metadata_rels),
        "projects_synced": projects_synced,
        "projects_sync_failed": projects_sync_failed,
        "overwrite_manual_fields": bool(overwrite_manual_fields),
    }


def edit_metadata_for_files(
    global_repo: Path,
    rel_paths: list[str],
    field_updates: Mapping[str, object],
) -> Dict[str, object]:
    repo = Path(global_repo).expanduser()
    if not repo.exists():
        raise RuntimeError(f"Global repo does not exist: {repo}")

    emd = _load_eidat_metadata_module()
    updates = {
        str(key or "").strip(): str(value or "").strip()
        for key, value in dict(field_updates or {}).items()
        if str(key or "").strip() in METADATA_EDITOR_FIELDS and str(value or "").strip()
    }
    if not updates:
        raise RuntimeError("No metadata fields were changed.")

    results: list[dict] = []
    updated = 0
    failed = 0
    updated_metadata_rels: set[str] = set()
    support_dir = eidat_support_dir(repo)
    emi = _load_eidat_index_module()
    try:
        docs_for_visible = read_eidat_index_documents(repo)
    except Exception:
        docs_for_visible = []
    docs_by_bundle_rel, docs_by_metadata_rel = _visible_bundle_doc_maps(docs_for_visible)

    clean_rel_paths = [str(p).strip() for p in (rel_paths or []) if str(p).strip()]
    for rel_path in clean_rel_paths:
        try:
            rel_norm = str(rel_path or "").strip().replace("\\", "/")
            visible_doc = docs_by_bundle_rel.get(rel_norm) or docs_by_metadata_rel.get(rel_norm)
            if visible_doc is not None:
                metadata_rel = str(visible_doc.get("metadata_rel") or "").strip()
                if not metadata_rel:
                    raise FileNotFoundError(f"Visible metadata file not found for: {rel_path}")
                metadata_path = support_dir / metadata_rel
                existing_meta = _read_json_file(metadata_path)
                if not existing_meta:
                    raise FileNotFoundError(f"Visible metadata file not found for: {rel_path}")
                preserved = {
                    key: existing_meta.get(key)
                    for key in (
                        "artifacts_rel",
                        "excel_sqlite_rel",
                        "tables_sqlite_rel",
                        "source_rel_path",
                        "source_rel_paths",
                        "internal_metadata_rel",
                        "similarity_group",
                        "file_extension",
                    )
                    if key in existing_meta
                }
                clean_meta = emd.apply_manual_metadata_overrides(existing_meta, updates)
                clean_meta.update(preserved)
                _write_json_file(metadata_path, clean_meta)
                updated_metadata_rels.add(metadata_rel)
                results.append(
                    {
                        "rel_path": rel_path,
                        "ok": True,
                        "metadata_path": str(metadata_path),
                    }
                )
                updated += 1
                continue
            abs_path = (repo / rel_path).expanduser()
            if not abs_path.exists():
                raise FileNotFoundError(f"Missing file: {abs_path}")
            artifacts_dir = get_file_artifacts_path(repo, rel_path)
            if not artifacts_dir:
                raise FileNotFoundError(f"Artifacts folder not found for: {rel_path}")
            artifacts_dir = Path(artifacts_dir)
            artifacts_dir.mkdir(parents=True, exist_ok=True)

            existing_meta = None
            try:
                existing_meta = emd.load_metadata_from_artifacts(artifacts_dir, abs_path)
            except Exception:
                existing_meta = None
            if not existing_meta:
                try:
                    existing_meta = _load_metadata_from_artifacts_dir(artifacts_dir)
                except Exception:
                    existing_meta = None

            if not existing_meta:
                extracted_meta = None
                if abs_path.suffix.lower() in EXCEL_EXTENSIONS:
                    try:
                        extracted_meta = emd.extract_metadata_from_excel(abs_path)
                    except Exception:
                        extracted_meta = None
                else:
                    combined_path = artifacts_dir / "combined.txt"
                    combined_text = ""
                    if combined_path.exists():
                        try:
                            combined_text = combined_path.read_text(encoding="utf-8", errors="ignore")
                        except Exception:
                            combined_text = ""
                    if combined_text.strip():
                        try:
                            extracted_meta = emd.extract_metadata_from_text(combined_text, pdf_path=abs_path)
                        except Exception:
                            extracted_meta = None
                existing_meta = emd.canonicalize_metadata_for_file(
                    abs_path,
                    existing_meta=None,
                    extracted_meta=extracted_meta,
                    default_document_type="Unknown",
                )

            clean_meta = emd.apply_manual_metadata_overrides(existing_meta, updates)
            metadata_path = emd.write_metadata(artifacts_dir, abs_path, clean_meta)
            if metadata_path is None:
                raise RuntimeError(f"Failed to write metadata for: {rel_path}")
            try:
                rel = str(Path(metadata_path).resolve().relative_to(eidat_support_dir(repo).resolve()))
            except Exception:
                rel = ""
            if rel:
                updated_metadata_rels.add(rel)
            results.append(
                {
                    "rel_path": rel_path,
                    "ok": True,
                    "metadata_path": str(metadata_path),
                }
            )
            updated += 1
        except Exception as exc:
            results.append(
                {
                    "rel_path": rel_path,
                    "ok": False,
                    "error": str(exc),
                }
            )
            failed += 1

    try:
        from Application.eidat_manager_db import support_paths as _support_paths  # type: ignore

        emi.publish_visible_bundles(_support_paths(repo))
    except Exception:
        pass

    index_result = None
    index_error = None
    try:
        index_result = eidat_manager_index(repo)
    except Exception as exc:
        index_error = str(exc)

    projects_synced, projects_sync_failed = _sync_projects_for_metadata_rels(repo, updated_metadata_rels)

    return {
        "updated": updated,
        "failed": failed,
        "results": results,
        "index": index_result,
        "index_error": index_error,
        "updated_metadata_rel": sorted(updated_metadata_rels),
        "projects_synced": projects_synced,
        "projects_sync_failed": projects_sync_failed,
        "field_updates": dict(updates),
    }


def _prefer_existing(*paths: Path) -> Path:
    """Return the first existing path, or the first element if none exist."""
    for p in paths:
        if p.exists():
            return p
    return paths[0]


def master_xlsx_for_read() -> Path:
    """Prefer Master_Database/master.xlsx, fall back to root-level legacy."""
    return _prefer_existing(MASTER_XLSX, LEGACY_MASTER_XLSX)


def master_csv_for_read() -> Path:
    """Prefer Master_Database/master.csv, fall back to root-level legacy."""
    return _prefer_existing(MASTER_CSV, LEGACY_MASTER_CSV)


def registry_csv_for_read() -> Path:
    """Prefer Master_Database/run_registry.csv, fall back to root-level legacy."""
    return _prefer_existing(REG_CSV, LEGACY_REG_CSV)


def registry_xlsx_for_read() -> Path:
    """Prefer Master_Database/run_registry.xlsx, fall back to root-level legacy."""
    return _prefer_existing(REG_XLSX, LEGACY_REG_XLSX)


def run_roots() -> list[Path]:
    """Return run_data_simple root."""
    return [RUNS_DIR]


def plots_root_for_open() -> Path:
    """Return the plots folder."""
    return PLOTS_DIR


def _venv_python_from(path: Path) -> Path:
    if os.name == "nt":
        return path / "Scripts" / "python.exe"
    return path / "bin" / "python"


def resolve_project_python() -> str:
    env = load_scanner_env()
    vdir = env.get("VENV_DIR", "").strip()
    if vdir:
        cand = _venv_python_from(Path(vdir))
        if cand.exists():
            return str(cand)
    cand = _venv_python_from(APP_ROOT / ".venv")
    if cand.exists():
        return str(cand)
    return sys.executable


def _base_env() -> Dict[str, str]:
    env = os.environ.copy()
    # Merge env files for direct Python invocations.
    #
    # Precedence (last wins):
    #   1) Legacy user_inputs/ocr_force.env (deprecated; fallback only)
    #   2) user_inputs/scanner.env (shared template/docs)
    #   3) user_inputs/scanner.local.env (machine-specific overrides)
    #   4) project/node .env overrides
    #
    # This lets us "move" OCR DPI settings into scanner.env without ocr_force.env continuing
    # to override them when both exist.
    env.update(parse_scanner_env(OCR_FORCE_ENV))
    env.update(parse_scanner_env(SCANNER_ENV))
    env.update(parse_scanner_env(SCANNER_ENV_LOCAL))
    for path in DOTENV_FILES:
        env.update(parse_scanner_env(path))
    # Remove deprecated force flags (no longer used)
    for key in (
        "EIDAT_FORCE_NUMERIC_RESCUE",
        "EIDAT_FORCE_NUMERIC_STRICT",
        "EIDAT_FORCE_CELL_INTERIOR",
    ):
        env.pop(key, None)
    # Ensure vendored site-packages are importable as fallback
    env["PYTHONPATH"] = str(APP_ROOT / "Lib" / "site-packages") + os.pathsep + env.get("PYTHONPATH", "")
    env.setdefault("QUIET", "1")
    # GUI: charts are experimental and slow; keep disabled unless explicitly enabled.
    env.setdefault("EIDAT_ENABLE_CHART_EXTRACTION", "0")
    # Force cache to always be in project root, not executable location
    # This ensures cache is consistent whether running as script or frozen exe
    if "CACHE_ROOT" not in env and "OCR_CACHE_ROOT" not in env:
        env["CACHE_ROOT"] = str(DATA_ROOT)
    return env


def spawn(cmd: Iterable[str], *, cwd: Optional[Path] = None, env: Optional[Dict[str, str]] = None) -> subprocess.Popen:
    return subprocess.Popen(
        list(cmd),
        cwd=str(cwd or ROOT),
        env=env or _base_env(),
        stdout=subprocess.PIPE,
        stderr=subprocess.STDOUT,
        text=True,
        bufsize=1,
    )


def run_install_full() -> subprocess.Popen:
    if not sys.platform.startswith("win"):
        raise RuntimeError("install.bat requires Windows")
    return spawn(["cmd.exe", "/c", str(ROOT / "install.bat")])


def run_scanner(terms: Path, pdf_dir: Path) -> subprocess.Popen:
    """Run simple extraction on all PDFs under the provided directory."""
    terms_path = resolve_terms_path(terms)
    pdf_root = resolve_pdf_root(pdf_dir)
    pdfs = [p for p in pdf_root.rglob("*.pdf") if p.is_file()]
    if not pdfs:
        raise RuntimeError(f"No PDFs found under: {pdf_root}")
    return run_simple_extraction(pdfs, terms_path)


def run_script(script_rel_path: str, *args: str) -> subprocess.Popen:
    py = resolve_project_python()
    script = APP_ROOT / script_rel_path
    if not script.exists():
        raise FileNotFoundError(f"Missing script: {script}")
    return spawn([py, str(script), *args])


def generate_terms() -> subprocess.Popen:
    return run_script("scripts/generate_terms_schema_simple.py")


def compile_master() -> subprocess.Popen:
    return run_script("scripts/compile_master_simple.py")


def compile_master_from_state() -> None:
    """
    Rebuild master.xlsx from simple run outputs.
    This discards all manual edits and rebuilds from extracted data.

    Unlike compile_master(), this runs synchronously in the current process.
    """
    import sys as _sys
    if str(APP_ROOT) not in _sys.path:
        _sys.path.insert(0, str(APP_ROOT))
    from scripts.compile_master_simple import build_master_simple, write_master  # type: ignore

    # Build from simple run results
    serials, rows, prog_map, sv_map, data_map = build_master_simple()

    if not serials:
        print("[WARN] No simple run data available to compile")
        return

    # Write the master workbook
    write_master(serials, rows, program_by_sn=prog_map, sv_by_sn=sv_map, data_by_sn=data_map)


def generate_plots() -> subprocess.Popen:
    return run_script("scripts/plot_from_master.py")


def export_plots_summary() -> subprocess.Popen:
    return run_script("scripts/plots_to_excel_summary.py")


def extract_page_tables(pdf: Path, pages: str | None = None) -> subprocess.Popen:
    pdf_path = resolve_pdf_path(Path(pdf), "PDF")
    args = ["--pdf", str(pdf_path)]
    if pages:
        args += ["--pages", pages]
    return run_script("scripts/extract_page_tables.py", *args)


def extract_csv_tables(pdf: Path, pages: str, num_cols: Optional[int] = None,
                      min_cols: int = 2, min_rows: int = 3,
                      match_threshold: float = 0.5, ocr: bool = False,
                      dpi: int = 300, delimiter: Optional[str] = None,
                      output: Optional[Path] = None) -> subprocess.Popen:
    """Extract tables using line-by-line CSV detection with smart alignment."""
    pdf_path = resolve_pdf_path(Path(pdf), "PDF")
    args = ["--pdf", str(pdf_path), "--pages", pages]
    if num_cols is not None:
        args += ["--num-cols", str(num_cols)]
    if min_cols != 2:
        args += ["--min-cols", str(min_cols)]
    if min_rows != 3:
        args += ["--min-rows", str(min_rows)]
    if match_threshold != 0.5:
        args += ["--match-threshold", str(match_threshold)]
    if ocr:
        args += ["--ocr"]
    if dpi != 300:
        args += ["--dpi", str(dpi)]
    if delimiter:
        args += ["--delimiter", delimiter]
    if output:
        out_path = resolve_repo_path(Path(output), "Output path")
        args += ["--out", str(out_path)]
    return run_script("scripts/extract_table_csv_lines.py", *args)


def pre_ocr_merge_pdfs(paths: list[Path], out_root: Optional[Path] = None, dpi: Optional[int] = None) -> subprocess.Popen:
    """Pre-OCR selected PDFs and write merged text artifacts (no extraction)."""
    resolved = resolve_pdf_paths(paths)
    args: list[str] = []
    for p in resolved:
        args += ["--pdf", str(Path(p))]
    if out_root:
        out_path = resolve_repo_path(Path(out_root), "Pre-OCR output folder")
        args += ["--out", str(out_path)]
    if dpi is not None:
        args += ["--dpi", str(int(dpi))]
    return run_script("scripts/pre_ocr_merge.py", *args)


def run_simple_extraction(paths: list[Path], terms: Optional[Path] = None) -> subprocess.Popen:
    """Run the simple merged-text extraction pipeline on selected PDFs."""
    terms_path = resolve_terms_path(terms)
    pdfs = resolve_pdf_paths(paths)
    args: list[str] = []
    for p in pdfs:
        args += ["--pdf", str(Path(p))]
    args += ["--terms", str(terms_path)]
    return run_script("scripts/simple_extraction.py", *args)


def run_excel_extraction(excel_paths: list[Path], config: Optional[Path] = None, global_repo: Optional[Path] = None) -> subprocess.Popen:
    """Run the Excel data extraction pipeline on selected Excel files."""
    cfg = Path(config) if config else DEFAULT_EXCEL_TREND_CONFIG
    if not cfg.exists():
        raise FileNotFoundError(f"Excel trend config not found: {cfg}")
    repo = global_repo or DEFAULT_REPO_ROOT
    args: list[str] = ["--global-repo", str(repo)]
    for p in excel_paths:
        args += ["--excel", str(Path(p))]
    args += ["--config", str(cfg)]
    return run_script("scripts/excel_extraction.py", *args)


def run_excel_scanner(data_dir: Path, config: Optional[Path] = None) -> subprocess.Popen:
    """Run Excel extraction on all Excel files under the provided directory."""
    cfg = Path(config) if config else DEFAULT_EXCEL_TREND_CONFIG
    data_root = resolve_pdf_root(data_dir)
    excels = [
        p
        for p in data_root.rglob("*")
        if p.is_file() and p.suffix.lower() in EXCEL_EXTENSIONS and not p.name.startswith("~$")
    ]
    if not excels:
        raise RuntimeError(f"No Excel data files found under: {data_root}")
    return run_excel_extraction(excels, cfg, data_root)


