def td_raw_cache_db_path_for(project_dir: Path) -> Path:
    return Path(project_dir).expanduser() / EIDAT_PROJECT_TD_RAW_CACHE_DB


def _td_resolve_raw_cache_db_path(db_path: Path) -> Path:
    path = Path(db_path).expanduser()
    if path.name.lower() == EIDAT_PROJECT_TD_RAW_CACHE_DB.lower():
        return path
    return td_raw_cache_db_path_for(path.parent)


def _td_stable_json(value: object) -> str:
    try:
        return json.dumps(value, sort_keys=True, separators=(",", ":"), ensure_ascii=False, default=str)
    except Exception:
        return json.dumps(str(value), sort_keys=True, separators=(",", ":"), ensure_ascii=False)


def _td_hash_payload(value: object) -> str:
    return hashlib.sha1(_td_stable_json(value).encode("utf-8")).hexdigest()


@lru_cache(maxsize=1)
def _td_builder_signature() -> str:
    backend_path = Path(__file__).resolve()
    try:
        backend_sha1 = hashlib.sha1(backend_path.read_bytes()).hexdigest()
    except Exception:
        backend_sha1 = ""
    return _td_hash_payload(
        {
            "backend_path": str(backend_path),
            "backend_sha1": backend_sha1,
            "cache_schema_version": TD_PROJECT_CACHE_SCHEMA_VERSION,
        }
    )


def _td_support_signatures(support_cfg: Mapping[str, object] | None) -> dict[str, str]:
    cfg = dict(support_cfg or {})

    def _sorted_rows(rows: Iterable[object]) -> list[dict[str, object]]:
        normalized = [dict(row) for row in rows if isinstance(row, Mapping)]
        return sorted(normalized, key=_td_stable_json)

    def _raw_mapping_rows() -> dict[str, list[dict[str, object]]]:
        out: dict[str, list[dict[str, object]]] = {}
        for program_title, rows in dict(cfg.get("program_mappings") or {}).items():
            key = str(program_title or "").strip()
            cleaned: list[dict[str, object]] = []
            for row in rows or []:
                if not isinstance(row, Mapping):
                    continue
                cleaned.append(
                    {
                        "program_title": key,
                        "sheet_name": str(row.get("sheet_name") or "").strip(),
                        "source_run_name": str(row.get("source_run_name") or "").strip(),
                        "condition_key": str(row.get("condition_key") or "").strip(),
                        "enabled": bool(row.get("enabled", True)),
                        "display_name": str(row.get("display_name") or "").strip(),
                        "run_type": str(row.get("run_type") or "").strip(),
                        "pulse_width": row.get("pulse_width_on", row.get("pulse_width")),
                        "control_period": row.get("control_period"),
                        "suppression_voltage": row.get("suppression_voltage"),
                        "valve_voltage": row.get("valve_voltage"),
                    }
                )
            if cleaned:
                out[key] = sorted(cleaned, key=_td_stable_json)
        return out

    def _calc_mapping_rows() -> dict[str, list[dict[str, object]]]:
        out: dict[str, list[dict[str, object]]] = {}
        for program_title, rows in dict(cfg.get("program_mappings") or {}).items():
            key = str(program_title or "").strip()
            cleaned: list[dict[str, object]] = []
            for row in rows or []:
                if not isinstance(row, Mapping):
                    continue
                cleaned.append(
                    {
                        "program_title": key,
                        "sheet_name": str(row.get("sheet_name") or "").strip(),
                        "source_run_name": str(row.get("source_run_name") or "").strip(),
                        "condition_key": str(row.get("condition_key") or "").strip(),
                        "exclude_first_n": row.get("exclude_first_n"),
                        "last_n_rows": row.get("last_n_rows"),
                    }
                )
            if cleaned:
                out[key] = sorted(cleaned, key=_td_stable_json)
        return out

    raw_payload = {
        "programs": _sorted_rows(cfg.get("programs") or []),
        "program_mappings": _raw_mapping_rows(),
        "run_conditions": _sorted_rows(cfg.get("run_conditions") or []),
        "condition_groups": _sorted_rows(cfg.get("condition_groups") or []),
        "condition_bounds": {
            str(key or "").strip(): {
                str(param or "").strip(): dict(value)
                for param, value in dict(bounds or {}).items()
                if str(param or "").strip() and isinstance(value, Mapping)
            }
            for key, bounds in dict(cfg.get("condition_bounds") or {}).items()
            if str(key or "").strip() and isinstance(bounds, Mapping)
        },
        "bounds_by_sequence": {
            str(key or "").strip(): {
                str(param or "").strip(): dict(value)
                for param, value in dict(bounds or {}).items()
                if str(param or "").strip() and isinstance(value, Mapping)
            }
            for key, bounds in dict(cfg.get("bounds_by_sequence") or {}).items()
            if str(key or "").strip() and isinstance(bounds, Mapping)
        },
        "sequences": sorted(
            [
                {
                    "run_name": str(row.get("run_name") or "").strip(),
                    "display_name": str(row.get("display_name") or "").strip(),
                    "program_title": str(row.get("program_title") or "").strip(),
                    "source_run_name": str(row.get("source_run_name") or "").strip(),
                    "condition_key": str(row.get("condition_key") or "").strip(),
                    "enabled": bool(row.get("enabled", True)),
                    "run_type": str(row.get("run_type") or "").strip(),
                    "pulse_width": row.get("pulse_width_on", row.get("pulse_width")),
                    "control_period": row.get("control_period"),
                    "suppression_voltage": row.get("suppression_voltage"),
                    "valve_voltage": row.get("valve_voltage"),
                }
                for row in (cfg.get("sequences") or [])
                if isinstance(row, Mapping)
            ],
            key=_td_stable_json,
        ),
    }
    calc_payload = {
        "settings": dict(cfg.get("settings") or {}),
        "program_mappings": _calc_mapping_rows(),
        "sequences": sorted(
            [
                {
                    "run_name": str(row.get("run_name") or "").strip(),
                    "program_title": str(row.get("program_title") or "").strip(),
                    "source_run_name": str(row.get("source_run_name") or "").strip(),
                    "condition_key": str(row.get("condition_key") or "").strip(),
                    "exclude_first_n": row.get("exclude_first_n"),
                    "last_n_rows": row.get("last_n_rows"),
                }
                for row in (cfg.get("sequences") or [])
                if isinstance(row, Mapping)
            ],
            key=_td_stable_json,
        ),
    }
    return {
        "raw": _td_hash_payload(raw_payload),
        "calc": _td_hash_payload(calc_payload),
    }


def _td_raw_cache_candidate_paths(db_path: Path) -> list[Path]:
    original = Path(db_path).expanduser()
    resolved = _td_resolve_raw_cache_db_path(original)
    out: list[Path] = []
    for candidate in (resolved, original):
        if candidate not in out:
            out.append(candidate)
    return out


def _td_norm_ident_token(value: object) -> str:
    txt = "".join(ch.lower() if ch.isalnum() else "_" for ch in str(value or "").strip())
    txt = re.sub(r"_+", "_", txt).strip("_")
    return txt or "unnamed"


def _td_raw_curve_table_name(run_name: str, parameter_name: str) -> str:
    return f"td_raw__{_td_norm_ident_token(run_name)}__{_td_norm_ident_token(parameter_name)}"


def _ensure_test_data_raw_cache_tables(conn: sqlite3.Connection) -> None:
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS td_raw_meta (
            key TEXT PRIMARY KEY,
            value TEXT
        )
        """
    )
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS td_raw_sequences (
            run_name TEXT PRIMARY KEY,
            display_name TEXT,
            x_axis_kind TEXT NOT NULL,
            source_run_name TEXT,
            pulse_width REAL,
            run_type TEXT,
            control_period REAL,
            computed_epoch_ns INTEGER NOT NULL
        )
        """
    )
    try:
        conn.execute("ALTER TABLE td_raw_sequences ADD COLUMN pulse_width REAL")
    except Exception:
        pass
    try:
        conn.execute("ALTER TABLE td_raw_sequences ADD COLUMN run_type TEXT")
    except Exception:
        pass
    try:
        conn.execute("ALTER TABLE td_raw_sequences ADD COLUMN control_period REAL")
    except Exception:
        pass
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS td_raw_condition_observations (
            observation_id TEXT PRIMARY KEY,
            run_name TEXT NOT NULL,
            serial TEXT NOT NULL,
            program_title TEXT,
            source_run_name TEXT,
            run_type TEXT,
            pulse_width REAL,
            control_period REAL,
            suppression_voltage REAL,
            valve_voltage REAL,
            source_mtime_ns INTEGER,
            computed_epoch_ns INTEGER NOT NULL
        )
        """
    )
    try:
        conn.execute("ALTER TABLE td_raw_condition_observations ADD COLUMN suppression_voltage REAL")
    except Exception:
        pass
    try:
        conn.execute("ALTER TABLE td_raw_condition_observations ADD COLUMN valve_voltage REAL")
    except Exception:
        pass
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS td_raw_curve_catalog (
            run_name TEXT NOT NULL,
            parameter_name TEXT NOT NULL,
            units TEXT,
            x_axis_kind TEXT NOT NULL,
            table_name TEXT NOT NULL,
            display_name TEXT,
            source_kind TEXT,
            computed_epoch_ns INTEGER NOT NULL,
            PRIMARY KEY (run_name, parameter_name)
        )
        """
    )
    conn.execute(
        """
        CREATE INDEX IF NOT EXISTS td_raw_curve_catalog_run_idx
        ON td_raw_curve_catalog (run_name, parameter_name)
        """
    )
    # Compatibility tables retained in the raw-cache DB so existing raw readers and
    # inspections can still query normalized rows while the GUI transitions to the
    # per-sequence/per-parameter materialized tables.
    _ensure_test_data_tables(conn)


def eidat_support_dir(global_repo: Path) -> Path:
    repo = Path(global_repo).expanduser()
    existing: list[Path] = []
    for candidate in _candidate_eidat_support_dirs(repo):
        try:
            if candidate.is_dir():
                existing.append(candidate)
        except Exception:
            continue
    if existing:
        return max(existing, key=_eidat_support_dir_score)
    return _default_eidat_support_dir(repo)


def eidat_projects_root(global_repo: Path) -> Path:
    return eidat_support_dir(global_repo) / EIDAT_PROJECTS_DIRNAME


def ensure_trending_project_sqlite(project_dir: Path, workbook_path: Path) -> Path:
    """
    Ensure a project-local SQLite cache exists for the EIDP Trending workbook.

    The DB is stored inside the project folder and rebuilt if the workbook is newer.
    """
    proj_dir = Path(project_dir).expanduser()
    wb_path = Path(workbook_path).expanduser()
    if not wb_path.exists():
        raise FileNotFoundError(f"Workbook not found: {wb_path}")

    db_path = proj_dir / EIDAT_PROJECT_IMPLEMENTATION_DB
    rebuild = True

    if db_path.exists():
        try:
            db_mtime = db_path.stat().st_mtime
            wb_mtime = wb_path.stat().st_mtime
            rebuild = wb_mtime > db_mtime
        except Exception:
            rebuild = True

        if not rebuild:
            try:
                with sqlite3.connect(str(db_path)) as conn:
                    conn.row_factory = sqlite3.Row
                    tables = {
                        r["name"]
                        for r in conn.execute(
                            "SELECT name FROM sqlite_master WHERE type='table'"
                        ).fetchall()
                    }
                required = {"serials", "terms", "term_values", "meta"}
                if not required.issubset(tables):
                    rebuild = True
            except Exception:
                rebuild = True

    if rebuild:
        _build_trending_project_sqlite(db_path, wb_path)

    return db_path


def _sqlite_drop_table(conn: sqlite3.Connection, table: str) -> None:
    try:
        name = str(table or "").strip()
        if not name:
            return
        safe = name.replace('"', '""')
        conn.execute(f'DROP TABLE IF EXISTS "{safe}"')
    except Exception:
        pass


def _quote_ident(name: str) -> str:
    return '"' + str(name or "").replace('"', '""') + '"'


def load_trending_project_terms(db_path: Path) -> list[dict]:
    """Return available terms from the project SQLite cache."""
    path = Path(db_path).expanduser()
    if not path.exists():
        return []
    rows: list[dict] = []
    with sqlite3.connect(str(path)) as conn:
        conn.row_factory = sqlite3.Row
        try:
            fetched = conn.execute(
                """
                SELECT term_key, term, term_label, units, min_val, max_val, data_group, table_label, row_index
                FROM terms
                ORDER BY row_index ASC
                """
            ).fetchall()
        except Exception:
            # Backwards compat: older caches won't have the table_label column.
            fetched = conn.execute(
                """
                SELECT term_key, term, term_label, units, min_val, max_val, data_group, row_index
                FROM terms
                ORDER BY row_index ASC
                """
            ).fetchall()
        for r in fetched:
            rows.append(dict(r))
    return rows


def load_trending_project_serials(db_path: Path) -> list[str]:
    path = Path(db_path).expanduser()
    if not path.exists():
        return []
    with sqlite3.connect(str(path)) as conn:
        conn.row_factory = sqlite3.Row
        rows = conn.execute(
            "SELECT serial FROM serials ORDER BY position ASC"
        ).fetchall()
    return [str(r["serial"] or "").strip() for r in rows if str(r["serial"] or "").strip()]


def load_trending_project_series(db_path: Path, term_key: str) -> list[dict]:
    """Return list of dicts with serial + value for a single term_key."""
    path = Path(db_path).expanduser()
    if not path.exists():
        return []
    with sqlite3.connect(str(path)) as conn:
        conn.row_factory = sqlite3.Row
        rows = conn.execute(
            """
            SELECT v.serial, v.value_text, v.value_num
            FROM term_values v
            WHERE v.term_key = ?
            ORDER BY v.position ASC
            """,
            (str(term_key),),
        ).fetchall()
    return [dict(r) for r in rows]


def _build_trending_project_sqlite(db_path: Path, workbook_path: Path) -> None:
    """Build a SQLite cache from the EIDP Trending workbook."""
    try:
        from openpyxl import load_workbook  # type: ignore
    except Exception as exc:
        raise RuntimeError(
            "openpyxl is required to read the EIDP Trending workbook. "
            "Install it with `py -m pip install openpyxl` within the project environment."
        ) from exc

    wb_path = Path(workbook_path).expanduser()
    if not wb_path.exists():
        raise FileNotFoundError(f"Workbook not found: {wb_path}")

    def _to_float(value: object | None) -> float | None:
        if value is None:
            return None
        if isinstance(value, (int, float)):
            return float(value)
        text = str(value).strip()
        if not text:
            return None
        text = text.replace(",", "")
        try:
            return float(text)
        except Exception:
            pass
        m = re.search(r"[-+]?\d*\.?\d+(?:[eE][-+]?\d+)?", text)
        if not m:
            return None
        try:
            return float(m.group(0))
        except Exception:
            return None

    wb = load_workbook(str(wb_path), read_only=True, data_only=True)
    if "master" not in wb.sheetnames:
        raise RuntimeError("Workbook missing required 'master' sheet.")
    ws = wb["master"]

    rows = ws.iter_rows(values_only=True)
    try:
        header = next(rows)
    except StopIteration:
        raise RuntimeError("Workbook master sheet is empty.")

    header = list(header)
    header_norm = [_normalize_text(str(h or "")) for h in header]

    # Serial columns start after the final fixed column (Max).
    serial_start = 9  # legacy default: Term..Max (9 fixed cols)
    try:
        if "max" in header_norm:
            serial_start = int(header_norm.index("max") + 1)
    except Exception:
        serial_start = 9

    # Fixed column indices (by name; Table Label is optional).
    header_map: dict[str, int] = {}
    for idx, val in enumerate(header):
        key = _normalize_text(str(val or ""))
        if not key:
            continue
        header_map[key] = idx
        compact = key.replace(" ", "")
        if compact and compact not in header_map:
            header_map[compact] = idx

    def _h(name: str) -> int | None:
        key = _normalize_text(name)
        if key in header_map:
            return header_map[key]
        compact = key.replace(" ", "")
        return header_map.get(compact)

    idx_term = _h("Term") or 0
    idx_header = _h("Header") or 1
    idx_groupafter = _h("GroupAfter") or 2
    idx_table_label = _h("Table Label")
    idx_valuetype = _h("ValueType") or _h("Value Type") or 3
    idx_datagroup = _h("Data Group") or 4
    idx_termlabel = _h("Term Label") or 5
    idx_units = _h("Units") or 6
    idx_min = _h("Min") or 7
    idx_max = _h("Max") or 8
    serial_cols: list[tuple[int, str]] = []
    for idx in range(int(serial_start), len(header)):
        val = header[idx]
        sn = str(val).strip() if val is not None else ""
        if sn:
            serial_cols.append((idx, sn))
    serials = [sn for _, sn in serial_cols]

    db_path = Path(db_path).expanduser()
    db_path.parent.mkdir(parents=True, exist_ok=True)
    # IMPORTANT: Do not delete the entire DB file. This project cache DB may also hold
    # Test Data trending caches (td_*). Only drop/recreate the EIDP Trending tables.
    with sqlite3.connect(str(db_path)) as conn:
        for t in ("meta", "serials", "terms", "term_values"):
            _sqlite_drop_table(conn, t)

        conn.execute(
            """
            CREATE TABLE meta (
                key TEXT PRIMARY KEY,
                value TEXT
            )
            """
        )
        conn.execute(
            """
            CREATE TABLE serials (
                position INTEGER NOT NULL,
                serial TEXT NOT NULL
            )
            """
        )
        conn.execute(
            """
            CREATE TABLE terms (
                term_key TEXT PRIMARY KEY,
                term TEXT,
                header TEXT,
                groupafter TEXT,
                valuetype TEXT,
                data_group TEXT,
                term_label TEXT,
                table_label TEXT,
                units TEXT,
                min_val REAL,
                max_val REAL,
                row_index INTEGER
            )
            """
        )
        conn.execute(
            """
            CREATE TABLE term_values (
                term_key TEXT NOT NULL,
                serial TEXT NOT NULL,
                position INTEGER NOT NULL,
                value_text TEXT,
                value_num REAL
            )
            """
        )
        conn.execute("CREATE INDEX idx_values_term ON term_values(term_key)")
        conn.execute("CREATE INDEX idx_values_serial ON term_values(serial)")

        conn.execute("INSERT INTO meta (key, value) VALUES (?, ?)", ("workbook_path", str(wb_path)))
        try:
            wb_mtime = str(wb_path.stat().st_mtime)
        except Exception:
            wb_mtime = ""
        conn.execute("INSERT INTO meta (key, value) VALUES (?, ?)", ("workbook_mtime", wb_mtime))

        serial_rows = [(idx, sn) for idx, sn in enumerate(serials)]
        conn.executemany("INSERT INTO serials (position, serial) VALUES (?, ?)", serial_rows)

        row_index = 1  # header row is 1 in Excel
        term_rows: list[tuple] = []
        value_rows: list[tuple] = []

        for row in rows:
            row_index += 1
            if not row:
                continue
            row = list(row)
            term = str(row[idx_term] or "").strip() if idx_term < len(row) else ""
            if not term:
                continue
            header_val = str(row[idx_header] or "").strip() if idx_header < len(row) else ""
            group_after = str(row[idx_groupafter] or "").strip() if idx_groupafter < len(row) else ""
            table_label = str(row[idx_table_label] or "").strip() if idx_table_label is not None and idx_table_label < len(row) else ""
            value_type = str(row[idx_valuetype] or "").strip() if idx_valuetype < len(row) else ""
            data_group = str(row[idx_datagroup] or "").strip() if idx_datagroup < len(row) else ""
            term_label = str(row[idx_termlabel] or "").strip() if idx_termlabel < len(row) else ""
            units = str(row[idx_units] or "").strip() if idx_units < len(row) else ""
            min_val = _to_float(row[idx_min] if idx_min < len(row) else None)
            max_val = _to_float(row[idx_max] if idx_max < len(row) else None)

            term_key = f"{term}__row_{row_index}"
            term_rows.append(
                (
                    term_key,
                    term,
                    header_val,
                    group_after,
                    value_type,
                    data_group,
                    term_label,
                    table_label,
                    units,
                    min_val,
                    max_val,
                    row_index,
                )
            )

            for pos, (col_idx, sn) in enumerate(serial_cols):
                if col_idx >= len(row):
                    cell_val = None
                else:
                    cell_val = row[col_idx]
                val_text = "" if cell_val is None else str(cell_val)
                val_num = _to_float(cell_val)
                value_rows.append((term_key, sn, pos, val_text, val_num))

        if term_rows:
            conn.executemany(
                """
                INSERT INTO terms (
                    term_key, term, header, groupafter, valuetype,
                    data_group, term_label, table_label, units, min_val, max_val, row_index
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                term_rows,
            )
        if value_rows:
            conn.executemany(
                """
                INSERT INTO term_values (
                    term_key, serial, position, value_text, value_num
                ) VALUES (?, ?, ?, ?, ?)
                """,
                value_rows,
            )
        conn.commit()

    try:
        wb.close()
    except Exception:
        pass


def _infer_node_root_from_workbook_path(workbook_path: Path) -> Path:
    """
    Best-effort: if workbook lives under:
      - `<node_root>/EIDAT Support/...` (legacy), or
      - `<node_root>/EIDAT/.../EIDAT Support/...` (current/nested),
    return `<node_root>`.
    Otherwise, return workbook parent.
    """
    p = Path(workbook_path).expanduser()
    try:
        p = p.resolve()
    except Exception:
        p = p.absolute()
    cur = p.parent
    for _ in range(12):
        if cur.name.strip().casefold() in {name.casefold() for name in _EIDAT_SUPPORT_DIR_NAMES}:
            base = cur.parent
            while base.name.strip().casefold() in {name.casefold() for name in _EIDAT_CONTAINER_DIR_NAMES}:
                base = base.parent
            return base
        if cur == cur.parent:
            break
        cur = cur.parent
    return p.parent


def _read_project_meta(project_dir: Path) -> dict:
    pj = Path(project_dir).expanduser() / EIDAT_PROJECT_META
    try:
        raw = json.loads(pj.read_text(encoding="utf-8"))
    except Exception:
        return {}
    return dict(raw) if isinstance(raw, dict) else {}


def _write_project_meta(project_dir: Path, meta: Mapping[str, object]) -> dict[str, object]:
    proj_dir = Path(project_dir).expanduser()
    proj_dir.mkdir(parents=True, exist_ok=True)
    payload = dict(meta or {})
    (proj_dir / EIDAT_PROJECT_META).write_text(json.dumps(payload, indent=2), encoding="utf-8")
    return payload


def td_trend_open_status_path(project_dir: Path) -> Path:
    return Path(project_dir).expanduser() / TD_TREND_OPEN_STATUS_FILENAME


def _td_file_mtime_ns(path: Path) -> int:
    try:
        st = Path(path).expanduser().stat()
    except Exception:
        return 0
    return int(getattr(st, "st_mtime_ns", int(st.st_mtime * 1e9)))


def _td_epoch_ns_text(epoch_ns: object) -> str:
    try:
        epoch_ns_int = int(epoch_ns or 0)
    except Exception:
        epoch_ns_int = 0
    if epoch_ns_int <= 0:
        return ""
    try:
        return datetime.fromtimestamp(epoch_ns_int / 1_000_000_000).strftime("%Y-%m-%d %H:%M:%S")
    except Exception:
        return ""


def _normalize_td_trend_open_status_snapshot(raw: Mapping[str, object] | None) -> dict[str, object]:
    source = dict(raw or {}) if isinstance(raw, Mapping) else {}
    tracked_paths = [
        str(value).strip()
        for value in (source.get("tracked_paths") or [])
        if str(value).strip()
    ]
    project_stamp_epoch_ns = int(source.get("project_stamp_epoch_ns") or 0)
    project_stamp_text = str(source.get("project_stamp_text") or "").strip() or _td_epoch_ns_text(project_stamp_epoch_ns)
    stamp_source_path = str(source.get("stamp_source_path") or "").strip()
    return {
        "version": int(source.get("version") or TD_TREND_OPEN_STATUS_VERSION),
        "project_stamp_epoch_ns": project_stamp_epoch_ns,
        "project_stamp_text": project_stamp_text,
        "tracked_paths": tracked_paths,
        "stamp_source_path": stamp_source_path,
    }


def collect_test_data_trend_open_project_stamp(project_dir: Path, workbook_path: Path) -> dict[str, object]:
    proj_dir = Path(project_dir).expanduser()
    wb_path = Path(workbook_path).expanduser()
    if not wb_path.exists():
        raise FileNotFoundError(f"Project workbook not found: {wb_path}")

    tracked_paths = [
        str(wb_path),
        str(proj_dir / EIDAT_PROJECT_META),
    ]
    project_stamp_epoch_ns = 0
    stamp_source_path = ""
    for path_txt in tracked_paths:
        stamp_ns = _td_file_mtime_ns(Path(path_txt).expanduser())
        if stamp_ns > project_stamp_epoch_ns:
            project_stamp_epoch_ns = stamp_ns
            stamp_source_path = path_txt
    if project_stamp_epoch_ns <= 0:
        project_stamp_epoch_ns = _td_file_mtime_ns(wb_path)
        stamp_source_path = str(wb_path) if project_stamp_epoch_ns > 0 else ""
    return {
        "project_stamp_epoch_ns": int(project_stamp_epoch_ns),
        "project_stamp_text": _td_epoch_ns_text(project_stamp_epoch_ns),
        "tracked_paths": list(tracked_paths),
        "stamp_source_path": stamp_source_path,
    }


def read_test_data_trend_open_status(project_dir: Path) -> dict[str, object]:
    snapshot_path = td_trend_open_status_path(project_dir)
    try:
        raw = json.loads(snapshot_path.read_text(encoding="utf-8"))
    except Exception:
        return {}
    if not isinstance(raw, Mapping):
        return {}
    normalized = _normalize_td_trend_open_status_snapshot(raw)
    if int(normalized.get("project_stamp_epoch_ns") or 0) <= 0:
        return {}
    normalized["snapshot_path"] = str(snapshot_path)
    return normalized


def write_test_data_trend_open_status(project_dir: Path, workbook_path: Path) -> dict[str, object]:
    proj_dir = Path(project_dir).expanduser()
    snapshot_path = td_trend_open_status_path(proj_dir)
    stamp = collect_test_data_trend_open_project_stamp(proj_dir, workbook_path)
    payload = {
        "version": TD_TREND_OPEN_STATUS_VERSION,
        "project_stamp_epoch_ns": int(stamp.get("project_stamp_epoch_ns") or 0),
        "project_stamp_text": str(stamp.get("project_stamp_text") or "").strip(),
        "tracked_paths": list(stamp.get("tracked_paths") or []),
        "stamp_source_path": str(stamp.get("stamp_source_path") or "").strip(),
    }
    proj_dir.mkdir(parents=True, exist_ok=True)
    snapshot_path.write_text(json.dumps(payload, indent=2), encoding="utf-8")
    normalized = _normalize_td_trend_open_status_snapshot(payload)
    normalized["snapshot_path"] = str(snapshot_path)
    return normalized


def inspect_test_data_trend_open_status(project_dir: Path, workbook_path: Path) -> dict[str, object]:
    proj_dir = Path(project_dir).expanduser()
    snapshot_path = td_trend_open_status_path(proj_dir)
    current = collect_test_data_trend_open_project_stamp(proj_dir, workbook_path)
    saved = read_test_data_trend_open_status(proj_dir)
    snapshot_exists = bool(saved)
    current_stamp_epoch_ns = int(current.get("project_stamp_epoch_ns") or 0)
    saved_stamp_epoch_ns = int(saved.get("project_stamp_epoch_ns") or 0)
    return {
        "snapshot_path": str(snapshot_path),
        "snapshot_exists": snapshot_exists,
        "current_project_stamp_epoch_ns": current_stamp_epoch_ns,
        "current_project_stamp_text": str(current.get("project_stamp_text") or "").strip(),
        "current_tracked_paths": list(current.get("tracked_paths") or []),
        "current_stamp_source_path": str(current.get("stamp_source_path") or "").strip(),
        "saved_project_stamp_epoch_ns": saved_stamp_epoch_ns,
        "saved_project_stamp_text": str(saved.get("project_stamp_text") or "").strip(),
        "saved_tracked_paths": list(saved.get("tracked_paths") or []),
        "saved_stamp_source_path": str(saved.get("stamp_source_path") or "").strip(),
        "is_newer_than_snapshot": bool(snapshot_exists and current_stamp_epoch_ns > saved_stamp_epoch_ns),
    }


def _td_param_norm_name(value: object) -> str:
    return "".join(ch.lower() for ch in str(value or "").strip() if ch.isalnum())


def _td_param_norm_program(value: object) -> str:
    text = re.sub(r"\s+", " ", str(value or "").strip())
    return text.casefold()


def _td_parameter_tokens(value: object) -> list[str]:
    return [token for token in re.findall(r"[a-z0-9]+", str(value or "").strip().lower()) if token]


def td_parameter_selector_is_canonical(value: object) -> bool:
    return str(value or "").strip().lower().startswith(TD_PARAMETER_SELECTOR_CANONICAL_PREFIX)


def td_parameter_selector_canonical_id(value: object) -> str:
    raw = str(value or "").strip()
    if td_parameter_selector_is_canonical(raw):
        return raw[len(TD_PARAMETER_SELECTOR_CANONICAL_PREFIX):].strip()
    return ""


def td_parameter_selector_value(canonical_id: object) -> str:
    cid = str(canonical_id or "").strip()
    return f"{TD_PARAMETER_SELECTOR_CANONICAL_PREFIX}{cid}" if cid else ""


def _td_parameter_implicit_canonical_id(raw_name: object) -> str:
    text = str(raw_name or "").strip()
    norm = _td_param_norm_name(text)
    if norm:
        return f"raw:{norm}"
    if not text:
        return "raw:blank"
    return "raw:" + hashlib.sha1(text.encode("utf-8")).hexdigest()[:12]


def _td_parameter_normalization_group_id(seed: object = "") -> str:
    text = str(seed or "").strip()
    norm = _td_param_norm_name(text)
    if norm:
        return f"group:{norm}:{uuid.uuid4().hex[:8]}"
    return f"group:{uuid.uuid4().hex}"


def _td_parameter_units_compatible(units_a: Sequence[object] | None, units_b: object) -> bool:
    a_norms = {_td_param_norm_name(value) for value in (units_a or []) if _td_param_norm_name(value)}
    b_norm = _td_param_norm_name(units_b)
    if not a_norms or not b_norm:
        return True
    return b_norm in a_norms


def _td_parameter_display_name_for_group(
    normalization: Mapping[str, object] | None,
    canonical_id: object,
    *,
    raw_names: Sequence[object] | None = None,
    fallback: object = "",
) -> str:
    groups_by_id = (
        normalization.get("groups_by_id")
        if isinstance(normalization, Mapping) and isinstance(normalization.get("groups_by_id"), Mapping)
        else {}
    )
    group = dict(groups_by_id.get(str(canonical_id or "").strip()) or {})
    display_name = str(group.get("display_name") or "").strip()
    if display_name:
        return display_name
    for raw_name in (raw_names or []):
        text = str(raw_name or "").strip()
        if text:
            return text
    return str(fallback or "").strip()


_TD_PARAMETER_SIMILARITY_STOPWORDS = {
    "a",
    "an",
    "and",
    "at",
    "for",
    "in",
    "of",
    "on",
    "the",
    "to",
}


def _td_parameter_similarity_tokens(value: object) -> list[str]:
    tokens = _td_parameter_tokens(value)
    filtered = [token for token in tokens if token not in _TD_PARAMETER_SIMILARITY_STOPWORDS]
    return filtered or tokens


def _td_parameter_names_similar(lhs: object, rhs: object) -> bool:
    lhs_text = str(lhs or "").strip()
    rhs_text = str(rhs or "").strip()
    lhs_norm = _td_param_norm_name(lhs_text)
    rhs_norm = _td_param_norm_name(rhs_text)
    if not lhs_norm or not rhs_norm:
        return False
    if lhs_norm == rhs_norm:
        return True
    lhs_tokens = _td_parameter_similarity_tokens(lhs_text)
    rhs_tokens = _td_parameter_similarity_tokens(rhs_text)
    if not lhs_tokens or not rhs_tokens:
        return SequenceMatcher(None, lhs_norm, rhs_norm).ratio() >= 0.9
    lhs_digits = [token for token in lhs_tokens if token.isdigit()]
    rhs_digits = [token for token in rhs_tokens if token.isdigit()]
    if lhs_digits and rhs_digits and lhs_digits != rhs_digits:
        return False
    lhs_set = set(lhs_tokens)
    rhs_set = set(rhs_tokens)
    overlap = len(lhs_set & rhs_set)
    min_count = min(len(lhs_set), len(rhs_set))
    raw_ratio = SequenceMatcher(None, lhs_norm, rhs_norm).ratio()
    token_ratio = SequenceMatcher(None, "".join(lhs_tokens), "".join(rhs_tokens)).ratio()
    best_ratio = max(raw_ratio, token_ratio)
    if min_count and overlap >= max(1, min_count - 1):
        return True
    if best_ratio >= 0.9:
        return True
    return bool(
        lhs_digits == rhs_digits
        and lhs_digits
        and overlap >= max(1, min_count - 2)
        and best_ratio >= 0.82
    )


def _td_parameter_display_candidate_sort_key(
    display_name: object,
    *,
    units: object = "",
) -> tuple[int, int, int, int, int]:
    text = str(display_name or "").strip()
    tokens = _td_parameter_similarity_tokens(text)
    alpha_words = sum(1 for token in tokens if token.isalpha() and len(token) >= 3)
    score = 0
    if str(units or "").strip():
        score += 10
    if " " in text:
        score += 4
    if "/" in text:
        score += 2
    if "(" in text or ")" in text:
        score += 1
    if alpha_words >= 2:
        score += 1
    score += min(len(tokens), 4)
    score -= text.count("_") * 2
    score -= text.count("-")
    if text.isupper() and any(ch.isalpha() for ch in text):
        score -= 1
    return (
        score,
        len(set(tokens)),
        len(text),
        -text.count("_"),
        -text.count("-"),
    )


def _td_parameter_config_candidates_from_defs(
    param_defs: Sequence[Mapping[str, object]] | None,
) -> list[dict[str, object]]:
    out: list[dict[str, object]] = []
    for column in (param_defs or []):
        if not isinstance(column, Mapping):
            continue
        display_name = str(column.get("name") or "").strip()
        if not display_name:
            continue
        aliases = [display_name]
        aliases.extend(
            [str(value).strip() for value in (column.get("aliases") or []) if str(value).strip()]
        )
        out.append(
            {
                "display_name": display_name,
                "units": str(column.get("units") or "").strip(),
                "aliases": aliases,
            }
        )
    return out


def _td_normalize_parameter_normalization(raw: object) -> dict[str, object]:
    payload = raw if isinstance(raw, Mapping) else {}
    groups_raw = payload.get("groups") if isinstance(payload.get("groups"), list) else []
    rules_raw = payload.get("mappings")
    if not isinstance(rules_raw, list):
        rules_raw = payload.get("rules") if isinstance(payload.get("rules"), list) else []
    groups: list[dict[str, object]] = []
    groups_by_id: dict[str, dict[str, object]] = {}
    for item in groups_raw:
        if not isinstance(item, Mapping):
            continue
        group_id = str(item.get("id") or "").strip() or _td_parameter_normalization_group_id(item.get("display_name"))
        display_name = str(item.get("display_name") or item.get("name") or "").strip()
        preferred_units = str(item.get("preferred_units") or item.get("units") or "").strip()
        group = {
            "id": group_id,
            "display_name": display_name,
            "preferred_units": preferred_units,
        }
        groups.append(group)
        groups_by_id[group_id] = dict(group)
    mappings: list[dict[str, object]] = []
    seen_rules: set[tuple[str, str, tuple[str, ...], tuple[str, ...], tuple[str, ...]]] = set()
    for item in rules_raw or []:
        if not isinstance(item, Mapping):
            continue
        displayed_parameter = str(
            item.get("displayed_parameter")
            or item.get("display_name")
            or ""
        ).strip()
        canonical_id = str(item.get("canonical_id") or "").strip() or _td_program_parameter_canonical_id(displayed_parameter)
        raw_name = str(item.get("raw_name") or item.get("name") or "").strip()
        if not canonical_id or not raw_name:
            continue
        if canonical_id not in groups_by_id:
            groups_by_id[canonical_id] = {
                "id": canonical_id,
                "display_name": displayed_parameter,
                "preferred_units": str(item.get("preferred_units") or item.get("units") or "").strip(),
            }
            groups.append(dict(groups_by_id[canonical_id]))
        program_titles = item.get("program_titles")
        if not isinstance(program_titles, list):
            program_titles = item.get("programs") if isinstance(item.get("programs"), list) else []
        asset_types = item.get("asset_types")
        if not isinstance(asset_types, list):
            asset_types = [item.get("asset_type")] if str(item.get("asset_type") or "").strip() else []
        asset_specific_types = item.get("asset_specific_types")
        if not isinstance(asset_specific_types, list):
            asset_specific_types = [item.get("asset_specific_type")] if str(item.get("asset_specific_type") or "").strip() else []
        programs_clean: list[str] = []
        seen_programs: set[str] = set()
        for value in (program_titles or []):
            text = str(value or "").strip()
            norm = _td_param_norm_program(text)
            if text and norm not in seen_programs:
                seen_programs.add(norm)
                programs_clean.append(text)
        assets_clean: list[str] = []
        seen_assets: set[str] = set()
        for value in (asset_types or []):
            text = _td_program_parameter_scope_text(value)
            norm = _td_param_norm_program(text)
            if text and norm not in seen_assets:
                seen_assets.add(norm)
                assets_clean.append(text)
        asset_specific_clean: list[str] = []
        seen_asset_specific: set[str] = set()
        for value in (asset_specific_types or []):
            text = _td_program_parameter_scope_text(value)
            norm = _td_param_norm_program(text)
            if text and norm not in seen_asset_specific:
                seen_asset_specific.add(norm)
                asset_specific_clean.append(text)
        rule_key = (
            canonical_id,
            _td_param_norm_name(raw_name),
            tuple(sorted(_td_param_norm_program(v) for v in programs_clean)),
            tuple(sorted(_td_param_norm_program(v) for v in assets_clean)),
            tuple(sorted(_td_param_norm_program(v) for v in asset_specific_clean)),
        )
        if rule_key in seen_rules:
            continue
        seen_rules.add(rule_key)
        if displayed_parameter:
            groups_by_id[canonical_id]["display_name"] = displayed_parameter
        preferred_units = str(item.get("preferred_units") or item.get("units") or groups_by_id[canonical_id].get("preferred_units") or "").strip()
        if preferred_units:
            groups_by_id[canonical_id]["preferred_units"] = preferred_units
        mappings.append(
            {
                "canonical_id": canonical_id,
                "raw_name": raw_name,
                "program_titles": programs_clean,
                "asset_types": assets_clean,
                "asset_specific_types": asset_specific_clean,
                "default_display_parameter": str(item.get("default_display_parameter") or "").strip(),
                "displayed_parameter": displayed_parameter,
                "preferred_units": preferred_units,
                "enabled": _td_bool(item.get("enabled"), True),
                "edited": bool(item.get("edited")),
            }
        )
    groups = [
        dict(groups_by_id.get(str(group.get("id") or "").strip()) or group)
        for group in groups
        if str(group.get("id") or "").strip()
    ]
    return {
        "version": int(payload.get("version") or TD_PARAMETER_NORMALIZATION_VERSION),
        "groups": groups,
        "groups_by_id": groups_by_id,
        "mappings": mappings,
    }


def _td_parameter_normalization_persistable(normalization: Mapping[str, object] | None) -> dict[str, object]:
    normalized = _td_normalize_parameter_normalization(normalization)
    return {
        "version": int(normalized.get("version") or TD_PARAMETER_NORMALIZATION_VERSION),
        "groups": [
            {
                "id": str(group.get("id") or "").strip(),
                "display_name": str(group.get("display_name") or "").strip(),
                "preferred_units": str(group.get("preferred_units") or "").strip(),
            }
            for group in (normalized.get("groups") or [])
            if isinstance(group, Mapping) and str(group.get("id") or "").strip()
        ],
        "mappings": [
            {
                "canonical_id": str(rule.get("canonical_id") or "").strip(),
                "raw_name": str(rule.get("raw_name") or "").strip(),
                "program_titles": [
                    str(value).strip()
                    for value in (rule.get("program_titles") or [])
                    if str(value).strip()
                ],
                "asset_types": [
                    str(value).strip()
                    for value in (rule.get("asset_types") or [])
                    if str(value).strip()
                ],
                "asset_specific_types": [
                    str(value).strip()
                    for value in (rule.get("asset_specific_types") or [])
                    if str(value).strip()
                ],
                "default_display_parameter": str(rule.get("default_display_parameter") or "").strip(),
                "displayed_parameter": str(rule.get("displayed_parameter") or "").strip(),
                "preferred_units": str(rule.get("preferred_units") or "").strip(),
                "enabled": _td_bool(rule.get("enabled"), True),
                "edited": bool(rule.get("edited")),
            }
            for rule in (normalized.get("mappings") or [])
            if isinstance(rule, Mapping)
            and str(rule.get("canonical_id") or "").strip()
            and str(rule.get("raw_name") or "").strip()
        ],
    }


def _td_project_global_repo(
    project_dir: Path,
    *,
    workbook_path: Path | None = None,
) -> Path | None:
    proj_dir = Path(project_dir).expanduser()
    meta_path = proj_dir / EIDAT_PROJECT_META
    meta = _read_project_meta(proj_dir)
    raw = str(meta.get("global_repo") or "").strip()
    if raw:
        return Path(raw).expanduser()

    def _coerce_workbook_path(value: object) -> Path | None:
        text = str(value or "").strip()
        if not text:
            return None
        candidate = Path(text).expanduser()
        if not candidate.is_absolute():
            candidate = proj_dir / candidate
        return candidate

    workbook = _coerce_workbook_path(workbook_path)
    if workbook is None:
        workbook = _coerce_workbook_path(meta.get("workbook"))
    if workbook is None:
        return None

    try:
        repo = resolve_test_data_project_global_repo(proj_dir, workbook)
    except Exception:
        return None
    resolved_repo = Path(repo).expanduser()

    if meta_path.exists():
        updated_meta = dict(meta)
        updated = False
        if not str(updated_meta.get("global_repo") or "").strip():
            updated_meta["global_repo"] = str(resolved_repo)
            updated = True
        if not str(updated_meta.get("workbook") or "").strip():
            updated_meta["workbook"] = str(workbook)
            updated = True
        if updated:
            try:
                _write_project_meta(proj_dir, updated_meta)
            except Exception:
                pass
    return resolved_repo


def _td_project_program_titles(
    project_dir: Path,
    *,
    workbook_path: Path | None = None,
    db_path: Path | None = None,
) -> list[str]:
    proj_dir = Path(project_dir).expanduser()
    programs: set[str] = set()
    impl_db = Path(db_path).expanduser() if db_path else (proj_dir / EIDAT_PROJECT_IMPLEMENTATION_DB)
    if impl_db.exists():
        try:
            with closing(sqlite3.connect(str(impl_db))) as conn:
                _ensure_test_data_impl_tables(conn)
                rows = conn.execute(
                    """
                    SELECT DISTINCT program_title
                    FROM td_source_metadata
                    WHERE TRIM(COALESCE(program_title, '')) <> ''
                    ORDER BY program_title
                    """
                ).fetchall()
            programs.update(str(row[0] or "").strip() for row in rows if str(row[0] or "").strip())
        except Exception:
            pass
    if programs:
        return sorted(programs, key=str.casefold)
    repo = _td_project_global_repo(proj_dir, workbook_path=workbook_path)
    if repo is None:
        return []
    meta = _read_project_meta(proj_dir)
    selected_rels = [
        str(value).strip()
        for value in (meta.get("selected_metadata_rel") or [])
        if str(value).strip()
    ]
    if not selected_rels:
        return []
    try:
        docs = read_eidat_index_documents(repo)
    except Exception:
        return []
    wanted = {value.casefold() for value in selected_rels}
    for doc in docs:
        if not isinstance(doc, Mapping):
            continue
        metadata_rel = str(doc.get("metadata_rel") or "").strip()
        program_title = str(doc.get("program_title") or "").strip()
        if metadata_rel and metadata_rel.casefold() in wanted and program_title:
            programs.add(program_title)
    return sorted(programs, key=str.casefold)


def load_td_repo_parameter_mappings(
    project_dir: Path,
    *,
    workbook_path: Path | None = None,
    db_path: Path | None = None,
) -> list[dict[str, object]]:
    proj_dir = Path(project_dir).expanduser()
    repo = _td_project_global_repo(proj_dir, workbook_path=workbook_path)
    if repo is None:
        return []
    rows: list[dict[str, object]] = []
    seen: set[tuple[str, str, str, str]] = set()
    for program_title in _td_project_program_titles(
        proj_dir,
        workbook_path=workbook_path,
        db_path=db_path,
    ):
        workbook_file = td_program_requirements_workbook_path_for(repo, program_title)
        if not workbook_file.exists():
            continue
        try:
            workbook_rows = _td_program_requirements_read_parameter_mappings(workbook_file)
        except Exception:
            continue
        for row in workbook_rows:
            normalized = _td_program_parameter_mapping_normalize(row, program_title=program_title)
            key = _td_program_parameter_scope_key(
                normalized.get("program_title"),
                normalized.get("asset_type"),
                normalized.get("asset_specific_type"),
                normalized.get("ingested_parameter"),
            )
            if not key[-1] or key in seen:
                continue
            seen.add(key)
            rows.append(normalized)
    return sorted(rows, key=_td_program_parameter_mapping_sort_key)


def save_td_repo_parameter_mappings(
    project_dir: Path,
    rows: Sequence[Mapping[str, object]] | None,
    *,
    workbook_path: Path | None = None,
) -> list[dict[str, object]]:
    proj_dir = Path(project_dir).expanduser()
    repo = _td_project_global_repo(proj_dir, workbook_path=workbook_path)
    if repo is None:
        raise RuntimeError("Project is missing its Global Repo path.")
    normalized_rows: list[dict[str, object]] = []
    for row in (rows or []):
        committed = _td_program_parameter_mapping_commit(row)
        if committed:
            normalized_rows.append(committed)
    rows_by_program: dict[str, list[dict[str, object]]] = {}
    for row in normalized_rows:
        program_title = str(row.get("program_title") or "").strip() or TD_SUPPORT_DEFAULT_PROGRAM_TITLE
        rows_by_program.setdefault(program_title, []).append(row)
    for program_title, program_rows in rows_by_program.items():
        workbook_file = td_program_requirements_workbook_path_for(repo, program_title)
        existing_conditions: list[dict[str, object]] = []
        if workbook_file.exists():
            try:
                from openpyxl import load_workbook  # type: ignore
            except Exception as exc:
                raise RuntimeError(
                    "openpyxl is required to update ProgramRequirements workbooks. "
                    "Install it with `py -m pip install openpyxl` within the project environment."
                ) from exc
            wb = load_workbook(str(workbook_file))
            try:
                state = _td_program_requirements_parse_workbook(wb)
            finally:
                try:
                    wb.close()
                except Exception:
                    pass
            existing_conditions = [
                dict(item)
                for item in (state.get("conditions") or [])
                if isinstance(item, Mapping)
            ]
        _td_program_requirements_write_workbook(
            workbook_file,
            program_title=program_title,
            discovered_conditions=existing_conditions,
            parameter_mappings=program_rows,
        )
    return sorted(normalized_rows, key=_td_program_parameter_mapping_sort_key)


def refresh_td_parameter_support_workbook(
    project_dir: Path,
    workbook_path: Path,
    db_path: Path,
    progress_cb: Callable[[str], None] | None = None,
) -> dict[str, object]:
    proj_dir = Path(project_dir).expanduser()
    workbook = Path(workbook_path).expanduser()
    impl_db = Path(db_path).expanduser()
    repo = _td_project_global_repo(proj_dir, workbook_path=workbook)
    if repo is None:
        raise RuntimeError("Project is missing its Global Repo path.")

    project_cfg = _load_project_td_trend_config(workbook)
    cfg_cols = [dict(c) for c in (project_cfg.get("columns") or []) if isinstance(c, dict)]

    _td_emit_progress(progress_cb, "Refreshing support workbook program sheets")
    support_refresh = _sync_td_support_workbook_program_sheets(
        workbook,
        global_repo=repo,
        project_dir=proj_dir,
        param_defs=cfg_cols,
    )

    _td_emit_progress(progress_cb, "Consolidating support workbook run conditions")
    run_conditions_refresh = _refresh_td_support_run_conditions_sheet(
        workbook,
        project_dir=proj_dir,
        param_defs=cfg_cols,
    )

    docs: list[dict[str, object]] = []
    try:
        selected_rels = _project_selected_metadata_rels(proj_dir)
    except Exception:
        selected_rels = set()
    if selected_rels:
        try:
            docs = [
                dict(doc)
                for doc in read_eidat_index_documents(repo)
                if isinstance(doc, Mapping)
                and str(doc.get("metadata_rel") or "").strip() in selected_rels
            ]
        except Exception:
            docs = []
    if not docs:
        docs = [
            {"program_title": title}
            for title in _td_project_program_titles(
                proj_dir,
                workbook_path=workbook,
                db_path=impl_db,
            )
            if str(title).strip()
        ]

    _td_emit_progress(progress_cb, "Importing ProgramRequirements into support workbook")
    program_requirements_import = _sync_td_support_program_requirements_import(
        workbook,
        global_repo=repo,
        project_dir=proj_dir,
        docs=docs,
    )

    return {
        "support_refresh": dict(support_refresh),
        "run_conditions_refresh": dict(run_conditions_refresh),
        "program_requirements_import": dict(program_requirements_import),
    }


def load_td_project_parameter_normalization(project_dir: Path) -> dict[str, object]:
    meta = _read_project_meta(Path(project_dir).expanduser())
    return _td_project_parameter_group_catalog(meta.get(TD_PARAMETER_NORMALIZATION_KEY))


def save_td_project_parameter_normalization(project_dir: Path, normalization: Mapping[str, object] | None) -> dict[str, object]:
    proj_dir = Path(project_dir).expanduser()
    meta = _read_project_meta(proj_dir)
    payload = _td_parameter_normalization_persistable(_td_project_parameter_group_catalog(normalization))
    meta[TD_PARAMETER_NORMALIZATION_KEY] = payload
    _write_project_meta(proj_dir, meta)
    return _td_project_parameter_group_catalog(payload)


def _td_project_parameter_group_catalog(normalization: Mapping[str, object] | object | None) -> dict[str, object]:
    normalized = _td_normalize_parameter_normalization(normalization)
    return _td_normalize_parameter_normalization(
        {
            "version": int(normalized.get("version") or TD_PARAMETER_NORMALIZATION_VERSION),
            "groups": [
                {
                    "id": str(group.get("id") or "").strip(),
                    "display_name": str(group.get("display_name") or "").strip(),
                    "preferred_units": str(group.get("preferred_units") or "").strip(),
                }
                for group in (normalized.get("groups") or [])
                if isinstance(group, Mapping) and str(group.get("id") or "").strip()
            ],
            "mappings": [],
        }
    )


def _td_project_parameter_group_overrides(
    project_dir: Path,
    normalization: Mapping[str, object] | None,
    *,
    canonical_groups: Mapping[str, Mapping[str, object]] | None = None,
) -> tuple[dict[str, object], dict[str, dict[str, object]]]:
    normalized = _td_normalize_parameter_normalization(normalization)
    project_catalog = load_td_project_parameter_normalization(project_dir)
    override_groups_by_id: dict[str, dict[str, object]] = {
        str(group.get("id") or "").strip(): {
            "id": str(group.get("id") or "").strip(),
            "display_name": str(group.get("display_name") or "").strip(),
            "preferred_units": str(group.get("preferred_units") or "").strip(),
        }
        for group in (project_catalog.get("groups") or [])
        if isinstance(group, Mapping) and str(group.get("id") or "").strip()
    }
    merged_normalization = dict(normalized)
    merged_groups_by_id: dict[str, dict[str, object]] = {
        str(key): dict(value)
        for key, value in dict(normalized.get("groups_by_id") or {}).items()
        if str(key).strip() and isinstance(value, Mapping)
    }
    for canonical_id, override in override_groups_by_id.items():
        merged_group = dict(merged_groups_by_id.get(canonical_id) or {"id": canonical_id})
        if not str(merged_group.get("display_name") or "").strip() and str(override.get("display_name") or "").strip():
            merged_group["display_name"] = str(override.get("display_name") or "").strip()
        if not str(merged_group.get("preferred_units") or "").strip() and str(override.get("preferred_units") or "").strip():
            merged_group["preferred_units"] = str(override.get("preferred_units") or "").strip()
        merged_groups_by_id[canonical_id] = merged_group
    merged_groups: list[dict[str, object]] = []
    seen_group_ids: set[str] = set()
    for group in (normalized.get("groups") or []):
        if not isinstance(group, Mapping):
            continue
        canonical_id = str(group.get("id") or "").strip()
        if not canonical_id or canonical_id in seen_group_ids:
            continue
        seen_group_ids.add(canonical_id)
        merged_groups.append(dict(merged_groups_by_id.get(canonical_id) or group))
    for canonical_id, group in merged_groups_by_id.items():
        if canonical_id in seen_group_ids:
            continue
        merged_groups.append(dict(group))
    merged_normalization["groups_by_id"] = merged_groups_by_id
    merged_normalization["groups"] = merged_groups
    merged_canonical_groups: dict[str, dict[str, object]] = {
        str(key): dict(value)
        for key, value in dict(canonical_groups or {}).items()
        if str(key).strip() and isinstance(value, Mapping)
    }
    for canonical_id, group in merged_canonical_groups.items():
        override = dict(override_groups_by_id.get(canonical_id) or {})
        if not override:
            continue
        if not str(group.get("display_name") or "").strip() and str(override.get("display_name") or "").strip():
            group["display_name"] = str(override.get("display_name") or "").strip()
        preferred_units = str(override.get("preferred_units") or "").strip()
        if not str(group.get("preferred_units") or "").strip() and preferred_units:
            group["preferred_units"] = preferred_units
        if preferred_units:
            group["unit_conflict"] = False
        merged_canonical_groups[canonical_id] = group
    return merged_normalization, merged_canonical_groups


def _td_parameter_group_units(units: Sequence[object] | None) -> str:
    distinct = sorted(
        {
            str(value or "").strip()
            for value in (units or [])
            if str(value or "").strip()
        },
        key=str.casefold,
    )
    return distinct[0] if len(distinct) == 1 else ""


def _td_parameter_group_has_conflict(units: Sequence[object] | None, preferred_units: object = "") -> bool:
    if str(preferred_units or "").strip():
        return False
    distinct = {
        str(value or "").strip()
        for value in (units or [])
        if str(value or "").strip()
    }
    return len(distinct) > 1


def td_rebuild_project_parameter_units_catalog(
    project_dir: Path,
    repo_rows: Sequence[Mapping[str, object]] | None,
) -> dict[str, object]:
    groups_by_id: dict[str, dict[str, object]] = {}
    for raw_row in (repo_rows or []):
        row = _td_program_parameter_mapping_normalize(raw_row)
        if not row:
            continue
        display_name = _td_program_parameter_effective_display(row)
        canonical_id = _td_program_parameter_canonical_id(display_name)
        if not canonical_id:
            continue
        group = groups_by_id.setdefault(
            canonical_id,
            {
                "id": canonical_id,
                "display_name": display_name,
                "_units": set(),
            },
        )
        if display_name:
            group["display_name"] = display_name
        units_text = str(row.get("preferred_units") or "").strip()
        if units_text:
            cast(set[str], group["_units"]).add(units_text)
    groups = []
    for canonical_id, group in sorted(groups_by_id.items(), key=lambda item: str(item[1].get("display_name") or item[0]).casefold()):
        groups.append(
            {
                "id": canonical_id,
                "display_name": str(group.get("display_name") or "").strip(),
                "preferred_units": _td_parameter_group_units(sorted(cast(set[str], group.get("_units") or set()), key=str.casefold)),
            }
        )
    return save_td_project_parameter_normalization(
        project_dir,
        {
            "version": TD_PARAMETER_NORMALIZATION_VERSION,
            "groups": groups,
            "mappings": [],
        },
    )


def td_build_project_parameter_units_rows(
    project_dir: Path,
    repo_rows: Sequence[Mapping[str, object]] | None,
    context: Mapping[str, object] | None = None,
) -> list[dict[str, object]]:
    normalized_rows = [
        _td_program_parameter_mapping_normalize(row)
        for row in (repo_rows or [])
        if _td_program_parameter_mapping_normalize(row)
    ]
    base_normalization = _td_build_repo_parameter_normalization(normalized_rows)
    normalization, _canonical_groups_unused = _td_project_parameter_group_overrides(project_dir, base_normalization)
    inventory_rows = [
        dict(item)
        for item in (dict(context or {}).get("inventory") or [])
        if isinstance(item, Mapping)
    ]
    groups_by_id: dict[str, dict[str, object]] = {}

    def _ensure_group(canonical_id: str, fallback_display: object = "") -> dict[str, object]:
        group = groups_by_id.get(canonical_id)
        if group is not None:
            return group
        display_name = _td_parameter_display_name_for_group(
            normalization,
            canonical_id,
            raw_names=[],
            fallback=fallback_display,
        ) or str(fallback_display or "").strip()
        group = {
            "canonical_id": canonical_id,
            "displayed_parameter": display_name,
            "_raw_names": set(),
            "_program_titles": set(),
            "_units": set(),
        }
        groups_by_id[canonical_id] = group
        return group

    for row in normalized_rows:
        display_name = _td_program_parameter_effective_display(row)
        canonical_id = _td_program_parameter_canonical_id(display_name)
        if not canonical_id:
            continue
        group = _ensure_group(canonical_id, display_name)
        cast(set[str], group["_raw_names"]).add(str(row.get("ingested_parameter") or "").strip())
        program_title = str(row.get("program_title") or "").strip()
        if program_title:
            cast(set[str], group["_program_titles"]).add(program_title)
        units_text = str(row.get("preferred_units") or "").strip()
        if units_text:
            cast(set[str], group["_units"]).add(units_text)

    for inventory_row in inventory_rows:
        raw_name = str(inventory_row.get("raw_name") or "").strip()
        if not raw_name:
            continue
        canonical_id = _td_effective_parameter_canonical(
            normalization,
            raw_name,
            inventory_row.get("program_title"),
            inventory_row.get("asset_type"),
            inventory_row.get("asset_specific_type"),
            fallback_display=(
                inventory_row.get("displayed_parameter")
                or inventory_row.get("default_display_parameter")
                or raw_name
            ),
        )
        if not canonical_id:
            continue
        group = _ensure_group(
            canonical_id,
            inventory_row.get("displayed_parameter")
            or inventory_row.get("default_display_parameter")
            or raw_name,
        )
        cast(set[str], group["_raw_names"]).add(raw_name)
        program_title = str(inventory_row.get("program_title") or "").strip()
        if program_title:
            cast(set[str], group["_program_titles"]).add(program_title)
        for value in (inventory_row.get("units") or []):
            units_text = str(value or "").strip()
            if units_text:
                cast(set[str], group["_units"]).add(units_text)
        preferred_units = str(inventory_row.get("preferred_units") or "").strip()
        if preferred_units:
            cast(set[str], group["_units"]).add(preferred_units)

    rows: list[dict[str, object]] = []
    for canonical_id, group in groups_by_id.items():
        raw_names = sorted(
            {str(value).strip() for value in cast(set[str], group.get("_raw_names") or set()) if str(value).strip()},
            key=str.casefold,
        )
        if not raw_names:
            continue
        display_name = _td_parameter_display_name_for_group(
            normalization,
            canonical_id,
            raw_names=raw_names,
            fallback=group.get("displayed_parameter") or raw_names[0],
        )
        source_units = sorted(
            {str(value).strip() for value in cast(set[str], group.get("_units") or set()) if str(value).strip()},
            key=str.casefold,
        )
        preferred_units = str(
            ((normalization.get("groups_by_id") or {}).get(canonical_id) or {}).get("preferred_units")
            if isinstance(normalization.get("groups_by_id"), Mapping)
            else ""
        ).strip()
        if not preferred_units:
            preferred_units = _td_parameter_group_units(source_units)
        rows.append(
            {
                "canonical_id": canonical_id,
                "displayed_parameter": display_name,
                "raw_names": raw_names,
                "raw_names_text": ", ".join(raw_names),
                "program_titles": sorted(
                    {str(value).strip() for value in cast(set[str], group.get("_program_titles") or set()) if str(value).strip()},
                    key=str.casefold,
                ),
                "source_units": source_units,
                "preferred_units": preferred_units,
                "unit_conflict": _td_parameter_group_has_conflict(source_units, preferred_units),
            }
        )
    for row in rows:
        row["program_titles_text"] = ", ".join(row.get("program_titles") or [])
    rows.sort(
        key=lambda item: (
            str(item.get("displayed_parameter") or "").casefold(),
            str(item.get("canonical_id") or "").casefold(),
        )
    )
    return rows


def td_save_project_parameter_units(
    project_dir: Path,
    repo_rows: Sequence[Mapping[str, object]] | None,
    unit_rows: Sequence[Mapping[str, object]] | None,
    *,
    workbook_path: Path | None = None,
) -> dict[str, object]:
    preferred_units_by_canonical: dict[str, str] = {}
    preferred_display_by_canonical: dict[str, str] = {}
    for raw_row in (unit_rows or []):
        if not isinstance(raw_row, Mapping):
            continue
        canonical_id = str(raw_row.get("canonical_id") or "").strip()
        display_name = str(raw_row.get("displayed_parameter") or "").strip()
        if not canonical_id and display_name:
            canonical_id = _td_program_parameter_canonical_id(display_name)
        if not canonical_id:
            continue
        preferred_units_by_canonical[canonical_id] = str(raw_row.get("preferred_units") or "").strip()
        if display_name:
            preferred_display_by_canonical[canonical_id] = display_name

    mirrored_rows: list[dict[str, object]] = []
    for raw_row in (repo_rows or []):
        row = _td_program_parameter_mapping_normalize(raw_row)
        if not row:
            continue
        display_name = _td_program_parameter_effective_display(row)
        canonical_id = _td_program_parameter_canonical_id(display_name)
        if canonical_id in preferred_units_by_canonical:
            units_text = preferred_units_by_canonical[canonical_id]
            row["preferred_units"] = units_text
            row["default_preferred_units"] = units_text
            if preferred_display_by_canonical.get(canonical_id):
                row["displayed_parameter"] = preferred_display_by_canonical[canonical_id]
        mirrored_rows.append(row)

    saved_rows = save_td_repo_parameter_mappings(
        project_dir,
        mirrored_rows,
        workbook_path=workbook_path,
    )
    normalization = td_rebuild_project_parameter_units_catalog(project_dir, saved_rows)
    return {
        "saved_rows": [dict(row) for row in saved_rows],
        "normalization": normalization,
    }


def _td_parameter_mapping_match_score(
    rule: Mapping[str, object] | None,
    *,
    program_title: object = "",
    asset_type: object = "",
    asset_specific_type: object = "",
) -> tuple[int, int, int] | None:
    mapping = dict(rule or {})
    want_program = _td_param_norm_program(program_title)
    want_asset = _td_param_norm_program(_td_program_parameter_scope_text(asset_type))
    want_specific = _td_param_norm_program(_td_program_parameter_scope_text(asset_specific_type))
    rule_programs = {
        _td_param_norm_program(value)
        for value in (mapping.get("program_titles") or [])
        if _td_param_norm_program(value)
    }
    rule_assets = {
        _td_param_norm_program(value)
        for value in (mapping.get("asset_types") or [])
        if _td_param_norm_program(value)
    }
    rule_asset_specific = {
        _td_param_norm_program(value)
        for value in (mapping.get("asset_specific_types") or [])
        if _td_param_norm_program(value)
    }
    if rule_programs and want_program not in rule_programs:
        return None
    if rule_assets and want_asset not in rule_assets:
        return None
    if rule_asset_specific and want_specific not in rule_asset_specific:
        return None
    return (
        1 if rule_asset_specific else 0,
        1 if rule_assets else 0,
        1 if rule_programs else 0,
    )


def _td_effective_parameter_canonical(
    normalization: Mapping[str, object] | None,
    raw_name: object,
    program_title: object = "",
    asset_type: object = "",
    asset_specific_type: object = "",
    fallback_display: object = "",
) -> str:
    normalized = _td_normalize_parameter_normalization(normalization)
    want_raw = _td_param_norm_name(raw_name)
    if not want_raw:
        fallback_text = str(fallback_display or "").strip()
        return _td_program_parameter_canonical_id(fallback_text) if fallback_text else _td_parameter_implicit_canonical_id(raw_name)
    best_match: tuple[tuple[int, int, int], str] | None = None
    for rule in (normalized.get("mappings") or []):
        if not isinstance(rule, Mapping):
            continue
        if _td_param_norm_name(rule.get("raw_name")) != want_raw:
            continue
        score = _td_parameter_mapping_match_score(
            rule,
            program_title=program_title,
            asset_type=asset_type,
            asset_specific_type=asset_specific_type,
        )
        if score is None:
            continue
        display_name = str(
            rule.get("displayed_parameter")
            or ((normalized.get("groups_by_id") or {}).get(str(rule.get("canonical_id") or "").strip()) or {}).get("display_name")
            or fallback_display
            or raw_name
        ).strip()
        canonical_id = str(rule.get("canonical_id") or "").strip() or _td_program_parameter_canonical_id(display_name)
        if not canonical_id:
            continue
        if best_match is None or score > best_match[0]:
            best_match = (score, canonical_id)
    if best_match is not None:
        return best_match[1]
    fallback_text = str(fallback_display or "").strip()
    if fallback_text:
        return _td_program_parameter_canonical_id(fallback_text)
    return _td_parameter_implicit_canonical_id(raw_name)


def _td_parameter_config_candidates(workbook_path: Path | None) -> list[dict[str, object]]:
    wb_path = Path(workbook_path).expanduser() if workbook_path else Path()
    if not wb_path or not wb_path.exists():
        return []
    try:
        project_cfg = _load_project_td_trend_config(wb_path)
    except Exception:
        return []
    return _td_parameter_config_candidates_from_defs(project_cfg.get("columns") or [])


def _td_parameter_inventory_suggestion(
    raw_name: str,
    *,
    units: Sequence[object] | None = None,
    config_candidates: Sequence[Mapping[str, object]] | None = None,
) -> dict[str, str]:
    raw_variants = _td_parameter_name_match_variants(raw_name)
    raw_norms = {_td_param_norm_name(value) for value in raw_variants if _td_param_norm_name(value)}
    if not raw_norms:
        return {}
    candidates = [dict(item) for item in (config_candidates or []) if isinstance(item, Mapping)]
    exact_matches: list[dict[str, object]] = []
    fuzzy_matches: list[dict[str, object]] = []
    raw_token_variants = [
        set(_td_parameter_tokens(value))
        for value in raw_variants
        if set(_td_parameter_tokens(value))
    ]
    for candidate in candidates:
        display_name = str(candidate.get("display_name") or "").strip()
        if not display_name:
            continue
        if not _td_parameter_units_compatible(units, candidate.get("units")):
            continue
        aliases = [str(value).strip() for value in (candidate.get("aliases") or []) if str(value).strip()]
        alias_norms = {_td_param_norm_name(value) for value in aliases if _td_param_norm_name(value)}
        if raw_norms & alias_norms:
            exact_matches.append(candidate)
            continue
        if not raw_token_variants:
            continue
        best_ratio = 0.0
        best_token_match = False
        for alias in aliases:
            alias_norm = _td_param_norm_name(alias)
            alias_tokens = set(_td_parameter_tokens(alias))
            for raw_variant in raw_variants:
                raw_variant_norm = _td_param_norm_name(raw_variant)
                if raw_variant_norm:
                    best_ratio = max(best_ratio, SequenceMatcher(None, raw_variant_norm, alias_norm).ratio())
            if alias_tokens and any(raw_tokens == alias_tokens for raw_tokens in raw_token_variants):
                best_token_match = True
        if best_token_match or best_ratio >= 0.92:
            fuzzy_matches.append(candidate)
    unique_exact = {str(item.get("display_name") or "").strip(): item for item in exact_matches}
    if len(unique_exact) == 1:
        match = next(iter(unique_exact.values()))
        return {
            "display_name": str(match.get("display_name") or "").strip(),
            "preferred_units": str(match.get("units") or "").strip(),
            "reason": "config_alias",
        }
    unique_fuzzy = {str(item.get("display_name") or "").strip(): item for item in fuzzy_matches}
    if len(unique_fuzzy) == 1:
        match = next(iter(unique_fuzzy.values()))
        return {
            "display_name": str(match.get("display_name") or "").strip(),
            "preferred_units": str(match.get("units") or "").strip(),
            "reason": "fuzzy_alias",
        }
    return {}


def _td_build_repo_parameter_normalization(
    rows: Sequence[Mapping[str, object]] | None,
) -> dict[str, object]:
    groups: list[dict[str, object]] = []
    groups_by_id: dict[str, dict[str, object]] = {}
    mappings: list[dict[str, object]] = []
    for row in rows or []:
        normalized_row = _td_program_parameter_mapping_normalize(row)
        if not normalized_row:
            continue
        display_name = _td_program_parameter_effective_display(normalized_row)
        canonical_id = _td_program_parameter_canonical_id(display_name)
        if canonical_id not in groups_by_id:
            group = {
                "id": canonical_id,
                "display_name": display_name,
                "preferred_units": str(normalized_row.get("preferred_units") or "").strip(),
            }
            groups_by_id[canonical_id] = group
            groups.append(dict(group))
        elif str(normalized_row.get("preferred_units") or "").strip() and not str(groups_by_id[canonical_id].get("preferred_units") or "").strip():
            groups_by_id[canonical_id]["preferred_units"] = str(normalized_row.get("preferred_units") or "").strip()
        mappings.append(
            {
                "canonical_id": canonical_id,
                "raw_name": str(normalized_row.get("ingested_parameter") or "").strip(),
                "program_titles": [str(normalized_row.get("program_title") or "").strip()] if str(normalized_row.get("program_title") or "").strip() else [],
                "asset_types": [str(normalized_row.get("asset_type") or "").strip()] if str(normalized_row.get("asset_type") or "").strip() else [],
                "asset_specific_types": [str(normalized_row.get("asset_specific_type") or "").strip()] if str(normalized_row.get("asset_specific_type") or "").strip() else [],
                "default_display_parameter": str(normalized_row.get("default_display_parameter") or "").strip(),
                "displayed_parameter": str(normalized_row.get("displayed_parameter") or "").strip(),
                "preferred_units": str(normalized_row.get("preferred_units") or "").strip(),
                "enabled": _td_bool(normalized_row.get("enabled"), True),
                "edited": bool(normalized_row.get("edited")),
            }
        )
    return _td_normalize_parameter_normalization(
        {
            "version": TD_PARAMETER_NORMALIZATION_VERSION,
            "groups": groups,
            "mappings": mappings,
        }
    )


def _td_find_parameter_mapping_rule(
    normalization: Mapping[str, object] | None,
    raw_name: object,
    *,
    program_title: object = "",
    asset_type: object = "",
    asset_specific_type: object = "",
) -> dict[str, object]:
    normalized = _td_normalize_parameter_normalization(normalization)
    want_raw = _td_param_norm_name(raw_name)
    if not want_raw:
        return {}
    best_rule: dict[str, object] = {}
    best_score: tuple[int, int, int] | None = None
    for raw_rule in (normalized.get("mappings") or []):
        if not isinstance(raw_rule, Mapping):
            continue
        if _td_param_norm_name(raw_rule.get("raw_name")) != want_raw:
            continue
        score = _td_parameter_mapping_match_score(
            raw_rule,
            program_title=program_title,
            asset_type=asset_type,
            asset_specific_type=asset_specific_type,
        )
        if score is None:
            continue
        if best_score is None or score > best_score:
            best_score = score
            best_rule = dict(raw_rule)
    return best_rule


def _td_parameter_mapping_rule_enabled(rule: Mapping[str, object] | None) -> bool:
    if not isinstance(rule, Mapping):
        return True
    return _td_bool(rule.get("enabled"), True)


def _td_effective_parameter_display(
    normalization: Mapping[str, object] | None,
    raw_name: object,
    *,
    program_title: object = "",
    asset_type: object = "",
    asset_specific_type: object = "",
    fallback_display: object = "",
) -> str:
    rule = _td_find_parameter_mapping_rule(
        normalization,
        raw_name,
        program_title=program_title,
        asset_type=asset_type,
        asset_specific_type=asset_specific_type,
    )
    display_name = str(
        rule.get("displayed_parameter")
        or rule.get("default_display_parameter")
        or fallback_display
        or raw_name
        or ""
    ).strip()
    return display_name


def _td_parameter_discovery_table_ready(conn: sqlite3.Connection, *, require_rows: bool = False) -> bool:
    _ensure_test_data_impl_tables(conn)
    required = {
        "surface",
        "run_name",
        "raw_name",
        "raw_norm",
        "units",
        "program_title",
        "asset_type",
        "asset_specific_type",
        "source_run_name",
        "source_key",
    }
    if not required.issubset(_td_table_columns(conn, TD_PARAM_DISCOVERY_TABLE)):
        return False
    if not require_rows:
        return True
    try:
        return int(conn.execute(f"SELECT COUNT(*) FROM {TD_PARAM_DISCOVERY_TABLE}").fetchone()[0] or 0) > 0
    except Exception:
        return False


def _td_parameter_runtime_tables_ready(conn: sqlite3.Connection, *, require_rows: bool = False) -> bool:
    _ensure_test_data_impl_tables(conn)
    required_specs = {
        TD_PARAM_NORM_GROUPS_TABLE: {"canonical_id", "display_name", "preferred_units", "explicit"},
        TD_PARAM_NORM_RULES_TABLE: {
            "raw_name",
            "raw_norm",
            "program_title",
            "program_norm",
            "asset_type",
            "asset_norm",
            "asset_specific_type",
            "asset_specific_norm",
            "canonical_id",
            "default_display_parameter",
            "displayed_parameter",
            "preferred_units",
            "enabled",
            "edited",
        },
        TD_PARAM_RUNTIME_ENTRIES_TABLE: {
            "surface",
            "run_name",
            "raw_name",
            "raw_norm",
            "units",
            "program_title",
            "asset_type",
            "asset_specific_type",
            "source_run_name",
            "source_key",
            "canonical_id",
            "default_display_parameter",
        },
        TD_PARAM_RUNTIME_GROUPS_TABLE: {
            "canonical_id",
            "display_name",
            "preferred_units",
            "raw_names_json",
            "units_json",
            "program_titles_json",
            "asset_types_json",
            "asset_specific_types_json",
            "source_run_names_json",
            "surfaces_json",
            "run_names_json",
            "unit_conflict",
            "explicit",
        },
    }
    for table_name, required_cols in required_specs.items():
        if not required_cols.issubset(_td_table_columns(conn, table_name)):
            return False
    if not require_rows:
        return True
    try:
        group_count = int(conn.execute(f"SELECT COUNT(*) FROM {TD_PARAM_RUNTIME_GROUPS_TABLE}").fetchone()[0] or 0)
        entry_count = int(conn.execute(f"SELECT COUNT(*) FROM {TD_PARAM_RUNTIME_ENTRIES_TABLE}").fetchone()[0] or 0)
    except Exception:
        return False
    return bool(group_count > 0 and entry_count > 0 and _td_meta_value(conn, TD_PARAM_RUNTIME_SIGNATURE_META_KEY))


def _td_parameter_discovery_signature(conn: sqlite3.Connection) -> str:
    return _td_hash_payload(
        {
            "cache_schema_version": TD_PROJECT_CACHE_SCHEMA_VERSION,
            "built_epoch_ns": _td_meta_value(conn, "built_epoch_ns"),
        }
    )


def _td_parameter_runtime_signature(
    discovery_signature: str,
    repo_parameter_rows: Sequence[Mapping[str, object]] | None,
) -> str:
    normalized_rows = [
        {
            "program_title": str(item.get("program_title") or "").strip(),
            "asset_type": str(item.get("asset_type") or "").strip(),
            "asset_specific_type": str(item.get("asset_specific_type") or "").strip(),
            "ingested_parameter": str(item.get("ingested_parameter") or "").strip(),
            "default_display_parameter": str(item.get("default_display_parameter") or "").strip(),
            "displayed_parameter": str(item.get("displayed_parameter") or "").strip(),
            "preferred_units": str(item.get("preferred_units") or "").strip(),
            "enabled": _td_bool(item.get("enabled"), True),
            "edited": bool(item.get("edited")),
        }
        for item in (
            _td_program_parameter_mapping_normalize(row)
            for row in (repo_parameter_rows or [])
        )
        if item and str(item.get("ingested_parameter") or "").strip()
    ]
    normalized_rows.sort(key=_td_stable_json)
    return _td_hash_payload(
        {
            "discovery_signature": str(discovery_signature or "").strip(),
            "repo_parameter_rows": normalized_rows,
        }
    )


def _td_parameter_runtime_context_enabled(context: Mapping[str, object] | None) -> bool:
    ctx = dict(context or {})
    return bool(
        str(ctx.get("runtime_mode") or "").strip().lower() == "db"
        and str(ctx.get("db_path") or "").strip()
    )


def _td_parameter_discovery_rows_from_table(conn: sqlite3.Connection) -> list[dict[str, str]]:
    if not _td_parameter_discovery_table_ready(conn, require_rows=False):
        return []
    try:
        rows = conn.execute(
            f"""
            SELECT
                surface,
                run_name,
                raw_name,
                raw_norm,
                COALESCE(units, ''),
                COALESCE(program_title, ''),
                COALESCE(asset_type, ''),
                COALESCE(asset_specific_type, ''),
                COALESCE(source_run_name, ''),
                COALESCE(source_key, '')
            FROM {TD_PARAM_DISCOVERY_TABLE}
            ORDER BY surface, run_name, raw_name, program_title, asset_type, asset_specific_type, source_run_name
            """
        ).fetchall()
    except Exception:
        return []
    out: list[dict[str, str]] = []
    for surface, run_name, raw_name, raw_norm, units, program_title, asset_type, asset_specific_type, source_run_name, source_key in rows:
        text = str(raw_name or "").strip()
        if not text:
            continue
        out.append(
            {
                "surface": str(surface or "").strip().lower(),
                "run_name": str(run_name or "").strip(),
                "raw_name": text,
                "raw_norm": str(raw_norm or _td_param_norm_name(text)).strip(),
                "units": str(units or "").strip(),
                "program_title": str(program_title or "").strip(),
                "asset_type": str(asset_type or "").strip(),
                "asset_specific_type": str(asset_specific_type or "").strip(),
                "source_run_name": str(source_run_name or "").strip(),
                "source_key": str(source_key or "").strip(),
            }
        )
    return out


def _td_collect_parameter_discovery_rows_from_cache(
    impl_db: Path,
    raw_db: Path,
) -> list[dict[str, str]]:
    rows_out: list[dict[str, str]] = []
    seen: set[tuple[str, str, str, str, str, str, str, str, str]] = set()

    def _append_row(
        *,
        surface: object,
        run_name: object,
        raw_name: object,
        units: object = "",
        program_title: object = "",
        asset_type: object = "",
        asset_specific_type: object = "",
        source_run_name: object = "",
        source_key: object = "",
    ) -> None:
        surface_text = str(surface or "").strip().lower()
        run_text = str(run_name or "").strip()
        raw_text = str(raw_name or "").strip()
        if not surface_text or not run_text or not raw_text:
            return
        record = {
            "surface": surface_text,
            "run_name": run_text,
            "raw_name": raw_text,
            "raw_norm": _td_param_norm_name(raw_text),
            "units": str(units or "").strip(),
            "program_title": str(program_title or "").strip(),
            "asset_type": _td_program_parameter_scope_text(asset_type),
            "asset_specific_type": _td_program_parameter_scope_text(asset_specific_type),
            "source_run_name": str(source_run_name or "").strip(),
            "source_key": str(source_key or "").strip(),
        }
        key = (
            record["surface"],
            record["run_name"],
            record["raw_name"],
            record["program_title"],
            record["asset_type"],
            record["asset_specific_type"],
            record["source_run_name"],
            record["source_key"],
            record["units"],
        )
        if key in seen:
            return
        seen.add(key)
        rows_out.append(record)

    if impl_db.exists():
        with sqlite3.connect(str(impl_db)) as conn:
            _ensure_test_data_impl_tables(conn)
            try:
                metric_rows = conn.execute(
                    """
                    SELECT DISTINCT
                        m.run_name,
                        m.column_name,
                        COALESCE(c.units, ''),
                        COALESCE(m.program_title, ''),
                        COALESCE(m.source_run_name, ''),
                        COALESCE(sm.asset_type, ''),
                        COALESCE(sm.asset_specific_type, ''),
                        COALESCE(sm.source_serial_number, m.serial)
                    FROM td_metrics_calc m
                    LEFT JOIN td_columns_calc c
                      ON c.run_name = m.run_name AND c.name = m.column_name AND c.kind = 'y'
                    LEFT JOIN td_source_metadata sm
                      ON sm.serial = m.serial
                    WHERE m.value_num IS NOT NULL
                    ORDER BY m.run_name, m.column_name
                    """
                ).fetchall()
            except Exception:
                metric_rows = []
            for run_name, raw_name, units, program_title, source_run_name, asset_type, asset_specific_type, source_key in metric_rows:
                _append_row(
                    surface="metrics",
                    run_name=run_name,
                    raw_name=raw_name,
                    units=units,
                    program_title=program_title,
                    asset_type=asset_type,
                    asset_specific_type=asset_specific_type,
                    source_run_name=source_run_name,
                    source_key=source_key,
                )
                _append_row(
                    surface="performance",
                    run_name=run_name,
                    raw_name=raw_name,
                    units=units,
                    program_title=program_title,
                    asset_type=asset_type,
                    asset_specific_type=asset_specific_type,
                    source_run_name=source_run_name,
                    source_key=source_key,
                )
            try:
                life_rows = conn.execute(
                    f"""
                    SELECT DISTINCT
                        condition_key,
                        parameter_name,
                        COALESCE(units, ''),
                        COALESCE(program_title, ''),
                        COALESCE(source_run_name, ''),
                        COALESCE(sm.asset_type, ''),
                        COALESCE(sm.asset_specific_type, ''),
                        COALESCE(sm.source_serial_number, l.serial)
                    FROM {TD_LIFE_METRICS_TABLE} l
                    LEFT JOIN td_source_metadata sm
                      ON sm.serial = l.serial
                    WHERE lower(stat) = 'mean'
                    ORDER BY condition_key, parameter_name
                    """
                ).fetchall()
            except Exception:
                life_rows = []
            for run_name, raw_name, units, program_title, source_run_name, asset_type, asset_specific_type, source_key in life_rows:
                _append_row(
                    surface="life_metrics",
                    run_name=run_name,
                    raw_name=raw_name,
                    units=units,
                    program_title=program_title,
                    asset_type=asset_type,
                    asset_specific_type=asset_specific_type,
                    source_run_name=source_run_name,
                    source_key=source_key,
                )
            try:
                curve_rows = conn.execute(
                    f"""
                    SELECT DISTINCT
                        c.run_name,
                        c.y_name,
                        COALESCE(cat.units, ''),
                        COALESCE(c.program_title, ''),
                        COALESCE(c.source_run_name, ''),
                        COALESCE(sm.asset_type, ''),
                        COALESCE(sm.asset_specific_type, ''),
                        COALESCE(sm.source_serial_number, c.serial)
                    FROM {TD_PLOTTER_CURVES_TABLE} c
                    LEFT JOIN {TD_PLOTTER_CURVE_CATALOG_TABLE} cat
                      ON cat.run_name = c.run_name AND cat.parameter_name = c.y_name
                    LEFT JOIN td_source_metadata sm
                      ON sm.serial = c.serial
                    ORDER BY c.run_name, c.y_name
                    """
                ).fetchall()
            except Exception:
                curve_rows = []
            for run_name, raw_name, units, program_title, source_run_name, asset_type, asset_specific_type, source_key in curve_rows:
                _append_row(
                    surface="curves",
                    run_name=run_name,
                    raw_name=raw_name,
                    units=units,
                    program_title=program_title,
                    asset_type=asset_type,
                    asset_specific_type=asset_specific_type,
                    source_run_name=source_run_name,
                    source_key=source_key,
                )

    if not rows_out and raw_db.exists():
        with sqlite3.connect(str(raw_db)) as conn:
            _ensure_test_data_raw_cache_tables(conn)
            try:
                curve_rows = conn.execute(
                    """
                    SELECT DISTINCT
                        c.run_name,
                        c.y_name,
                        COALESCE(cat.units, ''),
                        COALESCE(c.program_title, ''),
                        COALESCE(c.source_run_name, '')
                    FROM td_curves_raw c
                    LEFT JOIN td_raw_curve_catalog cat
                      ON cat.run_name = c.run_name AND cat.parameter_name = c.y_name
                    ORDER BY c.run_name, c.y_name
                    """
                ).fetchall()
            except Exception:
                curve_rows = []
        for run_name, raw_name, units, program_title, source_run_name in curve_rows:
            _append_row(
                surface="curves",
                run_name=run_name,
                raw_name=raw_name,
                units=units,
                program_title=program_title,
                source_run_name=source_run_name,
            )

    rows_out.sort(
        key=lambda item: (
            str(item.get("surface") or "").casefold(),
            str(item.get("run_name") or "").casefold(),
            str(item.get("raw_name") or "").casefold(),
            str(item.get("program_title") or "").casefold(),
            str(item.get("asset_type") or "").casefold(),
            str(item.get("asset_specific_type") or "").casefold(),
            str(item.get("source_run_name") or "").casefold(),
            str(item.get("units") or "").casefold(),
        )
    )
    return rows_out


def _td_write_parameter_discovery_rows(
    conn: sqlite3.Connection,
    rows: Sequence[Mapping[str, object]] | None,
) -> None:
    _ensure_test_data_impl_tables(conn)
    conn.execute(f"DELETE FROM {TD_PARAM_DISCOVERY_TABLE}")
    payload = [
        (
            str(row.get("surface") or "").strip().lower(),
            str(row.get("run_name") or "").strip(),
            str(row.get("raw_name") or "").strip(),
            str(row.get("raw_norm") or _td_param_norm_name(row.get("raw_name"))).strip(),
            str(row.get("units") or "").strip(),
            str(row.get("program_title") or "").strip(),
            str(row.get("asset_type") or "").strip(),
            str(row.get("asset_specific_type") or "").strip(),
            str(row.get("source_run_name") or "").strip(),
            str(row.get("source_key") or "").strip(),
        )
        for row in (rows or [])
        if str(row.get("surface") or "").strip()
        and str(row.get("run_name") or "").strip()
        and str(row.get("raw_name") or "").strip()
    ]
    if payload:
        conn.executemany(
            f"""
            INSERT OR REPLACE INTO {TD_PARAM_DISCOVERY_TABLE} (
                surface,
                run_name,
                raw_name,
                raw_norm,
                units,
                program_title,
                asset_type,
                asset_specific_type,
                source_run_name,
                source_key
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            payload,
        )


def _td_clear_parameter_runtime_tables(conn: sqlite3.Connection) -> None:
    _ensure_test_data_impl_tables(conn)
    for table_name in (
        TD_PARAM_NORM_GROUPS_TABLE,
        TD_PARAM_NORM_RULES_TABLE,
        TD_PARAM_RUNTIME_ENTRIES_TABLE,
        TD_PARAM_RUNTIME_GROUPS_TABLE,
    ):
        conn.execute(f"DELETE FROM {table_name}")
    for meta_key in (
        TD_PARAM_RUNTIME_SIGNATURE_META_KEY,
        TD_PARAM_RUNTIME_BUILT_META_KEY,
    ):
        conn.execute("DELETE FROM td_meta WHERE key=?", (meta_key,))


def invalidate_td_parameter_runtime_cache(db_path: Path) -> None:
    path = Path(db_path).expanduser()
    if not path.exists():
        return
    with sqlite3.connect(str(path)) as conn:
        _td_clear_parameter_runtime_tables(conn)
        conn.commit()


def _td_build_parameter_context_from_discovery_rows(
    *,
    proj_dir: Path,
    workbook: Path,
    impl_db: Path,
    raw_db: Path,
    normalization: Mapping[str, object] | None,
    repo_parameter_rows: Sequence[Mapping[str, object]] | None,
    discovery_rows: Sequence[Mapping[str, object]] | None,
) -> dict[str, object]:
    config_candidates = _td_parameter_config_candidates(workbook if workbook else None)
    inventory_acc: dict[tuple[str, str, str, str], dict[str, object]] = {}
    entry_keys: set[tuple[str, str, str, str, str, str, str, str, str]] = set()
    entries: list[dict[str, str]] = []
    normalized = _td_normalize_parameter_normalization(normalization)

    def _inventory_row(
        raw_name: str,
        *,
        program_title: str,
        asset_type: str,
        asset_specific_type: str,
    ) -> dict[str, object]:
        raw_norm = _td_param_norm_name(raw_name)
        row_key = (
            raw_norm,
            _td_param_norm_program(program_title),
            _td_param_norm_program(asset_type),
            _td_param_norm_program(asset_specific_type),
        )
        row = inventory_acc.get(row_key)
        if row is not None:
            return row
        row = {
            "raw_name": raw_name,
            "raw_norm": raw_norm,
            "program_title": program_title,
            "asset_type": asset_type,
            "asset_specific_type": asset_specific_type,
            "_units": set(),
            "_source_run_names": set(),
            "_surfaces": set(),
            "_run_names": set(),
            "_source_keys": set(),
        }
        inventory_acc[row_key] = row
        return row

    def _add_entry(
        *,
        raw_name: object,
        units: object = "",
        program_title: object = "",
        asset_type: object = "",
        asset_specific_type: object = "",
        source_run_name: object = "",
        run_name: object = "",
        surface: object = "",
        source_key: object = "",
        fallback_display: object = "",
    ) -> None:
        text = str(raw_name or "").strip()
        if not text:
            return
        surface_text = str(surface or "").strip().lower()
        program_text = str(program_title or "").strip()
        asset_text = _td_program_parameter_scope_text(asset_type)
        asset_specific_text = _td_program_parameter_scope_text(asset_specific_type)
        row = _inventory_row(
            text,
            program_title=program_text,
            asset_type=asset_text,
            asset_specific_type=asset_specific_text,
        )
        units_text = str(units or "").strip()
        if units_text:
            cast(set[str], row["_units"]).add(units_text)
        source_run_text = str(source_run_name or "").strip()
        run_text = str(run_name or "").strip()
        if source_run_text:
            cast(set[str], row["_source_run_names"]).add(source_run_text)
        if run_text:
            cast(set[str], row["_run_names"]).add(run_text)
        source_key_text = str(source_key or "").strip()
        if source_key_text:
            cast(set[str], row["_source_keys"]).add(source_key_text)
        row["default_display_parameter"] = _td_effective_parameter_display(
            normalized,
            text,
            program_title=program_text,
            asset_type=asset_text,
            asset_specific_type=asset_specific_text,
            fallback_display=fallback_display or text,
        ) or str(fallback_display or text).strip()
        row["mapping_rule"] = _td_find_parameter_mapping_rule(
            normalized,
            text,
            program_title=program_text,
            asset_type=asset_text,
            asset_specific_type=asset_specific_text,
        )
        if not surface_text:
            return
        cast(set[str], row["_surfaces"]).add(surface_text)
        entry_key = (
            surface_text,
            run_text.casefold(),
            _td_param_norm_name(text),
            _td_param_norm_program(program_text),
            _td_param_norm_program(asset_text),
            _td_param_norm_program(asset_specific_text),
            source_run_text.casefold(),
            source_key_text.casefold(),
            _td_param_norm_name(units_text),
        )
        if entry_key in entry_keys:
            return
        entry_keys.add(entry_key)
        entries.append(
            {
                "surface": surface_text,
                "run_name": run_text,
                "raw_name": text,
                "raw_norm": _td_param_norm_name(text),
                "units": units_text,
                "program_title": program_text,
                "program_norm": _td_param_norm_program(program_text),
                "asset_type": asset_text,
                "asset_specific_type": asset_specific_text,
                "source_run_name": source_run_text,
                "source_key": source_key_text,
                "default_display_parameter": str(row.get("default_display_parameter") or "").strip(),
            }
        )

    for discovery_row in (discovery_rows or []):
        if not isinstance(discovery_row, Mapping):
            continue
        _add_entry(
            raw_name=discovery_row.get("raw_name"),
            units=discovery_row.get("units"),
            program_title=discovery_row.get("program_title"),
            asset_type=discovery_row.get("asset_type"),
            asset_specific_type=discovery_row.get("asset_specific_type"),
            source_run_name=discovery_row.get("source_run_name"),
            run_name=discovery_row.get("run_name"),
            surface=discovery_row.get("surface"),
            source_key=discovery_row.get("source_key"),
        )

    canonical_groups: dict[str, dict[str, object]] = {}
    for entry in entries:
        raw_name = str(entry.get("raw_name") or "").strip()
        canonical_id = _td_effective_parameter_canonical(
            normalized,
            raw_name,
            entry.get("program_title"),
            entry.get("asset_type"),
            entry.get("asset_specific_type"),
            fallback_display=entry.get("default_display_parameter"),
        )
        group = canonical_groups.setdefault(
            canonical_id,
            {
                "id": canonical_id,
                "display_name": "",
                "preferred_units": "",
                "_raw_names": set(),
                "_units": set(),
                "_program_titles": set(),
                "_asset_types": set(),
                "_asset_specific_types": set(),
                "_source_run_names": set(),
                "_surfaces": set(),
                "_run_names": set(),
                "explicit": canonical_id in cast(dict[str, dict[str, object]], normalized.get("groups_by_id") or {}),
            },
        )
        cast(set[str], group["_raw_names"]).add(raw_name)
        if str(entry.get("units") or "").strip():
            cast(set[str], group["_units"]).add(str(entry.get("units") or "").strip())
        if str(entry.get("program_title") or "").strip():
            cast(set[str], group["_program_titles"]).add(str(entry.get("program_title") or "").strip())
        if str(entry.get("asset_type") or "").strip():
            cast(set[str], group["_asset_types"]).add(str(entry.get("asset_type") or "").strip())
        if str(entry.get("asset_specific_type") or "").strip():
            cast(set[str], group["_asset_specific_types"]).add(str(entry.get("asset_specific_type") or "").strip())
        if str(entry.get("source_run_name") or "").strip():
            cast(set[str], group["_source_run_names"]).add(str(entry.get("source_run_name") or "").strip())
        if str(entry.get("surface") or "").strip():
            cast(set[str], group["_surfaces"]).add(str(entry.get("surface") or "").strip())
        if str(entry.get("run_name") or "").strip():
            cast(set[str], group["_run_names"]).add(str(entry.get("run_name") or "").strip())
    for group_id, group in list(canonical_groups.items()):
        raw_names = sorted(cast(set[str], group.get("_raw_names") or set()), key=str.casefold)
        units = sorted(cast(set[str], group.get("_units") or set()), key=str.casefold)
        group["display_name"] = _td_parameter_display_name_for_group(
            normalized,
            group_id,
            raw_names=raw_names,
            fallback=(raw_names[0] if raw_names else group_id),
        )
        preferred_units = str(
            ((normalized.get("groups_by_id") or {}).get(group_id) or {}).get("preferred_units")
            if isinstance(normalized.get("groups_by_id"), Mapping)
            else ""
        ).strip()
        if not preferred_units and len(units) == 1:
            preferred_units = units[0]
        group["preferred_units"] = preferred_units
        group["raw_names"] = raw_names
        group["units"] = units
        group["program_titles"] = sorted(cast(set[str], group.get("_program_titles") or set()), key=str.casefold)
        group["asset_types"] = sorted(cast(set[str], group.get("_asset_types") or set()), key=str.casefold)
        group["asset_specific_types"] = sorted(cast(set[str], group.get("_asset_specific_types") or set()), key=str.casefold)
        group["source_run_names"] = sorted(cast(set[str], group.get("_source_run_names") or set()), key=str.casefold)
        group["surfaces"] = sorted(cast(set[str], group.get("_surfaces") or set()), key=str.casefold)
        group["run_names"] = sorted(cast(set[str], group.get("_run_names") or set()), key=str.casefold)
        group["unit_conflict"] = _td_parameter_group_has_conflict(units, preferred_units)
        for key in (
            "_raw_names",
            "_units",
            "_program_titles",
            "_asset_types",
            "_asset_specific_types",
            "_source_run_names",
            "_surfaces",
            "_run_names",
        ):
            group.pop(key, None)

    inventory: list[dict[str, object]] = []
    for row in sorted(
        inventory_acc.values(),
        key=lambda item: (
            str(item.get("program_title") or "").casefold(),
            str(item.get("asset_type") or "").casefold(),
            str(item.get("asset_specific_type") or "").casefold(),
            str(item.get("raw_name") or "").casefold(),
        ),
    ):
        raw_name = str(row.get("raw_name") or "").strip()
        program_title = str(row.get("program_title") or "").strip()
        asset_type = str(row.get("asset_type") or "").strip()
        asset_specific_type = str(row.get("asset_specific_type") or "").strip()
        mapping_rule = dict(row.get("mapping_rule") or {})
        units_sorted = sorted(cast(set[str], row.get("_units") or set()), key=str.casefold)
        canonical_id = _td_effective_parameter_canonical(
            normalized,
            raw_name,
            program_title,
            asset_type,
            asset_specific_type,
            fallback_display=row.get("default_display_parameter"),
        )
        canonical_ids = [canonical_id] if canonical_id else []
        suggestion = _td_parameter_inventory_suggestion(
            raw_name,
            units=units_sorted,
            config_candidates=config_candidates,
        )
        primary_canonical_id = canonical_id or _td_parameter_implicit_canonical_id(raw_name)
        enabled = _td_parameter_mapping_rule_enabled(mapping_rule)
        status = "implicit"
        if mapping_rule:
            if not enabled:
                status = "disabled"
            else:
                status = "edited" if bool(mapping_rule.get("edited")) else "default"
        elif suggestion:
            status = "suggested"
        preferred_units = str(
            mapping_rule.get("preferred_units")
            or suggestion.get("preferred_units")
            or ""
        ).strip()
        if not preferred_units and len(units_sorted) == 1:
            preferred_units = units_sorted[0]
        display_name = _td_effective_parameter_display(
            normalized,
            raw_name,
            program_title=program_title,
            asset_type=asset_type,
            asset_specific_type=asset_specific_type,
            fallback_display=row.get("default_display_parameter") or raw_name,
        )
        inventory.append(
            {
                "raw_name": raw_name,
                "raw_norm": str(row.get("raw_norm") or "").strip(),
                "units": units_sorted,
                "program_title": program_title,
                "program_titles": [program_title] if program_title else [],
                "asset_type": asset_type,
                "asset_specific_type": asset_specific_type,
                "source_run_names": sorted(cast(set[str], row.get("_source_run_names") or set()), key=str.casefold),
                "surfaces": sorted(cast(set[str], row.get("_surfaces") or set()), key=str.casefold),
                "run_names": sorted(cast(set[str], row.get("_run_names") or set()), key=str.casefold),
                "canonical_ids": list(canonical_ids),
                "canonical_display": display_name,
                "default_display_parameter": str(row.get("default_display_parameter") or raw_name).strip(),
                "displayed_parameter": display_name,
                "preferred_units": preferred_units,
                "default_preferred_units": preferred_units,
                "primary_canonical_id": primary_canonical_id,
                "enabled": enabled,
                "status": status,
                "edited": bool(mapping_rule.get("edited")),
                "suggestion": suggestion,
                "source_count": len(cast(set[str], row.get("_source_keys") or set())) or len(cast(set[str], row.get("_source_run_names") or set())),
                "program_count": 1 if program_title else 0,
            }
        )

    return {
        "project_dir": str(proj_dir),
        "workbook_path": str(workbook or ""),
        "db_path": str(impl_db),
        "raw_db_path": str(raw_db),
        "normalization": normalized,
        "repo_parameter_rows": [dict(row) for row in (repo_parameter_rows or []) if isinstance(row, Mapping)],
        "inventory": inventory,
        "inventory_by_raw_norm": {
            str(row.get("raw_norm") or "").strip(): dict(row)
            for row in inventory
            if isinstance(row, Mapping) and str(row.get("raw_norm") or "").strip()
        },
        "entries": entries,
        "canonical_groups": {
            str(group_id): dict(group)
            for group_id, group in canonical_groups.items()
            if str(group_id).strip()
        },
        "config_candidates": config_candidates,
    }


def _td_build_runtime_inventory_from_entries(
    normalization: Mapping[str, object] | None,
    entries: Sequence[Mapping[str, object]] | None,
    *,
    canonical_groups: Mapping[str, Mapping[str, object]] | None = None,
) -> list[dict[str, object]]:
    normalized = _td_normalize_parameter_normalization(normalization)
    groups_by_id = {
        str(key): dict(value)
        for key, value in dict(canonical_groups or {}).items()
        if str(key).strip() and isinstance(value, Mapping)
    }
    inventory_acc: dict[tuple[str, str, str, str], dict[str, object]] = {}
    for entry in (entries or []):
        if not isinstance(entry, Mapping):
            continue
        raw_name = str(entry.get("raw_name") or "").strip()
        raw_norm = str(entry.get("raw_norm") or _td_param_norm_name(raw_name)).strip()
        if not raw_name or not raw_norm:
            continue
        program_title = str(entry.get("program_title") or "").strip()
        asset_type = _td_program_parameter_scope_text(entry.get("asset_type"))
        asset_specific_type = _td_program_parameter_scope_text(entry.get("asset_specific_type"))
        row_key = (
            raw_norm,
            _td_param_norm_program(program_title),
            _td_param_norm_program(asset_type),
            _td_param_norm_program(asset_specific_type),
        )
        row = inventory_acc.get(row_key)
        if row is None:
            row = {
                "raw_name": raw_name,
                "raw_norm": raw_norm,
                "program_title": program_title,
                "asset_type": asset_type,
                "asset_specific_type": asset_specific_type,
                "default_display_parameter": str(entry.get("default_display_parameter") or raw_name).strip() or raw_name,
                "_units": set(),
                "_source_run_names": set(),
                "_surfaces": set(),
                "_run_names": set(),
                "_source_keys": set(),
                "_canonical_ids": set(),
            }
            inventory_acc[row_key] = row
        units_text = str(entry.get("units") or "").strip()
        if units_text:
            cast(set[str], row["_units"]).add(units_text)
        source_run_name = str(entry.get("source_run_name") or "").strip()
        if source_run_name:
            cast(set[str], row["_source_run_names"]).add(source_run_name)
        surface_text = str(entry.get("surface") or "").strip().lower()
        if surface_text:
            cast(set[str], row["_surfaces"]).add(surface_text)
        run_name = str(entry.get("run_name") or "").strip()
        if run_name:
            cast(set[str], row["_run_names"]).add(run_name)
        source_key = str(entry.get("source_key") or "").strip()
        if source_key:
            cast(set[str], row["_source_keys"]).add(source_key)
        canonical_id = str(entry.get("canonical_id") or "").strip()
        if canonical_id:
            cast(set[str], row["_canonical_ids"]).add(canonical_id)

    inventory: list[dict[str, object]] = []
    for row in sorted(
        inventory_acc.values(),
        key=lambda item: (
            str(item.get("program_title") or "").casefold(),
            str(item.get("asset_type") or "").casefold(),
            str(item.get("asset_specific_type") or "").casefold(),
            str(item.get("raw_name") or "").casefold(),
        ),
    ):
        raw_name = str(row.get("raw_name") or "").strip()
        program_title = str(row.get("program_title") or "").strip()
        asset_type = str(row.get("asset_type") or "").strip()
        asset_specific_type = str(row.get("asset_specific_type") or "").strip()
        units_sorted = sorted(cast(set[str], row.get("_units") or set()), key=str.casefold)
        mapping_rule = _td_find_parameter_mapping_rule(
            normalized,
            raw_name,
            program_title=program_title,
            asset_type=asset_type,
            asset_specific_type=asset_specific_type,
        )
        canonical_ids = sorted(cast(set[str], row.get("_canonical_ids") or set()), key=str.casefold)
        primary_canonical_id = (
            canonical_ids[0]
            if canonical_ids
            else _td_effective_parameter_canonical(
                normalized,
                raw_name,
                program_title,
                asset_type,
                asset_specific_type,
                fallback_display=row.get("default_display_parameter") or raw_name,
            )
        )
        group = dict(groups_by_id.get(primary_canonical_id) or {})
        enabled = _td_parameter_mapping_rule_enabled(mapping_rule)
        status = "implicit"
        if mapping_rule:
            if not enabled:
                status = "disabled"
            else:
                status = "edited" if bool(mapping_rule.get("edited")) else "default"
        preferred_units = str(
            mapping_rule.get("preferred_units")
            or group.get("preferred_units")
            or ""
        ).strip()
        if not preferred_units and len(units_sorted) == 1:
            preferred_units = units_sorted[0]
        display_name = _td_effective_parameter_display(
            normalized,
            raw_name,
            program_title=program_title,
            asset_type=asset_type,
            asset_specific_type=asset_specific_type,
            fallback_display=row.get("default_display_parameter") or group.get("display_name") or raw_name,
        )
        inventory.append(
            {
                "raw_name": raw_name,
                "raw_norm": str(row.get("raw_norm") or "").strip(),
                "units": units_sorted,
                "program_title": program_title,
                "program_titles": [program_title] if program_title else [],
                "asset_type": asset_type,
                "asset_specific_type": asset_specific_type,
                "source_run_names": sorted(cast(set[str], row.get("_source_run_names") or set()), key=str.casefold),
                "surfaces": sorted(cast(set[str], row.get("_surfaces") or set()), key=str.casefold),
                "run_names": sorted(cast(set[str], row.get("_run_names") or set()), key=str.casefold),
                "canonical_ids": canonical_ids or [primary_canonical_id],
                "canonical_display": display_name,
                "default_display_parameter": str(row.get("default_display_parameter") or raw_name).strip() or raw_name,
                "displayed_parameter": display_name,
                "preferred_units": preferred_units,
                "default_preferred_units": preferred_units,
                "primary_canonical_id": primary_canonical_id,
                "enabled": enabled,
                "status": status,
                "edited": bool(mapping_rule.get("edited")),
                "suggestion": {},
                "source_count": len(cast(set[str], row.get("_source_keys") or set())) or len(cast(set[str], row.get("_source_run_names") or set())),
                "program_count": 1 if program_title else 0,
            }
        )
    return inventory


def rebuild_td_parameter_discovery_cache(
    project_dir: Path,
    workbook_path: Path,
    db_path: Path,
    progress_cb: Callable[[str], None] | None = None,
) -> dict[str, object]:
    import time

    proj_dir = Path(project_dir).expanduser()
    del workbook_path
    impl_db = Path(db_path).expanduser()
    raw_db = td_raw_cache_db_path_for(proj_dir)
    started = time.perf_counter()
    with sqlite3.connect(str(impl_db)) as conn:
        _ensure_test_data_impl_tables(conn)
        discovery_signature = _td_parameter_discovery_signature(conn)
        if (
            _td_meta_value(conn, TD_PARAM_DISCOVERY_SIGNATURE_META_KEY) == discovery_signature
            and _td_parameter_discovery_table_ready(conn, require_rows=True)
        ):
            return {
                "mode": "noop",
                "rows": int(conn.execute(f"SELECT COUNT(*) FROM {TD_PARAM_DISCOVERY_TABLE}").fetchone()[0] or 0),
                "signature": discovery_signature,
                "elapsed_s": round(time.perf_counter() - started, 3),
            }
    _td_emit_progress(progress_cb, "Scanning parameter discovery rows from TD caches")
    discovery_rows = _td_collect_parameter_discovery_rows_from_cache(impl_db, raw_db)
    with sqlite3.connect(str(impl_db)) as conn:
        _ensure_test_data_impl_tables(conn)
        _td_write_parameter_discovery_rows(conn, discovery_rows)
        discovery_signature = _td_parameter_discovery_signature(conn)
        built_epoch_ns = _td_meta_value(conn, "built_epoch_ns")
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            (TD_PARAM_DISCOVERY_SIGNATURE_META_KEY, discovery_signature),
        )
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            (TD_PARAM_DISCOVERY_BUILT_META_KEY, built_epoch_ns),
        )
        conn.commit()
    elapsed = round(time.perf_counter() - started, 3)
    _td_emit_progress(progress_cb, f"Parameter discovery cache ready in {elapsed:.3f}s ({len(discovery_rows)} rows)")
    return {
        "mode": "rebuilt",
        "rows": len(discovery_rows),
        "signature": discovery_signature,
        "elapsed_s": elapsed,
    }


def refresh_td_parameter_runtime_cache(
    project_dir: Path,
    workbook_path: Path,
    db_path: Path,
    progress_cb: Callable[[str], None] | None = None,
) -> dict[str, object]:
    import time

    proj_dir = Path(project_dir).expanduser()
    workbook = Path(workbook_path).expanduser()
    impl_db = Path(db_path).expanduser()
    discovery_payload = rebuild_td_parameter_discovery_cache(
        proj_dir,
        workbook,
        impl_db,
        progress_cb=progress_cb,
    )
    repo_parameter_rows = load_td_repo_parameter_mappings(
        proj_dir,
        workbook_path=workbook,
        db_path=impl_db,
    )
    started = time.perf_counter()
    with sqlite3.connect(str(impl_db)) as conn:
        _ensure_test_data_impl_tables(conn)
        discovery_signature = _td_meta_value(conn, TD_PARAM_DISCOVERY_SIGNATURE_META_KEY) or _td_parameter_discovery_signature(conn)
        runtime_signature = _td_parameter_runtime_signature(discovery_signature, repo_parameter_rows)
        if (
            _td_meta_value(conn, TD_PARAM_RUNTIME_SIGNATURE_META_KEY) == runtime_signature
            and _td_parameter_runtime_tables_ready(conn, require_rows=True)
        ):
            return {
                "mode": "noop",
                "signature": runtime_signature,
                "elapsed_s": round(time.perf_counter() - started, 3),
                "discovery": dict(discovery_payload),
            }
    _td_emit_progress(progress_cb, "Building parameter runtime normalization cache")
    context = td_build_parameter_normalization_context(
        proj_dir,
        workbook,
        impl_db,
    )
    normalization = _td_normalize_parameter_normalization(context.get("normalization"))
    canonical_groups = {
        str(group_id): dict(group)
        for group_id, group in dict(context.get("canonical_groups") or {}).items()
        if str(group_id).strip() and isinstance(group, Mapping)
    }
    runtime_entries = [
        dict(item)
        for item in (context.get("entries") or [])
        if isinstance(item, Mapping)
    ]
    with sqlite3.connect(str(impl_db)) as conn:
        _ensure_test_data_impl_tables(conn)
        _td_clear_parameter_runtime_tables(conn)
        group_rows = [
            (
                str(group.get("id") or "").strip(),
                str(group.get("display_name") or "").strip(),
                str(group.get("preferred_units") or "").strip(),
                1 if bool(group.get("explicit")) else 0,
            )
            for group in (normalization.get("groups") or [])
            if isinstance(group, Mapping) and str(group.get("id") or "").strip()
        ]
        if group_rows:
            conn.executemany(
                f"""
                INSERT OR REPLACE INTO {TD_PARAM_NORM_GROUPS_TABLE} (
                    canonical_id,
                    display_name,
                    preferred_units,
                    explicit
                ) VALUES (?, ?, ?, ?)
                """,
                group_rows,
            )
        rule_rows = []
        for rule in (normalization.get("mappings") or []):
            if not isinstance(rule, Mapping):
                continue
            raw_name = str(rule.get("raw_name") or "").strip()
            canonical_id = str(rule.get("canonical_id") or "").strip()
            if not raw_name or not canonical_id:
                continue
            program_title = ",".join(
                sorted({str(value).strip() for value in (rule.get("program_titles") or []) if str(value).strip()}, key=str.casefold)
            )
            asset_type = ",".join(
                sorted({str(value).strip() for value in (rule.get("asset_types") or []) if str(value).strip()}, key=str.casefold)
            )
            asset_specific_type = ",".join(
                sorted({str(value).strip() for value in (rule.get("asset_specific_types") or []) if str(value).strip()}, key=str.casefold)
            )
            rule_rows.append(
                (
                    raw_name,
                    _td_param_norm_name(raw_name),
                    program_title,
                    _td_param_norm_program(program_title),
                    asset_type,
                    _td_param_norm_program(asset_type),
                    asset_specific_type,
                    _td_param_norm_program(asset_specific_type),
                    canonical_id,
                    str(rule.get("default_display_parameter") or "").strip(),
                    str(rule.get("displayed_parameter") or "").strip(),
                    str(rule.get("preferred_units") or "").strip(),
                    1 if _td_parameter_mapping_rule_enabled(rule) else 0,
                    1 if bool(rule.get("edited")) else 0,
                )
            )
        if rule_rows:
            conn.executemany(
                f"""
                INSERT OR REPLACE INTO {TD_PARAM_NORM_RULES_TABLE} (
                    raw_name,
                    raw_norm,
                    program_title,
                    program_norm,
                    asset_type,
                    asset_norm,
                    asset_specific_type,
                    asset_specific_norm,
                    canonical_id,
                    default_display_parameter,
                    displayed_parameter,
                    preferred_units,
                    enabled,
                    edited
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                rule_rows,
            )
        entry_rows = [
            (
                str(item.get("surface") or "").strip().lower(),
                str(item.get("run_name") or "").strip(),
                str(item.get("raw_name") or "").strip(),
                str(item.get("raw_norm") or _td_param_norm_name(item.get("raw_name"))).strip(),
                str(item.get("units") or "").strip(),
                str(item.get("program_title") or "").strip(),
                str(item.get("asset_type") or "").strip(),
                str(item.get("asset_specific_type") or "").strip(),
                str(item.get("source_run_name") or "").strip(),
                str(item.get("source_key") or "").strip(),
                _td_effective_parameter_canonical(
                    normalization,
                    item.get("raw_name"),
                    item.get("program_title"),
                    item.get("asset_type"),
                    item.get("asset_specific_type"),
                    fallback_display=item.get("default_display_parameter"),
                ),
                str(item.get("default_display_parameter") or "").strip(),
            )
            for item in runtime_entries
            if str(item.get("surface") or "").strip()
            and str(item.get("run_name") or "").strip()
            and str(item.get("raw_name") or "").strip()
        ]
        if entry_rows:
            conn.executemany(
                f"""
                INSERT OR REPLACE INTO {TD_PARAM_RUNTIME_ENTRIES_TABLE} (
                    surface,
                    run_name,
                    raw_name,
                    raw_norm,
                    units,
                    program_title,
                    asset_type,
                    asset_specific_type,
                    source_run_name,
                    source_key,
                    canonical_id,
                    default_display_parameter
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                entry_rows,
            )
        runtime_group_rows = [
            (
                str(group_id).strip(),
                str(group.get("display_name") or "").strip(),
                str(group.get("preferred_units") or "").strip(),
                json.dumps([str(value).strip() for value in (group.get("raw_names") or []) if str(value).strip()], separators=(",", ":")),
                json.dumps([str(value).strip() for value in (group.get("units") or []) if str(value).strip()], separators=(",", ":")),
                json.dumps([str(value).strip() for value in (group.get("program_titles") or []) if str(value).strip()], separators=(",", ":")),
                json.dumps([str(value).strip() for value in (group.get("asset_types") or []) if str(value).strip()], separators=(",", ":")),
                json.dumps([str(value).strip() for value in (group.get("asset_specific_types") or []) if str(value).strip()], separators=(",", ":")),
                json.dumps([str(value).strip() for value in (group.get("source_run_names") or []) if str(value).strip()], separators=(",", ":")),
                json.dumps([str(value).strip() for value in (group.get("surfaces") or []) if str(value).strip()], separators=(",", ":")),
                json.dumps([str(value).strip() for value in (group.get("run_names") or []) if str(value).strip()], separators=(",", ":")),
                1 if bool(group.get("unit_conflict")) else 0,
                1 if bool(group.get("explicit")) else 0,
            )
            for group_id, group in canonical_groups.items()
            if str(group_id).strip()
        ]
        if runtime_group_rows:
            conn.executemany(
                f"""
                INSERT OR REPLACE INTO {TD_PARAM_RUNTIME_GROUPS_TABLE} (
                    canonical_id,
                    display_name,
                    preferred_units,
                    raw_names_json,
                    units_json,
                    program_titles_json,
                    asset_types_json,
                    asset_specific_types_json,
                    source_run_names_json,
                    surfaces_json,
                    run_names_json,
                    unit_conflict,
                    explicit
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                runtime_group_rows,
            )
        discovery_signature = _td_meta_value(conn, TD_PARAM_DISCOVERY_SIGNATURE_META_KEY) or _td_parameter_discovery_signature(conn)
        runtime_signature = _td_parameter_runtime_signature(discovery_signature, repo_parameter_rows)
        built_epoch_ns = _td_meta_value(conn, "built_epoch_ns")
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            (TD_PARAM_RUNTIME_SIGNATURE_META_KEY, runtime_signature),
        )
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            (TD_PARAM_RUNTIME_BUILT_META_KEY, built_epoch_ns),
        )
        conn.commit()
    elapsed = round(time.perf_counter() - started, 3)
    _td_emit_progress(
        progress_cb,
        f"Parameter runtime cache ready in {elapsed:.3f}s ({len(runtime_entries)} entries, {len(canonical_groups)} groups)",
    )
    return {
        "mode": "rebuilt",
        "entries": len(runtime_entries),
        "groups": len(canonical_groups),
        "signature": runtime_signature,
        "elapsed_s": elapsed,
        "discovery": dict(discovery_payload),
    }


def td_load_parameter_runtime_context(project_dir: Path, db_path: Path) -> dict[str, object]:
    proj_dir = Path(project_dir).expanduser()
    impl_db = Path(db_path).expanduser()
    if not impl_db.exists():
        return {}
    repo_parameter_rows = load_td_repo_parameter_mappings(
        proj_dir,
        db_path=impl_db,
    )

    rebuilt_context: dict[str, object] | None = None

    def _rebuilt_runtime_context() -> dict[str, object]:
        nonlocal rebuilt_context
        if rebuilt_context is not None:
            return dict(rebuilt_context)
        context = td_build_parameter_normalization_context(
            proj_dir,
            db_path=impl_db,
        )
        rebuilt_context = dict(context) if isinstance(context, Mapping) else {}
        if rebuilt_context:
            rebuilt_context["project_dir"] = str(proj_dir)
            rebuilt_context["db_path"] = str(impl_db)
            rebuilt_context["runtime_mode"] = "rebuilt"
            rebuilt_context["repo_parameter_rows"] = [
                dict(row)
                for row in repo_parameter_rows
                if isinstance(row, Mapping)
            ]
        return dict(rebuilt_context)

    with closing(sqlite3.connect(str(impl_db))) as conn:
        if not _td_parameter_runtime_tables_ready(conn, require_rows=True):
            return _rebuilt_runtime_context()
        discovery_signature = str(_td_meta_value(conn, TD_PARAM_DISCOVERY_SIGNATURE_META_KEY) or "").strip()
        discovery_rows_ready = _td_parameter_discovery_table_ready(conn, require_rows=True)
        if discovery_rows_ready and not discovery_signature:
            discovery_signature = _td_parameter_discovery_signature(conn)
        can_validate_runtime = bool(repo_parameter_rows) or discovery_rows_ready or bool(discovery_signature)
        if can_validate_runtime:
            expected_runtime_signature = _td_parameter_runtime_signature(
                discovery_signature,
                repo_parameter_rows,
            )
            cached_runtime_signature = str(_td_meta_value(conn, TD_PARAM_RUNTIME_SIGNATURE_META_KEY) or "").strip()
            if cached_runtime_signature != expected_runtime_signature:
                return _rebuilt_runtime_context()
        group_rows = conn.execute(
            f"""
            SELECT canonical_id, display_name, preferred_units, explicit
            FROM {TD_PARAM_NORM_GROUPS_TABLE}
            ORDER BY canonical_id
            """
        ).fetchall()
        rule_rows = conn.execute(
            f"""
            SELECT
                canonical_id,
                raw_name,
                program_title,
                asset_type,
                asset_specific_type,
                default_display_parameter,
                displayed_parameter,
                preferred_units,
                enabled,
                edited
            FROM {TD_PARAM_NORM_RULES_TABLE}
            ORDER BY raw_norm, program_norm, asset_norm, asset_specific_norm, canonical_id
            """
        ).fetchall()
        runtime_group_rows = conn.execute(
            f"""
            SELECT
                canonical_id,
                display_name,
                preferred_units,
                raw_names_json,
                units_json,
                program_titles_json,
                asset_types_json,
                asset_specific_types_json,
                source_run_names_json,
                surfaces_json,
                run_names_json,
                unit_conflict,
                explicit
            FROM {TD_PARAM_RUNTIME_GROUPS_TABLE}
            ORDER BY canonical_id
            """
        ).fetchall()
        entry_rows = conn.execute(
            f"""
            SELECT
                surface,
                run_name,
                raw_name,
                raw_norm,
                COALESCE(units, ''),
                COALESCE(program_title, ''),
                COALESCE(asset_type, ''),
                COALESCE(asset_specific_type, ''),
                COALESCE(source_run_name, ''),
                COALESCE(source_key, ''),
                COALESCE(canonical_id, ''),
                COALESCE(default_display_parameter, '')
            FROM {TD_PARAM_RUNTIME_ENTRIES_TABLE}
            ORDER BY surface, run_name, raw_name, program_title, asset_type, asset_specific_type, source_run_name
            """
        ).fetchall()
    normalization_groups = [
        {
            "id": str(canonical_id or "").strip(),
            "display_name": str(display_name or "").strip(),
            "preferred_units": str(preferred_units or "").strip(),
            "explicit": bool(explicit),
        }
        for canonical_id, display_name, preferred_units, explicit in group_rows
        if str(canonical_id or "").strip()
    ]
    normalization_rules = [
        {
            "canonical_id": str(canonical_id or "").strip(),
            "raw_name": str(raw_name or "").strip(),
            "program_titles": [str(value).strip() for value in str(program_title or "").split(",") if str(value).strip()],
            "asset_types": [str(value).strip() for value in str(asset_type or "").split(",") if str(value).strip()],
            "asset_specific_types": [str(value).strip() for value in str(asset_specific_type or "").split(",") if str(value).strip()],
            "default_display_parameter": str(default_display_parameter or "").strip(),
            "displayed_parameter": str(displayed_parameter or "").strip(),
            "preferred_units": str(preferred_units or "").strip(),
            "enabled": bool(enabled),
            "edited": bool(edited),
        }
        for canonical_id, raw_name, program_title, asset_type, asset_specific_type, default_display_parameter, displayed_parameter, preferred_units, enabled, edited in rule_rows
        if str(canonical_id or "").strip() and str(raw_name or "").strip()
    ]
    canonical_groups: dict[str, dict[str, object]] = {}
    for row in runtime_group_rows:
        (
            canonical_id,
            display_name,
            preferred_units,
            raw_names_json,
            units_json,
            program_titles_json,
            asset_types_json,
            asset_specific_types_json,
            source_run_names_json,
            surfaces_json,
            run_names_json,
            unit_conflict,
            explicit,
        ) = row
        key = str(canonical_id or "").strip()
        if not key:
            continue
        try:
            raw_names = json.loads(raw_names_json or "[]")
        except Exception:
            raw_names = []
        try:
            units = json.loads(units_json or "[]")
        except Exception:
            units = []
        try:
            program_titles = json.loads(program_titles_json or "[]")
        except Exception:
            program_titles = []
        try:
            asset_types = json.loads(asset_types_json or "[]")
        except Exception:
            asset_types = []
        try:
            asset_specific_types = json.loads(asset_specific_types_json or "[]")
        except Exception:
            asset_specific_types = []
        try:
            source_run_names = json.loads(source_run_names_json or "[]")
        except Exception:
            source_run_names = []
        try:
            surfaces = json.loads(surfaces_json or "[]")
        except Exception:
            surfaces = []
        try:
            run_names = json.loads(run_names_json or "[]")
        except Exception:
            run_names = []
        canonical_groups[key] = {
            "id": key,
            "display_name": str(display_name or "").strip(),
            "preferred_units": str(preferred_units or "").strip(),
            "raw_names": [str(value).strip() for value in raw_names if str(value).strip()],
            "units": [str(value).strip() for value in units if str(value).strip()],
            "program_titles": [str(value).strip() for value in program_titles if str(value).strip()],
            "asset_types": [str(value).strip() for value in asset_types if str(value).strip()],
            "asset_specific_types": [str(value).strip() for value in asset_specific_types if str(value).strip()],
            "source_run_names": [str(value).strip() for value in source_run_names if str(value).strip()],
            "surfaces": [str(value).strip() for value in surfaces if str(value).strip()],
            "run_names": [str(value).strip() for value in run_names if str(value).strip()],
            "unit_conflict": bool(unit_conflict),
            "explicit": bool(explicit),
        }
    entries = [
        {
            "surface": str(surface or "").strip().lower(),
            "run_name": str(run_name or "").strip(),
            "raw_name": str(raw_name or "").strip(),
            "raw_norm": str(raw_norm or _td_param_norm_name(raw_name)).strip(),
            "units": str(units or "").strip(),
            "program_title": str(program_title or "").strip(),
            "program_norm": _td_param_norm_program(program_title),
            "asset_type": str(asset_type or "").strip(),
            "asset_specific_type": str(asset_specific_type or "").strip(),
            "source_run_name": str(source_run_name or "").strip(),
            "source_key": str(source_key or "").strip(),
            "canonical_id": str(canonical_id or "").strip(),
            "default_display_parameter": str(default_display_parameter or "").strip(),
        }
        for (
            surface,
            run_name,
            raw_name,
            raw_norm,
            units,
            program_title,
            asset_type,
            asset_specific_type,
            source_run_name,
            source_key,
            canonical_id,
            default_display_parameter,
        ) in entry_rows
        if str(raw_name or "").strip()
    ]
    normalization = _td_normalize_parameter_normalization(
        {
            "version": TD_PARAMETER_NORMALIZATION_VERSION,
            "groups": normalization_groups,
            "mappings": normalization_rules,
        }
    )
    normalization, canonical_groups = _td_project_parameter_group_overrides(
        proj_dir,
        normalization,
        canonical_groups=canonical_groups,
    )
    inventory = _td_build_runtime_inventory_from_entries(
        normalization,
        entries,
        canonical_groups=canonical_groups,
    )
    return {
        "project_dir": str(proj_dir),
        "db_path": str(impl_db),
        "runtime_mode": "db",
        "normalization": normalization,
        "repo_parameter_rows": [
            dict(row)
            for row in repo_parameter_rows
            if isinstance(row, Mapping)
        ],
        "entries": entries,
        "inventory": inventory,
        "inventory_by_raw_norm": {
            str(row.get("raw_norm") or "").strip(): dict(row)
            for row in inventory
            if isinstance(row, Mapping) and str(row.get("raw_norm") or "").strip()
        },
        "canonical_groups": canonical_groups,
    }


def td_build_parameter_normalization_context(
    project_dir: Path,
    workbook_path: Path | None = None,
    db_path: Path | None = None,
    normalization_override: Mapping[str, object] | None = None,
) -> dict[str, object]:
    proj_dir = Path(project_dir).expanduser()
    impl_db = Path(db_path).expanduser() if db_path else (proj_dir / EIDAT_PROJECT_IMPLEMENTATION_DB)
    raw_db = td_raw_cache_db_path_for(proj_dir)
    workbook = Path(workbook_path).expanduser() if workbook_path else Path()
    repo_parameter_rows = load_td_repo_parameter_mappings(
        proj_dir,
        workbook_path=workbook if workbook else None,
        db_path=impl_db,
    )
    normalization = (
        _td_normalize_parameter_normalization(normalization_override)
        if isinstance(normalization_override, Mapping)
        else _td_build_repo_parameter_normalization(repo_parameter_rows)
    )
    normalization, _canonical_groups_unused = _td_project_parameter_group_overrides(
        proj_dir,
        normalization,
    )
    discovery_rows: list[dict[str, str]] = []
    if impl_db.exists():
        with closing(sqlite3.connect(str(impl_db))) as conn:
            discovery_rows = _td_parameter_discovery_rows_from_table(conn)
    if not discovery_rows:
        discovery_rows = _td_collect_parameter_discovery_rows_from_cache(impl_db, raw_db)
    return _td_build_parameter_context_from_discovery_rows(
        proj_dir=proj_dir,
        workbook=workbook,
        impl_db=impl_db,
        raw_db=raw_db,
        normalization=normalization,
        repo_parameter_rows=repo_parameter_rows,
        discovery_rows=discovery_rows,
    )


def td_build_parameter_selector_options(
    context: Mapping[str, object] | None,
    *,
    run_names: Sequence[object] | None = None,
    surface: object = "",
    raw_names: Sequence[object] | None = None,
) -> list[dict[str, object]]:
    ctx = dict(context or {})
    normalization = _td_normalize_parameter_normalization(ctx.get("normalization"))
    run_set = {str(value).strip() for value in (run_names or []) if str(value).strip()}
    surface_key = str(surface or "").strip().lower()
    raw_norms = {_td_param_norm_name(value) for value in (raw_names or []) if _td_param_norm_name(value)}
    if _td_parameter_runtime_context_enabled(ctx):
        db_path = Path(str(ctx.get("db_path") or "")).expanduser()
        if db_path.exists():
            query_parts = [
                "SELECT canonical_id, raw_name, COALESCE(units, ''), COALESCE(program_title, ''),",
                "       COALESCE(asset_type, ''), COALESCE(asset_specific_type, ''), run_name, surface",
                f"FROM {TD_PARAM_RUNTIME_ENTRIES_TABLE}",
                "WHERE 1=1",
            ]
            params: list[object] = []
            if surface_key:
                query_parts.append("AND surface=?")
                params.append(surface_key)
            if run_set:
                placeholders = ",".join("?" for _ in run_set)
                query_parts.append(f"AND run_name IN ({placeholders})")
                params.extend(sorted(run_set))
            if raw_norms:
                placeholders = ",".join("?" for _ in raw_norms)
                query_parts.append(f"AND raw_norm IN ({placeholders})")
                params.extend(sorted(raw_norms))
            query_parts.append("ORDER BY canonical_id, raw_name")
            groups_runtime: dict[str, dict[str, object]] = {}
            try:
                with closing(sqlite3.connect(str(db_path))) as conn:
                    _ensure_test_data_impl_tables(conn)
                    rows = conn.execute(" ".join(query_parts), tuple(params)).fetchall()
            except Exception:
                rows = []
            for canonical_id, raw_name, units, program_title, asset_type, asset_specific_type, run_name, entry_surface in rows:
                canonical_key = str(canonical_id or "").strip()
                raw_text = str(raw_name or "").strip()
                if not canonical_key or not raw_text:
                    continue
                rule = _td_find_parameter_mapping_rule(
                    normalization,
                    raw_text,
                    program_title=program_title,
                    asset_type=asset_type,
                    asset_specific_type=asset_specific_type,
                )
                if rule and not _td_parameter_mapping_rule_enabled(rule):
                    continue
                group = groups_runtime.setdefault(
                    canonical_key,
                    {
                        "canonical_id": canonical_key,
                        "_raw_names": set(),
                        "_units": set(),
                        "_program_titles": set(),
                        "_asset_types": set(),
                        "_asset_specific_types": set(),
                        "_run_names": set(),
                        "_surfaces": set(),
                    },
                )
                cast(set[str], group["_raw_names"]).add(raw_text)
                if str(units or "").strip():
                    cast(set[str], group["_units"]).add(str(units or "").strip())
                if str(program_title or "").strip():
                    cast(set[str], group["_program_titles"]).add(str(program_title or "").strip())
                if str(asset_type or "").strip():
                    cast(set[str], group["_asset_types"]).add(str(asset_type or "").strip())
                if str(asset_specific_type or "").strip():
                    cast(set[str], group["_asset_specific_types"]).add(str(asset_specific_type or "").strip())
                if str(run_name or "").strip():
                    cast(set[str], group["_run_names"]).add(str(run_name or "").strip())
                if str(entry_surface or "").strip():
                    cast(set[str], group["_surfaces"]).add(str(entry_surface or "").strip())
            options_runtime: list[dict[str, object]] = []
            for canonical_id, group in groups_runtime.items():
                raw_name_list = sorted(cast(set[str], group.get("_raw_names") or set()), key=str.casefold)
                if not raw_name_list:
                    continue
                units = sorted(cast(set[str], group.get("_units") or set()), key=str.casefold)
                unit_conflict = False
                display_name = _td_parameter_display_name_for_group(
                    normalization,
                    canonical_id,
                    raw_names=raw_name_list,
                    fallback=raw_name_list[0],
                )
                preferred_units = str(
                    ((normalization.get("groups_by_id") or {}).get(canonical_id) or {}).get("preferred_units")
                    if isinstance(normalization.get("groups_by_id"), Mapping)
                    else ""
                ).strip()
                if not preferred_units and len(units) == 1:
                    preferred_units = units[0]
                unit_conflict = _td_parameter_group_has_conflict(units, preferred_units)
                label = f"{display_name} ({preferred_units})" if preferred_units else display_name
                if unit_conflict:
                    label = f"{label} [unit conflict]"
                search = " ".join(
                    [
                        display_name,
                        label,
                        " ".join(raw_name_list),
                        " ".join(sorted(cast(set[str], group.get("_program_titles") or set()), key=str.casefold)),
                    ]
                ).strip().lower()
                options_runtime.append(
                    {
                        "value": td_parameter_selector_value(canonical_id),
                        "canonical_id": canonical_id,
                        "display_name": display_name,
                        "label": label,
                        "preferred_units": preferred_units,
                        "units": units,
                        "unit_conflict": unit_conflict,
                        "raw_names": raw_name_list,
                        "program_titles": sorted(cast(set[str], group.get("_program_titles") or set()), key=str.casefold),
                        "asset_types": sorted(cast(set[str], group.get("_asset_types") or set()), key=str.casefold),
                        "asset_specific_types": sorted(cast(set[str], group.get("_asset_specific_types") or set()), key=str.casefold),
                        "run_names": sorted(cast(set[str], group.get("_run_names") or set()), key=str.casefold),
                        "surfaces": sorted(cast(set[str], group.get("_surfaces") or set()), key=str.casefold),
                        "search": search,
                    }
                )
            options_runtime.sort(
                key=lambda item: (
                    str(item.get("display_name") or "").casefold(),
                    str(item.get("label") or "").casefold(),
                )
            )
            if options_runtime:
                return options_runtime
    groups: dict[str, dict[str, object]] = {}
    for entry in (ctx.get("entries") or []):
        if not isinstance(entry, Mapping):
            continue
        entry_surface = str(entry.get("surface") or "").strip().lower()
        if surface_key and entry_surface != surface_key:
            continue
        entry_run = str(entry.get("run_name") or "").strip()
        if run_set and entry_run not in run_set:
            continue
        entry_raw_name = str(entry.get("raw_name") or "").strip()
        entry_raw_norm = _td_param_norm_name(entry_raw_name)
        if raw_norms and entry_raw_norm not in raw_norms:
            continue
        rule = _td_find_parameter_mapping_rule(
            normalization,
            entry_raw_name,
            program_title=entry.get("program_title"),
            asset_type=entry.get("asset_type"),
            asset_specific_type=entry.get("asset_specific_type"),
        )
        if rule and not _td_parameter_mapping_rule_enabled(rule):
            continue
        canonical_id = _td_effective_parameter_canonical(
            normalization,
            entry_raw_name,
            entry.get("program_title"),
            entry.get("asset_type"),
            entry.get("asset_specific_type"),
            fallback_display=entry.get("default_display_parameter"),
        )
        group = groups.setdefault(
            canonical_id,
            {
                "canonical_id": canonical_id,
                "_raw_names": set(),
                "_units": set(),
                "_program_titles": set(),
                "_asset_types": set(),
                "_asset_specific_types": set(),
                "_run_names": set(),
                "_surfaces": set(),
            },
        )
        cast(set[str], group["_raw_names"]).add(entry_raw_name)
        if str(entry.get("units") or "").strip():
            cast(set[str], group["_units"]).add(str(entry.get("units") or "").strip())
        if str(entry.get("program_title") or "").strip():
            cast(set[str], group["_program_titles"]).add(str(entry.get("program_title") or "").strip())
        if str(entry.get("asset_type") or "").strip():
            cast(set[str], group["_asset_types"]).add(str(entry.get("asset_type") or "").strip())
        if str(entry.get("asset_specific_type") or "").strip():
            cast(set[str], group["_asset_specific_types"]).add(str(entry.get("asset_specific_type") or "").strip())
        if entry_run:
            cast(set[str], group["_run_names"]).add(entry_run)
        if entry_surface:
            cast(set[str], group["_surfaces"]).add(entry_surface)
    if raw_norms:
        inventory_by_raw_norm = ctx.get("inventory_by_raw_norm") if isinstance(ctx.get("inventory_by_raw_norm"), Mapping) else {}
        for raw_name in (raw_names or []):
            raw_text = str(raw_name or "").strip()
            raw_norm = _td_param_norm_name(raw_text)
            if not raw_text or not raw_norm:
                continue
            if any(raw_text in cast(set[str], group.get("_raw_names") or set()) for group in groups.values()):
                continue
            inventory_row = dict(inventory_by_raw_norm.get(raw_norm) or {})
            if inventory_row and not _td_bool(inventory_row.get("enabled"), True):
                continue
            canonical_id = str(inventory_row.get("primary_canonical_id") or "").strip() or _td_parameter_implicit_canonical_id(raw_text)
            group = groups.setdefault(
                canonical_id,
                {
                    "canonical_id": canonical_id,
                    "_raw_names": {raw_text},
                    "_units": set(str(value).strip() for value in (inventory_row.get("units") or []) if str(value).strip()),
                    "_program_titles": set(
                        str(value).strip() for value in (inventory_row.get("program_titles") or []) if str(value).strip()
                    ),
                    "_asset_types": {str(inventory_row.get("asset_type") or "").strip()} if str(inventory_row.get("asset_type") or "").strip() else set(),
                    "_asset_specific_types": {str(inventory_row.get("asset_specific_type") or "").strip()} if str(inventory_row.get("asset_specific_type") or "").strip() else set(),
                    "_run_names": set(str(value).strip() for value in (inventory_row.get("run_names") or []) if str(value).strip()),
                    "_surfaces": set(str(value).strip() for value in (inventory_row.get("surfaces") or []) if str(value).strip()),
                },
            )
            cast(set[str], group["_raw_names"]).add(raw_text)
    options: list[dict[str, object]] = []
    for canonical_id, group in groups.items():
        raw_name_list = sorted(cast(set[str], group.get("_raw_names") or set()), key=str.casefold)
        if not raw_name_list:
            continue
        units = sorted(cast(set[str], group.get("_units") or set()), key=str.casefold)
        unit_conflict = False
        display_name = _td_parameter_display_name_for_group(
            normalization,
            canonical_id,
            raw_names=raw_name_list,
            fallback=raw_name_list[0],
        )
        preferred_units = str(
            ((normalization.get("groups_by_id") or {}).get(canonical_id) or {}).get("preferred_units")
            if isinstance(normalization.get("groups_by_id"), Mapping)
            else ""
        ).strip()
        if not preferred_units and len(units) == 1:
            preferred_units = units[0]
        unit_conflict = _td_parameter_group_has_conflict(units, preferred_units)
        label = f"{display_name} ({preferred_units})" if preferred_units else display_name
        if unit_conflict:
            label = f"{label} [unit conflict]"
        search = " ".join(
            [
                display_name,
                label,
                " ".join(raw_name_list),
                " ".join(sorted(cast(set[str], group.get("_program_titles") or set()), key=str.casefold)),
            ]
        ).strip().lower()
        options.append(
            {
                "value": td_parameter_selector_value(canonical_id),
                "canonical_id": canonical_id,
                "display_name": display_name,
                "label": label,
                "preferred_units": preferred_units,
                "units": units,
                "unit_conflict": unit_conflict,
                "raw_names": raw_name_list,
                "program_titles": sorted(cast(set[str], group.get("_program_titles") or set()), key=str.casefold),
                "asset_types": sorted(cast(set[str], group.get("_asset_types") or set()), key=str.casefold),
                "asset_specific_types": sorted(cast(set[str], group.get("_asset_specific_types") or set()), key=str.casefold),
                "run_names": sorted(cast(set[str], group.get("_run_names") or set()), key=str.casefold),
                "surfaces": sorted(cast(set[str], group.get("_surfaces") or set()), key=str.casefold),
                "search": search,
            }
        )
    options.sort(
        key=lambda item: (
            str(item.get("display_name") or "").casefold(),
            str(item.get("label") or "").casefold(),
        )
    )
    return options


def td_parameter_selection_matches(
    context: Mapping[str, object] | None,
    selection_value: object,
    raw_name: object,
    program_title: object = "",
    asset_type: object = "",
    asset_specific_type: object = "",
) -> bool:
    selected = str(selection_value or "").strip()
    raw_text = str(raw_name or "").strip()
    if not selected or not raw_text:
        return False
    if td_parameter_selector_is_canonical(selected):
        normalization = _td_normalize_parameter_normalization(dict(context or {}).get("normalization"))
        wanted_id = td_parameter_selector_canonical_id(selected)
        if not wanted_id:
            return False
        return wanted_id == _td_effective_parameter_canonical(
            normalization,
            raw_text,
            program_title,
            asset_type,
            asset_specific_type,
        )
    return _td_param_norm_name(selected) == _td_param_norm_name(raw_text)


def td_parameter_selection_raw_names(
    context: Mapping[str, object] | None,
    selection_value: object,
    *,
    run_names: Sequence[object] | None = None,
    surface: object = "",
    raw_names: Sequence[object] | None = None,
) -> list[str]:
    selected = str(selection_value or "").strip()
    if not selected:
        return []
    if not td_parameter_selector_is_canonical(selected):
        return [selected]
    ctx = dict(context or {})
    if _td_parameter_runtime_context_enabled(ctx):
        db_path = Path(str(ctx.get("db_path") or "")).expanduser()
        if db_path.exists():
            wanted_id = td_parameter_selector_canonical_id(selected)
            surface_key = str(surface or "").strip().lower()
            run_set = {str(value).strip() for value in (run_names or []) if str(value).strip()}
            raw_norms = {_td_param_norm_name(value) for value in (raw_names or []) if _td_param_norm_name(value)}
            query_parts = [
                f"SELECT DISTINCT raw_name FROM {TD_PARAM_RUNTIME_ENTRIES_TABLE} WHERE canonical_id=?"
            ]
            params: list[object] = [wanted_id]
            if surface_key:
                query_parts.append("AND surface=?")
                params.append(surface_key)
            if run_set:
                placeholders = ",".join("?" for _ in run_set)
                query_parts.append(f"AND run_name IN ({placeholders})")
                params.extend(sorted(run_set))
            if raw_norms:
                placeholders = ",".join("?" for _ in raw_norms)
                query_parts.append(f"AND raw_norm IN ({placeholders})")
                params.extend(sorted(raw_norms))
            query_parts.append("ORDER BY raw_name")
            try:
                with closing(sqlite3.connect(str(db_path))) as conn:
                    _ensure_test_data_impl_tables(conn)
                    rows = conn.execute(" ".join(query_parts), tuple(params)).fetchall()
            except Exception:
                rows = []
            resolved = [str(row[0] or "").strip() for row in rows if str(row[0] or "").strip()]
            if resolved:
                return resolved
    for option in td_build_parameter_selector_options(
        context,
        run_names=run_names,
        surface=surface,
        raw_names=raw_names,
    ):
        if str(option.get("value") or "").strip() == selected:
            return [str(value).strip() for value in (option.get("raw_names") or []) if str(value).strip()]
    canonical_groups = dict(dict(context or {}).get("canonical_groups") or {})
    group = dict(canonical_groups.get(td_parameter_selector_canonical_id(selected)) or {})
    return [str(value).strip() for value in (group.get("raw_names") or []) if str(value).strip()]


def td_parameter_value_display_name(
    context: Mapping[str, object] | None,
    selection_value: object,
    *,
    fallback: object = "",
) -> str:
    selected = str(selection_value or "").strip()
    if not selected:
        return str(fallback or "").strip()
    if not td_parameter_selector_is_canonical(selected):
        return selected
    canonical_id = td_parameter_selector_canonical_id(selected)
    canonical_groups = dict(dict(context or {}).get("canonical_groups") or {})
    group = dict(canonical_groups.get(canonical_id) or {})
    display_name = str(group.get("display_name") or "").strip()
    if display_name:
        return display_name
    raw_names = [str(value).strip() for value in (group.get("raw_names") or []) if str(value).strip()]
    if raw_names:
        return raw_names[0]
    return str(fallback or "").strip()


def resolve_test_data_project_global_repo(project_dir: Path, workbook_path: Path) -> Path:
    project_meta = _read_project_meta(project_dir)
    raw = str(project_meta.get("global_repo") or "").strip()
    if raw:
        return Path(raw).expanduser()
    return _infer_node_root_from_workbook_path(workbook_path)


def _is_td_project_doc_eligible(global_repo: Path, doc: Mapping[str, object]) -> bool:
    if not _is_confirmed_doc_type(doc, "TD"):
        return False
    resolved = _resolve_td_source_sqlite_for_node(
        Path(global_repo).expanduser(),
        excel_sqlite_rel=str(doc.get("excel_sqlite_rel") or "").strip(),
        artifacts_rel=str(doc.get("artifacts_rel") or "").strip(),
    )
    return str(resolved.get("status") or "").strip().lower() == "ok"


def _resolve_excel_sqlite_path_from_workbook(workbook_path: Path, excel_sqlite_rel: str) -> Path:
    """
    Resolve workbook-relative excel_sqlite_rel values into absolute paths.

    Supports:
    - absolute paths
    - paths starting with `EIDAT Support\\...` (legacy; relative to support dir)
    - paths starting with `EIDAT\\...\\EIDAT Support\\...` (current/nested; relative to node root)
    - paths starting with `debug\\...` (relative to the node's support dir)
    - other relative paths (relative to workbook folder)
    """
    raw = str(excel_sqlite_rel or "").strip().strip('"')
    if not raw:
        return Path()
    p = Path(raw).expanduser()
    if p.is_absolute():
        return p

    node_root = _infer_node_root_from_workbook_path(workbook_path)
    support_dir = eidat_support_dir(node_root)
    norm = raw.replace("/", "\\").lstrip("\\")
    low = norm.lower()
    parts = list(Path(norm).parts)
    support_idx = _first_support_segment_index(parts)

    if support_idx == 0:
        rest = Path(*parts[1:]) if len(parts) > 1 else Path()
        return (support_dir / rest).expanduser()
    if support_idx is not None:
        prefix = [str(part or "").strip().casefold() for part in parts[:support_idx]]
        if prefix and all(part in {name.casefold() for name in _EIDAT_CONTAINER_DIR_NAMES} for part in prefix):
            return (node_root / Path(*parts)).expanduser()
    td_root_prefix = TD_SERIAL_SOURCES_DIRNAME.replace("/", "\\").casefold() + "\\"
    if (
        low.startswith("debug\\")
        or low.startswith("projects\\")
        or low.startswith("cache\\")
        or low == TD_SERIAL_SOURCES_DIRNAME.casefold()
        or low.startswith(td_root_prefix)
    ):
        return (support_dir / Path(norm)).expanduser()

    return (Path(workbook_path).expanduser().parent / p).expanduser()


