def _purge_test_data_legacy_impl_raw_tables(conn: sqlite3.Connection) -> None:
    def _q(name: str) -> str:
        return '"' + str(name or "").replace('"', '""') + '"'

    rows = conn.execute(
        """
        SELECT name
        FROM sqlite_master
        WHERE type='table' AND (name IN (
            'td_raw_meta',
            'td_raw_sequences',
            'td_raw_curve_catalog',
            'td_columns',
            'td_columns_raw',
            'td_curves',
            'td_curves_raw',
            'td_metrics'
        ) OR name LIKE 'td_raw__%')
        """
    ).fetchall()
    for (name,) in rows:
        table_name = str(name or "").strip()
        if not table_name:
            continue
        conn.execute(f"DROP TABLE IF EXISTS {_q(table_name)}")


def _write_td_cache_debug_json(project_dir: Path, payload: dict) -> Path | None:
    path = Path(project_dir).expanduser() / TD_CACHE_DEBUG_JSON
    try:
        path.write_text(json.dumps(payload, indent=2, ensure_ascii=False, default=str), encoding="utf-8")
    except Exception:
        return None
    return path


def _read_td_cache_debug_json(project_dir: Path) -> dict[str, object]:
    path = Path(project_dir).expanduser() / TD_CACHE_DEBUG_JSON
    try:
        if not path.exists() or not path.is_file():
            return {}
        payload = json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return {}
    return dict(payload) if isinstance(payload, dict) else {}


def _read_test_data_config_columns(workbook_path: Path) -> list[dict]:
    try:
        from openpyxl import load_workbook  # type: ignore
    except Exception as exc:
        raise RuntimeError(
            "openpyxl is required to read Test Data Trending workbooks. "
            "Install it with `py -m pip install openpyxl` within the project environment."
        ) from exc

    wb = load_workbook(str(Path(workbook_path).expanduser()), read_only=True, data_only=True)
    try:
        if "Config" not in wb.sheetnames:
            return []
        ws = wb["Config"]
        header_row_idx: int | None = None
        headers: dict[str, int] = {}
        for r in range(1, (ws.max_row or 0) + 1):
            row_headers: dict[str, int] = {}
            for c in range(1, (ws.max_column or 0) + 1):
                key = str(ws.cell(r, c).value or "").strip().lower()
                if key:
                    row_headers[key] = c
            if row_headers.get("name") and row_headers.get("units"):
                header_row_idx = r
                headers = row_headers
                break
        if header_row_idx is None:
            return []

        cols: list[dict] = []
        for r in range(header_row_idx + 1, (ws.max_row or 0) + 1):
            name = str(ws.cell(r, headers.get("name", 1)).value or "").strip()
            if not name:
                break
            units = str(ws.cell(r, headers.get("units", 2)).value or "").strip()
            aliases: list[str] = []
            if headers.get("aliases"):
                raw_aliases = ws.cell(r, headers["aliases"]).value
                if raw_aliases is not None and str(raw_aliases).strip():
                    try:
                        parsed = json.loads(str(raw_aliases))
                    except Exception:
                        parsed = [part.strip() for part in str(raw_aliases).split(",")]
                    if isinstance(parsed, (list, tuple)):
                        aliases = [str(v).strip() for v in parsed if str(v).strip()]
            cols.append({"name": name, "units": units, "aliases": aliases})
        return cols
    finally:
        try:
            wb.close()
        except Exception:
            pass


def _read_test_data_config_statistics(workbook_path: Path) -> list[str]:
    try:
        from openpyxl import load_workbook  # type: ignore
    except Exception as exc:
        raise RuntimeError(
            "openpyxl is required to read Test Data Trending workbooks. "
            "Install it with `py -m pip install openpyxl` within the project environment."
        ) from exc

    wb = load_workbook(str(Path(workbook_path).expanduser()), read_only=True, data_only=True)
    try:
        if "Config" not in wb.sheetnames:
            return []
        ws = wb["Config"]
        for r in range(2, (ws.max_row or 0) + 1):
            key = str(ws.cell(r, 1).value or "").strip().lower()
            if key != "statistics":
                continue
            raw = str(ws.cell(r, 2).value or "").strip()
            vals = [part.strip().lower() for part in raw.split(",") if part.strip()]
            vals = [v for v in vals if v in TD_ALLOWED_STATS]
            return vals
        return []
    finally:
        try:
            wb.close()
        except Exception:
            pass


def _load_project_td_trend_config(workbook_path: Path) -> dict:
    runtime_cfg = _load_runtime_td_trend_config()
    runtime_cols = [dict(c) for c in (runtime_cfg.get("columns") or []) if isinstance(c, dict)]
    runtime_stats = [str(s).strip().lower() for s in (runtime_cfg.get("statistics") or []) if str(s).strip()]
    runtime_stats = [s for s in runtime_stats if s in TD_ALLOWED_STATS]

    workbook_cols = _read_test_data_config_columns(workbook_path)
    workbook_stats = _read_test_data_config_statistics(workbook_path)

    def _norm_name_local(value: object) -> str:
        return "".join(ch.lower() for ch in str(value or "").strip() if ch.isalnum())

    runtime_by_name = {
        _norm_name_local(col.get("name")): dict(col)
        for col in runtime_cols
        if str(col.get("name") or "").strip()
    }

    columns: list[dict] = []
    if workbook_cols:
        for wb_col in workbook_cols:
            name = str(wb_col.get("name") or "").strip()
            if not name:
                continue
            merged = dict(runtime_by_name.get(_norm_name_local(name)) or {})
            merged.update(dict(wb_col))
            if not merged.get("aliases") and runtime_by_name.get(_norm_name_local(name), {}).get("aliases"):
                merged["aliases"] = list(runtime_by_name[_norm_name_local(name)].get("aliases") or [])
            columns.append(merged)
        columns_source = "workbook_config"
    else:
        columns = runtime_cols
        columns_source = "runtime_config"

    statistics = workbook_stats or runtime_stats or list(TD_DEFAULT_STATS_ORDER)
    statistics_source = "workbook_config" if workbook_stats else "runtime_config"

    return {
        "columns": columns,
        "statistics": statistics,
        "columns_source": columns_source,
        "statistics_source": statistics_source,
        "runtime_config": runtime_cfg,
    }


def _read_test_data_sources(workbook_path: Path) -> list[dict]:
    try:
        from openpyxl import load_workbook  # type: ignore
    except Exception as exc:
        raise RuntimeError(
            "openpyxl is required to read Test Data Trending workbooks. "
            "Install it with `py -m pip install openpyxl` within the project environment."
        ) from exc

    wb = load_workbook(str(Path(workbook_path).expanduser()), read_only=True, data_only=True)
    try:
        if "Sources" not in wb.sheetnames:
            return []
        ws = wb["Sources"]
        headers: dict[str, int] = {}
        for col in range(1, (ws.max_column or 0) + 1):
            key = str(ws.cell(1, col).value or "").strip().lower()
            if key:
                headers[key] = col
        if "serial_number" not in headers or "excel_sqlite_rel" not in headers:
            return []

        out: list[dict] = []
        for row in range(2, (ws.max_row or 0) + 1):
            item: dict[str, str] = {}
            for key, col in headers.items():
                item[key] = str(ws.cell(row, col).value or "").strip()
            sn = str(item.get("serial_number") or item.get("serial") or "").strip()
            if not sn:
                continue
            item["serial"] = sn
            item["excel_sqlite_rel"] = str(item.get("excel_sqlite_rel") or "").strip()
            item["_sheet_row"] = str(row)
            out.append(item)
        return out
    finally:
        try:
            wb.close()
        except Exception:
            pass


TD_SOURCE_METADATA_FIELDS = (
    "program_title",
    "asset_type",
    "asset_specific_type",
    "vendor",
    "acceptance_test_plan_number",
    "part_number",
    "revision",
    "test_date",
    "report_date",
    "document_type",
    "document_type_acronym",
    "similarity_group",
    "metadata_source",
    "manual_override_updated_at",
    "applied_asset_specific_type_rule",
)


def _td_source_unknownish(value: object) -> bool:
    txt = str(value or "").strip()
    return not txt or txt.casefold() in {"unknown", "none", "null", "n/a", "na", "-"}


def _td_source_identity_part(value: object, *, fallback: str) -> str:
    txt = str(value or "").strip()
    if _td_source_unknownish(txt):
        return fallback
    return re.sub(r"\s+", " ", txt)


def _td_source_serial_number(source_row: Mapping[str, object], source_meta: Mapping[str, object] | None = None) -> str:
    meta = dict(source_meta or {})
    for key in ("serial_number", "source_serial_number"):
        txt = str(source_row.get(key) or meta.get(key) or "").strip()
        if txt:
            return txt
    return str(source_row.get("serial") or meta.get("serial") or "").strip()


def _td_build_source_composite_key(
    source_row: Mapping[str, object],
    source_meta: Mapping[str, object] | None = None,
) -> str:
    meta = dict(source_meta or {})
    serial_number = _td_source_serial_number(source_row, meta)
    if not serial_number:
        return ""

    program_title = source_row.get("program_title") or meta.get("program_title")
    asset_type = source_row.get("asset_type") or meta.get("asset_type")
    asset_specific_type = source_row.get("asset_specific_type") or meta.get("asset_specific_type")

    # Existing ad-hoc test workbooks often have no metadata context at all. In
    # that case, preserve the historical serial-only identity because there is
    # no program/asset namespace available to protect it.
    if all(_td_source_unknownish(value) for value in (program_title, asset_type, asset_specific_type)):
        return serial_number

    return " / ".join(
        [
            _td_source_identity_part(program_title, fallback="Unknown Program"),
            _td_source_identity_part(asset_type, fallback="Unknown Asset"),
            _td_source_identity_part(asset_specific_type, fallback="Unknown Type"),
            _td_source_identity_part(serial_number, fallback="Unknown Serial"),
        ]
    )


def _td_source_composite_key(
    source_row: Mapping[str, object],
    source_meta: Mapping[str, object] | None = None,
) -> str:
    existing_key = str(source_row.get("source_key") or "").strip()
    if existing_key:
        return existing_key
    if "source_key" in source_row:
        return _td_build_source_composite_key(source_row, source_meta)
    return _td_source_serial_number(source_row, source_meta)


def _td_rel_parts(value: object) -> list[str]:
    raw = str(value or "").strip().strip('"').strip("'")
    if not raw:
        return []
    return [part for part in re.split(r"[\\/]+", raw) if part and part != "."]


def _td_safe_path_name(value: object, *, fallback: str = "unknown") -> str:
    raw = str(value or "").strip() or str(fallback or "unknown")
    cleaned = re.sub(r"[^A-Za-z0-9._ -]+", "_", raw).strip(" .")
    cleaned = re.sub(r"\s+", "_", cleaned)
    return cleaned[:80] or str(fallback or "unknown")


def _td_official_artifacts_dir_for_source_like(node_root: Path, source_like: Mapping[str, object]) -> Path | None:
    serial = str(
        source_like.get("serial_number") or source_like.get("source_serial_number") or source_like.get("serial") or ""
    ).strip()
    if not serial:
        return None
    support_dir = eidat_support_dir(Path(node_root).expanduser())
    return (
        support_dir
        / TD_SERIAL_SOURCES_DIRNAME
        / _td_safe_path_name(source_like.get("program_title"), fallback="Unknown_Program")
        / _td_safe_path_name(source_like.get("asset_type"), fallback="Unknown_Asset")
        / _td_safe_path_name(source_like.get("asset_specific_type"), fallback="Unknown_Type")
        / _td_safe_path_name(serial, fallback="Unknown_Serial")
    )


def _td_official_sqlite_path_for_source_like(node_root: Path, source_like: Mapping[str, object]) -> Path | None:
    art_dir = _td_official_artifacts_dir_for_source_like(node_root, source_like)
    serial = str(
        source_like.get("serial_number") or source_like.get("source_serial_number") or source_like.get("serial") or ""
    ).strip()
    if art_dir is None or not serial:
        return None
    return art_dir / f"{_td_safe_path_name(serial, fallback='Unknown_Serial')}.sqlite3"


def _td_support_rel_path(support_dir: Path, path: Path | None) -> str:
    if path is None:
        return ""
    p = Path(path).expanduser()
    try:
        return str(p.resolve().relative_to(Path(support_dir).resolve())).replace("\\", "/")
    except Exception:
        try:
            return str(p.relative_to(Path(support_dir).expanduser())).replace("\\", "/")
        except Exception:
            return str(p).replace("\\", "/")


def _td_resolve_existing_official_materialization(
    node_root: Path,
    source_like: Mapping[str, object],
) -> dict[str, object]:
    node_root = Path(node_root).expanduser()
    support_dir = eidat_support_dir(node_root)
    sqlite_path = _td_official_sqlite_path_for_source_like(node_root, source_like)
    if sqlite_path is None or not sqlite_path.exists() or not sqlite_path.is_file():
        return {}
    art_dir = sqlite_path.parent
    metadata_path = art_dir / f"{sqlite_path.stem}_metadata.json"
    return {
        "path": sqlite_path,
        "artifacts_path": art_dir,
        "artifacts_rel": _td_support_rel_path(support_dir, art_dir),
        "metadata_path": metadata_path if metadata_path.exists() and metadata_path.is_file() else None,
        "metadata_rel": _td_support_rel_path(support_dir, metadata_path) if metadata_path.exists() and metadata_path.is_file() else "",
        "excel_sqlite_rel": _td_canonical_source_link_for_node(node_root, sqlite_path),
    }


def _td_rel_uses_official_source_location(value: object) -> bool:
    parts = [part.casefold() for part in _td_rel_parts(value)]
    try:
        root_idx = parts.index(TD_SERIAL_SOURCES_DIRNAME.casefold())
    except ValueError:
        return False
    return TD_SERIAL_SOURCE_ARTIFACTS_DIRNAME.casefold() in parts[root_idx + 1 :]


def _td_rel_uses_official_td_location(value: object) -> bool:
    parts = [part.casefold() for part in _td_rel_parts(value)]
    return TD_SERIAL_SOURCES_DIRNAME.casefold() in parts


def _td_doc_uses_official_source_location(doc: Mapping[str, object]) -> bool:
    return any(
        _td_rel_uses_official_source_location(doc.get(key))
        for key in ("metadata_rel", "artifacts_rel", "excel_sqlite_rel")
    )


def _td_doc_uses_official_td_location(doc: Mapping[str, object]) -> bool:
    return any(
        _td_rel_uses_official_td_location(doc.get(key))
        for key in ("metadata_rel", "artifacts_rel", "excel_sqlite_rel")
    )


def _td_is_serial_aggregate_doc(doc: Mapping[str, object]) -> bool:
    meta_source = str(doc.get("metadata_source") or "").strip().casefold()
    if meta_source in TD_OFFICIAL_METADATA_SOURCES:
        return True
    if not _td_doc_uses_official_td_location(doc):
        return False
    if _td_doc_uses_official_source_location(doc):
        return False
    excel_sqlite_rel = str(doc.get("excel_sqlite_rel") or "").strip().casefold()
    return excel_sqlite_rel.endswith(".sqlite3")


def _td_project_source_identity_key(source_row: Mapping[str, object]) -> str:
    return _td_build_source_composite_key(source_row, source_row).casefold()


def _td_project_doc_rank(global_repo: Path, support_dir: Path, doc: Mapping[str, object]) -> tuple[int, int, int, int, str]:
    aggregate_score = 1 if _td_is_serial_aggregate_doc(doc) else 0
    official_score = sum(
        1
        for key in ("metadata_rel", "artifacts_rel", "excel_sqlite_rel")
        if _td_rel_uses_official_td_location(doc.get(key))
    )
    sqlite_ok = 0
    try:
        resolved = _resolve_td_source_sqlite_for_node(
            Path(global_repo).expanduser(),
            excel_sqlite_rel=str(doc.get("excel_sqlite_rel") or "").strip(),
            artifacts_rel=str(doc.get("artifacts_rel") or "").strip(),
        )
        sqlite_ok = 1 if str(resolved.get("status") or "").strip().lower() == "ok" else 0
    except Exception:
        sqlite_ok = 0
    mtime_ns = 0
    try:
        meta_path = _resolve_support_path(support_dir, str(doc.get("metadata_rel") or "").strip())
        if meta_path and meta_path.exists():
            mtime_ns = int(getattr(meta_path.stat(), "st_mtime_ns", int(meta_path.stat().st_mtime * 1e9)))
    except Exception:
        mtime_ns = 0
    return (
        int(aggregate_score),
        int(official_score),
        int(sqlite_ok),
        int(mtime_ns),
        str(doc.get("metadata_rel") or "").casefold(),
    )


def _td_canonical_project_doc(
    global_repo: Path,
    doc: Mapping[str, object],
    *,
    docs_pool: Sequence[Mapping[str, object]] | None = None,
) -> dict[str, object]:
    row = dict(doc or {})
    row_key = _td_project_source_identity_key(row)
    if not row_key and not _td_doc_uses_official_td_location(row):
        return row

    repo = Path(global_repo).expanduser()
    support_dir = eidat_support_dir(repo)
    candidates: list[dict[str, object]] = []
    if _td_doc_uses_official_td_location(row):
        candidates.append(dict(row))

    pool = [dict(item) for item in (docs_pool or []) if isinstance(item, Mapping)]
    for candidate in pool:
        try:
            if not is_test_data_doc(candidate):
                continue
        except Exception:
            continue
        if not _td_doc_uses_official_td_location(candidate):
            continue
        cand_key = _td_project_source_identity_key(candidate)
        if row_key and cand_key == row_key:
            candidates.append(dict(candidate))

    if not candidates:
        serial = _td_source_serial_number(row, row).casefold()
        if serial:
            serial_matches: list[dict[str, object]] = []
            serial_identity_keys: set[str] = set()
            for candidate in pool:
                try:
                    if not is_test_data_doc(candidate):
                        continue
                except Exception:
                    continue
                if not _td_doc_uses_official_td_location(candidate):
                    continue
                cand_serial = _td_source_serial_number(candidate, candidate).casefold()
                if cand_serial != serial:
                    continue
                serial_matches.append(dict(candidate))
                cand_key = _td_project_source_identity_key(candidate)
                if cand_key:
                    serial_identity_keys.add(cand_key)
            if len(serial_identity_keys) == 1 and serial_matches:
                candidates = serial_matches

    if not candidates:
        return row
    aggregate_candidates = [dict(candidate) for candidate in candidates if _td_is_serial_aggregate_doc(candidate)]
    if aggregate_candidates:
        return max(aggregate_candidates, key=lambda item: _td_project_doc_rank(repo, support_dir, item))
    if _td_doc_uses_official_td_location(row):
        return row
    return max(candidates, key=lambda item: _td_project_doc_rank(repo, support_dir, item))


def _td_canonicalize_project_docs(
    global_repo: Path,
    docs: Sequence[Mapping[str, object]] | None,
    *,
    docs_pool: Sequence[Mapping[str, object]] | None = None,
) -> list[dict[str, object]]:
    pool = list(docs_pool or docs or [])
    out: list[dict[str, object]] = []
    seen: set[str] = set()
    for doc in docs or []:
        if not isinstance(doc, Mapping):
            continue
        canonical = _td_canonical_project_doc(global_repo, doc, docs_pool=pool)
        key = (
            str(canonical.get("metadata_rel") or "").strip().casefold()
            or _td_project_source_identity_key(canonical)
            or str(canonical.get("excel_sqlite_rel") or "").strip().casefold()
        )
        if key and key in seen:
            continue
        if key:
            seen.add(key)
        out.append(canonical)
    return out


def _td_source_row_payload(doc: Mapping[str, object]) -> dict[str, str]:
    return {
        "serial_number": str(doc.get("serial_number") or doc.get("source_serial_number") or doc.get("serial") or "").strip(),
        "program_title": str(doc.get("program_title") or "").strip(),
        "document_type": str(doc.get("document_type") or "").strip(),
        "metadata_rel": str(doc.get("metadata_rel") or "").strip(),
        "artifacts_rel": str(doc.get("artifacts_rel") or "").strip(),
        "excel_sqlite_rel": str(doc.get("excel_sqlite_rel") or "").strip(),
        "asset_type": str(doc.get("asset_type") or "").strip(),
        "asset_specific_type": str(doc.get("asset_specific_type") or "").strip(),
        "metadata_source": str(doc.get("metadata_source") or "").strip(),
    }


def _td_source_materialization_label(doc: Mapping[str, object]) -> str:
    candidate_values = [
        str(doc.get("artifacts_rel") or "").strip(),
        str(doc.get("metadata_rel") or "").strip(),
        str(doc.get("excel_sqlite_rel") or "").strip(),
    ]
    for raw in candidate_values:
        parts = _td_rel_parts(raw)
        if not parts:
            continue
        leaf = ""
        if raw == str(doc.get("metadata_rel") or "").strip():
            if len(parts) >= 2 and str(parts[-1]).lower().endswith(".json"):
                leaf = str(parts[-2]).strip()
            else:
                leaf = str(parts[-1]).strip()
        elif raw == str(doc.get("excel_sqlite_rel") or "").strip():
            leaf = Path(parts[-1]).stem
        else:
            leaf = str(parts[-1]).strip()
        if not leaf:
            continue
        m = re.match(r"(.+?)__[0-9a-f]{10}__excel$", leaf, flags=re.IGNORECASE)
        if m:
            leaf = str(m.group(1) or "").strip()
        elif leaf.lower().endswith("__excel"):
            leaf = leaf[: -len("__excel")].strip()
        if leaf.lower().endswith("_metadata"):
            leaf = leaf[: -len("_metadata")].strip()
        if leaf:
            return leaf
    return "source"


def _td_materialize_source_rows(
    global_repo: Path | None,
    docs: Sequence[Mapping[str, object]] | None,
    *,
    docs_pool: Sequence[Mapping[str, object]] | None = None,
) -> list[dict[str, str]]:
    rows = [dict(doc) for doc in (docs or []) if isinstance(doc, Mapping)]
    repo = Path(global_repo).expanduser() if global_repo is not None else None
    pool = [dict(item) for item in (docs_pool or []) if isinstance(item, Mapping)]
    pool.extend([dict(item) for item in rows])

    materialized: list[dict[str, str]] = []
    seen_rows: set[str] = set()
    for raw in rows:
        serial_number = _td_source_serial_number(raw, raw)
        if not serial_number:
            continue
        current = dict(raw)
        if repo is not None:
            try:
                current = _td_canonical_project_doc(repo, raw, docs_pool=pool)
            except Exception:
                current = dict(raw)
        row = _td_source_row_payload(current)
        exact_key = (
            str(row.get("metadata_rel") or "").strip().casefold()
            or str(row.get("excel_sqlite_rel") or "").strip().casefold()
            or str(row.get("artifacts_rel") or "").strip().casefold()
            or (
                _td_project_source_identity_key(row)
                + "|"
                + _td_source_materialization_label(row).casefold()
            )
        )
        if exact_key and exact_key in seen_rows:
            continue
        if exact_key:
            seen_rows.add(exact_key)
        materialized.append(row)

    grouped_counts: dict[str, int] = {}
    for row in materialized:
        base = _td_build_source_composite_key(row, row) or _td_source_serial_number(row, row)
        grouped_counts[base.casefold()] = int(grouped_counts.get(base.casefold(), 0)) + 1

    label_counts: dict[tuple[str, str], int] = {}
    for row in materialized:
        base = _td_build_source_composite_key(row, row) or _td_source_serial_number(row, row)
        base_key = base.casefold()
        if int(grouped_counts.get(base_key, 0)) <= 1 or _td_is_serial_aggregate_doc(row):
            row["source_key"] = base
            continue
        label = _td_source_materialization_label(row)
        source_key = f"{base} / {label}" if label else base
        pair_key = (base_key, source_key.casefold())
        count = int(label_counts.get(pair_key, 0)) + 1
        label_counts[pair_key] = count
        if count > 1:
            source_key = f"{source_key} ({count})"
        row["source_key"] = source_key
    return materialized


def _td_canonical_selected_metadata_rels(
    global_repo: Path,
    selected_rels: Sequence[object],
    docs_pool: Sequence[Mapping[str, object]] | None,
) -> list[str]:
    docs_by_rel: dict[str, Mapping[str, object]] = {}
    for doc in docs_pool or []:
        if not isinstance(doc, Mapping):
            continue
        rel = str(doc.get("metadata_rel") or "").strip()
        if rel:
            docs_by_rel.setdefault(rel, doc)
    out: list[str] = []
    seen: set[str] = set()
    for raw_rel in selected_rels or []:
        rel = str(raw_rel or "").strip()
        if not rel:
            continue
        doc = docs_by_rel.get(rel)
        if doc is not None:
            canonical = _td_canonical_project_doc(global_repo, doc, docs_pool=docs_pool)
            rel = str(canonical.get("metadata_rel") or rel).strip()
        key = rel.casefold()
        if key and key not in seen:
            seen.add(key)
            out.append(rel)
    return out


def _td_canonical_source_link_for_node(node_root: Path, path: Path) -> str:
    p = Path(path).expanduser()
    support_dir = eidat_support_dir(node_root)
    try:
        if _path_is_within_root(p, support_dir):
            try:
                rel = p.resolve().relative_to(support_dir.resolve())
            except Exception:
                rel = p.relative_to(support_dir)
            if support_dir.parent.name.strip().lower() == "eidat":
                out = Path("EIDAT") / "EIDAT Support" / rel
            else:
                out = Path("EIDAT Support") / rel
            return str(out).replace("/", "\\")
    except Exception:
        pass

    try:
        if _path_is_within_root(p, node_root):
            try:
                rel = p.resolve().relative_to(Path(node_root).expanduser().resolve())
            except Exception:
                rel = p.relative_to(Path(node_root).expanduser())
            return str(rel).replace("/", "\\")
    except Exception:
        pass

    return str(p)


def _write_test_data_source_link_updates(
    workbook_path: Path,
    updates_by_serial: Mapping[str, object],
) -> dict[str, dict[str, str]]:
    updates: dict[str, dict[str, str]] = {}
    for raw_key, raw_value in (updates_by_serial or {}).items():
        key = str(raw_key).strip()
        if not key:
            continue
        normalized: dict[str, str] = {}
        if isinstance(raw_value, Mapping):
            for field in ("metadata_rel", "artifacts_rel", "excel_sqlite_rel"):
                value = str(raw_value.get(field) or "").strip()
                if value:
                    normalized[field] = value
        else:
            value = str(raw_value or "").strip()
            if value:
                normalized["excel_sqlite_rel"] = value
        if normalized:
            updates[key] = normalized
    if not updates:
        return {}
    try:
        from openpyxl import load_workbook  # type: ignore
    except Exception as exc:
        raise RuntimeError(
            "openpyxl is required to heal Test Data source links in project workbooks. "
            "Install it with `py -m pip install openpyxl` within the project environment."
        ) from exc

    wb_path = Path(workbook_path).expanduser()
    wb = load_workbook(str(wb_path))
    changed: dict[str, dict[str, str]] = {}
    try:
        if "Sources" not in wb.sheetnames:
            return {}
        ws = wb["Sources"]
        headers: dict[str, int] = {}
        for col in range(1, (ws.max_column or 0) + 1):
            key = str(ws.cell(1, col).value or "").strip().lower()
            if key:
                headers[key] = col
        serial_col = headers.get("serial_number") or headers.get("serial")
        source_key_col = headers.get("source_key")
        target_cols = {
            field: headers.get(field)
            for field in ("metadata_rel", "artifacts_rel", "excel_sqlite_rel")
            if headers.get(field)
        }
        if not serial_col or not target_cols:
            return {}

        dirty = False
        for row in range(2, (ws.max_row or 0) + 1):
            serial = str(ws.cell(row, serial_col).value or "").strip()
            source_key = str(ws.cell(row, source_key_col).value or "").strip() if source_key_col else ""
            update_key = source_key if source_key in updates else serial
            if not update_key or update_key not in updates:
                continue
            requested = updates[update_key]
            row_changed = False
            applied = dict(requested)
            for field, col in target_cols.items():
                if field not in requested or not col:
                    continue
                new_value = str(requested.get(field) or "").strip()
                cur_value = str(ws.cell(row, col).value or "").strip()
                if cur_value == new_value:
                    continue
                ws.cell(row, col).value = new_value
                applied[field] = new_value
                row_changed = True
                dirty = True
            if row_changed:
                changed[update_key] = applied

        if dirty:
            wb.save(str(wb_path))
        return changed
    finally:
        try:
            wb.close()
        except Exception:
            pass


def _resolve_td_source_metadata_path(workbook_path: Path, source_row: Mapping[str, object]) -> Path | None:
    metadata_rel = str(source_row.get("metadata_rel") or "").strip()
    artifacts_rel = str(source_row.get("artifacts_rel") or "").strip()
    try:
        support_dir = eidat_support_dir(_infer_node_root_from_workbook_path(workbook_path))
        meta_path = _resolve_support_path(support_dir, metadata_rel) if metadata_rel else None
        if meta_path and meta_path.exists() and meta_path.is_file():
            return meta_path
        art_dir = _resolve_support_path(support_dir, artifacts_rel) if artifacts_rel else None
        if art_dir is not None:
            for p in sorted(art_dir.glob("*_metadata.json")):
                if p.exists() and p.is_file():
                    return p
    except Exception:
        return None
    return None


def _load_td_source_metadata(workbook_path: Path, source_row: Mapping[str, object]) -> dict[str, object]:
    serial_number = str(source_row.get("serial_number") or source_row.get("source_serial_number") or source_row.get("serial") or "").strip()
    excel_sqlite_rel = str(source_row.get("excel_sqlite_rel") or "").strip()
    metadata_rel = str(source_row.get("metadata_rel") or "").strip()
    artifacts_rel = str(source_row.get("artifacts_rel") or "").strip()

    fallback = {
        "serial_number": serial_number,
        "source_serial_number": serial_number,
        "program_title": str(source_row.get("program_title") or "").strip(),
        "asset_type": str(source_row.get("asset_type") or "").strip(),
        "asset_specific_type": str(source_row.get("asset_specific_type") or "").strip(),
        "document_type": str(source_row.get("document_type") or "").strip(),
        "metadata_rel": metadata_rel,
        "artifacts_rel": artifacts_rel,
        "excel_sqlite_rel": excel_sqlite_rel,
    }

    meta_from_file: dict[str, object] = {}
    metadata_mtime_ns = 0
    try:
        meta_path = _resolve_td_source_metadata_path(workbook_path, source_row)
        if meta_path and meta_path.exists() and meta_path.is_file():
            metadata_mtime_ns = int(getattr(meta_path.stat(), "st_mtime_ns", int(meta_path.stat().st_mtime * 1e9)))
            raw = json.loads(meta_path.read_text(encoding="utf-8"))
            if isinstance(raw, Mapping):
                meta_from_file = dict(raw)
    except Exception:
        meta_from_file = {}
        metadata_mtime_ns = 0

    merged = _merge_metadata(meta_from_file, fallback)
    merged_serial_number = str(merged.get("serial_number") or serial_number).strip()
    out: dict[str, object] = {
        "serial_number": merged_serial_number,
        "source_serial_number": merged_serial_number,
        "metadata_rel": metadata_rel,
        "artifacts_rel": artifacts_rel,
        "excel_sqlite_rel": excel_sqlite_rel,
        "metadata_mtime_ns": int(metadata_mtime_ns),
        "manual_override_fields_json": json.dumps(
            [str(v).strip() for v in (meta_from_file.get("manual_override_fields") or []) if str(v).strip()],
            ensure_ascii=True,
        ),
    }
    for key in TD_SOURCE_METADATA_FIELDS:
        out[key] = str(merged.get(key) or "").strip()
    if not out["metadata_rel"]:
        out["metadata_rel"] = str(merged.get("metadata_rel") or "").strip()
    if not out["artifacts_rel"]:
        out["artifacts_rel"] = str(merged.get("artifacts_rel") or "").strip()
    if not out["excel_sqlite_rel"]:
        out["excel_sqlite_rel"] = str(merged.get("excel_sqlite_rel") or "").strip()
    return out


def _td_source_runtime_state(
    workbook_path: Path,
    source_row: Mapping[str, object],
    *,
    project_raw_signature: str,
) -> dict[str, object]:
    source_resolution = _resolve_td_source_sqlite_for_workbook(workbook_path, source_row)
    sqlite_path_raw = source_resolution.get("path")
    sqlite_path = Path(sqlite_path_raw).expanduser() if sqlite_path_raw else Path()
    status = str(source_resolution.get("status") or "missing").strip().lower() or "missing"
    source_meta = _load_td_source_metadata(workbook_path, source_row)
    source_key = _td_source_composite_key(source_row, source_meta)
    serial_number = _td_source_serial_number(source_row, source_meta)
    mtime_ns = 0
    size_bytes = 0
    if status == "ok":
        try:
            st = sqlite_path.stat()
            mtime_ns = int(getattr(st, "st_mtime_ns", int(st.st_mtime * 1e9)))
            size_bytes = int(st.st_size)
        except Exception:
            status = "missing"
            mtime_ns = 0
            size_bytes = 0
    healed_excel_sqlite_rel = str(source_resolution.get("healed_excel_sqlite_rel") or "").strip()
    workbook_excel_sqlite_rel = str(
        source_resolution.get("workbook_excel_sqlite_rel")
        or source_row.get("excel_sqlite_rel")
        or ""
    ).strip()
    effective_links = _td_effective_source_link_fields(source_row, source_meta, source_resolution)
    effective_excel_sqlite_rel = str(effective_links.get("excel_sqlite_rel") or "").strip()
    effective_metadata_rel = str(effective_links.get("metadata_rel") or "").strip()
    effective_artifacts_rel = str(effective_links.get("artifacts_rel") or "").strip()
    return {
        "serial": source_key,
        "source_key": source_key,
        "serial_number": serial_number,
        "source_row": dict(source_row),
        "source_resolution": dict(source_resolution),
        "source_meta": dict(source_meta),
        "status": status,
        "sqlite_path": str(sqlite_path) if sqlite_path else "",
        "mtime_ns": int(mtime_ns),
        "size_bytes": int(size_bytes),
        "metadata_rel": effective_metadata_rel,
        "artifacts_rel": effective_artifacts_rel,
        "excel_sqlite_rel": effective_excel_sqlite_rel,
        "fingerprint": _td_source_raw_fingerprint(
            source_key=source_key,
            serial_number=serial_number,
            status=status,
            sqlite_path=sqlite_path,
            mtime_ns=mtime_ns,
            size_bytes=size_bytes,
            metadata_rel=effective_metadata_rel,
            artifacts_rel=effective_artifacts_rel,
            excel_sqlite_rel=effective_excel_sqlite_rel,
            metadata_mtime_ns=int(source_meta.get("metadata_mtime_ns") or 0),
            project_raw_signature=project_raw_signature,
        ),
    }


def _td_build_project_raw_signature(
    workbook_path: Path,
    *,
    raw_columns_csv: str,
) -> str:
    x_axis_cfg: dict = {}
    try:
        x_axis_cfg = dict((_load_excel_trend_config(DEFAULT_EXCEL_TREND_CONFIG) or {}).get("x_axis") or {})
    except Exception:
        x_axis_cfg = {}
    payload = {
        "schema_version": TD_PROJECT_CACHE_SCHEMA_VERSION,
        "node_root": str(_infer_node_root_from_workbook_path(workbook_path)),
        "workbook_path": str(Path(workbook_path).expanduser()),
        "x_axis": x_axis_cfg,
    }
    return _td_hash_payload(payload)


def _td_effective_source_link_fields(
    source_row: Mapping[str, object],
    source_meta: Mapping[str, object] | None,
    source_resolution: Mapping[str, object] | None,
) -> dict[str, str]:
    row = dict(source_row or {})
    meta = dict(source_meta or {})
    resolution = dict(source_resolution or {})
    metadata_rel = str(
        resolution.get("healed_metadata_rel")
        or resolution.get("metadata_rel")
        or row.get("metadata_rel")
        or meta.get("metadata_rel")
        or ""
    ).strip()
    artifacts_rel = str(
        resolution.get("healed_artifacts_rel")
        or resolution.get("artifacts_rel")
        or row.get("artifacts_rel")
        or meta.get("artifacts_rel")
        or ""
    ).strip()
    workbook_excel_sqlite_rel = str(
        resolution.get("workbook_excel_sqlite_rel")
        or resolution.get("excel_sqlite_rel")
        or row.get("excel_sqlite_rel")
        or meta.get("excel_sqlite_rel")
        or ""
    ).strip()
    excel_sqlite_rel = str(
        resolution.get("healed_excel_sqlite_rel")
        or workbook_excel_sqlite_rel
    ).strip()
    return {
        "metadata_rel": metadata_rel,
        "artifacts_rel": artifacts_rel,
        "excel_sqlite_rel": excel_sqlite_rel,
    }


def _td_source_raw_fingerprint(
    *,
    source_key: str,
    serial_number: str,
    status: str,
    sqlite_path: Path | str | None,
    mtime_ns: int | None,
    size_bytes: int | None,
    metadata_rel: str,
    artifacts_rel: str,
    excel_sqlite_rel: str,
    metadata_mtime_ns: int | None,
    project_raw_signature: str,
) -> str:
    return _td_hash_payload(
        {
            "serial": str(source_key or "").strip(),
            "serial_number": str(serial_number or "").strip(),
            "status": str(status or "").strip().lower(),
            "sqlite_path": str(Path(sqlite_path).expanduser()) if sqlite_path else "",
            "mtime_ns": int(mtime_ns or 0),
            "size_bytes": int(size_bytes or 0),
            "metadata_rel": str(metadata_rel or "").strip(),
            "artifacts_rel": str(artifacts_rel or "").strip(),
            "excel_sqlite_rel": str(excel_sqlite_rel or "").strip(),
            "metadata_mtime_ns": int(metadata_mtime_ns or 0),
            "project_raw_signature": str(project_raw_signature or "").strip(),
        }
    )


def _td_source_sqlite_artifact_candidates(
    *,
    node_root: Path,
    artifacts_rel: str,
) -> list[Path]:
    art_rel = str(artifacts_rel or "").strip()
    if not art_rel:
        return []
    support_dir = eidat_support_dir(node_root)
    art_dir = _resolve_support_path(support_dir, art_rel)
    if art_dir is None or not art_dir.exists() or not art_dir.is_dir():
        return []
    out: list[Path] = []
    for path in sorted(art_dir.glob("*.sqlite3")):
        if not path.exists() or not path.is_file():
            continue
        low = path.name.lower()
        if low in {
            EIDAT_PROJECT_IMPLEMENTATION_DB.lower(),
            EIDAT_PROJECT_TD_RAW_CACHE_DB.lower(),
        }:
            continue
        out.append(path)
    return out


def _resolve_td_source_sqlite_for_node(
    node_root: Path,
    *,
    excel_sqlite_rel: str,
    artifacts_rel: str,
) -> dict[str, object]:
    node_root = Path(node_root).expanduser()
    raw = str(excel_sqlite_rel or "").strip()
    candidate = _resolve_excel_sqlite_path_from_workbook(node_root / "dummy.xlsx", raw) if raw else Path()
    candidate_exists = bool(candidate) and candidate.exists()
    candidate_is_file = bool(candidate_exists and candidate.is_file())
    candidate_in_node = bool(candidate and candidate_is_file and _path_is_within_root(candidate, node_root))

    candidates = _td_source_sqlite_artifact_candidates(node_root=node_root, artifacts_rel=artifacts_rel)
    if candidate_in_node:
        healed_rel = _td_canonical_source_link_for_node(node_root, candidate)
        return {
            "status": "ok",
            "path": candidate,
            "resolved_from": "excel_sqlite_rel",
            "reason": "",
            "healed_excel_sqlite_rel": healed_rel,
            "workbook_excel_sqlite_rel": raw,
        }
    if len(candidates) == 1:
        healed_rel = _td_canonical_source_link_for_node(node_root, candidates[0])
        return {
            "status": "ok",
            "path": candidates[0],
            "resolved_from": "artifacts_rel",
            "reason": "",
            "healed_excel_sqlite_rel": healed_rel,
            "workbook_excel_sqlite_rel": raw,
        }
    if len(candidates) > 1:
        names = ", ".join(p.name for p in candidates[:6])
        return {
            "status": "invalid",
            "path": None,
            "resolved_from": "artifacts_rel",
            "reason": f"Multiple source SQLite files found in TD artifacts folder: {names}",
            "healed_excel_sqlite_rel": "",
            "workbook_excel_sqlite_rel": raw,
        }
    if raw:
        if candidate_exists and not candidate_is_file:
            return {
                "status": "invalid",
                "path": candidate,
                "resolved_from": "excel_sqlite_rel",
                "reason": f"Resolved source path is not a file: {candidate}",
                "healed_excel_sqlite_rel": "",
                "workbook_excel_sqlite_rel": raw,
            }
        if candidate_is_file and not candidate_in_node:
            return {
                "status": "invalid",
                "path": candidate,
                "resolved_from": "excel_sqlite_rel",
                "reason": f"Resolved source SQLite is outside the active node root ({node_root}): {candidate}",
                "healed_excel_sqlite_rel": "",
                "workbook_excel_sqlite_rel": raw,
            }
        return {
            "status": "missing",
            "path": candidate,
            "resolved_from": "excel_sqlite_rel",
            "reason": f"Source SQLite not found: {candidate}",
            "healed_excel_sqlite_rel": "",
            "workbook_excel_sqlite_rel": raw,
        }
    return {
        "status": "missing",
        "path": None,
        "resolved_from": "",
        "reason": "No source SQLite could be resolved from excel_sqlite_rel or artifacts_rel.",
        "healed_excel_sqlite_rel": "",
        "workbook_excel_sqlite_rel": raw,
    }


def _resolve_td_source_sqlite_for_workbook(
    workbook_path: Path,
    source_row: Mapping[str, object],
) -> dict[str, object]:
    wb_path = Path(workbook_path).expanduser()
    node_root = _infer_node_root_from_workbook_path(wb_path)
    support_dir = eidat_support_dir(node_root)
    meta = _load_td_source_metadata(wb_path, source_row)
    excel_sqlite_rel = str(source_row.get("excel_sqlite_rel") or meta.get("excel_sqlite_rel") or "").strip()
    artifacts_rel = str(source_row.get("artifacts_rel") or meta.get("artifacts_rel") or "").strip()
    official = _td_resolve_existing_official_materialization(node_root, meta or source_row)
    if official:
        official_path = Path(official.get("path") or "").expanduser()
        return {
            "status": "ok",
            "path": official_path,
            "resolved_from": "official_td_materialization",
            "reason": "",
            "healed_excel_sqlite_rel": str(official.get("excel_sqlite_rel") or "").strip(),
            "workbook_excel_sqlite_rel": excel_sqlite_rel,
            "excel_sqlite_rel": excel_sqlite_rel,
            "artifacts_rel": str(official.get("artifacts_rel") or artifacts_rel).strip(),
            "healed_artifacts_rel": str(official.get("artifacts_rel") or "").strip(),
            "metadata_rel": str(official.get("metadata_rel") or "").strip(),
            "healed_metadata_rel": str(official.get("metadata_rel") or "").strip(),
            "node_root": str(node_root),
            "support_dir": str(support_dir),
        }
    result = _resolve_td_source_sqlite_for_node(
        node_root,
        excel_sqlite_rel=excel_sqlite_rel,
        artifacts_rel=artifacts_rel,
    )
    return {
        **result,
        "path": Path(result["path"]).expanduser() if result.get("path") else None,
        "excel_sqlite_rel": excel_sqlite_rel,
        "artifacts_rel": artifacts_rel,
        "metadata_rel": str(source_row.get("metadata_rel") or meta.get("metadata_rel") or "").strip(),
        "node_root": str(node_root),
        "support_dir": str(support_dir),
        "healed_artifacts_rel": "",
        "healed_metadata_rel": "",
        "healed_excel_sqlite_rel": str(result.get("healed_excel_sqlite_rel") or "").strip(),
        "workbook_excel_sqlite_rel": str(result.get("workbook_excel_sqlite_rel") or excel_sqlite_rel).strip(),
    }


def _normalize_td_stat(s: object) -> str:
    raw = str(s or "").strip().lower()
    if not raw:
        return ""
    aliases = {
        "avg": "mean",
        "average": "mean",
        "stdev": "std",
        "st.dev": "std",
        "st dev": "std",
        "stddev": "std",
        "standard deviation": "std",
    }
    return aliases.get(raw, raw)


def _read_test_data_data_definitions(workbook_path: Path) -> list[dict]:
    """
    Read the user-editable EIDP-style `Data` sheet (Test Data Trending) as metric definitions.

    Mapping:
      - Data Group: run/sheet name
      - Header: column name
      - Table Label: stat (mean/min/max/std/median/count)
    """
    try:
        from openpyxl import load_workbook  # type: ignore
    except Exception as exc:
        raise RuntimeError(
            "openpyxl is required to read Test Data Trending workbooks. "
            "Install it with `py -m pip install openpyxl` within the project environment."
        ) from exc

    wb = load_workbook(str(Path(workbook_path).expanduser()), read_only=True, data_only=True)
    try:
        if "Data" not in wb.sheetnames:
            return []
        ws = wb["Data"]
        a1 = str(ws.cell(1, 1).value or "").strip().lower()
        if a1 == "metric":
            # Legacy TD workbook layout: old Data sheet is the computed metrics list.
            return []

        headers: dict[str, int] = {}
        for col in range(1, (ws.max_column or 0) + 1):
            key = str(ws.cell(1, col).value or "").strip().lower()
            if key:
                headers[key] = col

        def _h(*names: str) -> int | None:
            for n in names:
                c = headers.get(str(n).strip().lower())
                if c:
                    return int(c)
            return None

        col_term = _h("term")
        col_header = _h("header")
        col_group_after = _h("groupafter")
        col_table_label = _h("table label", "table_label", "tablelabel")
        col_value_type = _h("valuetype", "value type")
        col_data_group = _h("data group", "data_group", "datagroup")
        col_term_label = _h("term label", "term_label", "termlabel")
        col_units = _h("units")
        col_min = _h("min", "range (min)", "range_min")
        col_max = _h("max", "range (max)", "range_max")

        if col_header is None or col_table_label is None or col_data_group is None:
            return []

        allowed = TD_ALLOWED_STATS
        out: list[dict] = []
        for row in range(2, (ws.max_row or 0) + 1):
            dg = str(ws.cell(row, int(col_data_group)).value or "").strip()
            hdr = str(ws.cell(row, int(col_header)).value or "").strip()
            tl = str(ws.cell(row, int(col_table_label)).value or "").strip()
            norm = _normalize_td_stat(tl)
            active = bool(dg and hdr and norm in allowed)
            if not (dg or hdr or tl):
                continue

            out.append(
                {
                    "row_index": int(row),
                    "term": str(ws.cell(row, int(col_term)).value or "").strip() if col_term else "",
                    "header": hdr,
                    "group_after": str(ws.cell(row, int(col_group_after)).value or "").strip() if col_group_after else "",
                    "table_label": tl,
                    "value_type": str(ws.cell(row, int(col_value_type)).value or "").strip() if col_value_type else "",
                    "data_group": dg,
                    "term_label": str(ws.cell(row, int(col_term_label)).value or "").strip() if col_term_label else "",
                    "units": str(ws.cell(row, int(col_units)).value or "").strip() if col_units else "",
                    "min": str(ws.cell(row, int(col_min)).value or "").strip() if col_min else "",
                    "max": str(ws.cell(row, int(col_max)).value or "").strip() if col_max else "",
                    "active": bool(active),
                    "normalized_stat": norm if active else "",
                }
            )
        return out
    finally:
        try:
            wb.close()
        except Exception:
            pass


def td_support_workbook_path_for(workbook_path: Path, *, project_dir: Path | None = None) -> Path:
    wb_path = Path(workbook_path).expanduser()
    proj_dir = Path(project_dir).expanduser() if project_dir is not None else wb_path.parent
    try:
        pj = proj_dir / EIDAT_PROJECT_META
        if pj.exists():
            raw = json.loads(pj.read_text(encoding="utf-8"))
            if isinstance(raw, dict):
                val = str(raw.get("support_workbook") or "").strip()
                if val:
                    p = Path(val).expanduser()
                    if not p.is_absolute():
                        p = proj_dir / p
                    return p
    except Exception:
        pass
    stem = wb_path.stem or "td_project"
    return proj_dir / f"{stem}{TD_SUPPORT_WORKBOOK_SUFFIX}"


def _ordered_td_sheet_info_rows(conn: sqlite3.Connection) -> list[tuple]:
    try:
        cols = {str(row[1] or "") for row in conn.execute("PRAGMA table_info(__sheet_info)").fetchall()}
    except Exception:
        cols = set()
    order_sql = "ORDER BY COALESCE(import_order, rowid), rowid" if "import_order" in cols else "ORDER BY rowid"
    return conn.execute(f"SELECT sheet_name FROM __sheet_info {order_sql}").fetchall()


def _discover_td_runs_for_docs(global_repo: Path | None, docs: list[dict] | None) -> list[str]:
    repo = Path(global_repo).expanduser() if global_repo is not None else None
    runs: list[str] = []
    seen_runs: set[str] = set()
    for d in (docs or []):
        if repo is None:
            continue
        resolved = _resolve_td_source_sqlite_for_node(
            repo,
            excel_sqlite_rel=str((d or {}).get("excel_sqlite_rel") or "").strip(),
            artifacts_rel=str((d or {}).get("artifacts_rel") or "").strip(),
        )
        p = resolved.get("path")
        if not p:
            continue
        p = Path(p).expanduser()
        if not p.exists() or not p.is_file():
            continue
        try:
            with sqlite3.connect(str(p)) as conn:
                rows = _ordered_td_sheet_info_rows(conn)
        except Exception:
            try:
                with sqlite3.connect(str(p)) as conn:
                    rows = conn.execute(
                        "SELECT name FROM sqlite_master WHERE type='table' AND name LIKE 'sheet__%' ORDER BY name"
                    ).fetchall()
                rows = [(str(r[0] or "")[7:],) for r in rows if str(r[0] or "").startswith("sheet__")]
            except Exception:
                rows = []
        for row in rows:
            rn = str(row[0] or "").strip()
            key = rn.lower()
            if not rn or key in seen_runs:
                continue
            seen_runs.add(key)
            runs.append(rn)
    return runs


def _discover_td_runs_by_program_for_docs(global_repo: Path | None, docs: list[dict] | None) -> dict[str, list[str]]:
    repo = Path(global_repo).expanduser() if global_repo is not None else None
    runs_by_program: dict[str, list[str]] = {}
    seen: dict[str, set[str]] = {}
    for d in (docs or []):
        if repo is None or not isinstance(d, dict):
            continue
        program_title = str(d.get("program_title") or "").strip() or TD_SUPPORT_DEFAULT_PROGRAM_TITLE
        resolved = _resolve_td_source_sqlite_for_node(
            repo,
            excel_sqlite_rel=str((d or {}).get("excel_sqlite_rel") or "").strip(),
            artifacts_rel=str((d or {}).get("artifacts_rel") or "").strip(),
        )
        p = resolved.get("path")
        if not p:
            continue
        p = Path(p).expanduser()
        if not p.exists() or not p.is_file():
            continue
        try:
            with sqlite3.connect(str(p)) as conn:
                rows = _ordered_td_sheet_info_rows(conn)
        except Exception:
            try:
                with sqlite3.connect(str(p)) as conn:
                    rows = conn.execute(
                        "SELECT name FROM sqlite_master WHERE type='table' AND name LIKE 'sheet__%' ORDER BY name"
                    ).fetchall()
                rows = [(str(r[0] or "")[7:],) for r in rows if str(r[0] or "").startswith("sheet__")]
            except Exception:
                rows = []
        for row in rows:
            run_name = str(row[0] or "").strip()
            if not run_name:
                continue
            seen.setdefault(program_title, set())
            if run_name.lower() in seen[program_title]:
                continue
            seen[program_title].add(run_name.lower())
            runs_by_program.setdefault(program_title, []).append(run_name)
    return runs_by_program


def _td_read_sequence_context_rows(conn: sqlite3.Connection) -> list[dict[str, object]]:
    try:
        has_table = bool(
            conn.execute(
                "SELECT 1 FROM sqlite_master WHERE type='table' AND name='__sequence_context' LIMIT 1"
            ).fetchone()
        )
    except Exception:
        has_table = False
    if not has_table:
        return []
    try:
        cursor = conn.execute(
            """
            SELECT
                sheet_name,
                source_sheet_name,
                data_mode_raw,
                run_type,
                on_time_value,
                on_time_units,
                off_time_value,
                off_time_units,
                control_period,
                nominal_pf_value,
                nominal_pf_units,
                nominal_tf_value,
                nominal_tf_units,
                suppression_voltage_value,
                suppression_voltage_units,
                valve_voltage_value,
                valve_voltage_units,
                extraction_status,
                extraction_reason
            FROM __sequence_context
            ORDER BY rowid
            """
        )
    except Exception:
        return []
    names = [str(col[0] or "").strip() for col in (cursor.description or [])]
    out: list[dict[str, object]] = []
    for row in cursor.fetchall():
        payload = {names[idx]: row[idx] for idx in range(min(len(names), len(row)))}
        sheet_name = str(payload.get("sheet_name") or "").strip()
        if sheet_name:
            out.append(payload)
    return out


def _td_read_sequence_context_by_run(conn: sqlite3.Connection) -> dict[str, dict[str, object]]:
    by_run: dict[str, dict[str, object]] = {}
    for row in _td_read_sequence_context_rows(conn):
        run_name = str(row.get("sheet_name") or "").strip()
        if not run_name:
            continue
        key = _td_support_norm_name(run_name)
        if key and key not in by_run:
            by_run[key] = dict(row)
    return by_run


def _td_sequence_context_is_usable(row: Mapping[str, object] | None) -> bool:
    if not isinstance(row, Mapping):
        return False
    status = str(row.get("extraction_status") or "").strip().lower()
    if status != "ok":
        return False
    run_type = td_normalize_run_type(row.get("run_type"))
    pressure_units = str(row.get("nominal_pf_units") or "").strip()
    return bool(
        run_type
        and row.get("on_time_value") not in (None, "")
        and row.get("off_time_value") not in (None, "")
        and row.get("control_period") not in (None, "")
        and row.get("nominal_pf_value") not in (None, "")
        and pressure_units
    )


def _td_support_blankish(value: object) -> bool:
    return value is None or str(value).strip() == ""


def _td_sequence_context_support_fields(row: Mapping[str, object] | None) -> dict[str, object]:
    if not isinstance(row, Mapping):
        return {}
    return {
        "feed_pressure": row.get("nominal_pf_value"),
        "feed_pressure_units": str(row.get("nominal_pf_units") or "").strip(),
        "feed_temperature": row.get("nominal_tf_value"),
        "feed_temperature_units": str(row.get("nominal_tf_units") or "").strip(),
        "run_type": td_normalize_run_type(row.get("run_type")),
        "pulse_width": row.get("on_time_value"),
        "pulse_width_on": row.get("on_time_value"),
        "control_period": row.get("control_period", row.get("off_time_value")),
        "suppression_voltage": row.get("suppression_voltage_value"),
        "valve_voltage": row.get("valve_voltage_value"),
    }


def _td_sequence_context_source_label(
    row: Mapping[str, object] | None,
    *,
    source_run_name: object = "",
) -> str:
    if not isinstance(row, Mapping):
        return ""
    source_run = str(source_run_name or row.get("sheet_name") or "").strip()
    for candidate in (
        row.get("source_sheet_name"),
        row.get("display_name"),
        row.get("sheet_name"),
    ):
        text = str(candidate or "").strip()
        if not text:
            continue
        if source_run and _td_support_norm_name(text) == _td_support_norm_name(source_run):
            continue
        return text
    return ""


def _td_support_name_is_default(value: object, source_run_name: object) -> bool:
    text = str(value or "").strip()
    if not text:
        return True
    source = str(source_run_name or "").strip()
    return bool(source) and _td_support_norm_name(text) == _td_support_norm_name(source)


def _td_support_row_has_condition_values(row: Mapping[str, object] | None) -> bool:
    if not isinstance(row, Mapping):
        return False
    return any(
        not _td_support_blankish(row.get(field))
        for field in (
            "feed_pressure",
            "feed_pressure_units",
            "feed_temperature",
            "feed_temperature_units",
            "run_type",
            "pulse_width_on",
            "pulse_width",
            "control_period",
            "suppression_voltage",
            "valve_voltage",
        )
    )


def _td_support_row_has_core_bundle(row: Mapping[str, object] | None) -> bool:
    if not isinstance(row, Mapping):
        return False
    return bool(
        not _td_support_blankish(row.get("feed_pressure"))
        and str(row.get("feed_pressure_units") or "").strip()
        and td_normalize_run_type(row.get("run_type"))
        and not _td_support_blankish(row.get("pulse_width_on", row.get("pulse_width")))
        and not _td_support_blankish(row.get("control_period"))
    )


def _td_support_row_is_promotable(row: Mapping[str, object] | None) -> bool:
    if not isinstance(row, Mapping):
        return False
    source_run_name = str(row.get("source_run_name") or "").strip()
    explicit_condition_key = str(row.get("condition_key") or "").strip()
    explicit_display_name = str(row.get("display_name") or "").strip()
    if explicit_condition_key and not _td_support_name_is_default(explicit_condition_key, source_run_name):
        return True
    if explicit_display_name and not _td_support_name_is_default(explicit_display_name, source_run_name):
        return True
    return _td_support_row_has_core_bundle(row)


def _td_prefill_support_row_from_sequence_context(
    row: Mapping[str, object] | None,
    source_context: Mapping[str, object] | None,
    *,
    blank_unusable_defaults: bool,
) -> dict[str, object]:
    payload = dict(row or {})
    source_run_name = str(payload.get("source_run_name") or "").strip()
    source_label = _td_sequence_context_source_label(source_context, source_run_name=source_run_name)
    had_condition_values = _td_support_row_has_condition_values(payload)
    source_label_applied = False

    def _apply_source_label() -> None:
        nonlocal source_label_applied
        if not source_label:
            return
        if (
            _td_support_blankish(payload.get("condition_key"))
            or _td_support_name_is_default(payload.get("condition_key"), source_run_name)
        ):
            payload["condition_key"] = source_label
            source_label_applied = True
        if (
            _td_support_blankish(payload.get("display_name"))
            or _td_support_name_is_default(payload.get("display_name"), source_run_name)
        ):
            payload["display_name"] = source_label
            source_label_applied = True

    if not _td_sequence_context_is_usable(source_context):
        _apply_source_label()
        fallback_label = source_label or source_run_name
        if blank_unusable_defaults and not _td_support_row_has_condition_values(payload):
            if _td_support_blankish(payload.get("condition_key")) and fallback_label:
                payload["condition_key"] = fallback_label
            if _td_support_blankish(payload.get("display_name")) and fallback_label:
                payload["display_name"] = fallback_label
        if source_label_applied:
            payload["__source_label_promoted"] = True
        return payload

    support_fields = _td_sequence_context_support_fields(source_context)
    for field_name, field_value in support_fields.items():
        if _td_support_blankish(payload.get(field_name)):
            payload[field_name] = field_value
    derived_label = td_build_run_condition_label(payload)
    if derived_label and not had_condition_values:
        if _td_support_name_is_default(payload.get("condition_key"), source_run_name):
            payload["condition_key"] = derived_label
        if _td_support_name_is_default(payload.get("display_name"), source_run_name):
            payload["display_name"] = derived_label
    elif not derived_label:
        _apply_source_label()
    if source_label_applied:
        payload["__source_label_promoted"] = True
    return payload


def _discover_td_sequence_context_by_program_for_docs(
    global_repo: Path | None,
    docs: list[dict] | None,
) -> dict[str, dict[str, dict[str, object]]]:
    repo = Path(global_repo).expanduser() if global_repo is not None else None
    out: dict[str, dict[str, dict[str, object]]] = {}
    for d in (docs or []):
        if repo is None or not isinstance(d, dict):
            continue
        program_title = str(d.get("program_title") or "").strip() or TD_SUPPORT_DEFAULT_PROGRAM_TITLE
        resolved = _resolve_td_source_sqlite_for_node(
            repo,
            excel_sqlite_rel=str((d or {}).get("excel_sqlite_rel") or "").strip(),
            artifacts_rel=str((d or {}).get("artifacts_rel") or "").strip(),
        )
        p = resolved.get("path")
        if not p:
            continue
        p = Path(p).expanduser()
        if not p.exists() or not p.is_file():
            continue
        try:
            with sqlite3.connect(str(p)) as conn:
                rows = _td_read_sequence_context_rows(conn)
        except Exception:
            rows = []
        for row in rows:
            run_name = str(row.get("sheet_name") or "").strip()
            run_key = _td_support_norm_name(run_name)
            if not run_key:
                continue
            existing = dict((out.get(program_title) or {}).get(run_key) or {})
            if not existing or (_td_sequence_context_is_usable(row) and not _td_sequence_context_is_usable(existing)):
                out.setdefault(program_title, {})[run_key] = dict(row)
    return out


def _td_lookup_sequence_context(
    sequence_context_by_program: Mapping[str, Mapping[str, Mapping[str, object]]] | None,
    program_title: object,
    source_run_name: object,
) -> dict[str, object]:
    title_key = _td_support_norm_name(program_title)
    run_key = _td_support_norm_name(source_run_name)
    if not run_key or not isinstance(sequence_context_by_program, Mapping):
        return {}
    for title, rows in sequence_context_by_program.items():
        if _td_support_norm_name(title) != title_key:
            continue
        if isinstance(rows, Mapping) and run_key in rows:
            return dict(rows.get(run_key) or {})
    matches: list[dict[str, object]] = []
    for rows in sequence_context_by_program.values():
        if not isinstance(rows, Mapping):
            continue
        if run_key in rows:
            matches.append(dict(rows.get(run_key) or {}))
    if len(matches) == 1:
        return matches[0]
    return {}


