def _td_support_norm_name(value: object) -> str:
    return "".join(ch.lower() for ch in str(value or "").strip() if ch.isalnum())


def _td_program_parameter_canonical_id(display_name: object) -> str:
    norm = _td_param_norm_name(display_name)
    return f"display:{norm}" if norm else _td_parameter_implicit_canonical_id(display_name)


def _td_program_parameter_scope_text(value: object) -> str:
    return re.sub(r"\s+", " ", str(value or "").strip())


def _td_program_parameter_scope_key(
    program_title: object,
    asset_type: object,
    asset_specific_type: object,
    ingested_parameter: object,
) -> tuple[str, str, str, str]:
    return (
        _td_param_norm_program(program_title),
        _td_param_norm_program(_td_program_parameter_scope_text(asset_type)),
        _td_param_norm_program(_td_program_parameter_scope_text(asset_specific_type)),
        _td_param_norm_name(ingested_parameter),
    )


def _td_program_parameter_mapping_normalize(
    row: Mapping[str, object] | None,
    *,
    program_title: object = "",
) -> dict[str, object]:
    raw = dict(row or {})
    normalized_program = _td_program_parameter_scope_text(raw.get("program_title") or program_title)
    asset_type = _td_program_parameter_scope_text(raw.get("asset_type"))
    asset_specific_type = _td_program_parameter_scope_text(raw.get("asset_specific_type"))
    ingested_parameter = str(raw.get("ingested_parameter") or raw.get("raw_name") or "").strip()
    if not ingested_parameter:
        return {}
    default_display = str(
        raw.get("default_display_parameter")
        or raw.get("mapped_parameter")
        or raw.get("mapped_header")
        or raw.get("displayed_parameter")
        or raw.get("display_name")
        or ingested_parameter
    ).strip() or ingested_parameter
    displayed_parameter = str(
        raw.get("displayed_parameter")
        or raw.get("display_name")
        or default_display
        or ingested_parameter
    ).strip() or default_display
    edited = bool(raw.get("edited"))
    if _td_param_norm_name(displayed_parameter) != _td_param_norm_name(default_display):
        edited = True
    return {
        "program_title": normalized_program,
        "asset_type": asset_type,
        "asset_specific_type": asset_specific_type,
        "ingested_parameter": ingested_parameter,
        "default_display_parameter": default_display,
        "displayed_parameter": displayed_parameter,
        "preferred_units": str(raw.get("preferred_units") or raw.get("units") or "").strip(),
        "default_preferred_units": str(
            raw.get("default_preferred_units")
            or raw.get("preferred_units_default")
            or raw.get("default_units")
            or ""
        ).strip(),
        "enabled": _td_bool(raw.get("enabled"), True),
        "edited": bool(edited),
        "updated_at": str(raw.get("updated_at") or "").strip(),
    }


def _td_program_parameter_mapping_commit(
    row: Mapping[str, object] | None,
    *,
    program_title: object = "",
) -> dict[str, object]:
    normalized = _td_program_parameter_mapping_normalize(row, program_title=program_title)
    if not normalized:
        return {}
    display_name = str(
        normalized.get("displayed_parameter")
        or normalized.get("default_display_parameter")
        or normalized.get("ingested_parameter")
        or ""
    ).strip() or str(normalized.get("ingested_parameter") or "").strip()
    normalized["default_display_parameter"] = display_name
    normalized["displayed_parameter"] = display_name
    normalized["edited"] = False
    return normalized


def _td_program_parameter_effective_display(row: Mapping[str, object] | None) -> str:
    payload = _td_program_parameter_mapping_normalize(row)
    if not payload:
        return ""
    return str(
        payload.get("displayed_parameter")
        or payload.get("default_display_parameter")
        or payload.get("ingested_parameter")
        or ""
    ).strip()


def _td_program_parameter_mapping_sort_key(row: Mapping[str, object] | None) -> tuple[str, str, str, str]:
    payload = _td_program_parameter_mapping_normalize(row)
    return (
        _td_param_norm_program(payload.get("asset_type")),
        _td_param_norm_program(payload.get("asset_specific_type")),
        _td_param_norm_name(payload.get("ingested_parameter")),
        _td_param_norm_name(payload.get("displayed_parameter")),
    )


def _td_program_parameter_merge_rows(
    existing_rows: Sequence[Mapping[str, object]] | None,
    discovered_rows: Sequence[Mapping[str, object]] | None,
    *,
    program_title: object = "",
) -> list[dict[str, object]]:
    out_by_key: dict[tuple[str, str, str, str], dict[str, object]] = {}
    for item in existing_rows or []:
        normalized = _td_program_parameter_mapping_commit(item, program_title=program_title)
        key = _td_program_parameter_scope_key(
            normalized.get("program_title"),
            normalized.get("asset_type"),
            normalized.get("asset_specific_type"),
            normalized.get("ingested_parameter"),
        )
        if key[-1]:
            out_by_key[key] = normalized
    for item in discovered_rows or []:
        discovered = _td_program_parameter_mapping_normalize(item, program_title=program_title)
        key = _td_program_parameter_scope_key(
            discovered.get("program_title"),
            discovered.get("asset_type"),
            discovered.get("asset_specific_type"),
            discovered.get("ingested_parameter"),
        )
        if not key[-1]:
            continue
        existing = dict(out_by_key.get(key) or {})
        merged = dict(discovered)
        if existing:
            committed_existing = _td_program_parameter_mapping_commit(existing, program_title=program_title)
            existing_units = str(committed_existing.get("preferred_units") or "").strip()
            discovered_units = str(merged.get("preferred_units") or "").strip()
            merged["preferred_units"] = existing_units or discovered_units
            merged["default_preferred_units"] = str(
                committed_existing.get("default_preferred_units")
                or merged.get("default_preferred_units")
                or merged.get("preferred_units")
                or ""
            ).strip()
            merged["enabled"] = _td_bool(existing.get("enabled"), True)
            existing_default = str(committed_existing.get("default_display_parameter") or "").strip()
            existing_display = str(committed_existing.get("displayed_parameter") or existing_default).strip()
            discovered_default = str(
                merged.get("default_display_parameter")
                or merged.get("displayed_parameter")
                or merged.get("ingested_parameter")
                or ""
            ).strip()
            discovered_display = str(
                merged.get("displayed_parameter")
                or merged.get("default_display_parameter")
                or merged.get("ingested_parameter")
                or ""
            ).strip()
            merged["default_display_parameter"] = existing_default or discovered_default
            merged["displayed_parameter"] = existing_display or discovered_display or discovered_default
            merged["edited"] = bool(committed_existing.get("edited"))
            merged["updated_at"] = str(existing.get("updated_at") or merged.get("updated_at") or "").strip()
        else:
            merged["enabled"] = _td_bool(merged.get("enabled"), True)
        out_by_key[key] = merged
    return sorted(out_by_key.values(), key=_td_program_parameter_mapping_sort_key)


def _td_support_program_sheet_name(program_title: str, index: int) -> str:
    slug = re.sub(r"[^A-Za-z0-9]+", "_", str(program_title or "").strip()).strip("_")
    slug = slug or f"{index + 1:02d}"
    prefix = f"{TD_SUPPORT_PROGRAM_SHEET_PREFIX}{index + 1:02d}_"
    room = max(0, 31 - len(prefix))
    return (prefix + slug[:room])[:31]


def _td_support_condition_sheet_name(condition_key: str, index: int) -> str:
    slug = re.sub(r"[^A-Za-z0-9]+", "_", str(condition_key or "").strip()).strip("_")
    slug = slug or f"{index + 1:02d}"
    prefix = f"{TD_SUPPORT_CONDITION_SHEET_PREFIX}{index + 1:02d}_"
    room = max(0, 31 - len(prefix))
    return (prefix + slug[:room])[:31]


def _td_load_workbook_ignore_long_title_warning(*args, **kwargs):
    import warnings

    from openpyxl import load_workbook  # type: ignore

    with warnings.catch_warnings():
        warnings.filterwarnings(
            "ignore",
            message=r"Title is more than 31 characters.*",
            category=UserWarning,
        )
        return load_workbook(*args, **kwargs)


def _td_safe_excel_sheet_title(title: object, used: set[str], *, fallback: str = "Sheet") -> str:
    raw = re.sub(r"[\[\]\*:/\\?]+", "_", str(title or "").strip()).strip("'")
    raw = raw or fallback
    candidate = raw[:31] or fallback[:31] or "Sheet"
    suffix_idx = 2
    while candidate.lower() in used:
        suffix = f"_{suffix_idx}"
        candidate = (raw[: max(0, 31 - len(suffix))] + suffix)[:31]
        suffix_idx += 1
    used.add(candidate.lower())
    return candidate


def td_program_requirements_workbook_path_for(global_repo: Path | None, program_title: object) -> Path:
    repo = Path(global_repo or get_repo_root()).expanduser()
    return (
        edin_program_folders_root(repo)
        / edin_program_folder_name(program_title)
        / TD_PROGRAM_REQUIREMENTS_WORKBOOK_NAME
    )


def _td_program_requirements_split_member_sequences(value: object) -> list[str]:
    raw = str(value or "").replace("\n", ";")
    out: list[str] = []
    seen: set[str] = set()
    for part in raw.split(";"):
        text = str(part or "").strip()
        key = text.casefold()
        if not text or key in seen:
            continue
        seen.add(key)
        out.append(text)
    return out


def _td_program_requirements_member_sequences_text(value: object) -> str:
    return "; ".join(_td_program_requirements_split_member_sequences(value))


def _td_program_requirements_parse_bool(value: object, *, default: bool = True) -> bool:
    if isinstance(value, bool):
        return bool(value)
    text = str(value or "").strip().lower()
    if not text:
        return bool(default)
    if text in {"1", "true", "yes", "y", "on"}:
        return True
    if text in {"0", "false", "no", "n", "off"}:
        return False
    return bool(default)


def _td_program_requirements_condition_identity(value: object, *, fallback: object = "") -> str:
    text = str(value or fallback or "").strip()
    return _td_support_norm_name(text) or _td_norm_ident_token(text or fallback or "condition")


def _td_program_requirements_existing_catalog(requirements: Sequence[Mapping[str, object]] | None) -> list[dict[str, str]]:
    out: list[dict[str, str]] = []
    seen: set[str] = set()
    for row in requirements or []:
        if not isinstance(row, Mapping):
            continue
        name = str(row.get("parameter_name") or "").strip()
        key = _td_support_norm_name(name)
        if not key or key in seen:
            continue
        seen.add(key)
        out.append({"name": name, "units": str(row.get("units") or "").strip()})
    return out


def _td_program_requirements_merge_catalogs(*catalog_lists: Sequence[Mapping[str, object]] | None) -> list[dict[str, str]]:
    out: list[dict[str, str]] = []
    by_key: dict[str, int] = {}
    for catalog in catalog_lists:
        for item in catalog or []:
            if not isinstance(item, Mapping):
                continue
            name = str(item.get("name") or item.get("parameter_name") or "").strip()
            key = _td_support_norm_name(name)
            if not key:
                continue
            units = str(item.get("units") or "").strip()
            idx = by_key.get(key)
            if idx is None:
                by_key[key] = len(out)
                out.append({"name": name, "units": units})
                continue
            if units and not str(out[idx].get("units") or "").strip():
                out[idx]["units"] = units
    return out


def _td_program_requirements_runtime_x_aliases() -> set[str]:
    aliases = {"time", "pulse"}
    try:
        runtime_cfg = _load_runtime_td_trend_config()
        x_cfg = dict((runtime_cfg.get("config") or {}).get("x_axis") or {})
    except Exception:
        x_cfg = {}
    for value in (x_cfg.get("time_aliases") or []):
        key = _td_support_norm_name(value)
        if key:
            aliases.add(key)
    for value in (x_cfg.get("pulse_aliases") or []):
        key = _td_support_norm_name(value)
        if key:
            aliases.add(key)
    default_x = _td_support_norm_name(x_cfg.get("default_x"))
    if default_x:
        aliases.add(default_x)
    return aliases


def _td_program_requirements_param_def_map(param_defs: Sequence[Mapping[str, object]] | None) -> dict[str, dict[str, str]]:
    defs = [
        dict(item)
        for item in (param_defs or [])
        if isinstance(item, Mapping) and str(item.get("name") or "").strip()
    ]
    if not defs:
        try:
            defs = [
                dict(item)
                for item in (_load_runtime_td_trend_config().get("columns") or [])
                if isinstance(item, Mapping) and str(item.get("name") or "").strip()
            ]
        except Exception:
            defs = []
    out: dict[str, dict[str, str]] = {}
    for item in defs:
        name = str(item.get("name") or "").strip()
        units = str(item.get("units") or "").strip()
        aliases = [name]
        aliases.extend(
            str(alias).strip()
            for alias in (item.get("aliases") or [])
            if str(alias).strip()
        )
        for alias in aliases:
            key = _td_support_norm_name(alias)
            if key and key not in out:
                out[key] = {"name": name, "units": units}
    return out


_TD_DISCOVERABLE_UNIT_TOKENS = {
    "s": "s",
    "sec": "sec",
    "secs": "sec",
    "second": "sec",
    "seconds": "sec",
    "ms": "ms",
    "msec": "msec",
    "msecs": "msec",
    "psi": "psi",
    "psia": "psia",
    "lbf": "lbf",
    "v": "V",
    "kv": "kV",
    "a": "A",
    "amp": "A",
    "amps": "A",
    "ma": "mA",
    "mv": "mV",
    "hz": "Hz",
    "khz": "kHz",
    "%": "%",
    "pct": "%",
    "percent": "%",
    "f": "F",
    "c": "C",
    "degf": "F",
    "degc": "C",
    "in2": "in^2",
    "in^2": "in^2",
    "ft2": "ft^2",
    "ft^2": "ft^2",
}


def _td_discovered_unit_from_header_value(value: object) -> str:
    text = str(value or "").strip()
    if not text:
        return ""
    match = re.search(r"\(([^()]+)\)\s*$", text)
    if match:
        candidate = re.sub(r"\s+", "", str(match.group(1) or "").strip())
        if candidate:
            return _TD_DISCOVERABLE_UNIT_TOKENS.get(candidate.casefold(), candidate)
    # Fall back to a known trailing unit token when the source header was flattened
    # into text such as "Time sec" or "Pressure psia".
    tokens = re.findall(r"[A-Za-z0-9%^./]+|%", text)
    if not tokens:
        return ""
    candidate = str(tokens[-1] or "").strip()
    if not candidate:
        return ""
    return _TD_DISCOVERABLE_UNIT_TOKENS.get(candidate.casefold(), "")


def _td_discovered_unit_from_column_names(*values: object) -> str:
    for value in values:
        unit = _td_discovered_unit_from_header_value(value)
        if unit:
            return unit
    return ""


def _td_parameter_name_match_variants(value: object) -> list[str]:
    raw = str(value or "").strip()
    if not raw:
        return []
    variants: list[str] = []
    seen: set[str] = set()

    def _add(text: object) -> None:
        candidate = str(text or "").strip()
        norm = _td_param_norm_name(candidate)
        if not candidate or not norm or norm in seen:
            return
        seen.add(norm)
        variants.append(candidate)

    _add(raw)
    _add(re.sub(r"\s*\(([^()]*)\)\s*$", "", raw).strip())
    unit_norms = {_td_param_norm_name(key) for key in _TD_DISCOVERABLE_UNIT_TOKENS if _td_param_norm_name(key)}
    for candidate in list(variants):
        tokens = [token for token in re.split(r"[_\s]+", candidate) if token]
        if len(tokens) <= 1:
            continue
        if _td_param_norm_name(tokens[-1]) in unit_norms:
            _add(" ".join(tokens[:-1]))
            _add("_".join(tokens[:-1]))
    return variants


def _td_program_requirements_is_parameter_column(column_name: object, *, x_aliases: set[str]) -> bool:
    raw = str(column_name or "").strip()
    if not raw or raw.startswith("__"):
        return False
    key = _td_support_norm_name(raw)
    if not key or key in x_aliases:
        return False
    excluded = {
        "excelrow",
        "row",
        "rowid",
        "index",
        "runtype",
        "sheetname",
        "sourcesheetname",
        "datamoderaw",
        "extractionstatus",
        "extractionreason",
    }
    return key not in excluded


def _td_program_requirements_discover_run_parameters(
    conn: sqlite3.Connection,
    sheet_name: str,
    table_name: str,
    *,
    param_defs: Sequence[Mapping[str, object]] | None,
) -> list[dict[str, str]]:
    out: list[dict[str, str]] = []
    seen: set[str] = set()
    for spec in _td_source_sqlite_column_specs(
        conn,
        sheet_name=str(sheet_name or "").strip(),
        table_name=str(table_name or "").strip(),
        param_defs=param_defs,
    ):
        if not bool(spec.get("is_parameter")):
            continue
        canonical_name = str(spec.get("header") or "").strip()
        key = _td_support_norm_name(canonical_name)
        if not key or key in seen:
            continue
        seen.add(key)
        out.append(
            {
                "name": canonical_name,
                "units": str(spec.get("preferred_units") or "").strip(),
            }
        )
    return out


def _td_source_sqlite_column_specs(
    conn: sqlite3.Connection,
    *,
    sheet_name: str,
    table_name: str,
    param_defs: Sequence[Mapping[str, object]] | None,
) -> list[dict[str, object]]:
    name = str(table_name or "").strip()
    if not name or not _td_table_exists(conn, name):
        return []
    try:
        pragma_rows = conn.execute(f"PRAGMA table_info({_quote_ident(name)})").fetchall()
    except Exception:
        pragma_rows = []
    if not pragma_rows:
        return []
    column_map_rows: list[tuple[object, object, object]] = []
    if _td_table_exists(conn, "__column_map"):
        try:
            column_map_rows = conn.execute(
                """
                SELECT header, mapped_header, sqlite_column
                FROM __column_map
                WHERE sheet_name=?
                ORDER BY rowid
                """,
                (str(sheet_name or "").strip(),),
            ).fetchall()
        except Exception:
            column_map_rows = []
    map_by_sqlite: dict[str, dict[str, str]] = {}
    for header, mapped_header, sqlite_column in column_map_rows:
        sqlite_key = str(sqlite_column or "").strip()
        if not sqlite_key or sqlite_key in map_by_sqlite:
            continue
        map_by_sqlite[sqlite_key] = {
            "header": str(header or "").strip(),
            "mapped_header": str(mapped_header or "").strip(),
        }
    x_aliases = _td_program_requirements_runtime_x_aliases()
    param_map = _td_program_requirements_param_def_map(param_defs)
    out: list[dict[str, object]] = []
    for row in pragma_rows:
        sqlite_column = str(row[1] or "").strip()
        if not sqlite_column or sqlite_column.startswith("__") or _td_support_norm_name(sqlite_column) == "excelrow":
            continue
        mapped = dict(map_by_sqlite.get(sqlite_column) or {})
        header = str(mapped.get("header") or sqlite_column).strip() or sqlite_column
        mapped_header = str(mapped.get("mapped_header") or header).strip() or header
        param_match = (
            param_map.get(_td_support_norm_name(mapped_header))
            or param_map.get(_td_support_norm_name(header))
            or {}
        )
        preferred_units = str(param_match.get("units") or "").strip()
        if not preferred_units:
            preferred_units = _td_discovered_unit_from_column_names(header, mapped_header, sqlite_column)
        candidate_name = mapped_header or header
        is_parameter = _td_program_requirements_is_parameter_column(candidate_name, x_aliases=x_aliases)
        if is_parameter and not _td_program_requirements_is_parameter_column(header, x_aliases=x_aliases):
            is_parameter = _td_program_requirements_is_parameter_column(mapped_header, x_aliases=x_aliases)
        out.append(
            {
                "sqlite_column": sqlite_column,
                "header": header,
                "mapped_header": mapped_header,
                "default_display_parameter": mapped_header or header,
                "preferred_units": preferred_units,
                "is_parameter": bool(is_parameter),
            }
        )
    return out


def _td_autonormalize_parameter_mapping_rows(
    rows: Sequence[Mapping[str, object]] | None,
    *,
    config_candidates: Sequence[Mapping[str, object]] | None = None,
) -> list[dict[str, object]]:
    normalized_rows: list[dict[str, object]] = []
    for row in (rows or []):
        normalized = _td_program_parameter_mapping_normalize(row)
        if normalized:
            normalized_rows.append(normalized)
    if not normalized_rows:
        return sorted(normalized_rows, key=_td_program_parameter_mapping_sort_key)

    scopes: dict[tuple[str, str, str], list[dict[str, object]]] = {}
    for row in normalized_rows:
        scope_key = (
            _td_param_norm_program(row.get("program_title")),
            _td_param_norm_program(row.get("asset_type")),
            _td_param_norm_program(row.get("asset_specific_type")),
        )
        scopes.setdefault(scope_key, []).append(dict(row))

    out: list[dict[str, object]] = []
    for scoped_rows in scopes.values():
        metas: list[dict[str, object]] = []
        for row in scoped_rows:
            raw_name = str(row.get("ingested_parameter") or "").strip()
            candidate_name = str(
                row.get("default_display_parameter")
                or row.get("displayed_parameter")
                or raw_name
                or ""
            ).strip()
            preferred_units = str(row.get("preferred_units") or "").strip()
            suggestion = _td_parameter_inventory_suggestion(
                raw_name,
                units=[preferred_units] if preferred_units else [],
                config_candidates=config_candidates,
            )
            metas.append(
                {
                    "row": row,
                    "raw_name": raw_name,
                    "candidate_name": candidate_name or raw_name,
                    "preferred_units": preferred_units,
                    "suggestion": suggestion,
                }
            )

        visited: set[int] = set()
        for start_idx in range(len(metas)):
            if start_idx in visited:
                continue
            component: list[int] = []
            queue = [start_idx]
            visited.add(start_idx)
            while queue:
                idx = queue.pop()
                component.append(idx)
                lhs = metas[idx]
                lhs_suggestion = _td_param_norm_name((lhs.get("suggestion") or {}).get("display_name"))
                lhs_texts = {
                    str(lhs.get("candidate_name") or "").strip(),
                    str(lhs.get("raw_name") or "").strip(),
                }
                for other_idx, rhs in enumerate(metas):
                    if other_idx in visited:
                        continue
                    rhs_suggestion = _td_param_norm_name((rhs.get("suggestion") or {}).get("display_name"))
                    same_suggestion = bool(lhs_suggestion and lhs_suggestion == rhs_suggestion)
                    similar_text = any(
                        _td_parameter_names_similar(lhs_text, rhs_text)
                        for lhs_text in lhs_texts
                        for rhs_text in {
                            str(rhs.get("candidate_name") or "").strip(),
                            str(rhs.get("raw_name") or "").strip(),
                        }
                        if lhs_text and rhs_text
                    )
                    if not same_suggestion and not similar_text:
                        continue
                    visited.add(other_idx)
                    queue.append(other_idx)

            cluster = [metas[idx] for idx in component]
            suggestion_map = {
                _td_param_norm_name((meta.get("suggestion") or {}).get("display_name")): dict(meta.get("suggestion") or {})
                for meta in cluster
                if _td_param_norm_name((meta.get("suggestion") or {}).get("display_name"))
            }
            chosen_display = ""
            chosen_units = ""
            if len(suggestion_map) == 1:
                chosen = next(iter(suggestion_map.values()))
                chosen_display = str(chosen.get("display_name") or "").strip()
                chosen_units = str(chosen.get("preferred_units") or "").strip()
            else:
                best = max(
                    cluster,
                    key=lambda meta: _td_parameter_display_candidate_sort_key(
                        meta.get("candidate_name"),
                        units=meta.get("preferred_units"),
                    ),
                )
                chosen_display = str(best.get("candidate_name") or best.get("raw_name") or "").strip()
                chosen_units = str(best.get("preferred_units") or "").strip()
            if not chosen_units:
                cluster_units = sorted(
                    {
                        str(meta.get("preferred_units") or "").strip()
                        for meta in cluster
                        if str(meta.get("preferred_units") or "").strip()
                    },
                    key=str.casefold,
                )
                if len(cluster_units) == 1:
                    chosen_units = cluster_units[0]
            for meta in cluster:
                row = dict(meta.get("row") or {})
                if chosen_display:
                    row["default_display_parameter"] = chosen_display
                    if not bool(row.get("edited")):
                        row["displayed_parameter"] = chosen_display
                if chosen_units and not str(row.get("preferred_units") or "").strip():
                    row["preferred_units"] = chosen_units
                out.append(row)

    return sorted(out, key=_td_program_parameter_mapping_sort_key)


def _td_program_requirements_discover_conditions_by_program(
    global_repo: Path | None,
    docs: Sequence[Mapping[str, object]] | None,
    *,
    param_defs: Sequence[Mapping[str, object]] | None,
) -> dict[str, list[dict[str, object]]]:
    repo = Path(global_repo).expanduser() if global_repo is not None else None
    rows_by_program: dict[str, list[dict[str, object]]] = {}
    parameters_by_program_run: dict[str, dict[str, list[dict[str, str]]]] = {}
    refreshed_at = datetime.now().isoformat(timespec="seconds")
    for doc in docs or []:
        if repo is None or not isinstance(doc, Mapping):
            continue
        program_title = str(doc.get("program_title") or "").strip() or TD_SUPPORT_DEFAULT_PROGRAM_TITLE
        resolved = _resolve_td_source_sqlite_for_node(
            repo,
            excel_sqlite_rel=str(doc.get("excel_sqlite_rel") or "").strip(),
            artifacts_rel=str(doc.get("artifacts_rel") or "").strip(),
        )
        sqlite_path = resolved.get("path")
        if not sqlite_path:
            continue
        path = Path(sqlite_path).expanduser()
        if not path.exists() or not path.is_file():
            continue
        try:
            with sqlite3.connect(str(path)) as conn:
                try:
                    runs = [str(row[0] or "").strip() for row in _ordered_td_sheet_info_rows(conn) if str(row[0] or "").strip()]
                except Exception:
                    rows = conn.execute(
                        "SELECT name FROM sqlite_master WHERE type='table' AND name LIKE 'sheet__%' ORDER BY name"
                    ).fetchall()
                    runs = [str(row[0] or "")[7:] for row in rows if str(row[0] or "").startswith("sheet__")]
                sequence_context = _td_read_sequence_context_by_run(conn)
                table_name_by_run: dict[str, str] = {}
                if _td_table_exists(conn, "__sheet_info"):
                    try:
                        info_rows = conn.execute(
                            "SELECT sheet_name, COALESCE(table_name, '') FROM __sheet_info ORDER BY rowid"
                        ).fetchall()
                    except Exception:
                        info_rows = []
                    for sheet_name, table_name in info_rows:
                        run_name = str(sheet_name or "").strip()
                        run_key = _td_support_norm_name(run_name)
                        table = str(table_name or "").strip()
                        if run_key and table:
                            table_name_by_run[run_key] = table
                for run_name in runs:
                    clean_run = str(run_name or "").strip()
                    if not clean_run:
                        continue
                    row = _td_support_program_row_defaults(clean_run, program_title=program_title)
                    row = _td_prefill_support_row_from_sequence_context(
                        row,
                        sequence_context.get(_td_support_norm_name(clean_run)),
                        blank_unusable_defaults=False,
                    )
                    rows_by_program.setdefault(program_title, []).append(row)
                    table_name = table_name_by_run.get(_td_support_norm_name(clean_run)) or f"sheet__{clean_run}"
                    catalog = _td_program_requirements_discover_run_parameters(
                        conn,
                        clean_run,
                        table_name,
                        param_defs=param_defs,
                    )
                    if catalog:
                        run_key = _td_support_norm_name(clean_run)
                        merged = _td_program_requirements_merge_catalogs(
                            (parameters_by_program_run.get(program_title) or {}).get(run_key),
                            catalog,
                        )
                        parameters_by_program_run.setdefault(program_title, {})[run_key] = merged
        except Exception:
            continue

    out: dict[str, list[dict[str, object]]] = {}
    for program_title, rows in rows_by_program.items():
        conditions = _td_group_program_rows_into_conditions(rows)
        program_run_catalog = parameters_by_program_run.get(program_title) or {}
        normalized_conditions: list[dict[str, object]] = []
        for condition in conditions:
            member_sequences = [
                str(value).strip()
                for value in (condition.get("member_sequences") or [])
                if str(value).strip()
            ]
            member_catalog: list[dict[str, str]] = []
            for member_sequence in member_sequences:
                member_catalog = _td_program_requirements_merge_catalogs(
                    member_catalog,
                    program_run_catalog.get(_td_support_norm_name(member_sequence)),
                )
            normalized_conditions.append(
                {
                    "program_title": program_title,
                    "condition_key": str(condition.get("condition_key") or "").strip(),
                    "display_name": str(condition.get("display_name") or condition.get("condition_key") or "").strip(),
                    "run_type": str(condition.get("run_type") or "").strip(),
                    "pulse_width_on": condition.get("pulse_width_on", condition.get("pulse_width")),
                    "control_period": condition.get("control_period"),
                    "suppression_voltage": condition.get("suppression_voltage"),
                    "valve_voltage": condition.get("valve_voltage"),
                    "member_sequences": member_sequences,
                    "member_sequences_text": "; ".join(member_sequences),
                    "parameter_catalog": member_catalog,
                    "last_refreshed": refreshed_at,
                }
            )
        out[program_title] = normalized_conditions
    return out


def _td_program_requirements_discover_parameter_mappings_by_program(
    global_repo: Path | None,
    docs: Sequence[Mapping[str, object]] | None,
    *,
    param_defs: Sequence[Mapping[str, object]] | None,
) -> dict[str, list[dict[str, object]]]:
    repo = Path(global_repo).expanduser() if global_repo is not None else None
    config_candidates = _td_parameter_config_candidates_from_defs(param_defs)
    rows_by_program: dict[str, dict[tuple[str, str, str, str], dict[str, object]]] = {}
    for doc in docs or []:
        if repo is None or not isinstance(doc, Mapping):
            continue
        program_title = str(doc.get("program_title") or "").strip() or TD_SUPPORT_DEFAULT_PROGRAM_TITLE
        asset_type = _td_program_parameter_scope_text(doc.get("asset_type"))
        asset_specific_type = _td_program_parameter_scope_text(doc.get("asset_specific_type"))
        resolved = _resolve_td_source_sqlite_for_node(
            repo,
            excel_sqlite_rel=str(doc.get("excel_sqlite_rel") or "").strip(),
            artifacts_rel=str(doc.get("artifacts_rel") or "").strip(),
        )
        sqlite_path = resolved.get("path")
        if not sqlite_path:
            continue
        path = Path(sqlite_path).expanduser()
        if not path.exists() or not path.is_file():
            continue
        try:
            with sqlite3.connect(str(path)) as conn:
                try:
                    runs = [str(row[0] or "").strip() for row in _ordered_td_sheet_info_rows(conn) if str(row[0] or "").strip()]
                except Exception:
                    rows = conn.execute(
                        "SELECT name FROM sqlite_master WHERE type='table' AND name LIKE 'sheet__%' ORDER BY name"
                    ).fetchall()
                    runs = [str(row[0] or "")[7:] for row in rows if str(row[0] or "").startswith("sheet__")]
                table_name_by_run: dict[str, str] = {}
                if _td_table_exists(conn, "__sheet_info"):
                    try:
                        info_rows = conn.execute(
                            "SELECT sheet_name, COALESCE(table_name, '') FROM __sheet_info ORDER BY rowid"
                        ).fetchall()
                    except Exception:
                        info_rows = []
                    for sheet_name, table_name in info_rows:
                        run_name = str(sheet_name or "").strip()
                        run_key = _td_support_norm_name(run_name)
                        table = str(table_name or "").strip()
                        if run_key and table:
                            table_name_by_run[run_key] = table
                for run_name in runs:
                    clean_run = str(run_name or "").strip()
                    if not clean_run:
                        continue
                    table_name = table_name_by_run.get(_td_support_norm_name(clean_run)) or f"sheet__{clean_run}"
                    specs = _td_source_sqlite_column_specs(
                        conn,
                        sheet_name=clean_run,
                        table_name=table_name,
                        param_defs=param_defs,
                    )
                    for spec in specs:
                        if not bool(spec.get("is_parameter")):
                            continue
                        normalized = _td_program_parameter_mapping_normalize(
                            {
                                "program_title": program_title,
                                "asset_type": asset_type,
                                "asset_specific_type": asset_specific_type,
                                "ingested_parameter": str(spec.get("header") or "").strip(),
                                "default_display_parameter": str(
                                    spec.get("default_display_parameter")
                                    or spec.get("mapped_header")
                                    or spec.get("header")
                                    or ""
                                ).strip(),
                                "displayed_parameter": str(
                                    spec.get("default_display_parameter")
                                    or spec.get("mapped_header")
                                    or spec.get("header")
                                    or ""
                                ).strip(),
                                "preferred_units": str(spec.get("preferred_units") or "").strip(),
                                "edited": False,
                                "updated_at": "",
                            },
                            program_title=program_title,
                        )
                        if not normalized:
                            continue
                        scope_key = _td_program_parameter_scope_key(
                            normalized.get("program_title"),
                            normalized.get("asset_type"),
                            normalized.get("asset_specific_type"),
                            normalized.get("ingested_parameter"),
                        )
                        bucket = rows_by_program.setdefault(program_title, {})
                        existing = dict(bucket.get(scope_key) or {})
                        if existing:
                            if not str(existing.get("preferred_units") or "").strip():
                                existing["preferred_units"] = str(normalized.get("preferred_units") or "").strip()
                            existing_default = str(existing.get("default_display_parameter") or "").strip()
                            normalized_default = str(normalized.get("default_display_parameter") or "").strip()
                            if (not existing_default or existing_default == str(existing.get("ingested_parameter") or "").strip()) and normalized_default:
                                existing["default_display_parameter"] = normalized_default
                                existing["displayed_parameter"] = normalized_default
                            bucket[scope_key] = existing
                            continue
                        bucket[scope_key] = normalized
        except Exception:
            continue
    return {
        program_title: _td_autonormalize_parameter_mapping_rows(
            list(program_rows.values()),
            config_candidates=config_candidates,
        )
        for program_title, program_rows in rows_by_program.items()
    }


def _td_program_requirements_header_map(ws, *, row_idx: int) -> dict[str, int]:
    return {
        str(ws.cell(row_idx, col).value or "").strip().lower(): col
        for col in range(1, (ws.max_column or 0) + 1)
        if str(ws.cell(row_idx, col).value or "").strip()
    }


def _td_program_requirements_parse_condition_sheet(ws, *, fallback: Mapping[str, object] | None = None) -> dict[str, object]:
    fallback = dict(fallback or {})
    metadata: dict[str, object] = {}
    for row_idx in range(1, TD_PROGRAM_REQUIREMENTS_TABLE_HEADER_ROW):
        key = str(ws.cell(row_idx, 1).value or "").strip()
        if key:
            metadata[key] = ws.cell(row_idx, 2).value
    for key in TD_PROGRAM_REQUIREMENTS_METADATA_KEYS:
        if key not in metadata and key in fallback:
            metadata[key] = fallback.get(key)
    condition_key = str(metadata.get("condition_key") or fallback.get("condition_key") or ws.title).strip()
    display_name = str(metadata.get("display_name") or fallback.get("display_name") or condition_key or ws.title).strip()
    headers = _td_program_requirements_header_map(ws, row_idx=TD_PROGRAM_REQUIREMENTS_TABLE_HEADER_ROW)
    requirements: list[dict[str, object]] = []
    for row_idx in range(TD_PROGRAM_REQUIREMENTS_TABLE_FIRST_DATA_ROW, (ws.max_row or 0) + 1):
        row_data = {
            "enabled": ws.cell(row_idx, headers.get("enabled", 1)).value if headers else None,
            "parameter_name": ws.cell(row_idx, headers.get("parameter_name", 2)).value if headers else None,
            "units": ws.cell(row_idx, headers.get("units", 3)).value if headers else None,
            "min_value": ws.cell(row_idx, headers.get("min_value", 4)).value if headers else None,
            "max_value": ws.cell(row_idx, headers.get("max_value", 5)).value if headers else None,
        }
        if not any(value not in (None, "") for value in row_data.values()):
            continue
        requirements.append(
            {
                "enabled": _td_program_requirements_parse_bool(row_data.get("enabled"), default=True),
                "parameter_name": str(row_data.get("parameter_name") or "").strip(),
                "units": str(row_data.get("units") or "").strip(),
                "min_value": row_data.get("min_value"),
                "max_value": row_data.get("max_value"),
            }
        )
    member_sequences = _td_program_requirements_split_member_sequences(
        metadata.get("member_sequences") or fallback.get("member_sequences")
    )
    return {
        "program_title": str(metadata.get("program_title") or fallback.get("program_title") or "").strip(),
        "condition_key": condition_key,
        "display_name": display_name or condition_key,
        "sheet_name": str(fallback.get("sheet_name") or ws.title).strip() or ws.title,
        "run_type": str(metadata.get("run_type") or fallback.get("run_type") or "").strip(),
        "pulse_width_on": metadata.get("pulse_width_on", fallback.get("pulse_width_on")),
        "control_period": metadata.get("control_period", fallback.get("control_period")),
        "suppression_voltage": metadata.get("suppression_voltage", fallback.get("suppression_voltage")),
        "valve_voltage": metadata.get("valve_voltage", fallback.get("valve_voltage")),
        "member_sequences": member_sequences,
        "member_sequences_text": "; ".join(member_sequences),
        "last_refreshed": str(fallback.get("last_refreshed") or "").strip(),
        "requirements": requirements,
        "parameter_catalog": _td_program_requirements_existing_catalog(requirements),
    }


def _td_program_requirements_parse_parameter_map_sheet(ws, *, program_title: object = "") -> list[dict[str, object]]:
    headers = _td_program_requirements_header_map(ws, row_idx=1)
    rows: list[dict[str, object]] = []
    for row_idx in range(2, (ws.max_row or 0) + 1):
        raw = {
            header: ws.cell(row_idx, col).value
            for header, col in headers.items()
        }
        if not any(value not in (None, "") for value in raw.values()):
            continue
        normalized = _td_program_parameter_mapping_normalize(raw, program_title=program_title)
        if normalized:
            rows.append(normalized)
    return rows


def _td_program_requirements_write_parameter_map_sheet(
    ws,
    *,
    program_title: object,
    rows: Sequence[Mapping[str, object]] | None,
) -> None:
    try:
        ws.delete_rows(1, ws.max_row or 1)
    except Exception:
        parent = ws.parent
        title = ws.title
        try:
            parent.remove(ws)
        except Exception:
            pass
        ws = parent.create_sheet(title)
    ws.append(list(TD_PROGRAM_PARAMETER_MAP_HEADERS))
    for row in sorted(rows or [], key=_td_program_parameter_mapping_sort_key):
        normalized = _td_program_parameter_mapping_normalize(row, program_title=program_title)
        if not normalized:
            continue
        ws.append(
            [
                str(normalized.get("program_title") or program_title or "").strip(),
                str(normalized.get("asset_type") or "").strip(),
                str(normalized.get("asset_specific_type") or "").strip(),
                str(normalized.get("ingested_parameter") or "").strip(),
                str(normalized.get("default_display_parameter") or "").strip(),
                str(normalized.get("displayed_parameter") or "").strip(),
                str(normalized.get("preferred_units") or "").strip(),
                bool(normalized.get("enabled", True)),
                bool(normalized.get("edited")),
                str(normalized.get("updated_at") or "").strip(),
            ]
        )
    try:
        ws.freeze_panes = "A2"
    except Exception:
        pass


def _td_program_requirements_parse_workbook(wb) -> dict[str, object]:
    reserved = {
        TD_PROGRAM_REQUIREMENTS_INDEX_SHEET.lower(),
        TD_PROGRAM_REQUIREMENTS_VALIDATION_SHEET.lower(),
        TD_PROGRAM_PARAMETER_MAP_SHEET.lower(),
    }
    index_rows: list[dict[str, object]] = []
    parameter_mappings: list[dict[str, object]] = []
    if TD_PROGRAM_REQUIREMENTS_INDEX_SHEET in wb.sheetnames:
        ws_index = wb[TD_PROGRAM_REQUIREMENTS_INDEX_SHEET]
        headers = _td_program_requirements_header_map(ws_index, row_idx=1)
        for row_idx in range(2, (ws_index.max_row or 0) + 1):
            row = {
                header: ws_index.cell(row_idx, col).value
                for header, col in headers.items()
            }
            if not any(value not in (None, "") for value in row.values()):
                continue
            index_rows.append({str(key): value for key, value in row.items()})
    if TD_PROGRAM_PARAMETER_MAP_SHEET in wb.sheetnames:
        parameter_mappings = _td_program_requirements_parse_parameter_map_sheet(
            wb[TD_PROGRAM_PARAMETER_MAP_SHEET],
        )
    ordered_conditions: list[dict[str, object]] = []
    parsed_sheets: set[str] = set()
    for row in index_rows:
        sheet_name = str(row.get("sheet_name") or "").strip()
        if not sheet_name or sheet_name not in wb.sheetnames:
            continue
        condition = _td_program_requirements_parse_condition_sheet(
            wb[sheet_name],
            fallback=row,
        )
        ordered_conditions.append(condition)
        parsed_sheets.add(sheet_name.lower())
    for sheet_name in wb.sheetnames:
        if sheet_name.lower() in reserved or sheet_name.lower() in parsed_sheets:
            continue
        ws = wb[sheet_name]
        headers = _td_program_requirements_header_map(ws, row_idx=TD_PROGRAM_REQUIREMENTS_TABLE_HEADER_ROW)
        if "parameter_name" not in headers:
            continue
        condition = _td_program_requirements_parse_condition_sheet(
            ws,
            fallback={"sheet_name": sheet_name},
        )
        ordered_conditions.append(condition)
    return {
        "conditions": ordered_conditions,
        "parameter_mappings": parameter_mappings,
    }


def _td_program_requirements_apply_units(
    requirements: Sequence[Mapping[str, object]] | None,
    catalog: Sequence[Mapping[str, object]] | None,
) -> list[dict[str, object]]:
    catalog_map = {
        _td_support_norm_name(item.get("name")): str(item.get("units") or "").strip()
        for item in (catalog or [])
        if isinstance(item, Mapping) and str(item.get("name") or "").strip()
    }
    out: list[dict[str, object]] = []
    for row in requirements or []:
        if not isinstance(row, Mapping):
            continue
        parameter_name = str(row.get("parameter_name") or "").strip()
        units = str(row.get("units") or "").strip()
        if parameter_name and not units:
            units = str(catalog_map.get(_td_support_norm_name(parameter_name)) or "").strip()
        out.append(
            {
                "enabled": _td_program_requirements_parse_bool(row.get("enabled"), default=True),
                "parameter_name": parameter_name,
                "units": units,
                "min_value": row.get("min_value"),
                "max_value": row.get("max_value"),
            }
        )
    return out


def _td_program_requirements_write_condition_sheet(ws, condition: Mapping[str, object], *, validation_formula: str = "") -> None:
    try:
        ws.delete_rows(1, ws.max_row or 1)
    except Exception:
        parent = ws.parent
        title = ws.title
        try:
            parent.remove(ws)
        except Exception:
            pass
        ws = parent.create_sheet(title)
    for row_idx, key in enumerate(TD_PROGRAM_REQUIREMENTS_METADATA_KEYS, start=1):
        ws.cell(row_idx, 1).value = key
        value = condition.get(key)
        if key == "member_sequences":
            value = condition.get("member_sequences_text") or _td_program_requirements_member_sequences_text(value)
        ws.cell(row_idx, 2).value = value
    for col_idx, header in enumerate(TD_PROGRAM_REQUIREMENTS_SOURCE_HEADERS, start=1):
        ws.cell(TD_PROGRAM_REQUIREMENTS_TABLE_HEADER_ROW, col_idx).value = header
    requirements = _td_program_requirements_apply_units(
        condition.get("requirements"),
        condition.get("parameter_catalog"),
    )
    if not requirements:
        requirements = [
            {
                "enabled": True,
                "parameter_name": "",
                "units": "",
                "min_value": None,
                "max_value": None,
            }
        ]
    for row_idx, row in enumerate(requirements, start=TD_PROGRAM_REQUIREMENTS_TABLE_FIRST_DATA_ROW):
        ws.cell(row_idx, 1).value = row.get("enabled")
        ws.cell(row_idx, 2).value = row.get("parameter_name")
        ws.cell(row_idx, 3).value = row.get("units")
        ws.cell(row_idx, 4).value = row.get("min_value")
        ws.cell(row_idx, 5).value = row.get("max_value")
    try:
        ws.freeze_panes = f"A{TD_PROGRAM_REQUIREMENTS_TABLE_FIRST_DATA_ROW}"
    except Exception:
        pass
    if validation_formula:
        try:
            ws.data_validations.dataValidation = []
        except Exception:
            pass
        _apply_list_validation(
            ws,
            formula_range=validation_formula,
            sqref=f"B{TD_PROGRAM_REQUIREMENTS_TABLE_FIRST_DATA_ROW}:B{TD_PROGRAM_REQUIREMENTS_VALIDATION_LAST_ROW}",
            title="ProgramRequirements",
        )


def _td_program_requirements_write_workbook(
    workbook_path: Path,
    *,
    program_title: str,
    discovered_conditions: Sequence[Mapping[str, object]] | None,
    discovered_parameter_mappings: Sequence[Mapping[str, object]] | None = None,
    parameter_mappings: Sequence[Mapping[str, object]] | None = None,
) -> dict[str, object]:
    try:
        from openpyxl import Workbook  # type: ignore
    except Exception as exc:
        raise RuntimeError(
            "openpyxl is required to update ProgramRequirements workbooks. "
            "Install it with `py -m pip install openpyxl` within the project environment."
        ) from exc

    wb_path = Path(workbook_path).expanduser()
    wb_path.parent.mkdir(parents=True, exist_ok=True)
    created = False
    if wb_path.exists():
        wb = _td_load_workbook_ignore_long_title_warning(str(wb_path))
    else:
        wb = Workbook()
        created = True
    try:
        existing_state = _td_program_requirements_parse_workbook(wb)
        existing_conditions = [
            dict(item)
            for item in (existing_state.get("conditions") or [])
            if isinstance(item, Mapping)
        ]
        existing_parameter_mappings = [
            dict(item)
            for item in (existing_state.get("parameter_mappings") or [])
            if isinstance(item, Mapping)
        ]
        existing_by_key = {
            _td_program_requirements_condition_identity(item.get("condition_key"), fallback=item.get("sheet_name")): dict(item)
            for item in existing_conditions
        }
        discovered = [
            dict(item)
            for item in (discovered_conditions or [])
            if isinstance(item, Mapping) and str(item.get("condition_key") or "").strip()
        ]
        ordered_conditions: list[dict[str, object]] = []
        seen: set[str] = set()
        refreshed_at = datetime.now().isoformat(timespec="seconds")
        for item in discovered:
            key = _td_program_requirements_condition_identity(item.get("condition_key"), fallback=item.get("display_name"))
            existing = dict(existing_by_key.get(key) or {})
            merged_catalog = _td_program_requirements_merge_catalogs(
                existing.get("parameter_catalog"),
                _td_program_requirements_existing_catalog(existing.get("requirements")),
                item.get("parameter_catalog"),
            )
            merged = {
                **existing,
                **item,
                "program_title": program_title,
                "member_sequences": list(item.get("member_sequences") or []),
                "member_sequences_text": _td_program_requirements_member_sequences_text(item.get("member_sequences_text") or item.get("member_sequences")),
                "parameter_catalog": merged_catalog,
                "requirements": _td_program_requirements_apply_units(existing.get("requirements"), merged_catalog),
                "last_refreshed": refreshed_at,
            }
            ordered_conditions.append(merged)
            seen.add(key)
        for item in existing_conditions:
            key = _td_program_requirements_condition_identity(item.get("condition_key"), fallback=item.get("sheet_name"))
            if key in seen:
                continue
            carry = dict(item)
            carry["program_title"] = str(carry.get("program_title") or program_title).strip() or program_title
            carry["member_sequences"] = list(carry.get("member_sequences") or [])
            carry["member_sequences_text"] = _td_program_requirements_member_sequences_text(
                carry.get("member_sequences_text") or carry.get("member_sequences")
            )
            carry["parameter_catalog"] = _td_program_requirements_merge_catalogs(
                carry.get("parameter_catalog"),
                _td_program_requirements_existing_catalog(carry.get("requirements")),
            )
            carry["requirements"] = _td_program_requirements_apply_units(
                carry.get("requirements"),
                carry.get("parameter_catalog"),
            )
            ordered_conditions.append(carry)

        preserved_sheet_names = {
            str(item.get("sheet_name") or "").strip().lower()
            for item in existing_conditions
            if str(item.get("sheet_name") or "").strip()
        }
        used_sheet_names = {
            TD_PROGRAM_REQUIREMENTS_INDEX_SHEET.lower(),
            TD_PROGRAM_REQUIREMENTS_VALIDATION_SHEET.lower(),
        }
        used_sheet_names.update(
            str(sheet_name).strip().lower()
            for sheet_name in wb.sheetnames
            if str(sheet_name).strip().lower() not in preserved_sheet_names
        )
        for condition in ordered_conditions:
            existing_sheet_name = str(condition.get("sheet_name") or "").strip()
            if existing_sheet_name and existing_sheet_name.lower() in preserved_sheet_names and existing_sheet_name.lower() not in used_sheet_names:
                condition["sheet_name"] = existing_sheet_name
                used_sheet_names.add(existing_sheet_name.lower())
                continue
            preferred = str(condition.get("display_name") or condition.get("condition_key") or "").strip()
            condition["sheet_name"] = _td_safe_excel_sheet_title(preferred, used_sheet_names, fallback="Condition")

        ws_index = _td_reset_workbook_sheet(
            wb,
            TD_PROGRAM_REQUIREMENTS_INDEX_SHEET,
            list(TD_PROGRAM_REQUIREMENTS_INDEX_HEADERS),
        )
        for condition in ordered_conditions:
            ws_index.append(
                [
                    str(condition.get("program_title") or program_title).strip() or program_title,
                    str(condition.get("condition_key") or "").strip(),
                    str(condition.get("display_name") or condition.get("condition_key") or "").strip(),
                    str(condition.get("sheet_name") or "").strip(),
                    str(condition.get("run_type") or "").strip(),
                    condition.get("pulse_width_on"),
                    condition.get("control_period"),
                    condition.get("suppression_voltage"),
                    condition.get("valve_voltage"),
                    str(condition.get("member_sequences_text") or "").strip(),
                    str(condition.get("last_refreshed") or refreshed_at).strip(),
                ]
            )

        ws_validation = _ensure_validation_sheet(wb, sheet_name=TD_PROGRAM_REQUIREMENTS_VALIDATION_SHEET)
        validation_ranges: dict[str, str] = {}
        try:
            from openpyxl.utils import get_column_letter  # type: ignore
        except Exception:
            get_column_letter = None  # type: ignore[assignment]
        for col_idx, condition in enumerate(ordered_conditions, start=1):
            ws_validation.cell(1, col_idx).value = str(condition.get("condition_key") or condition.get("sheet_name") or "")
            catalog = _td_program_requirements_merge_catalogs(
                condition.get("parameter_catalog"),
                _td_program_requirements_existing_catalog(condition.get("requirements")),
            )
            for row_idx, item in enumerate(catalog, start=2):
                ws_validation.cell(row_idx, col_idx).value = str(item.get("name") or "").strip()
            if catalog and get_column_letter is not None:
                col_letter = get_column_letter(col_idx)
                validation_ranges[
                    _td_program_requirements_condition_identity(
                        condition.get("condition_key"),
                        fallback=condition.get("sheet_name"),
                    )
                ] = f"='{ws_validation.title}'!${col_letter}$2:${col_letter}${len(catalog) + 1}"

        for condition in ordered_conditions:
            sheet_name = str(condition.get("sheet_name") or "").strip()
            ws_condition = wb[sheet_name] if sheet_name in wb.sheetnames else wb.create_sheet(sheet_name)
            validation_formula = validation_ranges.get(
                _td_program_requirements_condition_identity(
                    condition.get("condition_key"),
                    fallback=sheet_name,
                ),
                "",
            )
            _td_program_requirements_write_condition_sheet(
                ws_condition,
                condition,
                validation_formula=validation_formula,
            )

        final_parameter_mappings = (
            [
                _td_program_parameter_mapping_normalize(item, program_title=program_title)
                for item in (parameter_mappings or [])
                if _td_program_parameter_mapping_normalize(item, program_title=program_title)
            ]
            if parameter_mappings is not None
            else _td_program_parameter_merge_rows(
                existing_parameter_mappings,
                discovered_parameter_mappings,
                program_title=program_title,
            )
        )
        ws_parameter_map = (
            wb[TD_PROGRAM_PARAMETER_MAP_SHEET]
            if TD_PROGRAM_PARAMETER_MAP_SHEET in wb.sheetnames
            else wb.create_sheet(TD_PROGRAM_PARAMETER_MAP_SHEET)
        )
        _td_program_requirements_write_parameter_map_sheet(
            ws_parameter_map,
            program_title=program_title,
            rows=final_parameter_mappings,
        )

        if (
            "Sheet" in wb.sheetnames
            and "Sheet" not in {TD_PROGRAM_REQUIREMENTS_INDEX_SHEET, TD_PROGRAM_REQUIREMENTS_VALIDATION_SHEET}
            and "sheet" not in {
                str(condition.get("sheet_name") or "").strip().lower()
                for condition in ordered_conditions
            }
        ):
            try:
                wb.remove(wb["Sheet"])
            except Exception:
                pass

        try:
            target_index = 1 if TD_PROGRAM_REQUIREMENTS_INDEX_SHEET in wb.sheetnames else 0
            current_index = list(wb.sheetnames).index(TD_PROGRAM_PARAMETER_MAP_SHEET)
            if current_index != target_index:
                wb.move_sheet(ws_parameter_map, offset=(target_index - current_index))
        except Exception:
            pass

        wb.save(str(wb_path))
    finally:
        try:
            wb.close()
        except Exception:
            pass
    return {
        "program_title": program_title,
        "path": str(wb_path),
        "created": bool(created),
        "updated": True,
        "condition_count": int(len(discovered_conditions or [])),
        "parameter_mapping_count": int(len(parameter_mappings or discovered_parameter_mappings or [])),
    }


def _sync_td_program_requirements_workbooks_for_docs(
    global_repo: Path | None,
    docs: Sequence[Mapping[str, object]] | None,
    *,
    param_defs: Sequence[Mapping[str, object]] | None,
    create_missing: bool,
) -> dict[str, object]:
    repo = Path(global_repo).expanduser() if global_repo is not None else None
    discovered = _td_program_requirements_discover_conditions_by_program(
        repo,
        docs,
        param_defs=param_defs,
    )
    discovered_parameter_mappings = _td_program_requirements_discover_parameter_mappings_by_program(
        repo,
        docs,
        param_defs=param_defs,
    )
    summaries: list[dict[str, object]] = []
    warnings: list[str] = []
    program_titles = sorted({*discovered.keys(), *discovered_parameter_mappings.keys()}, key=lambda value: value.casefold())
    for program_title in program_titles:
        workbook_path = td_program_requirements_workbook_path_for(repo, program_title)
        if not create_missing and not workbook_path.exists():
            summaries.append(
                {
                    "program_title": program_title,
                    "path": str(workbook_path),
                    "created": False,
                    "updated": False,
                    "skipped_missing": True,
                    "condition_count": int(len(discovered.get(program_title) or [])),
                    "parameter_mapping_count": int(len(discovered_parameter_mappings.get(program_title) or [])),
                }
            )
            continue
        try:
            payload = _td_program_requirements_write_workbook(
                workbook_path,
                program_title=program_title,
                discovered_conditions=discovered.get(program_title) or [],
                discovered_parameter_mappings=discovered_parameter_mappings.get(program_title) or [],
            )
            payload["skipped_missing"] = False
            summaries.append(payload)
        except PermissionError:
            message = f"ProgramRequirements workbook is not writable (close it in Excel first): {workbook_path}"
            warnings.append(message)
            summaries.append(
                {
                    "program_title": program_title,
                    "path": str(workbook_path),
                    "created": False,
                    "updated": False,
                    "skipped_missing": False,
                    "condition_count": int(len(discovered.get(program_title) or [])),
                    "parameter_mapping_count": int(len(discovered_parameter_mappings.get(program_title) or [])),
                    "warning": message,
                }
            )
        except Exception as exc:
            message = f"Failed to refresh ProgramRequirements workbook for '{program_title}': {exc}"
            warnings.append(message)
            summaries.append(
                {
                    "program_title": program_title,
                    "path": str(workbook_path),
                    "created": False,
                    "updated": False,
                    "skipped_missing": False,
                    "condition_count": int(len(discovered.get(program_title) or [])),
                    "parameter_mapping_count": int(len(discovered_parameter_mappings.get(program_title) or [])),
                    "warning": message,
                }
            )
    return {
        "workbooks": summaries,
        "warnings": warnings,
        "created_count": int(sum(1 for item in summaries if bool(item.get("created")))),
        "updated_count": int(sum(1 for item in summaries if bool(item.get("updated")))),
        "skipped_missing_count": int(sum(1 for item in summaries if bool(item.get("skipped_missing")))),
    }


def _td_program_requirements_read_source_workbook(path: Path) -> list[dict[str, object]]:
    try:
        from openpyxl import load_workbook  # type: ignore
    except Exception as exc:
        raise RuntimeError(
            "openpyxl is required to read ProgramRequirements workbooks. "
            "Install it with `py -m pip install openpyxl` within the project environment."
        ) from exc
    workbook_path = Path(path).expanduser()
    wb = load_workbook(str(workbook_path), read_only=True, data_only=True)
    try:
        state = _td_program_requirements_parse_workbook(wb)
    finally:
        try:
            wb.close()
        except Exception:
            pass
    imported: list[dict[str, object]] = []
    for condition in (state.get("conditions") or []):
        if not isinstance(condition, Mapping):
            continue
        catalog = _td_program_requirements_merge_catalogs(
            condition.get("parameter_catalog"),
            _td_program_requirements_existing_catalog(condition.get("requirements")),
        )
        requirements = _td_program_requirements_apply_units(condition.get("requirements"), catalog)
        requirements = [row for row in requirements if str(row.get("parameter_name") or "").strip()]
        if not requirements:
            continue
        member_sequences = [
            str(value).strip()
            for value in (condition.get("member_sequences") or [])
            if str(value).strip()
        ]
        imported.append(
            {
                "program_title": str(condition.get("program_title") or "").strip(),
                "condition_key": str(condition.get("condition_key") or "").strip(),
                "display_name": str(condition.get("display_name") or condition.get("condition_key") or "").strip(),
                "sheet_name": str(condition.get("sheet_name") or "").strip(),
                "run_type": str(condition.get("run_type") or "").strip(),
                "pulse_width_on": condition.get("pulse_width_on"),
                "control_period": condition.get("control_period"),
                "suppression_voltage": condition.get("suppression_voltage"),
                "valve_voltage": condition.get("valve_voltage"),
                "member_sequences": member_sequences,
                "member_sequences_text": "; ".join(member_sequences),
                "source_workbook": str(workbook_path),
                "source_sheet_name": str(condition.get("sheet_name") or "").strip(),
                "requirements": requirements,
            }
        )
    return imported


def _td_program_requirements_read_parameter_mappings(path: Path) -> list[dict[str, object]]:
    try:
        from openpyxl import load_workbook  # type: ignore
    except Exception as exc:
        raise RuntimeError(
            "openpyxl is required to read ProgramRequirements workbooks. "
            "Install it with `py -m pip install openpyxl` within the project environment."
        ) from exc
    workbook_path = Path(path).expanduser()
    wb = load_workbook(str(workbook_path), read_only=True, data_only=True)
    try:
        state = _td_program_requirements_parse_workbook(wb)
    finally:
        try:
            wb.close()
        except Exception:
            pass
    return [
        _td_program_parameter_mapping_normalize(row)
        for row in (state.get("parameter_mappings") or [])
        if _td_program_parameter_mapping_normalize(row)
    ]


def _td_program_requirements_read_support_state(wb) -> dict[str, list[dict[str, object]]]:
    out: dict[str, list[dict[str, object]]] = {}
    if TD_PROGRAM_REQUIREMENTS_SUPPORT_INDEX_SHEET not in wb.sheetnames:
        return out
    ws_index = wb[TD_PROGRAM_REQUIREMENTS_SUPPORT_INDEX_SHEET]
    headers = _td_program_requirements_header_map(ws_index, row_idx=1)
    for row_idx in range(2, (ws_index.max_row or 0) + 1):
        row = {
            header: ws_index.cell(row_idx, col).value
            for header, col in headers.items()
        }
        if not any(value not in (None, "") for value in row.values()):
            continue
        program_title = str(row.get("program_title") or "").strip()
        sheet_name = str(row.get("sheet_name") or "").strip()
        if not program_title or not sheet_name or sheet_name not in wb.sheetnames:
            continue
        ws = wb[sheet_name]
        tab_headers = _td_program_requirements_header_map(ws, row_idx=1)
        requirements: list[dict[str, object]] = []
        for tab_row_idx in range(2, (ws.max_row or 0) + 1):
            parameter_name = str(ws.cell(tab_row_idx, tab_headers.get("parameter_name", 2)).value or "").strip()
            if not parameter_name:
                continue
            requirements.append(
                {
                    "enabled": _td_program_requirements_parse_bool(
                        ws.cell(tab_row_idx, tab_headers.get("enabled", 1)).value,
                        default=True,
                    ),
                    "parameter_name": parameter_name,
                    "units": str(ws.cell(tab_row_idx, tab_headers.get("units", 3)).value or "").strip(),
                    "min_value": ws.cell(tab_row_idx, tab_headers.get("min_value", 4)).value,
                    "max_value": ws.cell(tab_row_idx, tab_headers.get("max_value", 5)).value,
                }
            )
        out.setdefault(program_title, []).append(
            {
                "program_title": program_title,
                "condition_key": str(row.get("condition_key") or "").strip(),
                "display_name": str(row.get("display_name") or row.get("condition_key") or "").strip(),
                "sheet_name": sheet_name,
                "run_type": str(row.get("run_type") or "").strip(),
                "pulse_width_on": row.get("pulse_width_on"),
                "control_period": row.get("control_period"),
                "suppression_voltage": row.get("suppression_voltage"),
                "valve_voltage": row.get("valve_voltage"),
                "member_sequences_text": str(row.get("member_sequences") or "").strip(),
                "source_workbook": str(row.get("source_workbook") or "").strip(),
                "source_sheet_name": str(row.get("source_sheet_name") or "").strip(),
                "requirements": requirements,
            }
        )
    return out


def _sync_td_support_program_requirements_import(
    workbook_path: Path,
    *,
    global_repo: Path | None,
    project_dir: Path | None = None,
    docs: Sequence[Mapping[str, object]] | None,
) -> dict[str, object]:
    support_path = td_support_workbook_path_for(workbook_path, project_dir=project_dir)
    if not support_path.exists():
        return {"path": str(support_path), "updated": False, "warnings": ["TD support workbook not found."]}
    try:
        from openpyxl import load_workbook  # type: ignore
    except Exception as exc:
        raise RuntimeError(
            "openpyxl is required to import ProgramRequirements into the TD support workbook. "
            "Install it with `py -m pip install openpyxl` within the project environment."
        ) from exc

    repo = Path(global_repo).expanduser() if global_repo is not None else None
    warnings: list[str] = []
    selected_programs: list[str] = []
    seen_programs: set[str] = set()
    for doc in docs or []:
        if not isinstance(doc, Mapping):
            continue
        program_title = str(doc.get("program_title") or "").strip() or TD_SUPPORT_DEFAULT_PROGRAM_TITLE
        key = _td_support_norm_name(program_title)
        if key in seen_programs:
            continue
        seen_programs.add(key)
        selected_programs.append(program_title)

    wb = load_workbook(str(support_path))
    try:
        existing_by_program = _td_program_requirements_read_support_state(wb)
        found_programs: set[str] = set()
        for program_title in selected_programs:
            workbook_file = td_program_requirements_workbook_path_for(repo, program_title)
            if not workbook_file.exists():
                continue
            try:
                imported_conditions = _td_program_requirements_read_source_workbook(workbook_file)
                existing_by_program[program_title] = imported_conditions
                found_programs.add(program_title)
            except Exception as exc:
                warnings.append(f"Failed to import ProgramRequirements workbook for '{program_title}': {exc}")

        for sheet_name in list(wb.sheetnames):
            if sheet_name == TD_PROGRAM_REQUIREMENTS_SUPPORT_INDEX_SHEET:
                wb.remove(wb[sheet_name])
                continue
            if str(sheet_name).startswith(TD_PROGRAM_REQUIREMENTS_SUPPORT_SHEET_PREFIX):
                wb.remove(wb[sheet_name])

        combined_conditions: list[dict[str, object]] = []
        for program_title in sorted(existing_by_program.keys(), key=lambda value: value.casefold()):
            for condition in existing_by_program.get(program_title) or []:
                if not isinstance(condition, Mapping):
                    continue
                requirements = [
                    dict(row)
                    for row in (condition.get("requirements") or [])
                    if isinstance(row, Mapping) and str(row.get("parameter_name") or "").strip()
                ]
                if not requirements:
                    continue
                combined_conditions.append(
                    {
                        **dict(condition),
                        "program_title": str(condition.get("program_title") or program_title).strip() or program_title,
                        "requirements": requirements,
                    }
                )

        if not combined_conditions:
            wb.save(str(support_path))
            return {
                "path": str(support_path),
                "updated": bool(found_programs),
                "condition_count": 0,
                "requirements_count": 0,
                "warnings": warnings,
            }

        used_sheet_names = {
            str(sheet_name).strip().lower()
            for sheet_name in wb.sheetnames
            if str(sheet_name).strip()
        }
        ws_index = _td_reset_workbook_sheet(
            wb,
            TD_PROGRAM_REQUIREMENTS_SUPPORT_INDEX_SHEET,
            list(TD_PROGRAM_REQUIREMENTS_SUPPORT_INDEX_HEADERS),
        )
        requirement_count = 0
        for idx, condition in enumerate(
            sorted(
                combined_conditions,
                key=lambda item: (
                    str(item.get("program_title") or "").casefold(),
                    str(item.get("display_name") or item.get("condition_key") or "").casefold(),
                ),
            ),
            start=1,
        ):
            preferred = (
                f"{TD_PROGRAM_REQUIREMENTS_SUPPORT_SHEET_PREFIX}{idx:02d}_"
                f"{str(condition.get('program_title') or '').strip()}_"
                f"{str(condition.get('condition_key') or '').strip()}"
            )
            sheet_name = _td_safe_excel_sheet_title(
                preferred,
                used_sheet_names,
                fallback=TD_PROGRAM_REQUIREMENTS_SUPPORT_SHEET_PREFIX.rstrip("_"),
            )
            ws_index.append(
                [
                    str(condition.get("program_title") or "").strip(),
                    str(condition.get("condition_key") or "").strip(),
                    str(condition.get("display_name") or condition.get("condition_key") or "").strip(),
                    sheet_name,
                    str(condition.get("run_type") or "").strip(),
                    condition.get("pulse_width_on"),
                    condition.get("control_period"),
                    condition.get("suppression_voltage"),
                    str(condition.get("member_sequences_text") or "").strip(),
                    str(condition.get("source_workbook") or "").strip(),
                    str(condition.get("source_sheet_name") or "").strip(),
                    int(len(condition.get("requirements") or [])),
                ]
            )
            ws_condition = _td_reset_workbook_sheet(
                wb,
                sheet_name,
                list(TD_PROGRAM_REQUIREMENTS_SUPPORT_HEADERS),
            )
            for row in condition.get("requirements") or []:
                requirement_count += 1
                ws_condition.append(
                    [
                        _td_program_requirements_parse_bool(row.get("enabled"), default=True),
                        str(row.get("parameter_name") or "").strip(),
                        str(row.get("units") or "").strip(),
                        row.get("min_value"),
                        row.get("max_value"),
                        str(condition.get("program_title") or "").strip(),
                        str(condition.get("condition_key") or "").strip(),
                        str(condition.get("display_name") or condition.get("condition_key") or "").strip(),
                        str(condition.get("run_type") or "").strip(),
                        condition.get("pulse_width_on"),
                        condition.get("control_period"),
                        condition.get("suppression_voltage"),
                        str(condition.get("member_sequences_text") or "").strip(),
                        str(condition.get("source_workbook") or "").strip(),
                        str(condition.get("source_sheet_name") or "").strip(),
                    ]
                )
        wb.save(str(support_path))
    finally:
        try:
            wb.close()
        except Exception:
            pass
    return {
        "path": str(support_path),
        "updated": True,
        "condition_count": int(len(combined_conditions)),
        "requirements_count": int(requirement_count),
        "warnings": warnings,
    }


def _td_normalize_support_workbook_sheet_names(wb) -> bool:
    changed = False
    used_titles: set[str] = set()
    rename_map: dict[str, str] = {}

    for ws in list(getattr(wb, "worksheets", []) or []):
        old_title = str(getattr(ws, "title", "") or "")
        preferred = old_title
        if len(old_title) > 31:
            preferred = old_title[:31]
        new_title = _td_safe_excel_sheet_title(preferred, used_titles, fallback="Sheet")
        if new_title != old_title:
            ws.title = new_title
            rename_map[old_title] = new_title
            changed = True

    if rename_map and TD_SUPPORT_PROGRAMS_SHEET in wb.sheetnames:
        ws_programs = wb[TD_SUPPORT_PROGRAMS_SHEET]
        headers: dict[str, int] = {}
        for col in range(1, (ws_programs.max_column or 0) + 1):
            key = str(ws_programs.cell(1, col).value or "").strip().lower()
            if key:
                headers[key] = col
        sheet_col = headers.get("sheet_name", 2)
        for row in range(2, (ws_programs.max_row or 0) + 1):
            old_value = str(ws_programs.cell(row, sheet_col).value or "").strip()
            new_value = rename_map.get(old_value)
            if not new_value:
                continue
            ws_programs.cell(row, sheet_col).value = new_value
            changed = True

    return changed


def _td_support_program_row_defaults(source_run_name: object, *, program_title: object = "") -> dict[str, object]:
    source = str(source_run_name or "").strip()
    return {
        "program_title": str(program_title or "").strip(),
        "source_run_name": source,
        "condition_key": source,
        "display_name": source,
        "feed_pressure": None,
        "feed_pressure_units": "",
        "feed_temperature": None,
        "feed_temperature_units": "",
        "run_type": "",
        "pulse_width": None,
        "pulse_width_on": None,
        "control_period": None,
        "suppression_voltage": None,
        "valve_voltage": None,
        "exclude_first_n": None,
        "last_n_rows": None,
        "enabled": True,
    }


def _td_condition_identity_parts(row: Mapping[str, object]) -> tuple[str, str, str, str, str, str, str]:
    return (
        _td_format_compact_value(row.get("feed_pressure")).lower(),
        str(row.get("feed_pressure_units") or "").strip().lower(),
        _td_format_compact_value(row.get("feed_temperature")).lower(),
        str(row.get("feed_temperature_units") or "").strip().lower(),
        td_normalize_run_type(row.get("run_type")).lower(),
        _td_format_compact_value(row.get("pulse_width_on", row.get("pulse_width"))).lower(),
        _td_format_compact_value(row.get("control_period")).lower(),
    )


def _td_condition_base_key(row: Mapping[str, object]) -> str:
    source_run_name = str(row.get("source_run_name") or "").strip()
    explicit = str(
        row.get("condition_key")
        or row.get("run_name")
        or row.get("sequence_name")
        or ""
    ).strip()
    has_core_bundle = _td_support_row_has_core_bundle(row)
    if explicit:
        if not source_run_name:
            return explicit
        if _td_support_norm_name(explicit) != _td_support_norm_name(source_run_name):
            return explicit
    if has_core_bundle:
        parts = [
            _td_format_compact_value(row.get("feed_pressure")),
            str(row.get("feed_pressure_units") or "").strip(),
            td_normalize_run_type(row.get("run_type")),
            _td_format_compact_value(_td_support_sequence_pulse_width(row)),
            _td_format_compact_value(row.get("control_period")),
        ]
        joined = "_".join([p for p in parts if str(p).strip()])
        slug = re.sub(r"[^A-Za-z0-9]+", "_", joined).strip("_")
        if slug:
            return slug
    return explicit or source_run_name


def _td_support_condition_group_identity(row: Mapping[str, object]) -> tuple[str, str, str, str, str, str, str, str]:
    condition_parts = _td_condition_identity_parts(row)
    if any(bool(part) for part in condition_parts):
        return ("",) + condition_parts
    return (_td_condition_base_key(row),) + condition_parts


def _td_distinct_condition_values(rows: Sequence[Mapping[str, object]], field_name: str) -> list[object]:
    values_by_key: dict[str, object] = {}
    for row in rows or []:
        if not isinstance(row, Mapping):
            continue
        value = row.get(field_name)
        label = _td_format_compact_value(value)
        if not label:
            continue
        key = label.casefold()
        if key not in values_by_key:
            values_by_key[key] = value
    return list(values_by_key.values())


def _td_group_program_rows_into_conditions(
    rows: Sequence[Mapping[str, object]],
    *,
    diagnostics: dict[str, int] | None = None,
) -> list[dict]:
    grouped: dict[tuple[str, str, str, str, str, str, str, str], dict] = {}
    diag = diagnostics if isinstance(diagnostics, dict) else None
    if diag is not None:
        diag.clear()
        diag.update(
            {
                "full_promoted": 0,
                "source_label_promoted": 0,
                "fallback_promoted": 0,
                "dropped": 0,
                "disabled_rows": 0,
            }
        )
    for raw_row in rows or []:
        if not isinstance(raw_row, Mapping):
            continue
        if not bool(raw_row.get("enabled", True)):
            if diag is not None:
                diag["disabled_rows"] += 1
            continue
        source_run_name = str(raw_row.get("source_run_name") or "").strip()
        is_promotable = _td_support_row_is_promotable(raw_row)
        if not is_promotable and not source_run_name:
            if diag is not None:
                diag["dropped"] += 1
            continue
        if diag is not None:
            explicit_condition_key = str(raw_row.get("condition_key") or "").strip()
            explicit_display_name = str(raw_row.get("display_name") or "").strip()
            explicit_label_without_core = bool(
                not _td_support_row_has_core_bundle(raw_row)
                and (
                    (explicit_condition_key and not _td_support_name_is_default(explicit_condition_key, source_run_name))
                    or (explicit_display_name and not _td_support_name_is_default(explicit_display_name, source_run_name))
                )
            )
            if bool(raw_row.get("__source_label_promoted")) or explicit_label_without_core:
                diag["source_label_promoted"] += 1
            elif is_promotable:
                diag["full_promoted"] += 1
            else:
                diag["fallback_promoted"] += 1
        condition_key = _td_condition_base_key(raw_row)
        if not condition_key or not source_run_name:
            if diag is not None and not source_run_name:
                diag["dropped"] += 1
            continue
        identity = _td_support_condition_group_identity(raw_row)
        group = grouped.get(identity)
        if group is None:
            display_name = _td_effective_run_condition_label(
                raw_row,
                fallback_display_name=(raw_row.get("display_name") or condition_key),
            )
            group = {
                "condition_key": condition_key,
                "display_name": display_name,
                "feed_pressure": raw_row.get("feed_pressure"),
                "feed_pressure_units": str(raw_row.get("feed_pressure_units") or "").strip(),
                "feed_temperature": raw_row.get("feed_temperature"),
                "feed_temperature_units": str(raw_row.get("feed_temperature_units") or "").strip(),
                "run_type": str(raw_row.get("run_type") or "").strip(),
                "pulse_width": raw_row.get("pulse_width_on", raw_row.get("pulse_width")),
                "pulse_width_on": raw_row.get("pulse_width_on", raw_row.get("pulse_width")),
                "control_period": raw_row.get("control_period"),
                "suppression_voltage": raw_row.get("suppression_voltage"),
                "valve_voltage": raw_row.get("valve_voltage"),
                "member_rows": [],
                "member_sequences": [],
                "member_programs": [],
            }
            grouped[identity] = group
        group["member_rows"].append(dict(raw_row))
        program_title = str(raw_row.get("program_title") or "").strip()
        if source_run_name not in group["member_sequences"]:
            group["member_sequences"].append(source_run_name)
        if program_title and program_title not in group["member_programs"]:
            group["member_programs"].append(program_title)
    out = list(grouped.values())
    out.sort(key=lambda d: (str(d.get("display_name") or "").lower(), str(d.get("condition_key") or "").lower()))
    used_keys: dict[str, int] = {}
    for idx, group in enumerate(out):
        member_rows = [dict(row) for row in (group.get("member_rows") or []) if isinstance(row, Mapping)]
        if len(member_rows) == 1:
            member = member_rows[0]
            source_run_name = str(member.get("source_run_name") or "").strip()
            explicit_key = str(
                member.get("condition_key")
                or member.get("run_name")
                or member.get("sequence_name")
                or ""
            ).strip()
            if (
                source_run_name
                and explicit_key
                and _td_support_norm_name(explicit_key) == _td_support_norm_name(source_run_name)
            ):
                group["condition_key"] = source_run_name
        base_key = str(group.get("condition_key") or "").strip() or f"condition_{idx + 1}"
        dup_count = used_keys.get(base_key.lower(), 0)
        used_keys[base_key.lower()] = dup_count + 1
        if dup_count > 0:
            suffix_parts = [
                _td_format_compact_value(group.get("feed_pressure")),
                str(group.get("feed_pressure_units") or "").strip(),
                _td_format_compact_value(group.get("feed_temperature")),
                str(group.get("feed_temperature_units") or "").strip(),
                td_normalize_run_type(group.get("run_type")),
                _td_format_compact_value(group.get("pulse_width_on")),
                _td_format_compact_value(group.get("control_period")),
            ]
            suffix = re.sub(r"[^A-Za-z0-9]+", "_", "_".join([p for p in suffix_parts if str(p).strip()])).strip("_")
            group["condition_key"] = f"{base_key}_{suffix or str(dup_count + 1)}"
        member_rows = [dict(row) for row in (group.get("member_rows") or []) if isinstance(row, Mapping)]
        member_suppression_voltages = _td_distinct_condition_values(member_rows, "suppression_voltage")
        member_valve_voltages = _td_distinct_condition_values(member_rows, "valve_voltage")
        group["suppression_voltage"] = member_suppression_voltages[0] if len(member_suppression_voltages) == 1 else None
        group["valve_voltage"] = member_valve_voltages[0] if len(member_valve_voltages) == 1 else None
        group["member_suppression_voltages"] = list(member_suppression_voltages)
        group["member_valve_voltages"] = list(member_valve_voltages)
        group["sheet_name"] = _td_support_condition_sheet_name(str(group.get("condition_key") or ""), idx)
    return out


def td_build_run_condition_key(sequence_row: dict | None) -> str:
    if not isinstance(sequence_row, dict):
        return ""
    return _td_condition_base_key(sequence_row)


def _write_td_support_workbook(
    path: Path,
    *,
    sequence_names: list[str],
    param_defs: list[dict],
    program_titles: list[str] | None = None,
    sequences_by_program: Mapping[str, Sequence[str]] | None = None,
) -> None:
    try:
        from openpyxl import Workbook  # type: ignore
        from openpyxl.comments import Comment  # type: ignore
    except Exception as exc:
        raise RuntimeError(
            "openpyxl is required to create the TD support workbook. "
            "Install it with `py -m pip install openpyxl` within the project environment."
        ) from exc

    wb = Workbook()
    ws_settings = wb.active
    ws_settings.title = "Settings"
    ws_settings.append(["key", "value"])
    ws_settings.append(["exclude_first_n_default", ""])
    ws_settings.append(["last_n_rows_default", 10])
    ws_settings.append(["perf_eq_strictness", "medium"])
    ws_settings.append(["perf_eq_point_count", "medium"])
    ws_settings["A4"].comment = Comment(
        (
            "Controls how strict performance-equation candidate qualification is.\n"
            "Allowed values: tight, medium, loose.\n"
            "tight: requires a larger meaningful X spread.\n"
            "medium: balanced default.\n"
            "loose: easiest qualification."
        ),
        "EIDAT",
    )
    ws_settings["B4"].comment = Comment(
        "Choose one of: tight, medium, loose. Default is medium.",
        "EIDAT",
    )
    ws_settings["A5"].comment = Comment(
        (
            "Controls the minimum distinct X points required for performance-equation candidates.\n"
            "tight = 4 points, medium = 3 points, loose = 2 points."
        ),
        "EIDAT",
    )
    ws_settings["B5"].comment = Comment(
        "Choose one of: tight, medium, loose. Default is medium.",
        "EIDAT",
    )

    all_sequences: list[str] = []
    seen_seq: set[str] = set()
    for seq_name in sequence_names:
        name = str(seq_name or "").strip()
        key = _td_support_norm_name(name)
        if not name or not key or key in seen_seq:
            continue
        seen_seq.add(key)
        all_sequences.append(name)

    raw_programs = [str(v).strip() for v in (program_titles or []) if str(v).strip()]
    if not raw_programs:
        raw_programs = [TD_SUPPORT_DEFAULT_PROGRAM_TITLE]
    programs: list[str] = []
    seen_programs: set[str] = set()
    for title in raw_programs:
        key = _td_support_norm_name(title)
        if not key or key in seen_programs:
            continue
        seen_programs.add(key)
        programs.append(title)

    program_sequence_map: dict[str, list[str]] = {}
    if isinstance(sequences_by_program, Mapping) and sequences_by_program:
        for title, seqs in sequences_by_program.items():
            clean_title = str(title or "").strip() or TD_SUPPORT_DEFAULT_PROGRAM_TITLE
            ordered: list[str] = []
            seen_local: set[str] = set()
            for seq in seqs or []:
                seq_name = str(seq or "").strip()
                if not seq_name or seq_name.lower() in seen_local:
                    continue
                seen_local.add(seq_name.lower())
                ordered.append(seq_name)
            if ordered:
                program_sequence_map[clean_title] = ordered
        if program_sequence_map:
            programs = [p for p in programs if p in program_sequence_map] or sorted(program_sequence_map.keys())
    if not program_sequence_map:
        for title in programs:
            program_sequence_map[str(title)] = list(all_sequences)

    ws_programs = wb.create_sheet(TD_SUPPORT_PROGRAMS_SHEET)
    ws_programs.append(["program_title", "sheet_name", "enabled"])
    for idx, title in enumerate(programs):
        ws_programs.append([title, _td_support_program_sheet_name(title, idx), True])

    for idx, title in enumerate(programs):
        ws_prog = wb.create_sheet(_td_support_program_sheet_name(title, idx))
        ws_prog.append(
            [
                "source_run_name",
                "condition_key",
                "display_name",
                "feed_pressure",
                "feed_pressure_units",
                "run_type",
                "pulse_width_on",
                "control_period",
                "exclude_first_n",
                "last_n_rows",
                "enabled",
                "feed_temperature",
                "feed_temperature_units",
                "suppression_voltage",
                "valve_voltage",
            ]
        )
        for seq_name in (program_sequence_map.get(title) or []):
            row = _td_support_program_row_defaults(seq_name, program_title=title)
            ws_prog.append(
                [
                    row["source_run_name"],
                    row["condition_key"],
                    row["display_name"],
                    "",
                    "",
                    "",
                    "",
                    "",
                    "",
                    "",
                    True,
                    "",
                    "",
                    "",
                    "",
                ]
            )

    path.parent.mkdir(parents=True, exist_ok=True)
    wb.save(str(path))
    try:
        wb.close()
    except Exception:
        pass


def _refresh_td_support_run_conditions_sheet(
    workbook_path: Path,
    *,
    project_dir: Path | None = None,
    param_defs: list[dict] | None = None,
) -> dict:
    try:
        from openpyxl import load_workbook  # type: ignore
    except Exception as exc:
        raise RuntimeError(
            "openpyxl is required to update the TD support workbook. "
            "Install it with `py -m pip install openpyxl` within the project environment."
        ) from exc

    wb_path = Path(workbook_path).expanduser()
    support_path = td_support_workbook_path_for(wb_path, project_dir=project_dir)
    if not support_path.exists():
        return {"path": str(support_path), "updated": False, "condition_count": 0, "rows_written": 0}

    support_cfg = _read_td_support_workbook(wb_path, project_dir=project_dir)
    condition_group_diagnostics = dict(support_cfg.get("condition_group_diagnostics") or {})
    run_conditions = [
        dict(row)
        for row in ((support_cfg.get("run_conditions") or []))
        if isinstance(row, dict) and str(row.get("condition_key") or "").strip()
    ]
    condition_bounds = {
        str(k).strip(): dict(v)
        for k, v in (support_cfg.get("condition_bounds") or {}).items()
        if str(k).strip() and isinstance(v, dict)
    }
    param_defs = [
        dict(d)
        for d in (param_defs or [])
        if isinstance(d, dict) and str(d.get("name") or "").strip()
    ]
    param_order = [str(d.get("name") or "").strip() for d in param_defs if str(d.get("name") or "").strip()]
    param_units = {
        str(d.get("name") or "").strip(): str(d.get("units") or "").strip()
        for d in param_defs
        if str(d.get("name") or "").strip()
    }
    headers = [
        "condition_key",
        "display_name",
        "feed_pressure",
        "feed_pressure_units",
        "run_type",
        "pulse_width_on",
        "control_period",
        "member_sequences",
        "member_programs",
        "parameter_name",
        "units",
        "min_value",
        "max_value",
        "enabled",
        "feed_temperature",
        "feed_temperature_units",
        "suppression_voltage",
        "valve_voltage",
    ]
    desired_rows: list[list[object]] = []
    rows_written = 0
    for row in run_conditions:
        condition_key = str(row.get("condition_key") or "").strip()
        if not condition_key:
            continue
        bounds = dict(condition_bounds.get(condition_key) or {})
        ordered_names = [name for name in param_order if name]
        ordered_names.extend(
            sorted(
                [name for name in bounds.keys() if str(name).strip() and str(name).strip() not in ordered_names],
                key=lambda s: str(s).lower(),
            )
        )
        if not ordered_names:
            ordered_names = [""]
        for param_name in ordered_names:
            bound = dict(bounds.get(param_name) or {}) if param_name else {}
            desired_rows.append(
                [
                    condition_key,
                    str(row.get("display_name") or condition_key).strip() or condition_key,
                    row.get("feed_pressure"),
                    str(row.get("feed_pressure_units") or "").strip(),
                    str(row.get("run_type") or "").strip(),
                    row.get("pulse_width_on", row.get("pulse_width")),
                    row.get("control_period"),
                    str(row.get("member_sequences_text") or "").strip(),
                    str(row.get("member_programs_text") or "").strip(),
                    param_name,
                    str(bound.get("units") or param_units.get(param_name) or "").strip(),
                    bound.get("min_value"),
                    bound.get("max_value"),
                    bool(bound.get("enabled", row.get("enabled", True))),
                    row.get("feed_temperature"),
                    str(row.get("feed_temperature_units") or "").strip(),
                    row.get("suppression_voltage"),
                    row.get("valve_voltage"),
                ]
            )
            rows_written += 1

    def _canon_support_cell(value: object) -> object:
        if value is None:
            return ""
        if isinstance(value, bool):
            return bool(value)
        if isinstance(value, (int, float)):
            f = float(value)
            if not math.isfinite(f):
                return ""
            if abs(f - round(f)) < 1e-9:
                return int(round(f))
            return round(f, 12)
        return str(value).strip()

    wb = _td_load_workbook_ignore_long_title_warning(str(support_path))
    try:
        normalized_changed = _td_normalize_support_workbook_sheet_names(wb)
        legacy_sheet_names = [
            sheet_name
            for sheet_name in wb.sheetnames
            if sheet_name == TD_SUPPORT_RUN_CONDITION_BOUNDS_SHEET
            or str(sheet_name).startswith(TD_SUPPORT_CONDITION_SHEET_PREFIX)
        ]
        existing_headers: list[object] = []
        existing_rows: list[list[object]] = []
        if TD_SUPPORT_RUN_CONDITIONS_SHEET in wb.sheetnames:
            ws_existing = wb[TD_SUPPORT_RUN_CONDITIONS_SHEET]
            existing_headers = [
                _canon_support_cell(ws_existing.cell(1, col).value)
                for col in range(1, len(headers) + 1)
            ]
            for row in ws_existing.iter_rows(min_row=2, max_col=len(headers), values_only=True):
                canon_row = [_canon_support_cell(value) for value in row]
                if any(value != "" for value in canon_row):
                    existing_rows.append(canon_row)
        desired_rows_canon = [[_canon_support_cell(value) for value in row] for row in desired_rows]
        if (
            not normalized_changed
            and not legacy_sheet_names
            and existing_headers == headers
            and existing_rows == desired_rows_canon
        ):
            return {
                "path": str(support_path),
                "updated": False,
                "condition_count": len(run_conditions),
                "rows_written": rows_written,
                "condition_group_diagnostics": condition_group_diagnostics,
            }

        for sheet_name in list(wb.sheetnames):
            if sheet_name == TD_SUPPORT_RUN_CONDITIONS_SHEET or sheet_name == TD_SUPPORT_RUN_CONDITION_BOUNDS_SHEET:
                wb.remove(wb[sheet_name])
                continue
            if str(sheet_name).startswith(TD_SUPPORT_CONDITION_SHEET_PREFIX):
                wb.remove(wb[sheet_name])

        ws_cond = wb.create_sheet(TD_SUPPORT_RUN_CONDITIONS_SHEET)
        ws_cond.append(headers)
        for row in desired_rows:
            ws_cond.append(list(row))
        wb.save(str(support_path))
    finally:
        try:
            wb.close()
        except Exception:
            pass

    return {
        "path": str(support_path),
        "updated": True,
        "condition_count": len(run_conditions),
        "rows_written": rows_written,
        "condition_group_diagnostics": condition_group_diagnostics,
    }


def _sync_td_support_workbook_program_sheets(
    workbook_path: Path,
    *,
    global_repo: Path | None,
    project_dir: Path | None = None,
    param_defs: list[dict] | None = None,
) -> dict:
    wb_path = Path(workbook_path).expanduser()
    proj_dir = Path(project_dir).expanduser() if project_dir is not None else wb_path.parent
    repo = Path(global_repo).expanduser() if global_repo is not None else None
    support_path = td_support_workbook_path_for(wb_path, project_dir=proj_dir)

    docs: list[dict] = []
    selected: set[str] = set()
    if repo is not None:
        try:
            docs = read_eidat_index_documents(repo)
        except Exception:
            docs = []
        try:
            selected = _project_selected_metadata_rels(proj_dir)
        except Exception:
            selected = set()
    chosen_docs = (
        [d for d in docs if isinstance(d, dict) and str(d.get("metadata_rel") or "").strip() in selected]
        if selected
        else []
    )
    discovered_program_titles = sorted(
        {
            str(doc.get("program_title") or "").strip()
            for doc in chosen_docs
            if isinstance(doc, dict) and str(doc.get("program_title") or "").strip()
        }
    )
    discovered_runs_by_program = _discover_td_runs_by_program_for_docs(repo, chosen_docs) if chosen_docs else {}
    discovered_sequence_names = _discover_td_runs_for_docs(repo, chosen_docs) if chosen_docs else []
    discovered_sequence_context_by_program = (
        _discover_td_sequence_context_by_program_for_docs(repo, chosen_docs) if chosen_docs else {}
    )
    clean_param_defs = [
        dict(d)
        for d in (param_defs or [])
        if isinstance(d, dict) and str(d.get("name") or "").strip()
    ]

    created = False
    if not support_path.exists():
        _write_td_support_workbook(
            support_path,
            sequence_names=(discovered_sequence_names or ["Run1"]),
            param_defs=clean_param_defs,
            program_titles=discovered_program_titles,
            sequences_by_program=discovered_runs_by_program,
        )
        created = True

    if not discovered_program_titles and not discovered_runs_by_program and not created:
        return {
            "path": str(support_path),
            "updated": False,
            "created": False,
            "program_count": 0,
        }

    support_cfg = _read_td_support_workbook(wb_path, project_dir=proj_dir)
    existing_programs = [
        dict(row)
        for row in (support_cfg.get("programs") or [])
        if isinstance(row, dict) and str(row.get("program_title") or "").strip()
    ]
    existing_rows_by_program = {
        str(title).strip(): [dict(row) for row in rows if isinstance(row, dict)]
        for title, rows in (support_cfg.get("program_mappings") or {}).items()
        if str(title).strip() and isinstance(rows, list)
    }

    desired_program_titles: list[str] = []
    seen_titles: set[str] = set()
    for row in existing_programs:
        title = str(row.get("program_title") or "").strip()
        key = _td_support_norm_name(title)
        if not title or not key or key in seen_titles:
            continue
        seen_titles.add(key)
        desired_program_titles.append(title)
    for title in discovered_program_titles:
        key = _td_support_norm_name(title)
        if not title or not key or key in seen_titles:
            continue
        seen_titles.add(key)
        desired_program_titles.append(title)
    if not desired_program_titles:
        desired_program_titles = [TD_SUPPORT_DEFAULT_PROGRAM_TITLE]

    desired_sequences_by_program: dict[str, list[str]] = {}
    for title in desired_program_titles:
        ordered: list[str] = []
        seen_sequences: set[str] = set()
        for row in existing_rows_by_program.get(title) or []:
            source_run = str(row.get("source_run_name") or "").strip()
            key = source_run.lower()
            if not source_run or key in seen_sequences:
                continue
            seen_sequences.add(key)
            ordered.append(source_run)
        for seq_name in discovered_runs_by_program.get(title) or []:
            clean = str(seq_name or "").strip()
            key = clean.lower()
            if not clean or key in seen_sequences:
                continue
            seen_sequences.add(key)
            ordered.append(clean)
        if not ordered and title == TD_SUPPORT_DEFAULT_PROGRAM_TITLE:
            for seq_name in discovered_sequence_names:
                clean = str(seq_name or "").strip()
                key = clean.lower()
                if not clean or key in seen_sequences:
                    continue
                seen_sequences.add(key)
                ordered.append(clean)
        desired_sequences_by_program[title] = ordered

    wb = _td_load_workbook_ignore_long_title_warning(str(support_path))
    try:
        changed = _td_normalize_support_workbook_sheet_names(wb)

        existing_sheet_by_title: dict[str, str] = {}
        for row in existing_programs:
            title = str(row.get("program_title") or "").strip()
            sheet_name = str(row.get("sheet_name") or "").strip()
            if title and sheet_name and sheet_name in wb.sheetnames:
                existing_sheet_by_title[title] = sheet_name

        protected_sheet_names = {
            TD_SUPPORT_PROGRAMS_SHEET.lower(),
            TD_SUPPORT_RUN_CONDITIONS_SHEET.lower(),
            TD_SUPPORT_RUN_CONDITION_BOUNDS_SHEET.lower(),
            "settings",
        }
        used_sheet_names = {
            str(sheet_name).strip().lower()
            for sheet_name in wb.sheetnames
            if str(sheet_name).strip() and str(sheet_name).strip().lower() in protected_sheet_names
        }
        desired_sheet_by_title: dict[str, str] = {}
        for idx, title in enumerate(desired_program_titles):
            existing_sheet = existing_sheet_by_title.get(title, "")
            if existing_sheet and existing_sheet in wb.sheetnames and existing_sheet.lower() not in used_sheet_names:
                desired_sheet_by_title[title] = existing_sheet
                used_sheet_names.add(existing_sheet.lower())
                continue
            preferred = _td_support_program_sheet_name(title, idx)
            sheet_name = _td_safe_excel_sheet_title(preferred, used_sheet_names, fallback="Program")
            desired_sheet_by_title[title] = sheet_name

        ws_programs = _td_reset_workbook_sheet(
            wb,
            TD_SUPPORT_PROGRAMS_SHEET,
            ["program_title", "sheet_name", "enabled"],
        )
        try:
            ws_programs.freeze_panes = "A2"
        except Exception:
            pass

        row_headers = [
            "source_run_name",
            "condition_key",
            "display_name",
            "feed_pressure",
            "feed_pressure_units",
            "run_type",
            "pulse_width_on",
            "control_period",
            "exclude_first_n",
            "last_n_rows",
            "enabled",
            "feed_temperature",
            "feed_temperature_units",
            "suppression_voltage",
            "valve_voltage",
        ]
        for title in desired_program_titles:
            sheet_name = desired_sheet_by_title[title]
            existing_enabled = next(
                (
                    bool(row.get("enabled", True))
                    for row in existing_programs
                    if str(row.get("program_title") or "").strip() == title
                ),
                True,
            )
            ws_programs.append([title, sheet_name, existing_enabled])

            existing_rows = {
                str(row.get("source_run_name") or "").strip().lower(): dict(row)
                for row in (existing_rows_by_program.get(title) or [])
                if str(row.get("source_run_name") or "").strip()
            }
            ws_program = _td_reset_workbook_sheet(wb, sheet_name, row_headers)
            desired_rows: list[list[object]] = []
            for seq_name in desired_sequences_by_program.get(title) or []:
                seq_key = str(seq_name or "").strip().lower()
                if not seq_key:
                    continue
                row_data = dict(existing_rows.get(seq_key) or _td_support_program_row_defaults(seq_name, program_title=title))
                row_data["program_title"] = title
                row_data["source_run_name"] = str(row_data.get("source_run_name") or seq_name).strip() or str(seq_name).strip()
                row_data = _td_prefill_support_row_from_sequence_context(
                    row_data,
                    _td_lookup_sequence_context(
                        discovered_sequence_context_by_program,
                        title,
                        row_data.get("source_run_name"),
                    ),
                    blank_unusable_defaults=True,
                )
                condition_key = str(row_data.get("condition_key") or "").strip()
                display_name = str(row_data.get("display_name") or "").strip()
                desired_rows.append(
                    [
                        row_data["source_run_name"],
                        condition_key,
                        display_name,
                        row_data.get("feed_pressure"),
                        str(row_data.get("feed_pressure_units") or "").strip(),
                        str(row_data.get("run_type") or "").strip(),
                        row_data.get("pulse_width_on", row_data.get("pulse_width")),
                        row_data.get("control_period"),
                        row_data.get("exclude_first_n"),
                        row_data.get("last_n_rows"),
                        bool(row_data.get("enabled", True)),
                        row_data.get("feed_temperature"),
                        str(row_data.get("feed_temperature_units") or "").strip(),
                        row_data.get("suppression_voltage"),
                        row_data.get("valve_voltage"),
                    ]
                )
            for row in desired_rows:
                ws_program.append(list(row))

        wb.save(str(support_path))
        changed = True
    finally:
        try:
            wb.close()
        except Exception:
            pass

    return {
        "path": str(support_path),
        "updated": bool(changed),
        "created": bool(created),
        "program_count": len(desired_program_titles),
    }


def _to_support_int(v: object) -> int | None:
    num = _to_support_number(v)
    if num is None:
        return None
    try:
        return max(0, int(float(num)))
    except Exception:
        return None


def _to_support_number(v: object) -> int | float | None:
    if v is None or isinstance(v, bool):
        return None
    if isinstance(v, (int, float)):
        f = float(v)
        if not math.isfinite(f):
            return None
        if abs(f - round(f)) < 1e-9:
            return int(round(f))
        return float(f)
    txt = str(v).strip().replace(",", "")
    if not txt:
        return None
    try:
        f = float(txt)
    except Exception:
        return None
    if not math.isfinite(f):
        return None
    if abs(f - round(f)) < 1e-9:
        return int(round(f))
    return float(f)


def _td_support_sequence_pulse_width(sequence_row: dict | None) -> object | None:
    if not isinstance(sequence_row, dict):
        return None
    value = sequence_row.get("pulse_width")
    if value not in (None, ""):
        return value
    return sequence_row.get("pulse_width_on")


def _normalize_support_scalar(v: object) -> object | None:
    if v is None:
        return None
    if isinstance(v, bool):
        return str(v).strip().lower()
    if isinstance(v, (int, float)):
        f = float(v)
        if not math.isfinite(f):
            return None
        if abs(f - round(f)) < 1e-9:
            return int(round(f))
        return float(f)
    txt = str(v).strip()
    if not txt:
        return None
    try:
        f = float(txt.replace(",", ""))
        if math.isfinite(f):
            if abs(f - round(f)) < 1e-9:
                return int(round(f))
            return float(f)
    except Exception:
        pass
    return txt.strip().lower()


def _support_values_equal(lhs: object | None, rhs: object | None) -> bool:
    a = _normalize_support_scalar(lhs)
    b = _normalize_support_scalar(rhs)
    if a is None or b is None:
        return False
    if isinstance(a, (int, float)) and isinstance(b, (int, float)):
        return abs(float(a) - float(b)) <= 1e-9
    return str(a).strip().lower() == str(b).strip().lower()


def _td_finite_float(v: object) -> float | None:
    if v is None:
        return None
    if isinstance(v, (int, float)):
        f = float(v)
    else:
        t = str(v).strip().replace(",", "")
        if not t:
            return None
        try:
            f = float(t)
        except Exception:
            return None
    if math.isfinite(f):
        return f
    return None


def _td_bool(v: object, default: bool = True) -> bool:
    if v is None:
        return bool(default)
    if isinstance(v, bool):
        return bool(v)
    txt = str(v).strip().lower()
    if not txt:
        return bool(default)
    if txt in {"1", "true", "yes", "y", "on"}:
        return True
    if txt in {"0", "false", "no", "n", "off"}:
        return False
    return bool(default)


def _read_td_support_workbook(workbook_path: Path, *, project_dir: Path | None = None) -> dict:
    try:
        from openpyxl import load_workbook  # type: ignore
    except Exception as exc:
        raise RuntimeError(
            "openpyxl is required to read the TD support workbook. "
            "Install it with `py -m pip install openpyxl` within the project environment."
        ) from exc

    support_path = td_support_workbook_path_for(workbook_path, project_dir=project_dir)
    if not support_path.exists():
        return {
            "path": str(support_path),
            "exists": False,
            "settings": {},
            "programs": [],
            "program_mappings": {},
            "run_conditions": [],
            "condition_groups": [],
            "condition_bounds": {},
            "sequences": [],
            "bounds_by_sequence": {},
        }

    wb = _td_load_workbook_ignore_long_title_warning(str(support_path), read_only=True, data_only=True)
    try:
        settings: dict[str, object] = {}
        if "Settings" in wb.sheetnames:
            ws = wb["Settings"]
            for row in range(2, (ws.max_row or 0) + 1):
                key = str(ws.cell(row, 1).value or "").strip()
                if not key:
                    continue
                val = _normalize_support_scalar(ws.cell(row, 2).value)
                if val is not None:
                    settings[key] = val

        programs: list[dict] = []
        program_mappings: dict[str, list[dict]] = {}
        run_conditions: list[dict] = []
        condition_bounds: dict[str, dict[str, dict]] = {}

        if TD_SUPPORT_PROGRAMS_SHEET in wb.sheetnames:
            ws = wb[TD_SUPPORT_PROGRAMS_SHEET]
            headers: dict[str, int] = {}
            for col in range(1, (ws.max_column or 0) + 1):
                key = str(ws.cell(1, col).value or "").strip().lower()
                if key:
                    headers[key] = col
            for row in range(2, (ws.max_row or 0) + 1):
                title = str(ws.cell(row, headers.get("program_title", 1)).value or "").strip()
                sheet_name = str(ws.cell(row, headers.get("sheet_name", 2)).value or "").strip()
                if not title:
                    continue
                enabled_raw = ws.cell(row, headers.get("enabled", 3)).value if headers.get("enabled") else True
                enabled = _td_bool(enabled_raw, True)
                programs.append({"program_title": title, "sheet_name": sheet_name, "enabled": bool(enabled)})

        combined_run_conditions_sheet = False
        if TD_SUPPORT_RUN_CONDITIONS_SHEET in wb.sheetnames:
            ws = wb[TD_SUPPORT_RUN_CONDITIONS_SHEET]
            headers: dict[str, int] = {}
            for col in range(1, (ws.max_column or 0) + 1):
                key = str(ws.cell(1, col).value or "").strip().lower()
                if key:
                    headers[key] = col
            combined_run_conditions_sheet = "parameter_name" in headers
            run_conditions_by_key: dict[str, dict] = {}
            for row in range(2, (ws.max_row or 0) + 1):
                condition_key = str(ws.cell(row, headers.get("condition_key", 1)).value or "").strip()
                raw_display_name = str(ws.cell(row, headers.get("display_name", 2)).value or "").strip()
                if not condition_key and not raw_display_name:
                    continue
                enabled_raw = ws.cell(row, headers.get("enabled", 14 if combined_run_conditions_sheet else 8)).value if headers.get("enabled") else True
                enabled = _td_bool(enabled_raw, True)
                row_payload = {
                    "condition_key": condition_key or raw_display_name,
                    "display_name": raw_display_name or condition_key,
                    "feed_pressure": ws.cell(row, headers.get("feed_pressure", 3)).value if headers.get("feed_pressure") else None,
                    "feed_pressure_units": str(ws.cell(row, headers.get("feed_pressure_units", 4)).value or "").strip(),
                    "feed_temperature": ws.cell(row, headers.get("feed_temperature", 5)).value if headers.get("feed_temperature") else None,
                    "feed_temperature_units": str(ws.cell(row, headers.get("feed_temperature_units", 6)).value or "").strip() if headers.get("feed_temperature_units") else "",
                    "run_type": str(ws.cell(row, headers.get("run_type", 5)).value or "").strip(),
                    "pulse_width": ws.cell(row, headers.get("pulse_width_on", 6)).value if headers.get("pulse_width_on") else None,
                    "pulse_width_on": ws.cell(row, headers.get("pulse_width_on", 6)).value if headers.get("pulse_width_on") else None,
                    "control_period": ws.cell(row, headers.get("control_period", 7)).value if headers.get("control_period") else None,
                    "suppression_voltage": ws.cell(row, headers.get("suppression_voltage", 10)).value if headers.get("suppression_voltage") else None,
                    "valve_voltage": ws.cell(row, headers.get("valve_voltage")).value if headers.get("valve_voltage") else None,
                    "sheet_name": str(ws.cell(row, headers.get("sheet_name", 8)).value or "").strip() if headers.get("sheet_name") else "",
                    "member_sequences_text": str(ws.cell(row, headers.get("member_sequences", 9)).value or "").strip() if headers.get("member_sequences") else "",
                    "member_programs_text": str(ws.cell(row, headers.get("member_programs", 10)).value or "").strip() if headers.get("member_programs") else "",
                    "enabled": bool(enabled),
                }
                display_name = _td_effective_run_condition_label(
                    row_payload,
                    fallback_display_name=(raw_display_name or condition_key),
                )
                row_payload["display_name"] = display_name
                key = str(row_payload.get("condition_key") or "").strip()
                if key and key not in run_conditions_by_key:
                    run_conditions_by_key[key] = dict(row_payload)
                if combined_run_conditions_sheet:
                    pname = str(ws.cell(row, headers.get("parameter_name", 10)).value or "").strip()
                    if pname:
                        condition_bounds.setdefault(key, {})[pname] = {
                            "condition_key": key,
                            "parameter_name": pname,
                            "units": str(ws.cell(row, headers.get("units", 11)).value or "").strip(),
                            "min_value": _td_finite_float(ws.cell(row, headers.get("min_value", 12)).value if headers.get("min_value") else None),
                            "max_value": _td_finite_float(ws.cell(row, headers.get("max_value", 13)).value if headers.get("max_value") else None),
                            "enabled": bool(enabled),
                        }
            run_conditions = list(run_conditions_by_key.values())

        if not combined_run_conditions_sheet and TD_SUPPORT_RUN_CONDITION_BOUNDS_SHEET in wb.sheetnames:
            ws = wb[TD_SUPPORT_RUN_CONDITION_BOUNDS_SHEET]
            headers: dict[str, int] = {}
            for col in range(1, (ws.max_column or 0) + 1):
                key = str(ws.cell(1, col).value or "").strip().lower()
                if key:
                    headers[key] = col
            for row in range(2, (ws.max_row or 0) + 1):
                condition_key = str(ws.cell(row, headers.get("condition_key", 1)).value or "").strip()
                pname = str(ws.cell(row, headers.get("parameter_name", 2)).value or "").strip()
                if not condition_key or not pname:
                    continue
                enabled_raw = ws.cell(row, headers.get("enabled", 6)).value if headers.get("enabled") else True
                enabled = _td_bool(enabled_raw, True)
                condition_bounds.setdefault(condition_key, {})[pname] = {
                    "condition_key": condition_key,
                    "parameter_name": pname,
                    "units": str(ws.cell(row, headers.get("units", 3)).value or "").strip(),
                    "min_value": _td_finite_float(ws.cell(row, headers.get("min_value", 4)).value if headers.get("min_value") else None),
                    "max_value": _td_finite_float(ws.cell(row, headers.get("max_value", 5)).value if headers.get("max_value") else None),
                    "enabled": bool(enabled),
                }

        program_rows = list(programs)
        if run_conditions and not program_rows:
            program_rows = [
                {
                    "program_title": TD_SUPPORT_DEFAULT_PROGRAM_TITLE,
                    "sheet_name": _td_support_program_sheet_name(TD_SUPPORT_DEFAULT_PROGRAM_TITLE, 0),
                    "enabled": True,
                }
            ]

        new_program_schema_detected = False
        for idx, prog in enumerate(program_rows):
            title = str(prog.get("program_title") or "").strip()
            sheet_name = str(prog.get("sheet_name") or "").strip() or _td_support_program_sheet_name(title, idx)
            if not title or sheet_name not in wb.sheetnames:
                continue
            ws = wb[sheet_name]
            headers: dict[str, int] = {}
            for col in range(1, (ws.max_column or 0) + 1):
                key = str(ws.cell(1, col).value or "").strip().lower()
                if key:
                    headers[key] = col
            rows_out: list[dict] = []
            has_full_condition_columns = any(
                k in headers
                for k in (
                    "display_name",
                    "feed_pressure",
                    "feed_temperature",
                    "pulse_width_on",
                    "control_period",
                    "suppression_voltage",
                    "valve_voltage",
                )
            )
            new_program_schema_detected = new_program_schema_detected or bool(has_full_condition_columns)
            for row in range(2, (ws.max_row or 0) + 1):
                source_run = str(ws.cell(row, headers.get("source_run_name", 1)).value or "").strip()
                condition_key = str(ws.cell(row, headers.get("condition_key", 2)).value or "").strip()
                if not source_run and not condition_key:
                    continue
                enabled_raw = ws.cell(row, headers.get("enabled", 5)).value if headers.get("enabled") else True
                enabled = _td_bool(enabled_raw, True)
                row_out = {
                    "program_title": title,
                    "sheet_name": sheet_name,
                    "source_run_name": source_run,
                    "condition_key": condition_key or source_run,
                    "exclude_first_n": _to_support_int(ws.cell(row, headers.get("exclude_first_n", 3)).value if headers.get("exclude_first_n") else None),
                    "last_n_rows": _to_support_int(ws.cell(row, headers.get("last_n_rows", 4)).value if headers.get("last_n_rows") else None),
                    "enabled": bool(enabled),
                }
                if has_full_condition_columns:
                    raw_display_name = str(ws.cell(row, headers.get("display_name", 3)).value or "").strip()
                    row_out.update(
                        {
                            "display_name": raw_display_name or (condition_key or source_run),
                            "feed_pressure": ws.cell(row, headers.get("feed_pressure")).value if headers.get("feed_pressure") else None,
                            "feed_pressure_units": str(ws.cell(row, headers.get("feed_pressure_units")).value or "").strip() if headers.get("feed_pressure_units") else "",
                            "feed_temperature": ws.cell(row, headers.get("feed_temperature")).value if headers.get("feed_temperature") else None,
                            "feed_temperature_units": str(ws.cell(row, headers.get("feed_temperature_units")).value or "").strip() if headers.get("feed_temperature_units") else "",
                            "run_type": str(ws.cell(row, headers.get("run_type")).value or "").strip() if headers.get("run_type") else "",
                            "pulse_width": ws.cell(row, headers.get("pulse_width_on")).value if headers.get("pulse_width_on") else None,
                            "pulse_width_on": ws.cell(row, headers.get("pulse_width_on")).value if headers.get("pulse_width_on") else None,
                            "control_period": ws.cell(row, headers.get("control_period")).value if headers.get("control_period") else None,
                            "suppression_voltage": ws.cell(row, headers.get("suppression_voltage")).value if headers.get("suppression_voltage") else None,
                            "valve_voltage": ws.cell(row, headers.get("valve_voltage")).value if headers.get("valve_voltage") else None,
                        }
                    )
                    row_out["display_name"] = _td_effective_run_condition_label(
                        row_out,
                        fallback_display_name=(raw_display_name or condition_key or source_run),
                    )
                rows_out.append(row_out)
            program_mappings[title] = rows_out

        if not combined_run_conditions_sheet and not condition_bounds:
            for sheet_name in wb.sheetnames:
                if not str(sheet_name).startswith(TD_SUPPORT_CONDITION_SHEET_PREFIX):
                    continue
                ws = wb[sheet_name]
                headers: dict[str, int] = {}
                for col in range(1, (ws.max_column or 0) + 1):
                    key = str(ws.cell(1, col).value or "").strip().lower()
                    if key:
                        headers[key] = col
                if "condition_key" not in headers or "parameter_name" not in headers:
                    continue
                for row in range(2, (ws.max_row or 0) + 1):
                    condition_key = str(ws.cell(row, headers.get("condition_key", 1)).value or "").strip()
                    pname = str(ws.cell(row, headers.get("parameter_name", 10)).value or "").strip()
                    if not condition_key or not pname:
                        continue
                    enabled_raw = ws.cell(row, headers.get("enabled", 14)).value if headers.get("enabled") else True
                    enabled = _td_bool(enabled_raw, True)
                    condition_bounds.setdefault(condition_key, {})[pname] = {
                        "condition_key": condition_key,
                        "parameter_name": pname,
                        "units": str(ws.cell(row, headers.get("units", 11)).value or "").strip(),
                        "min_value": _td_finite_float(ws.cell(row, headers.get("min_value", 12)).value if headers.get("min_value") else None),
                        "max_value": _td_finite_float(ws.cell(row, headers.get("max_value", 13)).value if headers.get("max_value") else None),
                        "enabled": bool(enabled),
                    }

        if not run_conditions and "Sequences" in wb.sheetnames:
            ws = wb["Sequences"]
            headers: dict[str, int] = {}
            for col in range(1, (ws.max_column or 0) + 1):
                key = str(ws.cell(1, col).value or "").strip().lower()
                if key:
                    headers[key] = col
            legacy_sequences: list[dict] = []
            for row in range(2, (ws.max_row or 0) + 1):
                seq_name = str(ws.cell(row, headers.get("sequence_name", 1)).value or "").strip()
                source_run = str(ws.cell(row, headers.get("source_run_name", 2)).value or "").strip()
                if not seq_name and not source_run:
                    continue
                enabled_raw = ws.cell(row, headers.get("enabled", 10)).value if headers.get("enabled") else True
                enabled = True
                if enabled_raw is not None and str(enabled_raw).strip() != "":
                    enabled = _td_bool(enabled_raw, True)
                sequence_name = seq_name or source_run
                pulse_width_col = headers.get("pulse_width") or headers.get("pulse_width_on")
                legacy_sequences.append(
                    {
                        "sequence_name": sequence_name,
                        "source_run_name": source_run or sequence_name,
                        "feed_pressure": ws.cell(row, headers.get("feed_pressure", 3)).value if headers.get("feed_pressure") else None,
                        "feed_pressure_units": str(ws.cell(row, headers.get("feed_pressure_units", 4)).value or "").strip(),
                        "run_type": str(ws.cell(row, headers.get("run_type", 5)).value or "").strip(),
                        "pulse_width": ws.cell(row, pulse_width_col if pulse_width_col else 6).value,
                        "pulse_width_on": ws.cell(row, pulse_width_col if pulse_width_col else 6).value,
                        "control_period": ws.cell(row, headers.get("control_period", 7)).value if headers.get("control_period") else None,
                        "exclude_first_n": _to_support_int(ws.cell(row, headers.get("exclude_first_n", 8)).value if headers.get("exclude_first_n") else None),
                        "last_n_rows": _to_support_int(ws.cell(row, headers.get("last_n_rows", 9)).value if headers.get("last_n_rows") else None),
                        "enabled": bool(enabled),
                    }
                )

            programs = [{"program_title": TD_SUPPORT_DEFAULT_PROGRAM_TITLE, "sheet_name": _td_support_program_sheet_name(TD_SUPPORT_DEFAULT_PROGRAM_TITLE, 0), "enabled": True}]
            program_mappings[TD_SUPPORT_DEFAULT_PROGRAM_TITLE] = []
            for row in legacy_sequences:
                cond_key = str(row.get("sequence_name") or row.get("source_run_name") or "").strip()
                run_conditions.append(
                    {
                        "condition_key": cond_key,
                        "display_name": cond_key,
                        "feed_pressure": row.get("feed_pressure"),
                        "feed_pressure_units": str(row.get("feed_pressure_units") or "").strip(),
                        "feed_temperature": None,
                        "feed_temperature_units": "",
                        "run_type": str(row.get("run_type") or "").strip(),
                        "pulse_width": row.get("pulse_width"),
                        "pulse_width_on": row.get("pulse_width"),
                        "control_period": row.get("control_period"),
                        "suppression_voltage": None,
                        "enabled": bool(row.get("enabled", True)),
                    }
                )
                program_mappings[TD_SUPPORT_DEFAULT_PROGRAM_TITLE].append(
                    {
                        "program_title": TD_SUPPORT_DEFAULT_PROGRAM_TITLE,
                        "sheet_name": programs[0]["sheet_name"],
                        "source_run_name": str(row.get("source_run_name") or cond_key).strip(),
                        "condition_key": cond_key,
                        "exclude_first_n": row.get("exclude_first_n"),
                        "last_n_rows": row.get("last_n_rows"),
                        "enabled": bool(row.get("enabled", True)),
                    }
                )

        if not condition_bounds and "ParameterBounds" in wb.sheetnames:
            ws = wb["ParameterBounds"]
            headers: dict[str, int] = {}
            for col in range(1, (ws.max_column or 0) + 1):
                key = str(ws.cell(1, col).value or "").strip().lower()
                if key:
                    headers[key] = col
            for row in range(2, (ws.max_row or 0) + 1):
                seq_name = str(ws.cell(row, headers.get("sequence_name", 1)).value or "").strip()
                pname = str(ws.cell(row, headers.get("parameter_name", 2)).value or "").strip()
                if not seq_name or not pname:
                    continue
                enabled_raw = ws.cell(row, headers.get("enabled", 6)).value if headers.get("enabled") else True
                enabled = True
                if enabled_raw is not None and str(enabled_raw).strip() != "":
                    enabled = _td_bool(enabled_raw, True)
                condition_bounds.setdefault(seq_name, {})[pname] = {
                    "condition_key": seq_name,
                    "parameter_name": pname,
                    "units": str(ws.cell(row, headers.get("units", 3)).value or "").strip(),
                    "min_value": _td_finite_float(ws.cell(row, headers.get("min_value", 4)).value if headers.get("min_value") else None),
                    "max_value": _td_finite_float(ws.cell(row, headers.get("max_value", 5)).value if headers.get("max_value") else None),
                    "enabled": bool(enabled),
                }

        run_conditions_by_key: dict[str, dict] = {}
        for row in run_conditions:
            key = str(row.get("condition_key") or "").strip()
            if key and key not in run_conditions_by_key:
                run_conditions_by_key[key] = dict(row)

        full_program_rows = [
            dict(row)
            for rows in program_mappings.values()
            for row in (rows or [])
            if isinstance(row, dict)
        ]
        has_new_program_schema = bool(new_program_schema_detected)

        condition_group_diagnostics = {
            "full_promoted": 0,
            "source_label_promoted": 0,
            "fallback_promoted": 0,
            "dropped": 0,
            "disabled_rows": 0,
        }
        sequences: list[dict] = []
        if has_new_program_schema:
            grouped_conditions = _td_group_program_rows_into_conditions(
                full_program_rows,
                diagnostics=condition_group_diagnostics,
            )
            run_conditions = [
                {
                    "condition_key": str(group.get("condition_key") or "").strip(),
                    "display_name": str(group.get("display_name") or "").strip(),
                    "feed_pressure": group.get("feed_pressure"),
                    "feed_pressure_units": str(group.get("feed_pressure_units") or "").strip(),
                    "feed_temperature": group.get("feed_temperature"),
                    "feed_temperature_units": str(group.get("feed_temperature_units") or "").strip(),
                    "run_type": str(group.get("run_type") or "").strip(),
                    "pulse_width": group.get("pulse_width_on"),
                    "pulse_width_on": group.get("pulse_width_on"),
                    "control_period": group.get("control_period"),
                    "suppression_voltage": group.get("suppression_voltage"),
                    "valve_voltage": group.get("valve_voltage"),
                    "member_suppression_voltages": list(group.get("member_suppression_voltages") or []),
                    "member_valve_voltages": list(group.get("member_valve_voltages") or []),
                    "sheet_name": str(group.get("sheet_name") or "").strip(),
                    "member_sequences_text": ", ".join([str(v).strip() for v in (group.get("member_sequences") or []) if str(v).strip()]),
                    "member_programs_text": ", ".join([str(v).strip() for v in (group.get("member_programs") or []) if str(v).strip()]),
                    "enabled": True,
                }
                for group in grouped_conditions
            ]
            for group in grouped_conditions:
                condition_key = str(group.get("condition_key") or "").strip()
                display_name = str(group.get("display_name") or condition_key).strip() or condition_key
                for member in (group.get("member_rows") or []):
                    if not isinstance(member, dict):
                        continue
                    sequences.append(
                        {
                            "sequence_name": condition_key,
                            "condition_key": condition_key,
                            "display_name": display_name,
                            "source_run_name": str(member.get("source_run_name") or "").strip(),
                            "program_title": str(member.get("program_title") or "").strip(),
                            "feed_pressure": group.get("feed_pressure"),
                            "feed_pressure_units": str(group.get("feed_pressure_units") or "").strip(),
                            "feed_temperature": group.get("feed_temperature"),
                            "feed_temperature_units": str(group.get("feed_temperature_units") or "").strip(),
                            "run_type": str(group.get("run_type") or "").strip(),
                            "pulse_width": group.get("pulse_width_on"),
                            "pulse_width_on": group.get("pulse_width_on"),
                            "control_period": group.get("control_period"),
                            "suppression_voltage": member.get("suppression_voltage"),
                            "valve_voltage": member.get("valve_voltage"),
                            "exclude_first_n": member.get("exclude_first_n"),
                            "last_n_rows": member.get("last_n_rows"),
                            "enabled": bool(member.get("enabled", True)),
                        }
                    )
        else:
            for program_title, rows in program_mappings.items():
                for row in rows:
                    if not isinstance(row, dict):
                        continue
                    condition_key = str(row.get("condition_key") or "").strip()
                    condition = dict(run_conditions_by_key.get(condition_key) or {})
                    sequences.append(
                        {
                            "sequence_name": condition_key,
                            "condition_key": condition_key,
                            "display_name": str(condition.get("display_name") or condition_key).strip() or condition_key,
                            "source_run_name": str(row.get("source_run_name") or condition_key).strip() or condition_key,
                            "program_title": str(program_title or "").strip(),
                            "feed_pressure": condition.get("feed_pressure"),
                            "feed_pressure_units": str(condition.get("feed_pressure_units") or "").strip(),
                            "feed_temperature": condition.get("feed_temperature"),
                            "feed_temperature_units": str(condition.get("feed_temperature_units") or "").strip(),
                            "run_type": str(condition.get("run_type") or "").strip(),
                            "pulse_width": condition.get("pulse_width"),
                            "pulse_width_on": condition.get("pulse_width_on"),
                            "control_period": condition.get("control_period"),
                            "suppression_voltage": condition.get("suppression_voltage"),
                            "valve_voltage": condition.get("valve_voltage"),
                            "exclude_first_n": row.get("exclude_first_n"),
                            "last_n_rows": row.get("last_n_rows"),
                            "enabled": bool(row.get("enabled", True) and condition.get("enabled", True)),
                        }
                    )

        return {
            "path": str(support_path),
            "exists": True,
            "settings": settings,
            "programs": program_rows if program_rows else programs,
            "program_mappings": program_mappings,
            "run_conditions": run_conditions,
            "condition_groups": run_conditions,
            "condition_bounds": condition_bounds,
            "sequences": sequences,
            "bounds_by_sequence": condition_bounds,
            "condition_group_diagnostics": condition_group_diagnostics,
        }
    finally:
        try:
            wb.close()
        except Exception:
            pass


TD_GENERATED_DATA_HEADERS = ["Term", "Header", "GroupAfter", "Table Label", "ValueType", "Data Group", "Term Label", "Units", "Min", "Max"]


def _is_generated_td_data_sheet(ws: object) -> bool:
    try:
        actual = [str(ws.cell(1, idx).value or "").strip() for idx in range(1, len(TD_GENERATED_DATA_HEADERS) + 1)]
    except Exception:
        return False
    return actual == list(TD_GENERATED_DATA_HEADERS)


def _load_runtime_td_trend_config() -> dict:
    cfg = {}
    cfg_path = DEFAULT_EXCEL_TREND_CONFIG
    fallback_used = False
    tried: list[Path] = []
    for candidate in (DEFAULT_EXCEL_TREND_CONFIG, CENTRAL_EXCEL_TREND_CONFIG):
        if candidate in tried:
            continue
        tried.append(candidate)
        try:
            loaded = load_excel_trend_config(candidate)
        except Exception:
            loaded = {}
        if isinstance(loaded, dict) and loaded:
            cfg = dict(loaded)
            cfg_path = candidate
            fallback_used = candidate != DEFAULT_EXCEL_TREND_CONFIG
            break
    if not isinstance(cfg, dict):
        cfg = {}
    cols = [dict(c) for c in (cfg.get("columns") or []) if isinstance(c, dict)]
    stats = [str(s).strip().lower() for s in (cfg.get("statistics") or []) if str(s).strip()]
    stats = [s for s in stats if s in TD_ALLOWED_STATS]
    if not stats:
        stats = list(TD_DEFAULT_STATS_ORDER)
    return {
        "config": cfg,
        "columns": cols,
        "statistics": stats,
        "path": str(cfg_path),
        "fallback_used": bool(fallback_used),
    }


def _ordered_support_param_defs(
    *,
    sequence_names: list[str] | tuple[str, ...] | set[str] | None = None,
    sequence_name: str = "",
    support_cfg: dict,
    fallback_defs: list[dict],
) -> list[dict]:
    def _support_norm_name(s: object) -> str:
        return "".join(ch.lower() for ch in str(s or "").strip() if ch.isalnum())

    raw_names = list(sequence_names or [])
    if sequence_name:
        raw_names.insert(0, str(sequence_name or "").strip())
    resolved_names: list[str] = []
    seen_names: set[str] = set()
    for raw in raw_names:
        name = str(raw or "").strip()
        if not name:
            continue
        key = _support_norm_name(name)
        if not key or key in seen_names:
            continue
        seen_names.add(key)
        resolved_names.append(name)

    fallback_defs = [dict(d) for d in fallback_defs if isinstance(d, dict) and str(d.get("name") or "").strip()]
    fallback_by_name = {str(d.get("name") or "").strip(): dict(d) for d in fallback_defs}
    fallback_order = [str(d.get("name") or "").strip() for d in fallback_defs if str(d.get("name") or "").strip()]

    if not bool((support_cfg or {}).get("exists")):
        return fallback_defs

    bounds_by_sequence = (support_cfg or {}).get("bounds_by_sequence") or {}
    seq_bounds: dict[str, dict] = {}
    for name in resolved_names:
        seq_bounds = dict(bounds_by_sequence.get(name) or {})
        if seq_bounds:
            break
    if not seq_bounds:
        return []

    defs_by_name: dict[str, dict] = {}
    for raw_name, raw_bound in seq_bounds.items():
        name = str(raw_name or "").strip()
        bound = dict(raw_bound or {}) if isinstance(raw_bound, dict) else {}
        if not name or not bool(bound.get("enabled", True)):
            continue
        fallback = dict(fallback_by_name.get(name) or {})
        defs_by_name[name] = {
            "name": name,
            "units": str(bound.get("units") or fallback.get("units") or "").strip(),
            "min_value": bound.get("min_value"),
            "max_value": bound.get("max_value"),
            "enabled": bool(bound.get("enabled", True)),
        }

    ordered_names = [name for name in fallback_order if name in defs_by_name]
    ordered_names.extend(sorted([name for name in defs_by_name.keys() if name not in ordered_names], key=lambda s: str(s).lower()))
    return [defs_by_name[name] for name in ordered_names]


def _td_complete_calc_param_defs(
    *,
    ordered_defs: Sequence[Mapping[str, object]] | None,
    discovered_names: Sequence[object] | None,
    units_by_name: Mapping[str, object] | None = None,
    fallback_units: Mapping[str, object] | None = None,
) -> list[dict[str, object]]:
    out: list[dict[str, object]] = []
    seen_norms: set[str] = set()
    discovered_texts = [
        str(value or "").strip()
        for value in (discovered_names or [])
        if str(value or "").strip()
    ]
    units_map = {str(k).strip(): str(v or "").strip() for k, v in (units_by_name or {}).items() if str(k).strip()}
    fallback_map = {str(k).strip(): str(v or "").strip() for k, v in (fallback_units or {}).items() if str(k).strip()}

    def _append(name: str, payload: Mapping[str, object] | None = None) -> None:
        text = str(name or "").strip()
        if not text:
            return
        norm = _td_param_norm_name(text)
        if not norm or norm in seen_norms:
            return
        seen_norms.add(norm)
        row = dict(payload or {})
        row["name"] = text
        row["units"] = str(row.get("units") or units_map.get(text) or fallback_map.get(text) or "").strip()
        out.append(row)

    for item in (ordered_defs or []):
        if not isinstance(item, Mapping):
            continue
        _append(str(item.get("name") or "").strip(), item)
    for name in sorted(discovered_texts, key=str.casefold):
        _append(name, {"name": name})
    return out


def _raw_curve_points(*, rows: list[dict], actual_x: str, y_name: str) -> tuple[list[float], list[float]]:
    xs: list[float] = []
    ys: list[float] = []
    for row in rows:
        fx = _td_finite_float(row.get(actual_x))
        fy = _td_finite_float(row.get(y_name))
        if fx is None or fy is None:
            continue
        xs.append(float(fx))
        ys.append(float(fy))
    return xs, ys


def _raw_curve_points_multi(
    *,
    rows: list[dict],
    actual_x: str,
    y_columns_by_name: Mapping[str, str],
) -> dict[str, tuple[list[float], list[float]]]:
    series: dict[str, dict[str, object]] = {
        str(y_name): {"actual_y": str(actual_y), "xs": [], "ys": []}
        for y_name, actual_y in (y_columns_by_name or {}).items()
        if str(y_name).strip() and str(actual_y).strip()
    }
    if not actual_x or not series:
        return {}

    for row in rows:
        fx = _td_finite_float(row.get(actual_x))
        if fx is None:
            continue
        x_val = float(fx)
        for payload in series.values():
            actual_y = str(payload.get("actual_y") or "").strip()
            fy = _td_finite_float(row.get(actual_y))
            if fy is None:
                continue
            cast(list[float], payload["xs"]).append(x_val)
            cast(list[float], payload["ys"]).append(float(fy))

    return {
        y_name: (cast(list[float], payload["xs"]), cast(list[float], payload["ys"]))
        for y_name, payload in series.items()
    }


def _td_apply_last_n_rows_limit(values: list[T], last_n_rows: int | None) -> list[T]:
    if last_n_rows is None:
        return values
    try:
        limit = int(last_n_rows)
    except Exception:
        return values
    if limit <= 0:
        return values
    prior_rows = values[:-1]
    effective_limit = max(0, limit - 1)
    if effective_limit == 0:
        return []
    if len(prior_rows) <= effective_limit:
        return prior_rows
    return prior_rows[-effective_limit:]


def _td_filter_curve_values(
    xs: Sequence[object],
    ys: Sequence[object],
    *,
    exclude_first_n: int | None,
    last_n_rows: int | None,
) -> list[float]:
    filtered: list[float] = []
    for raw_x, raw_y in zip(xs, ys):
        fx = _td_finite_float(raw_x)
        fy = _td_finite_float(raw_y)
        if fx is None or fy is None:
            continue
        filtered.append(float(fy))
    if exclude_first_n is not None and int(exclude_first_n) > 0:
        filtered = filtered[int(exclude_first_n):]
    return _td_apply_last_n_rows_limit(filtered, last_n_rows)


def _read_test_data_run_labeling(workbook_path: Path) -> dict | None:
    """
    Read optional `td_run_labeling` JSON from the Test Data Trending workbook's Config sheet.

    Stored as a Key/Value row where Value is JSON (stringified).
    """
    try:
        from openpyxl import load_workbook  # type: ignore
    except Exception:
        return None

    wb = load_workbook(str(Path(workbook_path).expanduser()), read_only=True, data_only=True)
    try:
        if "Config" not in wb.sheetnames:
            return None
        ws = wb["Config"]
        for r in range(2, (ws.max_row or 0) + 1):
            k = str(ws.cell(r, 1).value or "").strip()
            if not k:
                continue
            if k.strip().lower() != "td_run_labeling":
                continue
            raw = ws.cell(r, 2).value
            if raw is None:
                return None
            try:
                data = json.loads(str(raw))
            except Exception:
                return None
            return data if isinstance(data, dict) else None
        return None
    finally:
        try:
            wb.close()
        except Exception:
            pass


def td_read_run_labeling_config(workbook_path: Path) -> dict | None:
    """Public wrapper for UI: read `td_run_labeling` config from a workbook."""
    try:
        return _read_test_data_run_labeling(workbook_path)
    except Exception:
        return None


def td_metric_bound_line_specs(bound: dict | None) -> list[dict]:
    """Return plot-ready horizontal bound lines for a metric bound definition."""
    if not isinstance(bound, dict) or not bool(bound.get("enabled", True)):
        return []
    out: list[dict] = []
    for key in ("min_value", "max_value"):
        value = bound.get(key)
        if not isinstance(value, (int, float)):
            continue
        out.append(
            {
                "value": float(value),
                "color": "red",
                "linestyle": "--",
                "alpha": 0.8,
                "linewidth": 1.2,
            }
        )
    return out


def _td_norm_name(value: object) -> str:
    return "".join(ch.lower() for ch in str(value or "").strip() if ch.isalnum())


def _td_format_compact_value(value: object) -> str:
    num = _to_support_number(value)
    if num is not None:
        if isinstance(num, int):
            return str(num)
        try:
            return f"{float(num):g}"
        except Exception:
            pass
    return str(value or "").strip()


def td_normalize_run_type(value: object) -> str:
    raw = str(value or "").strip()
    if not raw:
        return ""
    key = _td_norm_name(raw)
    if key in {"ss", "steadystate", "steady"}:
        return "SS"
    if key in {"pm", "pulsemode", "pulsedmode", "pulsed", "pulse"}:
        return "PM"
    return raw


def td_perf_normalize_run_type_mode(value: object) -> str:
    raw = str(value or "").strip().lower()
    if raw in {"steady_state", "steady-state", "steadystate", "steady state", "ss", "steady_state_only"}:
        return "steady_state"
    if raw in {"pulsed_mode", "pulsed-mode", "pulsedmode", "pulsed mode", "pm", "pulse", "pm_only"}:
        return "pulsed_mode"
    return "all_conditions"


def td_perf_run_type_mode_label(value: object) -> str:
    mode = td_perf_normalize_run_type_mode(value)
    if mode == "steady_state":
        return "Steady-state"
    if mode == "pulsed_mode":
        return "Pulsed mode"
    return "All run conditions"


TD_PERF_PLOT_METHOD_LEGACY_SERIAL_CURVES = "legacy_serial_curves"
TD_PERF_PLOT_METHOD_CACHED_CONDITION_MEANS = "cached_condition_means"


def td_perf_normalize_plot_method(value: object) -> str:
    raw = str(value or "").strip().lower()
    if raw == TD_PERF_PLOT_METHOD_CACHED_CONDITION_MEANS:
        return TD_PERF_PLOT_METHOD_CACHED_CONDITION_MEANS
    return TD_PERF_PLOT_METHOD_LEGACY_SERIAL_CURVES


def td_perf_plot_method_label(value: object) -> str:
    normalized = td_perf_normalize_plot_method(value)
    if normalized == TD_PERF_PLOT_METHOD_CACHED_CONDITION_MEANS:
        return "Run Conditions"
    return "Legacy Serial Curves"


def _td_perf_run_type_sql_key(column_expr: str) -> str:
    return (
        f"lower(replace(replace(replace(replace(trim(COALESCE({column_expr}, '')), '-', ''), ' ', ''), '/', ''), '_', ''))"
    )


def _td_perf_run_type_sql_clause(mode: object, column_expr: str) -> tuple[str, list[object]]:
    normalized = td_perf_normalize_run_type_mode(mode)
    key_expr = _td_perf_run_type_sql_key(column_expr)
    if normalized == "pulsed_mode":
        return (
            f" AND {key_expr} IN ('pm', 'pulsemode', 'pulsedmode', 'pulsed', 'pulse')",
            [],
        )
    if normalized == "steady_state":
        return (
            f" AND {key_expr} NOT IN ('pm', 'pulsemode', 'pulsedmode', 'pulsed', 'pulse')",
            [],
        )
    return "", []


def td_build_run_condition_label(sequence_row: dict | None) -> str:
    if not isinstance(sequence_row, dict):
        return ""
    parts: list[str] = []
    pressure = _td_format_compact_value(sequence_row.get("feed_pressure"))
    pressure_units = str(sequence_row.get("feed_pressure_units") or "").strip()
    if pressure:
        parts.append(" ".join(x for x in (pressure, pressure_units) if x).strip())
    run_type = td_normalize_run_type(sequence_row.get("run_type"))
    if run_type:
        parts.append(run_type)
    if run_type == "PM":
        on_time = _td_format_compact_value(_td_support_sequence_pulse_width(sequence_row))
        off_time = ""
        on_numeric = _td_finite_float(_td_support_sequence_pulse_width(sequence_row))
        control_period_numeric = _td_finite_float(sequence_row.get("control_period"))
        if on_numeric is not None and control_period_numeric is not None and control_period_numeric >= on_numeric:
            off_time = _td_format_compact_value(control_period_numeric - on_numeric)
        elif sequence_row.get("off_time") not in (None, ""):
            off_time = _td_format_compact_value(sequence_row.get("off_time"))
        timing = ""
        if on_time and off_time:
            timing = f"{on_time} Sec ON / {off_time} Sec OFF"
        elif on_time:
            timing = f"{on_time} Sec ON"
        elif control_period_numeric is not None:
            timing = f"{_td_format_compact_value(control_period_numeric)} Sec Period"
        if timing:
            parts.append(timing)
    return ", ".join(part for part in parts if str(part).strip())


def _td_effective_run_condition_label(
    row: Mapping[str, object] | None,
    *,
    fallback_display_name: object = "",
) -> str:
    if not isinstance(row, Mapping):
        return str(fallback_display_name or "").strip()
    derived = td_build_run_condition_label(dict(row))
    if derived:
        return derived
    for candidate in (
        fallback_display_name,
        row.get("display_name"),
        row.get("condition_key"),
        row.get("run_name"),
        row.get("sequence_name"),
        row.get("source_run_name"),
    ):
        text = str(candidate or "").strip()
        if text:
            return text
    return ""


def _td_support_enabled_programs(support_cfg: dict) -> list[dict]:
    return [
        dict(row)
        for row in ((support_cfg or {}).get("programs") or [])
        if isinstance(row, dict) and bool(row.get("enabled", True)) and str(row.get("program_title") or "").strip()
    ]


def _td_support_run_conditions_by_key(support_cfg: dict) -> dict[str, dict]:
    out: dict[str, dict] = {}
    for row in ((support_cfg or {}).get("run_conditions") or []):
        if not isinstance(row, dict) or not bool(row.get("enabled", True)):
            continue
        key = str(row.get("condition_key") or "").strip()
        if key and key not in out:
            out[key] = dict(row)
    return out


def _td_support_match_program_title(program_title: object, support_cfg: dict) -> str:
    raw = str(program_title or "").strip()
    programs = _td_support_enabled_programs(support_cfg)
    if not programs:
        return raw or TD_SUPPORT_DEFAULT_PROGRAM_TITLE
    raw_norm = _td_support_norm_name(raw)
    if raw_norm:
        for row in programs:
            title = str(row.get("program_title") or "").strip()
            if title and _td_support_norm_name(title) == raw_norm:
                return title
    if raw:
        return raw
    return str(programs[0].get("program_title") or TD_SUPPORT_DEFAULT_PROGRAM_TITLE).strip() or TD_SUPPORT_DEFAULT_PROGRAM_TITLE


def _td_support_program_mappings(program_title: object, support_cfg: dict) -> list[dict]:
    want = _td_support_match_program_title(program_title, support_cfg)
    mappings_raw = (support_cfg or {}).get("program_mappings") or {}
    if isinstance(mappings_raw, dict):
        for title, rows in mappings_raw.items():
            if _td_support_norm_name(title) != _td_support_norm_name(want):
                continue
            return [dict(row) for row in (rows or []) if isinstance(row, dict) and bool(row.get("enabled", True))]
    return []


def _td_resolved_support_condition_payload(
    *,
    program_title: str,
    source_run_name: str,
    condition_key: str,
    support_cfg: dict,
    mapping: dict | None = None,
) -> dict:
    conditions_by_key = _td_support_run_conditions_by_key(support_cfg)
    resolved_condition_key = str(condition_key or "").strip() or str(source_run_name or "").strip()
    condition = dict(conditions_by_key.get(resolved_condition_key) or {})
    if not condition and isinstance(mapping, dict):
        derived_condition_key = td_build_run_condition_key(dict(mapping))
        if derived_condition_key:
            resolved_condition_key = derived_condition_key
            condition = dict(conditions_by_key.get(resolved_condition_key) or {})
    payload = {
        "program_title": str(program_title or "").strip(),
        "condition_key": resolved_condition_key,
        "sequence_name": resolved_condition_key,
        "source_run_name": str(source_run_name or "").strip(),
        "feed_pressure": condition.get("feed_pressure", (mapping or {}).get("feed_pressure")),
        "feed_pressure_units": str(condition.get("feed_pressure_units") or (mapping or {}).get("feed_pressure_units") or "").strip(),
        "feed_temperature": condition.get("feed_temperature", (mapping or {}).get("feed_temperature")),
        "feed_temperature_units": str(condition.get("feed_temperature_units") or (mapping or {}).get("feed_temperature_units") or "").strip(),
        "run_type": str(condition.get("run_type") or (mapping or {}).get("run_type") or "").strip(),
        "pulse_width": condition.get("pulse_width", (mapping or {}).get("pulse_width")),
        "pulse_width_on": condition.get("pulse_width_on", condition.get("pulse_width", (mapping or {}).get("pulse_width_on", (mapping or {}).get("pulse_width")))),
        "control_period": condition.get("control_period", (mapping or {}).get("control_period")),
        "suppression_voltage": condition.get("suppression_voltage", (mapping or {}).get("suppression_voltage")),
        "valve_voltage": condition.get("valve_voltage", (mapping or {}).get("valve_voltage")),
        "exclude_first_n": (mapping or {}).get("exclude_first_n"),
        "last_n_rows": (mapping or {}).get("last_n_rows"),
        "matched_support": bool(mapping or condition),
    }
    display_name = _td_effective_run_condition_label(
        payload,
        fallback_display_name=(
            condition.get("display_name")
            or (mapping or {}).get("display_name")
            or resolved_condition_key
            or source_run_name
        ),
    )
    payload["display_name"] = display_name
    payload["source_run_name"] = str(source_run_name or "").strip() or display_name
    return payload


def _td_resolve_support_condition_for_source(program_title: object, source_run_name: object, support_cfg: dict) -> dict:
    source_run = str(source_run_name or "").strip()
    matched_program = _td_support_match_program_title(program_title, support_cfg)
    if not source_run:
        return _td_resolved_support_condition_payload(
            program_title=matched_program,
            source_run_name="",
            condition_key="",
            support_cfg=support_cfg,
            mapping=None,
        )

    run_norm = _td_support_norm_name(source_run)
    mappings = _td_support_program_mappings(matched_program, support_cfg)
    for row in mappings:
        source_match = str(row.get("source_run_name") or "").strip()
        if source_match and _td_support_norm_name(source_match) == run_norm:
            return _td_resolved_support_condition_payload(
                program_title=matched_program,
                source_run_name=source_match,
                condition_key=str(row.get("condition_key") or source_match).strip() or source_match,
                support_cfg=support_cfg,
                mapping=row,
            )

    for row in mappings:
        condition_key = str(row.get("condition_key") or "").strip()
        if condition_key and _td_support_norm_name(condition_key) == run_norm:
            return _td_resolved_support_condition_payload(
                program_title=matched_program,
                source_run_name=str(row.get("source_run_name") or condition_key).strip() or condition_key,
                condition_key=condition_key,
                support_cfg=support_cfg,
                mapping=row,
            )

    conditions_by_key = _td_support_run_conditions_by_key(support_cfg)
    for condition_key, row in conditions_by_key.items():
        if _td_support_norm_name(condition_key) == run_norm or _td_support_norm_name(row.get("display_name")) == run_norm:
            return _td_resolved_support_condition_payload(
                program_title=matched_program,
                source_run_name=source_run,
                condition_key=condition_key,
                support_cfg=support_cfg,
                mapping=None,
            )

    return {
        "program_title": matched_program,
        "condition_key": source_run,
        "sequence_name": source_run,
        "display_name": source_run,
        "source_run_name": source_run,
        "feed_pressure": None,
        "feed_pressure_units": "",
        "feed_temperature": None,
        "feed_temperature_units": "",
        "run_type": "",
        "pulse_width": None,
        "pulse_width_on": None,
        "control_period": None,
        "suppression_voltage": None,
        "valve_voltage": None,
        "exclude_first_n": None,
        "last_n_rows": None,
        "matched_support": False,
    }


def _td_display_program_title(value: object) -> str:
    return str(value or "").strip() or "Unknown Program"


def td_list_run_selection_views(db_path: Path, workbook_path: Path, *, project_dir: Path | None = None) -> dict[str, list[dict]]:
    del workbook_path
    del project_dir
    runs_ex = [
        dict(item)
        for item in (td_list_runs_ex(db_path) or [])
        if isinstance(item, dict) and str(item.get("run_name") or "").strip()
    ]
    if not runs_ex:
        return {"sequence": [], "condition": []}

    observations_by_condition: dict[str, list[dict]] = {}
    run_type_mode_by_run: dict[str, str] = {}
    run_type_by_run: dict[str, str] = {}
    with closing(sqlite3.connect(str(Path(db_path).expanduser()))) as conn:
        _ensure_test_data_impl_tables(conn)
        for run_name, run_type in conn.execute(
            "SELECT run_name, COALESCE(run_type, '') FROM td_runs ORDER BY run_name"
        ).fetchall():
            run_key = str(run_name or "").strip()
            if not run_key:
                continue
            run_type_label = td_normalize_run_type(run_type)
            run_type_mode = td_perf_normalize_run_type_mode(run_type)
            run_type_by_run[run_key] = run_type_label if run_type_label in {"SS", "PM"} else ""
            run_type_mode_by_run[run_key] = run_type_mode if run_type_mode in {"steady_state", "pulsed_mode"} else ""
        obs_table = _td_preferred_sequence_observation_table(conn)
        rows = conn.execute(
            f"""
            SELECT run_name, COALESCE(program_title, ''), COALESCE(source_run_name, ''), control_period, suppression_voltage, valve_voltage, COALESCE(run_type, '')
            FROM {obs_table}
            ORDER BY run_name, program_title, source_run_name, observation_id
            """
        ).fetchall()
    for run_name, program_title, source_run_name, control_period, suppression_voltage, valve_voltage, run_type in rows:
        run_key = str(run_name or "").strip()
        if not run_key:
            continue
        seq_name = str(source_run_name or "").strip() or run_key
        run_type_label = td_normalize_run_type(run_type)
        run_type_mode = td_perf_normalize_run_type_mode(run_type)
        observations_by_condition.setdefault(run_key, []).append(
            {
                "program_title": str(program_title or "").strip(),
                "program_label": _td_display_program_title(program_title),
                "source_run_name": seq_name,
                "control_period": control_period,
                "control_period_label": _td_format_compact_value(control_period),
                "suppression_voltage": suppression_voltage,
                "suppression_voltage_label": _td_format_compact_value(suppression_voltage),
                "valve_voltage": valve_voltage,
                "valve_voltage_label": _td_format_compact_value(valve_voltage),
                "run_type": run_type_label if run_type_label in {"SS", "PM"} else "",
                "run_type_mode": run_type_mode if run_type_mode in {"steady_state", "pulsed_mode"} else "",
            }
        )

    sequence_items: list[dict] = []
    condition_items: list[dict] = []
    for item in runs_ex:
        run_name = str(item.get("run_name") or "").strip()
        if not run_name:
            continue
        run_display_name = str(item.get("display_name") or run_name).strip() or run_name
        source_rows = list(observations_by_condition.get(run_name) or [])
        member_sequences: list[str] = []
        member_programs: list[str] = []
        member_control_periods: list[str] = []
        member_suppression_voltages: list[str] = []
        member_valve_voltages: list[str] = []
        member_run_types: list[str] = []
        member_run_type_modes: list[str] = []
        detail_rows: list[str] = []
        seen_sequence_labels: set[str] = set()
        seen_program_labels: set[str] = set()
        seen_control_period_labels: set[str] = set()
        seen_suppression_labels: set[str] = set()
        seen_valve_labels: set[str] = set()
        seen_run_type_labels: set[str] = set()
        seen_run_type_modes: set[str] = set()
        for obs in source_rows:
            program_title = str(obs.get("program_title") or "").strip()
            program_label = str(obs.get("program_label") or "").strip() or _td_display_program_title(program_title)
            source_run_name = str(obs.get("source_run_name") or "").strip() or run_name
            control_period = obs.get("control_period")
            control_period_label = str(obs.get("control_period_label") or "").strip()
            suppression_voltage = obs.get("suppression_voltage")
            suppression_voltage_label = str(obs.get("suppression_voltage_label") or "").strip()
            valve_voltage = obs.get("valve_voltage")
            valve_voltage_label = str(obs.get("valve_voltage_label") or "").strip()
            run_type_label = str(obs.get("run_type") or "").strip()
            run_type_mode = str(obs.get("run_type_mode") or "").strip()
            detail = source_run_name if not program_title else f"{program_title}: {source_run_name}"
            detail_rows.append(detail)
            if source_run_name.lower() not in seen_sequence_labels:
                seen_sequence_labels.add(source_run_name.lower())
                member_sequences.append(source_run_name)
            if program_label.casefold() not in seen_program_labels:
                seen_program_labels.add(program_label.casefold())
                member_programs.append(program_label)
            if control_period_label and control_period_label.casefold() not in seen_control_period_labels:
                seen_control_period_labels.add(control_period_label.casefold())
                member_control_periods.append(control_period_label)
            if suppression_voltage_label and suppression_voltage_label.casefold() not in seen_suppression_labels:
                seen_suppression_labels.add(suppression_voltage_label.casefold())
                member_suppression_voltages.append(suppression_voltage_label)
            if valve_voltage_label and valve_voltage_label.casefold() not in seen_valve_labels:
                seen_valve_labels.add(valve_voltage_label.casefold())
                member_valve_voltages.append(valve_voltage_label)
            if run_type_label and run_type_label not in seen_run_type_labels:
                seen_run_type_labels.add(run_type_label)
                member_run_types.append(run_type_label)
            if run_type_mode and run_type_mode not in seen_run_type_modes:
                seen_run_type_modes.add(run_type_mode)
                member_run_type_modes.append(run_type_mode)
            sequence_items.append(
                {
                    "mode": "sequence",
                    "id": "sequence:" + "|".join([run_name, program_title or TD_SUPPORT_DEFAULT_PROGRAM_TITLE, source_run_name]),
                    "run_name": run_name,
                    "sequence_name": source_run_name,
                    "source_run_name": source_run_name,
                    "program_title": program_title,
                    "display_text": source_run_name if not program_title else f"{program_title} - {source_run_name}",
                    "run_condition": run_display_name,
                    "member_runs": [run_name],
                    "member_programs": [program_label],
                    "member_sequences": [source_run_name],
                    "control_period": control_period,
                    "member_control_periods": ([control_period_label] if control_period_label else []),
                    "suppression_voltage": suppression_voltage,
                    "member_suppression_voltages": ([suppression_voltage_label] if suppression_voltage_label else []),
                    "valve_voltage": valve_voltage,
                    "member_valve_voltages": ([valve_voltage_label] if valve_voltage_label else []),
                    "run_type": run_type_label,
                    "run_type_mode": run_type_mode,
                    "member_run_types": ([run_type_label] if run_type_label else []),
                    "member_run_type_modes": ([run_type_mode] if run_type_mode else []),
                    "details_text": (
                        f"Program: {program_title or TD_SUPPORT_DEFAULT_PROGRAM_TITLE} | "
                        f"Source Sequence: {source_run_name} | Run Condition: {run_display_name}"
                    ),
                }
            )
        if not source_rows:
            fallback_run_type = str(run_type_by_run.get(run_name) or "").strip()
            fallback_run_type_mode = str(run_type_mode_by_run.get(run_name) or "").strip()
            sequence_items.append(
                {
                    "mode": "sequence",
                    "id": f"sequence:{run_name}",
                    "run_name": run_name,
                    "sequence_name": run_name,
                    "source_run_name": run_name,
                    "program_title": "",
                    "display_text": run_name,
                    "run_condition": run_display_name,
                    "member_runs": [run_name],
                    "member_programs": [_td_display_program_title("")],
                    "member_sequences": [run_name],
                    "control_period": None,
                    "member_control_periods": [],
                    "suppression_voltage": None,
                    "member_suppression_voltages": [],
                    "valve_voltage": None,
                    "member_valve_voltages": [],
                    "run_type": fallback_run_type,
                    "run_type_mode": fallback_run_type_mode,
                    "member_run_types": ([fallback_run_type] if fallback_run_type else []),
                    "member_run_type_modes": ([fallback_run_type_mode] if fallback_run_type_mode else []),
                    "details_text": f"Run Condition: {run_display_name}",
                }
            )
            member_sequences = [run_name]
            member_programs = [_td_display_program_title("")]
            member_control_periods = []
            member_suppression_voltages = []
            member_valve_voltages = []
            member_run_types = [fallback_run_type] if fallback_run_type else []
            member_run_type_modes = [fallback_run_type_mode] if fallback_run_type_mode else []
            detail_rows = [run_name]
        condition_items.append(
            {
                "mode": "condition",
                "id": f"condition:{run_name}",
                "run_name": run_name,
                "display_text": run_display_name,
                "run_condition": run_display_name,
                "member_runs": [run_name],
                "member_programs": list(member_programs or [_td_display_program_title("")]),
                "member_sequences": member_sequences,
                "control_period": (member_control_periods[0] if len(member_control_periods) == 1 else None),
                "member_control_periods": list(member_control_periods),
                "suppression_voltage": (member_suppression_voltages[0] if len(member_suppression_voltages) == 1 else None),
                "member_suppression_voltages": list(member_suppression_voltages),
                "valve_voltage": (member_valve_voltages[0] if len(member_valve_voltages) == 1 else None),
                "member_valve_voltages": list(member_valve_voltages),
                "run_type": (member_run_types[0] if len(member_run_types) == 1 else ""),
                "run_type_mode": (member_run_type_modes[0] if len(member_run_type_modes) == 1 else ""),
                "member_run_types": list(member_run_types),
                "member_run_type_modes": list(member_run_type_modes),
                "details_text": "Source Sequences: " + ", ".join(detail_rows),
            }
        )

    sequence_items.sort(
        key=lambda d: (
            str(d.get("run_condition") or "").lower(),
            str(d.get("program_title") or "").lower(),
            str(d.get("sequence_name") or "").lower(),
        )
    )
    deduped_sequence_items: list[dict] = []
    seen_sequence_ids: set[str] = set()
    for item in sequence_items:
        key = "|".join(
            [
                str(item.get("run_name") or "").strip().lower(),
                str(item.get("program_title") or "").strip().lower(),
                str(item.get("sequence_name") or "").strip().lower(),
            ]
        )
        if key in seen_sequence_ids:
            continue
        seen_sequence_ids.add(key)
        deduped_sequence_items.append(item)
    sequence_items = deduped_sequence_items
    condition_items.sort(key=lambda d: str(d.get("display_text") or "").lower())
    return {"sequence": sequence_items, "condition": condition_items}


def td_list_runs_ex(db_path: Path) -> list[dict]:
    """Return runs with optional display_name for UI dropdowns."""
    path = Path(db_path).expanduser()
    if not path.exists():
        return []
    with closing(sqlite3.connect(str(path))) as conn:
        _ensure_test_data_impl_tables(conn)
        rows = conn.execute(
            "SELECT run_name, display_name FROM td_runs ORDER BY run_name"
        ).fetchall()
    out: list[dict] = []
    for run_name, display_name in rows:
        rn = str(run_name or "").strip()
        if not rn:
            continue
        dn = str(display_name or "").strip()
        out.append({"run_name": rn, "display_name": dn})
    return out


def _td_project_cache_refresh_mode(
    *,
    stale_context: bool,
    curve_count: int,
    raw_complete: bool,
    impl_complete: bool,
    expected_serials: set[str],
    cached_serials: set[str],
    cached_stats_csv: str,
    current_stats_csv: str,
    cached_raw_cols_csv: str,
    current_raw_cols_csv: str,
    cached_support_raw_signature: str,
    support_raw_signature: str,
    cached_support_calc_signature: str,
    support_calc_signature: str,
    cached_builder_signature: str,
    builder_signature: str,
    source_state_stale: bool,
) -> tuple[str, str]:
    if stale_context:
        return "full", "context changed"
    if cached_builder_signature and cached_builder_signature != builder_signature:
        return "full", "TD builder logic changed"
    if not raw_complete and (expected_serials or cached_serials or curve_count > 0):
        return "full", "raw cache is incomplete"
    if curve_count <= 0 and expected_serials:
        return "full", "raw cache is empty"
    if cached_raw_cols_csv != current_raw_cols_csv:
        return "full", "configured raw columns changed"
    if cached_support_raw_signature and cached_support_raw_signature != support_raw_signature:
        return "full", "support workbook raw inputs changed"
    if source_state_stale:
        return "incremental_raw", "source SQLite inputs changed"
    if expected_serials and expected_serials != cached_serials:
        return "incremental_raw", "source serial set changed"
    if raw_complete and not impl_complete:
        return "calc", "implementation cache is incomplete"
    if cached_stats_csv != current_stats_csv:
        return "calc", "selected statistics changed"
    if cached_support_calc_signature and cached_support_calc_signature != support_calc_signature:
        return "calc", "support workbook calculation inputs changed"
    return "none", ""


def _td_meta_value(conn: sqlite3.Connection, key: str) -> str:
    try:
        row = conn.execute("SELECT value FROM td_meta WHERE key=? LIMIT 1", (str(key),)).fetchone()
    except Exception:
        return ""
    return str(row[0] or "").strip() if row and row[0] is not None else ""


def _td_impl_cache_counts(conn: sqlite3.Connection) -> dict[str, int | bool]:
    _ensure_test_data_impl_tables(conn)
    try:
        runs_count = int(conn.execute("SELECT COUNT(*) FROM td_runs").fetchone()[0] or 0)
    except Exception:
        runs_count = 0
    try:
        calc_y_count = int(conn.execute("SELECT COUNT(*) FROM td_columns_calc WHERE kind='y'").fetchone()[0] or 0)
    except Exception:
        calc_y_count = 0
    try:
        metrics_count = int(conn.execute("SELECT COUNT(*) FROM td_metrics_calc").fetchone()[0] or 0)
    except Exception:
        metrics_count = 0
    try:
        sequence_obs_count = int(
            conn.execute("SELECT COUNT(*) FROM td_condition_observations_sequences").fetchone()[0] or 0
        )
    except Exception:
        sequence_obs_count = 0
    try:
        sequence_metrics_count = int(
            conn.execute("SELECT COUNT(*) FROM td_metrics_calc_sequences").fetchone()[0] or 0
        )
    except Exception:
        sequence_metrics_count = 0
    try:
        life_metrics_count = int(conn.execute(f"SELECT COUNT(*) FROM {TD_LIFE_METRICS_TABLE}").fetchone()[0] or 0)
    except Exception:
        life_metrics_count = 0
    return {
        "runs": runs_count,
        "calc_y": calc_y_count,
        "metrics": metrics_count,
        "sequence_observations": sequence_obs_count,
        "sequence_metrics": sequence_metrics_count,
        "life_metrics": life_metrics_count,
        "complete": bool(
            runs_count > 0
            and calc_y_count > 0
            and metrics_count > 0
            and sequence_obs_count > 0
            and sequence_metrics_count > 0
            and life_metrics_count > 0
        ),
    }


def _td_parameter_runtime_counts(conn: sqlite3.Connection) -> dict[str, int | bool]:
    _ensure_test_data_impl_tables(conn)
    try:
        discovery_rows = int(conn.execute(f"SELECT COUNT(*) FROM {TD_PARAM_DISCOVERY_TABLE}").fetchone()[0] or 0)
    except Exception:
        discovery_rows = 0
    try:
        norm_groups = int(conn.execute(f"SELECT COUNT(*) FROM {TD_PARAM_NORM_GROUPS_TABLE}").fetchone()[0] or 0)
    except Exception:
        norm_groups = 0
    try:
        norm_rules = int(conn.execute(f"SELECT COUNT(*) FROM {TD_PARAM_NORM_RULES_TABLE}").fetchone()[0] or 0)
    except Exception:
        norm_rules = 0
    try:
        runtime_entries = int(conn.execute(f"SELECT COUNT(*) FROM {TD_PARAM_RUNTIME_ENTRIES_TABLE}").fetchone()[0] or 0)
    except Exception:
        runtime_entries = 0
    try:
        runtime_groups = int(conn.execute(f"SELECT COUNT(*) FROM {TD_PARAM_RUNTIME_GROUPS_TABLE}").fetchone()[0] or 0)
    except Exception:
        runtime_groups = 0
    discovery_signature = _td_meta_value(conn, TD_PARAM_DISCOVERY_SIGNATURE_META_KEY)
    runtime_signature = _td_meta_value(conn, TD_PARAM_RUNTIME_SIGNATURE_META_KEY)
    discovery_ready = _td_parameter_discovery_table_ready(conn, require_rows=True)
    runtime_ready = _td_parameter_runtime_tables_ready(conn, require_rows=True)
    return {
        "discovery_rows": discovery_rows,
        "norm_groups": norm_groups,
        "norm_rules": norm_rules,
        "runtime_entries": runtime_entries,
        "runtime_groups": runtime_groups,
        "discovery_signature_present": bool(discovery_signature),
        "runtime_signature_present": bool(runtime_signature),
        "discovery_ready": bool(discovery_ready),
        "runtime_ready": bool(runtime_ready),
        "complete": bool(discovery_ready and runtime_ready and discovery_signature and runtime_signature),
    }


def _td_raw_cache_counts(conn: sqlite3.Connection) -> dict[str, int | bool]:
    _ensure_test_data_raw_cache_tables(conn)
    try:
        raw_runs_count = int(conn.execute("SELECT COUNT(*) FROM td_raw_sequences").fetchone()[0] or 0)
    except Exception:
        raw_runs_count = 0
    try:
        raw_curve_count = int(conn.execute("SELECT COUNT(*) FROM td_curves_raw").fetchone()[0] or 0)
    except Exception:
        raw_curve_count = 0
    try:
        raw_y_count = int(conn.execute("SELECT COUNT(*) FROM td_columns_raw WHERE kind='y'").fetchone()[0] or 0)
    except Exception:
        raw_y_count = 0
    return {
        "raw_runs": raw_runs_count,
        "raw_curves": raw_curve_count,
        "raw_y": raw_y_count,
        "complete": bool(raw_runs_count > 0 and raw_curve_count > 0 and raw_y_count > 0),
    }


def _td_is_recoverable_cache_validation_error(exc: BaseException | str) -> bool:
    message = str(exc or "").strip()
    if not message:
        return False
    recoverable_markers = (
        "Project cache DB not found",
        "Project cache DB is incomplete",
        "Project parameter runtime cache is incomplete",
        "Project raw cache DB not found",
        "Project raw cache DB is incomplete",
        "Project cache is stale",
        "Project cache contains non-ok source rows",
        "Project workbook outputs are incomplete",
        "Project cache has no compiled Test Data sources",
    )
    return any(marker in message for marker in recoverable_markers)


def inspect_test_data_project_cache_state(project_dir: Path, workbook_path: Path) -> dict[str, object]:
    proj_dir = Path(project_dir).expanduser()
    wb_path = Path(workbook_path).expanduser()
    if not wb_path.exists():
        raise FileNotFoundError(f"Workbook not found: {wb_path}")

    db_path = proj_dir / EIDAT_PROJECT_IMPLEMENTATION_DB
    raw_db_path = td_raw_cache_db_path_for(proj_dir)
    db_path.parent.mkdir(parents=True, exist_ok=True)

    with closing(sqlite3.connect(str(db_path))) as conn:
        _ensure_test_data_impl_tables(conn)
        conn.commit()
    with closing(sqlite3.connect(str(raw_db_path))) as conn:
        _ensure_test_data_raw_cache_tables(conn)
        conn.commit()

    project_cfg = _load_project_td_trend_config(wb_path)
    current_stats_csv = ",".join(_td_normalize_selected_stats(project_cfg.get("statistics")))
    current_raw_cols_csv = ",".join(
        [str(c.get("name") or "").strip() for c in (project_cfg.get("columns") or []) if str(c.get("name") or "").strip()]
    )
    support_cfg = _read_td_support_workbook(wb_path, project_dir=proj_dir)
    support_signatures = _td_support_signatures(support_cfg)
    support_raw_signature = str(support_signatures.get("raw") or "").strip()
    support_calc_signature = str(support_signatures.get("calc") or "").strip()
    builder_signature = _td_builder_signature()
    project_raw_signature = _td_build_project_raw_signature(
        wb_path,
        raw_columns_csv=current_raw_cols_csv,
    )

    try:
        sources = _read_test_data_sources(wb_path)
    except Exception:
        sources = []
    source_states = [
        _td_source_runtime_state(
            wb_path,
            dict(source_row),
            project_raw_signature=project_raw_signature,
        )
        for source_row in sources
        if str(source_row.get("serial") or "").strip()
    ]
    expected_serials = {str(item.get("serial") or "").strip() for item in source_states if str(item.get("serial") or "").strip()}

    with closing(sqlite3.connect(str(db_path))) as conn:
        _ensure_test_data_impl_tables(conn)
        cached_sources_rows = conn.execute(
            "SELECT serial, sqlite_path, mtime_ns, size_bytes, status, last_ingested_epoch_ns, COALESCE(raw_fingerprint, '') FROM td_sources"
        ).fetchall()
        cached_sources = {
            str(row[0] or "").strip(): {
                "sqlite_path": str(row[1] or "").strip(),
                "mtime_ns": int(row[2] or 0),
                "size_bytes": int(row[3] or 0),
                "status": str(row[4] or "").strip().lower(),
                "last_ingested_epoch_ns": int(row[5] or 0),
                "raw_fingerprint": str(row[6] or "").strip(),
            }
            for row in cached_sources_rows
            if str(row[0] or "").strip()
        }
        cached_source_serial_numbers = {
            str(row[0] or "").strip(): str(row[1] or "").strip()
            for row in conn.execute(
                "SELECT serial, COALESCE(source_serial_number, '') FROM td_source_metadata"
            ).fetchall()
            if str(row[0] or "").strip()
        }
        cached_stats_csv = _td_meta_value(conn, "statistics")
        cached_raw_cols_csv = _td_meta_value(conn, "raw_columns")
        cached_support_raw_signature = _td_meta_value(conn, "support_raw_signature")
        cached_support_calc_signature = _td_meta_value(conn, "support_calc_signature")
        cached_builder_signature = _td_meta_value(conn, "td_builder_signature")
        cached_workbook_path = _td_meta_value(conn, "workbook_path")
        cached_node_root = _td_meta_value(conn, "node_root")
        cached_project_raw_signature = _td_meta_value(conn, "project_raw_signature")
        cached_schema_version = _td_meta_value(conn, "cache_schema_version")
        impl_counts = _td_impl_cache_counts(conn)
        parameter_runtime_counts = _td_parameter_runtime_counts(conn)
    with closing(sqlite3.connect(str(raw_db_path))) as conn:
        raw_counts = _td_raw_cache_counts(conn)
        curve_count = int(raw_counts.get("raw_curves") or 0)

    current_node_root = str(_infer_node_root_from_workbook_path(wb_path))
    stale_context = False
    try:
        stale_context = str(Path(cached_workbook_path).expanduser()) != str(wb_path)
    except Exception:
        stale_context = bool(cached_workbook_path) and cached_workbook_path != str(wb_path)
    if not stale_context and cached_node_root and cached_node_root != current_node_root:
        stale_context = True

    support_mtime_ns = 0
    try:
        support_path = td_support_workbook_path_for(wb_path, project_dir=proj_dir)
        if support_path.exists():
            st = support_path.stat()
            support_mtime_ns = int(getattr(st, "st_mtime_ns", int(st.st_mtime * 1e9)))
    except Exception:
        support_mtime_ns = 0

    added_serials: list[str] = []
    changed_serials: list[str] = []
    unchanged_serials: list[str] = []
    missing_serials: list[str] = []
    invalid_serials: list[str] = []
    source_rebuild_needed = False
    fingerprints_by_serial: dict[str, str] = {}
    source_state_by_serial: dict[str, dict[str, object]] = {}
    cached_keys_by_source_serial_number: dict[str, list[str]] = {}
    for cached_serial, source_serial_number in cached_source_serial_numbers.items():
        serial_number_key = str(source_serial_number or "").strip()
        if not serial_number_key:
            continue
        cached_keys_by_source_serial_number.setdefault(serial_number_key, []).append(cached_serial)
    matched_cached_serials: set[str] = set()
    comparison_expected_serials: set[str] = set()
    for item in source_states:
        serial = str(item.get("serial") or "").strip()
        if not serial:
            continue
        source_state_by_serial[serial] = dict(item)
        fingerprint = str(item.get("fingerprint") or "").strip()
        fingerprints_by_serial[serial] = fingerprint
        serial_number = str(item.get("serial_number") or "").strip()
        cached_serial = serial
        cached = cached_sources.get(cached_serial) or {}
        if not cached and serial_number and serial_number in cached_sources:
            cached_serial = serial_number
            cached = cached_sources.get(cached_serial) or {}
        if not cached and serial_number:
            alias_candidates = list(cached_keys_by_source_serial_number.get(serial_number) or [])
            if len(alias_candidates) == 1:
                cached_serial = alias_candidates[0]
                cached = cached_sources.get(cached_serial) or {}
        if cached_serial:
            comparison_expected_serials.add(cached_serial)
        else:
            comparison_expected_serials.add(serial)
        item_status = str(item.get("status") or "").strip().lower()
        if item_status == "missing":
            missing_serials.append(serial)
        elif item_status != "ok":
            invalid_serials.append(serial)
        if not cached:
            added_serials.append(serial)
            if item_status == "ok":
                source_rebuild_needed = True
            continue
        matched_cached_serials.add(cached_serial)
        cached_fingerprint = str(cached.get("raw_fingerprint") or "").strip()
        fingerprint_matches = cached_fingerprint == fingerprint
        if not fingerprint_matches and cached_serial and cached_serial != serial:
            fingerprint_matches = cached_fingerprint == _td_source_raw_fingerprint(
                source_key=cached_serial,
                serial_number=serial_number,
                status=str(item.get("status") or "").strip().lower(),
                sqlite_path=item.get("sqlite_path"),
                mtime_ns=int(item.get("mtime_ns") or 0),
                size_bytes=int(item.get("size_bytes") or 0),
                metadata_rel=str(item.get("metadata_rel") or "").strip(),
                artifacts_rel=str(item.get("artifacts_rel") or "").strip(),
                excel_sqlite_rel=str(item.get("excel_sqlite_rel") or "").strip(),
                metadata_mtime_ns=int((dict(item.get("source_meta") or {})).get("metadata_mtime_ns") or 0),
                project_raw_signature=project_raw_signature,
            )
        if not fingerprint_matches:
            changed_serials.append(serial)
            if item_status == "ok":
                source_rebuild_needed = True
            continue
        unchanged_serials.append(serial)

    removed_serials = sorted(set(cached_sources.keys()) - matched_cached_serials)
    source_state_stale = bool(source_rebuild_needed or removed_serials)
    if cached_schema_version != TD_PROJECT_CACHE_SCHEMA_VERSION:
        source_state_stale = True
        stale_context = True
    if cached_project_raw_signature and cached_project_raw_signature != project_raw_signature:
        stale_context = True

    refresh_mode, refresh_reason = _td_project_cache_refresh_mode(
        stale_context=bool(stale_context),
        curve_count=int(curve_count),
        raw_complete=bool(raw_counts.get("complete")),
        impl_complete=bool(impl_counts.get("complete")),
        expected_serials=set(comparison_expected_serials),
        cached_serials=set(cached_sources.keys()),
        cached_stats_csv=str(cached_stats_csv),
        current_stats_csv=str(current_stats_csv),
        cached_raw_cols_csv=str(cached_raw_cols_csv),
        current_raw_cols_csv=str(current_raw_cols_csv),
        cached_support_raw_signature=str(cached_support_raw_signature),
        support_raw_signature=str(support_raw_signature),
        cached_support_calc_signature=str(cached_support_calc_signature),
        support_calc_signature=str(support_calc_signature),
        cached_builder_signature=str(cached_builder_signature),
        builder_signature=str(builder_signature),
        source_state_stale=bool(source_state_stale),
    )
    return {
        "db_path": db_path,
        "raw_db_path": raw_db_path,
        "mode": refresh_mode,
        "reason": refresh_reason,
        "impl_counts": dict(impl_counts),
        "parameter_runtime_counts": dict(parameter_runtime_counts),
        "raw_counts": dict(raw_counts),
        "impl_complete": bool(impl_counts.get("complete")),
        "parameter_runtime_complete": bool(parameter_runtime_counts.get("complete")),
        "raw_complete": bool(raw_counts.get("complete")),
        "project_raw_signature": project_raw_signature,
        "current_stats_csv": current_stats_csv,
        "current_raw_cols_csv": current_raw_cols_csv,
        "support_raw_signature": support_raw_signature,
        "support_calc_signature": support_calc_signature,
        "builder_signature": builder_signature,
        "support_mtime_ns": int(support_mtime_ns),
        "source_states": source_states,
        "source_state_by_serial": source_state_by_serial,
        "fingerprints_by_serial": fingerprints_by_serial,
        "counts": {
            "added": len(added_serials),
            "changed": len(changed_serials),
            "removed": len(removed_serials),
            "unchanged": len(unchanged_serials),
            "missing": len(missing_serials),
            "invalid": len(invalid_serials),
            "non_ok": len(missing_serials) + len(invalid_serials),
            "reingested": len(added_serials) + len(changed_serials),
        },
        "added_serials": list(added_serials),
        "changed_serials": list(changed_serials),
        "removed_serials": list(removed_serials),
        "unchanged_serials": list(unchanged_serials),
        "missing_serials": list(missing_serials),
        "invalid_serials": list(invalid_serials),
    }


def _td_cache_state_summary(state: Mapping[str, object] | None) -> dict[str, object]:
    raw_state = dict(state or {})
    impl_counts_raw = raw_state.get("impl_counts") if isinstance(raw_state.get("impl_counts"), Mapping) else {}
    parameter_runtime_counts_raw = (
        raw_state.get("parameter_runtime_counts")
        if isinstance(raw_state.get("parameter_runtime_counts"), Mapping)
        else {}
    )
    raw_counts_raw = raw_state.get("raw_counts") if isinstance(raw_state.get("raw_counts"), Mapping) else {}
    sync_counts_raw = raw_state.get("counts") if isinstance(raw_state.get("counts"), Mapping) else {}
    return {
        "mode": str(raw_state.get("mode") or "").strip(),
        "reason": str(raw_state.get("reason") or "").strip(),
        "impl_complete": bool(raw_state.get("impl_complete")),
        "parameter_runtime_complete": bool(raw_state.get("parameter_runtime_complete")),
        "raw_complete": bool(raw_state.get("raw_complete")),
        "impl_counts": {
            "td_runs": int(impl_counts_raw.get("runs") or 0),
            "td_columns_calc_y": int(impl_counts_raw.get("calc_y") or 0),
            "td_metrics_calc": int(impl_counts_raw.get("metrics") or 0),
            "td_condition_observations_sequences": int(impl_counts_raw.get("sequence_observations") or 0),
            "td_metrics_calc_sequences": int(impl_counts_raw.get("sequence_metrics") or 0),
            "td_life_metrics": int(impl_counts_raw.get("life_metrics") or 0),
        },
        "parameter_runtime_counts": {
            "td_param_discovery": int(parameter_runtime_counts_raw.get("discovery_rows") or 0),
            "td_param_norm_groups": int(parameter_runtime_counts_raw.get("norm_groups") or 0),
            "td_param_norm_rules": int(parameter_runtime_counts_raw.get("norm_rules") or 0),
            "td_param_runtime_entries": int(parameter_runtime_counts_raw.get("runtime_entries") or 0),
            "td_param_runtime_groups": int(parameter_runtime_counts_raw.get("runtime_groups") or 0),
        },
        "raw_counts": {
            "td_raw_sequences": int(raw_counts_raw.get("raw_runs") or 0),
            "td_columns_raw_y": int(raw_counts_raw.get("raw_y") or 0),
            "td_curves_raw": int(raw_counts_raw.get("raw_curves") or 0),
        },
        "sync_counts": {
            "added": int(sync_counts_raw.get("added") or 0),
            "changed": int(sync_counts_raw.get("changed") or 0),
            "removed": int(sync_counts_raw.get("removed") or 0),
            "unchanged": int(sync_counts_raw.get("unchanged") or 0),
            "missing": int(sync_counts_raw.get("missing") or 0),
            "invalid": int(sync_counts_raw.get("invalid") or 0),
            "non_ok": int(sync_counts_raw.get("non_ok") or 0),
            "reingested": int(sync_counts_raw.get("reingested") or 0),
        },
    }


def _td_cache_validation_summary_line(summary: Mapping[str, object] | None) -> str:
    state = dict(summary or {})
    impl_counts = state.get("impl_counts") if isinstance(state.get("impl_counts"), Mapping) else {}
    parameter_runtime_counts = (
        state.get("parameter_runtime_counts")
        if isinstance(state.get("parameter_runtime_counts"), Mapping)
        else {}
    )
    raw_counts = state.get("raw_counts") if isinstance(state.get("raw_counts"), Mapping) else {}
    sync_counts = state.get("sync_counts") if isinstance(state.get("sync_counts"), Mapping) else {}
    parts = [
        f"mode={str(state.get('mode') or 'n/a').strip() or 'n/a'}",
        f"reason={str(state.get('reason') or 'n/a').strip() or 'n/a'}",
        f"impl_complete={bool(state.get('impl_complete'))}",
        f"parameter_runtime_complete={bool(state.get('parameter_runtime_complete'))}",
        f"raw_complete={bool(state.get('raw_complete'))}",
        f"td_runs={int(impl_counts.get('td_runs') or 0)}",
        f"td_columns_calc_y={int(impl_counts.get('td_columns_calc_y') or 0)}",
        f"td_metrics_calc={int(impl_counts.get('td_metrics_calc') or 0)}",
        f"td_condition_observations_sequences={int(impl_counts.get('td_condition_observations_sequences') or 0)}",
        f"td_metrics_calc_sequences={int(impl_counts.get('td_metrics_calc_sequences') or 0)}",
        f"td_life_metrics={int(impl_counts.get('td_life_metrics') or 0)}",
        f"td_param_discovery={int(parameter_runtime_counts.get('td_param_discovery') or 0)}",
        f"td_param_norm_groups={int(parameter_runtime_counts.get('td_param_norm_groups') or 0)}",
        f"td_param_norm_rules={int(parameter_runtime_counts.get('td_param_norm_rules') or 0)}",
        f"td_param_runtime_entries={int(parameter_runtime_counts.get('td_param_runtime_entries') or 0)}",
        f"td_param_runtime_groups={int(parameter_runtime_counts.get('td_param_runtime_groups') or 0)}",
        f"td_raw_sequences={int(raw_counts.get('td_raw_sequences') or 0)}",
        f"td_columns_raw_y={int(raw_counts.get('td_columns_raw_y') or 0)}",
        f"td_curves_raw={int(raw_counts.get('td_curves_raw') or 0)}",
        f"added={int(sync_counts.get('added') or 0)}",
        f"changed={int(sync_counts.get('changed') or 0)}",
        f"removed={int(sync_counts.get('removed') or 0)}",
        f"unchanged={int(sync_counts.get('unchanged') or 0)}",
        f"missing={int(sync_counts.get('missing') or 0)}",
        f"invalid={int(sync_counts.get('invalid') or 0)}",
        f"non_ok={int(sync_counts.get('non_ok') or 0)}",
        f"reingested={int(sync_counts.get('reingested') or 0)}",
    ]
    workbook_outputs = state.get("workbook_outputs") if isinstance(state.get("workbook_outputs"), Mapping) else {}
    source_status_counts = state.get("source_status_counts") if isinstance(state.get("source_status_counts"), Mapping) else {}
    data_calc = workbook_outputs.get("data_calc") if isinstance(workbook_outputs.get("data_calc"), Mapping) else {}
    metrics_long = workbook_outputs.get("metrics_long") if isinstance(workbook_outputs.get("metrics_long"), Mapping) else {}
    raw_cache_long = workbook_outputs.get("raw_cache_long") if isinstance(workbook_outputs.get("raw_cache_long"), Mapping) else {}
    if "compiled_serials_count" in state:
        parts.append(f"compiled_serials={int(state.get('compiled_serials_count') or 0)}")
    if "excluded_sources_count" in state:
        parts.append(f"excluded_sources={int(state.get('excluded_sources_count') or 0)}")
    if source_status_counts:
        parts.extend(
            [
                f"source_missing={int(source_status_counts.get('missing') or 0)}",
                f"source_invalid={int(source_status_counts.get('invalid') or 0)}",
                f"source_non_ok={int(source_status_counts.get('non_ok') or 0)}",
            ]
        )
    if workbook_outputs:
        parts.extend(
            [
                f"data_calc_ok={bool(data_calc.get('ok'))}",
                f"metrics_long_rows={int(metrics_long.get('rows') or 0)}",
                f"raw_cache_long_rows={int(raw_cache_long.get('rows') or 0)}",
            ]
        )
    return ", ".join(parts)


def _td_record_post_build_validation(
    project_dir: Path,
    *,
    state_summary: Mapping[str, object] | None,
    validation_ok: bool,
    validation_error: str = "",
) -> Path | None:
    payload = _read_td_cache_debug_json(project_dir)
    existing_counts = payload.get("counts") if isinstance(payload.get("counts"), Mapping) else {}
    payload["backend_module_path"] = str(Path(__file__).resolve())
    payload["post_build_validation"] = {
        "ok": bool(validation_ok),
        "error": str(validation_error or "").strip(),
        "summary": _td_cache_validation_summary_line(state_summary),
        "cache_state": dict(state_summary or {}),
        "build_counts": {
            "serials_count": int(existing_counts.get("serials_count") or 0),
            "valid_sources": int(existing_counts.get("valid_sources") or 0),
            "missing_sources": int(existing_counts.get("missing_sources") or 0),
            "invalid_sources": int(existing_counts.get("invalid_sources") or 0),
            "curves_written": int(existing_counts.get("curves_written") or 0),
            "metrics_written": int(existing_counts.get("metrics_written") or 0),
        },
    }
    return _write_td_cache_debug_json(project_dir, payload)


def _td_source_status_counts(source_rows: Sequence[Mapping[str, object]] | None) -> dict[str, int]:
    rows = list(source_rows or [])
    return {
        "missing": sum(1 for item in rows if str(item.get("status") or "").strip().lower() == "missing"),
        "invalid": sum(
            1
            for item in rows
            if str(item.get("status") or "").strip().lower() not in {"", "ok", "missing"}
        ),
        "non_ok": len(rows),
    }


def _td_compiled_serials_from_cache(conn: sqlite3.Connection, workbook_path: Path) -> list[str]:
    _ensure_test_data_impl_tables(conn)
    compiled_serial_set = {
        str(row[0] or "").strip()
        for row in conn.execute(
            """
            SELECT serial
            FROM td_sources
            WHERE lower(COALESCE(status, '')) = 'ok'
            ORDER BY serial ASC
            """
        ).fetchall()
        if str(row[0] or "").strip()
    }
    if not compiled_serial_set:
        return []
    wb_path = Path(workbook_path).expanduser()
    source_serials: list[str] = []
    for item in _read_test_data_sources(wb_path):
        if not isinstance(item, Mapping):
            continue
        try:
            source_meta = _load_td_source_metadata(wb_path, item)
        except Exception:
            source_meta = {}
        source_key = _td_source_composite_key(item, source_meta)
        if source_key:
            source_serials.append(source_key)
    ordered = [serial for serial in source_serials if serial in compiled_serial_set]
    extras = sorted(compiled_serial_set - set(ordered), key=lambda value: str(value).lower())
    return ordered + extras


def _td_excluded_source_details(conn: sqlite3.Connection) -> list[dict[str, str]]:
    diag_by_serial: dict[str, str] = {}
    try:
        diag_rows = conn.execute(
            """
            SELECT serial, COALESCE(run_name, ''), COALESCE(reason, '')
            FROM td_source_diagnostics
            ORDER BY serial ASC, CASE WHEN COALESCE(run_name, '') = '' THEN 0 ELSE 1 END ASC, rowid ASC
            """
        ).fetchall()
    except Exception:
        diag_rows = []
    for serial, _run_name, reason in diag_rows:
        sn = str(serial or "").strip()
        rs = str(reason or "").strip()
        if not sn or not rs or sn in diag_by_serial:
            continue
        diag_by_serial[sn] = rs

    try:
        rows = conn.execute(
            """
            SELECT
                s.serial,
                lower(COALESCE(s.status, '')),
                COALESCE(s.sqlite_path, ''),
                COALESCE(m.program_title, ''),
                COALESCE(m.document_type, ''),
                COALESCE(m.metadata_rel, ''),
                COALESCE(m.artifacts_rel, ''),
                COALESCE(m.excel_sqlite_rel, '')
            FROM td_sources s
            LEFT JOIN td_source_metadata m
              ON m.serial = s.serial
            WHERE lower(COALESCE(s.status, '')) <> 'ok'
            ORDER BY s.serial ASC
            """
        ).fetchall()
    except Exception:
        rows = []

    out: list[dict[str, str]] = []
    for serial, status, sqlite_path, program_title, document_type, metadata_rel, artifacts_rel, excel_sqlite_rel in rows:
        sn = str(serial or "").strip()
        st = str(status or "").strip().lower()
        sp = str(sqlite_path or "").strip()
        if not sn:
            continue
        reason = diag_by_serial.get(sn) or ""
        if not reason:
            if st == "missing":
                reason = f"Source SQLite could not be resolved{': ' + sp if sp else ''}"
            elif st:
                reason = f"Source status={st}"
            else:
                reason = "Source status is not ok"
        out.append(
            {
                "serial": sn,
                "status": st or "unknown",
                "reason": reason,
                "program_title": str(program_title or "").strip(),
                "document_type": str(document_type or "").strip(),
                "metadata_rel": str(metadata_rel or "").strip(),
                "artifacts_rel": str(artifacts_rel or "").strip(),
                "excel_sqlite_rel": str(excel_sqlite_rel or "").strip(),
            }
        )
    return out


def _td_non_ok_source_failures(conn: sqlite3.Connection) -> list[dict[str, str]]:
    return _td_excluded_source_details(conn)


def _td_excluded_source_warning_summary(excluded_sources: Sequence[Mapping[str, object]] | None) -> str:
    rows = list(excluded_sources or [])
    if not rows:
        return ""
    counts = _td_source_status_counts(rows)
    noun = "source" if len(rows) == 1 else "sources"
    return (
        f"Excluded {len(rows)} TD {noun} from compilation "
        f"(missing={int(counts.get('missing') or 0)}, invalid={int(counts.get('invalid') or 0)}). "
        "They will be ignored until fixed."
    )


def _td_format_source_failure_lines(source_failures: Sequence[Mapping[str, object]] | None, *, limit: int = 4) -> str:
    lines: list[str] = []
    for item in source_failures or []:
        serial = str((item or {}).get("serial") or "").strip()
        status = str((item or {}).get("status") or "").strip().lower() or "unknown"
        reason = str((item or {}).get("reason") or "").strip()
        reference = (
            str((item or {}).get("metadata_rel") or "").strip()
            or str((item or {}).get("excel_sqlite_rel") or "").strip()
            or str((item or {}).get("artifacts_rel") or "").strip()
        )
        if not serial:
            continue
        line = f"{serial} [{status}]"
        if reference:
            line += f" ({reference})"
        if reason:
            line += f": {reason}"
        lines.append(line)
    if not lines:
        return ""
    return " | ".join(lines[: max(1, int(limit))])


def _td_expected_metric_labels_from_cache(conn: sqlite3.Connection) -> list[str]:
    _ensure_test_data_impl_tables(conn)
    stats_csv = str(_td_meta_value(conn, "statistics") or "").strip()
    stats = _td_normalize_selected_stats([part.strip() for part in stats_csv.split(",") if part.strip()])
    runs = [
        str(row[0] or "").strip()
        for row in conn.execute("SELECT run_name FROM td_runs ORDER BY run_name ASC").fetchall()
        if str(row[0] or "").strip()
    ]
    y_by_run: dict[str, set[str]] = {}
    for run_name, name in conn.execute(
        "SELECT run_name, name FROM td_columns_calc WHERE kind='y' ORDER BY run_name ASC, name ASC"
    ).fetchall():
        run = str(run_name or "").strip()
        col = str(name or "").strip()
        if not run or not col:
            continue
        y_by_run.setdefault(run, set()).add(col)
    labels: list[str] = []
    for run in runs:
        for col in sorted(y_by_run.get(run, set()), key=lambda value: str(value).lower()):
            for stat in stats:
                labels.append(f"{run}.{col}.{stat}")
    return labels


def td_cached_statistics(db_path: Path) -> list[str]:
    path = Path(db_path).expanduser()
    if not path.exists() or not path.is_file():
        return []
    with sqlite3.connect(str(path)) as conn:
        _ensure_test_data_impl_tables(conn)
        stats_csv = str(_td_meta_value(conn, "statistics") or "").strip()
        stats = [part.strip().lower() for part in stats_csv.split(",") if part.strip()]
        available = {stat for stat in stats if stat in TD_ALLOWED_STATS}
        if not available:
            rows = conn.execute(
                """
                SELECT lower(stat) FROM td_metrics_calc
                UNION
                SELECT lower(stat) FROM td_metrics_calc_sequences
                """
            ).fetchall()
            available = {
                str(row[0] or "").strip().lower()
                for row in rows
                if str(row[0] or "").strip().lower() in TD_ALLOWED_STATS
            }
    return [stat for stat in TD_ALLOWED_STATS_ORDER if stat in available]


def _td_validate_generated_workbook_outputs(
    workbook_path: Path,
    *,
    expected_serials: Sequence[str],
    expected_metric_labels: Sequence[str],
    expected_metrics_long_rows: int,
    expected_metrics_long_sequence_rows: int,
    expected_life_metrics_rows: int,
    expected_raw_long_rows: int,
) -> dict[str, object]:
    try:
        from openpyxl import load_workbook  # type: ignore
    except Exception as exc:
        raise RuntimeError(
            "openpyxl is required to validate Test Data Trending workbook outputs. "
            "Install it with `py -m pip install openpyxl` within the project environment."
        ) from exc

    expected_serial_list = [str(value).strip() for value in expected_serials if str(value).strip()]
    expected_metric_set = {str(value).strip() for value in expected_metric_labels if str(value).strip()}
    metrics_header = [
        "observation_id",
        "serial",
        "condition_key",
        "condition_display",
        "program_title",
        "source_run_name",
        "parameter_name",
        "stat",
        "value_num",
        "source_mtime_ns",
    ]
    raw_header = [
        "observation_id",
        "serial",
        "program_title",
        "source_run_name",
        "condition_key",
        "condition_display",
        "x_axis_kind",
        "run_type",
        "pulse_width",
        "control_period",
        "source_mtime_ns",
    ]
    life_header = [
        "observation_id",
        "serial",
        "sequence_index",
        "sequence_label",
        "condition_key",
        "condition_display",
        "program_title",
        "source_run_name",
        "parameter_name",
        "stat",
        "value_num",
        "units",
        "sequence_pulses",
        "cumulative_pulses",
        "sequence_on_time",
        "cumulative_on_time",
        "sequence_elapsed_time",
        "cumulative_elapsed_time",
        "sequence_throughput",
        "cumulative_throughput",
        "sequence_impulse",
        "cumulative_impulse",
        "diagnostics",
        "source_mtime_ns",
        "computed_epoch_ns",
    ]
    summary: dict[str, object] = {
        "ok": False,
        "data_calc": {
            "exists": False,
            "ok": False,
            "serial_headers": 0,
            "expected_serial_headers": len(expected_serial_list),
            "metric_rows": 0,
            "expected_metric_rows": len(expected_metric_set),
        },
        "metrics_long": {
            "exists": False,
            "ok": False,
            "rows": 0,
            "expected_rows": int(expected_metrics_long_rows),
        },
        "metrics_long_sequences": {
            "exists": False,
            "ok": False,
            "rows": 0,
            "expected_rows": int(expected_metrics_long_sequence_rows),
        },
        "life_metrics": {
            "exists": False,
            "ok": False,
            "rows": 0,
            "expected_rows": int(expected_life_metrics_rows),
        },
        "raw_cache_long": {
            "exists": False,
            "ok": False,
            "rows": 0,
            "expected_rows": int(expected_raw_long_rows),
        },
    }
    problems: list[str] = []

    def _sample(values: Sequence[str], *, limit: int = 3) -> str:
        return ", ".join([str(value).strip() for value in values[:limit] if str(value).strip()])

    def _count_data_rows(ws) -> int:
        count = 0
        for row in ws.iter_rows(min_row=2, values_only=True):
            if any(value not in (None, "") for value in row):
                count += 1
        return count

    wb = load_workbook(str(Path(workbook_path).expanduser()), read_only=True, data_only=True)
    try:
        if "Data_calc" not in wb.sheetnames:
            problems.append("Project workbook outputs are incomplete: missing sheet Data_calc.")
        else:
            ws = wb["Data_calc"]
            data_calc = summary["data_calc"] if isinstance(summary.get("data_calc"), dict) else {}
            data_calc["exists"] = True
            header_values = next(ws.iter_rows(min_row=1, max_row=1, values_only=True), tuple())
            header = [str(value or "").strip() for value in header_values]
            actual_serials = [value for value in header[1:] if value]
            data_calc["serial_headers"] = len(actual_serials)
            if not header or header[0] != "Metric":
                problems.append("Project workbook outputs are incomplete: Data_calc header row is invalid.")
            if actual_serials != expected_serial_list:
                problems.append(
                    "Project workbook outputs are incomplete: Data_calc serial headers do not match the compiled source set."
                )
            metric_labels: list[str] = []
            for row in ws.iter_rows(min_row=2, max_col=1, values_only=True):
                metric = _td_parse_metric_label(row[0] if row else "")
                if metric is None:
                    continue
                metric_labels.append(str(row[0] or "").strip())
            metric_set = set(metric_labels)
            data_calc["metric_rows"] = len(metric_labels)
            if not expected_metric_set:
                problems.append("Project workbook outputs are incomplete: cache produced no expected Data_calc metric labels.")
            if not metric_labels:
                problems.append("Project workbook outputs are incomplete: Data_calc has no generated metric label rows.")
            if len(metric_labels) != len(metric_set):
                problems.append("Project workbook outputs are incomplete: Data_calc contains duplicate metric labels.")
            missing_labels = sorted(expected_metric_set - metric_set)
            extra_labels = sorted(metric_set - expected_metric_set)
            if missing_labels or extra_labels:
                detail_parts: list[str] = []
                if missing_labels:
                    detail_parts.append(
                        f"missing labels ({len(missing_labels)}): {_sample(missing_labels)}"
                    )
                if extra_labels:
                    detail_parts.append(
                        f"unexpected labels ({len(extra_labels)}): {_sample(extra_labels)}"
                    )
                problems.append(
                    "Project workbook outputs are incomplete: Data_calc metric labels do not match the cache. "
                    + "; ".join([part for part in detail_parts if part])
                    + "."
                )
            data_calc["ok"] = not any("Data_calc" in problem for problem in problems)

        if "Metrics_long" not in wb.sheetnames:
            problems.append("Project workbook outputs are incomplete: missing sheet Metrics_long.")
        else:
            ws = wb["Metrics_long"]
            metrics_long = summary["metrics_long"] if isinstance(summary.get("metrics_long"), dict) else {}
            metrics_long["exists"] = True
            header_values = next(ws.iter_rows(min_row=1, max_row=1, values_only=True), tuple())
            header = [str(value or "").strip() for value in header_values]
            row_count = _count_data_rows(ws)
            metrics_long["rows"] = row_count
            if header[: len(metrics_header)] != metrics_header:
                problems.append("Project workbook outputs are incomplete: Metrics_long header row is invalid.")
            if row_count <= 0:
                problems.append("Project workbook outputs are incomplete: Metrics_long has no data rows.")
            if row_count != int(expected_metrics_long_rows):
                problems.append(
                    "Project workbook outputs are incomplete: Metrics_long row count does not match td_metrics_calc."
                )
            metrics_long["ok"] = not any("Metrics_long" in problem for problem in problems)

        if "Metrics_long_sequences" not in wb.sheetnames:
            problems.append("Project workbook outputs are incomplete: missing sheet Metrics_long_sequences.")
        else:
            ws = wb["Metrics_long_sequences"]
            metrics_long_sequences = (
                summary["metrics_long_sequences"]
                if isinstance(summary.get("metrics_long_sequences"), dict)
                else {}
            )
            metrics_long_sequences["exists"] = True
            header_values = next(ws.iter_rows(min_row=1, max_row=1, values_only=True), tuple())
            header = [str(value or "").strip() for value in header_values]
            row_count = _count_data_rows(ws)
            metrics_long_sequences["rows"] = row_count
            if header[: len(metrics_header)] != metrics_header:
                problems.append(
                    "Project workbook outputs are incomplete: Metrics_long_sequences header row is invalid."
                )
            if row_count <= 0:
                problems.append("Project workbook outputs are incomplete: Metrics_long_sequences has no data rows.")
            if row_count != int(expected_metrics_long_sequence_rows):
                problems.append(
                    "Project workbook outputs are incomplete: Metrics_long_sequences row count does not match td_metrics_calc_sequences."
                )
            metrics_long_sequences["ok"] = not any(
                "Metrics_long_sequences" in problem for problem in problems
            )

        if "Life_metrics" not in wb.sheetnames:
            problems.append("Project workbook outputs are incomplete: missing sheet Life_metrics.")
        else:
            ws = wb["Life_metrics"]
            life_metrics = summary["life_metrics"] if isinstance(summary.get("life_metrics"), dict) else {}
            life_metrics["exists"] = True
            header_values = next(ws.iter_rows(min_row=1, max_row=1, values_only=True), tuple())
            header = [str(value or "").strip() for value in header_values]
            row_count = _count_data_rows(ws)
            life_metrics["rows"] = row_count
            if header[: len(life_header)] != life_header:
                problems.append("Project workbook outputs are incomplete: Life_metrics header row is invalid.")
            if row_count <= 0:
                problems.append("Project workbook outputs are incomplete: Life_metrics has no data rows.")
            if row_count != int(expected_life_metrics_rows):
                problems.append(
                    "Project workbook outputs are incomplete: Life_metrics row count does not match td_life_metrics."
                )
            life_metrics["ok"] = not any("Life_metrics" in problem for problem in problems)

        if "RawCache_long" not in wb.sheetnames:
            problems.append("Project workbook outputs are incomplete: missing sheet RawCache_long.")
        else:
            ws = wb["RawCache_long"]
            raw_cache_long = summary["raw_cache_long"] if isinstance(summary.get("raw_cache_long"), dict) else {}
            raw_cache_long["exists"] = True
            header_values = next(ws.iter_rows(min_row=1, max_row=1, values_only=True), tuple())
            header = [str(value or "").strip() for value in header_values]
            row_count = _count_data_rows(ws)
            raw_cache_long["rows"] = row_count
            if header[: len(raw_header)] != raw_header:
                problems.append("Project workbook outputs are incomplete: RawCache_long header row is invalid.")
            if row_count <= 0:
                problems.append("Project workbook outputs are incomplete: RawCache_long has no data rows.")
            if row_count != int(expected_raw_long_rows):
                problems.append(
                    "Project workbook outputs are incomplete: RawCache_long row count does not match td_raw_condition_observations."
                )
            raw_cache_long["ok"] = not any("RawCache_long" in problem for problem in problems)
    finally:
        try:
            wb.close()
        except Exception:
            pass

    summary["ok"] = not problems
    summary["problems"] = list(problems)
    return summary


def _td_collect_project_readiness(
    project_dir: Path,
    workbook_path: Path,
    *,
    validate_workbook_outputs: bool = True,
) -> dict[str, object]:
    proj_dir = Path(project_dir).expanduser()
    wb_path = Path(workbook_path).expanduser()
    db_path = proj_dir / EIDAT_PROJECT_IMPLEMENTATION_DB
    raw_db_path = td_raw_cache_db_path_for(proj_dir)
    if not wb_path.exists():
        raise FileNotFoundError(f"Workbook not found: {wb_path}")

    readiness: dict[str, object] = {
        "db_path": db_path,
        "raw_db_path": raw_db_path,
        "summary": {},
        "source_failures": [],
        "excluded_sources": [],
        "compiled_serials": [],
        "warning_summary": "",
        "warnings": [],
        "problems": [],
    }
    problems: list[str] = []
    warnings: list[str] = []
    summary: dict[str, object] = {}

    if not db_path.exists() or not db_path.is_file():
        problems.append(f"Project cache DB not found: {db_path}.")
    if not raw_db_path.exists() or not raw_db_path.is_file():
        problems.append(f"Project raw cache DB not found: {raw_db_path}.")

    if not problems:
        state = inspect_test_data_project_cache_state(proj_dir, wb_path)
        summary = _td_cache_state_summary(state)
        refresh_mode = str(state.get("mode") or "").strip().lower()
        if refresh_mode and refresh_mode != "none":
            reason = str(state.get("reason") or "project cache is stale").strip() or "project cache is stale"
            stale_message = f"Project cache is stale: {reason}."
            if refresh_mode == "calc":
                warnings.append(stale_message)
            else:
                problems.append(stale_message)

        with closing(sqlite3.connect(str(db_path))) as conn:
            _ensure_test_data_impl_tables(conn)
            required_impl_tables = (
                "td_runs",
                "td_columns_calc",
                "td_metrics_calc",
                "td_condition_observations_sequences",
                "td_metrics_calc_sequences",
                TD_LIFE_METRICS_TABLE,
                TD_PARAM_DISCOVERY_TABLE,
                TD_PARAM_NORM_GROUPS_TABLE,
                TD_PARAM_NORM_RULES_TABLE,
                TD_PARAM_RUNTIME_ENTRIES_TABLE,
                TD_PARAM_RUNTIME_GROUPS_TABLE,
            )
            impl_tables = {
                str(row[0] or "").strip()
                for row in conn.execute(
                    f"""
                    SELECT name
                    FROM sqlite_master
                    WHERE type='table' AND name IN ({','.join('?' for _ in required_impl_tables)})
                    """,
                    required_impl_tables,
                ).fetchall()
                if str(row[0] or "").strip()
            }
            missing_impl_tables = [name for name in required_impl_tables if name not in impl_tables]
            if missing_impl_tables:
                problems.append(
                    f"Project cache DB is incomplete ({', '.join(missing_impl_tables)} missing): {db_path}."
                )
            impl_counts = _td_impl_cache_counts(conn)
            if not bool(impl_counts.get("complete")):
                problems.append(f"Project cache DB is incomplete: {db_path}.")
            parameter_runtime_counts = _td_parameter_runtime_counts(conn)
            summary["parameter_runtime_counts"] = {
                "td_param_discovery": int(parameter_runtime_counts.get("discovery_rows") or 0),
                "td_param_norm_groups": int(parameter_runtime_counts.get("norm_groups") or 0),
                "td_param_norm_rules": int(parameter_runtime_counts.get("norm_rules") or 0),
                "td_param_runtime_entries": int(parameter_runtime_counts.get("runtime_entries") or 0),
                "td_param_runtime_groups": int(parameter_runtime_counts.get("runtime_groups") or 0),
            }
            summary["parameter_runtime_complete"] = bool(parameter_runtime_counts.get("complete"))
            if not bool(parameter_runtime_counts.get("complete")):
                problems.append(f"Project parameter runtime cache is incomplete: {db_path}.")

            source_failures = _td_excluded_source_details(conn)
            compiled_serials = _td_compiled_serials_from_cache(conn, wb_path)
            readiness["source_failures"] = list(source_failures)
            readiness["excluded_sources"] = list(source_failures)
            readiness["compiled_serials"] = list(compiled_serials)
            source_status_counts = _td_source_status_counts(source_failures)
            summary["source_status_counts"] = source_status_counts
            summary["compiled_serials_count"] = len(compiled_serials)
            summary["excluded_sources_count"] = len(source_failures)
            if source_failures:
                warning_summary = _td_excluded_source_warning_summary(source_failures)
                readiness["warning_summary"] = warning_summary
                summary["warning_summary"] = warning_summary
                if warning_summary:
                    warnings.append(warning_summary)
            if not compiled_serials:
                problems.append(
                    "Project cache has no compiled Test Data sources. All sources are currently excluded from compilation."
                )

            expected_metric_labels = _td_expected_metric_labels_from_cache(conn)
            expected_metrics_long_rows = int(conn.execute("SELECT COUNT(*) FROM td_metrics_calc").fetchone()[0] or 0)
            expected_metrics_long_sequence_rows = int(
                conn.execute("SELECT COUNT(*) FROM td_metrics_calc_sequences").fetchone()[0] or 0
            )
            expected_life_metrics_rows = int(
                conn.execute(f"SELECT COUNT(*) FROM {TD_LIFE_METRICS_TABLE}").fetchone()[0] or 0
            )

        with closing(sqlite3.connect(str(raw_db_path))) as conn:
            _ensure_test_data_raw_cache_tables(conn)
            required_raw_tables = ("td_raw_sequences", "td_columns_raw", "td_curves_raw")
            raw_tables = {
                str(row[0] or "").strip()
                for row in conn.execute(
                    """
                    SELECT name
                    FROM sqlite_master
                    WHERE type='table' AND name IN (?, ?, ?)
                    """,
                    required_raw_tables,
                ).fetchall()
                if str(row[0] or "").strip()
            }
            missing_raw_tables = [name for name in required_raw_tables if name not in raw_tables]
            if missing_raw_tables:
                problems.append(
                    f"Project raw cache DB is incomplete ({', '.join(missing_raw_tables)} missing): {raw_db_path}."
                )
            raw_counts = _td_raw_cache_counts(conn)
            if not bool(raw_counts.get("complete")):
                problems.append(f"Project raw cache DB is incomplete: {raw_db_path}.")
            expected_raw_long_rows = int(
                conn.execute("SELECT COUNT(*) FROM td_raw_condition_observations").fetchone()[0] or 0
            )

        source_sheet_serials = [
            str(item.get("serial") or "").strip()
            for item in _read_test_data_sources(wb_path)
            if str(item.get("serial") or "").strip()
        ]
        if not source_sheet_serials:
            problems.append("Project workbook outputs are incomplete: Sources sheet has no serial rows.")

        compiled_serials = list(readiness.get("compiled_serials") or [])
        if compiled_serials and validate_workbook_outputs:
            workbook_outputs = _td_validate_generated_workbook_outputs(
                wb_path,
                expected_serials=compiled_serials,
                expected_metric_labels=expected_metric_labels,
                expected_metrics_long_rows=expected_metrics_long_rows,
                expected_metrics_long_sequence_rows=expected_metrics_long_sequence_rows,
                expected_life_metrics_rows=expected_life_metrics_rows,
                expected_raw_long_rows=expected_raw_long_rows,
            )
            summary["workbook_outputs"] = workbook_outputs
            for problem in workbook_outputs.get("problems") or []:
                if str(problem).strip():
                    warnings.append(str(problem).strip())
        elif compiled_serials:
            summary["workbook_outputs_deferred"] = True

    deduped_warnings = list(dict.fromkeys([str(warning).strip() for warning in warnings if str(warning).strip()]))
    if deduped_warnings:
        summary["warnings"] = list(deduped_warnings)
    readiness["summary"] = summary
    readiness["warnings"] = deduped_warnings
    readiness["problems"] = list(dict.fromkeys([str(problem).strip() for problem in problems if str(problem).strip()]))
    return readiness


def _td_project_readiness_error_message(
    readiness: Mapping[str, object],
    *,
    guidance: str,
) -> str:
    problems = [str(problem).strip() for problem in (readiness.get("problems") or []) if str(problem).strip()]
    source_failures = readiness.get("source_failures") if isinstance(readiness.get("source_failures"), Sequence) else []
    summary = readiness.get("summary") if isinstance(readiness.get("summary"), Mapping) else {}
    parts: list[str] = []
    if problems:
        parts.append(" ".join(problems))
    source_txt = _td_format_source_failure_lines(cast(Sequence[Mapping[str, object]], source_failures), limit=4)
    if source_txt:
        parts.append(f"Source details: {source_txt}.")
    summary_txt = _td_cache_validation_summary_line(summary)
    if summary_txt:
        parts.append(f"Cache summary: {summary_txt}.")
    if guidance:
        parts.append(guidance)
    return " ".join([part for part in parts if part]).strip()


def _td_ensure_project_ready(
    project_dir: Path,
    workbook_path: Path,
    *,
    guidance: str,
    validate_workbook_outputs: bool = True,
) -> dict[str, object]:
    readiness = _td_collect_project_readiness(
        project_dir,
        workbook_path,
        validate_workbook_outputs=validate_workbook_outputs,
    )
    problems = [str(problem).strip() for problem in (readiness.get("problems") or []) if str(problem).strip()]
    if problems:
        raise RuntimeError(_td_project_readiness_error_message(readiness, guidance=guidance))
    return readiness


def ensure_test_data_project_cache(
    project_dir: Path,
    workbook_path: Path,
    *,
    rebuild: bool = False,
    progress_cb: Callable[[str], None] | None = None,
) -> Path:
    """
    Ensure `td_*` cache tables exist and are up-to-date inside the project's
    `implementation_trending.sqlite3`.
    """
    payload = sync_test_data_project_cache(
        project_dir,
        workbook_path,
        rebuild=rebuild,
        progress_cb=progress_cb,
    )
    return Path(str(payload.get("db_path") or (Path(project_dir).expanduser() / EIDAT_PROJECT_IMPLEMENTATION_DB))).expanduser()


def export_test_data_project_debug_excels(
    project_dir: Path,
    workbook_path: Path,
    *,
    force: bool = True,
    progress_cb: Callable[[str], None] | None = None,
) -> dict[str, Path]:
    """
    Export optional Excel debug files from the existing TD project cache only.
    """
    proj_dir = Path(project_dir).expanduser()
    db_path = proj_dir / EIDAT_PROJECT_IMPLEMENTATION_DB
    raw_db_path = td_raw_cache_db_path_for(proj_dir)
    cache_warning: Exception | None = None
    try:
        validate_existing_test_data_project_cache(proj_dir, workbook_path)
    except Exception as exc:
        cache_warning = exc
        _td_emit_progress(progress_cb, f"Cache validation failed; exporting existing SQLite files anyway: {exc}")

    generated: dict[str, Path] = {}

    _td_emit_progress(progress_cb, "Exporting implementation cache Excel mirror")
    impl_xlsx_path = _sync_sqlite_excel_mirror(db_path, force=force)
    if impl_xlsx_path is not None:
        generated["implementation_excel"] = impl_xlsx_path

    _td_emit_progress(progress_cb, "Exporting raw cache Excel mirror")
    raw_xlsx_path = _sync_sqlite_excel_mirror(raw_db_path, force=force)
    if raw_xlsx_path is not None:
        generated["raw_cache_excel"] = raw_xlsx_path

    raw_points_path = raw_db_path.with_name(EIDAT_PROJECT_TD_RAW_POINTS_XLSX)
    if raw_points_path.exists():
        generated["raw_points_excel"] = raw_points_path

    if generated:
        return generated
    if cache_warning is not None:
        raise RuntimeError(
            "No debug Excel files were generated because no project SQLite files could be exported."
        ) from cache_warning
    if not workbook_path.exists():
        raise FileNotFoundError(f"Workbook not found: {Path(workbook_path).expanduser()}")
    raise RuntimeError(
        "No debug Excel files were generated because the project SQLite files were not found."
    )

def _sync_sqlite_excel_mirror(db_path: Path, *, force: bool = False) -> Path | None:
    db_path = Path(db_path).expanduser()
    if not db_path.exists() or not db_path.is_file():
        return None
    out_path = db_path.with_suffix(".xlsx")
    if not force:
        try:
            db_mtime_ns = int(db_path.stat().st_mtime_ns)
            xlsx_mtime_ns = int(out_path.stat().st_mtime_ns) if out_path.exists() else 0
            if out_path.exists() and xlsx_mtime_ns >= db_mtime_ns:
                return out_path
        except Exception:
            pass
    try:
        from openpyxl import Workbook  # type: ignore
        from openpyxl.styles import Alignment, Font, PatternFill  # type: ignore
        from openpyxl.utils import get_column_letter  # type: ignore
    except Exception:
        return None

    header_font = Font(bold=True)
    header_fill = PatternFill(start_color="D9E1F2", end_color="D9E1F2", fill_type="solid")

    with closing(sqlite3.connect(str(db_path))) as conn:
        tables = [
            str(row[0] or "").strip()
            for row in conn.execute(
                "SELECT name FROM sqlite_master WHERE type='table' ORDER BY name"
            ).fetchall()
            if str(row[0] or "").strip()
        ]

        wb = Workbook()
        wb.remove(wb.active)
        used_sheet_titles: set[str] = set()

        for table_name in tables:
            safe_title = _td_safe_excel_sheet_title(table_name, used_sheet_titles, fallback="table")
            ws = wb.create_sheet(title=safe_title)
            cols = [
                str(col[1] or "").strip()
                for col in conn.execute(f'PRAGMA table_info("{table_name.replace(chr(34), chr(34) * 2)}")').fetchall()
            ]
            rows = conn.execute(f'SELECT * FROM "{table_name.replace(chr(34), chr(34) * 2)}"').fetchall()

            for col_idx, col_name in enumerate(cols, start=1):
                cell = ws.cell(row=1, column=col_idx, value=col_name)
                cell.font = header_font
                cell.fill = header_fill
                cell.alignment = Alignment(horizontal="center")

            for row_idx, row in enumerate(rows, start=2):
                for col_idx, value in enumerate(row, start=1):
                    pretty = value
                    if isinstance(pretty, str) and pretty and pretty[:1] in ("{", "["):
                        try:
                            pretty = json.dumps(json.loads(pretty), indent=2)
                        except Exception:
                            pretty = value
                    ws.cell(row=row_idx, column=col_idx, value=pretty)

            for col_idx in range(1, len(cols) + 1):
                max_len = len(str(cols[col_idx - 1] or ""))
                for row_idx in range(2, len(rows) + 2):
                    cell_val = ws.cell(row=row_idx, column=col_idx).value
                    if cell_val is not None:
                        max_len = max(max_len, min(60, len(str(cell_val))))
                ws.column_dimensions[get_column_letter(col_idx)].width = max_len + 3
            ws.freeze_panes = "A2"

    wb.save(str(out_path))
    if db_path.name.lower() == EIDAT_PROJECT_TD_RAW_CACHE_DB.lower():
        try:
            _sync_td_raw_points_workbook(db_path, force=force)
        except Exception:
            pass
    return out_path


def _sync_td_raw_points_workbook(db_path: Path, *, force: bool = False) -> Path | None:
    db_path = Path(db_path).expanduser()
    if not db_path.exists() or not db_path.is_file():
        return None
    out_path = db_path.with_name(EIDAT_PROJECT_TD_RAW_POINTS_XLSX)
    if not force:
        try:
            db_mtime_ns = int(db_path.stat().st_mtime_ns)
            xlsx_mtime_ns = int(out_path.stat().st_mtime_ns) if out_path.exists() else 0
            if out_path.exists() and xlsx_mtime_ns >= db_mtime_ns:
                return out_path
        except Exception:
            pass
    try:
        from openpyxl import Workbook  # type: ignore
        from openpyxl.styles import Alignment, Font, PatternFill  # type: ignore
        from openpyxl.utils import get_column_letter  # type: ignore
    except Exception:
        return None

    def _safe_sheet_name(name: str, used: set[str]) -> str:
        base = re.sub(r'[:\\/?*\\[\\]]+', "_", str(name or "").strip()) or "raw"
        base = base[:31].rstrip() or "raw"
        cand = base
        idx = 2
        while cand.lower() in {u.lower() for u in used}:
            suffix = f"_{idx}"
            cand = (base[: max(0, 31 - len(suffix))] + suffix).rstrip() or f"raw_{idx}"
            idx += 1
        used.add(cand)
        return cand

    def _x_key(value: object) -> tuple[str, object]:
        try:
            f = float(value)
        except Exception:
            return ("s", str(value))
        if not math.isfinite(f):
            return ("s", str(value))
        if abs(f - round(f)) < 1e-9:
            return ("i", int(round(f)))
        return ("f", round(f, 12))

    def _display_x(value: object) -> object:
        try:
            f = float(value)
        except Exception:
            return value
        if not math.isfinite(f):
            return value
        if abs(f - round(f)) < 1e-9:
            return int(round(f))
        return float(f)

    with closing(sqlite3.connect(str(db_path))) as conn:
        _ensure_test_data_raw_cache_tables(conn)
        rows = conn.execute(
            """
            SELECT run_name, y_name, x_name, serial, x_json, y_json
            FROM td_curves_raw
            ORDER BY run_name, y_name, x_name, serial
            """
        ).fetchall()
    if not rows:
        return None

    grouped: dict[tuple[str, str, str], dict[str, list[tuple[object, object]]]] = {}
    for run_name, y_name, x_name, serial, x_json, y_json in rows:
        run = str(run_name or "").strip()
        y = str(y_name or "").strip()
        x = str(x_name or "").strip()
        sn = str(serial or "").strip()
        if not run or not y or not x or not sn:
            continue
        try:
            xs = json.loads(x_json or "[]")
            ys = json.loads(y_json or "[]")
        except Exception:
            xs, ys = [], []
        points = list(zip(list(xs), list(ys)))
        grouped.setdefault((run, y, x), {})[sn] = points
    if not grouped:
        return None

    header_font = Font(bold=True)
    header_fill = PatternFill(start_color="D9E1F2", end_color="D9E1F2", fill_type="solid")
    wb = Workbook()
    wb.remove(wb.active)
    used_sheet_names: set[str] = set()

    for (run, y, x_name), serial_map in sorted(grouped.items(), key=lambda item: tuple(str(v).lower() for v in item[0])):
        sheet_name = _safe_sheet_name(f"{run}__{y}__{x_name}", used_sheet_names)
        ws = wb.create_sheet(title=sheet_name)
        serials = sorted(serial_map.keys(), key=lambda value: value.lower())
        ws.append([x_name] + serials)
        ordered_keys: list[tuple[str, object]] = []
        display_by_key: dict[tuple[str, object], object] = {}
        values_by_serial: dict[str, dict[tuple[str, object], object]] = {serial: {} for serial in serials}
        seen_keys: set[tuple[str, object]] = set()

        for serial in serials:
            for x_raw, y_raw in serial_map.get(serial, []):
                key = _x_key(x_raw)
                if key not in seen_keys:
                    seen_keys.add(key)
                    ordered_keys.append(key)
                    display_by_key[key] = _display_x(x_raw)
                values_by_serial.setdefault(serial, {})
                if key not in values_by_serial[serial]:
                    values_by_serial[serial][key] = y_raw

        def _sort_key(item: tuple[str, object]) -> tuple[int, object]:
            if item[0] == "s":
                return (1, str(item[1]))
            return (0, item[1])

        ordered_keys.sort(key=_sort_key)
        for key in ordered_keys:
            ws.append([display_by_key.get(key)] + [values_by_serial.get(serial, {}).get(key) for serial in serials])

        for col_idx in range(1, len(serials) + 2):
            cell = ws.cell(1, col_idx)
            cell.font = header_font
            cell.fill = header_fill
            cell.alignment = Alignment(horizontal="center")
            if col_idx == 1:
                ws.column_dimensions[get_column_letter(col_idx)].width = max(14, len(str(x_name or "")) + 2)
            else:
                ws.column_dimensions[get_column_letter(col_idx)].width = max(14, len(str(ws.cell(1, col_idx).value or "")) + 2)
        try:
            ws.freeze_panes = "B2"
        except Exception:
            pass

    wb.save(str(out_path))
    return out_path


def _resolve_td_support_sequence_for_run(run_name: str, support_cfg: dict) -> dict:
    run = str(run_name or "").strip()
    if not run:
        return {
            "sequence_name": "",
            "condition_key": "",
            "display_name": "",
            "source_run_name": "",
            "program_title": "",
            "pulse_width": None,
            "exclude_first_n": None,
            "last_n_rows": None,
        }
    return _td_resolve_support_condition_for_source("", run, support_cfg)


TD_SEQUENCE_OBS_SERIAL_IDX = 1
TD_SEQUENCE_OBS_RUN_IDX = 2
TD_SEQUENCE_OBS_RUN_TYPE_IDX = 5
TD_SEQUENCE_OBS_PULSE_WIDTH_IDX = 6
TD_SEQUENCE_OBS_CONTROL_PERIOD_IDX = 7
TD_SEQUENCE_OBS_SUPPRESSION_VOLTAGE_IDX = 8
TD_SEQUENCE_OBS_VALVE_VOLTAGE_IDX = 9


def _td_group_sequence_observation_rows(
    sequence_obs_rows: Sequence[Sequence[object]] | None,
) -> tuple[dict[tuple[str, str], list[tuple[object, ...]]], dict[str, list[tuple[object, ...]]]]:
    by_condition_serial: dict[tuple[str, str], list[tuple[object, ...]]] = {}
    by_condition: dict[str, list[tuple[object, ...]]] = {}
    for raw_row in sequence_obs_rows or []:
        row = tuple(raw_row or ())
        if len(row) <= TD_SEQUENCE_OBS_RUN_IDX:
            continue
        serial = str(row[TD_SEQUENCE_OBS_SERIAL_IDX] or "").strip()
        condition_key = str(row[TD_SEQUENCE_OBS_RUN_IDX] or "").strip()
        if not condition_key:
            continue
        by_condition.setdefault(condition_key, []).append(row)
        if serial:
            by_condition_serial.setdefault((condition_key, serial), []).append(row)
    return by_condition_serial, by_condition


def _td_unique_sequence_float(rows: Sequence[Sequence[object]], index: int) -> float | None:
    values_by_key: dict[float, float] = {}
    for row in rows or []:
        if len(row) <= index:
            continue
        value = _td_finite_float(row[index])
        if value is None:
            continue
        values_by_key.setdefault(round(float(value), 12), float(value))
    if len(values_by_key) == 1:
        return next(iter(values_by_key.values()))
    return None


def _td_unique_sequence_text(rows: Sequence[Sequence[object]], index: int) -> str:
    values_by_key: dict[str, str] = {}
    for row in rows or []:
        if len(row) <= index:
            continue
        value = str(row[index] or "").strip()
        if not value:
            continue
        values_by_key.setdefault(value.casefold(), value)
    if len(values_by_key) == 1:
        return next(iter(values_by_key.values()))
    return ""


def _td_first_finite_from_values(*values: object) -> float | None:
    for value in values:
        out = _td_finite_float(value)
        if out is not None:
            return out
    return None


def _td_first_text_from_values(*values: object) -> str:
    for value in values:
        text = str(value or "").strip()
        if text:
            return text
    return ""


def _write_test_data_project_calc_cache_from_aggregates(
    db_path: Path,
    workbook_path: Path,
    *,
    cfg_cols: Sequence[Mapping[str, object]],
    cfg_units: Mapping[str, str],
    selected_stats: Sequence[str],
    support_cfg: Mapping[str, object],
    support_settings: Mapping[str, object],
    bounds_by_sequence: Mapping[str, Mapping[str, object]],
    condition_defaults_by_run: Mapping[str, Mapping[str, object]],
    condition_meta_by_key: Mapping[str, Mapping[str, object]],
    aggregated_curve_values: Mapping[tuple[str, str, str], Sequence[float]],
    aggregated_obs_meta: Mapping[tuple[str, str], Mapping[str, object]],
    condition_y_names: Mapping[str, set[str]],
    condition_units_by_name: Mapping[str, Mapping[str, object]] | None = None,
    sequence_obs_rows: Sequence[tuple[object, ...]] | None = None,
    sequence_metric_rows: Sequence[tuple[object, ...]] | None = None,
    project_cfg: Mapping[str, object] | None = None,
    computed_epoch_ns: int,
    progress_cb: Callable[[str], None] | None = None,
) -> dict[str, object]:
    import time
    import statistics

    db_path = Path(db_path).expanduser()
    wb_path = Path(workbook_path).expanduser()
    total_started = time.perf_counter()
    timings: dict[str, float] = {
        "calc_aggregate_s": 0.0,
        "calc_write_s": 0.0,
        "total_s": 0.0,
    }

    _td_emit_progress(progress_cb, "Aggregating calculated Test Data cache")
    t0 = time.perf_counter()
    metrics_written = 0
    sequence_observations_written = 0
    sequence_metrics_written = 0
    life_metrics_written = 0
    calc_columns_written = 0
    inserted_columns: set[tuple[str, str]] = set()
    inserted_runs: set[str] = set()
    run_rows_to_write: list[tuple[object, ...]] = []
    column_rows_to_write: list[tuple[object, ...]] = []
    obs_rows_to_write: list[tuple[object, ...]] = []
    metric_rows_to_write: list[tuple[object, ...]] = []
    sequence_obs_rows_list = [tuple(row or ()) for row in (sequence_obs_rows or [])]
    sequence_rows_by_condition_serial, sequence_rows_by_condition = _td_group_sequence_observation_rows(sequence_obs_rows_list)

    def _compute_stats(values: list[float]) -> dict[str, float | int | None]:
        n = len(values)
        if n == 0:
            return {"mean": None, "min": None, "max": None, "std": None, "median": None, "count": 0}
        out: dict[str, float | int | None] = {
            "mean": (sum(values) / n),
            "min": min(values),
            "max": max(values),
            "median": statistics.median(values),
            "count": n,
        }
        out["std"] = statistics.stdev(values) if n >= 2 else None
        return out

    def _compute_constant_stats(value: float) -> dict[str, float | int | None]:
        return {
            "mean": float(value),
            "min": float(value),
            "max": float(value),
            "median": float(value),
            "std": 0.0,
            "count": 1,
        }

    for (condition_key, serial_txt), meta in aggregated_obs_meta.items():
        condition_key_clean = str(condition_key or "").strip()
        serial_clean = str(serial_txt or "").strip()
        if not condition_key_clean or not serial_clean:
            continue
        condition_meta = dict(condition_meta_by_key.get(condition_key_clean) or {})
        run_defaults = dict(condition_defaults_by_run.get(condition_key_clean) or {})
        run_display_name = (
            str(condition_meta.get("display_name") or run_defaults.get("display_name") or condition_key_clean).strip()
            or condition_key_clean
        )
        default_x = str(run_defaults.get("default_x") or "Time").strip() or "Time"
        condition_sequence_rows = sequence_rows_by_condition.get(condition_key_clean) or []
        run_pulse_width_value = _td_first_finite_from_values(
            condition_meta.get("pulse_width_on"),
            condition_meta.get("pulse_width"),
            run_defaults.get("pulse_width"),
        )
        if run_pulse_width_value is None:
            run_pulse_width_value = _td_unique_sequence_float(condition_sequence_rows, TD_SEQUENCE_OBS_PULSE_WIDTH_IDX)
        run_control_period_value = _td_first_finite_from_values(condition_meta.get("control_period", run_defaults.get("control_period")))
        if run_control_period_value is None:
            run_control_period_value = _td_unique_sequence_float(condition_sequence_rows, TD_SEQUENCE_OBS_CONTROL_PERIOD_IDX)
        run_suppression_voltage_value = _td_first_finite_from_values(
            condition_meta.get("suppression_voltage", run_defaults.get("suppression_voltage"))
        )
        if run_suppression_voltage_value is None:
            run_suppression_voltage_value = _td_unique_sequence_float(condition_sequence_rows, TD_SEQUENCE_OBS_SUPPRESSION_VOLTAGE_IDX)
        run_valve_voltage_value = _td_first_finite_from_values(
            condition_meta.get("valve_voltage", run_defaults.get("valve_voltage"))
        )
        if run_valve_voltage_value is None:
            run_valve_voltage_value = _td_unique_sequence_float(condition_sequence_rows, TD_SEQUENCE_OBS_VALVE_VOLTAGE_IDX)
        run_type_text = _td_first_text_from_values(
            condition_meta.get("run_type"),
            run_defaults.get("run_type"),
            _td_unique_sequence_text(condition_sequence_rows, TD_SEQUENCE_OBS_RUN_TYPE_IDX),
        )
        member_source_runs = sorted({str(v).strip() for v in (meta.get("source_run_names") or set()) if str(v).strip()})

        if condition_key_clean not in inserted_runs:
            inserted_runs.add(condition_key_clean)
            run_rows_to_write.append(
                (
                    condition_key_clean,
                    default_x,
                    run_display_name,
                    run_type_text,
                    run_control_period_value,
                    run_pulse_width_value,
                )
            )
            calc_param_defs = _td_complete_calc_param_defs(
                ordered_defs=_ordered_support_param_defs(
                    sequence_names=[condition_key_clean],
                    support_cfg={
                        "bounds_by_sequence": {condition_key_clean: dict(bounds_by_sequence.get(condition_key_clean) or {})},
                        "settings": dict(support_settings or {}),
                    },
                    fallback_defs=[dict(d) for d in cfg_cols if isinstance(d, Mapping)],
                )
                or [dict(d) for d in cfg_cols if isinstance(d, Mapping)],
                discovered_names=sorted(condition_y_names.get(condition_key_clean) or set(), key=str.casefold),
                units_by_name=dict((condition_units_by_name or {}).get(condition_key_clean) or {}),
                fallback_units=cfg_units,
            )
            for param_def in calc_param_defs:
                col_name = str(param_def.get("name") or "").strip()
                if not col_name or (condition_key_clean, col_name) in inserted_columns:
                    continue
                inserted_columns.add((condition_key_clean, col_name))
                column_rows_to_write.append(
                    (condition_key_clean, col_name, str(param_def.get("units") or cfg_units.get(col_name) or "").strip(), "y")
                )
                calc_columns_written += 1
            if run_pulse_width_value is not None and (condition_key_clean, "pulse_width") not in inserted_columns:
                inserted_columns.add((condition_key_clean, "pulse_width"))
                column_rows_to_write.append(
                    (condition_key_clean, "pulse_width", str(cfg_units.get("pulse_width") or "").strip(), "y")
                )
                calc_columns_written += 1

        observation_id_calc = f"{_td_norm_ident_token(serial_clean)}__{_td_norm_ident_token(condition_key_clean)}"
        program_titles_txt = ", ".join(sorted({str(v).strip() for v in (meta.get("program_titles") or set()) if str(v).strip()}))
        member_source_runs_txt = ", ".join(member_source_runs)
        source_mtime_max = max([int(v) for v in (meta.get("source_mtime_ns") or [])], default=0)
        serial_sequence_rows = sequence_rows_by_condition_serial.get((condition_key_clean, serial_clean)) or condition_sequence_rows
        pulse_width_value = run_pulse_width_value
        if pulse_width_value is None:
            pulse_width_value = _td_unique_sequence_float(serial_sequence_rows, TD_SEQUENCE_OBS_PULSE_WIDTH_IDX)
        control_period_value = run_control_period_value
        if control_period_value is None:
            control_period_value = _td_unique_sequence_float(serial_sequence_rows, TD_SEQUENCE_OBS_CONTROL_PERIOD_IDX)
        suppression_voltage_value = run_suppression_voltage_value
        if suppression_voltage_value is None:
            suppression_voltage_value = _td_unique_sequence_float(serial_sequence_rows, TD_SEQUENCE_OBS_SUPPRESSION_VOLTAGE_IDX)
        valve_voltage_value = run_valve_voltage_value
        if valve_voltage_value is None:
            valve_voltage_value = _td_unique_sequence_float(serial_sequence_rows, TD_SEQUENCE_OBS_VALVE_VOLTAGE_IDX)
        obs_run_type_text = run_type_text or _td_unique_sequence_text(serial_sequence_rows, TD_SEQUENCE_OBS_RUN_TYPE_IDX)
        obs_rows_to_write.append(
            (
                observation_id_calc,
                serial_clean,
                condition_key_clean,
                program_titles_txt,
                member_source_runs_txt,
                obs_run_type_text,
                pulse_width_value,
                control_period_value,
                suppression_voltage_value,
                valve_voltage_value,
                source_mtime_max,
                int(computed_epoch_ns),
            )
        )
        for y_name in sorted(condition_y_names.get(condition_key_clean) or set()):
            values = [float(v) for v in (aggregated_curve_values.get((condition_key_clean, serial_clean, y_name)) or [])]
            stats_map = _compute_stats(values)
            for stat in selected_stats:
                metric_rows_to_write.append(
                    (
                        observation_id_calc,
                        serial_clean,
                        condition_key_clean,
                        y_name,
                        str(stat),
                        stats_map.get(stat),
                        int(computed_epoch_ns),
                        source_mtime_max,
                        program_titles_txt,
                        member_source_runs_txt,
                    )
                )
                metrics_written += 1
        if pulse_width_value is not None:
            stats_map = _compute_constant_stats(float(pulse_width_value))
            for stat in selected_stats:
                metric_rows_to_write.append(
                    (
                        observation_id_calc,
                        serial_clean,
                        condition_key_clean,
                        "pulse_width",
                        str(stat),
                        stats_map.get(stat),
                        int(computed_epoch_ns),
                        source_mtime_max,
                        program_titles_txt,
                        member_source_runs_txt,
                    )
                )
                metrics_written += 1
    timings["calc_aggregate_s"] = round(time.perf_counter() - t0, 3)

    support_mtime_ns = 0
    try:
        support_path_meta = Path(str(support_cfg.get("path") or "")).expanduser()
        if support_path_meta.exists():
            st = support_path_meta.stat()
            support_mtime_ns = int(getattr(st, "st_mtime_ns", int(st.st_mtime * 1e9)))
    except Exception:
        support_mtime_ns = 0

    plotter_sequence_rows: list[tuple[object, ...]] = []
    plotter_catalog_rows_to_write: list[tuple[object, ...]] = []
    plotter_obs_rows_by_id: dict[str, tuple[object, ...]] = {}
    plotter_curve_rows_to_write: list[tuple[object, ...]] = []
    raw_db_path = _td_resolve_raw_cache_db_path(db_path)
    if raw_db_path.exists() and raw_db_path.is_file():
        with sqlite3.connect(str(raw_db_path)) as raw_conn:
            _ensure_test_data_raw_cache_tables(raw_conn)
            raw_runs = raw_conn.execute(
                """
                SELECT
                    run_name,
                    COALESCE(display_name, ''),
                    COALESCE(x_axis_kind, ''),
                    COALESCE(source_run_name, ''),
                    pulse_width,
                    COALESCE(run_type, ''),
                    control_period,
                    computed_epoch_ns
                FROM td_raw_sequences
                ORDER BY run_name
                """
            ).fetchall()
            for run_name, display_name, x_axis_kind, source_run_name, pulse_width, run_type, control_period, row_epoch_ns in raw_runs:
                run = str(run_name or "").strip()
                x_axis = str(x_axis_kind or "").strip()
                if not run or not x_axis:
                    continue
                plotter_sequence_rows.append(
                    (
                        run,
                        str(display_name or "").strip(),
                        x_axis,
                        str(source_run_name or "").strip(),
                        pulse_width,
                        str(run_type or "").strip(),
                        control_period,
                        int(row_epoch_ns or computed_epoch_ns),
                    )
                )
            raw_catalog_rows = raw_conn.execute(
                """
                SELECT
                    run_name,
                    parameter_name,
                    COALESCE(units, ''),
                    COALESCE(x_axis_kind, ''),
                    COALESCE(display_name, ''),
                    COALESCE(source_kind, ''),
                    computed_epoch_ns
                FROM td_raw_curve_catalog
                ORDER BY run_name, parameter_name
                """
            ).fetchall()
            for run_name, parameter_name, units, x_axis_kind, display_name, source_kind, row_epoch_ns in raw_catalog_rows:
                run = str(run_name or "").strip()
                parameter = str(parameter_name or "").strip()
                x_axis = str(x_axis_kind or "").strip()
                if not run or not parameter or not x_axis:
                    continue
                plotter_catalog_rows_to_write.append(
                    (
                        run,
                        parameter,
                        str(units or "").strip(),
                        x_axis,
                        str(display_name or "").strip(),
                        str(source_kind or "").strip(),
                        int(row_epoch_ns or computed_epoch_ns),
                    )
                )
            raw_obs_rows = raw_conn.execute(
                """
                SELECT
                    observation_id,
                    run_name,
                    serial,
                    COALESCE(program_title, ''),
                    COALESCE(source_run_name, ''),
                    COALESCE(run_type, ''),
                    pulse_width,
                    control_period,
                    suppression_voltage,
                    valve_voltage,
                    source_mtime_ns,
                    computed_epoch_ns
                FROM td_raw_condition_observations
                ORDER BY run_name, serial, observation_id
                """
            ).fetchall()
            for observation_id, run_name, serial, program_title, source_run_name, run_type, pulse_width, control_period, suppression_voltage, valve_voltage, source_mtime_ns, row_epoch_ns in raw_obs_rows:
                obs_id = str(observation_id or "").strip()
                if not obs_id:
                    continue
                plotter_obs_rows_by_id[obs_id] = (
                    obs_id,
                    str(run_name or "").strip(),
                    str(serial or "").strip(),
                    str(program_title or "").strip(),
                    str(source_run_name or "").strip(),
                    str(run_type or "").strip(),
                    pulse_width,
                    control_period,
                    suppression_voltage,
                    valve_voltage,
                    source_mtime_ns,
                    int(row_epoch_ns or computed_epoch_ns),
                )
            raw_curve_rows = raw_conn.execute(
                """
                SELECT
                    run_name,
                    y_name,
                    x_name,
                    observation_id,
                    serial,
                    COALESCE(program_title, ''),
                    COALESCE(source_run_name, ''),
                    x_json,
                    y_json,
                    n_points,
                    source_mtime_ns,
                    computed_epoch_ns
                FROM td_curves_raw
                ORDER BY run_name, serial, y_name, observation_id
                """
            ).fetchall()
            for run_name, y_name, x_name, observation_id, serial, program_title, source_run_name, x_json, y_json, n_points, source_mtime_ns, row_epoch_ns in raw_curve_rows:
                run = str(run_name or "").strip()
                y_col = str(y_name or "").strip()
                x_col = str(x_name or "").strip()
                obs_id = str(observation_id or "").strip()
                serial_txt = str(serial or "").strip()
                source_run_txt = str(source_run_name or run).strip() or run
                if not run or not y_col or not x_col or not obs_id or not serial_txt:
                    continue
                if obs_id not in plotter_obs_rows_by_id:
                    plotter_obs_rows_by_id[obs_id] = (
                        obs_id,
                        run,
                        serial_txt,
                        str(program_title or "").strip(),
                        source_run_txt,
                        "",
                        None,
                        None,
                        None,
                        None,
                        source_mtime_ns,
                        int(row_epoch_ns or computed_epoch_ns),
                    )
                try:
                    n_points_int = int(n_points)
                except Exception:
                    try:
                        n_points_int = max(len(json.loads(x_json or "[]")), len(json.loads(y_json or "[]")))
                    except Exception:
                        n_points_int = 0
                plotter_curve_rows_to_write.append(
                    (
                        run,
                        y_col,
                        x_col,
                        obs_id,
                        serial_txt,
                        x_json or "[]",
                        y_json or "[]",
                        max(0, int(n_points_int)),
                        source_mtime_ns,
                        int(row_epoch_ns or computed_epoch_ns),
                        str(program_title or "").strip(),
                        source_run_txt,
                    )
                )

    _td_emit_progress(progress_cb, "Writing calculated Test Data cache")
    t0 = time.perf_counter()
    with sqlite3.connect(str(db_path)) as conn:
        _ensure_test_data_impl_tables(conn)
        _purge_test_data_legacy_impl_raw_tables(conn)
        conn.execute("DELETE FROM td_runs")
        conn.execute("DELETE FROM td_columns_calc")
        conn.execute("DELETE FROM td_metrics_calc")
        conn.execute("DELETE FROM td_condition_observations")
        conn.execute("DELETE FROM td_metrics_calc_sequences")
        conn.execute("DELETE FROM td_condition_observations_sequences")
        conn.execute(f"DELETE FROM {TD_PLOTTER_SEQUENCES_TABLE}")
        conn.execute(f"DELETE FROM {TD_PLOTTER_CURVE_CATALOG_TABLE}")
        conn.execute(f"DELETE FROM {TD_PLOTTER_OBSERVATIONS_TABLE}")
        conn.execute(f"DELETE FROM {TD_PLOTTER_CURVES_TABLE}")
        if run_rows_to_write:
            conn.executemany(
                "INSERT OR REPLACE INTO td_runs(run_name, default_x, display_name, run_type, control_period, pulse_width) VALUES (?, ?, ?, ?, ?, ?)",
                run_rows_to_write,
            )
        if column_rows_to_write:
            conn.executemany(
                "INSERT OR REPLACE INTO td_columns_calc(run_name, name, units, kind) VALUES (?, ?, ?, ?)",
                column_rows_to_write,
            )
        if obs_rows_to_write:
            conn.executemany(
                """
                INSERT OR REPLACE INTO td_condition_observations(
                    observation_id, serial, run_name, program_title, source_run_name, run_type, pulse_width, control_period, suppression_voltage, valve_voltage, source_mtime_ns, computed_epoch_ns
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                obs_rows_to_write,
            )
        if metric_rows_to_write:
            conn.executemany(
                """
                INSERT OR REPLACE INTO td_metrics_calc
                (observation_id, serial, run_name, column_name, stat, value_num, computed_epoch_ns, source_mtime_ns, program_title, source_run_name)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                metric_rows_to_write,
            )
        if plotter_sequence_rows:
            conn.executemany(
                f"""
                INSERT OR REPLACE INTO {TD_PLOTTER_SEQUENCES_TABLE}
                (run_name, display_name, x_axis_kind, source_run_name, pulse_width, run_type, control_period, computed_epoch_ns)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                """,
                plotter_sequence_rows,
            )
        if plotter_catalog_rows_to_write:
            conn.executemany(
                f"""
                INSERT OR REPLACE INTO {TD_PLOTTER_CURVE_CATALOG_TABLE}
                (run_name, parameter_name, units, x_axis_kind, display_name, source_kind, computed_epoch_ns)
                VALUES (?, ?, ?, ?, ?, ?, ?)
                """,
                plotter_catalog_rows_to_write,
            )
        plotter_obs_rows_to_write = list(plotter_obs_rows_by_id.values())
        if plotter_obs_rows_to_write:
            conn.executemany(
                f"""
                INSERT OR REPLACE INTO {TD_PLOTTER_OBSERVATIONS_TABLE}
                (observation_id, run_name, serial, program_title, source_run_name, run_type, pulse_width, control_period, suppression_voltage, valve_voltage, source_mtime_ns, computed_epoch_ns)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                plotter_obs_rows_to_write,
            )
        if plotter_curve_rows_to_write:
            conn.executemany(
                f"""
                INSERT OR REPLACE INTO {TD_PLOTTER_CURVES_TABLE}
                (run_name, y_name, x_name, observation_id, serial, x_json, y_json, n_points, source_mtime_ns, computed_epoch_ns, program_title, source_run_name)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                plotter_curve_rows_to_write,
            )
        sequence_metric_rows_list = list(sequence_metric_rows or [])
        if sequence_obs_rows_list:
            conn.executemany(
                """
                INSERT OR REPLACE INTO td_condition_observations_sequences(
                    observation_id, serial, run_name, program_title, source_run_name, run_type, pulse_width, control_period, suppression_voltage, valve_voltage, source_mtime_ns, computed_epoch_ns
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                sequence_obs_rows_list,
            )
            sequence_observations_written = len(sequence_obs_rows_list)
        if sequence_metric_rows_list:
            conn.executemany(
                """
                INSERT OR REPLACE INTO td_metrics_calc_sequences
                (observation_id, serial, run_name, column_name, stat, value_num, computed_epoch_ns, source_mtime_ns, program_title, source_run_name)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                sequence_metric_rows_list,
            )
            sequence_metrics_written = len(sequence_metric_rows_list)
        _td_emit_progress(progress_cb, "Calculating TD life metrics")
        life_metrics_written = _td_rebuild_life_metrics(
            conn,
            workbook_path=wb_path,
            project_cfg=project_cfg,
            raw_db_path=raw_db_path,
            computed_epoch_ns=int(computed_epoch_ns),
        )
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            ("workbook_path", str(wb_path)),
        )
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            ("built_epoch_ns", str(int(computed_epoch_ns))),
        )
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            ("statistics", ",".join([str(s) for s in selected_stats])),
        )
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            ("support_workbook_path", str(support_cfg.get("path") or "")),
        )
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            ("support_workbook_mtime_ns", str(int(support_mtime_ns))),
        )
        support_signatures = _td_support_signatures(support_cfg)
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            ("support_raw_signature", str(support_signatures.get("raw") or "")),
        )
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            ("support_calc_signature", str(support_signatures.get("calc") or "")),
        )
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            ("td_builder_signature", _td_builder_signature()),
        )
        conn.commit()
    timings["calc_write_s"] = round(time.perf_counter() - t0, 3)
    timings["total_s"] = round(time.perf_counter() - total_started, 3)

    return {
        "db_path": str(db_path),
        "workbook": str(wb_path),
        "metrics_written": metrics_written,
        "calc_columns_written": calc_columns_written,
        "sequence_observations_written": sequence_observations_written,
        "sequence_metrics_written": sequence_metrics_written,
        "life_metrics_written": life_metrics_written,
        "mode": "calc_from_current_pass",
        "timings": dict(timings),
    }


def _rebuild_test_data_project_calc_cache_from_raw(
    db_path: Path,
    workbook_path: Path,
    *,
    progress_cb: Callable[[str], None] | None = None,
) -> dict:
    import time
    import statistics

    def _apply_last_n_rows_limit(values: list[T], last_n_rows: int | None) -> list[T]:
        if last_n_rows is None:
            return values
        try:
            limit = int(last_n_rows)
        except Exception:
            return values
        if limit <= 0:
            return values
        prior_rows = values[:-1]
        effective_limit = max(0, limit - 1)
        if effective_limit == 0:
            return []
        if len(prior_rows) <= effective_limit:
            return prior_rows
        return prior_rows[-effective_limit:]

    def _finite_float(v: object) -> float | None:
        if v is None:
            return None
        if isinstance(v, (int, float)):
            f = float(v)
        else:
            t = str(v).strip().replace(",", "")
            if not t:
                return None
            try:
                f = float(t)
            except Exception:
                return None
        if math.isfinite(f):
            return f
        return None

    def _compute_stats(values: list[float]) -> dict[str, float | int | None]:
        n = len(values)
        if n == 0:
            return {"mean": None, "min": None, "max": None, "std": None, "median": None, "count": 0}
        out: dict[str, float | int | None] = {
            "mean": (sum(values) / n),
            "min": min(values),
            "max": max(values),
            "median": statistics.median(values),
            "count": n,
        }
        out["std"] = statistics.stdev(values) if n >= 2 else None
        return out

    def _compute_constant_stats(value: float) -> dict[str, float | int | None]:
        return {
            "mean": float(value),
            "min": float(value),
            "max": float(value),
            "median": float(value),
            "std": 0.0,
            "count": 1,
        }

    def _filter_curve_values(
        xs: list[object],
        ys: list[object],
        *,
        exclude_first_n: int | None,
        last_n_rows: int | None,
    ) -> list[float]:
        filtered: list[float] = []
        for raw_x, raw_y in zip(xs, ys):
            fx = _finite_float(raw_x)
            fy = _finite_float(raw_y)
            if fx is None or fy is None:
                continue
            filtered.append(float(fy))
        if exclude_first_n is not None and int(exclude_first_n) > 0:
            filtered = filtered[int(exclude_first_n):]
        return _apply_last_n_rows_limit(filtered, last_n_rows)

    wb_path = Path(workbook_path).expanduser()
    if not wb_path.exists():
        raise FileNotFoundError(f"Workbook not found: {wb_path}")
    db_path = Path(db_path).expanduser()
    if not db_path.exists():
        raise FileNotFoundError(f"Project cache DB not found: {db_path}")
    raw_db_path = _td_resolve_raw_cache_db_path(db_path)
    if not raw_db_path.exists() or not raw_db_path.is_file():
        raise RuntimeError(
            f"Project raw cache DB not found: {raw_db_path}. "
            f"Run 'Update Project' first to create or refresh {EIDAT_PROJECT_TD_RAW_CACHE_DB}."
        )

    project_cfg = _load_project_td_trend_config(wb_path)
    cfg_cols = [dict(c) for c in (project_cfg.get("columns") or []) if isinstance(c, dict)]
    cfg_units = {
        str(c.get("name") or "").strip(): str(c.get("units") or "").strip()
        for c in cfg_cols
        if str(c.get("name") or "").strip()
    }
    selected_stats = _td_cache_selected_stats(project_cfg.get("statistics"))

    support_cfg = _read_td_support_workbook(wb_path, project_dir=db_path.parent)
    support_settings = dict(support_cfg.get("settings") or {})
    bounds_by_sequence = {
        str(k).strip(): dict(v)
        for k, v in (support_cfg.get("bounds_by_sequence") or {}).items()
        if str(k).strip() and isinstance(v, dict)
    }
    computed_epoch_ns = time.time_ns()
    total_started = time.perf_counter()
    timings: dict[str, float] = {
        "raw_cache_read_s": 0.0,
        "calc_aggregate_s": 0.0,
        "calc_write_s": 0.0,
        "total_s": 0.0,
    }

    _td_emit_progress(progress_cb, "Reading raw Test Data cache")
    t0 = time.perf_counter()
    with sqlite3.connect(str(raw_db_path)) as raw_conn:
        _ensure_test_data_raw_cache_tables(raw_conn)
        raw_runs = raw_conn.execute(
            """
            SELECT
                run_name,
                COALESCE(display_name, ''),
                COALESCE(x_axis_kind, ''),
                COALESCE(source_run_name, ''),
                pulse_width,
                COALESCE(run_type, ''),
                control_period,
                computed_epoch_ns
            FROM td_raw_sequences
            ORDER BY run_name
            """
        ).fetchall()
        raw_curve_catalog_rows = raw_conn.execute(
            """
            SELECT
                run_name,
                parameter_name,
                COALESCE(units, ''),
                COALESCE(x_axis_kind, ''),
                COALESCE(display_name, ''),
                COALESCE(source_kind, ''),
                computed_epoch_ns
            FROM td_raw_curve_catalog
            ORDER BY run_name, parameter_name
            """
        ).fetchall()
        raw_x_cols = raw_conn.execute(
            "SELECT run_name, name FROM td_columns_raw WHERE kind='x' ORDER BY run_name, name"
        ).fetchall()
        raw_y_cols = raw_conn.execute(
            "SELECT run_name, name FROM td_columns_raw WHERE kind='y' ORDER BY run_name, name"
        ).fetchall()
        try:
            raw_curve_rows = raw_conn.execute(
                """
                SELECT
                    run_name,
                    y_name,
                    x_name,
                    observation_id,
                    serial,
                    COALESCE(program_title, ''),
                    COALESCE(source_run_name, ''),
                    x_json,
                    y_json,
                    n_points,
                    source_mtime_ns,
                    computed_epoch_ns
                FROM td_curves_raw
                ORDER BY run_name, serial, y_name, observation_id
                """
            ).fetchall()
        except Exception:
            raw_curve_rows = [
                (
                    run_name,
                    y_name,
                    x_name,
                    f"{_td_norm_ident_token(serial)}__{_td_norm_ident_token(run_name)}",
                    serial,
                    "",
                    run_name,
                    x_json,
                    y_json,
                    n_points,
                    source_mtime_ns,
                    computed_epoch_ns,
                )
                for run_name, y_name, x_name, serial, x_json, y_json, n_points, source_mtime_ns, computed_epoch_ns in raw_conn.execute(
                    """
                    SELECT run_name, y_name, x_name, serial, x_json, y_json, n_points, source_mtime_ns, computed_epoch_ns
                    FROM td_curves_raw
                    ORDER BY run_name, serial, y_name
                    """
                ).fetchall()
            ]
        try:
            raw_obs_rows = raw_conn.execute(
                """
                SELECT
                    observation_id,
                    run_name,
                    serial,
                    COALESCE(program_title, ''),
                    COALESCE(source_run_name, ''),
                    COALESCE(run_type, ''),
                    pulse_width,
                    control_period,
                    suppression_voltage,
                    valve_voltage,
                    source_mtime_ns,
                    computed_epoch_ns
                FROM td_raw_condition_observations
                ORDER BY run_name, serial, observation_id
                """
            ).fetchall()
        except Exception:
            raw_obs_rows = []
    timings["raw_cache_read_s"] = round(time.perf_counter() - t0, 3)
    _td_emit_progress(
        progress_cb,
        "Read raw Test Data cache complete "
        + f"in {timings['raw_cache_read_s']:.3f}s (runs={len(raw_runs)}, y_columns={len(raw_y_cols)}, curves={len(raw_curve_rows)})",
    )
    if not raw_runs or not raw_y_cols or not raw_curve_rows:
        raise RuntimeError(
            f"Project raw cache DB is incomplete: {raw_db_path}. "
            f"Run 'Update Project' first to create or refresh {EIDAT_PROJECT_TD_RAW_CACHE_DB}."
        )
    _td_emit_progress(progress_cb, "Aggregating calculated metrics from raw cache")
    with sqlite3.connect(str(db_path)) as conn:
        _ensure_test_data_impl_tables(conn)
        _purge_test_data_legacy_impl_raw_tables(conn)
        existing_display_names = {
            str(run_name or "").strip(): {
                "display_name": str(display_name or "").strip(),
                "run_type": str(run_type or "").strip(),
                "control_period": control_period,
                "pulse_width": pulse_width,
            }
            for run_name, display_name, run_type, control_period, pulse_width in conn.execute(
                "SELECT run_name, display_name, COALESCE(run_type, ''), control_period, pulse_width FROM td_runs"
            ).fetchall()
            if str(run_name or "").strip()
        }

        conn.execute("DELETE FROM td_runs")
        conn.execute("DELETE FROM td_columns_calc")
        conn.execute("DELETE FROM td_metrics_calc")
        conn.execute("DELETE FROM td_condition_observations")
        conn.execute("DELETE FROM td_metrics_calc_sequences")
        conn.execute("DELETE FROM td_condition_observations_sequences")
        conn.execute(f"DELETE FROM {TD_PLOTTER_SEQUENCES_TABLE}")
        conn.execute(f"DELETE FROM {TD_PLOTTER_CURVE_CATALOG_TABLE}")
        conn.execute(f"DELETE FROM {TD_PLOTTER_OBSERVATIONS_TABLE}")
        conn.execute(f"DELETE FROM {TD_PLOTTER_CURVES_TABLE}")

        raw_x_by_run: dict[str, list[str]] = {}
        raw_y_by_run: dict[str, set[str]] = {}
        raw_run_defaults: dict[str, dict[str, object]] = {}
        for run_name, x_name in raw_x_cols:
            run = str(run_name or "").strip()
            x = str(x_name or "").strip()
            if run and x:
                raw_x_by_run.setdefault(run, []).append(x)
        for run_name, y_name in raw_y_cols:
            run = str(run_name or "").strip()
            y = str(y_name or "").strip()
            if run and y:
                raw_y_by_run.setdefault(run, set()).add(y)
        plotter_sequence_rows: list[tuple[object, ...]] = []
        for run_name, display_name_raw, default_x_raw, source_run_name_raw, raw_pulse_width, raw_run_type, raw_control_period, raw_run_computed_epoch_ns in raw_runs:
            run = str(run_name or "").strip()
            if not run:
                continue
            source_run_name_txt = str(source_run_name_raw or "").strip()
            raw_run_defaults[run] = {
                "display_name": str(display_name_raw or "").strip(),
                "default_x": str(default_x_raw or "").strip(),
                "source_run_name": source_run_name_txt,
                "pulse_width": raw_pulse_width,
                "run_type": str(raw_run_type or "").strip(),
                "control_period": raw_control_period,
            }
            plotter_sequence_rows.append(
                (
                    run,
                    str(display_name_raw or "").strip(),
                    str(default_x_raw or "").strip(),
                    source_run_name_txt,
                    raw_pulse_width,
                    str(raw_run_type or "").strip(),
                    raw_control_period,
                    int(raw_run_computed_epoch_ns or computed_epoch_ns),
                )
            )

        plotter_catalog_rows_to_write: list[tuple[object, ...]] = []
        for run_name, parameter_name, units, x_axis_kind, display_name, source_kind, catalog_computed_epoch_ns in raw_curve_catalog_rows:
            run = str(run_name or "").strip()
            parameter = str(parameter_name or "").strip()
            x_axis = str(x_axis_kind or "").strip()
            if not run or not parameter or not x_axis:
                continue
            plotter_catalog_rows_to_write.append(
                (
                    run,
                    parameter,
                    str(units or "").strip(),
                    x_axis,
                    str(display_name or "").strip(),
                    str(source_kind or "").strip(),
                    int(catalog_computed_epoch_ns or computed_epoch_ns),
                )
            )

        raw_obs_by_id: dict[str, dict[str, object]] = {}
        plotter_obs_rows_by_id: dict[str, tuple[object, ...]] = {}
        for observation_id, run_name, serial, program_title, source_run_name, run_type, pulse_width, control_period, suppression_voltage, valve_voltage, source_mtime_ns, obs_computed_epoch_ns in raw_obs_rows:
            obs_id = str(observation_id or "").strip()
            if not obs_id:
                continue
            run_txt = str(run_name or "").strip()
            serial_txt = str(serial or "").strip()
            program_txt = str(program_title or "").strip()
            source_run_txt = str(source_run_name or "").strip()
            raw_obs_by_id[obs_id] = {
                "observation_id": obs_id,
                "run_name": run_txt,
                "serial": serial_txt,
                "program_title": program_txt,
                "source_run_name": source_run_txt,
                "run_type": str(run_type or "").strip(),
                "pulse_width": pulse_width,
                "control_period": control_period,
                "suppression_voltage": suppression_voltage,
                "valve_voltage": valve_voltage,
                "source_mtime_ns": source_mtime_ns,
            }
            plotter_obs_rows_by_id[obs_id] = (
                obs_id,
                run_txt,
                serial_txt,
                program_txt,
                source_run_txt,
                str(run_type or "").strip(),
                pulse_width,
                control_period,
                suppression_voltage,
                valve_voltage,
                source_mtime_ns,
                int(obs_computed_epoch_ns or computed_epoch_ns),
            )
        plotter_curve_rows_to_write: list[tuple[object, ...]] = []
        for run_name, y_name, x_name, observation_id, serial, program_title, source_run_name, x_json, y_json, n_points, source_mtime_ns, curve_computed_epoch_ns in raw_curve_rows:
            obs_id = str(observation_id or "").strip()
            run_txt = str(run_name or "").strip()
            serial_txt = str(serial or "").strip()
            program_txt = str(program_title or "").strip()
            source_run_txt = str(source_run_name or run_txt).strip() or run_txt
            y_name_txt = str(y_name or "").strip()
            x_name_txt = str(x_name or "").strip()
            if obs_id and obs_id not in raw_obs_by_id:
                raw_obs_by_id[obs_id] = {
                    "observation_id": obs_id,
                    "run_name": run_txt,
                    "serial": serial_txt,
                    "program_title": program_txt,
                    "source_run_name": source_run_txt,
                    "run_type": "",
                    "pulse_width": None,
                    "control_period": None,
                    "suppression_voltage": None,
                    "valve_voltage": None,
                    "source_mtime_ns": source_mtime_ns,
                }
                plotter_obs_rows_by_id[obs_id] = (
                    obs_id,
                    run_txt,
                    serial_txt,
                    program_txt,
                    source_run_txt,
                    "",
                    None,
                    None,
                    None,
                    None,
                    source_mtime_ns,
                    int(curve_computed_epoch_ns or computed_epoch_ns),
                )
            if not run_txt or not y_name_txt or not x_name_txt or not obs_id or not serial_txt:
                continue
            try:
                n_points_int = int(n_points)
            except Exception:
                try:
                    n_points_int = max(len(json.loads(x_json or "[]")), len(json.loads(y_json or "[]")))
                except Exception:
                    n_points_int = 0
            plotter_curve_rows_to_write.append(
                (
                    run_txt,
                    y_name_txt,
                    x_name_txt,
                    obs_id,
                    serial_txt,
                    x_json or "[]",
                    y_json or "[]",
                    max(0, int(n_points_int)),
                    source_mtime_ns,
                    int(curve_computed_epoch_ns or computed_epoch_ns),
                    program_txt,
                    source_run_txt,
                )
            )
        support_rows = [
            dict(row)
            for row in ((support_cfg.get("sequences") or []))
            if isinstance(row, dict) and bool(row.get("enabled", True))
        ]
        if not support_rows:
            support_rows = [_td_support_program_row_defaults(run_name) for run_name in raw_run_defaults.keys() if str(run_name or "").strip()]
        support_by_program_source: dict[tuple[str, str], dict] = {}
        support_by_source: dict[str, list[dict]] = {}
        for row in support_rows:
            program_key = _td_support_norm_name(row.get("program_title"))
            source_key = _td_support_norm_name(row.get("source_run_name"))
            if source_key:
                support_by_program_source[(program_key, source_key)] = dict(row)
                support_by_source.setdefault(source_key, []).append(dict(row))

        condition_meta_by_key = {
            str(row.get("condition_key") or "").strip(): dict(row)
            for row in ((support_cfg.get("condition_groups") or support_cfg.get("run_conditions") or []))
            if isinstance(row, dict) and str(row.get("condition_key") or "").strip()
        }

        aggregated_curve_values: dict[tuple[str, str, str], list[float]] = {}
        aggregated_obs_meta: dict[tuple[str, str], dict[str, object]] = {}
        condition_y_names: dict[str, set[str]] = {}
        condition_units_by_name: dict[str, dict[str, str]] = {}
        sequence_obs_rows_by_id: dict[str, tuple[object, ...]] = {}
        sequence_metric_rows_by_key: dict[tuple[str, str, str], tuple[object, ...]] = {}
        raw_curve_units_by_run_param: dict[tuple[str, str], str] = {}
        for run_name, parameter_name, units, _x_axis_kind, _display_name, _source_kind, _catalog_epoch_ns in raw_curve_catalog_rows:
            run_txt = str(run_name or "").strip()
            parameter_txt = str(parameter_name or "").strip()
            units_txt = str(units or "").strip()
            if run_txt and parameter_txt and units_txt and (run_txt, parameter_txt) not in raw_curve_units_by_run_param:
                raw_curve_units_by_run_param[(run_txt, parameter_txt)] = units_txt
        t0 = time.perf_counter()
        for run_name_raw, y_name_raw, x_name_raw, observation_id, serial, program_title, source_run_name_raw, x_json, y_json, _n_points, source_mtime_ns, _curve_computed_epoch_ns in raw_curve_rows:
            raw_run = str(run_name_raw or "").strip()
            y_name = str(y_name_raw or "").strip()
            obs_id = str(observation_id or "").strip()
            serial_txt = str(serial or "").strip()
            if not raw_run or not y_name or not serial_txt or not obs_id:
                continue
            source_run_name = str(source_run_name_raw or raw_run).strip() or raw_run
            program_norm = _td_support_norm_name(program_title)
            source_norm = _td_support_norm_name(source_run_name)
            support_row = dict(support_by_program_source.get((program_norm, source_norm)) or {})
            if not support_row:
                source_candidates = [dict(row) for row in (support_by_source.get(source_norm) or []) if isinstance(row, dict)]
                if not program_norm and source_candidates:
                    support_row = source_candidates[0]
                elif program_norm:
                    blank_program_candidates = [row for row in source_candidates if not str(row.get("program_title") or "").strip()]
                    if len(blank_program_candidates) == 1:
                        support_row = blank_program_candidates[0]
            if not support_row or not bool(support_row.get("enabled", True)):
                continue
            condition_key = str(support_row.get("condition_key") or source_run_name).strip() or source_run_name
            try:
                xs = json.loads(x_json or "[]")
            except Exception:
                xs = []
            try:
                ys = json.loads(y_json or "[]")
            except Exception:
                ys = []
            exclude_first_n = support_row.get("exclude_first_n")
            if exclude_first_n is None:
                exclude_first_n = support_settings.get("exclude_first_n_default")
            last_n_rows = support_row.get("last_n_rows")
            if last_n_rows is None:
                last_n_rows = support_settings.get("last_n_rows_default")
            filtered_y = _filter_curve_values(
                xs,
                ys,
                exclude_first_n=_to_support_int(exclude_first_n),
                last_n_rows=_to_support_int(last_n_rows),
            )
            condition_y_names.setdefault(condition_key, set()).add(y_name)
            units_txt = str(raw_curve_units_by_run_param.get((raw_run, y_name)) or "").strip()
            if units_txt:
                condition_units_by_name.setdefault(condition_key, {}).setdefault(y_name, units_txt)
            aggregated_curve_values.setdefault((condition_key, serial_txt, y_name), []).extend(filtered_y)
            obs_meta = aggregated_obs_meta.setdefault(
                (condition_key, serial_txt),
                {
                    "program_titles": set(),
                    "source_run_names": set(),
                    "source_mtime_ns": [],
                },
            )
            prog_txt = str(program_title or "").strip()
            if prog_txt:
                obs_meta["program_titles"].add(prog_txt)
            obs_meta["source_run_names"].add(source_run_name)
            if isinstance(source_mtime_ns, int):
                obs_meta["source_mtime_ns"].append(int(source_mtime_ns))

            raw_obs_meta = dict(raw_obs_by_id.get(obs_id) or {})
            sequence_pulse_width = _finite_float(
                support_row.get("pulse_width_on", support_row.get("pulse_width", raw_obs_meta.get("pulse_width")))
            )
            sequence_control_period = _finite_float(
                support_row.get("control_period", raw_obs_meta.get("control_period"))
            )
            sequence_suppression_voltage = _finite_float(
                support_row.get("suppression_voltage", raw_obs_meta.get("suppression_voltage"))
            )
            sequence_valve_voltage = _finite_float(
                support_row.get("valve_voltage", raw_obs_meta.get("valve_voltage"))
            )
            sequence_run_type = str(
                support_row.get("run_type") or raw_obs_meta.get("run_type") or ""
            ).strip()
            sequence_source_mtime = int(source_mtime_ns or raw_obs_meta.get("source_mtime_ns") or 0)
            sequence_obs_rows_by_id[obs_id] = (
                obs_id,
                serial_txt,
                condition_key,
                prog_txt,
                source_run_name,
                sequence_run_type,
                sequence_pulse_width,
                sequence_control_period,
                sequence_suppression_voltage,
                sequence_valve_voltage,
                sequence_source_mtime,
                computed_epoch_ns,
            )
            stats_map = _compute_stats(list(filtered_y))
            for stat in selected_stats:
                sequence_metric_rows_by_key[(obs_id, y_name, str(stat))] = (
                    obs_id,
                    serial_txt,
                    condition_key,
                    y_name,
                    str(stat),
                    stats_map.get(stat),
                    computed_epoch_ns,
                    sequence_source_mtime,
                    prog_txt,
                    source_run_name,
                )
            if sequence_pulse_width is not None:
                pulse_stats_map = _compute_constant_stats(float(sequence_pulse_width))
                for stat in selected_stats:
                    sequence_metric_rows_by_key[(obs_id, "pulse_width", str(stat))] = (
                        obs_id,
                        serial_txt,
                        condition_key,
                        "pulse_width",
                        str(stat),
                        pulse_stats_map.get(stat),
                        computed_epoch_ns,
                        sequence_source_mtime,
                        prog_txt,
                        source_run_name,
                    )

        metrics_written = 0
        calc_columns_written = 0
        inserted_columns: set[tuple[str, str]] = set()
        inserted_runs: set[str] = set()
        run_rows_to_write: list[tuple[object, ...]] = []
        column_rows_to_write: list[tuple[object, ...]] = []
        obs_rows_to_write: list[tuple[object, ...]] = []
        metric_rows_to_write: list[tuple[object, ...]] = []
        sequence_rows_by_condition_serial, sequence_rows_by_condition = _td_group_sequence_observation_rows(
            list(sequence_obs_rows_by_id.values())
        )
        for (condition_key, serial_txt), meta in aggregated_obs_meta.items():
            condition_meta = dict(condition_meta_by_key.get(condition_key) or {})
            run_display_name = str(condition_meta.get("display_name") or condition_key).strip() or condition_key
            default_x = "Time"
            member_source_runs = sorted({str(v).strip() for v in (meta.get("source_run_names") or set()) if str(v).strip()})
            for source_run in member_source_runs:
                raw_default = str((raw_run_defaults.get(source_run) or {}).get("default_x") or "").strip()
                if raw_default:
                    default_x = raw_default
                    break
            condition_sequence_rows = sequence_rows_by_condition.get(condition_key) or []
            run_pulse_width_value = _td_first_finite_from_values(
                condition_meta.get("pulse_width_on"),
                condition_meta.get("pulse_width"),
            )
            if run_pulse_width_value is None:
                run_pulse_width_value = _td_unique_sequence_float(condition_sequence_rows, TD_SEQUENCE_OBS_PULSE_WIDTH_IDX)
            run_control_period_value = _td_first_finite_from_values(condition_meta.get("control_period"))
            if run_control_period_value is None:
                run_control_period_value = _td_unique_sequence_float(condition_sequence_rows, TD_SEQUENCE_OBS_CONTROL_PERIOD_IDX)
            run_suppression_voltage_value = _td_first_finite_from_values(condition_meta.get("suppression_voltage"))
            if run_suppression_voltage_value is None:
                run_suppression_voltage_value = _td_unique_sequence_float(
                    condition_sequence_rows,
                    TD_SEQUENCE_OBS_SUPPRESSION_VOLTAGE_IDX,
                )
            run_valve_voltage_value = _td_first_finite_from_values(condition_meta.get("valve_voltage"))
            if run_valve_voltage_value is None:
                run_valve_voltage_value = _td_unique_sequence_float(condition_sequence_rows, TD_SEQUENCE_OBS_VALVE_VOLTAGE_IDX)
            run_type_text = _td_first_text_from_values(
                condition_meta.get("run_type"),
                _td_unique_sequence_text(condition_sequence_rows, TD_SEQUENCE_OBS_RUN_TYPE_IDX),
            )
            if condition_key not in inserted_runs:
                inserted_runs.add(condition_key)
                run_rows_to_write.append(
                    (
                        condition_key,
                        default_x,
                        run_display_name,
                        run_type_text,
                        run_control_period_value,
                        run_pulse_width_value,
                    )
                )
                calc_param_defs = _td_complete_calc_param_defs(
                    ordered_defs=_ordered_support_param_defs(
                        sequence_names=[condition_key],
                        support_cfg={"bounds_by_sequence": {condition_key: bounds_by_sequence.get(condition_key) or {}}, "settings": support_settings},
                        fallback_defs=cfg_cols,
                    )
                    or [dict(d) for d in cfg_cols if isinstance(d, dict)],
                    discovered_names=sorted(condition_y_names.get(condition_key) or set(), key=str.casefold),
                    units_by_name=dict(condition_units_by_name.get(condition_key) or {}),
                    fallback_units=cfg_units,
                )
                for param_def in calc_param_defs:
                    col_name = str(param_def.get("name") or "").strip()
                    if not col_name:
                        continue
                    if (condition_key, col_name) in inserted_columns:
                        continue
                    inserted_columns.add((condition_key, col_name))
                    column_rows_to_write.append(
                        (condition_key, col_name, str(param_def.get("units") or cfg_units.get(col_name) or "").strip(), "y")
                    )
                    calc_columns_written += 1
                if run_pulse_width_value is not None and (condition_key, "pulse_width") not in inserted_columns:
                    inserted_columns.add((condition_key, "pulse_width"))
                    column_rows_to_write.append(
                        (condition_key, "pulse_width", str(cfg_units.get("pulse_width") or "").strip(), "y")
                    )
                    calc_columns_written += 1

            observation_id_calc = f"{_td_norm_ident_token(serial_txt)}__{_td_norm_ident_token(condition_key)}"
            program_titles_txt = ", ".join(sorted({str(v).strip() for v in (meta.get("program_titles") or set()) if str(v).strip()}))
            member_source_runs_txt = ", ".join(member_source_runs)
            source_mtime_max = max([int(v) for v in (meta.get("source_mtime_ns") or [])], default=0)
            serial_sequence_rows = sequence_rows_by_condition_serial.get((condition_key, serial_txt)) or condition_sequence_rows
            pulse_width_value = run_pulse_width_value
            if pulse_width_value is None:
                pulse_width_value = _td_unique_sequence_float(serial_sequence_rows, TD_SEQUENCE_OBS_PULSE_WIDTH_IDX)
            control_period_value = run_control_period_value
            if control_period_value is None:
                control_period_value = _td_unique_sequence_float(serial_sequence_rows, TD_SEQUENCE_OBS_CONTROL_PERIOD_IDX)
            suppression_voltage_value = run_suppression_voltage_value
            if suppression_voltage_value is None:
                suppression_voltage_value = _td_unique_sequence_float(serial_sequence_rows, TD_SEQUENCE_OBS_SUPPRESSION_VOLTAGE_IDX)
            valve_voltage_value = run_valve_voltage_value
            if valve_voltage_value is None:
                valve_voltage_value = _td_unique_sequence_float(serial_sequence_rows, TD_SEQUENCE_OBS_VALVE_VOLTAGE_IDX)
            obs_run_type_text = run_type_text or _td_unique_sequence_text(serial_sequence_rows, TD_SEQUENCE_OBS_RUN_TYPE_IDX)
            obs_rows_to_write.append(
                (
                    observation_id_calc,
                    serial_txt,
                    condition_key,
                    program_titles_txt,
                    member_source_runs_txt,
                    obs_run_type_text,
                    pulse_width_value,
                    control_period_value,
                    suppression_voltage_value,
                    valve_voltage_value,
                    source_mtime_max,
                    computed_epoch_ns,
                )
            )
            for y_name in sorted(condition_y_names.get(condition_key) or set()):
                values = list(aggregated_curve_values.get((condition_key, serial_txt, y_name)) or [])
                stats_map = _compute_stats(values)
                for stat in selected_stats:
                    metric_rows_to_write.append(
                        (
                            observation_id_calc,
                            serial_txt,
                            condition_key,
                            y_name,
                            str(stat),
                            stats_map.get(stat),
                            computed_epoch_ns,
                            source_mtime_max,
                            program_titles_txt,
                            member_source_runs_txt,
                        )
                    )
                    metrics_written += 1
            if pulse_width_value is not None:
                stats_map = _compute_constant_stats(float(pulse_width_value))
                for stat in selected_stats:
                    metric_rows_to_write.append(
                        (
                            observation_id_calc,
                            serial_txt,
                            condition_key,
                            "pulse_width",
                            str(stat),
                            stats_map.get(stat),
                            computed_epoch_ns,
                            source_mtime_max,
                            program_titles_txt,
                            member_source_runs_txt,
                        )
                    )
                    metrics_written += 1
        timings["calc_aggregate_s"] = round(time.perf_counter() - t0, 3)
        _td_emit_progress(
            progress_cb,
            "Aggregated calculated metrics from raw cache "
            + f"in {timings['calc_aggregate_s']:.3f}s "
            + f"(conditions={len(aggregated_obs_meta)}, metric_rows={len(metric_rows_to_write)}, sequence_metric_rows={len(sequence_metric_rows_by_key)})",
        )

        support_mtime_ns = 0
        try:
            support_path_meta = Path(str(support_cfg.get("path") or "")).expanduser()
            if support_path_meta.exists():
                st = support_path_meta.stat()
                support_mtime_ns = int(getattr(st, "st_mtime_ns", int(st.st_mtime * 1e9)))
        except Exception:
            support_mtime_ns = 0

        _td_emit_progress(progress_cb, "Writing calculated Test Data cache")
        t0 = time.perf_counter()
        if run_rows_to_write:
            conn.executemany(
                "INSERT OR REPLACE INTO td_runs(run_name, default_x, display_name, run_type, control_period, pulse_width) VALUES (?, ?, ?, ?, ?, ?)",
                run_rows_to_write,
            )
        if column_rows_to_write:
            conn.executemany(
                "INSERT OR REPLACE INTO td_columns_calc(run_name, name, units, kind) VALUES (?, ?, ?, ?)",
                column_rows_to_write,
            )
        if obs_rows_to_write:
            conn.executemany(
                """
                INSERT OR REPLACE INTO td_condition_observations(
                    observation_id, serial, run_name, program_title, source_run_name, run_type, pulse_width, control_period, suppression_voltage, valve_voltage, source_mtime_ns, computed_epoch_ns
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                obs_rows_to_write,
            )
        if metric_rows_to_write:
            conn.executemany(
                """
                INSERT OR REPLACE INTO td_metrics_calc
                (observation_id, serial, run_name, column_name, stat, value_num, computed_epoch_ns, source_mtime_ns, program_title, source_run_name)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                metric_rows_to_write,
            )
        if plotter_sequence_rows:
            conn.executemany(
                f"""
                INSERT OR REPLACE INTO {TD_PLOTTER_SEQUENCES_TABLE}
                (run_name, display_name, x_axis_kind, source_run_name, pulse_width, run_type, control_period, computed_epoch_ns)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                """,
                plotter_sequence_rows,
            )
        if plotter_catalog_rows_to_write:
            conn.executemany(
                f"""
                INSERT OR REPLACE INTO {TD_PLOTTER_CURVE_CATALOG_TABLE}
                (run_name, parameter_name, units, x_axis_kind, display_name, source_kind, computed_epoch_ns)
                VALUES (?, ?, ?, ?, ?, ?, ?)
                """,
                plotter_catalog_rows_to_write,
            )
        plotter_obs_rows_to_write = list(plotter_obs_rows_by_id.values())
        if plotter_obs_rows_to_write:
            conn.executemany(
                f"""
                INSERT OR REPLACE INTO {TD_PLOTTER_OBSERVATIONS_TABLE}
                (observation_id, run_name, serial, program_title, source_run_name, run_type, pulse_width, control_period, suppression_voltage, valve_voltage, source_mtime_ns, computed_epoch_ns)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                plotter_obs_rows_to_write,
            )
        if plotter_curve_rows_to_write:
            conn.executemany(
                f"""
                INSERT OR REPLACE INTO {TD_PLOTTER_CURVES_TABLE}
                (run_name, y_name, x_name, observation_id, serial, x_json, y_json, n_points, source_mtime_ns, computed_epoch_ns, program_title, source_run_name)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                plotter_curve_rows_to_write,
            )
        sequence_obs_rows_to_write = list(sequence_obs_rows_by_id.values())
        sequence_metric_rows_to_write = list(sequence_metric_rows_by_key.values())
        if sequence_obs_rows_to_write:
            conn.executemany(
                """
                INSERT OR REPLACE INTO td_condition_observations_sequences(
                    observation_id, serial, run_name, program_title, source_run_name, run_type, pulse_width, control_period, suppression_voltage, valve_voltage, source_mtime_ns, computed_epoch_ns
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                sequence_obs_rows_to_write,
            )
        if sequence_metric_rows_to_write:
            conn.executemany(
                """
                INSERT OR REPLACE INTO td_metrics_calc_sequences
                (observation_id, serial, run_name, column_name, stat, value_num, computed_epoch_ns, source_mtime_ns, program_title, source_run_name)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                sequence_metric_rows_to_write,
            )
        _td_emit_progress(progress_cb, "Calculating TD life metrics")
        life_metrics_written = _td_rebuild_life_metrics(
            conn,
            workbook_path=wb_path,
            project_cfg=project_cfg,
            raw_db_path=raw_db_path,
            computed_epoch_ns=int(computed_epoch_ns),
        )
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            ("workbook_path", str(wb_path)),
        )
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            ("built_epoch_ns", str(computed_epoch_ns)),
        )
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            ("statistics", ",".join(selected_stats)),
        )
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            ("support_workbook_path", str(support_cfg.get("path") or "")),
        )
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            ("support_workbook_mtime_ns", str(int(support_mtime_ns))),
        )
        support_signatures = _td_support_signatures(support_cfg)
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            ("support_raw_signature", str(support_signatures.get("raw") or "")),
        )
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            ("support_calc_signature", str(support_signatures.get("calc") or "")),
        )
        conn.execute(
            "INSERT OR REPLACE INTO td_meta(key, value) VALUES (?, ?)",
            ("td_builder_signature", _td_builder_signature()),
        )
        conn.commit()
        timings["calc_write_s"] = round(time.perf_counter() - t0, 3)
        _td_emit_progress(
            progress_cb,
            "Wrote calculated Test Data cache "
            + f"in {timings['calc_write_s']:.3f}s "
            + f"(metrics={metrics_written}, calc_columns={calc_columns_written}, life_metrics={life_metrics_written})",
        )

    timings["total_s"] = round(time.perf_counter() - total_started, 3)

    return {
        "db_path": str(db_path),
        "workbook": str(wb_path),
        "metrics_written": metrics_written,
        "calc_columns_written": calc_columns_written,
        "sequence_observations_written": len(sequence_obs_rows_by_id),
        "sequence_metrics_written": len(sequence_metric_rows_by_key),
        "life_metrics_written": life_metrics_written,
        "mode": "calc_from_raw",
        "timings": dict(timings),
    }


def _validate_test_data_project_cache_for_update(project_dir: Path, workbook_path: Path) -> Path:
    """
    Validate that the project-local TD project is fully ready for downstream TD actions.
    """
    guidance = (
        "Run 'Update Project' first to rebuild all required Test Data cache and workbook outputs."
    )
    readiness = _td_ensure_project_ready(project_dir, workbook_path, guidance=guidance)
    return Path(str(readiness.get("db_path") or (Path(project_dir).expanduser() / EIDAT_PROJECT_IMPLEMENTATION_DB))).expanduser()


def validate_existing_test_data_project_cache(project_dir: Path, workbook_path: Path) -> Path:
    """
    Validate that an existing TD project is fully ready for Trend/Analyze.
    """
    guidance = (
        "Run 'Update Project' to rebuild all required Test Data cache and workbook outputs before opening Trend / Analyze."
    )
    readiness = _td_ensure_project_ready(project_dir, workbook_path, guidance=guidance)
    return Path(str(readiness.get("db_path") or (Path(project_dir).expanduser() / EIDAT_PROJECT_IMPLEMENTATION_DB))).expanduser()


def validate_test_data_project_cache_for_open(project_dir: Path, workbook_path: Path) -> Path:
    """
    Fast-open validation for Trend/Analyze.

    This only checks the project-local cache DBs required by the viewer.
    Source freshness belongs to Update Project / explicit cache refresh.
    """
    del workbook_path
    proj_dir = Path(project_dir).expanduser()
    db_path = proj_dir / EIDAT_PROJECT_IMPLEMENTATION_DB
    guidance = "Run 'Update Project' to rebuild the project cache before opening Trend / Analyze."

    if not db_path.exists() or not db_path.is_file():
        raise RuntimeError(f"Project cache DB not found: {db_path}. {guidance}")

    def _check_required_tables(conn: sqlite3.Connection, table_names: Sequence[str]) -> list[str]:
        rows = conn.execute(
            f"SELECT name FROM sqlite_master WHERE type='table' AND name IN ({','.join(['?'] * len(table_names))})",
            tuple(table_names),
        ).fetchall()
        present = {str(row[0] or "").strip() for row in rows if str(row[0] or "").strip()}
        return [name for name in table_names if name not in present]

    try:
        with closing(sqlite3.connect(str(db_path))) as conn:
            missing_impl_tables = _check_required_tables(
                conn,
                (
                    "td_sources",
                    "td_runs",
                    "td_columns_calc",
                    "td_metrics_calc",
                    "td_condition_observations_sequences",
                    "td_metrics_calc_sequences",
                    TD_LIFE_METRICS_TABLE,
                    TD_PARAM_DISCOVERY_TABLE,
                    TD_PARAM_NORM_GROUPS_TABLE,
                    TD_PARAM_NORM_RULES_TABLE,
                    TD_PARAM_RUNTIME_ENTRIES_TABLE,
                    TD_PARAM_RUNTIME_GROUPS_TABLE,
                ),
            )
            if missing_impl_tables:
                raise RuntimeError(
                    f"Project cache DB is missing required tables ({', '.join(missing_impl_tables)}): {db_path}. {guidance}"
                )
            sources_count = int(conn.execute("SELECT COUNT(*) FROM td_sources").fetchone()[0] or 0)
            runs_count = int(conn.execute("SELECT COUNT(*) FROM td_runs").fetchone()[0] or 0)
            calc_y_count = int(conn.execute("SELECT COUNT(*) FROM td_columns_calc WHERE kind='y'").fetchone()[0] or 0)
            metrics_count = int(conn.execute("SELECT COUNT(*) FROM td_metrics_calc").fetchone()[0] or 0)
            sequence_obs_count = int(conn.execute("SELECT COUNT(*) FROM td_condition_observations_sequences").fetchone()[0] or 0)
            sequence_metrics_count = int(conn.execute("SELECT COUNT(*) FROM td_metrics_calc_sequences").fetchone()[0] or 0)
            life_metrics_count = int(conn.execute(f"SELECT COUNT(*) FROM {TD_LIFE_METRICS_TABLE}").fetchone()[0] or 0)
            parameter_runtime_counts = _td_parameter_runtime_counts(conn)
    except RuntimeError:
        raise
    except Exception as exc:
        raise RuntimeError(f"Project cache DB is unreadable: {db_path}. {guidance}") from exc

    if (
        sources_count <= 0
        or runs_count <= 0
        or calc_y_count <= 0
        or metrics_count <= 0
        or sequence_obs_count <= 0
        or sequence_metrics_count <= 0
        or life_metrics_count <= 0
        or not bool(parameter_runtime_counts.get("complete"))
    ):
        raise RuntimeError(f"Project cache DB is incomplete: {db_path}. {guidance}")

    return db_path


def _td_delete_serial_rows_from_cache(
    impl_conn: sqlite3.Connection,
    raw_conn: sqlite3.Connection,
    serials: Sequence[object],
) -> None:
    serial_list = sorted({str(value).strip() for value in (serials or []) if str(value).strip()})
    if not serial_list:
        return
    placeholders = ",".join("?" for _ in serial_list)
    for table_name in ("td_sources", "td_source_metadata", "td_source_diagnostics"):
        try:
            impl_conn.execute(f"DELETE FROM {table_name} WHERE serial IN ({placeholders})", tuple(serial_list))
        except Exception:
            pass
    for table_name in ("td_raw_condition_observations", "td_curves_raw", "td_curves", "td_metrics"):
        try:
            raw_conn.execute(f"DELETE FROM {table_name} WHERE serial IN ({placeholders})", tuple(serial_list))
        except Exception:
            pass
    try:
        raw_tables = [
            str(row[0] or "").strip()
            for row in raw_conn.execute(
                "SELECT name FROM sqlite_master WHERE type='table' AND name GLOB 'td_raw__*' ORDER BY name"
            ).fetchall()
            if str(row[0] or "").strip()
        ]
    except Exception:
        raw_tables = []
    for table_name in raw_tables:
        try:
            safe = table_name.replace('"', '""')
            raw_conn.execute(f'DELETE FROM "{safe}" WHERE serial IN ({placeholders})', tuple(serial_list))
        except Exception:
            pass


def _td_rebuild_raw_summary_tables(
    raw_conn: sqlite3.Connection,
    *,
    cfg_units: Mapping[str, str],
    computed_epoch_ns: int,
) -> None:
    try:
        existing_runs_rows = raw_conn.execute(
            "SELECT run_name, COALESCE(display_name, '') FROM td_runs"
        ).fetchall()
    except Exception:
        existing_runs_rows = []
    display_by_run = {
        str(run_name or "").strip(): str(display_name or "").strip()
        for run_name, display_name in existing_runs_rows
        if str(run_name or "").strip()
    }
    try:
        catalog_rows_existing = raw_conn.execute(
            """
            SELECT run_name, parameter_name, COALESCE(units, ''), COALESCE(display_name, '')
            FROM td_raw_curve_catalog
            """
        ).fetchall()
    except Exception:
        catalog_rows_existing = []
    units_by_run_param = {
        (str(run_name or "").strip(), str(param_name or "").strip()): str(units or "").strip()
        for run_name, param_name, units, _display_name in catalog_rows_existing
        if str(run_name or "").strip() and str(param_name or "").strip()
    }
    for run_name, _param_name, _units, display_name in catalog_rows_existing:
        run = str(run_name or "").strip()
        if run and str(display_name or "").strip() and not display_by_run.get(run):
            display_by_run[run] = str(display_name or "").strip()

    curve_rows = raw_conn.execute(
        """
        SELECT run_name, y_name, x_name, COALESCE(program_title, ''), COALESCE(source_run_name, '')
        FROM td_curves_raw
        ORDER BY run_name, y_name, x_name
        """
    ).fetchall()
    obs_rows = raw_conn.execute(
        """
        SELECT run_name, COALESCE(run_type, ''), pulse_width, control_period
        FROM td_raw_condition_observations
        ORDER BY run_name, observation_id
        """
    ).fetchall()

    raw_conn.execute("DELETE FROM td_runs")
    raw_conn.execute("DELETE FROM td_raw_sequences")
    raw_conn.execute("DELETE FROM td_columns")
    raw_conn.execute("DELETE FROM td_columns_raw")
    raw_conn.execute("DELETE FROM td_raw_curve_catalog")

    run_meta_by_run: dict[str, dict[str, object]] = {}
    for run_name, run_type, pulse_width, control_period in obs_rows:
        run = str(run_name or "").strip()
        if not run or run in run_meta_by_run:
            continue
        run_meta_by_run[run] = {
            "run_type": str(run_type or "").strip(),
            "pulse_width": pulse_width,
            "control_period": control_period,
        }

    x_priority = ["Time", "Pulse Number"]
    x_by_run: dict[str, set[str]] = {}
    y_by_run: dict[str, set[str]] = {}
    for run_name, y_name, x_name, _program_title, _source_run_name in curve_rows:
        run = str(run_name or "").strip()
        y_name_clean = str(y_name or "").strip()
        x_name_clean = str(x_name or "").strip()
        if not run or not y_name_clean:
            continue
        if x_name_clean:
            x_by_run.setdefault(run, set()).add(x_name_clean)
        y_by_run.setdefault(run, set()).add(y_name_clean)

    for run in sorted(set(x_by_run.keys()) | set(y_by_run.keys()), key=lambda value: str(value).lower()):
        xs = sorted(
            list(x_by_run.get(run) or set()),
            key=lambda value: x_priority.index(value) if value in x_priority else 999,
        )
        default_x = xs[0] if xs else ""
        run_meta = dict(run_meta_by_run.get(run) or {})
        display_name = str(display_by_run.get(run) or run).strip() or run
        raw_conn.execute(
            "INSERT OR REPLACE INTO td_runs(run_name, default_x, display_name, run_type, control_period, pulse_width) VALUES (?, ?, ?, ?, ?, ?)",
            (
                run,
                default_x,
                display_name,
                str(run_meta.get('run_type') or "").strip(),
                run_meta.get("control_period"),
                run_meta.get("pulse_width"),
            ),
        )
        raw_conn.execute(
            """
            INSERT OR REPLACE INTO td_raw_sequences(run_name, display_name, x_axis_kind, source_run_name, pulse_width, run_type, control_period, computed_epoch_ns)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                run,
                display_name,
                default_x,
                run,
                run_meta.get("pulse_width"),
                str(run_meta.get("run_type") or "").strip(),
                run_meta.get("control_period"),
                int(computed_epoch_ns),
            ),
        )
        for x_name in xs:
            raw_conn.execute(
                "INSERT OR REPLACE INTO td_columns(run_name, name, units, kind) VALUES (?, ?, ?, ?)",
                (run, x_name, "", "x"),
            )
            raw_conn.execute(
                "INSERT OR REPLACE INTO td_columns_raw(run_name, name, units, kind) VALUES (?, ?, ?, ?)",
                (run, x_name, "", "x"),
            )
        ys = sorted(list(y_by_run.get(run) or set()), key=lambda value: str(value).lower())
        for y_name in ys:
            units = str(units_by_run_param.get((run, y_name)) or cfg_units.get(y_name) or "").strip()
            raw_conn.execute(
                "INSERT OR REPLACE INTO td_columns_raw(run_name, name, units, kind) VALUES (?, ?, ?, ?)",
                (run, y_name, units, "y"),
            )
            raw_conn.execute(
                """
                INSERT OR REPLACE INTO td_raw_curve_catalog
                (run_name, parameter_name, units, x_axis_kind, table_name, display_name, source_kind, computed_epoch_ns)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    run,
                    y_name,
                    units,
                    default_x,
                    _td_raw_curve_table_name(run, y_name),
                    display_name,
                    "source_sqlite",
                    int(computed_epoch_ns),
                ),
            )

    expected_tables = {
        _td_raw_curve_table_name(str(run_name or "").strip(), str(y_name or "").strip())
        for run_name, y_name, _x_name, _program_title, _source_run_name in curve_rows
        if str(run_name or "").strip() and str(y_name or "").strip()
    }
    raw_tables = [
        str(row[0] or "").strip()
        for row in raw_conn.execute(
            "SELECT name FROM sqlite_master WHERE type='table' AND name GLOB 'td_raw__*' ORDER BY name"
        ).fetchall()
        if str(row[0] or "").strip()
    ]
    for table_name in raw_tables:
        if table_name in expected_tables:
            continue
        _sqlite_drop_table(raw_conn, table_name)


def sync_test_data_project_cache(
    project_dir: Path,
    workbook_path: Path,
    *,
    rebuild: bool = False,
    progress_cb: Callable[[str], None] | None = None,
) -> dict[str, object]:
    import time

    proj_dir = Path(project_dir).expanduser()
    wb_path = Path(workbook_path).expanduser()
    if not wb_path.exists():
        raise FileNotFoundError(f"Workbook not found: {wb_path}")
    db_path = proj_dir / EIDAT_PROJECT_IMPLEMENTATION_DB

    state: dict[str, object] = {}
    refresh_reason = ""
    if rebuild:
        _td_emit_progress(progress_cb, "Refreshing raw Test Data cache (forced full rebuild)")
        payload = rebuild_test_data_project_cache(db_path, wb_path, progress_cb=progress_cb)
        payload["mode"] = "full_rebuild"
        payload.setdefault("counts", {})
        payload["reason"] = "forced full rebuild"
    else:
        state = inspect_test_data_project_cache_state(proj_dir, wb_path)
        refresh_mode = str(state.get("mode") or "").strip().lower() or "none"
        refresh_reason = str(state.get("reason") or "").strip()
        if refresh_mode == "full":
            _td_emit_progress(progress_cb, f"Refreshing raw Test Data cache ({refresh_reason})")
            payload = rebuild_test_data_project_cache(db_path, wb_path, progress_cb=progress_cb)
            payload["mode"] = "full_rebuild"
        elif refresh_mode == "incremental_raw":
            _td_emit_progress(progress_cb, f"Refreshing raw Test Data cache ({refresh_reason})")
            payload = rebuild_test_data_project_cache(
                db_path,
                wb_path,
                progress_cb=progress_cb,
                _entries_override=[
                    dict((state.get("source_state_by_serial") or {}).get(serial) or {}).get("source_row")
                    for serial in list(state.get("added_serials") or []) + list(state.get("changed_serials") or [])
                    if dict((state.get("source_state_by_serial") or {}).get(serial) or {}).get("source_row")
                ],
                _full_reset=False,
                _removed_serials=list(state.get("removed_serials") or []),
                _preclassified_counts=dict(state.get("counts") or {}),
            )
            payload["mode"] = "incremental_raw"
        elif refresh_mode == "calc":
            _td_emit_progress(progress_cb, f"Refreshing calculated Test Data cache ({refresh_reason})")
            payload = _rebuild_test_data_project_calc_cache_from_raw(db_path, wb_path, progress_cb=progress_cb)
            payload["mode"] = "calc_only"
            payload["counts"] = dict(state.get("counts") or {})
        else:
            payload = {
                "db_path": str(db_path),
                "raw_db_path": str(td_raw_cache_db_path_for(proj_dir)),
                "workbook": str(wb_path),
                "mode": "noop",
                "counts": dict(state.get("counts") or {}),
                "reason": refresh_reason,
            }
    payload["db_path"] = str(payload.get("db_path") or db_path)
    payload["raw_db_path"] = str(payload.get("raw_db_path") or td_raw_cache_db_path_for(proj_dir))
    payload["workbook"] = str(payload.get("workbook") or wb_path)
    payload["counts"] = dict(payload.get("counts") or state.get("counts") or {})
    payload["reason"] = str(payload.get("reason") or refresh_reason).strip()
    runtime_db_path = Path(str(payload.get("db_path") or db_path)).expanduser()
    repo_parameter_rows = load_td_repo_parameter_mappings(
        proj_dir,
        workbook_path=wb_path,
        db_path=runtime_db_path,
    )
    _td_emit_progress(progress_cb, "Rebuilding project parameter group catalog from ProgramRequirements")
    td_rebuild_project_parameter_units_catalog(
        proj_dir,
        repo_parameter_rows,
    )
    _td_emit_progress(progress_cb, "Refreshing parameter runtime cache")
    t0 = time.perf_counter()
    runtime_payload = refresh_td_parameter_runtime_cache(
        proj_dir,
        wb_path,
        runtime_db_path,
        progress_cb=progress_cb,
    )
    runtime_elapsed = round(time.perf_counter() - t0, 3)
    payload["parameter_runtime"] = dict(runtime_payload)
    timings = dict(payload.get("timings") or {})
    timings["parameter_runtime_s"] = runtime_elapsed
    payload["timings"] = timings
    _td_emit_progress(
        progress_cb,
        "Parameter runtime cache stage complete "
        + f"in {runtime_elapsed:.3f}s (mode={str(runtime_payload.get('mode') or 'unknown').strip() or 'unknown'})",
    )
    return payload


def rebuild_test_data_project_cache(
    db_path: Path,
    workbook_path: Path,
    *,
    progress_cb: Callable[[str], None] | None = None,
    _entries_override: list[dict] | None = None,
    _full_reset: bool = True,
    _removed_serials: Sequence[object] | None = None,
    _preclassified_counts: Mapping[str, object] | None = None,
) -> dict:
    """
    Rebuild `td_*` cache tables inside `implementation_trending.sqlite3` from the
    workbook's `Sources` + `Config` sheets.
    """
    from contextlib import closing
    import time
    import statistics

    wb_path = Path(workbook_path).expanduser()
    if not wb_path.exists():
        raise FileNotFoundError(f"Workbook not found: {wb_path}")
    db_path = Path(db_path).expanduser()
    raw_db_path = _td_resolve_raw_cache_db_path(db_path)
    db_path.parent.mkdir(parents=True, exist_ok=True)
    raw_db_path.parent.mkdir(parents=True, exist_ok=True)

    project_cfg = _load_project_td_trend_config(wb_path)
    cfg_cols = [dict(c) for c in (project_cfg.get("columns") or []) if isinstance(c, dict)]
    y_cols: list[tuple[str, str]] = []
    cfg_units: dict[str, str] = {}
    for c in cfg_cols:
        name = str(c.get("name") or "").strip()
        units = str(c.get("units") or "").strip()
        if name:
            y_cols.append((name, units))
            if units:
                cfg_units[name] = units
    cfg_param_meta_map = _td_program_requirements_param_def_map(cfg_cols)

    sources = _read_test_data_sources(wb_path)
    entries = (
        [dict(s) for s in (_entries_override or []) if isinstance(s, dict) and str(s.get("serial") or "").strip()]
        if _entries_override is not None
        else [dict(s) for s in sources if str(s.get("serial") or "").strip()]
    )
    full_reset = bool(_full_reset)
    removed_serials = sorted({str(value).strip() for value in (_removed_serials or []) if str(value).strip()})
    preclassified_counts = {
        str(key): int(value or 0)
        for key, value in (_preclassified_counts or {}).items()
        if str(key).strip()
    }

    computed_epoch_ns = time.time_ns()
    total_started = time.perf_counter()
    timings: dict[str, float] = {
        "source_resolution_s": 0.0,
        "source_sqlite_read_s": 0.0,
        "run_discovery_and_matching_s": 0.0,
        "raw_curve_extraction_s": 0.0,
        "raw_db_write_s": 0.0,
        "calc_rebuild_s": 0.0,
        "total_s": 0.0,
    }

    # Stats selection is driven entirely by user_inputs/excel_trend_config.json.
    selected_stats = _td_cache_selected_stats(project_cfg.get("statistics"))

    support_cfg = _read_td_support_workbook(wb_path, project_dir=db_path.parent)
    support_settings = dict(support_cfg.get("settings") or {})
    bounds_by_sequence = {
        str(k).strip(): dict(v)
        for k, v in (support_cfg.get("bounds_by_sequence") or {}).items()
        if str(k).strip() and isinstance(v, dict)
    }
    support_sequences = [dict(s) for s in (support_cfg.get("sequences") or []) if isinstance(s, dict) and bool(s.get("enabled", True))]
    condition_meta_by_key = {
        str(row.get("condition_key") or "").strip(): dict(row)
        for row in ((support_cfg.get("condition_groups") or support_cfg.get("run_conditions") or []))
        if isinstance(row, dict) and str(row.get("condition_key") or "").strip()
    }

    # Optional: run/sequence condition labeling (user-controlled via JSON stored in workbook Config).
    td_run_labeling = None
    try:
        td_run_labeling = _read_test_data_run_labeling(wb_path)
    except Exception:
        td_run_labeling = None
    td_run_labeling_enabled = bool(isinstance(td_run_labeling, dict) and td_run_labeling.get("enabled"))
    run_var_samples: dict[str, dict[str, list[object]]] = {}

    # For TD curve plots, only allow canonical X axes:
    # - Time
    # - Pulse Number
    #
    # Never offer excel_row as an X axis (it is still used for stable ordering when present).
    X_TIME = "Time"
    X_PULSE = "Pulse Number"
    run_x_union: dict[str, set[str]] = {}
    run_default_x: dict[str, str] = {}

    def _norm_name(s: str) -> str:
        return "".join(ch.lower() for ch in str(s or "") if ch.isalnum())

    # X-axis header detection is controlled by `user_inputs/excel_trend_config.json` (optional).
    # This is independent of the Test Data Trending workbook's Config sheet.
    x_axis_cfg: dict = {}
    try:
        x_axis_cfg = dict((_load_excel_trend_config(DEFAULT_EXCEL_TREND_CONFIG) or {}).get("x_axis") or {})
    except Exception:
        x_axis_cfg = {}

    time_aliases = [
        str(s).strip()
        for s in (x_axis_cfg.get("time_aliases") if isinstance(x_axis_cfg, dict) else []) or []
        if str(s).strip()
    ] or [X_TIME]
    pulse_aliases = [
        str(s).strip()
        for s in (x_axis_cfg.get("pulse_aliases") if isinstance(x_axis_cfg, dict) else []) or []
        if str(s).strip()
    ] or [X_PULSE]
    fm = (x_axis_cfg.get("fuzzy_match") if isinstance(x_axis_cfg, dict) else None) or {}
    fm_enabled = bool(isinstance(fm, dict) and fm.get("enabled", True))
    try:
        fm_min_ratio = float((fm if isinstance(fm, dict) else {}).get("min_ratio", 0.82))
    except Exception:
        fm_min_ratio = 0.82
    fm_min_ratio = min(1.0, max(0.0, float(fm_min_ratio)))

    sv = (x_axis_cfg.get("sequential_validation") if isinstance(x_axis_cfg, dict) else None) or {}
    sv_enabled = bool(isinstance(sv, dict) and sv.get("enabled", True))
    try:
        sv_max_probe_rows = int((sv if isinstance(sv, dict) else {}).get("max_probe_rows", 250))
    except Exception:
        sv_max_probe_rows = 250
    try:
        sv_min_samples = int((sv if isinstance(sv, dict) else {}).get("min_samples", 6))
    except Exception:
        sv_min_samples = 6
    try:
        sv_pulse_min_run = int((sv if isinstance(sv, dict) else {}).get("pulse_min_run", 5))
    except Exception:
        sv_pulse_min_run = 5
    sv_max_probe_rows = max(20, int(sv_max_probe_rows))
    sv_min_samples = max(4, int(sv_min_samples))
    sv_pulse_min_run = max(3, int(sv_pulse_min_run))

    # Default X preference (keep "Time" first unless overridden in config).
    default_x_pref = str((x_axis_cfg.get("default_x") if isinstance(x_axis_cfg, dict) else None) or X_TIME).strip() or X_TIME
    if _norm_name(default_x_pref) == _norm_name(X_PULSE):
        x_priority = [X_PULSE, X_TIME]
    else:
        x_priority = [X_TIME, X_PULSE]

    time_norms = {_norm_name(x) for x in ([X_TIME] + list(time_aliases))}
    pulse_norms = {_norm_name(x) for x in ([X_PULSE] + list(pulse_aliases))}
    x_exclude_norms = time_norms | pulse_norms | {_norm_name("excel_row")}

    def _match_by_aliases(
        col_list: list[str],
        aliases: list[str],
        *,
        preferred_label: str = "",
        fuzzy_enabled: bool,
        min_ratio: float,
    ) -> list[tuple[str, float, int]]:
        """
        Return [(col_name, score, col_index)] for columns whose header matches any alias.
        Results are ordered by col_index (left-most first).
        """
        if not col_list or not aliases:
            return []
        # Precompute normalized forms for fast exact matching.
        preferred_norm = _norm_name(preferred_label)
        alias_norms = {_norm_name(a) for a in aliases if _norm_name(a)}
        out: list[tuple[str, float, int]] = []
        for idx, col in enumerate(col_list):
            c = str(col or "").strip()
            if not c:
                continue
            c_norm = _norm_name(c)
            if not c_norm:
                continue
            if c_norm == _norm_name("excel_row"):
                continue
            if c_norm in alias_norms:
                out.append((c, 1.0, int(idx)))
                continue
            if not fuzzy_enabled:
                continue
            best = 0.0
            for a in aliases:
                score = _fuzzy_col_score(str(a or ""), c)  # defined below (label helpers)
                if score > best:
                    best = float(score)
            if best >= float(min_ratio):
                out.append((c, float(best), int(idx)))
        out.sort(
            key=lambda t: (
                0 if preferred_norm and _norm_name(t[0]) == preferred_norm else 1,
                int(t[2]),
                -float(t[1]),
                str(t[0]).lower(),
            )
        )
        return out

    def _probe_finite_values(
        src: sqlite3.Connection,
        table: str,
        col: str,
        *,
        order_by: str,
        max_rows: int,
    ) -> list[float]:
        q_table = _quote_ident(table)
        q_col = _quote_ident(col)
        try:
            rows = src.execute(
                f"SELECT {q_col} FROM {q_table} "
                f"WHERE {q_col} IS NOT NULL "
                f"ORDER BY {order_by} "
                f"LIMIT {int(max_rows)}"
            ).fetchall()
        except Exception:
            rows = []
        out: list[float] = []
        for (v,) in rows:
            fv = _finite_float(v)
            if fv is None:
                continue
            out.append(float(fv))
        return out

    def _is_time_sequential(values: list[float], *, min_samples: int) -> bool:
        if len(values) < int(min_samples):
            return False
        pos = 0
        prev = values[0]
        for v in values[1:]:
            d = float(v) - float(prev)
            if d < -1e-9:
                return False
            if d > 1e-9:
                pos += 1
            prev = v
        return pos >= 2

    def _is_pulse_sequential(values: list[float], *, min_samples: int, min_run: int) -> bool:
        if len(values) < int(min_samples):
            return False
        int_like = 0
        ints: list[int] = []
        for v in values:
            rv = round(float(v))
            if abs(float(v) - float(rv)) < 1e-9:
                int_like += 1
                ints.append(int(rv))
            else:
                ints.append(int(rv))
        if float(int_like) / float(max(1, len(values))) < 0.98:
            return False
        best = 1
        cur = 1
        for i in range(1, len(ints)):
            if int(ints[i]) == int(ints[i - 1]) + 1:
                cur += 1
                if cur > best:
                    best = cur
            else:
                cur = 1
        return best >= int(min_run)

    def _finite_float(v: object) -> float | None:
        if v is None:
            return None
        if isinstance(v, (int, float)):
            f = float(v)
        else:
            t = str(v).strip().replace(",", "")
            if not t:
                return None
            try:
                f = float(t)
            except Exception:
                return None
        if math.isfinite(f):
            return f
        return None

    def _compute_stats(values: list[float]) -> dict[str, float | int | None]:
        n = len(values)
        if n == 0:
            return {"mean": None, "min": None, "max": None, "std": None, "median": None, "count": 0}
        out: dict[str, float | int | None] = {
            "mean": (sum(values) / n),
            "min": min(values),
            "max": max(values),
            "median": statistics.median(values),
            "count": n,
        }
        out["std"] = statistics.stdev(values) if n >= 2 else None
        return out

    def _compute_constant_stats(value: float) -> dict[str, float | int | None]:
        return {
            "mean": float(value),
            "min": float(value),
            "max": float(value),
            "median": float(value),
            "std": 0.0,
            "count": 1,
        }

    def _quote_ident(name: str) -> str:
        return '"' + (name or "").replace('"', '""') + '"'

    # --- Optional: Run/sequence labeling helpers (used only when enabled) ---
    label_template = ""
    label_missing = "blank"
    label_value_pick = "most_common"
    label_fuzzy_enabled = True
    label_fuzzy_min_ratio = 0.82
    label_disamb_enabled = True
    label_disamb_template = "{label} — {run_name}"
    label_variables: dict[str, dict] = {}
    if td_run_labeling_enabled and isinstance(td_run_labeling, dict):
        label_template = str(td_run_labeling.get("template") or "").strip()
        label_missing = str(td_run_labeling.get("missing_value") or "blank").strip() or "blank"
        label_value_pick = str(td_run_labeling.get("value_pick") or "most_common").strip().lower() or "most_common"
        fm = td_run_labeling.get("fuzzy_match") or {}
        if isinstance(fm, dict):
            label_fuzzy_enabled = bool(fm.get("enabled", True))
            try:
                label_fuzzy_min_ratio = float(fm.get("min_ratio", 0.82))
            except Exception:
                label_fuzzy_min_ratio = 0.82
        dd = td_run_labeling.get("duplicate_disambiguation") or {}
        if isinstance(dd, dict):
            label_disamb_enabled = bool(dd.get("enabled", True))
            label_disamb_template = str(dd.get("template") or label_disamb_template).strip() or label_disamb_template
        vars_cfg = td_run_labeling.get("variables") or {}
        if isinstance(vars_cfg, dict):
            for k, v in vars_cfg.items():
                kk = str(k or "").strip()
                if not kk or not isinstance(v, dict):
                    continue
                label_variables[kk] = dict(v)

    from collections import Counter
    from difflib import SequenceMatcher
    import re

    def _normalize_text(s: object) -> str:
        return re.sub(r"\s+", " ", str(s or "").strip()).lower()

    def _token_overlap_score(query: str, candidate: str) -> float:
        q = _normalize_text(query)
        c = _normalize_text(candidate)
        q_toks = [t for t in re.findall(r"[a-z0-9]+", q) if t]
        c_toks = [t for t in re.findall(r"[a-z0-9]+", c) if t]
        if not q_toks or not c_toks:
            return 0.0
        q_unique = list(dict.fromkeys(q_toks))
        c_unique = list(dict.fromkeys(c_toks))

        def _tok_match(a: str, b: str) -> bool:
            if a == b:
                return True
            if len(a) >= 4 and len(b) >= 4 and (a.startswith(b) or b.startswith(a)):
                return True
            return False

        matched = 0
        for qt in q_unique:
            for ct in c_unique:
                if _tok_match(qt, ct):
                    matched += 1
                    break
        return matched / float(len(q_unique)) if q_unique else 0.0

    def _fuzzy_col_score(target: str, candidate: str) -> float:
        t_key = _norm_name(target)
        c_key = _norm_name(candidate)
        seq = SequenceMatcher(None, t_key, c_key).ratio() if (t_key and c_key) else 0.0
        cov = _token_overlap_score(target, candidate)
        return max(cov, (seq + cov) / 2.0)

    def _best_match_col(target: str, cols: set[str]) -> str:
        t = str(target or "").strip()
        if not t or not cols:
            return ""
        # Exact/normalized match first.
        t_norm = _norm_name(t)
        for c in cols:
            if _norm_name(c) == t_norm:
                return c
        if not label_fuzzy_enabled:
            return ""
        best = ("", 0.0)
        for c in cols:
            score = _fuzzy_col_score(t, c)
            if score > best[1]:
                best = (c, float(score))
        if best[0] and best[1] >= float(label_fuzzy_min_ratio):
            return best[0]
        return ""

    def _source_column_label_candidates(spec: Mapping[str, object]) -> list[str]:
        out: list[str] = []
        for value in (
            spec.get("mapped_header"),
            spec.get("header"),
            spec.get("sqlite_column"),
        ):
            text = str(value or "").strip()
            if text and text not in out:
                out.append(text)
        return out

    def _match_source_column_specs(
        specs: Sequence[Mapping[str, object]],
        aliases: Sequence[str],
        *,
        preferred_label: str = "",
        fuzzy_enabled: bool,
        min_ratio: float,
    ) -> list[tuple[dict[str, object], float, int]]:
        if not specs or not aliases:
            return []
        preferred_norm = _norm_name(preferred_label)
        alias_norms = {_norm_name(alias) for alias in aliases if _norm_name(alias)}
        out: list[tuple[dict[str, object], float, int]] = []
        for idx, raw_spec in enumerate(specs):
            spec = dict(raw_spec or {})
            labels = _source_column_label_candidates(spec)
            if not labels:
                continue
            best_score = 0.0
            exact_match = False
            for label in labels:
                label_norm = _norm_name(label)
                if not label_norm or label_norm == _norm_name("excel_row"):
                    continue
                if label_norm in alias_norms:
                    exact_match = True
                    best_score = 1.0
                    break
                if not fuzzy_enabled:
                    continue
                for alias in aliases:
                    score = _fuzzy_col_score(str(alias or ""), label)
                    if score > best_score:
                        best_score = float(score)
            if exact_match or best_score >= float(min_ratio):
                out.append((spec, float(best_score), int(idx)))
        out.sort(
            key=lambda item: (
                0
                if preferred_norm
                and any(_norm_name(label) == preferred_norm for label in _source_column_label_candidates(item[0]))
                else 1,
                int(item[2]),
                -float(item[1]),
                str(item[0].get("header") or item[0].get("sqlite_column") or "").lower(),
            )
        )
        return out

    def _most_common_nonempty_value(src: sqlite3.Connection, table: str, col: str) -> object | None:
        q_table = _quote_ident(table)
        q_col = _quote_ident(col)
        try:
            row = src.execute(
                f"""
                SELECT {q_col} AS v, COUNT(*) AS n
                FROM {q_table}
                WHERE {q_col} IS NOT NULL AND TRIM(CAST({q_col} AS TEXT)) <> ''
                GROUP BY {q_col}
                ORDER BY n DESC, CAST({q_col} AS TEXT) ASC
                LIMIT 1
                """
            ).fetchone()
        except Exception:
            row = None
        if not row:
            return None
        return row[0]

    def _canonical_label_value(v: object) -> object | None:
        if v is None:
            return None
        if isinstance(v, (int, float)):
            f = float(v)
            if not math.isfinite(f):
                return None
            if abs(f - round(f)) < 1e-9:
                return int(round(f))
            return float(f)
        s = str(v).strip()
        if not s:
            return None
        t = s.replace(",", "")
        try:
            f = float(t)
            if math.isfinite(f):
                if abs(f - round(f)) < 1e-9:
                    return int(round(f))
                return float(f)
        except Exception:
            pass
        return s

    def _pick_most_common(values: list[object]) -> object | None:
        vals = [v for v in values if v is not None and str(v).strip() != ""]
        if not vals:
            return None
        counts = Counter(vals)
        # Deterministic tie-break: lexicographic on lowercase string form.
        best = sorted(counts.items(), key=lambda kv: (-int(kv[1]), str(kv[0]).strip().lower()))[0]
        return best[0]

    def _format_label_value(v: object | None, fmt_spec: str | None) -> str:
        if v is None or str(v).strip() == "":
            return label_missing
        if fmt_spec:
            try:
                if isinstance(v, (int, float)):
                    return format(float(v), fmt_spec)
                f = _finite_float(v)
                if f is not None:
                    return format(float(f), fmt_spec)
            except Exception:
                pass
        return str(v).strip()

    pressure_aliases = [
        "feed pressure",
        "feed_pressure",
        "pressure",
        "pc",
    ]
    pulse_on_aliases = [
        "pulse width on",
        "pulse_width_on",
        "pulse_width",
        "pulse width",
        "pulse on",
        "pulse_on",
    ]
    current_source_sequence_context_by_run: dict[str, dict[str, object]] = {}

    def _read_run_rows(src: sqlite3.Connection, table: str, *, cols: set[str], order_by: str) -> list[dict]:
        q_table = _quote_ident(table)
        q_cols = ", ".join(_quote_ident(c) for c in cols)
        try:
            cursor = src.execute(f"SELECT {q_cols} FROM {q_table} ORDER BY {order_by}")
            names = [str(d[0] or "") for d in (cursor.description or [])]
            rows = cursor.fetchall()
        except Exception:
            return []
        out: list[dict] = []
        for row in rows:
            item = {names[i]: row[i] for i in range(min(len(names), len(row)))}
            out.append(item)
        return out

    def _most_common_from_rows(rows: list[dict], col_name: str) -> object | None:
        vals = [_canonical_label_value(row.get(col_name)) for row in rows]
        return _pick_most_common(vals)

    def _resolve_support_sequence(program_title: str, source_run: str, rows: list[dict], cols: set[str]) -> dict:
        effective = _td_resolve_support_condition_for_source(program_title, source_run, support_cfg)
        effective = _td_prefill_support_row_from_sequence_context(
            effective,
            current_source_sequence_context_by_run.get(_td_support_norm_name(source_run)),
            blank_unusable_defaults=False,
        )
        if not support_sequences:
            return effective

        pressure_col = ""
        pulse_col = ""
        for alias in pressure_aliases:
            pressure_col = _best_match_col(alias, cols)
            if pressure_col:
                break
        for alias in pulse_on_aliases:
            pulse_col = _best_match_col(alias, cols)
            if pulse_col:
                break
        actual_pressure = _most_common_from_rows(rows, pressure_col) if pressure_col else None
        actual_pulse = _most_common_from_rows(rows, pulse_col) if pulse_col else None

        heur_matches: list[dict] = []
        for seq in support_sequences:
            seq_program = str(seq.get("program_title") or "").strip()
            if seq_program and _td_support_norm_name(seq_program) != _td_support_norm_name(program_title):
                continue
            source_match = str(seq.get("source_run_name") or "").strip()
            if source_match and _norm_name(source_match) == _norm_name(source_run):
                effective = {
                    **effective,
                    "condition_key": str(seq.get("condition_key") or seq.get("sequence_name") or source_run).strip() or str(source_run or "").strip(),
                    "sequence_name": str(seq.get("condition_key") or seq.get("sequence_name") or source_run).strip() or str(source_run or "").strip(),
                    "display_name": str(seq.get("display_name") or seq.get("condition_key") or seq.get("sequence_name") or source_run).strip() or str(source_run or "").strip(),
                    "source_run_name": str(source_run or "").strip(),
                    "feed_pressure": seq.get("feed_pressure", effective.get("feed_pressure")),
                    "feed_pressure_units": str(seq.get("feed_pressure_units") or effective.get("feed_pressure_units") or "").strip(),
                    "feed_temperature": seq.get("feed_temperature", effective.get("feed_temperature")),
                    "feed_temperature_units": str(seq.get("feed_temperature_units") or effective.get("feed_temperature_units") or "").strip(),
                    "pulse_width": _td_support_sequence_pulse_width(seq),
                    "exclude_first_n": seq.get("exclude_first_n"),
                    "last_n_rows": seq.get("last_n_rows"),
                    "run_type": str(seq.get("run_type") or effective.get("run_type") or "").strip(),
                    "control_period": seq.get("control_period", effective.get("control_period")),
                    "suppression_voltage": seq.get("suppression_voltage", effective.get("suppression_voltage")),
                    "valve_voltage": seq.get("valve_voltage", effective.get("valve_voltage")),
                    "program_title": str(program_title or "").strip(),
                    "matched_support": False,
                }
            wants_pressure = seq.get("feed_pressure") not in (None, "")
            wants_pulse = _td_support_sequence_pulse_width(seq) not in (None, "")
            if not wants_pressure and not wants_pulse:
                continue
            if wants_pressure and not _support_values_equal(seq.get("feed_pressure"), actual_pressure):
                continue
            if wants_pulse and not _support_values_equal(_td_support_sequence_pulse_width(seq), actual_pulse):
                continue
            heur_matches.append(seq)
        if len(heur_matches) > 1:
            names = ", ".join(sorted({str(m.get("sequence_name") or "").strip() for m in heur_matches if str(m.get("sequence_name") or "").strip()}))
            raise RuntimeError(f"Ambiguous TD support heuristics for source run '{source_run}': {names}")
        if len(heur_matches) == 1:
            seq = heur_matches[0]
            effective = {
                **effective,
                "condition_key": str(seq.get("condition_key") or seq.get("sequence_name") or source_run).strip() or str(source_run or "").strip(),
                "sequence_name": str(seq.get("condition_key") or seq.get("sequence_name") or source_run).strip() or str(source_run or "").strip(),
                "display_name": str(seq.get("display_name") or seq.get("condition_key") or seq.get("sequence_name") or source_run).strip() or str(source_run or "").strip(),
                "source_run_name": str(source_run or "").strip(),
                "feed_pressure": seq.get("feed_pressure", effective.get("feed_pressure")),
                "feed_pressure_units": str(seq.get("feed_pressure_units") or effective.get("feed_pressure_units") or "").strip(),
                "feed_temperature": seq.get("feed_temperature", effective.get("feed_temperature")),
                "feed_temperature_units": str(seq.get("feed_temperature_units") or effective.get("feed_temperature_units") or "").strip(),
                "pulse_width": _td_support_sequence_pulse_width(seq),
                "exclude_first_n": seq.get("exclude_first_n"),
                "last_n_rows": seq.get("last_n_rows"),
                "run_type": str(seq.get("run_type") or effective.get("run_type") or "").strip(),
                "control_period": seq.get("control_period", effective.get("control_period")),
                "suppression_voltage": seq.get("suppression_voltage", effective.get("suppression_voltage")),
                "valve_voltage": seq.get("valve_voltage", effective.get("valve_voltage")),
                "program_title": str(program_title or "").strip(),
                "matched_support": True,
            }
        effective = _td_prefill_support_row_from_sequence_context(
            effective,
            current_source_sequence_context_by_run.get(_td_support_norm_name(source_run)),
            blank_unusable_defaults=False,
        )
        return effective

    def _filter_rows_for_metric(
        run_info: dict,
        *,
        y_name: str,
        actual_x: str,
        rows: list[dict],
    ) -> tuple[list[float], list[float]]:
        filtered: list[tuple[float, float]] = []
        for row in rows:
            fx = _finite_float(row.get(actual_x))
            fy = _finite_float(row.get(y_name))
            if fx is None or fy is None:
                continue
            filtered.append((float(fx), float(fy)))

        exclude_first_n = run_info.get("exclude_first_n")
        if exclude_first_n is None:
            exclude_first_n = support_settings.get("exclude_first_n_default")
        last_n_rows = run_info.get("last_n_rows")
        if last_n_rows is None:
            last_n_rows = support_settings.get("last_n_rows_default")

        if exclude_first_n is not None and int(exclude_first_n) > 0:
            filtered = filtered[int(exclude_first_n):]
        filtered = _apply_last_n_rows_limit(filtered, last_n_rows)
        xs = [x for x, _y in filtered]
        ys = [y for _x, y in filtered]
        return xs, ys

    def _match_configured_y_columns(col_list: list[str], desired_defs: list[dict], *, used_x_actual: set[str]) -> tuple[dict[str, str], list[str]]:
        actual_cols = [str(c or "").strip() for c in col_list if str(c or "").strip()]
        available = [c for c in actual_cols if _norm_name(c) not in x_exclude_norms and c not in used_x_actual]
        matched: dict[str, str] = {}
        issues: list[str] = []
        used_actual: set[str] = set()
        eps = 1e-9
        for raw_def in desired_defs:
            cfg_name = str(raw_def.get("name") or "").strip()
            if not cfg_name:
                continue
            aliases = [cfg_name] + [str(v or "").strip() for v in (raw_def.get("aliases") or []) if str(v or "").strip()]

            exact_matches: list[str] = []
            alias_norms = {_norm_name(alias) for alias in aliases if _norm_name(alias)}
            for actual in available:
                if actual in used_actual:
                    continue
                if _norm_name(actual) in alias_norms:
                    exact_matches.append(actual)
            if len(exact_matches) == 1:
                matched[cfg_name] = exact_matches[0]
                used_actual.add(exact_matches[0])
                continue
            if len(exact_matches) > 1:
                issues.append(f"Ambiguous matches for '{cfg_name}': {', '.join(sorted(exact_matches))}")
                continue

            best_score = 0.0
            best_actuals: list[str] = []
            for actual in available:
                if actual in used_actual:
                    continue
                score = max((_fuzzy_col_score(alias, actual) for alias in aliases), default=0.0)
                if score > best_score + eps:
                    best_score = float(score)
                    best_actuals = [actual]
                elif abs(score - best_score) <= eps and score >= float(fm_min_ratio):
                    best_actuals.append(actual)
            if best_score >= float(fm_min_ratio) and len(best_actuals) == 1:
                matched[cfg_name] = best_actuals[0]
                used_actual.add(best_actuals[0])
            elif best_score >= float(fm_min_ratio) and len(best_actuals) > 1:
                issues.append(f"Ambiguous fuzzy matches for '{cfg_name}': {', '.join(sorted(best_actuals))}")
        return matched, issues

