    if not full_reset and (removed_serials or entries):
        entry_source_keys: list[str] = []
        for entry in entries:
            if not isinstance(entry, Mapping):
                continue
            try:
                entry_meta = _load_td_source_metadata(wb_path, entry)
            except Exception:
                entry_meta = {}
            source_key = _td_source_composite_key(entry, entry_meta)
            if source_key:
                entry_source_keys.append(source_key)
        serials_to_delete = sorted({*removed_serials, *entry_source_keys})
        _td_delete_serial_rows_from_cache(impl_conn, raw_conn, serials_to_delete)
        impl_conn.commit()
        raw_conn.commit()

    for idx, entry in enumerate(entries, start=1):
        source_meta = _load_td_source_metadata(wb_path, entry)
        source_serial_number = _td_source_serial_number(entry, source_meta)
        sn = _td_source_composite_key(entry, source_meta)
        _td_emit_progress(progress_cb, f"Ingesting source {idx}/{max(1, len(entries))}: {sn or source_serial_number or 'unknown serial'}")
        t_source_resolution = time.perf_counter()
        source_resolution = _resolve_td_source_sqlite_for_workbook(wb_path, entry)
        sqlite_path_raw = source_resolution.get("path")
        sqlite_path = Path(sqlite_path_raw).expanduser() if sqlite_path_raw else Path()
        status = str(source_resolution.get("status") or "missing").strip().lower() or "missing"
        source_reason = str(source_resolution.get("reason") or "").strip()
        resolved_from = str(source_resolution.get("resolved_from") or "").strip()
        workbook_excel_sqlite_rel = str(source_resolution.get("workbook_excel_sqlite_rel") or entry.get("excel_sqlite_rel") or "").strip()
        healed_excel_sqlite_rel = str(source_resolution.get("healed_excel_sqlite_rel") or "").strip()
        healed_artifacts_rel = str(source_resolution.get("healed_artifacts_rel") or "").strip()
        healed_metadata_rel = str(source_resolution.get("healed_metadata_rel") or "").strip()
        source_info = {
            "serial": sn,
            "source_key": sn,
            "serial_number": source_serial_number,
            "status": status,
            "resolved_from": resolved_from,
            "resolved_sqlite_path": str(sqlite_path) if sqlite_path else "",
            "workbook_excel_sqlite_rel": workbook_excel_sqlite_rel,
            "excel_sqlite_rel": healed_excel_sqlite_rel or workbook_excel_sqlite_rel,
            "healed_excel_sqlite_rel": healed_excel_sqlite_rel,
            "artifacts_rel": healed_artifacts_rel or str(source_resolution.get("artifacts_rel") or entry.get("artifacts_rel") or "").strip(),
            "metadata_rel": healed_metadata_rel or str(source_resolution.get("metadata_rel") or entry.get("metadata_rel") or "").strip(),
            "node_root": str(source_resolution.get("node_root") or "").strip(),
            "support_dir": str(source_resolution.get("support_dir") or "").strip(),
            "reason": source_reason,
        }
        debug_sources.append(dict(source_info))
        source_debug_source_idx = len(debug_sources) - 1
        try:
            st = sqlite_path.stat()
            mtime_ns = int(getattr(st, "st_mtime_ns", int(st.st_mtime * 1e9)))
            size_bytes = int(st.st_size)
        except Exception:
            mtime_ns = None
            size_bytes = None
        if status == "missing":
            missing_sources += 1
        elif status != "ok":
            invalid_sources += 1
        else:
            row_link_updates = source_link_updates.setdefault(sn, {})
            if healed_metadata_rel and healed_metadata_rel != str(entry.get("metadata_rel") or "").strip():
                entry["metadata_rel"] = healed_metadata_rel
                source_meta["metadata_rel"] = healed_metadata_rel
