def td_list_x_columns(db_path: Path, run_name: str) -> list[str]:
    run = str(run_name or "").strip()
    if not run:
        return []
    original_path = Path(db_path).expanduser()
    if original_path.name.lower() != EIDAT_PROJECT_TD_RAW_CACHE_DB.lower():
        found_plotter, out = _td_try_list_plotter_x_columns(original_path, run)
        if found_plotter:
            return out
    raw_path = _td_resolve_raw_cache_db_path(original_path)
    found_raw, out = _td_try_list_raw_x_columns(raw_path, run)
    if found_raw or original_path == raw_path:
        return out
    return _td_list_legacy_x_columns(original_path, run)


def td_read_sources_metadata(workbook_path: Path) -> list[dict]:
    try:
        from openpyxl import load_workbook  # type: ignore
    except Exception as exc:
        raise RuntimeError(
            "openpyxl is required to read Test Data Trending workbooks. "
            "Install it with `py -m pip install openpyxl` within the project environment."
        ) from exc

    wb = load_workbook(str(Path(workbook_path).expanduser()), read_only=True, data_only=True)
    try:
        if "Sources" not in wb.sheetnames:
            return []
        ws = wb["Sources"]
        headers: list[tuple[int, str]] = []
        for col in range(1, (ws.max_column or 0) + 1):
            raw = str(ws.cell(1, col).value or "").strip()
            key = raw.lower()
            if key:
                headers.append((col, key))
        if not headers:
            return []

        out: list[dict] = []
        for row in range(2, (ws.max_row or 0) + 1):
            item: dict[str, str] = {}
            for col, key in headers:
                item[key] = str(ws.cell(row, col).value or "").strip()
            sn = str(item.get("serial_number") or "").strip()
            if not sn:
                continue
            item["serial"] = sn
            out.append(item)
        return out
    finally:
        try:
            wb.close()
        except Exception:
            pass


def td_read_sources_metadata_from_cache(db_path: Path) -> list[dict]:
    path = Path(db_path).expanduser()
    if not path.exists():
        return []
    with sqlite3.connect(str(path)) as conn:
        _ensure_test_data_impl_tables(conn)
        rows = conn.execute(
            """
            SELECT
                s.serial,
                COALESCE(m.source_serial_number, s.serial),
                COALESCE(m.program_title, ''),
                COALESCE(m.document_type, ''),
                COALESCE(m.metadata_rel, ''),
                COALESCE(m.artifacts_rel, ''),
                COALESCE(m.excel_sqlite_rel, '')
            FROM td_sources s
            LEFT JOIN td_source_metadata m
              ON m.serial = s.serial
            ORDER BY s.serial
            """
        ).fetchall()
    out: list[dict] = []
    for serial, source_serial_number, program_title, document_type, metadata_rel, artifacts_rel, excel_sqlite_rel in rows:
        sn = str(serial or "").strip()
        if not sn:
            continue
        out.append(
            {
                "serial": sn,
                "source_key": sn,
                "serial_number": str(source_serial_number or sn).strip(),
                "program_title": str(program_title or "").strip(),
                "document_type": str(document_type or "").strip(),
                "metadata_rel": str(metadata_rel or "").strip(),
                "artifacts_rel": str(artifacts_rel or "").strip(),
                "excel_sqlite_rel": str(excel_sqlite_rel or "").strip(),
            }
        )
    return out


def td_read_observation_filter_rows_from_cache(db_path: Path) -> list[dict]:
    path = Path(db_path).expanduser()
    if not path.exists():
        return []
    with sqlite3.connect(str(path)) as conn:
        _ensure_test_data_impl_tables(conn)
        obs_table = _td_preferred_sequence_observation_table(conn)
        rows = conn.execute(
            f"""
            SELECT
                o.observation_id,
                o.serial,
                COALESCE(m.source_serial_number, o.serial),
                COALESCE(o.program_title, ''),
                COALESCE(o.source_run_name, ''),
                o.control_period,
                o.suppression_voltage,
                o.valve_voltage,
                COALESCE(m.document_type, ''),
                COALESCE(m.metadata_rel, ''),
                COALESCE(m.artifacts_rel, ''),
                COALESCE(m.excel_sqlite_rel, '')
            FROM {obs_table} o
            LEFT JOIN td_source_metadata m
              ON m.serial = o.serial
            ORDER BY o.serial, o.run_name, o.observation_id
            """
        ).fetchall()
    out: list[dict] = []
    for observation_id, serial, source_serial_number, program_title, source_run_name, control_period, suppression_voltage, valve_voltage, document_type, metadata_rel, artifacts_rel, excel_sqlite_rel in rows:
        sn = str(serial or "").strip()
        obs_id = str(observation_id or "").strip()
        if not sn or not obs_id:
            continue
        out.append(
            {
                "observation_id": obs_id,
                "serial": sn,
                "source_key": sn,
                "serial_number": str(source_serial_number or sn).strip(),
                "program_title": str(program_title or "").strip(),
                "source_run_name": str(source_run_name or "").strip(),
                "control_period": control_period,
                "suppression_voltage": suppression_voltage,
                "valve_voltage": valve_voltage,
                "document_type": str(document_type or "").strip(),
                "metadata_rel": str(metadata_rel or "").strip(),
                "artifacts_rel": str(artifacts_rel or "").strip(),
                "excel_sqlite_rel": str(excel_sqlite_rel or "").strip(),
            }
        )
    return out


def td_load_metric_series(
    db_path: Path,
    run_name: str,
    column_name: str,
    stat: str,
    *,
    program_title: str | None = None,
    source_run_name: str | None = None,
    control_period_filter: object = None,
    run_type_filter: object = None,
    metric_source: object = TD_METRIC_PLOT_SOURCE_AGGREGATE,
) -> list[dict]:
    path = Path(db_path).expanduser()
    if not path.exists():
        return []
    run = str(run_name or "").strip()
    col = str(column_name or "").strip()
    st = str(stat or "").strip().lower()
    if not run or not col or not st:
        return []
    metric_source_norm = td_metric_normalize_plot_source(metric_source)
    metrics_table = _td_metric_source_table_name(metric_source_norm)
    observations_table = _td_metric_source_observation_table_name(metric_source_norm)
    metric_sql = [
        f"""
        SELECT
            m.observation_id,
            m.serial,
            m.value_num,
            COALESCE(m.program_title, ''),
            COALESCE(m.source_run_name, ''),
            COALESCE(sm.asset_type, ''),
            COALESCE(sm.asset_specific_type, ''),
            COALESCE(o.run_type, ''),
            o.control_period,
            o.suppression_voltage,
            o.valve_voltage
        FROM {metrics_table} m
        LEFT JOIN {observations_table} o
          ON o.observation_id = m.observation_id
        LEFT JOIN td_source_metadata sm
          ON sm.serial = m.serial
        WHERE m.run_name=? AND m.column_name=? AND m.stat=?
        """
    ]
    metric_params: list[object] = [run, col, st]
    prog = str(program_title or "").strip() if metric_source_norm == TD_METRIC_PLOT_SOURCE_ALL_SEQUENCES else ""
    src_run = str(source_run_name or "").strip() if metric_source_norm == TD_METRIC_PLOT_SOURCE_ALL_SEQUENCES else ""
    if prog:
        metric_sql.append(" AND lower(COALESCE(m.program_title, '')) = lower(?)")
        metric_params.append(prog)
    if src_run:
        metric_sql.append(" AND lower(COALESCE(m.source_run_name, '')) = lower(?)")
        metric_params.append(src_run)
    run_type_sql, run_type_params = _td_perf_run_type_sql_clause(run_type_filter, "o.run_type")
    if run_type_sql:
        metric_sql.append(run_type_sql)
        metric_params.extend(run_type_params)
    if control_period_filter not in (None, ""):
        cp_filter_num = _to_support_number(control_period_filter)
        run_type_key = _td_perf_run_type_sql_key("o.run_type")
        if cp_filter_num is not None:
            metric_sql.append(
                f" AND ({run_type_key} NOT IN ('pm', 'pulsemode', 'pulsedmode', 'pulsed', 'pulse') OR ABS(COALESCE(o.control_period, 0) - ?) <= 1e-9)"
            )
            metric_params.append(cp_filter_num)
        else:
            metric_sql.append(
                f" AND ({run_type_key} NOT IN ('pm', 'pulsemode', 'pulsedmode', 'pulsed', 'pulse') OR lower(TRIM(CAST(o.control_period AS TEXT))) = lower(TRIM(CAST(? AS TEXT))))"
            )
            metric_params.append(str(control_period_filter))
    metric_sql.append(" ORDER BY m.serial, m.observation_id")
    with sqlite3.connect(str(path)) as conn:
        _ensure_test_data_impl_tables(conn)
        rows = conn.execute("".join(metric_sql), tuple(metric_params)).fetchall()
    return [
        {
            "observation_id": str(r[0] or "").strip(),
            "serial": str(r[1] or "").strip(),
            "value_num": r[2],
            "program_title": str(r[3] or "").strip(),
            "source_run_name": str(r[4] or "").strip(),
            "asset_type": str(r[5] or "").strip(),
            "asset_specific_type": str(r[6] or "").strip(),
            "run_type": str(r[7] or "").strip(),
            "control_period": r[8],
            "suppression_voltage": r[9],
            "valve_voltage": r[10],
        }
        for r in rows
        if str(r[0] or "").strip() and str(r[1] or "").strip()
    ]


def td_load_metric_summary_for_selection(
    db_path: Path,
    run_name: str,
    column_names: Sequence[object],
    serial: object,
    stats: Sequence[object],
    *,
    program_title: str | None = None,
    source_run_name: str | None = None,
    control_period_filter: object = None,
    run_type_filter: object = None,
    metric_source: object = TD_METRIC_PLOT_SOURCE_AGGREGATE,
) -> list[dict]:
    path = Path(db_path).expanduser()
    if not path.exists():
        return []
    run = str(run_name or "").strip()
    serial_txt = str(serial or "").strip()
    raw_columns = [str(value or "").strip() for value in (column_names or []) if str(value or "").strip()]
    stats_norm = [str(value or "").strip().lower() for value in (stats or []) if str(value or "").strip()]
    if not run or not serial_txt or not raw_columns or not stats_norm:
        return []
    metric_source_norm = td_metric_normalize_plot_source(metric_source)
    metrics_table = _td_metric_source_table_name(metric_source_norm)
    observations_table = _td_metric_source_observation_table_name(metric_source_norm)
    column_placeholders = ",".join("?" for _ in raw_columns)
    stat_placeholders = ",".join("?" for _ in stats_norm)
    metric_sql = [
        f"""
        SELECT
            m.observation_id,
            m.serial,
            m.column_name,
            lower(m.stat),
            m.value_num,
            COALESCE(m.program_title, ''),
            COALESCE(m.source_run_name, ''),
            COALESCE(sm.asset_type, ''),
            COALESCE(sm.asset_specific_type, ''),
            COALESCE(o.run_type, ''),
            o.control_period,
            o.suppression_voltage,
            o.valve_voltage
        FROM {metrics_table} m
        LEFT JOIN {observations_table} o
          ON o.observation_id = m.observation_id
        LEFT JOIN td_source_metadata sm
          ON sm.serial = m.serial
        WHERE m.run_name=? AND m.serial=?
          AND m.column_name IN ({column_placeholders})
          AND lower(m.stat) IN ({stat_placeholders})
        """
    ]
    metric_params: list[object] = [run, serial_txt, *raw_columns, *stats_norm]
    prog = str(program_title or "").strip() if metric_source_norm == TD_METRIC_PLOT_SOURCE_ALL_SEQUENCES else ""
    src_run = str(source_run_name or "").strip() if metric_source_norm == TD_METRIC_PLOT_SOURCE_ALL_SEQUENCES else ""
    if prog:
        metric_sql.append(" AND lower(COALESCE(m.program_title, '')) = lower(?)")
        metric_params.append(prog)
    if src_run:
        metric_sql.append(" AND lower(COALESCE(m.source_run_name, '')) = lower(?)")
        metric_params.append(src_run)
    run_type_sql, run_type_params = _td_perf_run_type_sql_clause(run_type_filter, "o.run_type")
    if run_type_sql:
        metric_sql.append(run_type_sql)
        metric_params.extend(run_type_params)
    if control_period_filter not in (None, ""):
        cp_filter_num = _to_support_number(control_period_filter)
        run_type_key = _td_perf_run_type_sql_key("o.run_type")
        if cp_filter_num is not None:
            metric_sql.append(
                f" AND ({run_type_key} NOT IN ('pm', 'pulsemode', 'pulsedmode', 'pulsed', 'pulse') OR ABS(COALESCE(o.control_period, 0) - ?) <= 1e-9)"
            )
            metric_params.append(cp_filter_num)
        else:
            metric_sql.append(
                f" AND ({run_type_key} NOT IN ('pm', 'pulsemode', 'pulsedmode', 'pulsed', 'pulse') OR lower(TRIM(CAST(o.control_period AS TEXT))) = lower(TRIM(CAST(? AS TEXT))))"
            )
            metric_params.append(str(control_period_filter))
    metric_sql.append(" ORDER BY m.column_name, lower(m.stat), m.observation_id")
    with sqlite3.connect(str(path)) as conn:
        _ensure_test_data_impl_tables(conn)
        rows = conn.execute("".join(metric_sql), tuple(metric_params)).fetchall()
    return [
        {
            "observation_id": str(r[0] or "").strip(),
            "serial": str(r[1] or "").strip(),
            "column_name": str(r[2] or "").strip(),
            "stat": str(r[3] or "").strip().lower(),
            "value_num": r[4],
            "program_title": str(r[5] or "").strip(),
            "source_run_name": str(r[6] or "").strip(),
            "asset_type": str(r[7] or "").strip(),
            "asset_specific_type": str(r[8] or "").strip(),
            "run_type": str(r[9] or "").strip(),
            "control_period": r[10],
            "suppression_voltage": r[11],
            "valve_voltage": r[12],
        }
        for r in rows
        if str(r[0] or "").strip() and str(r[1] or "").strip() and str(r[2] or "").strip()
    ]


def td_list_life_axes(db_path: Path) -> list[dict]:
    path = Path(db_path).expanduser()
    if not path.exists():
        return []
    try:
        with sqlite3.connect(str(path)) as conn:
            _ensure_test_data_impl_tables(conn)
    except Exception:
        return []
    return [{"key": key, "label": label} for key, label in TD_LIFE_AXIS_OPTIONS]


def td_list_life_parameter_options(db_path: Path, run_names: Sequence[object]) -> list[dict[str, str]]:
    path = Path(db_path).expanduser()
    if not path.exists():
        return []
    runs = [str(value or "").strip() for value in (run_names or []) if str(value or "").strip()]
    sql = [
        f"""
        SELECT parameter_name, COALESCE(units, ''), cumulative_impulse
        FROM {TD_LIFE_METRICS_TABLE}
        WHERE lower(stat) = 'mean'
        """
    ]
    params: list[object] = []
    if runs:
        sql.append(f" AND condition_key IN ({','.join('?' for _ in runs)})")
        params.extend(runs)
    sql.append(" ORDER BY parameter_name, units")
    with sqlite3.connect(str(path)) as conn:
        _ensure_test_data_impl_tables(conn)
        rows = conn.execute("".join(sql), tuple(params)).fetchall()
    union: dict[str, dict[str, str]] = {}
    cumulative_impulse_option: dict[str, str] | None = None
    cumulative_impulse_units = _td_life_cumulative_impulse_units_from_pairs(rows)
    has_cumulative_impulse = False
    for raw_name, raw_units, raw_cumulative_impulse in rows:
        name = str(raw_name or "").strip()
        if not name:
            if _td_finite_float(raw_cumulative_impulse) is not None:
                has_cumulative_impulse = True
            continue
        units = str(raw_units or "").strip()
        key = _td_param_norm_name(name)
        if key not in union:
            union[key] = {"name": name, "units": units}
        elif units and not str(union[key].get("units") or "").strip():
            union[key]["units"] = units
        if _td_life_is_cumulative_impulse_parameter(name):
            cumulative_impulse_option = union[key]
        if _td_finite_float(raw_cumulative_impulse) is not None:
            has_cumulative_impulse = True
    if has_cumulative_impulse:
        if cumulative_impulse_option is None:
            union[_td_param_norm_name(TD_LIFE_CUMULATIVE_IMPULSE_DISPLAY_NAME)] = {
                "name": TD_LIFE_CUMULATIVE_IMPULSE_DISPLAY_NAME,
                "units": cumulative_impulse_units,
            }
        elif cumulative_impulse_units and not str(cumulative_impulse_option.get("units") or "").strip():
            cumulative_impulse_option["units"] = cumulative_impulse_units
    return sorted(union.values(), key=lambda item: str(item.get("name") or "").casefold())


def td_list_life_parameters(db_path: Path, run_names: Sequence[object]) -> list[str]:
    return [
        str(item.get("name") or "").strip()
        for item in td_list_life_parameter_options(db_path, run_names)
        if isinstance(item, Mapping) and str(item.get("name") or "").strip()
    ]


def _td_normalize_life_axis(value: object) -> str:
    raw = str(value or "").strip().lower()
    aliases = {
        "sequence": "sequence_index",
        "seq": "sequence_index",
        "sequence_index": "sequence_index",
        "cumulative_pulses": "cumulative_pulses",
        "pulses": "cumulative_pulses",
        "cumulative_throughput": "cumulative_throughput",
        "throughput": "cumulative_throughput",
        "cumulative_on_time": "cumulative_on_time",
        "on_time": "cumulative_on_time",
        "cumulative_impulse": "cumulative_impulse",
        "impulse": "cumulative_impulse",
    }
    return aliases.get(raw, "sequence_index")


def td_load_life_metric_series(
    db_path: Path,
    run_names: Sequence[object],
    parameter: str,
    life_axis: str,
    serials: Sequence[object] | None = None,
    stat: object = "mean",
) -> list[dict]:
    path = Path(db_path).expanduser()
    if not path.exists():
        return []
    runs = [str(value or "").strip() for value in (run_names or []) if str(value or "").strip()]
    param = str(parameter or "").strip()
    axis = _td_normalize_life_axis(life_axis)
    stat_key = str(stat or "").strip().lower()
    if stat_key not in TD_ALLOWED_STATS:
        stat_key = "mean"
    allowed_axes = {key for key, _label in TD_LIFE_AXIS_OPTIONS}
    if axis not in allowed_axes:
        axis = "sequence_index"
    serial_list = [str(value or "").strip() for value in (serials or []) if str(value or "").strip()]
    if not runs or not param:
        return []
    param_is_cumulative_impulse = _td_life_is_cumulative_impulse_parameter(param)
    params: list[object]
    sql: list[str]
    if param_is_cumulative_impulse:
        sql = [
            f"""
            SELECT
                l.observation_id,
                l.serial,
                l.condition_key,
                COALESCE(l.condition_display, ''),
                COALESCE(l.program_title, ''),
                COALESCE(l.source_run_name, ''),
                COALESCE(sm.asset_type, ''),
                COALESCE(sm.asset_specific_type, ''),
                l.sequence_index,
                COALESCE(l.sequence_label, ''),
                ?,
                l.cumulative_impulse,
                '',
                l.{axis},
                l.sequence_pulses,
                l.cumulative_pulses,
                l.sequence_on_time,
                l.cumulative_on_time,
                l.sequence_elapsed_time,
                l.cumulative_elapsed_time,
                l.sequence_throughput,
                l.cumulative_throughput,
                l.sequence_impulse,
                l.cumulative_impulse,
                COALESCE(l.diagnostics, ''),
                COALESCE(o.run_type, ''),
                o.control_period,
                o.suppression_voltage,
                o.valve_voltage
            FROM {TD_LIFE_METRICS_TABLE} l
            LEFT JOIN td_condition_observations_sequences o
              ON o.observation_id = l.observation_id
            LEFT JOIN td_source_metadata sm
              ON sm.serial = l.serial
            WHERE lower(l.stat) = 'mean'
              AND l.cumulative_impulse IS NOT NULL
            """
        ]
        params = [TD_LIFE_CUMULATIVE_IMPULSE_DISPLAY_NAME]
        sql.append(f" AND l.condition_key IN ({','.join('?' for _ in runs)})")
        params.extend(runs)
        if serial_list:
            sql.append(f" AND l.serial IN ({','.join('?' for _ in serial_list)})")
            params.extend(serial_list)
        sql.append(" ORDER BY l.serial, l.sequence_index, l.condition_key, l.observation_id, l.parameter_name")
    else:
        sql = [
            f"""
            SELECT
                l.observation_id,
                l.serial,
                l.condition_key,
                COALESCE(l.condition_display, ''),
                COALESCE(l.program_title, ''),
                COALESCE(l.source_run_name, ''),
                COALESCE(sm.asset_type, ''),
                COALESCE(sm.asset_specific_type, ''),
                l.sequence_index,
                COALESCE(l.sequence_label, ''),
                l.parameter_name,
                m.value_num,
                COALESCE(NULLIF(l.units, ''), COALESCE(c.units, '')),
                l.{axis},
                l.sequence_pulses,
                l.cumulative_pulses,
                l.sequence_on_time,
                l.cumulative_on_time,
                l.sequence_elapsed_time,
                l.cumulative_elapsed_time,
                l.sequence_throughput,
                l.cumulative_throughput,
                l.sequence_impulse,
                l.cumulative_impulse,
                COALESCE(l.diagnostics, ''),
                COALESCE(o.run_type, ''),
                o.control_period,
                o.suppression_voltage,
                o.valve_voltage
            FROM {TD_LIFE_METRICS_TABLE} l
            INNER JOIN td_metrics_calc_sequences m
              ON m.observation_id = l.observation_id
             AND m.serial = l.serial
             AND m.run_name = l.condition_key
             AND m.column_name = l.parameter_name
             AND lower(m.stat) = ?
            LEFT JOIN td_columns_calc c
              ON c.run_name = m.run_name
             AND c.name = m.column_name
             AND c.kind = 'y'
            LEFT JOIN td_condition_observations_sequences o
              ON o.observation_id = l.observation_id
            LEFT JOIN td_source_metadata sm
              ON sm.serial = l.serial
            WHERE l.parameter_name = ?
              AND lower(l.stat) = 'mean'
            """
        ]
        params = [stat_key, param]
        sql.append(f" AND l.condition_key IN ({','.join('?' for _ in runs)})")
        params.extend(runs)
        if serial_list:
            sql.append(f" AND l.serial IN ({','.join('?' for _ in serial_list)})")
            params.extend(serial_list)
        sql.append(" ORDER BY l.serial, l.sequence_index, l.condition_key, l.observation_id")
    with sqlite3.connect(str(path)) as conn:
        _ensure_test_data_impl_tables(conn)
        cumulative_impulse_units = ""
        if param_is_cumulative_impulse:
            units_sql = [
                f"""
                SELECT parameter_name, COALESCE(units, '')
                FROM {TD_LIFE_METRICS_TABLE}
                WHERE lower(stat) = 'mean'
                """
            ]
            units_params: list[object] = []
            units_sql.append(f" AND condition_key IN ({','.join('?' for _ in runs)})")
            units_params.extend(runs)
            if serial_list:
                units_sql.append(f" AND serial IN ({','.join('?' for _ in serial_list)})")
                units_params.extend(serial_list)
            units_sql.append(" ORDER BY parameter_name, units")
            cumulative_impulse_units = _td_life_cumulative_impulse_units_from_pairs(
                conn.execute("".join(units_sql), tuple(units_params)).fetchall()
            )
        rows = conn.execute("".join(sql), tuple(params)).fetchall()
    out: list[dict] = []
    seen_observations: set[tuple[str, str]] = set()
    for row in rows:
        x_value = _td_finite_float(row[13])
        y_value = _td_finite_float(row[11])
        if x_value is None or y_value is None:
            continue
        if param_is_cumulative_impulse:
            obs_key = (str(row[0] or "").strip(), str(row[1] or "").strip())
            if obs_key in seen_observations:
                continue
            seen_observations.add(obs_key)
        out.append(
            {
                "observation_id": str(row[0] or "").strip(),
                "serial": str(row[1] or "").strip(),
                "condition_key": str(row[2] or "").strip(),
                "condition_display": str(row[3] or "").strip(),
                "program_title": str(row[4] or "").strip(),
                "source_run_name": str(row[5] or "").strip(),
                "asset_type": str(row[6] or "").strip(),
                "asset_specific_type": str(row[7] or "").strip(),
                "sequence_index": int(row[8] or 0),
                "sequence_label": str(row[9] or "").strip(),
                "parameter_name": str(row[10] or "").strip(),
                "stat": stat_key,
                "value_num": y_value,
                "units": cumulative_impulse_units if param_is_cumulative_impulse else str(row[12] or "").strip(),
                "life_axis": axis,
                "x_value": x_value,
                "y_value": y_value,
                "sequence_pulses": row[14],
                "cumulative_pulses": row[15],
                "sequence_on_time": row[16],
                "cumulative_on_time": row[17],
                "sequence_elapsed_time": row[18],
                "cumulative_elapsed_time": row[19],
                "sequence_throughput": row[20],
                "cumulative_throughput": row[21],
                "sequence_impulse": row[22],
                "cumulative_impulse": row[23],
                "diagnostics": str(row[24] or "").strip(),
                "run_type": str(row[25] or "").strip(),
                "control_period": row[26],
                "suppression_voltage": row[27],
                "valve_voltage": row[28],
            }
        )
    return out


def td_load_life_metric_xy(
    db_path: Path,
    run_names: Sequence[object],
    x_parameter: str,
    y_parameter: str,
    serials: Sequence[object] | None = None,
    stat: object = "mean",
) -> list[dict]:
    path = Path(db_path).expanduser()
    if not path.exists():
        return []
    runs = [str(value or "").strip() for value in (run_names or []) if str(value or "").strip()]
    x_param = str(x_parameter or "").strip()
    y_param = str(y_parameter or "").strip()
    stat_key = str(stat or "").strip().lower()
    if stat_key not in TD_ALLOWED_STATS:
        stat_key = "mean"
    serial_list = [str(value or "").strip() for value in (serials or []) if str(value or "").strip()]
    if not runs or not x_param or not y_param:
        return []
    x_is_cumulative_impulse = _td_life_is_cumulative_impulse_parameter(x_param)
    y_is_cumulative_impulse = _td_life_is_cumulative_impulse_parameter(y_param)
    params: list[object] = []
    sql: list[str]
    if x_is_cumulative_impulse and y_is_cumulative_impulse:
        sql = [
            f"""
            SELECT
                l.observation_id,
                l.serial,
                l.condition_key,
                COALESCE(l.condition_display, ''),
                COALESCE(l.program_title, ''),
                COALESCE(l.source_run_name, ''),
                COALESCE(sm.asset_type, ''),
                COALESCE(sm.asset_specific_type, ''),
                l.sequence_index,
                COALESCE(l.sequence_label, ''),
                l.cumulative_impulse,
                l.cumulative_impulse,
                '',
                '',
                l.cumulative_pulses,
                l.cumulative_on_time,
                l.cumulative_throughput,
                l.cumulative_impulse,
                COALESCE(l.diagnostics, ''),
                COALESCE(o.run_type, ''),
                o.control_period,
                o.suppression_voltage,
                o.valve_voltage
            FROM {TD_LIFE_METRICS_TABLE} l
            LEFT JOIN td_condition_observations_sequences o
              ON o.observation_id = l.observation_id
            LEFT JOIN td_source_metadata sm
              ON sm.serial = l.serial
            WHERE lower(l.stat) = 'mean'
              AND l.cumulative_impulse IS NOT NULL
            """
        ]
        sql.append(f" AND l.condition_key IN ({','.join('?' for _ in runs)})")
        params.extend(runs)
        if serial_list:
            sql.append(f" AND l.serial IN ({','.join('?' for _ in serial_list)})")
            params.extend(serial_list)
        sql.append(" ORDER BY l.serial, l.sequence_index, l.condition_key, l.observation_id, l.parameter_name")
    elif x_is_cumulative_impulse:
        sql = [
            f"""
            SELECT
                y.observation_id,
                y.serial,
                y.condition_key,
                COALESCE(y.condition_display, ''),
                COALESCE(y.program_title, ''),
                COALESCE(y.source_run_name, ''),
                COALESCE(sm.asset_type, ''),
                COALESCE(sm.asset_specific_type, ''),
                y.sequence_index,
                COALESCE(y.sequence_label, ''),
                y.cumulative_impulse,
                COALESCE(my.value_num, y.value_num),
                '',
                COALESCE(NULLIF(y.units, ''), COALESCE(cy.units, '')),
                y.cumulative_pulses,
                y.cumulative_on_time,
                y.cumulative_throughput,
                y.cumulative_impulse,
                COALESCE(y.diagnostics, ''),
                COALESCE(o.run_type, ''),
                o.control_period,
                o.suppression_voltage,
                o.valve_voltage
            FROM {TD_LIFE_METRICS_TABLE} y
            LEFT JOIN td_metrics_calc_sequences my
              ON my.observation_id = y.observation_id
             AND my.serial = y.serial
             AND my.run_name = y.condition_key
             AND my.column_name = y.parameter_name
             AND lower(my.stat) = ?
            LEFT JOIN td_columns_calc cy
              ON cy.run_name = my.run_name
             AND cy.name = my.column_name
             AND cy.kind = 'y'
            LEFT JOIN td_condition_observations_sequences o
              ON o.observation_id = y.observation_id
            LEFT JOIN td_source_metadata sm
              ON sm.serial = y.serial
            WHERE y.parameter_name = ?
              AND lower(y.stat) = 'mean'
            """
        ]
        params.extend([stat_key, y_param])
        sql.append(f" AND y.condition_key IN ({','.join('?' for _ in runs)})")
        params.extend(runs)
        if serial_list:
            sql.append(f" AND y.serial IN ({','.join('?' for _ in serial_list)})")
            params.extend(serial_list)
        sql.append(" ORDER BY y.serial, y.sequence_index, y.condition_key, y.observation_id")
    elif y_is_cumulative_impulse:
        sql = [
            f"""
            SELECT
                x.observation_id,
                x.serial,
                x.condition_key,
                COALESCE(x.condition_display, ''),
                COALESCE(x.program_title, ''),
                COALESCE(x.source_run_name, ''),
                COALESCE(sm.asset_type, ''),
                COALESCE(sm.asset_specific_type, ''),
                x.sequence_index,
                COALESCE(x.sequence_label, ''),
                COALESCE(mx.value_num, x.value_num),
                x.cumulative_impulse,
                COALESCE(NULLIF(x.units, ''), COALESCE(cx.units, '')),
                '',
                x.cumulative_pulses,
                x.cumulative_on_time,
                x.cumulative_throughput,
                x.cumulative_impulse,
                COALESCE(x.diagnostics, ''),
                COALESCE(o.run_type, ''),
                o.control_period,
                o.suppression_voltage,
                o.valve_voltage
            FROM {TD_LIFE_METRICS_TABLE} x
            LEFT JOIN td_metrics_calc_sequences mx
              ON mx.observation_id = x.observation_id
             AND mx.serial = x.serial
             AND mx.run_name = x.condition_key
             AND mx.column_name = x.parameter_name
             AND lower(mx.stat) = ?
            LEFT JOIN td_columns_calc cx
              ON cx.run_name = mx.run_name
             AND cx.name = mx.column_name
             AND cx.kind = 'y'
            LEFT JOIN td_condition_observations_sequences o
              ON o.observation_id = x.observation_id
            LEFT JOIN td_source_metadata sm
              ON sm.serial = x.serial
            WHERE x.parameter_name = ?
              AND lower(x.stat) = 'mean'
            """
        ]
        params.extend([stat_key, x_param])
        sql.append(f" AND x.condition_key IN ({','.join('?' for _ in runs)})")
        params.extend(runs)
        if serial_list:
            sql.append(f" AND x.serial IN ({','.join('?' for _ in serial_list)})")
            params.extend(serial_list)
        sql.append(" ORDER BY x.serial, x.sequence_index, x.condition_key, x.observation_id")
    else:
        sql = [
            f"""
            SELECT
                x.observation_id,
                x.serial,
                x.condition_key,
                COALESCE(x.condition_display, ''),
                COALESCE(x.program_title, ''),
                COALESCE(x.source_run_name, ''),
                COALESCE(sm.asset_type, ''),
                COALESCE(sm.asset_specific_type, ''),
                x.sequence_index,
                COALESCE(x.sequence_label, ''),
                COALESCE(mx.value_num, x.value_num),
                COALESCE(my.value_num, y.value_num),
                COALESCE(NULLIF(x.units, ''), COALESCE(cx.units, '')),
                COALESCE(NULLIF(y.units, ''), COALESCE(cy.units, '')),
                x.cumulative_pulses,
                x.cumulative_on_time,
                x.cumulative_throughput,
                x.cumulative_impulse,
                COALESCE(x.diagnostics, ''),
                COALESCE(o.run_type, ''),
                o.control_period,
                o.suppression_voltage,
                o.valve_voltage
            FROM {TD_LIFE_METRICS_TABLE} x
            INNER JOIN {TD_LIFE_METRICS_TABLE} y
              ON y.serial = x.serial
             AND y.observation_id = x.observation_id
             AND lower(y.stat) = 'mean'
             AND y.parameter_name = ?
            LEFT JOIN td_metrics_calc_sequences mx
              ON mx.observation_id = x.observation_id
             AND mx.serial = x.serial
             AND mx.run_name = x.condition_key
             AND mx.column_name = x.parameter_name
             AND lower(mx.stat) = ?
            LEFT JOIN td_metrics_calc_sequences my
              ON my.observation_id = x.observation_id
             AND my.serial = x.serial
             AND my.run_name = x.condition_key
             AND my.column_name = y.parameter_name
             AND lower(my.stat) = ?
            LEFT JOIN td_columns_calc cx
              ON cx.run_name = mx.run_name
             AND cx.name = mx.column_name
             AND cx.kind = 'y'
            LEFT JOIN td_columns_calc cy
              ON cy.run_name = my.run_name
             AND cy.name = my.column_name
             AND cy.kind = 'y'
            LEFT JOIN td_condition_observations_sequences o
              ON o.observation_id = x.observation_id
            LEFT JOIN td_source_metadata sm
              ON sm.serial = x.serial
            WHERE x.parameter_name = ?
              AND lower(x.stat) = 'mean'
            """
        ]
        params.extend([y_param, stat_key, stat_key, x_param])
        sql.append(f" AND x.condition_key IN ({','.join('?' for _ in runs)})")
        params.extend(runs)
        if serial_list:
            sql.append(f" AND x.serial IN ({','.join('?' for _ in serial_list)})")
            params.extend(serial_list)
        sql.append(" ORDER BY x.serial, x.sequence_index, x.condition_key, x.observation_id")
    with sqlite3.connect(str(path)) as conn:
        _ensure_test_data_impl_tables(conn)
        cumulative_impulse_units = ""
        if x_is_cumulative_impulse or y_is_cumulative_impulse:
            units_sql = [
                f"""
                SELECT parameter_name, COALESCE(units, '')
                FROM {TD_LIFE_METRICS_TABLE}
                WHERE lower(stat) = 'mean'
                """
            ]
            units_params: list[object] = []
            units_sql.append(f" AND condition_key IN ({','.join('?' for _ in runs)})")
            units_params.extend(runs)
            if serial_list:
                units_sql.append(f" AND serial IN ({','.join('?' for _ in serial_list)})")
                units_params.extend(serial_list)
            units_sql.append(" ORDER BY parameter_name, units")
            cumulative_impulse_units = _td_life_cumulative_impulse_units_from_pairs(
                conn.execute("".join(units_sql), tuple(units_params)).fetchall()
            )
        rows = conn.execute("".join(sql), tuple(params)).fetchall()
    out: list[dict] = []
    seen_observations: set[tuple[str, str]] = set()
    for row in rows:
        x_value = _td_finite_float(row[10])
        y_value = _td_finite_float(row[11])
        if x_value is None or y_value is None:
            continue
        if x_is_cumulative_impulse and y_is_cumulative_impulse:
            obs_key = (str(row[0] or "").strip(), str(row[1] or "").strip())
            if obs_key in seen_observations:
                continue
            seen_observations.add(obs_key)
        out.append(
            {
                "observation_id": str(row[0] or "").strip(),
                "serial": str(row[1] or "").strip(),
                "condition_key": str(row[2] or "").strip(),
                "condition_display": str(row[3] or "").strip(),
                "program_title": str(row[4] or "").strip(),
                "source_run_name": str(row[5] or "").strip(),
                "asset_type": str(row[6] or "").strip(),
                "asset_specific_type": str(row[7] or "").strip(),
                "sequence_index": int(row[8] or 0),
                "sequence_label": str(row[9] or "").strip(),
                "x_parameter": x_param,
                "y_parameter": y_param,
                "stat": stat_key,
                "x_value": x_value,
                "y_value": y_value,
                "x_units": cumulative_impulse_units if x_is_cumulative_impulse else str(row[12] or "").strip(),
                "y_units": cumulative_impulse_units if y_is_cumulative_impulse else str(row[13] or "").strip(),
                "cumulative_pulses": row[14],
                "cumulative_on_time": row[15],
                "cumulative_throughput": row[16],
                "cumulative_impulse": row[17],
                "diagnostics": str(row[18] or "").strip(),
                "run_type": str(row[19] or "").strip(),
                "control_period": row[20],
                "suppression_voltage": row[21],
                "valve_voltage": row[22],
            }
        )
    return out


def td_metric_plot_values(series_rows: list[dict], serials: list[str], stat: str) -> list[float]:
    labels = [str(sn or "").strip() for sn in (serials or [])]
    vmap: dict[str, float] = {}
    for row in series_rows or []:
        if not isinstance(row, dict):
            continue
        sn = str(row.get("serial") or "").strip()
        val = row.get("value_num")
        if not sn or not isinstance(val, (int, float)) or not math.isfinite(float(val)):
            continue
        vmap[sn] = float(val)
    return [(float(vmap.get(sn)) if isinstance(vmap.get(sn), (int, float)) else float("nan")) for sn in labels]


def td_metric_average_plot_values(series_rows: list[dict], serials: list[str]) -> list[float]:
    labels = [str(sn or "").strip() for sn in (serials or [])]
    values: list[float] = []
    for row in series_rows or []:
        if not isinstance(row, dict):
            continue
        val = row.get("value_num")
        if not isinstance(val, (int, float)) or not math.isfinite(float(val)):
            continue
        values.append(float(val))
    if not values:
        return [float("nan")] * len(labels)
    overall = float(sum(values) / float(max(1, len(values))))
    return [overall] * len(labels)


def td_list_control_periods(db_path: Path) -> list[object]:
    path = Path(db_path).expanduser()
    if not path.exists():
        return []
    with sqlite3.connect(str(path)) as conn:
        _ensure_test_data_impl_tables(conn)
        rows = conn.execute(
            """
            SELECT DISTINCT control_period
            FROM td_condition_observations
            WHERE """
            + _td_perf_run_type_sql_key("run_type")
            + """ IN ('pm', 'pulsemode', 'pulsedmode', 'pulsed', 'pulse') AND control_period IS NOT NULL
            ORDER BY control_period
            """
        ).fetchall()
    return [row[0] for row in rows if row and row[0] is not None]


def td_list_performance_run_type_modes(db_path: Path) -> list[str]:
    path = Path(db_path).expanduser()
    if not path.exists():
        return []
    modes: set[str] = set()
    with sqlite3.connect(str(path)) as conn:
        _ensure_test_data_impl_tables(conn)
        rows = conn.execute(
            """
            SELECT DISTINCT COALESCE(run_type, '')
            FROM td_condition_observations
            """
        ).fetchall()
    for row in rows:
        run_type = td_normalize_run_type((row[0] if row else "") or "")
        if run_type == "PM":
            modes.add("pulsed_mode")
        else:
            modes.add("steady_state")
    ordered = [mode for mode in ("steady_state", "pulsed_mode") if mode in modes]
    return ordered or ["steady_state"]


def _td_perf_norm_key(value: object) -> str:
    return "".join(ch.lower() for ch in str(value or "").strip() if ch.isalnum())


TD_PERF_BOUNDS_MODE_MEDIAN_3SIGMA = "median_3sigma"
TD_PERF_BOUNDS_MODE_ACTUAL = "actual"
TD_PERF_BOUNDS_MODES = {
    TD_PERF_BOUNDS_MODE_MEDIAN_3SIGMA,
    TD_PERF_BOUNDS_MODE_ACTUAL,
}


def td_perf_normalize_bounds_mode(value: object) -> str:
    raw = str(value or "").strip().lower()
    return raw if raw in TD_PERF_BOUNDS_MODES else TD_PERF_BOUNDS_MODE_MEDIAN_3SIGMA


def _td_perf_finite_float(value: object) -> float | None:
    if value is None or isinstance(value, bool):
        return None
    if isinstance(value, (int, float)):
        try:
            out = float(value)
        except Exception:
            return None
        return out if math.isfinite(out) else None
    text = str(value or "").strip()
    if not text:
        return None
    try:
        out = float(text)
    except Exception:
        return None
    return out if math.isfinite(out) else None


def td_perf_display_value(values_by_stat: Mapping[str, object], display_stat: object, *, bounds_mode: object = None) -> float | None:
    st = str(display_stat or "").strip().lower()
    if not st:
        return None
    mode = td_perf_normalize_bounds_mode(bounds_mode)
    if st in {"min", "max"} and mode == TD_PERF_BOUNDS_MODE_MEDIAN_3SIGMA:
        median_val = _td_perf_finite_float(values_by_stat.get("median"))
        std_val = _td_perf_finite_float(values_by_stat.get("std"))
        if median_val is not None and std_val is not None:
            return float(median_val - (3.0 * std_val)) if st == "min" else float(median_val + (3.0 * std_val))
    return _td_perf_finite_float(values_by_stat.get(st))


def td_perf_mean_3sigma_value(values_by_stat: Mapping[str, object], bound: object) -> float | None:
    raw = str(bound or "").strip().lower()
    if raw in {"min", "min_3sigma", "lower", "lower_3sigma"}:
        sign = -1.0
    elif raw in {"max", "max_3sigma", "upper", "upper_3sigma"}:
        sign = 1.0
    else:
        return None
    mean_val = _td_perf_finite_float(values_by_stat.get("mean"))
    std_val = _td_perf_finite_float(values_by_stat.get("std"))
    if mean_val is None or std_val is None:
        return None
    return float(mean_val + (sign * 3.0 * std_val))


