def td_perf_normalize_fit_mode(value: object) -> str:
    raw = str(value or "").strip().lower()
    return raw if raw in TD_PERF_FIT_MODES else TD_PERF_FIT_MODE_AUTO


def td_perf_fit_family_label(value: object) -> str:
    fam = td_perf_normalize_fit_mode(value)
    if fam == TD_PERF_FIT_MODE_POLYNOMIAL:
        return "Polynomial"
    if fam == TD_PERF_FIT_MODE_LOGARITHMIC:
        return "Logarithmic"
    if fam == TD_PERF_FIT_MODE_SATURATING_EXPONENTIAL:
        return "Saturating Exponential"
    if fam == TD_PERF_FIT_MODE_HYBRID_SATURATING_LINEAR:
        return "Hybrid Saturating + Linear"
    if fam == TD_PERF_FIT_MODE_HYBRID_QUADRATIC_RESIDUAL:
        return "Hybrid + Quadratic Residual"
    if fam == TD_PERF_FIT_MODE_MONOTONE_PCHIP:
        return "Monotone PCHIP"
    if fam == TD_PERF_FIT_MODE_PIECEWISE_AUTO:
        return "Piecewise Auto"
    if fam == TD_PERF_FIT_MODE_PIECEWISE_2:
        return "Piecewise 2-Segment"
    if fam == TD_PERF_FIT_MODE_PIECEWISE_3:
        return "Piecewise 3-Segment"
    if fam == TD_PERF_FIT_MODE_POLYNOMIAL_SURFACE:
        return "Polynomial Surface"
    if fam == TD_PERF_FIT_MODE_AUTO_SURFACE:
        return "Auto Surface"
    if fam == TD_PERF_FIT_FAMILY_PLANE:
        return "Plane"
    if fam == TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE:
        return "Quadratic Surface"
    if fam == TD_PERF_FIT_FAMILY_QUADRATIC_3INPUT:
        return "Quadratic 3-Input"
    if fam == TD_PERF_FIT_FAMILY_STAGED_MEDIATOR:
        return "Staged Mediator"
    if fam == TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE_CONTROL_PERIOD:
        return "Quadratic Surface + Control Period"
    if fam == TD_PERF_FIT_FAMILY_QUADRATIC_CURVE_CONTROL_PERIOD:
        return "Quadratic Curve + Control Period"
    if fam == TD_PERF_FIT_FAMILY_HYBRID_QUADRATIC_RESIDUAL_CONTROL_PERIOD:
        return "Hybrid + CP Residual"
    if fam == TD_PERF_FIT_FAMILY_QUADRATIC_3INPUT_CONTROL_PERIOD:
        return "Quadratic 3-Input + Control Period"
    if fam == TD_PERF_FIT_FAMILY_STAGED_MEDIATOR_CONTROL_PERIOD:
        return "Staged Mediator + Control Period"
    return "Auto"


def _td_perf_import_numpy():
    try:
        import numpy as np  # type: ignore
    except Exception as exc:
        raise RuntimeError("numpy is required for performance fitting.") from exc
    return np


def _td_perf_import_curve_fit():
    try:
        from scipy.optimize import curve_fit  # type: ignore
    except Exception as exc:
        raise RuntimeError(
            "scipy is required for Auto, Logarithmic, Saturating Exponential, Hybrid Saturating + Linear, and Monotone PCHIP performance fitting."
        ) from exc
    return curve_fit


def _td_perf_import_pchip():
    try:
        from scipy.interpolate import PchipInterpolator  # type: ignore
    except Exception as exc:
        raise RuntimeError("scipy is required for Monotone PCHIP performance fitting.") from exc
    return PchipInterpolator


def _td_perf_fmt_num(value: object) -> str:
    try:
        return f"{float(value):.4g}"
    except Exception:
        return "0"


def _td_perf_fmt_poly_equation(coeffs: list[float], degree: int, *, x0: float | None, sx: float | None) -> tuple[str, str]:
    if not coeffs:
        return "", ""
    deg = int(degree)
    parts: list[str] = []
    for i, coeff in enumerate(coeffs):
        power = deg - i
        try:
            cf = float(coeff)
        except Exception:
            continue
        if power == 0:
            parts.append(f"{cf:+.4g}")
        elif power == 1:
            parts.append(f"{cf:+.4g}*x'")
        else:
            parts.append(f"{cf:+.4g}*x'^{power}")
    expr = " ".join(parts).lstrip("+").strip()
    if x0 is not None and sx is not None:
        return f"y = {expr}", f"x' = (x - {_td_perf_fmt_num(x0)}) / {_td_perf_fmt_num(sx)}"
    return f"y = {expr}", ""


def _td_perf_fmt_surface_equation(coeffs: list[float], family: str) -> str:
    raw = str(family or "").strip().lower()
    if raw == TD_PERF_FIT_FAMILY_PLANE:
        labels = ["", "x1'", "x2'"]
    elif raw == TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE:
        labels = ["", "x1'", "x2'", "x1'^2", "x1'*x2'", "x2'^2"]
    else:
        return ""
    parts: list[str] = []
    for coeff, label in zip(coeffs, labels):
        try:
            cf = float(coeff)
        except Exception:
            continue
        if not label:
            parts.append(f"{cf:+.4g}")
        else:
            parts.append(f"{cf:+.4g}*{label}")
    expr = " ".join(parts).lstrip("+").strip()
    return f"y = {expr}" if expr else ""


def _td_perf_fmt_surface_normalization(x1_center: float, x1_scale: float, x2_center: float, x2_scale: float) -> str:
    return (
        f"x1' = (x1 - {_td_perf_fmt_num(x1_center)}) / {_td_perf_fmt_num(x1_scale)} ; "
        f"x2' = (x2 - {_td_perf_fmt_num(x2_center)}) / {_td_perf_fmt_num(x2_scale)}"
    )


def _td_perf_fmt_variable_poly_expr(coeffs: Sequence[object], variable_name: str) -> str:
    terms: list[str] = []
    coeff_list = [float(v) for v in coeffs]
    degree = len(coeff_list) - 1
    for idx, coeff in enumerate(coeff_list):
        power = degree - idx
        if power <= 0:
            terms.append(f"{float(coeff):+.4g}")
        elif power == 1:
            terms.append(f"{float(coeff):+.4g}*{variable_name}")
        else:
            terms.append(f"{float(coeff):+.4g}*{variable_name}^{power}")
    expr = " ".join(terms).lstrip("+").strip()
    return expr or "0"


def _td_perf_fmt_surface_control_period_equation(coeff_cp_models: Sequence[Sequence[object]]) -> str:
    labels = ["", "x1'", "x2'", "x1'^2", "x1'*x2'", "x2'^2"]
    parts: list[str] = []
    for coeffs, label in zip(coeff_cp_models, labels):
        coeff_expr = _td_perf_fmt_variable_poly_expr(coeffs, "cp'")
        if not label:
            parts.append(f"({coeff_expr})")
        else:
            parts.append(f"({coeff_expr})*{label}")
    expr = " + ".join(part for part in parts if part.strip())
    return f"y = {expr}" if expr else ""


def _td_perf_fmt_3input_control_period_equation(coeff_cp_models: Sequence[Sequence[object]]) -> str:
    labels = ["", "x1'", "x2'", "x3'", "x1'^2", "x2'^2", "x3'^2", "x1'*x2'", "x1'*x3'", "x2'*x3'"]
    parts: list[str] = []
    for coeffs, label in zip(coeff_cp_models, labels):
        coeff_expr = _td_perf_fmt_variable_poly_expr(coeffs, "cp'")
        if not label:
            parts.append(f"({coeff_expr})")
        else:
            parts.append(f"({coeff_expr})*{label}")
    expr = " + ".join(part for part in parts if part.strip())
    return f"y = {expr}" if expr else ""


def _td_perf_fmt_3input_equation(coeffs: Sequence[object]) -> str:
    labels = ["", "x1'", "x2'", "x3'", "x1'^2", "x2'^2", "x3'^2", "x1'*x2'", "x1'*x3'", "x2'*x3'"]
    parts: list[str] = []
    for coeff, label in zip(coeffs, labels):
        try:
            coeff_value = float(coeff)
        except Exception:
            continue
        if not label:
            parts.append(f"{coeff_value:+.4g}")
        else:
            parts.append(f"{coeff_value:+.4g}*{label}")
    expr = " ".join(parts).lstrip("+").strip()
    return f"y = {expr}" if expr else ""


def _td_perf_fmt_surface_control_period_normalization(
    x1_center: float,
    x1_scale: float,
    x2_center: float,
    x2_scale: float,
    cp_center: float,
    cp_scale: float,
) -> str:
    return (
        f"{_td_perf_fmt_surface_normalization(x1_center, x1_scale, x2_center, x2_scale)} ; "
        f"cp' = (control_period - {_td_perf_fmt_num(cp_center)}) / {_td_perf_fmt_num(cp_scale)}"
    )


def _td_perf_fmt_3input_control_period_normalization(
    x1_center: float,
    x1_scale: float,
    x2_center: float,
    x2_scale: float,
    x3_center: float,
    x3_scale: float,
    cp_center: float,
    cp_scale: float,
) -> str:
    return (
        f"{_td_perf_fmt_surface_normalization(x1_center, x1_scale, x2_center, x2_scale)} ; "
        f"x3' = (x3 - {_td_perf_fmt_num(x3_center)}) / {_td_perf_fmt_num(x3_scale)} ; "
        f"cp' = (control_period - {_td_perf_fmt_num(cp_center)}) / {_td_perf_fmt_num(cp_scale)}"
    )


def _td_perf_fmt_3input_normalization(
    x1_center: float,
    x1_scale: float,
    x2_center: float,
    x2_scale: float,
    x3_center: float,
    x3_scale: float,
) -> str:
    return (
        f"{_td_perf_fmt_surface_normalization(x1_center, x1_scale, x2_center, x2_scale)} ; "
        f"x3' = (x3 - {_td_perf_fmt_num(x3_center)}) / {_td_perf_fmt_num(x3_scale)}"
    )


def _td_perf_fmt_curve_control_period_equation(coeff_cp_models: Sequence[Sequence[object]]) -> str:
    labels = ["x'^2", "x'", ""]
    parts: list[str] = []
    for coeffs, label in zip(coeff_cp_models, labels):
        coeff_expr = _td_perf_fmt_variable_poly_expr(coeffs, "cp'")
        if not label:
            parts.append(f"({coeff_expr})")
        else:
            parts.append(f"({coeff_expr})*{label}")
    expr = " + ".join(part for part in parts if part.strip())
    return f"y = {expr}" if expr else ""


def _td_perf_fmt_curve_control_period_normalization(
    x_center: float,
    x_scale: float,
    cp_center: float,
    cp_scale: float,
) -> str:
    return (
        f"x' = (x - {_td_perf_fmt_num(x_center)}) / {_td_perf_fmt_num(x_scale)} ; "
        f"cp' = (control_period - {_td_perf_fmt_num(cp_center)}) / {_td_perf_fmt_num(cp_scale)}"
    )


def _td_perf_fmt_hybrid_curve_control_period_equation(
    base_equation: object,
    residual_cp_models: Sequence[Sequence[object]],
) -> str:
    base_expr = str(base_equation or "").strip()
    residual_expr = _td_perf_fmt_curve_control_period_equation(residual_cp_models).strip()
    if base_expr.lower().startswith("y ="):
        base_expr = base_expr[3:].strip()
    if residual_expr.lower().startswith("y ="):
        residual_expr = residual_expr[3:].strip()
    if base_expr and residual_expr:
        return f"y = ({base_expr}) + ({residual_expr})"
    if base_expr:
        return f"y = {base_expr}"
    if residual_expr:
        return f"y = {residual_expr}"
    return ""


def _td_perf_fmt_staged_mediator_control_period_equation(
    stage1_equation: object,
    stage2_equation: object,
    *,
    mediator_target: object,
) -> str:
    mediator_name = str(mediator_target or "input3").strip() or "input3"
    stage1_expr = str(stage1_equation or "").strip()
    stage2_expr = str(stage2_equation or "").strip()
    if stage1_expr.lower().startswith("y ="):
        stage1_expr = stage1_expr[3:].strip()
    if stage2_expr.lower().startswith("y ="):
        stage2_expr = stage2_expr[3:].strip()
    if not stage1_expr and not stage2_expr:
        return ""
    if not stage1_expr:
        return f"y = {stage2_expr}"
    if not stage2_expr:
        return f"{mediator_name} = {stage1_expr}"
    return f"{mediator_name} = {stage1_expr} ; y = {stage2_expr}"


def _td_perf_fmt_staged_mediator_equation(
    stage1_equation: object,
    stage2_equation: object,
    *,
    mediator_target: object,
) -> str:
    return _td_perf_fmt_staged_mediator_control_period_equation(
        stage1_equation,
        stage2_equation,
        mediator_target=mediator_target,
    )


def _td_perf_fmt_staged_mediator_control_period_normalization(
    stage1_norm: object,
    stage2_model: Mapping[str, object],
    *,
    mediator_target: object,
) -> str:
    mediator_name = str(mediator_target or "input3").strip() or "input3"
    stage1_text = str(stage1_norm or "").strip()
    stage2_text = _td_perf_fmt_curve_control_period_normalization(
        float(stage2_model.get("x_center") or 0.0),
        float(stage2_model.get("x_scale") or 1.0),
        float(stage2_model.get("cp_center") or 0.0),
        float(stage2_model.get("cp_scale") or 1.0),
    ).replace("x'", f"{mediator_name}'").replace("(x -", f"({mediator_name} -")
    if stage1_text and stage2_text:
        return f"Stage 1: {stage1_text} ; Stage 2: {stage2_text}"
    return stage1_text or stage2_text


def _td_perf_fmt_staged_mediator_normalization(
    stage1_norm: object,
    stage2_model: Mapping[str, object],
    *,
    mediator_target: object,
) -> str:
    mediator_name = str(mediator_target or "input3").strip() or "input3"
    stage1_text = str(stage1_norm or "").strip()
    stage2_text = str(stage2_model.get("x_norm_equation") or "").strip()
    if stage2_text:
        stage2_text = stage2_text.replace("x'", f"{mediator_name}'").replace("(x -", f"({mediator_name} -")
    if stage1_text and stage2_text:
        return f"Stage 1: {stage1_text} ; Stage 2: {stage2_text}"
    return stage1_text or stage2_text


def _td_perf_surface_control_period_label(value: object) -> str:
    try:
        numeric = float(value)
        if math.isfinite(numeric):
            return f"{numeric:g}"
    except Exception:
        pass
    text = str(value or "").strip()
    return text or "?"


def _td_perf_surface_control_period_reason(
    *,
    point_count: int,
    distinct_x1: int,
    distinct_x2: int,
    fit_failed: bool = False,
    min_points: int = 6,
    min_distinct_x1: int = 2,
    min_distinct_x2: int = 2,
) -> str:
    reasons: list[str] = []
    if point_count < min_points:
        reasons.append(f"{int(point_count)} points (<{int(min_points)})")
    if distinct_x1 < min_distinct_x1:
        reasons.append(f"{int(distinct_x1)} distinct x1 (<{int(min_distinct_x1)})")
    if distinct_x2 < min_distinct_x2:
        reasons.append(f"{int(distinct_x2)} distinct x2 (<{int(min_distinct_x2)})")
    if fit_failed:
        reasons.append("quadratic slice fit failed")
    return "; ".join(reasons)


def _td_perf_curve_control_period_reason(*, point_count: int, distinct_x1: int, fit_failed: bool = False) -> str:
    reasons: list[str] = []
    if point_count < 3:
        reasons.append(f"{int(point_count)} points (<3)")
    if distinct_x1 < 2:
        reasons.append(f"{int(distinct_x1)} distinct x1 (<2)")
    if fit_failed:
        reasons.append("quadratic slice fit failed")
    return "; ".join(reasons)


def _td_perf_three_input_control_period_reason(
    *,
    point_count: int,
    distinct_x1: int,
    distinct_x2: int,
    distinct_x3: int,
    fit_failed: bool = False,
    min_points: int = 10,
    min_distinct_x1: int = 2,
    min_distinct_x2: int = 2,
    min_distinct_x3: int = 2,
) -> str:
    reasons: list[str] = []
    if point_count < min_points:
        reasons.append(f"{int(point_count)} points (<{int(min_points)})")
    if distinct_x1 < min_distinct_x1:
        reasons.append(f"{int(distinct_x1)} distinct x1 (<{int(min_distinct_x1)})")
    if distinct_x2 < min_distinct_x2:
        reasons.append(f"{int(distinct_x2)} distinct x2 (<{int(min_distinct_x2)})")
    if distinct_x3 < min_distinct_x3:
        reasons.append(f"{int(distinct_x3)} distinct x3 (<{int(min_distinct_x3)})")
    if fit_failed:
        reasons.append("quadratic 3-input slice fit failed")
    return "; ".join(reasons)


def _td_perf_surface_control_period_entry_text(entry: Mapping[str, object]) -> str:
    cp_text = _td_perf_surface_control_period_label(entry.get("control_period"))
    point_count = int(entry.get("point_count") or 0)
    distinct_x1 = int(entry.get("distinct_x1") or 0)
    distinct_x2 = int(entry.get("distinct_x2") or 0)
    reason = str(entry.get("reason") or "").strip()
    detail = f"CP {cp_text}: {point_count} points, {distinct_x1} distinct x1, {distinct_x2} distinct x2"
    return f"{detail} ({reason})" if reason else detail


def _td_perf_curve_control_period_entry_text(entry: Mapping[str, object]) -> str:
    cp_text = _td_perf_surface_control_period_label(entry.get("control_period"))
    point_count = int(entry.get("point_count") or 0)
    distinct_x1 = int(entry.get("distinct_x1") or 0)
    reason = str(entry.get("reason") or "").strip()
    detail = f"CP {cp_text}: {point_count} points, {distinct_x1} distinct x1"
    return f"{detail} ({reason})" if reason else detail


def _td_perf_three_input_control_period_entry_text(entry: Mapping[str, object]) -> str:
    cp_text = _td_perf_surface_control_period_label(entry.get("control_period"))
    point_count = int(entry.get("point_count") or 0)
    distinct_x1 = int(entry.get("distinct_x1") or 0)
    distinct_x2 = int(entry.get("distinct_x2") or 0)
    distinct_x3 = int(entry.get("distinct_x3") or 0)
    reason = str(entry.get("reason") or "").strip()
    detail = (
        f"CP {cp_text}: {point_count} points, {distinct_x1} distinct x1, "
        f"{distinct_x2} distinct x2, {distinct_x3} distinct x3"
    )
    return f"{detail} ({reason})" if reason else detail


def _td_perf_format_surface_control_period_warning(ignored_periods: Sequence[Mapping[str, object]]) -> str:
    ignored = [dict(entry) for entry in (ignored_periods or []) if isinstance(entry, Mapping)]
    if not ignored:
        return ""
    details = "; ".join(_td_perf_surface_control_period_entry_text(entry) for entry in ignored)
    return f"Ignored control periods for CP-surface fit: {details}"


def _td_perf_format_surface_control_period_failure(
    ignored_periods: Sequence[Mapping[str, object]],
    *,
    eligible_count: int,
) -> str:
    details = "; ".join(
        _td_perf_surface_control_period_entry_text(entry)
        for entry in (ignored_periods or [])
        if isinstance(entry, Mapping)
    )
    prefix = "Quadratic Surface + Control Period requires at least two distinct control periods with valid surface coverage."
    if details:
        return f"{prefix} Eligible periods: {int(eligible_count)}. {details}"
    return prefix


