def _td_perf_append_fit_warning(model: dict[str, object], text: str) -> None:
    note = str(text or "").strip()
    if not note:
        return
    warnings = model.get("warnings")
    warning_list = [str(item).strip() for item in warnings] if isinstance(warnings, list) else []
    warning_list = [item for item in warning_list if item]
    if note not in warning_list:
        warning_list.append(note)
    model["warnings"] = warning_list
    existing = [str(item).strip() for item in str(model.get("fit_warning_text") or "").splitlines() if str(item).strip()]
    merged: list[str] = []
    for item in existing + [note]:
        if item and item not in merged:
            merged.append(item)
    model["fit_warning_text"] = "\n".join(merged)


def _td_perf_surface_control_period_in_domain(model: Mapping[str, object], control_period: object) -> bool:
    if control_period in (None, ""):
        return True
    try:
        cp_numeric = float(control_period)
    except Exception:
        return False
    domain = model.get("fit_domain_control_period")
    if not isinstance(domain, Sequence) or isinstance(domain, (str, bytes)) or len(domain) < 2:
        return True
    try:
        cp_min = float(domain[0])
        cp_max = float(domain[1])
    except Exception:
        return True
    if not (math.isfinite(cp_min) and math.isfinite(cp_max)):
        return True
    lo = min(cp_min, cp_max)
    hi = max(cp_min, cp_max)
    return (lo - 1e-9) <= cp_numeric <= (hi + 1e-9)


def _td_perf_surface_control_period_out_of_domain_warning(model: Mapping[str, object], control_period: object) -> str:
    if control_period in (None, "") or _td_perf_surface_control_period_in_domain(model, control_period):
        return ""
    domain = model.get("fit_domain_control_period")
    if not isinstance(domain, Sequence) or isinstance(domain, (str, bytes)) or len(domain) < 2:
        return ""
    try:
        cp_min = float(domain[0])
        cp_max = float(domain[1])
    except Exception:
        return ""
    cp_text = _td_perf_surface_control_period_label(control_period)
    return (
        f"Surface overlay omitted for control period {cp_text} because the fitted control-period domain is "
        f"{min(cp_min, cp_max):g} to {max(cp_min, cp_max):g}."
    )


def _td_perf_prepare_xy(xs: Sequence[float], ys: Sequence[float]):
    np = _td_perf_import_numpy()
    if len(xs) != len(ys):
        return None, None, None
    x_arr = np.asarray([float(v) for v in xs], dtype=float)
    y_arr = np.asarray([float(v) for v in ys], dtype=float)
    finite_mask = np.isfinite(x_arr) & np.isfinite(y_arr)
    if not bool(np.all(finite_mask)):
        return None, None, None
    order = np.argsort(x_arr, kind="mergesort")
    return x_arr[order], y_arr[order], order


def _td_perf_edge_weights(xs: Sequence[float]) -> list[float]:
    values = [float(v) for v in xs]
    if not values:
        return []
    x_min = float(min(values))
    x_max = float(max(values))
    x_span = float(x_max - x_min)
    if not math.isfinite(x_span) or x_span <= 0.0:
        return [1.0 for _ in values]
    edge_lo = x_min + (0.20 * x_span)
    edge_hi = x_max - (0.20 * x_span)
    return [1.75 if (float(x) <= edge_lo or float(x) >= edge_hi) else 1.0 for x in values]


def _td_perf_prepare_sample_weights(xs: Sequence[float], sample_weights: Sequence[float] | None):
    np = _td_perf_import_numpy()
    if sample_weights is None:
        return _td_perf_edge_weights(xs)
    if len(sample_weights) != len(xs):
        return None
    try:
        arr = np.asarray([float(v) for v in sample_weights], dtype=float)
    except Exception:
        return None
    if not bool(np.all(np.isfinite(arr))):
        return None
    arr = np.clip(arr, 1e-6, None)
    return [float(v) for v in arr.tolist()]


def _td_perf_curve_fit_sigma(sample_weights: Sequence[float] | None):
    if sample_weights is None:
        return None
    return [float(1.0 / max(float(v), 1e-6)) for v in sample_weights]


def _td_perf_weighted_lstsq(design, y_values, sample_weights: Sequence[float] | None):
    np = _td_perf_import_numpy()
    if sample_weights is None:
        return np.linalg.lstsq(design, y_values, rcond=None)
    w = np.sqrt(np.asarray([float(v) for v in sample_weights], dtype=float)).reshape(-1, 1)
    weighted_design = design * w
    weighted_y = np.asarray(y_values, dtype=float) * w[:, 0]
    return np.linalg.lstsq(weighted_design, weighted_y, rcond=None)


def _td_perf_piecewise_basis(xs, breakpoints: Sequence[float]):
    np = _td_perf_import_numpy()
    x_arr = np.asarray(xs, dtype=float)
    cols = [np.ones_like(x_arr), x_arr]
    for bp in breakpoints:
        cols.append(np.maximum(0.0, x_arr - float(bp)))
    return np.column_stack(cols)


def _td_perf_piecewise_segment_params(coeffs: Sequence[float], breakpoints: Sequence[float]) -> list[dict[str, float]]:
    intercept = float(coeffs[0])
    slope = float(coeffs[1])
    segments: list[dict[str, float]] = []
    running_intercept = intercept
    running_slope = slope
    prev_bp: float | None = None
    for idx, bp in enumerate(breakpoints):
        seg: dict[str, float] = {
            "x_min": float("-inf") if prev_bp is None else float(prev_bp),
            "x_max": float(bp),
            "intercept": float(running_intercept),
            "slope": float(running_slope),
        }
        segments.append(seg)
        delta = float(coeffs[idx + 2])
        running_intercept = float(running_intercept - (delta * float(bp)))
        running_slope = float(running_slope + delta)
        prev_bp = float(bp)
    segments.append(
        {
            "x_min": float(prev_bp if prev_bp is not None else float("-inf")),
            "x_max": float("inf"),
            "intercept": float(running_intercept),
            "slope": float(running_slope),
        }
    )
    return segments


def _td_perf_piecewise_param_count(segment_count: int) -> int:
    return 2 + (2 * max(0, int(segment_count) - 1))


def _td_perf_fmt_piecewise_equation(segments: Sequence[Mapping[str, object]], breakpoints: Sequence[float]) -> str:
    if not segments:
        return ""
    pieces: list[str] = []
    for idx, seg in enumerate(segments):
        intercept = _td_perf_fmt_num(seg.get("intercept"))
        slope = _td_perf_fmt_num(seg.get("slope"))
        expr = f"{intercept} {float(seg.get('slope') or 0.0):+.4g}*x"
        if idx == 0:
            cond = f"x <= {_td_perf_fmt_num(breakpoints[0])}" if breakpoints else "all x"
        elif idx == (len(segments) - 1):
            cond = f"x > {_td_perf_fmt_num(breakpoints[-1])}"
        else:
            cond = f"{_td_perf_fmt_num(breakpoints[idx - 1])} < x <= {_td_perf_fmt_num(breakpoints[idx])}"
        pieces.append(f"{cond}: y = {expr}")
    bp_text = ", ".join(_td_perf_fmt_num(bp) for bp in breakpoints)
    if bp_text:
        return f"breaks: [{bp_text}] | " + " ; ".join(pieces)
    return " ; ".join(pieces)


def _td_perf_piecewise_candidate_breaks(
    unique_x: Sequence[float],
    *,
    segment_count: int,
    min_points_per_segment: int,
    min_span: float,
) -> list[tuple[float, ...]]:
    values = [float(v) for v in unique_x]
    if len(values) < max(2, int(segment_count)):
        return []

    def _sample_indices(start: int, stop: int, *, max_count: int) -> list[int]:
        if stop <= start or max_count <= 0:
            return []
        count = stop - start
        if count <= max_count:
            return list(range(start, stop))
        if max_count == 1:
            return [start + ((count - 1) // 2)]
        step = float(count - 1) / float(max_count - 1)
        last = stop - 1
        sampled = sorted({start + int(round(step * idx)) for idx in range(max_count)} | {start, last})
        return [idx for idx in sampled if start <= idx < stop]

    def _valid_spans(boundaries: Sequence[float]) -> bool:
        parts = [values[0], *[float(v) for v in boundaries], values[-1]]
        return all((parts[i + 1] - parts[i]) >= float(min_span) for i in range(len(parts) - 1))

    candidates: list[tuple[float, ...]] = []
    if int(segment_count) == 2:
        start = min_points_per_segment - 1
        stop = len(values) - min_points_per_segment
        for idx in _sample_indices(start, stop, max_count=TD_PERF_PIECEWISE_MAX_BREAK_CANDIDATES_2):
            bp = float(values[idx])
            if _valid_spans([bp]):
                candidates.append((bp,))
        return candidates
    if int(segment_count) == 3:
        start1 = min_points_per_segment - 1
        stop1 = len(values) - ((2 * min_points_per_segment) - 1)
        for idx1 in _sample_indices(start1, stop1, max_count=TD_PERF_PIECEWISE_MAX_BREAK_CANDIDATES_3):
            bp1 = float(values[idx1])
            start2 = idx1 + min_points_per_segment
            stop2 = len(values) - min_points_per_segment
            for idx2 in _sample_indices(start2, stop2, max_count=TD_PERF_PIECEWISE_MAX_BREAK_CANDIDATES_3):
                bp2 = float(values[idx2])
                if _valid_spans([bp1, bp2]):
                    candidates.append((bp1, bp2))
        return candidates
    return []


def _td_perf_fit_piecewise_model(
    xs: list[float],
    ys: list[float],
    *,
    segment_count: int,
    fit_mode: str,
    sample_weights: Sequence[float] | None = None,
) -> dict[str, object] | None:
    np = _td_perf_import_numpy()
    seg_count = int(segment_count)
    if seg_count not in {2, 3} or len(xs) != len(ys):
        return None
    min_points_per_segment = 2
    if len(xs) < (seg_count * min_points_per_segment):
        return None
    prepared = _td_perf_prepare_xy(xs, ys)
    if prepared[0] is None:
        return None
    x_sorted, y_sorted, order = prepared
    assert order is not None
    weights_in = _td_perf_prepare_sample_weights(xs, sample_weights)
    if weights_in is None:
        return None
    weights_sorted = [float(weights_in[idx]) for idx in order.tolist()]
    unique_x = sorted({round(float(v), 12) for v in x_sorted.tolist()})
    min_unique = seg_count + 1
    if len(unique_x) < min_unique:
        return None
    x_span = float(x_sorted[-1] - x_sorted[0])
    diffs = np.diff(np.asarray(unique_x, dtype=float))
    positive_diffs = [float(v) for v in diffs.tolist() if float(v) > 0.0]
    median_dx = float(np.median(np.asarray(positive_diffs, dtype=float))) if positive_diffs else 0.0
    min_span = max(1e-9, 2.0 * median_dx)
    best_model: dict[str, object] | None = None
    best_score = float("inf")
    candidates = _td_perf_piecewise_candidate_breaks(
        unique_x,
        segment_count=seg_count,
        min_points_per_segment=min_points_per_segment,
        min_span=min_span,
    )
    if not candidates:
        return None

    slope_scale = max(abs(float(y_sorted[-1] - y_sorted[0])) / max(x_span, 1e-9), 1e-9)
    slope_delta_tol = max(1e-6, slope_scale * 0.08)
    split_penalty = TD_PERF_FIT_COMPLEXITY_PENALTIES[
        TD_PERF_FIT_MODE_PIECEWISE_2 if seg_count == 2 else TD_PERF_FIT_MODE_PIECEWISE_3
    ]

    for breakpoints in candidates:
        edges = [x_sorted[0], *[float(v) for v in breakpoints], x_sorted[-1]]
        counts: list[int] = []
        for idx in range(seg_count):
            if idx == 0:
                mask = x_sorted <= float(edges[idx + 1])
            elif idx == (seg_count - 1):
                mask = x_sorted > float(edges[idx])
            else:
                mask = (x_sorted > float(edges[idx])) & (x_sorted <= float(edges[idx + 1]))
            count = int(np.count_nonzero(mask))
            if count < min_points_per_segment:
                counts = []
                break
            span = float(np.max(x_sorted[mask]) - np.min(x_sorted[mask]))
            if span < min_span:
                counts = []
                break
            counts.append(count)
        if len(counts) != seg_count:
            continue

        design = _td_perf_piecewise_basis(x_sorted, breakpoints)
        coeffs, _residuals, rank, _singular = _td_perf_weighted_lstsq(design, y_sorted, weights_sorted)
        if int(rank) < int(design.shape[1]):
            continue
        coeff_list = [float(v) for v in coeffs.tolist()]
        segments = _td_perf_piecewise_segment_params(coeff_list, breakpoints)
        if len(segments) != seg_count:
            continue
        slope_deltas = [abs(float(segments[i + 1]["slope"]) - float(segments[i]["slope"])) for i in range(seg_count - 1)]
        if any(delta < slope_delta_tol for delta in slope_deltas):
            continue
        y_hat = design.dot(coeffs)
        family = TD_PERF_FIT_MODE_PIECEWISE_2 if seg_count == 2 else TD_PERF_FIT_MODE_PIECEWISE_3
        model = _td_perf_finalize_model(
            fit_family=family,
            fit_mode=fit_mode,
            equation=_td_perf_fmt_piecewise_equation(segments, breakpoints),
            x_norm_equation="",
            params={
                "segment_count": seg_count,
                "breakpoints": [float(v) for v in breakpoints],
                "coeffs": coeff_list,
                "segments": [
                    {
                        "x_min": float(seg["x_min"]),
                        "x_max": float(seg["x_max"]),
                        "intercept": float(seg["intercept"]),
                        "slope": float(seg["slope"]),
                    }
                    for seg in segments
                ],
            },
            param_count=_td_perf_piecewise_param_count(seg_count),
            x_values=x_sorted,
            y_true=y_sorted,
            y_hat=y_hat,
            complexity_penalty=split_penalty,
            extra={
                "breakpoints": [float(v) for v in breakpoints],
                "segments": [
                    {
                        "x_min": float(seg["x_min"]),
                        "x_max": float(seg["x_max"]),
                        "intercept": float(seg["intercept"]),
                        "slope": float(seg["slope"]),
                    }
                    for seg in segments
                ],
                "segment_count": seg_count,
                "fit_domain": [float(x_sorted[0]), float(x_sorted[-1])],
                "sample_weights_used": [float(v) for v in weights_sorted],
            },
        )
        model["monotonic_violations"] = 0
        model["monotonicity_penalty"] = 0.0
        if _td_perf_model_score_value(model) < best_score:
            best_model = model
            best_score = _td_perf_model_score_value(model)
    return best_model


def _td_perf_aic_metrics(y_true, y_hat, *, param_count: int) -> tuple[float, float]:
    np = _td_perf_import_numpy()
    residuals = np.asarray(y_true, dtype=float) - np.asarray(y_hat, dtype=float)
    n = int(len(residuals))
    if n <= 0:
        return float("inf"), float("inf")
    sse = float(np.sum(residuals**2))
    mse = max(sse / float(max(1, n)), 1e-12)
    k = max(1, int(param_count))
    aic = float(n * math.log(mse) + (2.0 * k))
    if n > (k + 1):
        aicc = float(aic + ((2.0 * k * (k + 1)) / float(n - k - 1)))
    else:
        aicc = float("inf")
    return aic, aicc


def _td_perf_monotonic_violations(x_values, y_values) -> int:
    np = _td_perf_import_numpy()
    xs = np.asarray(x_values, dtype=float)
    ys = np.asarray(y_values, dtype=float)
    if len(xs) < 3:
        return 0
    order = np.argsort(xs)
    ys_sorted = ys[order]
    diffs = np.diff(ys_sorted)
    net = float(ys_sorted[-1] - ys_sorted[0])
    direction = 1.0 if net >= 0 else -1.0
    tol = max(1e-9, float(np.max(np.abs(diffs))) * 1e-6 if len(diffs) else 1e-9)
    return int(sum(1 for diff in diffs if (float(diff) * direction) < (-tol)))


def _td_perf_normalized_rmse(y_true, y_hat) -> float:
    np = _td_perf_import_numpy()
    y_true_arr = np.asarray(y_true, dtype=float)
    y_hat_arr = np.asarray(y_hat, dtype=float)
    if len(y_true_arr) <= 0:
        return float("inf")
    y_span = max(float(np.max(y_true_arr) - np.min(y_true_arr)), 1e-9)
    rmse = float(np.sqrt(np.mean((y_true_arr - y_hat_arr) ** 2)))
    return rmse / y_span


def _td_perf_edge_rmse_norm(x_values, y_true, y_hat) -> float:
    np = _td_perf_import_numpy()
    xs = np.asarray(x_values, dtype=float)
    y_true_arr = np.asarray(y_true, dtype=float)
    y_hat_arr = np.asarray(y_hat, dtype=float)
    if len(xs) <= 1:
        return _td_perf_normalized_rmse(y_true_arr, y_hat_arr)
    x_min = float(np.min(xs))
    x_max = float(np.max(xs))
    x_span = float(x_max - x_min)
    if x_span <= 0.0:
        return _td_perf_normalized_rmse(y_true_arr, y_hat_arr)
    edge_lo = x_min + (0.20 * x_span)
    edge_hi = x_max - (0.20 * x_span)
    mask = (xs <= edge_lo) | (xs >= edge_hi)
    if int(np.count_nonzero(mask)) <= 0:
        return _td_perf_normalized_rmse(y_true_arr, y_hat_arr)
    return _td_perf_normalized_rmse(y_true_arr[mask], y_hat_arr[mask])


def _td_perf_group_duplicate_xy(xs, ys):
    np = _td_perf_import_numpy()
    grouped: dict[float, list[float]] = {}
    for x_val, y_val in zip(xs, ys):
        grouped.setdefault(round(float(x_val), 12), []).append(float(y_val))
    pairs = sorted((float(x_key), float(np.median(np.asarray(vals, dtype=float)))) for x_key, vals in grouped.items())
    return [float(x) for x, _ in pairs], [float(y) for _x, y in pairs]


def _td_perf_tail_slope_seed(xs, ys) -> float:
    np = _td_perf_import_numpy()
    if len(xs) < 2:
        return 0.0
    tail_count = max(2, int(math.ceil(len(xs) * 0.25)))
    tail_x = np.asarray(xs[-tail_count:], dtype=float)
    tail_y = np.asarray(ys[-tail_count:], dtype=float)
    if len(tail_x) < 2 or float(np.max(tail_x) - np.min(tail_x)) <= 0.0:
        return 0.0
    coeffs = np.polyfit(tail_x, tail_y, 1)
    return max(float(coeffs[0]), 0.0)


def _td_perf_parametric_aic_key(model: Mapping[str, object]) -> tuple[float, float]:
    family = str(model.get("fit_family") or "").strip().lower()
    if family == TD_PERF_FIT_MODE_MONOTONE_PCHIP:
        return float("inf"), float("inf")
    return float(model.get("aicc") or float("inf")), float(model.get("aic") or float("inf"))


def _td_perf_model_score_value(model: Mapping[str, object]) -> float:
    try:
        score = float(model.get("score"))
    except Exception:
        return float("inf")
    return score if math.isfinite(score) else float("inf")


def td_perf_normalize_surface_family(value: object) -> str:
    raw = str(value or "").strip().lower()
    if raw in {
        TD_PERF_FIT_MODE_AUTO_SURFACE,
        TD_PERF_FIT_FAMILY_PLANE,
        TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE,
        TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE_CONTROL_PERIOD,
    }:
        return raw
    if raw in {"auto", TD_PERF_FIT_MODE_POLYNOMIAL_SURFACE}:
        return TD_PERF_FIT_MODE_AUTO_SURFACE
    if raw in {"quadratic", "quadratic_surface"}:
        return TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE
    if raw in {"quadratic_surface_control_period", "quadratic_surface_cp", "quadratic_control_period"}:
        return TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE_CONTROL_PERIOD
    return TD_PERF_FIT_MODE_AUTO_SURFACE


def td_perf_predict_model(
    model: Mapping[str, object],
    xs: Iterable[float],
    *,
    control_period: object = None,
) -> list[float]:
    np = _td_perf_import_numpy()
    family = td_perf_normalize_fit_mode(model.get("fit_family"))
    x_arr = np.asarray([float(v) for v in xs], dtype=float)
    if family == TD_PERF_FIT_MODE_POLYNOMIAL:
        coeffs = [float(v) for v in (model.get("coeffs") or [])]
        if not coeffs:
            return []
        p = np.poly1d(coeffs)
        if bool(model.get("normalize_x")):
            x0 = float(model.get("x0") or 0.0)
            sx = float(model.get("sx") or 1.0) or 1.0
            x_arr = (x_arr - x0) / sx
        return [float(v) for v in p(x_arr).tolist()]
    params = model.get("params") or {}
    if family == TD_PERF_FIT_MODE_LOGARITHMIC:
        if np.any(x_arr <= 0):
            raise ValueError("Logarithmic model requires X > 0.")
        a = float((params or {}).get("a") or 0.0)
        b = float((params or {}).get("b") or 0.0)
        return [float(v) for v in (a + (b * np.log(x_arr))).tolist()]
    if family == TD_PERF_FIT_MODE_SATURATING_EXPONENTIAL:
        L = float((params or {}).get("L") or 0.0)
        A = float((params or {}).get("A") or 0.0)
        k = float((params or {}).get("k") or 0.0)
        return [float(v) for v in (L - (A * np.exp(-k * x_arr))).tolist()]
    if family == TD_PERF_FIT_MODE_HYBRID_SATURATING_LINEAR:
        b = float((params or {}).get("b") or 0.0)
        m = float((params or {}).get("m") or 0.0)
        A = float((params or {}).get("A") or 0.0)
        k = float((params or {}).get("k") or 0.0)
        return [float(v) for v in (b + (m * x_arr) + (A * (1.0 - np.exp(-k * x_arr)))).tolist()]
    if family == TD_PERF_FIT_MODE_HYBRID_QUADRATIC_RESIDUAL:
        base_params = dict((params or {}).get("base_params") or {})
        b = float(base_params.get("b") or 0.0)
        m = float(base_params.get("m") or 0.0)
        A = float(base_params.get("A") or 0.0)
        k = float(base_params.get("k") or 0.0)
        base = b + (m * x_arr) + (A * (1.0 - np.exp(-k * x_arr)))
        coeffs = [float(v) for v in ((params or {}).get("residual_coeffs") or [])]
        if len(coeffs) != 3:
            return [float(v) for v in base.tolist()]
        if bool((params or {}).get("normalize_x")):
            x0 = float((params or {}).get("x0") or 0.0)
            sx = float((params or {}).get("sx") or 1.0) or 1.0
            xn = (x_arr - x0) / sx
        else:
            xn = x_arr
        residual = np.poly1d(coeffs)(xn)
        return [float(v) for v in (base + residual).tolist()]
    if family == TD_PERF_FIT_MODE_MONOTONE_PCHIP:
        PchipInterpolator = _td_perf_import_pchip()
        knots = [float(v) for v in ((params or {}).get("knots") or [])]
        knot_values = [float(v) for v in ((params or {}).get("knot_values") or [])]
        if len(knots) < 2 or len(knots) != len(knot_values):
            return []
        interpolator = PchipInterpolator(knots, knot_values, extrapolate=False)
        y_hat = interpolator(x_arr)
        left_y = float((params or {}).get("left_y") or knot_values[0])
        right_y = float((params or {}).get("right_y") or knot_values[-1])
        y_hat = np.where(x_arr < float(knots[0]), left_y, y_hat)
        y_hat = np.where(x_arr > float(knots[-1]), right_y, y_hat)
        return [float(v) for v in y_hat.tolist()]
    if family in {TD_PERF_FIT_MODE_PIECEWISE_2, TD_PERF_FIT_MODE_PIECEWISE_3}:
        coeffs = [float(v) for v in ((params or {}).get("coeffs") or [])]
        breakpoints = [float(v) for v in ((params or {}).get("breakpoints") or [])]
        if len(coeffs) != (2 + len(breakpoints)):
            return []
        design = _td_perf_piecewise_basis(x_arr, breakpoints)
        y_hat = design.dot(np.asarray(coeffs, dtype=float))
        return [float(v) for v in y_hat.tolist()]
    if family == TD_PERF_FIT_FAMILY_QUADRATIC_CURVE_CONTROL_PERIOD:
        if control_period in (None, ""):
            return []
        return _td_perf_predict_quadratic_curve_control_period(model, x_arr.tolist(), control_period)
    if family == TD_PERF_FIT_FAMILY_HYBRID_QUADRATIC_RESIDUAL_CONTROL_PERIOD:
        if control_period in (None, ""):
            return []
        return _td_perf_predict_hybrid_quadratic_residual_control_period(model, x_arr.tolist(), control_period)
    return []


def td_perf_build_aggregate_curve(
    curves: Mapping[str, Sequence[Sequence[object]]],
    *,
    max_bins: int = 24,
    min_serials_per_bin: int = 1,
    return_meta: bool = False,
) -> dict[str, list[float] | list[int]]:
    np = _td_perf_import_numpy()
    serial_points: dict[str, list[tuple[float, float]]] = {}
    pooled_x: list[float] = []
    for serial, rows in (curves or {}).items():
        pts: list[tuple[float, float]] = []
        for row in rows or []:
            if len(row) < 2:
                continue
            try:
                x_val = float(row[0])
                y_val = float(row[1])
            except Exception:
                continue
            if not (math.isfinite(x_val) and math.isfinite(y_val)):
                continue
            pts.append((x_val, y_val))
            pooled_x.append(x_val)
        if pts:
            serial_points[str(serial)] = pts
    empty: dict[str, list[float] | list[int]] = {"x": [], "y": []}
    if return_meta:
        empty.update({"serial_support": [], "edge_weight": []})
    if not pooled_x:
        return empty
    x_min = float(min(pooled_x))
    x_max = float(max(pooled_x))
    if not math.isfinite(x_min) or not math.isfinite(x_max):
        return empty
    unique_x = sorted({round(float(v), 12) for v in pooled_x})
    if len(unique_x) <= 1 or float(x_min) == float(x_max):
        y_vals = [y for pts in serial_points.values() for _x, y in pts]
        y_med = float(np.median(np.asarray(y_vals, dtype=float))) if y_vals else 0.0
        out: dict[str, list[float] | list[int]] = {"x": [float(x_min)], "y": [y_med]}
        if return_meta:
            out["serial_support"] = [len(serial_points)]
            out["edge_weight"] = [1.0]
        return out

    bin_count = max(2, min(int(max_bins), len(unique_x)))
    edges = np.linspace(float(x_min), float(x_max), bin_count + 1)
    bins: list[tuple[float, float]] = list(zip(edges[:-1].tolist(), edges[1:].tolist()))
    agg_x: list[float] = []
    agg_y: list[float] = []
    serial_support: list[int] = []
    for idx, (left, right) in enumerate(bins):
        serial_bin_points: list[tuple[float, float]] = []
        for pts in serial_points.values():
            if idx == (len(bins) - 1):
                in_bin = [(x, y) for x, y in pts if x >= left and x <= right]
            else:
                in_bin = [(x, y) for x, y in pts if x >= left and x < right]
            if not in_bin:
                continue
            x_med = float(np.median(np.asarray([x for x, _y in in_bin], dtype=float)))
            y_med = float(np.median(np.asarray([y for _x, y in in_bin], dtype=float)))
            serial_bin_points.append((x_med, y_med))
        if len(serial_bin_points) < max(1, int(min_serials_per_bin)):
            continue
        agg_x.append(float(np.median(np.asarray([x for x, _y in serial_bin_points], dtype=float))))
        agg_y.append(float(np.median(np.asarray([y for _x, y in serial_bin_points], dtype=float))))
        serial_support.append(int(len(serial_bin_points)))
    if not agg_x:
        return empty
    edge_weight = _td_perf_edge_weights(agg_x)
    pairs = sorted(zip(agg_x, agg_y, serial_support, edge_weight), key=lambda item: item[0])
    out = {
        "x": [float(x) for x, _y, _support, _edge in pairs],
        "y": [float(y) for _x, y, _support, _edge in pairs],
    }
    if return_meta:
        out["serial_support"] = [int(support) for _x, _y, support, _edge in pairs]
        out["edge_weight"] = [float(edge) for _x, _y, _support, edge in pairs]
    return out


def _td_perf_surface_normalize_axes(x1_values, x2_values, *, centers: tuple[float, float] | None = None, scales: tuple[float, float] | None = None):
    np = _td_perf_import_numpy()
    x1 = np.asarray(x1_values, dtype=float)
    x2 = np.asarray(x2_values, dtype=float)
    if centers is None:
        x1_center = float(np.mean(x1))
        x2_center = float(np.mean(x2))
    else:
        x1_center, x2_center = float(centers[0]), float(centers[1])
    if scales is None:
        x1_scale = float(np.std(x1)) or 1.0
        x2_scale = float(np.std(x2)) or 1.0
    else:
        x1_scale = float(scales[0]) or 1.0
        x2_scale = float(scales[1]) or 1.0
    return (x1 - x1_center) / x1_scale, (x2 - x2_center) / x2_scale, x1_center, x1_scale, x2_center, x2_scale


def _td_perf_surface_normalize_three_axes(
    x1_values,
    x2_values,
    x3_values,
    *,
    centers: tuple[float, float, float] | None = None,
    scales: tuple[float, float, float] | None = None,
):
    np = _td_perf_import_numpy()
    x1 = np.asarray(x1_values, dtype=float)
    x2 = np.asarray(x2_values, dtype=float)
    x3 = np.asarray(x3_values, dtype=float)
    if centers is None:
        x1_center = float(np.mean(x1))
        x2_center = float(np.mean(x2))
        x3_center = float(np.mean(x3))
    else:
        x1_center, x2_center, x3_center = float(centers[0]), float(centers[1]), float(centers[2])
    if scales is None:
        x1_scale = float(np.std(x1)) or 1.0
        x2_scale = float(np.std(x2)) or 1.0
        x3_scale = float(np.std(x3)) or 1.0
    else:
        x1_scale = float(scales[0]) or 1.0
        x2_scale = float(scales[1]) or 1.0
        x3_scale = float(scales[2]) or 1.0
    return (
        (x1 - x1_center) / x1_scale,
        (x2 - x2_center) / x2_scale,
        (x3 - x3_center) / x3_scale,
        x1_center,
        x1_scale,
        x2_center,
        x2_scale,
        x3_center,
        x3_scale,
    )


def _td_perf_surface_design_matrix(x1_values, x2_values, family: str):
    np = _td_perf_import_numpy()
    x1 = np.asarray(x1_values, dtype=float)
    x2 = np.asarray(x2_values, dtype=float)
    raw = str(family or "").strip().lower()
    if raw == TD_PERF_FIT_FAMILY_PLANE:
        return np.column_stack([np.ones_like(x1), x1, x2])
    if raw == TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE:
        return np.column_stack([np.ones_like(x1), x1, x2, x1**2, x1 * x2, x2**2])
    raise ValueError(f"Unsupported surface family: {family}")


def _td_perf_three_input_design_matrix(x1_values, x2_values, x3_values):
    np = _td_perf_import_numpy()
    x1 = np.asarray(x1_values, dtype=float)
    x2 = np.asarray(x2_values, dtype=float)
    x3 = np.asarray(x3_values, dtype=float)
    return np.column_stack(
        [
            np.ones_like(x1),
            x1,
            x2,
            x3,
            x1**2,
            x2**2,
            x3**2,
            x1 * x2,
            x1 * x3,
            x2 * x3,
        ]
    )


def _td_perf_surface_normalize_control_period(values, *, center: float | None = None, scale: float | None = None):
    np = _td_perf_import_numpy()
    arr = np.asarray([float(v) for v in values], dtype=float)
    cp_center = float(np.mean(arr)) if center is None else float(center)
    cp_scale = (float(np.std(arr)) or 1.0) if scale is None else (float(scale) or 1.0)
    return (arr - cp_center) / cp_scale, cp_center, cp_scale


def _td_perf_surface_control_period_coeffs(model: Mapping[str, object], control_period, count: int):
    np = _td_perf_import_numpy()
    if count <= 0:
        return np.asarray([], dtype=float).reshape(0, 0)
    if control_period is None:
        raise ValueError("Control-period-aware surface prediction requires control_period.")
    if isinstance(control_period, Iterable) and not isinstance(control_period, (str, bytes)):
        cp_values = [float(v) for v in control_period]
        if len(cp_values) != count:
            raise ValueError("control_period iterable length must match x1/x2 inputs.")
    else:
        cp_values = [float(control_period)] * count
    cp_norm, _cp_center, _cp_scale = _td_perf_surface_normalize_control_period(
        cp_values,
        center=float(model.get("cp_center") or 0.0),
        scale=float(model.get("cp_scale") or 1.0),
    )
    coeff_cp_models = [np.asarray([float(v) for v in coeffs], dtype=float) for coeffs in (model.get("coeff_cp_models") or [])]
    if not coeff_cp_models:
        return np.asarray([], dtype=float).reshape(0, 0)
    coeff_matrix = []
    for coeffs in coeff_cp_models:
        coeff_matrix.append(np.poly1d(coeffs)(cp_norm))
    return np.vstack(coeff_matrix).T


def _td_perf_predict_quadratic_3input_control_period(
    model: Mapping[str, object],
    x1_values: Iterable[float],
    x2_values: Iterable[float],
    x3_values: Iterable[float],
    control_period,
) -> list[float]:
    np = _td_perf_import_numpy()
    x1_list = [float(v) for v in x1_values]
    x2_list = [float(v) for v in x2_values]
    x3_list = [float(v) for v in x3_values]
    if not x1_list or len(x1_list) != len(x2_list) or len(x1_list) != len(x3_list):
        return []
    x1n, x2n, x3n, _x1_center, _x1_scale, _x2_center, _x2_scale, _x3_center, _x3_scale = _td_perf_surface_normalize_three_axes(
        x1_list,
        x2_list,
        x3_list,
        centers=(
            float(model.get("x1_center") or 0.0),
            float(model.get("x2_center") or 0.0),
            float(model.get("x3_center") or 0.0),
        ),
        scales=(
            float(model.get("x1_scale") or 1.0),
            float(model.get("x2_scale") or 1.0),
            float(model.get("x3_scale") or 1.0),
        ),
    )
    design = _td_perf_three_input_design_matrix(x1n, x2n, x3n)
    coeff_matrix = _td_perf_surface_control_period_coeffs(model, control_period, len(x1_list))
    if coeff_matrix.size <= 0 or coeff_matrix.shape[1] != int(design.shape[1]):
        return []
    y_hat = np.sum(design * coeff_matrix, axis=1)
    return [float(v) for v in y_hat.tolist()]


def _td_perf_predict_quadratic_3input(
    model: Mapping[str, object],
    x1_values: Iterable[float],
    x2_values: Iterable[float],
    x3_values: Iterable[float],
) -> list[float]:
    np = _td_perf_import_numpy()
    coeffs = [float(v) for v in (model.get("coeffs") or [])]
    x1_list = [float(v) for v in x1_values]
    x2_list = [float(v) for v in x2_values]
    x3_list = [float(v) for v in x3_values]
    if len(coeffs) != 10 or not x1_list or len(x1_list) != len(x2_list) or len(x1_list) != len(x3_list):
        return []
    x1n, x2n, x3n, _x1_center, _x1_scale, _x2_center, _x2_scale, _x3_center, _x3_scale = _td_perf_surface_normalize_three_axes(
        x1_list,
        x2_list,
        x3_list,
        centers=(
            float(model.get("x1_center") or 0.0),
            float(model.get("x2_center") or 0.0),
            float(model.get("x3_center") or 0.0),
        ),
        scales=(
            float(model.get("x1_scale") or 1.0),
            float(model.get("x2_scale") or 1.0),
            float(model.get("x3_scale") or 1.0),
        ),
    )
    design = _td_perf_three_input_design_matrix(x1n, x2n, x3n)
    y_hat = design.dot(np.asarray(coeffs, dtype=float))
    return [float(v) for v in y_hat.tolist()]


def td_perf_predict_surface(
    model: Mapping[str, object],
    x1_values: Iterable[float],
    x2_values: Iterable[float],
    *,
    control_period: object = None,
) -> list[float]:
    np = _td_perf_import_numpy()
    family = td_perf_normalize_fit_mode(model.get("fit_family"))
    coeffs = [float(v) for v in (model.get("coeffs") or [])]
    if family == TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE_CONTROL_PERIOD:
        x1_list = [float(v) for v in x1_values]
        x2_list = [float(v) for v in x2_values]
        if len(x1_list) != len(x2_list) or not x1_list:
            return []
        x1n, x2n, _x1_center, _x1_scale, _x2_center, _x2_scale = _td_perf_surface_normalize_axes(
            x1_list,
            x2_list,
            centers=(float(model.get("x1_center") or 0.0), float(model.get("x2_center") or 0.0)),
            scales=(float(model.get("x1_scale") or 1.0), float(model.get("x2_scale") or 1.0)),
        )
        design = _td_perf_surface_design_matrix(x1n, x2n, TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE)
        coeff_matrix = _td_perf_surface_control_period_coeffs(model, control_period, len(x1_list))
        if coeff_matrix.size <= 0:
            return []
        y_hat = np.sum(design * coeff_matrix, axis=1)
        return [float(v) for v in y_hat.tolist()]
    if family not in {TD_PERF_FIT_FAMILY_PLANE, TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE} or not coeffs:
        return []
    x1n, x2n, _x1_center, _x1_scale, _x2_center, _x2_scale = _td_perf_surface_normalize_axes(
        list(x1_values),
        list(x2_values),
        centers=(float(model.get("x1_center") or 0.0), float(model.get("x2_center") or 0.0)),
        scales=(float(model.get("x1_scale") or 1.0), float(model.get("x2_scale") or 1.0)),
    )
    design = _td_perf_surface_design_matrix(x1n, x2n, family)
    y_hat = design.dot(np.asarray(coeffs, dtype=float))
    return [float(v) for v in y_hat.tolist()]


def td_perf_build_surface_grid(
    model: Mapping[str, object],
    x1_min: float,
    x1_max: float,
    x2_min: float,
    x2_max: float,
    *,
    points: int = 24,
    control_period: object = None,
) -> dict[str, list[list[float]]]:
    np = _td_perf_import_numpy()
    if not all(math.isfinite(float(v)) for v in (x1_min, x1_max, x2_min, x2_max)):
        return {"x1_grid": [], "x2_grid": [], "z_grid": []}
    if (
        td_perf_normalize_fit_mode(model.get("fit_family")) == TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE_CONTROL_PERIOD
        and control_period not in (None, "")
        and not _td_perf_surface_control_period_in_domain(model, control_period)
    ):
        return {"x1_grid": [], "x2_grid": [], "z_grid": []}
    xs = np.linspace(float(x1_min), float(x1_max), max(2, int(points)))
    ys = np.linspace(float(x2_min), float(x2_max), max(2, int(points)))
    xg, yg = np.meshgrid(xs, ys)
    zg = td_perf_predict_surface(model, xg.ravel().tolist(), yg.ravel().tolist(), control_period=control_period)
    if not zg:
        return {"x1_grid": [], "x2_grid": [], "z_grid": []}
    zg_arr = np.asarray(zg, dtype=float).reshape(xg.shape)
    return {
        "x1_grid": [[float(v) for v in row] for row in xg.tolist()],
        "x2_grid": [[float(v) for v in row] for row in yg.tolist()],
        "z_grid": [[float(v) for v in row] for row in zg_arr.tolist()],
    }


def td_perf_build_fit_curve(model: Mapping[str, object], x_min: float, x_max: float, *, points: int = 220) -> dict[str, list[float]]:
    np = _td_perf_import_numpy()
    if not math.isfinite(float(x_min)) or not math.isfinite(float(x_max)):
        return {"xfit": [], "yfit": []}
    if float(x_min) == float(x_max):
        xs = np.asarray([float(x_min)], dtype=float)
    else:
        xs = np.linspace(float(x_min), float(x_max), max(2, int(points)))
    ys = td_perf_predict_model(model, xs.tolist())
    return {"xfit": [float(v) for v in xs.tolist()], "yfit": [float(v) for v in ys]}


def _td_perf_finalize_model(
    *,
    fit_family: str,
    fit_mode: str,
    equation: str,
    x_norm_equation: str,
    params: dict[str, object],
    param_count: int,
    x_values,
    y_true,
    y_hat,
    complexity_penalty: float = 0.0,
    composite_score: bool = True,
    extra: dict[str, object] | None = None,
) -> dict[str, object]:
    np = _td_perf_import_numpy()
    x_arr = np.asarray(x_values, dtype=float)
    y_true_arr = np.asarray(y_true, dtype=float)
    y_hat_arr = np.asarray(y_hat, dtype=float)
    rmse = float(np.sqrt(np.mean((y_true_arr - y_hat_arr) ** 2)))
    aic, aicc = _td_perf_aic_metrics(y_true_arr, y_hat_arr, param_count=param_count)
    global_rmse_norm = _td_perf_normalized_rmse(y_true_arr, y_hat_arr)
    edge_rmse_norm = _td_perf_edge_rmse_norm(x_arr, y_true_arr, y_hat_arr) if composite_score else global_rmse_norm
    monotonic_violations = _td_perf_monotonic_violations(x_arr, y_hat_arr)
    monotonicity_penalty = 0.5 * float(monotonic_violations) if composite_score else 0.0
    score = (
        float(global_rmse_norm + (1.5 * edge_rmse_norm) + monotonicity_penalty + float(complexity_penalty))
        if composite_score
        else float(aicc if math.isfinite(aicc) else aic)
    )
    model = {
        "fit_family": fit_family,
        "fit_mode": fit_mode,
        "equation": equation,
        "x_norm_equation": x_norm_equation,
        "params": dict(params),
        "param_count": int(param_count),
        "rmse": rmse,
        "aic": float(aic),
        "aicc": float(aicc),
        "score": score,
        "global_rmse_norm": float(global_rmse_norm),
        "edge_rmse_norm": float(edge_rmse_norm),
        "complexity_penalty": float(complexity_penalty),
        "monotonicity_penalty": float(monotonicity_penalty),
        "monotonic_violations": monotonic_violations,
        "warnings": [],
    }
    if extra:
        model.update(extra)
    return model


def _td_perf_fit_polynomial_model(
    xs: list[float],
    ys: list[float],
    *,
    degree: int,
    normalize_x: bool,
    fit_mode: str,
    sample_weights: Sequence[float] | None = None,
) -> dict[str, object] | None:
    np = _td_perf_import_numpy()
    deg = int(degree)
    if deg <= 0 or len(xs) < max(2, deg + 1):
        return None
    prepared = _td_perf_prepare_xy(xs, ys)
    if prepared[0] is None:
        return None
    x_arr, y_arr, order = prepared
    assert order is not None
    weights_in = _td_perf_prepare_sample_weights(xs, sample_weights)
    if weights_in is None:
        return None
    weights = [float(weights_in[idx]) for idx in order.tolist()]
    if normalize_x:
        x0 = float(np.mean(x_arr))
        sx = float(np.std(x_arr)) or 1.0
        xn = (x_arr - x0) / sx
    else:
        x0 = 0.0
        sx = 1.0
        xn = x_arr
    design = np.vander(xn, deg + 1, increasing=False)
    coeffs, _residuals, rank, _singular = _td_perf_weighted_lstsq(design, y_arr, weights)
    if int(rank) < int(design.shape[1]):
        return None
    coeffs = [float(v) for v in coeffs.tolist()]
    y_hat = design.dot(np.asarray(coeffs, dtype=float))
    equation, x_norm_equation = _td_perf_fmt_poly_equation(
        coeffs,
        deg,
        x0=(x0 if normalize_x else None),
        sx=(sx if normalize_x else None),
    )
    return _td_perf_finalize_model(
        fit_family=TD_PERF_FIT_MODE_POLYNOMIAL,
        fit_mode=fit_mode,
        equation=equation,
        x_norm_equation=x_norm_equation,
        params={"degree": float(deg)},
        param_count=len(coeffs),
        x_values=x_arr,
        y_true=y_arr,
        y_hat=y_hat,
        complexity_penalty=TD_PERF_FIT_COMPLEXITY_PENALTIES[TD_PERF_FIT_MODE_POLYNOMIAL],
        extra={
            "degree": deg,
            "coeffs": coeffs,
            "x0": x0,
            "sx": sx,
            "normalize_x": bool(normalize_x),
            "fit_domain": [float(x_arr[0]), float(x_arr[-1])],
            "sample_weights_used": [float(v) for v in weights],
        },
    )


def _td_perf_fit_logarithmic_model(
    xs: list[float],
    ys: list[float],
    *,
    fit_mode: str,
    sample_weights: Sequence[float] | None = None,
) -> dict[str, object] | None:
    np = _td_perf_import_numpy()
    curve_fit = _td_perf_import_curve_fit()
    prepared = _td_perf_prepare_xy(xs, ys)
    if prepared[0] is None:
        return None
    x_arr, y_arr, order = prepared
    assert order is not None
    if len(x_arr) < 2 or np.any(x_arr <= 0):
        return None
    weights_in = _td_perf_prepare_sample_weights(xs, sample_weights)
    if weights_in is None:
        return None
    ordered_weights = [float(weights_in[idx]) for idx in order.tolist()]

    def _fn(x, a, b):
        return a + (b * np.log(x))

    log_x = np.log(x_arr)
    denom = float(np.max(log_x) - np.min(log_x)) or 1.0
    a0 = float(np.mean(y_arr))
    b0 = float((y_arr[-1] - y_arr[0]) / denom)
    params, _cov = curve_fit(
        _fn,
        x_arr,
        y_arr,
        p0=[a0, b0],
        sigma=_td_perf_curve_fit_sigma(ordered_weights),
        absolute_sigma=False,
        maxfev=20000,
    )
    a, b = [float(v) for v in params]
    y_hat = _fn(x_arr, a, b)
    return _td_perf_finalize_model(
        fit_family=TD_PERF_FIT_MODE_LOGARITHMIC,
        fit_mode=fit_mode,
        equation=f"y = {_td_perf_fmt_num(a)} {float(b):+.4g}*ln(x)",
        x_norm_equation="",
        params={"a": a, "b": b},
        param_count=2,
        x_values=x_arr,
        y_true=y_arr,
        y_hat=y_hat,
        complexity_penalty=TD_PERF_FIT_COMPLEXITY_PENALTIES[TD_PERF_FIT_MODE_LOGARITHMIC],
        extra={
            "fit_domain": [float(x_arr[0]), float(x_arr[-1])],
            "sample_weights_used": [float(v) for v in ordered_weights],
        },
    )


def _td_perf_fit_saturating_exponential_model(
    xs: list[float],
    ys: list[float],
    *,
    fit_mode: str,
    sample_weights: Sequence[float] | None = None,
) -> dict[str, object] | None:
    np = _td_perf_import_numpy()
    curve_fit = _td_perf_import_curve_fit()
    prepared = _td_perf_prepare_xy(xs, ys)
    if prepared[0] is None:
        return None
    x_arr, y_arr, order = prepared
    assert order is not None
    if len(x_arr) < 3:
        return None
    weights_in = _td_perf_prepare_sample_weights(xs, sample_weights)
    if weights_in is None:
        return None
    ordered_weights = [float(weights_in[idx]) for idx in order.tolist()]

    def _fn(x, L, A, k):
        return L - (A * np.exp(-k * x))

    ymax = float(np.max(y_arr))
    ymin = float(np.min(y_arr))
    x_span = max(float(np.max(x_arr) - np.min(x_arr)), 1e-6)
    L0 = max(ymax + max(abs(ymax) * 0.05, 1e-3), ymax + 1e-3)
    A0 = max(L0 - ymin, 1e-3)
    k0 = max(1.0 / x_span, 1e-6)
    params, _cov = curve_fit(
        _fn,
        x_arr,
        y_arr,
        p0=[L0, A0, k0],
        bounds=([ymax, 0.0, 0.0], [float("inf"), float("inf"), float("inf")]),
        sigma=_td_perf_curve_fit_sigma(ordered_weights),
        absolute_sigma=False,
        maxfev=40000,
    )
    L, A, k = [float(v) for v in params]
    if L < ymax or A <= 0.0 or k <= 0.0:
        return None
    y_hat = _fn(x_arr, L, A, k)
    model = _td_perf_finalize_model(
        fit_family=TD_PERF_FIT_MODE_SATURATING_EXPONENTIAL,
        fit_mode=fit_mode,
        equation=f"y = {_td_perf_fmt_num(L)} - {_td_perf_fmt_num(A)}*exp(-{_td_perf_fmt_num(k)}*x)",
        x_norm_equation="",
        params={"L": L, "A": A, "k": k},
        param_count=3,
        x_values=x_arr,
        y_true=y_arr,
        y_hat=y_hat,
        complexity_penalty=TD_PERF_FIT_COMPLEXITY_PENALTIES[TD_PERF_FIT_MODE_SATURATING_EXPONENTIAL],
        extra={
            "fit_domain": [float(x_arr[0]), float(x_arr[-1])],
            "sample_weights_used": [float(v) for v in ordered_weights],
        },
    )
    model["monotonic_violations"] = 0
    model["monotonicity_penalty"] = 0.0
    return model


def _td_perf_fit_hybrid_saturating_linear_model(
    xs: list[float],
    ys: list[float],
    *,
    fit_mode: str,
    sample_weights: Sequence[float] | None = None,
) -> dict[str, object] | None:
    np = _td_perf_import_numpy()
    curve_fit = _td_perf_import_curve_fit()
    prepared = _td_perf_prepare_xy(xs, ys)
    if prepared[0] is None:
        return None
    x_arr, y_arr, order = prepared
    assert order is not None
    if len(x_arr) < 4:
        return None
    weights_in = _td_perf_prepare_sample_weights(xs, sample_weights)
    if weights_in is None:
        return None
    ordered_weights = [float(weights_in[idx]) for idx in order.tolist()]

    def _fn(x, b, m, A, k):
        return b + (m * x) + (A * (1.0 - np.exp(-k * x)))

    x_span = max(float(np.max(x_arr) - np.min(x_arr)), 1e-6)
    ymin = float(np.min(y_arr))
    ymax = float(np.max(y_arr))
    m0 = _td_perf_tail_slope_seed(x_arr, y_arr)
    b0 = float(y_arr[0] - (m0 * x_arr[0]))
    A0 = max((ymax - ymin) - (m0 * x_span), 1e-3)
    k0 = max(1.0 / x_span, 1e-6)
    params, _cov = curve_fit(
        _fn,
        x_arr,
        y_arr,
        p0=[b0, m0, A0, k0],
        bounds=([-float("inf"), 0.0, 0.0, 0.0], [float("inf"), float("inf"), float("inf"), float("inf")]),
        sigma=_td_perf_curve_fit_sigma(ordered_weights),
        absolute_sigma=False,
        maxfev=50000,
    )
    b, m, A, k = [float(v) for v in params]
    if m < 0.0 or A < 0.0 or k < 0.0:
        return None
    y_hat = _fn(x_arr, b, m, A, k)
    model = _td_perf_finalize_model(
        fit_family=TD_PERF_FIT_MODE_HYBRID_SATURATING_LINEAR,
        fit_mode=fit_mode,
        equation=(
            f"y = {_td_perf_fmt_num(b)} + {_td_perf_fmt_num(m)}*x + "
            f"{_td_perf_fmt_num(A)}*(1 - exp(-{_td_perf_fmt_num(k)}*x))"
        ),
        x_norm_equation="",
        params={"b": b, "m": m, "A": A, "k": k},
        param_count=4,
        x_values=x_arr,
        y_true=y_arr,
        y_hat=y_hat,
        complexity_penalty=TD_PERF_FIT_COMPLEXITY_PENALTIES[TD_PERF_FIT_MODE_HYBRID_SATURATING_LINEAR],
        extra={
            "fit_domain": [float(x_arr[0]), float(x_arr[-1])],
            "sample_weights_used": [float(v) for v in ordered_weights],
        },
    )
    model["monotonic_violations"] = 0
    model["monotonicity_penalty"] = 0.0
    return model


def _td_perf_fit_hybrid_quadratic_residual_model(
    xs: list[float],
    ys: list[float],
    *,
    fit_mode: str,
    normalize_x: bool,
    sample_weights: Sequence[float] | None = None,
) -> dict[str, object] | None:
    np = _td_perf_import_numpy()
    base_model = _td_perf_fit_hybrid_saturating_linear_model(xs, ys, fit_mode=fit_mode, sample_weights=sample_weights)
    if not isinstance(base_model, dict):
        return None
    prepared = _td_perf_prepare_xy(xs, ys)
    if prepared[0] is None:
        return None
    x_arr, y_arr, order = prepared
    assert order is not None
    weights_in = _td_perf_prepare_sample_weights(xs, sample_weights)
    if weights_in is None:
        return None
    weights = [float(weights_in[idx]) for idx in order.tolist()]
    base_pred = np.asarray(td_perf_predict_model(base_model, x_arr.tolist()), dtype=float)
    residuals = y_arr - base_pred
    if normalize_x:
        x0 = float(np.mean(x_arr))
        sx = float(np.std(x_arr)) or 1.0
        xn = (x_arr - x0) / sx
    else:
        x0 = 0.0
        sx = 1.0
        xn = x_arr
    design = np.vander(xn, 3, increasing=False)
    coeffs, _residuals, rank, _singular = _td_perf_weighted_lstsq(design, residuals, weights)
    if int(rank) < int(design.shape[1]):
        return None
    residual_coeffs = [float(v) for v in coeffs.tolist()]
    residual_hat = design.dot(np.asarray(residual_coeffs, dtype=float))
    y_hat = base_pred + residual_hat
    residual_eq, residual_norm_eq = _td_perf_fmt_poly_equation(
        residual_coeffs,
        2,
        x0=(x0 if normalize_x else None),
        sx=(sx if normalize_x else None),
    )
    base_params = dict(base_model.get("params") or {})
    return _td_perf_finalize_model(
        fit_family=TD_PERF_FIT_MODE_HYBRID_QUADRATIC_RESIDUAL,
        fit_mode=fit_mode,
        equation=(
            f"{str(base_model.get('equation') or '').strip()} ; residual: {residual_eq or 'y = 0'}"
        ),
        x_norm_equation=residual_norm_eq or str(base_model.get("x_norm_equation") or ""),
        params={
            "base_model_family": TD_PERF_FIT_MODE_HYBRID_SATURATING_LINEAR,
            "base_params": base_params,
            "residual_coeffs": residual_coeffs,
            "normalize_x": bool(normalize_x),
            "x0": float(x0),
            "sx": float(sx),
        },
        param_count=7,
        x_values=x_arr,
        y_true=y_arr,
        y_hat=y_hat,
        complexity_penalty=TD_PERF_FIT_COMPLEXITY_PENALTIES[TD_PERF_FIT_MODE_HYBRID_QUADRATIC_RESIDUAL],
        extra={
            "base_model": {
                "fit_family": TD_PERF_FIT_MODE_HYBRID_SATURATING_LINEAR,
                "fit_mode": fit_mode,
                "params": base_params,
                "equation": str(base_model.get("equation") or ""),
            },
            "residual_coeffs": residual_coeffs,
            "x0": float(x0),
            "sx": float(sx),
            "normalize_x": bool(normalize_x),
            "fit_domain": [float(x_arr[0]), float(x_arr[-1])],
            "sample_weights_used": [float(v) for v in weights],
        },
    )


def _td_perf_fit_monotone_pchip_model(
    xs: list[float],
    ys: list[float],
    *,
    fit_mode: str,
    sample_weights: Sequence[float] | None = None,
) -> dict[str, object] | None:
    np = _td_perf_import_numpy()
    PchipInterpolator = _td_perf_import_pchip()
    prepared = _td_perf_prepare_xy(xs, ys)
    if prepared[0] is None:
        return None
    x_arr, y_arr, order = prepared
    assert order is not None
    unique_x, unique_y = _td_perf_group_duplicate_xy(x_arr.tolist(), y_arr.tolist())
    if len(unique_x) < 2:
        return None
    weights_in = _td_perf_prepare_sample_weights(xs, sample_weights)
    if weights_in is None:
        return None
    ordered_weights = [float(weights_in[idx]) for idx in order.tolist()]
    interpolator = PchipInterpolator(unique_x, unique_y, extrapolate=False)
    y_hat = interpolator(x_arr)
    if np.any(~np.isfinite(y_hat)):
        return None
    return _td_perf_finalize_model(
        fit_family=TD_PERF_FIT_MODE_MONOTONE_PCHIP,
        fit_mode=fit_mode,
        equation=f"PCHIP knot fit ({len(unique_x)} knots, clamped outside observed domain)",
        x_norm_equation="",
        params={
            "knots": [float(v) for v in unique_x],
            "knot_values": [float(v) for v in unique_y],
            "left_y": float(unique_y[0]),
            "right_y": float(unique_y[-1]),
        },
        param_count=len(unique_x),
        x_values=x_arr,
        y_true=y_arr,
        y_hat=y_hat,
        complexity_penalty=TD_PERF_FIT_COMPLEXITY_PENALTIES[TD_PERF_FIT_MODE_MONOTONE_PCHIP],
        extra={
            "fit_domain": [float(unique_x[0]), float(unique_x[-1])],
            "sample_weights_used": [float(v) for v in ordered_weights],
        },
    )


def _td_perf_choose_best_model(models: list[dict[str, object]]) -> dict[str, object] | None:
    viable = [m for m in models if isinstance(m, dict)]
    if not viable:
        return None
    best_score = min(_td_perf_model_score_value(m) for m in viable)
    tied = [m for m in viable if _td_perf_model_score_value(m) <= (best_score + 0.05)]
    tied.sort(
        key=lambda m: (
            _td_perf_model_score_value(m),
            int(m.get("monotonic_violations") or 99),
            *_td_perf_parametric_aic_key(m),
            float(m.get("rmse") or float("inf")),
            int(TD_PERF_FIT_FAMILY_PRIORITY.get(str(m.get("fit_family") or "").strip().lower(), 99)),
        )
    )
    return tied[0] if tied else None


def td_perf_fit_model(
    xs: list[float],
    ys: list[float],
    *,
    fit_mode: object = None,
    polynomial_degree: int = 2,
    normalize_x: bool = True,
    sample_weights: list[float] | None = None,
) -> dict[str, object] | None:
    mode = td_perf_normalize_fit_mode(fit_mode)
    if len(xs) != len(ys) or len(xs) < 2:
        return None
    if mode in {
        TD_PERF_FIT_MODE_AUTO,
        TD_PERF_FIT_MODE_LOGARITHMIC,
        TD_PERF_FIT_MODE_SATURATING_EXPONENTIAL,
        TD_PERF_FIT_MODE_HYBRID_SATURATING_LINEAR,
        TD_PERF_FIT_MODE_HYBRID_QUADRATIC_RESIDUAL,
        TD_PERF_FIT_MODE_MONOTONE_PCHIP,
    }:
        _td_perf_import_curve_fit()
    if mode == TD_PERF_FIT_MODE_POLYNOMIAL:
        return _td_perf_fit_polynomial_model(
            xs,
            ys,
            degree=polynomial_degree,
            normalize_x=normalize_x,
            fit_mode=mode,
            sample_weights=sample_weights,
        )
    if mode == TD_PERF_FIT_MODE_LOGARITHMIC:
        return _td_perf_fit_logarithmic_model(xs, ys, fit_mode=mode, sample_weights=sample_weights)
    if mode == TD_PERF_FIT_MODE_SATURATING_EXPONENTIAL:
        return _td_perf_fit_saturating_exponential_model(xs, ys, fit_mode=mode, sample_weights=sample_weights)
    if mode == TD_PERF_FIT_MODE_HYBRID_SATURATING_LINEAR:
        return _td_perf_fit_hybrid_saturating_linear_model(xs, ys, fit_mode=mode, sample_weights=sample_weights)
    if mode == TD_PERF_FIT_MODE_HYBRID_QUADRATIC_RESIDUAL:
        return _td_perf_fit_hybrid_quadratic_residual_model(
            xs,
            ys,
            fit_mode=mode,
            normalize_x=normalize_x,
            sample_weights=sample_weights,
        )
    if mode == TD_PERF_FIT_MODE_MONOTONE_PCHIP:
        return _td_perf_fit_monotone_pchip_model(xs, ys, fit_mode=mode, sample_weights=sample_weights)
    if mode == TD_PERF_FIT_MODE_PIECEWISE_2:
        return _td_perf_fit_piecewise_model(xs, ys, segment_count=2, fit_mode=mode, sample_weights=sample_weights)
    if mode == TD_PERF_FIT_MODE_PIECEWISE_3:
        return _td_perf_fit_piecewise_model(xs, ys, segment_count=3, fit_mode=mode, sample_weights=sample_weights)
    if mode == TD_PERF_FIT_MODE_PIECEWISE_AUTO:
        return _td_perf_choose_best_model(
            [
                c
                for c in (
                    _td_perf_fit_piecewise_model(xs, ys, segment_count=2, fit_mode=mode, sample_weights=sample_weights),
                    _td_perf_fit_piecewise_model(xs, ys, segment_count=3, fit_mode=mode, sample_weights=sample_weights),
                )
                if isinstance(c, dict)
            ]
        )
    candidates = [
        _td_perf_fit_polynomial_model(
            xs,
            ys,
            degree=polynomial_degree,
            normalize_x=normalize_x,
            fit_mode=mode,
            sample_weights=sample_weights,
        ),
        _td_perf_fit_logarithmic_model(xs, ys, fit_mode=mode, sample_weights=sample_weights),
        _td_perf_fit_saturating_exponential_model(xs, ys, fit_mode=mode, sample_weights=sample_weights),
        _td_perf_fit_hybrid_saturating_linear_model(xs, ys, fit_mode=mode, sample_weights=sample_weights),
        _td_perf_fit_hybrid_quadratic_residual_model(
            xs,
            ys,
            fit_mode=mode,
            normalize_x=normalize_x,
            sample_weights=sample_weights,
        ),
        _td_perf_fit_monotone_pchip_model(xs, ys, fit_mode=mode, sample_weights=sample_weights),
        _td_perf_fit_piecewise_model(xs, ys, segment_count=2, fit_mode=mode, sample_weights=sample_weights),
        _td_perf_fit_piecewise_model(xs, ys, segment_count=3, fit_mode=mode, sample_weights=sample_weights),
    ]
    return _td_perf_choose_best_model([c for c in candidates if isinstance(c, dict)])


def _td_perf_excel_num(value: object) -> str:
    try:
        out = float(value)
    except Exception:
        return "0"
    if not math.isfinite(out):
        return "0"
    return format(out, ".15g")


def _td_perf_excel_ref(column_index: int, row_index: int, *, absolute: bool = False) -> str:
    try:
        from openpyxl.utils import get_column_letter  # type: ignore
    except Exception as exc:  # pragma: no cover - optional dep guard
        raise RuntimeError(
            "openpyxl is required to export performance equations to Excel. "
            "Install it with `py -m pip install openpyxl` within the project environment."
        ) from exc
    col = get_column_letter(int(column_index))
    if absolute:
        return f"${col}${int(row_index)}"
    return f"{col}{int(row_index)}"


def _td_perf_export_series_for_stat(
    db_path: Path,
    run_name: str,
    column_name: str,
    stat: str,
    *,
    control_period_filter: object = None,
    run_type_filter: object = None,
) -> list[dict]:
    st = str(stat or "").strip().lower()
    if not st:
        return []
    if st in {"min_3sigma", "max_3sigma"}:
        mean_rows = td_load_metric_series(
            db_path,
            run_name,
            column_name,
            "mean",
            control_period_filter=control_period_filter,
            run_type_filter=run_type_filter,
        )
        std_rows = td_load_metric_series(
            db_path,
            run_name,
            column_name,
            "std",
            control_period_filter=control_period_filter,
            run_type_filter=run_type_filter,
        )
        mean_by_obs = {
            str(row.get("observation_id") or "").strip(): dict(row)
            for row in mean_rows
            if isinstance(row, dict) and str(row.get("observation_id") or "").strip()
        }
        std_by_obs = {
            str(row.get("observation_id") or "").strip(): dict(row)
            for row in std_rows
            if isinstance(row, dict) and str(row.get("observation_id") or "").strip()
        }
        out: list[dict] = []
        for obs_id in sorted(set(mean_by_obs.keys()) | set(std_by_obs.keys())):
            mean_row = mean_by_obs.get(obs_id) or {}
            std_row = std_by_obs.get(obs_id) or {}
            value = td_perf_mean_3sigma_value(
                {
                    "mean": mean_row.get("value_num"),
                    "std": std_row.get("value_num"),
                },
                st,
            )
            if value is None:
                continue
            base_row = dict(mean_row or std_row)
            base_row["value_num"] = float(value)
            out.append(base_row)
        return out
    return td_load_metric_series(
        db_path,
        run_name,
        column_name,
        st,
        control_period_filter=control_period_filter,
        run_type_filter=run_type_filter,
    )


def _td_perf_export_condition_label(row: Mapping[str, object], *, display_name: str = "") -> str:
    parts: list[str] = []
    for candidate in (display_name, row.get("program_title"), row.get("source_run_name")):
        text = str(candidate or "").strip()
        if text and text not in parts:
            parts.append(text)
    if parts:
        return " | ".join(parts)
    return str(row.get("run_name") or "").strip()


def _td_perf_join_unique_text(values: Sequence[object]) -> str:
    out: list[str] = []
    seen: set[str] = set()
    for value in values:
        text = str(value or "").strip()
        if not text:
            continue
        key = text.lower()
        if key in seen:
            continue
        seen.add(key)
        out.append(text)
    return ", ".join(out)


def _td_perf_unique_run_specs(run_specs: Sequence[Mapping[str, object]]) -> list[dict[str, object]]:
    unique: list[dict[str, object]] = []
    seen: set[tuple[str, str, str, str]] = set()
    for raw_spec in run_specs or []:
        if not isinstance(raw_spec, Mapping):
            continue
        spec = dict(raw_spec)
        key = tuple(
            str(spec.get(name) or "").strip().lower()
            for name in ("run_name", "input1_column", "input2_column", "output_column")
        )
        if not key[0] or key in seen:
            continue
        seen.add(key)
        unique.append(spec)
    return unique


def _td_perf_control_period_cluster_key(value: object) -> tuple[str, object]:
    try:
        num = float(value)
    except Exception:
        return ("text", str(value or "").strip().lower())
    if not math.isfinite(num):
        return ("text", str(value or "").strip().lower())
    return ("num", round(float(num), 9))


def _td_perf_cluster_points_3d(
    points: list[dict[str, object]],
    *,
    rel_tol: float,
    abs_tol: float,
) -> list[dict[str, object]]:
    ordered: list[dict[str, object]] = []
    for point in sorted(
        points,
        key=lambda item: (
            float(item.get("x1") or 0.0),
            float(item.get("x2") or 0.0),
            _td_perf_control_period_cluster_key(item.get("control_period")),
            str(item.get("source_run_name") or "").lower(),
            str(item.get("observation_id") or "").lower(),
        ),
    ):
        try:
            x1 = float(point.get("x1"))
            x2 = float(point.get("x2"))
        except Exception:
            continue
        if not (math.isfinite(x1) and math.isfinite(x2)):
            continue
        copy = dict(point)
        copy["x1"] = x1
        copy["x2"] = x2
        copy["_cp_key"] = _td_perf_control_period_cluster_key(point.get("control_period"))
        ordered.append(copy)
    if not ordered:
        return []

    clusters: list[dict[str, object]] = []
    for point in ordered:
        x1 = float(point["x1"])
        x2 = float(point["x2"])
        if not clusters:
            clusters.append(
                {
                    "x1_center": x1,
                    "x2_center": x2,
                    "points": [point],
                    "_cp_key": point.get("_cp_key"),
                    "_x1_sum": x1,
                    "_x2_sum": x2,
                    "_point_count": 1,
                }
            )
            continue
        cluster = clusters[-1]
        if cluster.get("_cp_key") != point.get("_cp_key"):
            clusters.append(
                {
                    "x1_center": x1,
                    "x2_center": x2,
                    "points": [point],
                    "_cp_key": point.get("_cp_key"),
                    "_x1_sum": x1,
                    "_x2_sum": x2,
                    "_point_count": 1,
                }
            )
            continue
        ref_x1 = float(cluster.get("x1_center") or x1)
        ref_x2 = float(cluster.get("x2_center") or x2)
        tol_x1 = max(float(abs_tol), float(rel_tol) * max(abs(ref_x1), abs(x1)))
        tol_x2 = max(float(abs_tol), float(rel_tol) * max(abs(ref_x2), abs(x2)))
        if abs(x1 - ref_x1) <= tol_x1 and abs(x2 - ref_x2) <= tol_x2:
            pts = cluster.get("points")
            if not isinstance(pts, list):
                pts = []
                cluster["points"] = pts
            pts.append(point)
            point_count = int(cluster.get("_point_count") or 0) + 1
            x1_sum = float(cluster.get("_x1_sum") or 0.0) + x1
            x2_sum = float(cluster.get("_x2_sum") or 0.0) + x2
            cluster["_point_count"] = point_count
            cluster["_x1_sum"] = x1_sum
            cluster["_x2_sum"] = x2_sum
            cluster["x1_center"] = float(x1_sum / max(1, point_count))
            cluster["x2_center"] = float(x2_sum / max(1, point_count))
            continue
        clusters.append(
            {
                "x1_center": x1,
                "x2_center": x2,
                "points": [point],
                "_cp_key": point.get("_cp_key"),
                "_x1_sum": x1,
                "_x2_sum": x2,
                "_point_count": 1,
            }
        )
    return [
        {k: v for k, v in cluster.items() if not str(k).startswith("_") or str(k) == "_cp_key"}
        for cluster in clusters
    ]

def _td_perf_fit_surface_family(
    x1s: list[float],
    x2s: list[float],
    ys: list[float],
    *,
    family: str,
    fit_mode: str,
) -> dict[str, object] | None:
    np = _td_perf_import_numpy()
    if len(x1s) != len(x2s) or len(x1s) != len(ys):
        return None
    x1_arr = np.asarray([float(v) for v in x1s], dtype=float)
    x2_arr = np.asarray([float(v) for v in x2s], dtype=float)
    y_arr = np.asarray([float(v) for v in ys], dtype=float)
    if len(x1_arr) < 3:
        return None
    if len({round(float(v), 12) for v in x1_arr.tolist()}) < 2:
        return None
    if len({round(float(v), 12) for v in x2_arr.tolist()}) < 2:
        return None
    x1n, x2n, x1_center, x1_scale, x2_center, x2_scale = _td_perf_surface_normalize_axes(x1_arr, x2_arr)
    design = _td_perf_surface_design_matrix(x1n, x2n, family)
    term_count = int(design.shape[1])
    if len(y_arr) < term_count:
        return None
    if str(family).strip().lower() == TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE:
        return _td_perf_fit_quadratic_surface_iterative(
            x1_arr,
            x2_arr,
            y_arr,
            fit_mode=fit_mode,
            x1n=x1n,
            x2n=x2n,
            x1_center=x1_center,
            x1_scale=x1_scale,
            x2_center=x2_center,
            x2_scale=x2_scale,
            design=design,
        )
    cond_number = float(np.linalg.cond(design))
    coeffs, _residuals, rank, _singular = np.linalg.lstsq(design, y_arr, rcond=None)
    if int(rank) < term_count:
        return None
    y_hat = design.dot(coeffs)
    coeff_list = [float(v) for v in coeffs.tolist()]
    model = _td_perf_finalize_model(
        fit_family=str(family).strip().lower(),
        fit_mode=fit_mode,
        equation=_td_perf_fmt_surface_equation(coeff_list, str(family).strip().lower()),
        x_norm_equation=_td_perf_fmt_surface_normalization(x1_center, x1_scale, x2_center, x2_scale),
        params={f"c{i}": float(v) for i, v in enumerate(coeff_list)},
        param_count=term_count,
        x_values=list(range(len(y_arr))),
        y_true=y_arr,
        y_hat=y_hat,
        composite_score=False,
        extra={
            "coeffs": coeff_list,
            "plot_dimension": "3d",
            "x1_center": float(x1_center),
            "x1_scale": float(x1_scale),
            "x2_center": float(x2_center),
            "x2_scale": float(x2_scale),
            "solver": "lstsq",
            "condition_number": float(cond_number),
            "ridge_alpha": 0.0,
            "iterations": 1,
            "converged": True,
            "y_center": 0.0,
            "y_scale": 1.0,
        },
    )
    model["monotonic_violations"] = 0
    model["monotonicity_penalty"] = 0.0
    return model


def _td_perf_local_low_score(coords, y_norm):
    np = _td_perf_import_numpy()
    point_count = int(len(y_norm))
    if point_count <= 0:
        return np.asarray([], dtype=float)
    k = min(6, max(3, int(math.ceil(math.sqrt(point_count)))))
    coord_arr = np.asarray(coords, dtype=float)
    if len(coord_arr.shape) != 2 or int(coord_arr.shape[0]) != point_count:
        return np.zeros(point_count, dtype=float)
    dist_sq = np.sum((coord_arr[:, None, :] - coord_arr[None, :, :]) ** 2, axis=2)
    low_score = np.zeros(point_count, dtype=float)
    for idx in range(point_count):
        order = np.argsort(dist_sq[idx], kind="mergesort")[:k]
        local = np.asarray(y_norm[order], dtype=float)
        local_min = float(np.min(local))
        local_med = float(np.median(local))
        denom = max(local_med - local_min, 1e-9)
        low_score[idx] = float(np.clip((local_med - float(y_norm[idx])) / denom, 0.0, 1.0))
    return low_score


def _td_perf_surface_low_score(x1n, x2n, y_norm):
    np = _td_perf_import_numpy()
    return _td_perf_local_low_score(np.column_stack([np.asarray(x1n, dtype=float), np.asarray(x2n, dtype=float)]), y_norm)


def _td_perf_three_input_low_score(x1n, x2n, x3n, y_norm):
    np = _td_perf_import_numpy()
    return _td_perf_local_low_score(
        np.column_stack([np.asarray(x1n, dtype=float), np.asarray(x2n, dtype=float), np.asarray(x3n, dtype=float)]),
        y_norm,
    )


def _td_perf_surface_solve_linear_system(design, y_values):
    np = _td_perf_import_numpy()
    term_count = int(design.shape[1])
    cond_number = float(np.linalg.cond(design))
    ridge_alpha = 0.0
    solver = "lstsq"
    if cond_number <= 1e5:
        coeffs, _residuals, rank, _singular = np.linalg.lstsq(design, y_values, rcond=None)
        if int(rank) < term_count:
            cond_number = float("inf")
        else:
            return coeffs, solver, cond_number, ridge_alpha
    solver = "ridge"
    ridge_alpha = 1e-6 if cond_number <= 1e8 else 1e-4
    xtx = design.T.dot(design) + (ridge_alpha * np.eye(term_count, dtype=float))
    xty = design.T.dot(np.asarray(y_values, dtype=float))
    coeffs = np.linalg.solve(xtx, xty)
    return coeffs, solver, cond_number, ridge_alpha


def _td_perf_analyze_quadratic_surface_control_period_fit_support(
    x1s: list[float],
    x2s: list[float],
    ys: list[float],
    control_periods: Sequence[float],
    *,
    fit_mode: str,
    min_points: int = 6,
    min_distinct_x1: int = 2,
    min_distinct_x2: int = 2,
) -> dict[str, object]:
    np = _td_perf_import_numpy()
    diagnostics: dict[str, object] = {
        "eligible_control_period_values": [],
        "ignored_control_periods": [],
        "slice_models": [],
        "slice_rows": [],
        "x1_center": 0.0,
        "x1_scale": 1.0,
        "x2_center": 0.0,
        "x2_scale": 1.0,
    }
    if len(x1s) != len(x2s) or len(x1s) != len(ys) or len(x1s) != len(control_periods):
        return diagnostics
    x1_arr = np.asarray([float(v) for v in x1s], dtype=float)
    x2_arr = np.asarray([float(v) for v in x2s], dtype=float)
    y_arr = np.asarray([float(v) for v in ys], dtype=float)
    cp_arr = np.asarray([float(v) for v in control_periods], dtype=float)
    if not bool(np.all(np.isfinite(x1_arr) & np.isfinite(x2_arr) & np.isfinite(y_arr) & np.isfinite(cp_arr))):
        return diagnostics
    if len(x1_arr) < 6:
        return diagnostics

    cp_groups: dict[float, list[int]] = {}
    for idx, cp_value in enumerate(cp_arr.tolist()):
        cp_groups.setdefault(round(float(cp_value), 12), []).append(idx)

    x1n_all, x2n_all, x1_center, x1_scale, x2_center, x2_scale = _td_perf_surface_normalize_axes(x1_arr, x2_arr)
    diagnostics.update(
        {
            "x1_center": float(x1_center),
            "x1_scale": float(x1_scale),
            "x2_center": float(x2_center),
            "x2_scale": float(x2_scale),
        }
    )

    slice_rows: list[dict[str, object]] = []
    slice_models: list[dict[str, object]] = []
    eligible_control_period_values: list[float] = []
    ignored_control_periods: list[dict[str, object]] = []
    for cp_value in sorted(float(v) for v in cp_groups.keys()):
        idxs = cp_groups.get(round(float(cp_value), 12), [])
        slice_x1 = x1_arr[idxs]
        slice_x2 = x2_arr[idxs]
        slice_y = y_arr[idxs]
        point_count = int(len(idxs))
        distinct_x1 = len({round(float(v), 12) for v in slice_x1.tolist()})
        distinct_x2 = len({round(float(v), 12) for v in slice_x2.tolist()})
        reason = _td_perf_surface_control_period_reason(
            point_count=point_count,
            distinct_x1=distinct_x1,
            distinct_x2=distinct_x2,
            min_points=min_points,
            min_distinct_x1=min_distinct_x1,
            min_distinct_x2=min_distinct_x2,
        )
        row = {
            "control_period": float(cp_value),
            "point_count": point_count,
            "distinct_x1": int(distinct_x1),
            "distinct_x2": int(distinct_x2),
            "eligible": not bool(reason),
            "reason": reason,
        }
        if reason:
            ignored_control_periods.append(dict(row))
            slice_rows.append(dict(row))
            continue
        slice_x1n = np.asarray([float(x1n_all[idx]) for idx in idxs], dtype=float)
        slice_x2n = np.asarray([float(x2n_all[idx]) for idx in idxs], dtype=float)
        slice_design = _td_perf_surface_design_matrix(slice_x1n, slice_x2n, TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE)
        slice_model = _td_perf_fit_quadratic_surface_iterative(
            slice_x1,
            slice_x2,
            slice_y,
            fit_mode=fit_mode,
            x1n=slice_x1n,
            x2n=slice_x2n,
            x1_center=x1_center,
            x1_scale=x1_scale,
            x2_center=x2_center,
            x2_scale=x2_scale,
            design=slice_design,
        )
        coeff_list = [float(v) for v in (slice_model.get("coeffs") or [])] if isinstance(slice_model, dict) else []
        if not isinstance(slice_model, dict) or len(coeff_list) != 6:
            row["eligible"] = False
            row["reason"] = _td_perf_surface_control_period_reason(
                point_count=point_count,
                distinct_x1=distinct_x1,
                distinct_x2=distinct_x2,
                fit_failed=True,
                min_points=min_points,
                min_distinct_x1=min_distinct_x1,
                min_distinct_x2=min_distinct_x2,
            )
            ignored_control_periods.append(dict(row))
            slice_rows.append(dict(row))
            continue
        eligible_control_period_values.append(float(cp_value))
        row["eligible"] = True
        row["reason"] = ""
        slice_rows.append(dict(row))
        slice_models.append(
            {
                "control_period": float(cp_value),
                "coeffs": coeff_list,
                "solver": str(slice_model.get("solver") or ""),
                "condition_number": float(slice_model.get("condition_number") or 0.0),
                "point_count": point_count,
                "distinct_x1": int(distinct_x1),
                "distinct_x2": int(distinct_x2),
            }
        )

    diagnostics.update(
        {
            "eligible_control_period_values": [float(v) for v in eligible_control_period_values],
            "ignored_control_periods": ignored_control_periods,
            "slice_models": slice_models,
            "slice_rows": slice_rows,
        }
    )
    return diagnostics


def _td_perf_fit_quadratic_surface_control_period_model(
    x1s: list[float],
    x2s: list[float],
    ys: list[float],
    control_periods: Sequence[float],
    *,
    fit_mode: str,
    min_points: int = 6,
    min_distinct_x1: int = 2,
    min_distinct_x2: int = 2,
) -> dict[str, object] | None:
    np = _td_perf_import_numpy()
    if len(x1s) != len(x2s) or len(x1s) != len(ys) or len(x1s) != len(control_periods):
        return None
    x1_arr = np.asarray([float(v) for v in x1s], dtype=float)
    x2_arr = np.asarray([float(v) for v in x2s], dtype=float)
    y_arr = np.asarray([float(v) for v in ys], dtype=float)
    cp_arr = np.asarray([float(v) for v in control_periods], dtype=float)
    if not bool(np.all(np.isfinite(x1_arr) & np.isfinite(x2_arr) & np.isfinite(y_arr) & np.isfinite(cp_arr))):
        return None
    if len(x1_arr) < 6:
        return None

    support = _td_perf_analyze_quadratic_surface_control_period_fit_support(
        x1s,
        x2s,
        ys,
        control_periods,
        fit_mode=fit_mode,
        min_points=min_points,
        min_distinct_x1=min_distinct_x1,
        min_distinct_x2=min_distinct_x2,
    )
    cp_values = [float(v) for v in (support.get("eligible_control_period_values") or [])]
    slice_models = [dict(item) for item in (support.get("slice_models") or []) if isinstance(item, Mapping)]
    ignored_control_periods = [dict(item) for item in (support.get("ignored_control_periods") or []) if isinstance(item, Mapping)]
    x1_center = float(support.get("x1_center") or 0.0)
    x1_scale = float(support.get("x1_scale") or 1.0)
    x2_center = float(support.get("x2_center") or 0.0)
    x2_scale = float(support.get("x2_scale") or 1.0)
    if len(cp_values) < 2 or len(slice_models) < 2:
        return None

    coeff_rows = [[float(v) for v in (slice_model.get("coeffs") or [])] for slice_model in slice_models]

    cp_norm, cp_center, cp_scale = _td_perf_surface_normalize_control_period(cp_values)
    cp_degree = 1 if len(cp_values) == 2 else 2
    coeff_matrix_arr = np.asarray(coeff_rows, dtype=float)
    coeff_cp_models: list[list[float]] = []
    coeffs_at_center: list[float] = []
    for basis_idx in range(coeff_matrix_arr.shape[1]):
        coeff_values = coeff_matrix_arr[:, basis_idx]
        cp_coeffs = np.polyfit(cp_norm, coeff_values, cp_degree)
        coeff_cp_models.append([float(v) for v in cp_coeffs.tolist()])
        coeffs_at_center.append(float(np.poly1d(cp_coeffs)(0.0)))

    y_hat = np.asarray(
        td_perf_predict_surface(
            {
                "fit_family": TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE_CONTROL_PERIOD,
                "x1_center": float(x1_center),
                "x1_scale": float(x1_scale),
                "x2_center": float(x2_center),
                "x2_scale": float(x2_scale),
                "cp_center": float(cp_center),
                "cp_scale": float(cp_scale),
                "coeff_cp_models": coeff_cp_models,
            },
            x1_arr.tolist(),
            x2_arr.tolist(),
            control_period=cp_arr.tolist(),
        ),
        dtype=float,
    )
    params: dict[str, object] = {
        "cp_center": float(cp_center),
        "cp_scale": float(cp_scale),
        "control_period_degree": int(cp_degree),
        "control_period_values": [float(v) for v in cp_values],
        "eligible_control_period_values": [float(v) for v in cp_values],
        "ignored_control_periods": [dict(entry) for entry in ignored_control_periods],
        "fit_domain_control_period": [float(min(cp_values)), float(max(cp_values))],
        "coeff_cp_models": [[float(v) for v in coeffs] for coeffs in coeff_cp_models],
    }
    for basis_idx, coeffs in enumerate(coeff_cp_models):
        params[f"basis_{basis_idx}_cp_coeffs"] = [float(v) for v in coeffs]
    model = _td_perf_finalize_model(
        fit_family=TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE_CONTROL_PERIOD,
        fit_mode=fit_mode,
        equation=_td_perf_fmt_surface_control_period_equation(coeff_cp_models),
        x_norm_equation=_td_perf_fmt_surface_control_period_normalization(
            x1_center,
            x1_scale,
            x2_center,
            x2_scale,
            cp_center,
            cp_scale,
        ),
        params=params,
        param_count=(len(coeff_cp_models) * (cp_degree + 1)),
        x_values=list(range(len(y_arr))),
        y_true=y_arr,
        y_hat=y_hat,
        composite_score=False,
        extra={
            "coeffs": [float(v) for v in coeffs_at_center],
            "coeff_cp_models": [[float(v) for v in coeffs] for coeffs in coeff_cp_models],
            "plot_dimension": "3d",
            "x1_center": float(x1_center),
            "x1_scale": float(x1_scale),
            "x2_center": float(x2_center),
            "x2_scale": float(x2_scale),
            "cp_center": float(cp_center),
            "cp_scale": float(cp_scale),
            "control_period_values": [float(v) for v in cp_values],
            "eligible_control_period_values": [float(v) for v in cp_values],
            "ignored_control_periods": [dict(entry) for entry in ignored_control_periods],
            "control_period_degree": int(cp_degree),
            "fit_domain_control_period": [float(min(cp_values)), float(max(cp_values))],
            "slice_models": slice_models,
            "solver": "slice_polyfit",
        },
    )
    warning_text = _td_perf_format_surface_control_period_warning(ignored_control_periods)
    if warning_text:
        _td_perf_append_fit_warning(model, warning_text)
    return model


def _td_perf_analyze_quadratic_3input_control_period_fit_support(
    x1s: list[float],
    x2s: list[float],
    x3s: list[float],
    ys: list[float],
    control_periods: Sequence[float],
    *,
    min_points: int = 10,
    min_distinct_x1: int = 2,
    min_distinct_x2: int = 2,
    min_distinct_x3: int = 2,
) -> dict[str, object]:
    np = _td_perf_import_numpy()
    diagnostics: dict[str, object] = {
        "eligible_control_period_values": [],
        "ignored_control_periods": [],
        "slice_models": [],
        "slice_rows": [],
        "x1_center": 0.0,
        "x1_scale": 1.0,
        "x2_center": 0.0,
        "x2_scale": 1.0,
        "x3_center": 0.0,
        "x3_scale": 1.0,
    }
    if len(x1s) != len(x2s) or len(x1s) != len(x3s) or len(x1s) != len(ys) or len(x1s) != len(control_periods):
        return diagnostics
    x1_arr = np.asarray([float(v) for v in x1s], dtype=float)
    x2_arr = np.asarray([float(v) for v in x2s], dtype=float)
    x3_arr = np.asarray([float(v) for v in x3s], dtype=float)
    y_arr = np.asarray([float(v) for v in ys], dtype=float)
    cp_arr = np.asarray([float(v) for v in control_periods], dtype=float)
    if not bool(np.all(np.isfinite(x1_arr) & np.isfinite(x2_arr) & np.isfinite(x3_arr) & np.isfinite(y_arr) & np.isfinite(cp_arr))):
        return diagnostics
    if len(x1_arr) < 10:
        return diagnostics

    cp_groups: dict[float, list[int]] = {}
    for idx, cp_value in enumerate(cp_arr.tolist()):
        cp_groups.setdefault(round(float(cp_value), 12), []).append(idx)

    x1n_all, x2n_all, x3n_all, x1_center, x1_scale, x2_center, x2_scale, x3_center, x3_scale = _td_perf_surface_normalize_three_axes(
        x1_arr,
        x2_arr,
        x3_arr,
    )
    diagnostics.update(
        {
            "x1_center": float(x1_center),
            "x1_scale": float(x1_scale),
            "x2_center": float(x2_center),
            "x2_scale": float(x2_scale),
            "x3_center": float(x3_center),
            "x3_scale": float(x3_scale),
        }
    )

    slice_rows: list[dict[str, object]] = []
    slice_models: list[dict[str, object]] = []
    eligible_control_period_values: list[float] = []
    ignored_control_periods: list[dict[str, object]] = []
    for cp_value in sorted(float(v) for v in cp_groups.keys()):
        idxs = cp_groups.get(round(float(cp_value), 12), [])
        slice_x1 = x1_arr[idxs]
        slice_x2 = x2_arr[idxs]
        slice_x3 = x3_arr[idxs]
        slice_y = y_arr[idxs]
        point_count = int(len(idxs))
        distinct_x1 = len({round(float(v), 12) for v in slice_x1.tolist()})
        distinct_x2 = len({round(float(v), 12) for v in slice_x2.tolist()})
        distinct_x3 = len({round(float(v), 12) for v in slice_x3.tolist()})
        reason = _td_perf_three_input_control_period_reason(
            point_count=point_count,
            distinct_x1=distinct_x1,
            distinct_x2=distinct_x2,
            distinct_x3=distinct_x3,
            min_points=min_points,
            min_distinct_x1=min_distinct_x1,
            min_distinct_x2=min_distinct_x2,
            min_distinct_x3=min_distinct_x3,
        )
        row = {
            "control_period": float(cp_value),
            "point_count": point_count,
            "distinct_x1": int(distinct_x1),
            "distinct_x2": int(distinct_x2),
            "distinct_x3": int(distinct_x3),
            "eligible": not bool(reason),
            "reason": reason,
        }
        if reason:
            ignored_control_periods.append(dict(row))
            slice_rows.append(dict(row))
            continue
        slice_x1n = np.asarray([float(x1n_all[idx]) for idx in idxs], dtype=float)
        slice_x2n = np.asarray([float(x2n_all[idx]) for idx in idxs], dtype=float)
        slice_x3n = np.asarray([float(x3n_all[idx]) for idx in idxs], dtype=float)
        design = _td_perf_three_input_design_matrix(slice_x1n, slice_x2n, slice_x3n)
        slice_model = _td_perf_fit_quadratic_3input_iterative(
            slice_x1,
            slice_x2,
            slice_x3,
            slice_y,
            x1n=slice_x1n,
            x2n=slice_x2n,
            x3n=slice_x3n,
            x1_center=x1_center,
            x1_scale=x1_scale,
            x2_center=x2_center,
            x2_scale=x2_scale,
            x3_center=x3_center,
            x3_scale=x3_scale,
            design=design,
        )
        coeff_list = [float(v) for v in (slice_model.get("coeffs") or [])] if isinstance(slice_model, dict) else []
        if not isinstance(slice_model, dict) or len(coeff_list) != 10:
            row["eligible"] = False
            row["reason"] = _td_perf_three_input_control_period_reason(
                point_count=point_count,
                distinct_x1=distinct_x1,
                distinct_x2=distinct_x2,
                distinct_x3=distinct_x3,
                fit_failed=True,
                min_points=min_points,
                min_distinct_x1=min_distinct_x1,
                min_distinct_x2=min_distinct_x2,
                min_distinct_x3=min_distinct_x3,
            )
            ignored_control_periods.append(dict(row))
            slice_rows.append(dict(row))
            continue
        eligible_control_period_values.append(float(cp_value))
        row["eligible"] = True
        row["reason"] = ""
        slice_rows.append(dict(row))
        slice_models.append(
            {
                "control_period": float(cp_value),
                "coeffs": coeff_list,
                "solver": str(slice_model.get("solver") or ""),
                "condition_number": float(slice_model.get("condition_number") or 0.0),
                "ridge_alpha": float(slice_model.get("ridge_alpha") or 0.0),
                "point_count": point_count,
                "distinct_x1": int(distinct_x1),
                "distinct_x2": int(distinct_x2),
                "distinct_x3": int(distinct_x3),
            }
        )

    diagnostics.update(
        {
            "eligible_control_period_values": [float(v) for v in eligible_control_period_values],
            "ignored_control_periods": ignored_control_periods,
            "slice_models": slice_models,
            "slice_rows": slice_rows,
        }
    )
    return diagnostics


def _td_perf_fit_quadratic_3input_control_period_model(
    x1s: list[float],
    x2s: list[float],
    x3s: list[float],
    ys: list[float],
    control_periods: Sequence[float],
    *,
    min_points: int = 10,
    min_distinct_x1: int = 2,
    min_distinct_x2: int = 2,
    min_distinct_x3: int = 2,
) -> dict[str, object] | None:
    np = _td_perf_import_numpy()
    if len(x1s) != len(x2s) or len(x1s) != len(x3s) or len(x1s) != len(ys) or len(x1s) != len(control_periods):
        return None
    x1_arr = np.asarray([float(v) for v in x1s], dtype=float)
    x2_arr = np.asarray([float(v) for v in x2s], dtype=float)
    x3_arr = np.asarray([float(v) for v in x3s], dtype=float)
    y_arr = np.asarray([float(v) for v in ys], dtype=float)
    cp_arr = np.asarray([float(v) for v in control_periods], dtype=float)
    if not bool(np.all(np.isfinite(x1_arr) & np.isfinite(x2_arr) & np.isfinite(x3_arr) & np.isfinite(y_arr) & np.isfinite(cp_arr))):
        return None
    if len(x1_arr) < 10:
        return None

    support = _td_perf_analyze_quadratic_3input_control_period_fit_support(
        x1s,
        x2s,
        x3s,
        ys,
        control_periods,
        min_points=min_points,
        min_distinct_x1=min_distinct_x1,
        min_distinct_x2=min_distinct_x2,
        min_distinct_x3=min_distinct_x3,
    )
    cp_values = [float(v) for v in (support.get("eligible_control_period_values") or [])]
    slice_models = [dict(item) for item in (support.get("slice_models") or []) if isinstance(item, Mapping)]
    ignored_control_periods = [dict(item) for item in (support.get("ignored_control_periods") or []) if isinstance(item, Mapping)]
    x1_center = float(support.get("x1_center") or 0.0)
    x1_scale = float(support.get("x1_scale") or 1.0)
    x2_center = float(support.get("x2_center") or 0.0)
    x2_scale = float(support.get("x2_scale") or 1.0)
    x3_center = float(support.get("x3_center") or 0.0)
    x3_scale = float(support.get("x3_scale") or 1.0)
    if len(cp_values) < 2 or len(slice_models) < 2:
        return None

    coeff_rows = [[float(v) for v in (slice_model.get("coeffs") or [])] for slice_model in slice_models]
    cp_norm, cp_center, cp_scale = _td_perf_surface_normalize_control_period(cp_values)
    cp_degree = 1 if len(cp_values) == 2 else 2
    coeff_matrix_arr = np.asarray(coeff_rows, dtype=float)
    coeff_cp_models: list[list[float]] = []
    coeffs_at_center: list[float] = []
    for basis_idx in range(coeff_matrix_arr.shape[1]):
        coeff_values = coeff_matrix_arr[:, basis_idx]
        cp_coeffs = np.polyfit(cp_norm, coeff_values, cp_degree)
        coeff_cp_models.append([float(v) for v in cp_coeffs.tolist()])
        coeffs_at_center.append(float(np.poly1d(cp_coeffs)(0.0)))

    y_hat = np.asarray(
        _td_perf_predict_quadratic_3input_control_period(
            {
                "fit_family": TD_PERF_FIT_FAMILY_QUADRATIC_3INPUT_CONTROL_PERIOD,
                "x1_center": float(x1_center),
                "x1_scale": float(x1_scale),
                "x2_center": float(x2_center),
                "x2_scale": float(x2_scale),
                "x3_center": float(x3_center),
                "x3_scale": float(x3_scale),
                "cp_center": float(cp_center),
                "cp_scale": float(cp_scale),
                "coeff_cp_models": coeff_cp_models,
            },
            x1_arr.tolist(),
            x2_arr.tolist(),
            x3_arr.tolist(),
            cp_arr.tolist(),
        ),
        dtype=float,
    )
    params: dict[str, object] = {
        "cp_center": float(cp_center),
        "cp_scale": float(cp_scale),
        "control_period_degree": int(cp_degree),
        "control_period_values": [float(v) for v in cp_values],
        "eligible_control_period_values": [float(v) for v in cp_values],
        "ignored_control_periods": [dict(entry) for entry in ignored_control_periods],
        "fit_domain_control_period": [float(min(cp_values)), float(max(cp_values))],
        "coeff_cp_models": [[float(v) for v in coeffs] for coeffs in coeff_cp_models],
    }
    for basis_idx, coeffs in enumerate(coeff_cp_models):
        params[f"basis_{basis_idx}_cp_coeffs"] = [float(v) for v in coeffs]
    model = _td_perf_finalize_model(
        fit_family=TD_PERF_FIT_FAMILY_QUADRATIC_3INPUT_CONTROL_PERIOD,
        fit_mode=TD_PERF_FIT_FAMILY_QUADRATIC_3INPUT_CONTROL_PERIOD,
        equation=_td_perf_fmt_3input_control_period_equation(coeff_cp_models),
        x_norm_equation=_td_perf_fmt_3input_control_period_normalization(
            x1_center,
            x1_scale,
            x2_center,
            x2_scale,
            x3_center,
            x3_scale,
            cp_center,
            cp_scale,
        ),
        params=params,
        param_count=(len(coeff_cp_models) * (cp_degree + 1)),
        x_values=list(range(len(y_arr))),
        y_true=y_arr,
        y_hat=y_hat,
        composite_score=False,
        extra={
            "coeffs": [float(v) for v in coeffs_at_center],
            "coeff_cp_models": [[float(v) for v in coeffs] for coeffs in coeff_cp_models],
            "x1_center": float(x1_center),
            "x1_scale": float(x1_scale),
            "x2_center": float(x2_center),
            "x2_scale": float(x2_scale),
            "x3_center": float(x3_center),
            "x3_scale": float(x3_scale),
            "cp_center": float(cp_center),
            "cp_scale": float(cp_scale),
            "control_period_values": [float(v) for v in cp_values],
            "eligible_control_period_values": [float(v) for v in cp_values],
            "ignored_control_periods": [dict(entry) for entry in ignored_control_periods],
            "control_period_degree": int(cp_degree),
            "fit_domain_control_period": [float(min(cp_values)), float(max(cp_values))],
            "slice_models": slice_models,
            "solver": "slice_polyfit",
        },
    )
    warning_text = _td_perf_format_three_input_control_period_warning(ignored_control_periods)
    if warning_text:
        _td_perf_append_fit_warning(model, warning_text)
    return model


def _td_perf_fit_quadratic_3input_model(
    x1s: list[float],
    x2s: list[float],
    x3s: list[float],
    ys: list[float],
    *,
    min_points: int = 10,
    min_distinct_x1: int = 2,
    min_distinct_x2: int = 2,
    min_distinct_x3: int = 2,
) -> dict[str, object] | None:
    np = _td_perf_import_numpy()
    if len(x1s) != len(x2s) or len(x1s) != len(x3s) or len(x1s) != len(ys):
        return None
    x1_arr = np.asarray([float(v) for v in x1s], dtype=float)
    x2_arr = np.asarray([float(v) for v in x2s], dtype=float)
    x3_arr = np.asarray([float(v) for v in x3s], dtype=float)
    y_arr = np.asarray([float(v) for v in ys], dtype=float)
    if not bool(np.all(np.isfinite(x1_arr) & np.isfinite(x2_arr) & np.isfinite(x3_arr) & np.isfinite(y_arr))):
        return None
    point_count = int(len(x1_arr))
    distinct_x1 = len({round(float(v), 12) for v in x1_arr.tolist()})
    distinct_x2 = len({round(float(v), 12) for v in x2_arr.tolist()})
    distinct_x3 = len({round(float(v), 12) for v in x3_arr.tolist()})
    if (
        point_count < max(10, int(min_points))
        or distinct_x1 < max(2, int(min_distinct_x1))
        or distinct_x2 < max(2, int(min_distinct_x2))
        or distinct_x3 < max(2, int(min_distinct_x3))
    ):
        return None
    x1n, x2n, x3n, x1_center, x1_scale, x2_center, x2_scale, x3_center, x3_scale = _td_perf_surface_normalize_three_axes(
        x1_arr,
        x2_arr,
        x3_arr,
    )
    design = _td_perf_three_input_design_matrix(x1n, x2n, x3n)
    fit = _td_perf_fit_quadratic_3input_iterative(
        x1_arr,
        x2_arr,
        x3_arr,
        y_arr,
        x1n=x1n,
        x2n=x2n,
        x3n=x3n,
        x1_center=x1_center,
        x1_scale=x1_scale,
        x2_center=x2_center,
        x2_scale=x2_scale,
        x3_center=x3_center,
        x3_scale=x3_scale,
        design=design,
    )
    coeffs = [float(v) for v in (fit.get("coeffs") or [])] if isinstance(fit, dict) else []
    if len(coeffs) != 10:
        return None
    y_hat = np.asarray(_td_perf_predict_quadratic_3input(fit, x1_arr.tolist(), x2_arr.tolist(), x3_arr.tolist()), dtype=float)
    if len(y_hat) != len(y_arr):
        return None
    return _td_perf_finalize_model(
        fit_family=TD_PERF_FIT_FAMILY_QUADRATIC_3INPUT,
        fit_mode=TD_PERF_FIT_FAMILY_QUADRATIC_3INPUT,
        equation=_td_perf_fmt_3input_equation(coeffs),
        x_norm_equation=_td_perf_fmt_3input_normalization(
            float(x1_center),
            float(x1_scale),
            float(x2_center),
            float(x2_scale),
            float(x3_center),
            float(x3_scale),
        ),
        params={f"c{i}": float(v) for i, v in enumerate(coeffs)},
        param_count=int(len(coeffs)),
        x_values=list(range(len(y_arr))),
        y_true=y_arr,
        y_hat=y_hat,
        composite_score=False,
        extra={
            "coeffs": coeffs,
            "x1_center": float(x1_center),
            "x1_scale": float(x1_scale),
            "x2_center": float(x2_center),
            "x2_scale": float(x2_scale),
            "x3_center": float(x3_center),
            "x3_scale": float(x3_scale),
            "solver": str(fit.get("solver") or ""),
            "condition_number": float(fit.get("condition_number") or 0.0),
            "ridge_alpha": float(fit.get("ridge_alpha") or 0.0),
            "iterations": int(fit.get("iterations") or 0),
            "converged": bool(fit.get("converged")),
        },
    )


def _td_perf_fit_staged_mediator_model(
    x1s: list[float],
    x2s: list[float],
    x3s: list[float],
    ys: list[float],
    *,
    mediator_target: object,
) -> dict[str, object] | None:
    np = _td_perf_import_numpy()
    if len(x1s) != len(x2s) or len(x1s) != len(x3s) or len(x1s) != len(ys):
        return None
    stage1_model = td_perf_fit_surface_model(
        x1s,
        x2s,
        x3s,
        auto_surface_families=True,
        surface_family=TD_PERF_FIT_MODE_AUTO_SURFACE,
    )
    if not isinstance(stage1_model, dict):
        return None
    x3_hat = td_perf_predict_surface(stage1_model, x1s, x2s)
    if len(x3_hat) != len(ys) or len(x3_hat) != len(x3s):
        return None
    x3_hat_list = [float(v) for v in x3_hat]
    x3_arr = np.asarray([float(v) for v in x3s], dtype=float)
    stage1_rmse = float(np.sqrt(np.mean((np.asarray(x3_hat_list, dtype=float) - x3_arr) ** 2))) if len(x3_hat_list) == len(x3_arr) else None
    stage2_model = td_perf_fit_model(
        [float(v) for v in x3s],
        ys,
        fit_mode=TD_PERF_FIT_MODE_AUTO,
    )
    if not isinstance(stage2_model, dict):
        return None
    mediator_domain = _td_smart_solver_numeric_domain(stage2_model.get("fit_domain") or x3s)
    clamped_mediator, clamp_hits = _td_smart_solver_clamp_values(x3_hat_list, mediator_domain)
    y_hat = td_perf_predict_model(stage2_model, clamped_mediator)
    if len(y_hat) != len(ys):
        return None
    y_hat_arr = np.asarray([float(v) for v in y_hat], dtype=float)
    y_arr = np.asarray([float(v) for v in ys], dtype=float)
    model = _td_perf_finalize_model(
        fit_family=TD_PERF_FIT_FAMILY_STAGED_MEDIATOR,
        fit_mode=TD_PERF_FIT_FAMILY_STAGED_MEDIATOR,
        equation=_td_perf_fmt_staged_mediator_equation(
            stage1_model.get("equation"),
            stage2_model.get("equation"),
            mediator_target=mediator_target,
        ),
        x_norm_equation=_td_perf_fmt_staged_mediator_normalization(
            stage1_model.get("x_norm_equation"),
            stage2_model,
            mediator_target=mediator_target,
        ),
        params={
            "mediator_target": str(mediator_target or "").strip(),
            "stage1_fit_family": str(stage1_model.get("fit_family") or ""),
            "stage2_fit_family": str(stage2_model.get("fit_family") or ""),
        },
        param_count=int(stage1_model.get("param_count") or 0) + int(stage2_model.get("param_count") or 0),
        x_values=list(range(len(y_arr))),
        y_true=y_arr,
        y_hat=y_hat_arr,
        composite_score=False,
        extra={
            "mediator_target": str(mediator_target or "").strip(),
            "stage1_model": dict(stage1_model),
            "stage2_model": dict(stage2_model),
            "stage1_fit_family": str(stage1_model.get("fit_family") or ""),
            "stage2_fit_family": str(stage2_model.get("fit_family") or ""),
            "solver": "staged_mediator",
            "low_x_breakpoint": _td_finite_float(stage2_model.get("low_x_breakpoint")),
            "low_x_window_enabled": bool(stage2_model.get("low_x_window_enabled")),
            "stabilization_passes": int(stage2_model.get("stabilization_passes") or 0),
            "fallback_used": bool(stage2_model.get("fallback_used")),
            "base_fit_family": str(stage2_model.get("base_fit_family") or stage2_model.get("fit_family") or ""),
            "support_profile": {
                "stage1": dict(stage1_model.get("support_profile") or {}) if isinstance(stage1_model.get("support_profile"), Mapping) else {},
                "stage2": dict(stage2_model.get("support_profile") or {}) if isinstance(stage2_model.get("support_profile"), Mapping) else {},
            },
            "stage1_rmse": (float(stage1_rmse) if isinstance(stage1_rmse, (int, float)) and math.isfinite(float(stage1_rmse)) else None),
            "stage2_fit_source": "actual_input_3",
            "mediator_clamp_count": int(clamp_hits),
            "stage2_input_domain": [float(v) for v in mediator_domain[:2]],
            "stage1_clamped_predictions": [float(v) for v in clamped_mediator if isinstance(v, (int, float))],
        },
    )
    combined_warning = _td_perf_merge_warning_texts(
        _td_perf_merge_warning_texts(stage1_model.get("fit_warning_text"), prefix="Stage 1: "),
        _td_perf_merge_warning_texts(stage2_model.get("fit_warning_text"), prefix="Stage 2: "),
    )
    if combined_warning:
        _td_perf_append_fit_warning(model, combined_warning)
    if int(clamp_hits) > 0 and len(mediator_domain) >= 2:
        _td_perf_append_fit_warning(
            model,
            "Stage 1 mediator predictions were clamped to the Stage 2 fit domain "
            f"({min(mediator_domain):g} to {max(mediator_domain):g}) for {int(clamp_hits)} point(s).",
        )
    model["stage1_rmse"] = (float(stage1_rmse) if isinstance(stage1_rmse, (int, float)) and math.isfinite(float(stage1_rmse)) else None)
    model["stage2_fit_source"] = "actual_input_3"
    model["mediator_clamp_count"] = int(clamp_hits)
    model["stage2_input_domain"] = [float(v) for v in mediator_domain[:2]]
    return model


def _td_perf_merge_warning_texts(*texts: object, prefix: str = "") -> str:
    parts: list[str] = []
    for raw in texts:
        txt = str(raw or "").strip()
        if not txt:
            continue
        for line in txt.splitlines():
            line_txt = str(line or "").strip()
            if not line_txt:
                continue
            candidate = f"{prefix}{line_txt}" if prefix else line_txt
            if candidate not in parts:
                parts.append(candidate)
    return "\n".join(parts)


def _td_perf_fit_staged_mediator_control_period_model(
    x1s: list[float],
    x2s: list[float],
    x3s: list[float],
    ys: list[float],
    control_periods: Sequence[float],
    *,
    mediator_target: object,
    fit_mode: str,
) -> dict[str, object] | None:
    np = _td_perf_import_numpy()
    stage1_support = _td_perf_analyze_quadratic_surface_control_period_fit_support(
        x1s,
        x2s,
        x3s,
        control_periods,
        fit_mode=fit_mode,
        min_points=TD_SMART_SOLVER_STAGE1_SURFACE_MIN_POINTS,
        min_distinct_x1=TD_SMART_SOLVER_STAGE1_SURFACE_MIN_DISTINCT_X,
        min_distinct_x2=TD_SMART_SOLVER_STAGE1_SURFACE_MIN_DISTINCT_X,
    )
    stage1_model = _td_perf_fit_quadratic_surface_control_period_model(
        x1s,
        x2s,
        x3s,
        control_periods,
        fit_mode=fit_mode,
        min_points=TD_SMART_SOLVER_STAGE1_SURFACE_MIN_POINTS,
        min_distinct_x1=TD_SMART_SOLVER_STAGE1_SURFACE_MIN_DISTINCT_X,
        min_distinct_x2=TD_SMART_SOLVER_STAGE1_SURFACE_MIN_DISTINCT_X,
    )
    if not isinstance(stage1_model, dict):
        return None

    x3_hat = td_perf_predict_surface(stage1_model, x1s, x2s, control_period=control_periods)
    if len(x3_hat) != len(ys) or len(x3_hat) != len(x3s):
        return None
    x3_hat_list = [float(v) for v in x3_hat]
    x3_arr = np.asarray([float(v) for v in x3s], dtype=float)
    stage1_rmse = float(np.sqrt(np.mean((np.asarray(x3_hat_list, dtype=float) - x3_arr) ** 2))) if len(x3_hat_list) == len(x3_arr) else None

    stage2_candidates: list[dict[str, object]] = []
    for stage2_fit_source, stage2_xs in (
        ("actual_input_3", [float(v) for v in x3s]),
        ("stage1_pred_input_3", list(x3_hat_list)),
    ):
        stage2_support = _td_perf_analyze_quadratic_curve_control_period_fit_support(stage2_xs, ys, control_periods)
        stage2_legacy = _td_perf_fit_quadratic_curve_control_period_model(stage2_xs, ys, control_periods)
        stage2_model = _td_perf_fit_hybrid_quadratic_residual_control_period_model(
            stage2_xs,
            ys,
            control_periods,
            support=stage2_support,
            legacy_model=stage2_legacy,
        )
        if not isinstance(stage2_model, dict):
            stage2_model = stage2_legacy
        if not isinstance(stage2_model, dict):
            continue
        stage2_model = _td_smart_solver_attach_curve_cp_boundary_metadata(
            stage2_model,
            stage2_xs,
            ys,
            control_periods,
        ) or {}
        if not stage2_model:
            continue
        mediator_domain = _td_smart_solver_numeric_domain(stage2_model.get("fit_domain") or stage2_xs)
        clamped_mediator, clamp_hits = _td_smart_solver_clamp_values(x3_hat_list, mediator_domain)
        y_hat = _td_smart_solver_predict_model(stage2_model, clamped_mediator, control_period=control_periods)
        if len(y_hat) != len(ys):
            continue
        stage2_ignored = [dict(entry) for entry in (stage2_model.get("ignored_control_periods") or []) if isinstance(entry, Mapping)]
        stage1_ignored = [dict(entry) for entry in (stage1_model.get("ignored_control_periods") or []) if isinstance(entry, Mapping)]
        stage2_candidates.append(
            {
                "stage2_fit_source": stage2_fit_source,
                "stage2_model": dict(stage2_model),
                "stage2_support": dict(stage2_support),
                "y_hat": [float(v) for v in y_hat],
                "mediator_domain": mediator_domain,
                "clamped_mediator": [float(v) for v in clamped_mediator],
                "clamp_hits": int(clamp_hits),
                "ignored_control_periods": [
                    {"stage": "stage1", **entry}
                    for entry in stage1_ignored
                ] + [
                    {"stage": "stage2", **entry}
                    for entry in stage2_ignored
                ],
                "summary": _td_smart_solver_candidate_summary(
                    model=stage2_model,
                    actual_values=ys,
                    predicted_values=y_hat,
                    ignored_control_periods=[
                        {"stage": "stage1", **entry}
                        for entry in stage1_ignored
                    ] + [
                        {"stage": "stage2", **entry}
                        for entry in stage2_ignored
                    ],
                    clamp_hits=int(clamp_hits),
                    stage2_fit_source=stage2_fit_source,
                    stage1_rmse=stage1_rmse,
                ),
            }
        )

    if not stage2_candidates:
        return None

    selected_stage2 = dict(stage2_candidates[0])
    stage2_selection_reason = f"Stage 2 retained {selected_stage2.get('stage2_fit_source')} as the baseline staged source."
    for candidate in stage2_candidates[1:]:
        current_summary = dict(selected_stage2.get("summary") or {})
        candidate_summary = dict(candidate.get("summary") or {})
        current_fallout = int(current_summary.get("fell_out_count") or 0)
        candidate_fallout = int(candidate_summary.get("fell_out_count") or 0)
        if candidate_fallout < current_fallout:
            selected_stage2 = dict(candidate)
            stage2_selection_reason = (
                f"Stage 2 selected {str(candidate.get('stage2_fit_source') or '')} because it reduced composed fallout "
                f"({candidate_fallout} vs {current_fallout})."
            )
            continue
        if candidate_fallout > current_fallout:
            continue
        current_rmse = _td_smart_solver_candidate_rmse(current_summary)
        candidate_rmse = _td_smart_solver_candidate_rmse(candidate_summary)
        if (
            math.isfinite(candidate_rmse)
            and math.isfinite(current_rmse)
            and current_rmse > 0.0
            and candidate_rmse <= (0.95 * current_rmse)
        ):
            selected_stage2 = dict(candidate)
            stage2_selection_reason = (
                f"Stage 2 selected {str(candidate.get('stage2_fit_source') or '')} because composed RMSE improved by at least 5% "
                f"({candidate_rmse:.6g} vs {current_rmse:.6g})."
            )

    stage2_model = dict(selected_stage2.get("stage2_model") or {})
    y_hat = [float(v) for v in (selected_stage2.get("y_hat") or [])]
    if len(y_hat) != len(ys):
        return None
    y_hat_arr = np.asarray(y_hat, dtype=float)
    y_arr = np.asarray([float(v) for v in ys], dtype=float)
    model = _td_perf_finalize_model(
        fit_family=TD_PERF_FIT_FAMILY_STAGED_MEDIATOR_CONTROL_PERIOD,
        fit_mode=TD_PERF_FIT_FAMILY_STAGED_MEDIATOR_CONTROL_PERIOD,
        equation=_td_perf_fmt_staged_mediator_control_period_equation(
            stage1_model.get("equation"),
            stage2_model.get("equation"),
            mediator_target=mediator_target,
        ),
        x_norm_equation=_td_perf_fmt_staged_mediator_control_period_normalization(
            stage1_model.get("x_norm_equation"),
            stage2_model,
            mediator_target=mediator_target,
        ),
        params={
            "mediator_target": str(mediator_target or "").strip(),
            "stage1_fit_family": str(stage1_model.get("fit_family") or ""),
            "stage2_fit_family": str(stage2_model.get("fit_family") or ""),
        },
        param_count=int(stage1_model.get("param_count") or 0) + int(stage2_model.get("param_count") or 0),
        x_values=list(range(len(y_arr))),
        y_true=y_arr,
        y_hat=y_hat_arr,
        composite_score=False,
        extra={
            "mediator_target": str(mediator_target or "").strip(),
            "stage1_model": dict(stage1_model),
            "stage2_model": dict(stage2_model),
            "stage1_fit_family": str(stage1_model.get("fit_family") or ""),
            "stage2_fit_family": str(stage2_model.get("fit_family") or ""),
            "control_period_values": [float(v) for v in (stage2_model.get("control_period_values") or []) if isinstance(v, (int, float))],
            "fit_domain_control_period": [
                float(v)
                for v in (stage2_model.get("fit_domain_control_period") or [])
                if isinstance(v, (int, float))
            ][:2],
            "stage1_slice_rows": [dict(row) for row in (stage1_support.get("slice_rows") or []) if isinstance(row, Mapping)],
            "stage2_slice_rows": [dict(row) for row in ((selected_stage2.get("stage2_support") or {}).get("slice_rows") or []) if isinstance(row, Mapping)],
            "solver": "staged_mediator_cp",
            "low_x_breakpoint": _td_finite_float(stage2_model.get("low_x_breakpoint")),
            "low_x_window_enabled": bool(stage2_model.get("low_x_window_enabled")),
            "stabilization_passes": int(stage2_model.get("stabilization_passes") or 0),
            "fallback_used": bool(stage2_model.get("fallback_used")),
            "base_fit_family": str(stage2_model.get("base_fit_family") or stage2_model.get("fit_family") or ""),
            "ignored_control_periods": [dict(entry) for entry in (selected_stage2.get("ignored_control_periods") or []) if isinstance(entry, Mapping)],
            "support_profile": {
                "stage1": dict(stage1_model.get("support_profile") or {}) if isinstance(stage1_model.get("support_profile"), Mapping) else {},
                "stage2": dict(stage2_model.get("support_profile") or {}) if isinstance(stage2_model.get("support_profile"), Mapping) else {},
            },
            "stage1_rmse": (float(stage1_rmse) if isinstance(stage1_rmse, (int, float)) and math.isfinite(float(stage1_rmse)) else None),
            "stage2_fit_source": str(selected_stage2.get("stage2_fit_source") or ""),
            "mediator_clamp_count": int(selected_stage2.get("clamp_hits") or 0),
            "stage2_input_domain": [float(v) for v in (selected_stage2.get("mediator_domain") or []) if isinstance(v, (int, float))][:2],
            "stage1_clamped_predictions": [float(v) for v in (selected_stage2.get("clamped_mediator") or []) if isinstance(v, (int, float))],
            "stage2_candidate_scores": {
                str(candidate.get("stage2_fit_source") or ""): dict(candidate.get("summary") or {})
                for candidate in stage2_candidates
            },
            "stage2_selection_reason": stage2_selection_reason,
        },
    )
    combined_warning = _td_perf_merge_warning_texts(
        _td_perf_merge_warning_texts(stage1_model.get("fit_warning_text"), prefix="Stage 1: "),
        _td_perf_merge_warning_texts(stage2_model.get("fit_warning_text"), prefix="Stage 2: "),
    )
    if combined_warning:
        _td_perf_append_fit_warning(model, combined_warning)
    clamp_hits = int(selected_stage2.get("clamp_hits") or 0)
    if clamp_hits > 0:
        mediator_domain = [float(v) for v in (selected_stage2.get("mediator_domain") or []) if isinstance(v, (int, float))]
        if len(mediator_domain) >= 2:
            _td_perf_append_fit_warning(
                model,
                "Stage 1 mediator predictions were clamped to the Stage 2 fit domain "
                f"({min(mediator_domain):g} to {max(mediator_domain):g}) for {clamp_hits} point(s).",
            )
    model["stage1_rmse"] = (float(stage1_rmse) if isinstance(stage1_rmse, (int, float)) and math.isfinite(float(stage1_rmse)) else None)
    model["stage2_fit_source"] = str(selected_stage2.get("stage2_fit_source") or "")
    model["mediator_clamp_count"] = int(selected_stage2.get("clamp_hits") or 0)
    model["stage2_input_domain"] = [float(v) for v in (selected_stage2.get("mediator_domain") or []) if isinstance(v, (int, float))][:2]
    model["stage2_candidate_scores"] = {
        str(candidate.get("stage2_fit_source") or ""): dict(candidate.get("summary") or {})
        for candidate in stage2_candidates
    }
    model["stage2_selection_reason"] = stage2_selection_reason
    return model


def _td_smart_solver_stage_slice_rows(
    points: Sequence[Mapping[str, object]],
    *,
    stage1_model: Mapping[str, object],
    stage2_model: Mapping[str, object],
) -> list[dict[str, object]]:
    cp_groups: dict[float, list[Mapping[str, object]]] = {}
    for point in points:
        cp_value = _td_finite_float(point.get("control_period"))
        if cp_value is None:
            continue
        cp_groups.setdefault(round(float(cp_value), 12), []).append(point)
    stage1_rows = {
        round(float(entry.get("control_period") or 0.0), 12): dict(entry)
        for entry in (stage1_model.get("stage1_slice_rows") or stage1_model.get("slice_rows") or [])
        if isinstance(entry, Mapping)
    }
    stage2_rows = {
        round(float(entry.get("control_period") or 0.0), 12): dict(entry)
        for entry in (stage2_model.get("stage2_slice_rows") or stage2_model.get("slice_rows") or [])
        if isinstance(entry, Mapping)
    }
    rows: list[dict[str, object]] = []
    for cp_key in sorted(cp_groups.keys()):
        members = cp_groups.get(cp_key, [])
        stage1_row = stage1_rows.get(cp_key, {})
        stage2_row = stage2_rows.get(cp_key, {})
        reasons: list[str] = []
        if stage1_row and not bool(stage1_row.get("eligible")):
            reasons.append(f"Stage 1: {str(stage1_row.get('reason') or '').strip()}")
        if stage2_row and not bool(stage2_row.get("eligible")):
            reasons.append(f"Stage 2: {str(stage2_row.get('reason') or '').strip()}")
        rows.append(
            {
                "control_period": float(cp_key),
                "point_count": int(len(members)),
                "distinct_x1": len({round(float(point.get("input_1") or 0.0), 12) for point in members if _td_finite_float(point.get("input_1")) is not None}),
                "distinct_x2": len({round(float(point.get("input_2") or 0.0), 12) for point in members if _td_finite_float(point.get("input_2")) is not None}),
                "distinct_x3": len({round(float(point.get("input_3") or 0.0), 12) for point in members if _td_finite_float(point.get("input_3")) is not None}),
                "eligible": bool(stage1_row.get("eligible", True)) and bool(stage2_row.get("eligible", True)),
                "reason": "; ".join(part for part in reasons if part),
            }
        )
    return rows


def _td_perf_analyze_quadratic_curve_control_period_fit_support(
    xs: list[float],
    ys: list[float],
    control_periods: Sequence[float],
) -> dict[str, object]:
    np = _td_perf_import_numpy()
    diagnostics: dict[str, object] = {
        "eligible_control_period_values": [],
        "ignored_control_periods": [],
        "slice_models": [],
        "slice_rows": [],
        "x_center": 0.0,
        "x_scale": 1.0,
    }
    if len(xs) != len(ys) or len(xs) != len(control_periods):
        return diagnostics
    x_arr = np.asarray([float(v) for v in xs], dtype=float)
    y_arr = np.asarray([float(v) for v in ys], dtype=float)
    cp_arr = np.asarray([float(v) for v in control_periods], dtype=float)
    if not bool(np.all(np.isfinite(x_arr) & np.isfinite(y_arr) & np.isfinite(cp_arr))):
        return diagnostics
    if len(x_arr) < 3:
        return diagnostics

    cp_groups: dict[float, list[int]] = {}
    for idx, cp_value in enumerate(cp_arr.tolist()):
        cp_groups.setdefault(round(float(cp_value), 12), []).append(idx)

    x_center = float(np.mean(x_arr))
    x_scale = float(np.std(x_arr)) or 1.0
    x_norm_all = (x_arr - x_center) / x_scale
    diagnostics.update(
        {
            "x_center": float(x_center),
            "x_scale": float(x_scale),
        }
    )

    slice_rows: list[dict[str, object]] = []
    slice_models: list[dict[str, object]] = []
    eligible_control_period_values: list[float] = []
    ignored_control_periods: list[dict[str, object]] = []
    for cp_value in sorted(float(v) for v in cp_groups.keys()):
        idxs = cp_groups.get(round(float(cp_value), 12), [])
        slice_x = x_arr[idxs]
        slice_y = y_arr[idxs]
        point_count = int(len(idxs))
        distinct_x1 = len({round(float(v), 12) for v in slice_x.tolist()})
        reason = _td_perf_curve_control_period_reason(
            point_count=point_count,
            distinct_x1=distinct_x1,
        )
        row = {
            "control_period": float(cp_value),
            "point_count": point_count,
            "distinct_x1": int(distinct_x1),
            "distinct_x2": None,
            "eligible": not bool(reason),
            "reason": reason,
        }
        if reason:
            ignored_control_periods.append(dict(row))
            slice_rows.append(dict(row))
            continue
        slice_x_norm = np.asarray([float(x_norm_all[idx]) for idx in idxs], dtype=float)
        design = np.vander(slice_x_norm, 3, increasing=False)
        coeffs, _residuals, rank, _singular = np.linalg.lstsq(design, slice_y, rcond=None)
        coeff_list = [float(v) for v in coeffs.tolist()]
        if int(rank) < int(design.shape[1]) or len(coeff_list) != 3:
            row["eligible"] = False
            row["reason"] = _td_perf_curve_control_period_reason(
                point_count=point_count,
                distinct_x1=distinct_x1,
                fit_failed=True,
            )
            ignored_control_periods.append(dict(row))
            slice_rows.append(dict(row))
            continue
        eligible_control_period_values.append(float(cp_value))
        row["eligible"] = True
        row["reason"] = ""
        slice_rows.append(dict(row))
        slice_models.append(
            {
                "control_period": float(cp_value),
                "coeffs": coeff_list,
                "point_count": point_count,
                "distinct_x1": int(distinct_x1),
            }
        )

    diagnostics.update(
        {
            "eligible_control_period_values": [float(v) for v in eligible_control_period_values],
            "ignored_control_periods": ignored_control_periods,
            "slice_models": slice_models,
            "slice_rows": slice_rows,
        }
    )
    return diagnostics


def _td_perf_predict_quadratic_curve_control_period(
    model: Mapping[str, object],
    x_values: Iterable[float],
    control_period,
) -> list[float]:
    np = _td_perf_import_numpy()
    x_list = [float(v) for v in x_values]
    count = len(x_list)
    if count <= 0:
        return []
    if control_period is None:
        raise ValueError("Control-period-aware curve prediction requires control_period.")
    if isinstance(control_period, Iterable) and not isinstance(control_period, (str, bytes)):
        cp_values = [float(v) for v in control_period]
        if len(cp_values) != count:
            raise ValueError("control_period iterable length must match x inputs.")
    else:
        cp_values = [float(control_period)] * count
    x_center = float(model.get("x_center") or 0.0)
    x_scale = float(model.get("x_scale") or 1.0) or 1.0
    x_norm = (np.asarray(x_list, dtype=float) - x_center) / x_scale
    cp_norm, _cp_center, _cp_scale = _td_perf_surface_normalize_control_period(
        cp_values,
        center=float(model.get("cp_center") or 0.0),
        scale=float(model.get("cp_scale") or 1.0),
    )
    coeff_cp_models = [
        np.asarray([float(v) for v in coeffs], dtype=float)
        for coeffs in (model.get("coeff_cp_models") or [])
    ]
    if len(coeff_cp_models) != 3:
        return []
    coeff_columns = [np.poly1d(coeffs)(cp_norm) for coeffs in coeff_cp_models]
    y_hat = (
        (coeff_columns[0] * (x_norm ** 2))
        + (coeff_columns[1] * x_norm)
        + coeff_columns[2]
    )
    return [float(v) for v in y_hat.tolist()]


def _td_perf_fit_quadratic_curve_control_period_model(
    xs: list[float],
    ys: list[float],
    control_periods: Sequence[float],
) -> dict[str, object] | None:
    np = _td_perf_import_numpy()
    if len(xs) != len(ys) or len(xs) != len(control_periods):
        return None
    x_arr = np.asarray([float(v) for v in xs], dtype=float)
    y_arr = np.asarray([float(v) for v in ys], dtype=float)
    cp_arr = np.asarray([float(v) for v in control_periods], dtype=float)
    if not bool(np.all(np.isfinite(x_arr) & np.isfinite(y_arr) & np.isfinite(cp_arr))):
        return None
    if len(x_arr) < 3:
        return None

    support = _td_perf_analyze_quadratic_curve_control_period_fit_support(xs, ys, control_periods)
    cp_values = [float(v) for v in (support.get("eligible_control_period_values") or [])]
    slice_models = [dict(item) for item in (support.get("slice_models") or []) if isinstance(item, Mapping)]
    ignored_control_periods = [dict(item) for item in (support.get("ignored_control_periods") or []) if isinstance(item, Mapping)]
    x_center = float(support.get("x_center") or 0.0)
    x_scale = float(support.get("x_scale") or 1.0)
    if len(cp_values) < 2 or len(slice_models) < 2:
        return None

    coeff_rows = [[float(v) for v in (slice_model.get("coeffs") or [])] for slice_model in slice_models]
    cp_norm, cp_center, cp_scale = _td_perf_surface_normalize_control_period(cp_values)
    cp_degree = 1 if len(cp_values) == 2 else 2
    coeff_matrix_arr = np.asarray(coeff_rows, dtype=float)
    coeff_cp_models: list[list[float]] = []
    coeffs_at_center: list[float] = []
    for basis_idx in range(coeff_matrix_arr.shape[1]):
        coeff_values = coeff_matrix_arr[:, basis_idx]
        cp_coeffs = np.polyfit(cp_norm, coeff_values, cp_degree)
        coeff_cp_models.append([float(v) for v in cp_coeffs.tolist()])
        coeffs_at_center.append(float(np.poly1d(cp_coeffs)(0.0)))

    y_hat = np.asarray(
        _td_perf_predict_quadratic_curve_control_period(
            {
                "x_center": float(x_center),
                "x_scale": float(x_scale),
                "cp_center": float(cp_center),
                "cp_scale": float(cp_scale),
                "coeff_cp_models": coeff_cp_models,
            },
            x_arr.tolist(),
            cp_arr.tolist(),
        ),
        dtype=float,
    )
    params: dict[str, object] = {
        "cp_center": float(cp_center),
        "cp_scale": float(cp_scale),
        "control_period_degree": int(cp_degree),
        "control_period_values": [float(v) for v in cp_values],
        "eligible_control_period_values": [float(v) for v in cp_values],
        "ignored_control_periods": [dict(entry) for entry in ignored_control_periods],
        "fit_domain_control_period": [float(min(cp_values)), float(max(cp_values))],
        "coeff_cp_models": [[float(v) for v in coeffs] for coeffs in coeff_cp_models],
    }
    for basis_idx, coeffs in enumerate(coeff_cp_models):
        params[f"basis_{basis_idx}_cp_coeffs"] = [float(v) for v in coeffs]
    model = _td_perf_finalize_model(
        fit_family=TD_PERF_FIT_FAMILY_QUADRATIC_CURVE_CONTROL_PERIOD,
        fit_mode=TD_PERF_FIT_MODE_POLYNOMIAL,
        equation=_td_perf_fmt_curve_control_period_equation(coeff_cp_models),
        x_norm_equation=_td_perf_fmt_curve_control_period_normalization(
            x_center,
            x_scale,
            cp_center,
            cp_scale,
        ),
        params=params,
        param_count=(len(coeff_cp_models) * (cp_degree + 1)),
        x_values=list(range(len(y_arr))),
        y_true=y_arr,
        y_hat=y_hat,
        composite_score=False,
        extra={
            "coeffs": [float(v) for v in coeffs_at_center],
            "coeff_cp_models": [[float(v) for v in coeffs] for coeffs in coeff_cp_models],
            "x_center": float(x_center),
            "x_scale": float(x_scale),
            "cp_center": float(cp_center),
            "cp_scale": float(cp_scale),
            "control_period_values": [float(v) for v in cp_values],
            "eligible_control_period_values": [float(v) for v in cp_values],
            "ignored_control_periods": [dict(entry) for entry in ignored_control_periods],
            "control_period_degree": int(cp_degree),
            "fit_domain_control_period": [float(min(cp_values)), float(max(cp_values))],
            "slice_models": slice_models,
            "solver": "slice_polyfit_curve",
        },
    )
    warning_text = _td_perf_format_curve_control_period_warning(ignored_control_periods)
    if warning_text:
        _td_perf_append_fit_warning(model, warning_text)
    return model


def _td_perf_curve_cp_balanced_aggregate(
    xs: Sequence[float],
    ys: Sequence[float],
    control_periods: Sequence[float],
    *,
    eligible_control_period_values: Sequence[float],
) -> dict[str, list[float] | list[int]]:
    eligible_keys = {round(float(value), 12) for value in (eligible_control_period_values or [])}
    curves: dict[str, list[tuple[float, float, str]]] = {}
    for idx, (x_value, y_value, cp_value) in enumerate(zip(xs, ys, control_periods)):
        cp_key = round(float(cp_value), 12)
        if cp_key not in eligible_keys:
            continue
        curves.setdefault(f"cp_{cp_key:.12g}", []).append((float(x_value), float(y_value), f"cp_{idx}"))
    return td_perf_build_aggregate_curve(curves, max_bins=24, min_serials_per_bin=1, return_meta=True)


def _td_perf_curve_cp_detect_low_x_window(
    x_values,
    residual_values,
    control_period_values,
):
    np = _td_perf_import_numpy()
    x_arr = np.asarray([float(value) for value in x_values], dtype=float)
    residual_arr = np.asarray([float(value) for value in residual_values], dtype=float)
    cp_arr = np.asarray([float(value) for value in control_period_values], dtype=float)
    info: dict[str, object] = {
        "low_x_breakpoint": None,
        "low_x_window_enabled": False,
        "candidate_cutoff": None,
        "residual_abs_threshold": 0.0,
        "low_x_bins": [],
        "point_bin_signs": {},
    }
    if len(x_arr) < 3:
        return info
    x_min = float(np.min(x_arr))
    x_max = float(np.max(x_arr))
    x_span = float(x_max - x_min)
    if not math.isfinite(x_span) or x_span <= 0.0:
        return info

    abs_residuals = np.abs(residual_arr)
    median_abs = float(np.median(abs_residuals))
    mad_abs = float(np.median(np.abs(abs_residuals - median_abs)))
    residual_abs_threshold = float(median_abs + (1.5 * mad_abs))
    candidate_cutoff = float(x_min + (0.30 * x_span))
    candidate_indices = [idx for idx, x_value in enumerate(x_arr.tolist()) if float(x_value) <= candidate_cutoff]
    if len(candidate_indices) < 3:
        info["candidate_cutoff"] = candidate_cutoff
        info["residual_abs_threshold"] = residual_abs_threshold
        return info

    ordered_candidate_indices = sorted(candidate_indices, key=lambda idx: (float(x_arr[idx]), idx))
    bin_count = min(6, max(3, int(math.floor(math.sqrt(len(ordered_candidate_indices))))))
    if len(ordered_candidate_indices) < bin_count:
        bin_count = len(ordered_candidate_indices)
    if bin_count < 1:
        return info

    bins: list[dict[str, object]] = []
    point_bin_signs: dict[int, int] = {}
    for bin_index, raw_chunk in enumerate(np.array_split(np.asarray(ordered_candidate_indices, dtype=int), bin_count)):
        idxs = [int(value) for value in raw_chunk.tolist()]
        if not idxs:
            continue
        bin_x = np.asarray([float(x_arr[idx]) for idx in idxs], dtype=float)
        bin_residuals = np.asarray([float(residual_arr[idx]) for idx in idxs], dtype=float)
        median_residual = float(np.median(bin_residuals))
        median_sign = 1 if median_residual > 0.0 else (-1 if median_residual < 0.0 else 0)
        if median_sign == 0:
            sign_consistency = 0.0
        else:
            sign_consistency = float(
                sum(
                    1
                    for value in bin_residuals.tolist()
                    if (value > 0.0 and median_sign > 0) or (value < 0.0 and median_sign < 0)
                )
                / max(1, len(idxs))
            )
        distinct_control_periods = len({round(float(cp_arr[idx]), 12) for idx in idxs})
        significant = bool(
            median_sign != 0
            and abs(median_residual) >= residual_abs_threshold
            and distinct_control_periods >= 2
            and sign_consistency >= 0.7
        )
        bins.append(
            {
                "bin_index": int(bin_index),
                "left": float(np.min(bin_x)),
                "right": float(np.max(bin_x)),
                "point_count": int(len(idxs)),
                "distinct_control_periods": int(distinct_control_periods),
                "median_residual": float(median_residual),
                "sign": int(median_sign),
                "sign_consistency": float(sign_consistency),
                "significant": bool(significant),
            }
        )
        for idx in idxs:
            point_bin_signs[int(idx)] = int(median_sign)

    last_significant_index = -1
    for bin_row in bins:
        if bool(bin_row.get("significant")) and int(bin_row.get("bin_index") or 0) == (last_significant_index + 1):
            last_significant_index = int(bin_row.get("bin_index") or 0)
            continue
        break

    info["candidate_cutoff"] = float(candidate_cutoff)
    info["residual_abs_threshold"] = float(residual_abs_threshold)
    info["low_x_bins"] = bins
    if last_significant_index >= 0:
        last_bin = bins[last_significant_index]
        breakpoint = float(last_bin.get("right") or candidate_cutoff)
        info["low_x_breakpoint"] = breakpoint
        info["low_x_window_enabled"] = True
        info["point_bin_signs"] = {
            idx: sign
            for idx, sign in point_bin_signs.items()
            if float(x_arr[idx]) <= breakpoint
        }
    return info


def _td_perf_curve_cp_point_weights(
    x_values,
    residual_values,
    *,
    low_x_window_enabled: bool,
    low_x_breakpoint: float | None,
    point_bin_signs: Mapping[int, object],
):
    np = _td_perf_import_numpy()
    x_arr = np.asarray([float(value) for value in x_values], dtype=float)
    residual_arr = np.asarray([float(value) for value in residual_values], dtype=float)
    if not low_x_window_enabled or low_x_breakpoint is None:
        return np.ones(len(x_arr), dtype=float)
    weights = np.full(len(x_arr), 0.6, dtype=float)
    for idx, (x_value, residual_value) in enumerate(zip(x_arr.tolist(), residual_arr.tolist())):
        if float(x_value) > float(low_x_breakpoint):
            continue
        local_sign_raw = point_bin_signs.get(int(idx), 0)
        try:
            local_sign = int(local_sign_raw)
        except Exception:
            local_sign = 0
        residual_sign = 1 if residual_value > 0.0 else (-1 if residual_value < 0.0 else 0)
        weights[idx] = 2.5 if (local_sign != 0 and local_sign == residual_sign) else 1.0
    return weights


def _td_perf_curve_cp_fit_residual_slice(
    x_norm_values,
    residual_values,
    sample_weights,
    *,
    penalty_multiplier: float,
):
    np = _td_perf_import_numpy()
    x_norm = np.asarray([float(value) for value in x_norm_values], dtype=float)
    residual_arr = np.asarray([float(value) for value in residual_values], dtype=float)
    weight_arr = np.asarray([float(value) for value in sample_weights], dtype=float)
    if len(x_norm) != len(residual_arr) or len(x_norm) != len(weight_arr) or len(x_norm) < 3:
        return None
    design = np.column_stack([x_norm ** 2, x_norm, np.ones_like(x_norm)])
    ridge_diag = float(max(penalty_multiplier, 1e-9)) * np.asarray([8.0, 2.0, 0.5], dtype=float)
    xtwx = design.T.dot(weight_arr[:, None] * design) + np.diag(ridge_diag)
    xtwy = design.T.dot(weight_arr * residual_arr)
    try:
        coeffs = np.linalg.solve(xtwx, xtwy)
    except Exception:
        return None
    return np.asarray(coeffs, dtype=float)


def _td_perf_predict_hybrid_quadratic_residual_control_period(
    model: Mapping[str, object],
    x_values: Iterable[float],
    control_period,
) -> list[float]:
    np = _td_perf_import_numpy()
    x_list = [float(value) for value in x_values]
    count = len(x_list)
    if count <= 0:
        return []
    if control_period is None:
        raise ValueError("Control-period-aware curve prediction requires control_period.")
    if isinstance(control_period, Iterable) and not isinstance(control_period, (str, bytes)):
        cp_values = [float(value) for value in control_period]
        if len(cp_values) != count:
            raise ValueError("control_period iterable length must match x inputs.")
    else:
        cp_values = [float(control_period)] * count
    x_arr = np.asarray(x_list, dtype=float)
    base_params = dict(model.get("base_params") or (model.get("params") or {}).get("base_params") or {})
    base = (
        float(base_params.get("b") or 0.0)
        + (float(base_params.get("m") or 0.0) * x_arr)
        + (
            float(base_params.get("A") or 0.0)
            * (1.0 - np.exp(-float(base_params.get("k") or 0.0) * x_arr))
        )
    )
    x_center = float(model.get("x_center") or 0.0)
    x_scale = float(model.get("x_scale") or 1.0) or 1.0
    x_norm = (x_arr - x_center) / x_scale
    cp_norm, _cp_center, _cp_scale = _td_perf_surface_normalize_control_period(
        cp_values,
        center=float(model.get("cp_center") or 0.0),
        scale=float(model.get("cp_scale") or 1.0),
    )
    residual_cp_models = [
        np.asarray([float(value) for value in coeffs], dtype=float)
        for coeffs in (model.get("residual_cp_models") or model.get("coeff_cp_models") or [])
    ]
    if len(residual_cp_models) != 3:
        return [float(value) for value in base.tolist()]
    residual_coeff_columns = [np.poly1d(coeffs)(cp_norm) for coeffs in residual_cp_models]
    residual = (
        (residual_coeff_columns[0] * (x_norm ** 2))
        + (residual_coeff_columns[1] * x_norm)
        + residual_coeff_columns[2]
    )
    return [float(value) for value in (base + residual).tolist()]


def _td_perf_fit_hybrid_quadratic_residual_control_period_candidate(
    xs: list[float],
    ys: list[float],
    control_periods: Sequence[float],
    *,
    support: Mapping[str, object],
    penalty_multiplier: float,
) -> tuple[dict[str, object] | None, dict[str, object]]:
    np = _td_perf_import_numpy()
    diagnostics: dict[str, object] = {
        "reason": "",
        "low_x_breakpoint": None,
        "low_x_window_enabled": False,
        "support_profile": {},
        "base_fit_family": "",
        "base_params": {},
        "residual_cp_models": [],
    }
    if len(xs) != len(ys) or len(xs) != len(control_periods):
        diagnostics["reason"] = "input vectors are inconsistent"
        return None, diagnostics

    x_arr = np.asarray([float(value) for value in xs], dtype=float)
    y_arr = np.asarray([float(value) for value in ys], dtype=float)
    cp_arr = np.asarray([float(value) for value in control_periods], dtype=float)
    if not bool(np.all(np.isfinite(x_arr) & np.isfinite(y_arr) & np.isfinite(cp_arr))):
        diagnostics["reason"] = "input vectors contain non-finite values"
        return None, diagnostics

    eligible_control_period_values = [float(value) for value in (support.get("eligible_control_period_values") or [])]
    ignored_control_periods = [dict(item) for item in (support.get("ignored_control_periods") or []) if isinstance(item, Mapping)]
    if len(eligible_control_period_values) < 2:
        diagnostics["reason"] = "at least two eligible control periods are required"
        return None, diagnostics

    aggregate_curve = _td_perf_curve_cp_balanced_aggregate(
        x_arr.tolist(),
        y_arr.tolist(),
        cp_arr.tolist(),
        eligible_control_period_values=eligible_control_period_values,
    )
    aggregate_x = [float(value) for value in (aggregate_curve.get("x") or [])]
    aggregate_y = [float(value) for value in (aggregate_curve.get("y") or [])]
    if len(aggregate_x) < 4 or len(aggregate_y) < 4:
        diagnostics["reason"] = "cp-balanced aggregate curve did not produce enough support points"
        diagnostics["support_profile"] = {"aggregate_curve": aggregate_curve}
        return None, diagnostics

    base_model = _td_perf_fit_hybrid_saturating_linear_model(
        aggregate_x,
        aggregate_y,
        fit_mode=TD_PERF_FIT_FAMILY_HYBRID_QUADRATIC_RESIDUAL_CONTROL_PERIOD,
    )
    if not isinstance(base_model, dict):
        diagnostics["reason"] = "global backbone fit failed"
        diagnostics["support_profile"] = {"aggregate_curve": aggregate_curve}
        return None, diagnostics

    base_pred = np.asarray(td_perf_predict_model(base_model, x_arr.tolist()), dtype=float)
    residual_arr = y_arr - base_pred
    low_x_info = _td_perf_curve_cp_detect_low_x_window(x_arr.tolist(), residual_arr.tolist(), cp_arr.tolist())
    point_weights = _td_perf_curve_cp_point_weights(
        x_arr.tolist(),
        residual_arr.tolist(),
        low_x_window_enabled=bool(low_x_info.get("low_x_window_enabled")),
        low_x_breakpoint=_td_finite_float(low_x_info.get("low_x_breakpoint")),
        point_bin_signs=dict(low_x_info.get("point_bin_signs") or {}),
    )

    x_center = float(support.get("x_center") or 0.0)
    x_scale = float(support.get("x_scale") or 1.0) or 1.0
    x_norm = (x_arr - x_center) / x_scale
    cp_values = [float(value) for value in eligible_control_period_values]
    cp_norm, cp_center, cp_scale = _td_perf_surface_normalize_control_period(cp_values)
    cp_degree = 1 if len(cp_values) == 2 else 2
    cp_key_to_indices: dict[float, list[int]] = {}
    for idx, cp_value in enumerate(cp_arr.tolist()):
        cp_key_to_indices.setdefault(round(float(cp_value), 12), []).append(idx)

    coeff_rows: list[list[float]] = []
    slice_models: list[dict[str, object]] = []
    slice_fit_weights: list[float] = []
    for cp_value in cp_values:
        idxs = cp_key_to_indices.get(round(float(cp_value), 12), [])
        if len(idxs) < 3:
            diagnostics["reason"] = f"residual slice fit lacks support for control period {cp_value:g}"
            diagnostics["support_profile"] = {
                "aggregate_curve": aggregate_curve,
                "low_x_bins": [dict(row) for row in (low_x_info.get("low_x_bins") or []) if isinstance(row, Mapping)],
            }
            return None, diagnostics
        slice_coeffs = _td_perf_curve_cp_fit_residual_slice(
            [float(x_norm[idx]) for idx in idxs],
            [float(residual_arr[idx]) for idx in idxs],
            [float(point_weights[idx]) for idx in idxs],
            penalty_multiplier=penalty_multiplier,
        )
        if slice_coeffs is None or len(slice_coeffs) != 3:
            diagnostics["reason"] = f"residual slice fit failed for control period {cp_value:g}"
            diagnostics["support_profile"] = {
                "aggregate_curve": aggregate_curve,
                "low_x_bins": [dict(row) for row in (low_x_info.get("low_x_bins") or []) if isinstance(row, Mapping)],
            }
            return None, diagnostics
        point_count = int(len(idxs))
        distinct_x1 = len({round(float(x_arr[idx]), 12) for idx in idxs})
        slice_weight = float(min(point_count, 4))
        coeff_rows.append([float(value) for value in slice_coeffs.tolist()])
        slice_fit_weights.append(slice_weight)
        slice_models.append(
            {
                "control_period": float(cp_value),
                "residual_coeffs": [float(value) for value in slice_coeffs.tolist()],
                "point_count": int(point_count),
                "distinct_x1": int(distinct_x1),
                "slice_weight": float(slice_weight),
            }
        )

    coeff_matrix_arr = np.asarray(coeff_rows, dtype=float)
    slice_weight_arr = np.asarray(slice_fit_weights, dtype=float)
    residual_cp_models: list[list[float]] = []
    residual_coeffs_at_center: list[float] = []
    for basis_idx in range(coeff_matrix_arr.shape[1]):
        coeff_values = coeff_matrix_arr[:, basis_idx]
        cp_coeffs = np.polyfit(cp_norm, coeff_values, cp_degree, w=slice_weight_arr)
        residual_cp_models.append([float(value) for value in cp_coeffs.tolist()])
        residual_coeffs_at_center.append(float(np.poly1d(cp_coeffs)(0.0)))

    y_hat = np.asarray(
        _td_perf_predict_hybrid_quadratic_residual_control_period(
            {
                "base_params": dict(base_model.get("params") or {}),
                "residual_cp_models": residual_cp_models,
                "x_center": float(x_center),
                "x_scale": float(x_scale),
                "cp_center": float(cp_center),
                "cp_scale": float(cp_scale),
            },
            x_arr.tolist(),
            cp_arr.tolist(),
        ),
        dtype=float,
    )

    support_profile = {
        "aggregate_curve": {
            "x": [float(value) for value in aggregate_x],
            "y": [float(value) for value in aggregate_y],
            "serial_support": [int(value) for value in (aggregate_curve.get("serial_support") or [])],
            "edge_weight": [float(value) for value in (aggregate_curve.get("edge_weight") or [])],
        },
        "candidate_cutoff": low_x_info.get("candidate_cutoff"),
        "residual_abs_threshold": float(low_x_info.get("residual_abs_threshold") or 0.0),
        "low_x_bins": [dict(row) for row in (low_x_info.get("low_x_bins") or []) if isinstance(row, Mapping)],
        "slice_fit_weights": [float(value) for value in slice_fit_weights],
    }
    params: dict[str, object] = {
        "base_params": dict(base_model.get("params") or {}),
        "cp_center": float(cp_center),
        "cp_scale": float(cp_scale),
        "control_period_degree": int(cp_degree),
        "control_period_values": [float(value) for value in cp_values],
        "eligible_control_period_values": [float(value) for value in cp_values],
        "ignored_control_periods": [dict(entry) for entry in ignored_control_periods],
        "fit_domain_control_period": [float(min(cp_values)), float(max(cp_values))],
        "residual_cp_models": [[float(value) for value in coeffs] for coeffs in residual_cp_models],
        "low_x_breakpoint": _td_finite_float(low_x_info.get("low_x_breakpoint")),
        "low_x_window_enabled": bool(low_x_info.get("low_x_window_enabled")),
        "support_profile": support_profile,
        "stabilization_passes": 0,
        "fallback_used": False,
    }
    for basis_idx, coeffs in enumerate(residual_cp_models):
        params[f"basis_{basis_idx}_cp_coeffs"] = [float(value) for value in coeffs]
    model = _td_perf_finalize_model(
        fit_family=TD_PERF_FIT_FAMILY_HYBRID_QUADRATIC_RESIDUAL_CONTROL_PERIOD,
        fit_mode=TD_PERF_FIT_FAMILY_HYBRID_QUADRATIC_RESIDUAL_CONTROL_PERIOD,
        equation=_td_perf_fmt_hybrid_curve_control_period_equation(base_model.get("equation"), residual_cp_models),
        x_norm_equation=_td_perf_fmt_curve_control_period_normalization(
            float(x_center),
            float(x_scale),
            float(cp_center),
            float(cp_scale),
        ),
        params=params,
        param_count=(4 + (len(residual_cp_models) * (cp_degree + 1))),
        x_values=x_arr,
        y_true=y_arr,
        y_hat=y_hat,
        composite_score=False,
        extra={
            "coeffs": [float(value) for value in residual_coeffs_at_center],
            "coeff_cp_models": [[float(value) for value in coeffs] for coeffs in residual_cp_models],
            "residual_cp_models": [[float(value) for value in coeffs] for coeffs in residual_cp_models],
            "base_fit_family": str(base_model.get("fit_family") or ""),
            "base_params": dict(base_model.get("params") or {}),
            "x_center": float(x_center),
            "x_scale": float(x_scale),
            "cp_center": float(cp_center),
            "cp_scale": float(cp_scale),
            "control_period_values": [float(value) for value in cp_values],
            "eligible_control_period_values": [float(value) for value in cp_values],
            "ignored_control_periods": [dict(entry) for entry in ignored_control_periods],
            "control_period_degree": int(cp_degree),
            "fit_domain": [float(np.min(x_arr)), float(np.max(x_arr))],
            "fit_domain_control_period": [float(min(cp_values)), float(max(cp_values))],
            "slice_models": slice_models,
            "low_x_breakpoint": _td_finite_float(low_x_info.get("low_x_breakpoint")),
            "low_x_window_enabled": bool(low_x_info.get("low_x_window_enabled")),
            "stabilization_passes": 0,
            "fallback_used": False,
            "support_profile": support_profile,
            "solver": "hybrid_curve_cp_residual",
        },
    )
    warning_text = _td_perf_format_curve_control_period_warning(ignored_control_periods)
    if warning_text:
        _td_perf_append_fit_warning(model, warning_text)

    diagnostics.update(
        {
            "low_x_breakpoint": model.get("low_x_breakpoint"),
            "low_x_window_enabled": bool(model.get("low_x_window_enabled")),
            "support_profile": support_profile,
            "base_fit_family": str(base_model.get("fit_family") or ""),
            "base_params": dict(base_model.get("params") or {}),
            "residual_cp_models": [[float(value) for value in coeffs] for coeffs in residual_cp_models],
        }
    )
    return model, diagnostics


def _td_perf_curve_cp_stability_checks(model: Mapping[str, object]) -> tuple[bool, list[dict[str, object]]]:
    np = _td_perf_import_numpy()
    x_domain = model.get("fit_domain")
    if not isinstance(x_domain, Sequence) or isinstance(x_domain, (str, bytes)) or len(x_domain) < 2:
        return True, []
    try:
        x_min = float(x_domain[0])
        x_max = float(x_domain[1])
    except Exception:
        return True, []
    if not math.isfinite(x_min) or not math.isfinite(x_max) or x_max <= x_min:
        return True, []

    cp_values = [float(value) for value in (model.get("control_period_values") or [])]
    cp_eval_values = sorted(
        {
            *cp_values,
            *[
                float((cp_values[idx] + cp_values[idx + 1]) / 2.0)
                for idx in range(max(0, len(cp_values) - 1))
            ],
        }
    )
    if not cp_eval_values:
        return True, []

    x_grid = np.linspace(float(x_min), float(x_max), 220)
    low_x_breakpoint = _td_finite_float(model.get("low_x_breakpoint")) if bool(model.get("low_x_window_enabled")) else None
    rows: list[dict[str, object]] = []
    stable = True
    for cp_value in cp_eval_values:
        y_values = np.asarray(
            _td_perf_predict_hybrid_quadratic_residual_control_period(model, x_grid.tolist(), cp_value),
            dtype=float,
        )
        if len(y_values) != len(x_grid):
            continue
        dx = np.diff(x_grid)
        dy = np.diff(y_values)
        slope = dy / np.where(dx == 0.0, 1.0, dx)
        mid_x = (x_grid[:-1] + x_grid[1:]) / 2.0
        positive_slopes = np.asarray([float(value) for value in slope.tolist() if float(value) > 0.0], dtype=float)
        median_positive_slope = float(np.median(positive_slopes)) if positive_slopes.size else 0.0
        slope_threshold = float(abs(median_positive_slope) * 0.02)
        negative_mask = np.asarray(
            [
                bool((low_x_breakpoint is None or float(midpoint) > float(low_x_breakpoint)) and float(delta) < -slope_threshold)
                for midpoint, delta in zip(mid_x.tolist(), slope.tolist())
            ],
            dtype=bool,
        )
        negative_interval_count = 0
        in_interval = False
        for is_negative in negative_mask.tolist():
            if is_negative and not in_interval:
                negative_interval_count += 1
                in_interval = True
            elif not is_negative:
                in_interval = False
        worst_negative_slope = float(np.min(slope[negative_mask])) if bool(np.any(negative_mask)) else 0.0
        rows.append(
            {
                "control_period": float(cp_value),
                "negative_interval_count": int(negative_interval_count),
                "median_positive_slope": float(median_positive_slope),
                "slope_threshold": float(slope_threshold),
                "worst_negative_slope": float(worst_negative_slope),
            }
        )
        if negative_interval_count > 1:
            stable = False
    return stable, rows


def _td_perf_curve_cp_apply_fallback_metadata(
    legacy_model: Mapping[str, object],
    *,
    reason: str,
    diagnostics: Mapping[str, object],
    stabilization_passes: int,
) -> dict[str, object]:
    fallback_model = dict(legacy_model or {})
    fallback_model["fallback_used"] = True
    fallback_model["fallback_reason"] = str(reason or "").strip()
    fallback_model["stabilization_passes"] = int(stabilization_passes)
    fallback_model["low_x_breakpoint"] = diagnostics.get("low_x_breakpoint")
    fallback_model["low_x_window_enabled"] = bool(diagnostics.get("low_x_window_enabled"))
    fallback_model["support_profile"] = diagnostics.get("support_profile") if isinstance(diagnostics.get("support_profile"), Mapping) else {}
    fallback_model["base_fit_family"] = str(diagnostics.get("base_fit_family") or "")
    fallback_model["base_params"] = (
        dict(diagnostics.get("base_params") or {})
        if isinstance(diagnostics.get("base_params"), Mapping)
        else {}
    )
    fallback_model["residual_cp_models"] = [
        [float(value) for value in coeffs]
        for coeffs in (diagnostics.get("residual_cp_models") or [])
        if isinstance(coeffs, Sequence) and not isinstance(coeffs, (str, bytes))
    ]
    _td_perf_append_fit_warning(
        fallback_model,
        f"Stabilized CP curve fit fell back to legacy quadratic CP model: {str(reason or '').strip()}",
    )
    return fallback_model


def _td_perf_fit_hybrid_quadratic_residual_control_period_model(
    xs: list[float],
    ys: list[float],
    control_periods: Sequence[float],
    *,
    support: Mapping[str, object] | None = None,
    legacy_model: Mapping[str, object] | None = None,
) -> dict[str, object] | None:
    support_data = (
        dict(support or {})
        if isinstance(support, Mapping)
        else _td_perf_analyze_quadratic_curve_control_period_fit_support(xs, ys, control_periods)
    )
    legacy_baseline = dict(legacy_model or {}) if isinstance(legacy_model, Mapping) else _td_perf_fit_quadratic_curve_control_period_model(xs, ys, control_periods)
    candidate, diagnostics = _td_perf_fit_hybrid_quadratic_residual_control_period_candidate(
        xs,
        ys,
        control_periods,
        support=support_data,
        penalty_multiplier=1.0,
    )
    if not isinstance(candidate, dict):
        if isinstance(legacy_baseline, Mapping):
            return _td_perf_curve_cp_apply_fallback_metadata(
                legacy_baseline,
                reason=str(diagnostics.get("reason") or "stabilized candidate fit failed"),
                diagnostics=diagnostics,
                stabilization_passes=0,
            )
        return None

    stable, stability_rows = _td_perf_curve_cp_stability_checks(candidate)
    support_profile = dict(candidate.get("support_profile") or {})
    support_profile["stability_checks"] = [dict(row) for row in stability_rows]
    candidate["support_profile"] = support_profile
    candidate["stabilization_passes"] = 0
    candidate["fallback_used"] = False

    stabilization_passes = 0
    if not stable:
        stabilization_passes = 1
        stabilized_candidate, stabilized_diagnostics = _td_perf_fit_hybrid_quadratic_residual_control_period_candidate(
            xs,
            ys,
            control_periods,
            support=support_data,
            penalty_multiplier=2.0,
        )
        if not isinstance(stabilized_candidate, dict):
            if isinstance(legacy_baseline, Mapping):
                return _td_perf_curve_cp_apply_fallback_metadata(
                    legacy_baseline,
                    reason=str(stabilized_diagnostics.get("reason") or "stabilization refit failed"),
                    diagnostics=stabilized_diagnostics,
                    stabilization_passes=stabilization_passes,
                )
            return candidate
        stable, stability_rows = _td_perf_curve_cp_stability_checks(stabilized_candidate)
        support_profile = dict(stabilized_candidate.get("support_profile") or {})
        support_profile["stability_checks"] = [dict(row) for row in stability_rows]
        stabilized_candidate["support_profile"] = support_profile
        stabilized_candidate["stabilization_passes"] = stabilization_passes
        stabilized_candidate["fallback_used"] = False
        candidate = stabilized_candidate
        diagnostics = stabilized_diagnostics
        if not stable and isinstance(legacy_baseline, Mapping):
            return _td_perf_curve_cp_apply_fallback_metadata(
                legacy_baseline,
                reason="stabilization pass still found offshoots outside the inferred low-x window",
                diagnostics=diagnostics,
                stabilization_passes=stabilization_passes,
            )

    try:
        candidate_rmse = float(candidate.get("rmse"))
    except Exception:
        candidate_rmse = float("inf")
    try:
        legacy_rmse = float((legacy_baseline or {}).get("rmse"))
    except Exception:
        legacy_rmse = float("inf")
    if (
        isinstance(legacy_baseline, Mapping)
        and math.isfinite(candidate_rmse)
        and math.isfinite(legacy_rmse)
        and legacy_rmse > 0.0
        and candidate_rmse > (1.15 * legacy_rmse)
    ):
        return _td_perf_curve_cp_apply_fallback_metadata(
            legacy_baseline,
            reason=(
                "stabilized candidate RMSE exceeded the legacy quadratic CP baseline "
                f"({candidate_rmse:.4g} vs {legacy_rmse:.4g})"
            ),
            diagnostics=diagnostics,
            stabilization_passes=stabilization_passes,
        )

    candidate["stabilization_passes"] = int(stabilization_passes)
    candidate["fallback_used"] = False
    return candidate


def _td_perf_fit_quadratic_surface_iterative(
    x1_arr,
    x2_arr,
    y_arr,
    *,
    fit_mode: str,
    x1n,
    x2n,
    x1_center: float,
    x1_scale: float,
    x2_center: float,
    x2_scale: float,
    design,
) -> dict[str, object] | None:
    np = _td_perf_import_numpy()
    term_count = int(design.shape[1])
    if len(y_arr) < term_count:
        return None
    y_center = float(np.median(y_arr))
    y_std = float(np.std(y_arr))
    y_span = float(np.max(y_arr) - np.min(y_arr))
    y_scale = max(y_std, y_span / 4.0, 1e-9)
    y_norm = (np.asarray(y_arr, dtype=float) - y_center) / y_scale
    low_score = _td_perf_surface_low_score(x1n, x2n, y_norm)
    weights = np.ones(len(y_arr), dtype=float)
    prev_coeffs = None
    coeffs_norm = None
    final_solver = "lstsq"
    final_cond = float(np.linalg.cond(design))
    final_ridge_alpha = 0.0
    iterations = 0
    converged = False

    for iteration in range(1, 13):
        sqrt_w = np.sqrt(np.asarray(weights, dtype=float)).reshape(-1, 1)
        weighted_design = np.asarray(design, dtype=float) * sqrt_w
        weighted_y = np.asarray(y_norm, dtype=float) * sqrt_w[:, 0]
        coeffs_iter, solver, cond_number, ridge_alpha = _td_perf_surface_solve_linear_system(weighted_design, weighted_y)
        y_hat_norm = np.asarray(design, dtype=float).dot(np.asarray(coeffs_iter, dtype=float))
        residual_norm = y_hat_norm - y_norm
        robust = 1.0 / np.maximum(1.0, np.abs(residual_norm) / 1.5)
        asym = 1.0 + (2.5 * low_score * np.maximum(residual_norm, 0.0))
        new_weights = np.clip(robust * asym, 0.2, 8.0)

        coeff_delta = float("inf")
        if prev_coeffs is not None:
            denom = max(float(np.linalg.norm(prev_coeffs)), 1e-12)
            coeff_delta = float(np.linalg.norm(np.asarray(coeffs_iter, dtype=float) - np.asarray(prev_coeffs, dtype=float)) / denom)
        weight_delta = float(np.sqrt(np.mean((new_weights - np.asarray(weights, dtype=float)) ** 2)))

        coeffs_norm = np.asarray(coeffs_iter, dtype=float)
        final_solver = solver
        final_cond = float(cond_number)
        final_ridge_alpha = float(ridge_alpha)
        iterations = iteration

        if prev_coeffs is not None and (coeff_delta < 1e-6 or weight_delta < 1e-4):
            converged = True
            weights = new_weights
            break

        prev_coeffs = np.asarray(coeffs_iter, dtype=float)
        weights = new_weights

    if coeffs_norm is None:
        return None

    coeffs_raw = np.asarray(coeffs_norm, dtype=float) * float(y_scale)
    coeffs_raw[0] = float(coeffs_raw[0] + y_center)
    y_hat = np.asarray(design, dtype=float).dot(coeffs_raw)
    coeff_list = [float(v) for v in coeffs_raw.tolist()]
    model = _td_perf_finalize_model(
        fit_family=TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE,
        fit_mode=fit_mode,
        equation=_td_perf_fmt_surface_equation(coeff_list, TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE),
        x_norm_equation=_td_perf_fmt_surface_normalization(x1_center, x1_scale, x2_center, x2_scale),
        params={f"c{i}": float(v) for i, v in enumerate(coeff_list)},
        param_count=term_count,
        x_values=list(range(len(y_arr))),
        y_true=y_arr,
        y_hat=y_hat,
        composite_score=False,
        extra={
            "coeffs": coeff_list,
            "plot_dimension": "3d",
            "x1_center": float(x1_center),
            "x1_scale": float(x1_scale),
            "x2_center": float(x2_center),
            "x2_scale": float(x2_scale),
            "solver": f"irls_{final_solver}",
            "condition_number": float(final_cond),
            "ridge_alpha": float(final_ridge_alpha),
            "iterations": int(iterations),
            "converged": bool(converged),
            "y_center": float(y_center),
            "y_scale": float(y_scale),
        },
    )
    model["monotonic_violations"] = 0
    model["monotonicity_penalty"] = 0.0
    return model


def _td_perf_fit_quadratic_3input_iterative(
    x1_arr,
    x2_arr,
    x3_arr,
    y_arr,
    *,
    x1n,
    x2n,
    x3n,
    x1_center: float,
    x1_scale: float,
    x2_center: float,
    x2_scale: float,
    x3_center: float,
    x3_scale: float,
    design,
) -> dict[str, object] | None:
    np = _td_perf_import_numpy()
    term_count = int(design.shape[1])
    if len(y_arr) < term_count:
        return None
    y_center = float(np.median(y_arr))
    y_std = float(np.std(y_arr))
    y_span = float(np.max(y_arr) - np.min(y_arr))
    y_scale = max(y_std, y_span / 4.0, 1e-9)
    y_norm = (np.asarray(y_arr, dtype=float) - y_center) / y_scale
    low_score = _td_perf_three_input_low_score(x1n, x2n, x3n, y_norm)
    weights = np.ones(len(y_arr), dtype=float)
    prev_coeffs = None
    coeffs_norm = None
    final_solver = "lstsq"
    final_cond = float(np.linalg.cond(design))
    final_ridge_alpha = 0.0
    iterations = 0
    converged = False

    for iteration in range(1, 13):
        sqrt_w = np.sqrt(np.asarray(weights, dtype=float)).reshape(-1, 1)
        weighted_design = np.asarray(design, dtype=float) * sqrt_w
        weighted_y = np.asarray(y_norm, dtype=float) * sqrt_w[:, 0]
        coeffs_iter, solver, cond_number, ridge_alpha = _td_perf_surface_solve_linear_system(weighted_design, weighted_y)
        y_hat_norm = np.asarray(design, dtype=float).dot(np.asarray(coeffs_iter, dtype=float))
        residual_norm = y_hat_norm - y_norm
        robust = 1.0 / np.maximum(1.0, np.abs(residual_norm) / 1.5)
        asym = 1.0 + (2.5 * low_score * np.maximum(residual_norm, 0.0))
        new_weights = np.clip(robust * asym, 0.2, 8.0)

        coeff_delta = float("inf")
        if prev_coeffs is not None:
            denom = max(float(np.linalg.norm(prev_coeffs)), 1e-12)
            coeff_delta = float(np.linalg.norm(np.asarray(coeffs_iter, dtype=float) - np.asarray(prev_coeffs, dtype=float)) / denom)
        weight_delta = float(np.sqrt(np.mean((new_weights - np.asarray(weights, dtype=float)) ** 2)))

        coeffs_norm = np.asarray(coeffs_iter, dtype=float)
        final_solver = solver
        final_cond = float(cond_number)
        final_ridge_alpha = float(ridge_alpha)
        iterations = iteration

        if prev_coeffs is not None and (coeff_delta < 1e-6 or weight_delta < 1e-4):
            converged = True
            weights = new_weights
            break

        prev_coeffs = np.asarray(coeffs_iter, dtype=float)
        weights = new_weights

    if coeffs_norm is None:
        return None

    coeffs_raw = np.asarray(coeffs_norm, dtype=float) * float(y_scale)
    coeffs_raw[0] = float(coeffs_raw[0] + y_center)
    coeff_list = [float(v) for v in coeffs_raw.tolist()]
    return {
        "coeffs": coeff_list,
        "x1_center": float(x1_center),
        "x1_scale": float(x1_scale),
        "x2_center": float(x2_center),
        "x2_scale": float(x2_scale),
        "x3_center": float(x3_center),
        "x3_scale": float(x3_scale),
        "solver": f"irls_{final_solver}",
        "condition_number": float(final_cond),
        "ridge_alpha": float(final_ridge_alpha),
        "iterations": int(iterations),
        "converged": bool(converged),
        "y_center": float(y_center),
        "y_scale": float(y_scale),
    }


def td_perf_fit_surface_model(
    x1s: list[float],
    x2s: list[float],
    ys: list[float],
    *,
    auto_surface_families: bool = False,
    surface_family: object = None,
    control_periods: Sequence[float] | None = None,
) -> dict[str, object] | None:
    explicit_family = surface_family not in (None, "")
    selected_family = td_perf_normalize_surface_family(
        surface_family if explicit_family else (TD_PERF_FIT_MODE_AUTO_SURFACE if bool(auto_surface_families) else TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE)
    )
    fit_mode = (
        TD_PERF_FIT_MODE_AUTO_SURFACE
        if selected_family == TD_PERF_FIT_MODE_AUTO_SURFACE
        else TD_PERF_FIT_MODE_POLYNOMIAL_SURFACE
    )
    if len(x1s) != len(x2s) or len(x1s) != len(ys) or len(ys) < 3:
        return None
    if selected_family == TD_PERF_FIT_FAMILY_PLANE:
        return _td_perf_fit_surface_family(
            x1s,
            x2s,
            ys,
            family=TD_PERF_FIT_FAMILY_PLANE,
            fit_mode=fit_mode,
        )
    if selected_family == TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE:
        model = _td_perf_fit_surface_family(
            x1s,
            x2s,
            ys,
            family=TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE,
            fit_mode=fit_mode,
        )
        if model or explicit_family:
            return model
        return _td_perf_fit_surface_family(
            x1s,
            x2s,
            ys,
            family=TD_PERF_FIT_FAMILY_PLANE,
            fit_mode=fit_mode,
        )
    if selected_family == TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE_CONTROL_PERIOD:
        if control_periods is None:
            return None
        return _td_perf_fit_quadratic_surface_control_period_model(
            x1s,
            x2s,
            ys,
            control_periods,
            fit_mode=fit_mode,
        )
    candidates = [
        _td_perf_fit_surface_family(
            x1s,
            x2s,
            ys,
            family=TD_PERF_FIT_FAMILY_PLANE,
            fit_mode=fit_mode,
        ),
        _td_perf_fit_surface_family(
            x1s,
            x2s,
            ys,
            family=TD_PERF_FIT_FAMILY_QUADRATIC_SURFACE,
            fit_mode=fit_mode,
        ),
    ]
    return _td_perf_choose_best_model([c for c in candidates if isinstance(c, dict)])


def td_perf_collect_equation_export_rows(
    db_path: Path,
    *,
    run_specs: Sequence[Mapping[str, object]],
    control_period_filter: object = None,
    run_type_filter: object = None,
    progress_cb: Callable[[str], None] | None = None,
) -> list[dict[str, object]]:
    path = Path(db_path).expanduser()
    if not path.exists():
        return []
    support_settings = _td_perf_load_support_settings(path)
    strictness_mode = _td_perf_support_setting_choice(
        support_settings,
        "perf_eq_strictness",
        allowed=set(TD_PERF_EQ_STRICTNESS_PRESETS.keys()),
        default=str(TD_PERF_EQ_DEFAULTS["perf_eq_strictness"]),
    )
    strictness_defaults = dict(TD_PERF_EQ_STRICTNESS_PRESETS.get(strictness_mode) or TD_PERF_EQ_STRICTNESS_PRESETS["medium"])
    x_rel_tol = _td_perf_support_setting_float(
        support_settings,
        "perf_eq_x_rel_tol",
        float(strictness_defaults["perf_eq_x_rel_tol"]),
    )
    x_abs_tol = _td_perf_support_setting_float(
        support_settings,
        "perf_eq_x_abs_tol",
        float(strictness_defaults["perf_eq_x_abs_tol"]),
    )

    unique_specs = _td_perf_unique_run_specs(run_specs)
    out: list[dict[str, object]] = []
    for spec_index, spec in enumerate(unique_specs, start=1):
        run_name = str((spec or {}).get("run_name") or "").strip()
        if not run_name:
            continue
        _td_emit_progress(
            progress_cb,
            f"Collecting cached export rows ({spec_index}/{max(1, len(unique_specs))}): {run_name}",
        )
        display_name = str((spec or {}).get("display_name") or run_name).strip()
        input1_column = str((spec or {}).get("input1_column") or "").strip()
        input2_column = str((spec or {}).get("input2_column") or "").strip()
        output_column = str((spec or {}).get("output_column") or "").strip()
        if not input1_column or not output_column:
            continue
        x1_rows = _td_perf_export_series_for_stat(
            path,
            run_name,
            input1_column,
            "mean",
            control_period_filter=control_period_filter,
            run_type_filter=run_type_filter,
        )
        y_rows = _td_perf_export_series_for_stat(
            path,
            run_name,
            output_column,
            "mean",
            control_period_filter=control_period_filter,
            run_type_filter=run_type_filter,
        )
        if not x1_rows or not y_rows:
            continue
        x1_map = {
            str(row.get("observation_id") or "").strip(): dict(row)
            for row in x1_rows
            if isinstance(row, dict) and str(row.get("observation_id") or "").strip()
        }
        y_map = {
            str(row.get("observation_id") or "").strip(): dict(row)
            for row in y_rows
            if isinstance(row, dict) and str(row.get("observation_id") or "").strip()
        }
        if input2_column:
            x2_rows = _td_perf_export_series_for_stat(
                path,
                run_name,
                input2_column,
                "mean",
                control_period_filter=control_period_filter,
                run_type_filter=run_type_filter,
            )
            x2_map = {
                str(row.get("observation_id") or "").strip(): dict(row)
                for row in x2_rows
                if isinstance(row, dict) and str(row.get("observation_id") or "").strip()
            }
            points_3d: list[dict[str, object]] = []
            for obs_id in sorted(set(x1_map.keys()) & set(x2_map.keys()) & set(y_map.keys())):
                row_x1 = x1_map.get(obs_id) or {}
                row_x2 = x2_map.get(obs_id) or {}
                row_y = y_map.get(obs_id) or {}
                try:
                    x1 = float(row_x1.get("value_num"))
                    x2 = float(row_x2.get("value_num"))
                    y = float(row_y.get("value_num"))
                except Exception:
                    continue
                if not (math.isfinite(x1) and math.isfinite(x2) and math.isfinite(y)):
                    continue
                points_3d.append(
                    {
                        "observation_id": obs_id,
                        "run_name": run_name,
                        "display_name": display_name,
                        "program_title": str(row_y.get("program_title") or row_x1.get("program_title") or row_x2.get("program_title") or "").strip(),
                        "source_run_name": str(row_y.get("source_run_name") or row_x1.get("source_run_name") or row_x2.get("source_run_name") or "").strip(),
                        "control_period": row_y.get("control_period", row_x1.get("control_period", row_x2.get("control_period"))),
                        "x1": x1,
                        "x2": x2,
                        "actual_mean": y,
                    }
                )
            for cluster in _td_perf_cluster_points_3d(points_3d, rel_tol=x_rel_tol, abs_tol=x_abs_tol):
                points = list(cluster.get("points") or [])
                if not points:
                    continue
                first = dict(points[0])
                out.append(
                    {
                        "run_name": run_name,
                        "display_name": display_name,
                        "program_title": _td_perf_join_unique_text([p.get("program_title") for p in points]),
                        "source_run_name": _td_perf_join_unique_text([p.get("source_run_name") for p in points]),
                        "control_period": first.get("control_period"),
                        "condition_label": _td_perf_export_condition_label(first, display_name=display_name),
                        "input_1": float(cluster.get("x1_center") or 0.0),
                        "input_2": float(cluster.get("x2_center") or 0.0),
                        "actual_mean": float(sum(float(p.get("actual_mean") or 0.0) for p in points) / max(1, len(points))),
                        "sample_count": int(len(points)),
                    }
                )
            continue

        points_2d: list[dict[str, object]] = []
        for obs_id in sorted(set(x1_map.keys()) & set(y_map.keys())):
            row_x1 = x1_map.get(obs_id) or {}
            row_y = y_map.get(obs_id) or {}
            try:
                x1 = float(row_x1.get("value_num"))
                y = float(row_y.get("value_num"))
            except Exception:
                continue
            if not (math.isfinite(x1) and math.isfinite(y)):
                continue
            points_2d.append(
                {
                    "observation_id": obs_id,
                    "run_name": run_name,
                    "display_name": display_name,
                    "program_title": str(row_y.get("program_title") or row_x1.get("program_title") or "").strip(),
                    "source_run_name": str(row_y.get("source_run_name") or row_x1.get("source_run_name") or "").strip(),
                    "control_period": row_y.get("control_period", row_x1.get("control_period")),
                    "x": x1,
                    "actual_mean": y,
                }
            )
        for cluster in _td_perf_cluster_points(points_2d, rel_tol=x_rel_tol, abs_tol=x_abs_tol):
            points = list(cluster.get("points") or [])
            if not points:
                continue
            first = dict(points[0])
            out.append(
                {
                    "run_name": run_name,
                    "display_name": display_name,
                    "program_title": _td_perf_join_unique_text([p.get("program_title") for p in points]),
                    "source_run_name": _td_perf_join_unique_text([p.get("source_run_name") for p in points]),
                    "control_period": first.get("control_period"),
                    "condition_label": _td_perf_export_condition_label(first, display_name=display_name),
                    "input_1": float(cluster.get("x_center") or 0.0),
                    "input_2": None,
                    "actual_mean": float(sum(float(p.get("actual_mean") or 0.0) for p in points) / max(1, len(points))),
                    "sample_count": int(len(points)),
                }
            )
    out.sort(
        key=lambda row: (
            str(row.get("run_name") or "").lower(),
            float(row.get("input_1") or 0.0),
            float(row.get("input_2") or 0.0) if row.get("input_2") not in (None, "") else float("-inf"),
            str(row.get("condition_label") or "").lower(),
        )
    )
    return out


def td_perf_collect_condition_export_rows(
    db_path: Path,
    *,
    run_specs: Sequence[Mapping[str, object]],
    control_period_filter: object = None,
    run_type_filter: object = None,
) -> list[dict[str, object]]:
    path = Path(db_path).expanduser()
    if not path.exists():
        return []

    out: list[dict[str, object]] = []
    for spec in _td_perf_unique_run_specs(run_specs):
        run_name = str((spec or {}).get("run_name") or "").strip()
        if not run_name:
            continue
        display_name = str((spec or {}).get("display_name") or run_name).strip()
        input1_column = str((spec or {}).get("input1_column") or "").strip()
        input2_column = str((spec or {}).get("input2_column") or "").strip()
        output_column = str((spec or {}).get("output_column") or "").strip()
        if not input1_column or not output_column:
            continue

        x1_rows = _td_perf_export_series_for_stat(
            path,
            run_name,
            input1_column,
            "mean",
            control_period_filter=control_period_filter,
            run_type_filter=run_type_filter,
        )
        y_rows = _td_perf_export_series_for_stat(
            path,
            run_name,
            output_column,
            "mean",
            control_period_filter=control_period_filter,
            run_type_filter=run_type_filter,
        )
        if not x1_rows or not y_rows:
            continue

        x1_map = {
            str(row.get("observation_id") or "").strip(): dict(row)
            for row in x1_rows
            if isinstance(row, dict) and str(row.get("observation_id") or "").strip()
        }
        y_map = {
            str(row.get("observation_id") or "").strip(): dict(row)
            for row in y_rows
            if isinstance(row, dict) and str(row.get("observation_id") or "").strip()
        }
        x2_map: dict[str, dict[str, object]] = {}
        observation_ids = set(x1_map.keys()) & set(y_map.keys())
        if input2_column:
            x2_rows = _td_perf_export_series_for_stat(
                path,
                run_name,
                input2_column,
                "mean",
                control_period_filter=control_period_filter,
                run_type_filter=run_type_filter,
            )
            x2_map = {
                str(row.get("observation_id") or "").strip(): dict(row)
                for row in x2_rows
                if isinstance(row, dict) and str(row.get("observation_id") or "").strip()
            }
            observation_ids &= set(x2_map.keys())
        if not observation_ids:
            continue

        x1_values: list[float] = []
        x2_values: list[float] = []
        y_values: list[float] = []
        control_period_values: list[object] = []
        program_titles: list[object] = []
        source_run_names: list[object] = []
        for obs_id in sorted(observation_ids):
            row_x1 = x1_map.get(obs_id) or {}
            row_y = y_map.get(obs_id) or {}
            try:
                x1 = float(row_x1.get("value_num"))
                y = float(row_y.get("value_num"))
            except Exception:
                continue
            if not (math.isfinite(x1) and math.isfinite(y)):
                continue
            if input2_column:
                row_x2 = x2_map.get(obs_id) or {}
                try:
                    x2 = float(row_x2.get("value_num"))
                except Exception:
                    continue
                if not math.isfinite(x2):
                    continue
                x2_values.append(float(x2))
                control_period = row_y.get("control_period", row_x2.get("control_period", row_x1.get("control_period")))
                program_titles.append(
                    row_y.get("program_title") or row_x1.get("program_title") or row_x2.get("program_title") or ""
                )
                source_run_names.append(
                    row_y.get("source_run_name") or row_x1.get("source_run_name") or row_x2.get("source_run_name") or ""
                )
            else:
                control_period = row_y.get("control_period", row_x1.get("control_period"))
                program_titles.append(row_y.get("program_title") or row_x1.get("program_title") or "")
                source_run_names.append(row_y.get("source_run_name") or row_x1.get("source_run_name") or "")
            x1_values.append(float(x1))
            y_values.append(float(y))
            control_period_values.append(control_period)

        if not x1_values or not y_values:
            continue

        finite_control_periods = [
            float(value)
            for value in control_period_values
            if isinstance(value, (int, float)) and math.isfinite(float(value))
        ]
        control_period_value: object
        if finite_control_periods:
            control_period_value = float(sum(finite_control_periods) / max(1, len(finite_control_periods)))
        else:
            control_period_value = next((value for value in control_period_values if value not in (None, "")), None)

        out.append(
            {
                "run_name": run_name,
                "display_name": display_name,
                "program_title": _td_perf_join_unique_text(program_titles),
                "source_run_name": _td_perf_join_unique_text(source_run_names),
                "control_period": control_period_value,
                "condition_label": _td_perf_export_condition_label({"run_name": run_name}, display_name=display_name),
                "input_1": float(sum(x1_values) / max(1, len(x1_values))),
                "input_2": (
                    float(sum(x2_values) / max(1, len(x2_values)))
                    if input2_column and x2_values
                    else None
                ),
                "actual_mean": float(sum(y_values) / max(1, len(y_values))),
                "sample_count": int(len(y_values)),
            }
        )

    out.sort(
        key=lambda row: (
            str(row.get("run_name") or "").lower(),
            str(row.get("condition_label") or "").lower(),
            float(row.get("input_1") or 0.0),
            float(row.get("input_2") or 0.0) if row.get("input_2") not in (None, "") else float("-inf"),
        )
    )
    return out


def td_perf_collect_cached_condition_mean_export_rows(
    db_path: Path,
    *,
    run_specs: Sequence[Mapping[str, object]],
    control_period_filter: object = None,
    run_type_filter: object = None,
    progress_cb: Callable[[str], None] | None = None,
) -> list[dict[str, object]]:
    path = Path(db_path).expanduser()
    if not path.exists():
        return []

    out: list[dict[str, object]] = []
    unique_specs = _td_perf_unique_run_specs(run_specs)
    for spec_index, spec in enumerate(unique_specs, start=1):
        run_name = str((spec or {}).get("run_name") or "").strip()
        if not run_name:
            continue
        _td_emit_progress(
            progress_cb,
            f"Collecting cached run-condition rows ({spec_index}/{max(1, len(unique_specs))}): {run_name}",
        )
        display_name = str((spec or {}).get("display_name") or run_name).strip()
        input1_column = str((spec or {}).get("input1_column") or "").strip()
        input2_column = str((spec or {}).get("input2_column") or "").strip()
        output_column = str((spec or {}).get("output_column") or "").strip()
        if not input1_column or not output_column:
            continue
        x1_rows = _td_perf_export_series_for_stat(
            path,
            run_name,
            input1_column,
            "mean",
            control_period_filter=control_period_filter,
            run_type_filter=run_type_filter,
        )
        y_rows = _td_perf_export_series_for_stat(
            path,
            run_name,
            output_column,
            "mean",
            control_period_filter=control_period_filter,
            run_type_filter=run_type_filter,
        )
        if not x1_rows or not y_rows:
            continue
        x1_map = {
            str(row.get("observation_id") or "").strip(): dict(row)
            for row in x1_rows
            if isinstance(row, dict) and str(row.get("observation_id") or "").strip()
        }
        y_map = {
            str(row.get("observation_id") or "").strip(): dict(row)
            for row in y_rows
            if isinstance(row, dict) and str(row.get("observation_id") or "").strip()
        }
        x2_map: dict[str, dict[str, object]] = {}
        observation_ids = set(x1_map.keys()) & set(y_map.keys())
        if input2_column:
            x2_rows = _td_perf_export_series_for_stat(
                path,
                run_name,
                input2_column,
                "mean",
                control_period_filter=control_period_filter,
                run_type_filter=run_type_filter,
            )
            x2_map = {
                str(row.get("observation_id") or "").strip(): dict(row)
                for row in x2_rows
                if isinstance(row, dict) and str(row.get("observation_id") or "").strip()
            }
            observation_ids &= set(x2_map.keys())
        for obs_id in sorted(observation_ids):
            row_x1 = x1_map.get(obs_id) or {}
            row_y = y_map.get(obs_id) or {}
            row_x2 = x2_map.get(obs_id) or {}
            try:
                x1 = float(row_x1.get("value_num"))
                y = float(row_y.get("value_num"))
            except Exception:
                continue
            if not (math.isfinite(x1) and math.isfinite(y)):
                continue
            x2_value: float | None = None
            if input2_column:
                try:
                    x2_value = float(row_x2.get("value_num"))
                except Exception:
                    continue
                if not math.isfinite(float(x2_value)):
                    continue
            base_row = row_y or row_x1 or row_x2
            serial = str(base_row.get("serial") or row_x1.get("serial") or row_x2.get("serial") or "").strip()
            if not serial:
                continue
            label_source = row_y or row_x1 or row_x2
            out.append(
                {
                    "observation_id": obs_id,
                    "run_name": run_name,
                    "display_name": display_name,
                    "program_title": str(
                        base_row.get("program_title")
                        or row_x1.get("program_title")
                        or row_x2.get("program_title")
                        or ""
                    ).strip(),
                    "source_run_name": str(
                        base_row.get("source_run_name")
                        or row_x1.get("source_run_name")
                        or row_x2.get("source_run_name")
                        or ""
                    ).strip(),
                    "control_period": base_row.get(
                        "control_period",
                        row_x1.get("control_period", row_x2.get("control_period")),
                    ),
                    "suppression_voltage": base_row.get(
                        "suppression_voltage",
                        row_x1.get("suppression_voltage", row_x2.get("suppression_voltage")),
                    ),
                    "condition_label": _td_perf_export_condition_label(label_source, display_name=display_name),
                    "serial": serial,
                    "input_1": float(x1),
                    "input_2": float(x2_value) if isinstance(x2_value, (int, float)) else None,
                    "actual_mean": float(y),
                    "sample_count": 1,
                }
            )
    out.sort(
        key=lambda row: (
            str(row.get("run_name") or "").lower(),
            str(row.get("serial") or "").lower(),
            float(row.get("input_1") or 0.0),
            float(row.get("input_2") or 0.0) if row.get("input_2") not in (None, "") else float("-inf"),
            str(row.get("observation_id") or "").lower(),
        )
    )
    return out


def _td_smart_solver_compact_value(value: object) -> str:
    if value is None or isinstance(value, bool):
        return ""
    if isinstance(value, (int, float)):
        try:
            numeric = float(value)
        except Exception:
            return ""
        return f"{numeric:g}" if math.isfinite(numeric) else ""
    raw = str(value or "").strip()
    if not raw:
        return ""
    try:
        numeric = float(raw)
    except Exception:
        return raw
    return f"{numeric:g}" if math.isfinite(numeric) else raw


def _td_smart_solver_match_filter_value(value: object, allowed: set[str]) -> bool:
    if not allowed:
        return True
    compact = _td_smart_solver_compact_value(value)
    return bool(compact and compact in allowed)


def _td_smart_solver_warning_text(messages: Sequence[object]) -> str:
    merged: list[str] = []
    for raw in messages or []:
        text = str(raw or "").strip()
        if text and text not in merged:
            merged.append(text)
    return "\n".join(merged)


TD_SMART_SOLVER_VARIABLE_DESCRIPTORS = {
    "output": "Metric the solver predicts.",
    "input1": "Primary driver. Always required.",
    "input2": "Secondary direct driver for the 3D solve.",
    "input3": "Correlation helper. Use when a third metric improves the solve, especially in edge cases.",
    "control_period": "Control-period behavior remains unchanged in this solver pass.",
}

TD_SMART_SOLVER_STAGE1_SURFACE_MIN_POINTS = 8
TD_SMART_SOLVER_STAGE1_SURFACE_MIN_DISTINCT_X = 3
TD_SMART_SOLVER_DIRECT_3INPUT_MIN_POINTS = 12
TD_SMART_SOLVER_DIRECT_3INPUT_MIN_DISTINCT_X = 3
TD_SMART_SOLVER_BOUNDARY_POLICY_BOUNDED_CURVE_CP_V1 = "bounded_curve_cp_v1"


def _td_smart_solver_numeric_domain(values: Sequence[object]) -> list[float]:
    domain = [float(v) for v in (values or []) if isinstance(v, (int, float)) and math.isfinite(float(v))]
    if not domain:
        return []
    return [float(min(domain)), float(max(domain))]


def _td_smart_solver_clamp_values(values: Sequence[float], domain: Sequence[object]) -> tuple[list[float], int]:
    if not isinstance(domain, Sequence) or isinstance(domain, (str, bytes)) or len(domain) < 2:
        return [float(v) for v in (values or [])], 0
    try:
        lo = float(domain[0])
        hi = float(domain[1])
    except Exception:
        return [float(v) for v in (values or [])], 0
    if not (math.isfinite(lo) and math.isfinite(hi)):
        return [float(v) for v in (values or [])], 0
    lo, hi = min(lo, hi), max(lo, hi)
    out: list[float] = []
    hit_count = 0
    for raw in values or []:
        value = float(raw)
        clamped = min(max(value, lo), hi)
        if abs(clamped - value) > 1e-12:
            hit_count += 1
        out.append(float(clamped))
    return out, int(hit_count)


def _td_smart_solver_clamp_scalar(value: float, domain: Sequence[object]) -> float:
    try:
        numeric = float(value)
    except Exception:
        return float(value)
    if not isinstance(domain, Sequence) or isinstance(domain, (str, bytes)) or len(domain) < 2:
        return float(numeric)
    try:
        lo = float(domain[0])
        hi = float(domain[1])
    except Exception:
        return float(numeric)
    if not (math.isfinite(lo) and math.isfinite(hi)):
        return float(numeric)
    return float(min(max(numeric, min(lo, hi)), max(lo, hi)))


def _td_smart_solver_curve_cp_support_key(value: object) -> float | None:
    numeric = _td_finite_float(value)
    if numeric is None:
        return None
    return round(float(numeric), 12)


def _td_smart_solver_curve_cp_find_partner_index(
    support_rows: Sequence[Mapping[str, object]],
    index: int,
    *,
    side: str,
) -> int | None:
    if not isinstance(support_rows, Sequence) or index < 0 or index >= len(support_rows):
        return None
    current = support_rows[index]
    current_cp = float(current.get("control_period") or 0.0)
    current_x = (
        _td_finite_float(current.get("x_min"))
        if side == "left"
        else _td_finite_float(current.get("x_max"))
    )
    if current_x is None:
        return None
    for offset in range(1, len(support_rows)):
        candidates: list[tuple[float, int]] = []
        for neighbor_index in (index - offset, index + offset):
            if neighbor_index < 0 or neighbor_index >= len(support_rows):
                continue
            row = support_rows[neighbor_index]
            neighbor_x = (
                _td_finite_float(row.get("x_min"))
                if side == "left"
                else _td_finite_float(row.get("x_max"))
            )
            if neighbor_x is None:
                continue
            if side == "left" and float(neighbor_x) >= (float(current_x) - 1e-12):
                continue
            if side == "right" and float(neighbor_x) <= (float(current_x) + 1e-12):
                continue
            candidates.append((abs(float(row.get("control_period") or 0.0) - current_cp), neighbor_index))
        if candidates:
            candidates.sort(key=lambda item: (item[0], item[1]))
            return int(candidates[0][1])
    return None


def _td_smart_solver_curve_cp_boundary_support(
    xs: Sequence[float],
    ys: Sequence[float],
    control_periods: Sequence[float],
    *,
    eligible_control_period_values: Sequence[float],
) -> tuple[list[dict[str, object]], list[dict[str, object]], list[float]]:
    eligible_keys = {
        round(float(value), 12)
        for value in (eligible_control_period_values or [])
        if isinstance(value, (int, float)) and math.isfinite(float(value))
    }
    groups: dict[float, list[tuple[float, float]]] = {}
    for x_value, y_value, cp_value in zip(xs, ys, control_periods):
        cp_key = _td_smart_solver_curve_cp_support_key(cp_value)
        if cp_key is None or cp_key not in eligible_keys:
            continue
        x_num = _td_finite_float(x_value)
        y_num = _td_finite_float(y_value)
        if x_num is None or y_num is None:
            continue
        groups.setdefault(cp_key, []).append((float(x_num), float(y_num)))

    support_rows: list[dict[str, object]] = []
    for cp_key in sorted(groups.keys()):
        pts = sorted(groups.get(cp_key, []), key=lambda item: item[0])
        if not pts:
            continue
        x_min = float(pts[0][0])
        x_max = float(pts[-1][0])
        left_vals = [float(y_val) for x_val, y_val in pts if abs(float(x_val) - x_min) <= 1e-12]
        right_vals = [float(y_val) for x_val, y_val in pts if abs(float(x_val) - x_max) <= 1e-12]
        support_rows.append(
            {
                "control_period": float(cp_key),
                "point_count": int(len(pts)),
                "x_min": float(x_min),
                "x_max": float(x_max),
                "left_x": float(x_min),
                "left_y": float(sum(left_vals) / len(left_vals)) if left_vals else float(pts[0][1]),
                "right_x": float(x_max),
                "right_y": float(sum(right_vals) / len(right_vals)) if right_vals else float(pts[-1][1]),
            }
        )

    if not support_rows:
        return [], [], []

    updated_rows: list[dict[str, object]] = []
    for index, row in enumerate(support_rows):
        entry = dict(row)
        left_partner_index = _td_smart_solver_curve_cp_find_partner_index(support_rows, index, side="left")
        right_partner_index = _td_smart_solver_curve_cp_find_partner_index(support_rows, index, side="right")
        if left_partner_index is not None:
            entry["left_partner_control_period"] = float(support_rows[left_partner_index].get("control_period") or 0.0)
        if right_partner_index is not None:
            entry["right_partner_control_period"] = float(support_rows[right_partner_index].get("control_period") or 0.0)
        updated_rows.append(entry)
    support_rows = updated_rows

    bridge_pairs: list[dict[str, object]] = []
    for index in range(len(support_rows) - 1):
        lower = support_rows[index]
        upper = support_rows[index + 1]
        pair: dict[str, object] = {
            "lower_control_period": float(lower.get("control_period") or 0.0),
            "upper_control_period": float(upper.get("control_period") or 0.0),
        }
        lower_x_min = float(lower.get("x_min") or 0.0)
        lower_x_max = float(lower.get("x_max") or 0.0)
        upper_x_min = float(upper.get("x_min") or 0.0)
        upper_x_max = float(upper.get("x_max") or 0.0)
        if abs(lower_x_min - upper_x_min) > 1e-12:
            if lower_x_min < upper_x_min:
                pair["left_bridge"] = {
                    "from_control_period": float(upper.get("control_period") or 0.0),
                    "to_control_period": float(lower.get("control_period") or 0.0),
                    "x0": float(lower.get("left_x") or lower_x_min),
                    "y0": float(lower.get("left_y") or 0.0),
                    "x1": float(upper.get("left_x") or upper_x_min),
                    "y1": float(upper.get("left_y") or 0.0),
                }
            else:
                pair["left_bridge"] = {
                    "from_control_period": float(lower.get("control_period") or 0.0),
                    "to_control_period": float(upper.get("control_period") or 0.0),
                    "x0": float(upper.get("left_x") or upper_x_min),
                    "y0": float(upper.get("left_y") or 0.0),
                    "x1": float(lower.get("left_x") or lower_x_min),
                    "y1": float(lower.get("left_y") or 0.0),
                }
        if abs(lower_x_max - upper_x_max) > 1e-12:
            if lower_x_max < upper_x_max:
                pair["right_bridge"] = {
                    "from_control_period": float(lower.get("control_period") or 0.0),
                    "to_control_period": float(upper.get("control_period") or 0.0),
                    "x0": float(lower.get("right_x") or lower_x_max),
                    "y0": float(lower.get("right_y") or 0.0),
                    "x1": float(upper.get("right_x") or upper_x_max),
                    "y1": float(upper.get("right_y") or 0.0),
                }
            else:
                pair["right_bridge"] = {
                    "from_control_period": float(upper.get("control_period") or 0.0),
                    "to_control_period": float(lower.get("control_period") or 0.0),
                    "x0": float(upper.get("right_x") or upper_x_max),
                    "y0": float(upper.get("right_y") or 0.0),
                    "x1": float(lower.get("right_x") or lower_x_max),
                    "y1": float(lower.get("right_y") or 0.0),
                }
        bridge_pairs.append(pair)

    global_domain = [
        float(min(float(row.get("x_min") or 0.0) for row in support_rows)),
        float(max(float(row.get("x_max") or 0.0) for row in support_rows)),
    ]
    return support_rows, bridge_pairs, global_domain


def _td_smart_solver_attach_curve_cp_boundary_metadata(
    model: Mapping[str, object] | None,
    xs: Sequence[float],
    ys: Sequence[float],
    control_periods: Sequence[float],
) -> dict[str, object] | None:
    if not isinstance(model, Mapping):
        return None
    family = td_perf_normalize_fit_mode(model.get("fit_family"))
    if family not in TD_PERF_CURVE_CONTROL_PERIOD_FAMILIES:
        return dict(model)
    eligible_values = [
        float(value)
        for value in (model.get("eligible_control_period_values") or model.get("control_period_values") or [])
        if isinstance(value, (int, float)) and math.isfinite(float(value))
    ]
    support_rows, bridge_pairs, global_domain = _td_smart_solver_curve_cp_boundary_support(
        xs,
        ys,
        control_periods,
        eligible_control_period_values=eligible_values,
    )
    out = dict(model)
    out["smart_solver_scope"] = "solver_tab"
    out["smart_solver_boundary_policy"] = TD_SMART_SOLVER_BOUNDARY_POLICY_BOUNDED_CURVE_CP_V1
    out["curve_cp_slice_support"] = [dict(row) for row in support_rows]
    out["curve_cp_bridge_pairs"] = [dict(row) for row in bridge_pairs]
    out["curve_cp_global_domain"] = [float(value) for value in global_domain[:2]]
    if len(global_domain) >= 2:
        out["fit_domain"] = [float(value) for value in global_domain[:2]]
    return out


def _td_smart_solver_curve_cp_slice_raw_value(
    model: Mapping[str, object],
    slice_row: Mapping[str, object],
    x_value: float,
) -> float:
    family = td_perf_normalize_fit_mode(model.get("fit_family"))
    x_num = float(x_value)
    x_center = float(model.get("x_center") or 0.0)
    x_scale = float(model.get("x_scale") or 1.0) or 1.0
    x_norm = (x_num - x_center) / x_scale
    if family == TD_PERF_FIT_FAMILY_QUADRATIC_CURVE_CONTROL_PERIOD:
        coeffs = [float(value) for value in (slice_row.get("coeffs") or [])]
        if len(coeffs) == 3:
            return float((coeffs[0] * (x_norm ** 2)) + (coeffs[1] * x_norm) + coeffs[2])
    if family == TD_PERF_FIT_FAMILY_HYBRID_QUADRATIC_RESIDUAL_CONTROL_PERIOD:
        residual_coeffs = [float(value) for value in (slice_row.get("residual_coeffs") or [])]
        base_params = dict(model.get("base_params") or (model.get("params") or {}).get("base_params") or {})
        base_value = (
            float(base_params.get("b") or 0.0)
            + (float(base_params.get("m") or 0.0) * x_num)
            + (
                float(base_params.get("A") or 0.0)
                * (1.0 - math.exp(-float(base_params.get("k") or 0.0) * x_num))
            )
        )
        if len(residual_coeffs) == 3:
            return float(
                base_value
                + (residual_coeffs[0] * (x_norm ** 2))
                + (residual_coeffs[1] * x_norm)
                + residual_coeffs[2]
            )
    cp_value = _td_finite_float(slice_row.get("control_period"))
    if cp_value is None:
        return float("nan")
    fallback = td_perf_predict_model(model, [x_num], control_period=[float(cp_value)])
    if not fallback:
        return float("nan")
    return float(fallback[0])


def _td_smart_solver_curve_cp_line_value(
    x_value: float,
    x0: float,
    y0: float,
    x1: float,
    y1: float,
) -> float:
    lo = min(float(x0), float(x1))
    hi = max(float(x0), float(x1))
    x_clamped = min(max(float(x_value), lo), hi)
    if abs(float(x1) - float(x0)) <= 1e-12:
        return float(y1)
    weight = (x_clamped - float(x0)) / (float(x1) - float(x0))
    return float(float(y0) + (weight * (float(y1) - float(y0))))


def _td_smart_solver_curve_cp_pair_value(
    model: Mapping[str, object],
    base_row: Mapping[str, object],
    other_row: Mapping[str, object],
    x_value: float,
) -> float:
    x_num = float(x_value)
    x_min = float(base_row.get("x_min") or 0.0)
    x_max = float(base_row.get("x_max") or 0.0)
    if x_num < x_min:
        other_x_min = float(other_row.get("x_min") or 0.0)
        if other_x_min < (x_min - 1e-12):
            return _td_smart_solver_curve_cp_line_value(
                x_num,
                float(other_row.get("left_x") or other_x_min),
                float(other_row.get("left_y") or 0.0),
                float(base_row.get("left_x") or x_min),
                float(base_row.get("left_y") or 0.0),
            )
        return float(base_row.get("left_y") or 0.0)
    if x_num > x_max:
        other_x_max = float(other_row.get("x_max") or 0.0)
        if other_x_max > (x_max + 1e-12):
            return _td_smart_solver_curve_cp_line_value(
                x_num,
                float(base_row.get("right_x") or x_max),
                float(base_row.get("right_y") or 0.0),
                float(other_row.get("right_x") or other_x_max),
                float(other_row.get("right_y") or 0.0),
            )
        return float(base_row.get("right_y") or 0.0)
    return _td_smart_solver_curve_cp_slice_raw_value(model, base_row, x_num)


def _td_smart_solver_curve_cp_exact_value(
    model: Mapping[str, object],
    support_rows: Sequence[Mapping[str, object]],
    support_by_key: Mapping[float, Mapping[str, object]],
    slice_row: Mapping[str, object],
    x_value: float,
) -> float:
    x_num = float(x_value)
    x_min = float(slice_row.get("x_min") or 0.0)
    x_max = float(slice_row.get("x_max") or 0.0)
    if x_num < x_min:
        partner_key = _td_smart_solver_curve_cp_support_key(slice_row.get("left_partner_control_period"))
        partner = support_by_key.get(partner_key) if partner_key is not None else None
        if isinstance(partner, Mapping):
            return _td_smart_solver_curve_cp_line_value(
                x_num,
                float(partner.get("left_x") or partner.get("x_min") or 0.0),
                float(partner.get("left_y") or 0.0),
                float(slice_row.get("left_x") or x_min),
                float(slice_row.get("left_y") or 0.0),
            )
        return float(slice_row.get("left_y") or 0.0)
    if x_num > x_max:
        partner_key = _td_smart_solver_curve_cp_support_key(slice_row.get("right_partner_control_period"))
        partner = support_by_key.get(partner_key) if partner_key is not None else None
        if isinstance(partner, Mapping):
            return _td_smart_solver_curve_cp_line_value(
                x_num,
                float(slice_row.get("right_x") or x_max),
                float(slice_row.get("right_y") or 0.0),
                float(partner.get("right_x") or partner.get("x_max") or 0.0),
                float(partner.get("right_y") or 0.0),
            )
        return float(slice_row.get("right_y") or 0.0)
    return _td_smart_solver_curve_cp_slice_raw_value(model, slice_row, x_num)


def _td_smart_solver_predict_curve_cp_bounded(
    model: Mapping[str, object],
    x_values: Iterable[float],
    control_period,
) -> list[float]:
    x_list = [float(value) for value in x_values]
    count = len(x_list)
    if count <= 0:
        return []
    if control_period is None:
        raise ValueError("Control-period-aware Smart Solver prediction requires control_period.")
    if isinstance(control_period, Iterable) and not isinstance(control_period, (str, bytes)):
        cp_values = [float(value) for value in control_period]
        if len(cp_values) != count:
            raise ValueError("control_period iterable length must match x inputs.")
    else:
        cp_values = [float(control_period)] * count

    support_rows = [
        dict(row)
        for row in (model.get("curve_cp_slice_support") or [])
        if isinstance(row, Mapping)
    ]
    if not support_rows:
        return td_perf_predict_model(model, x_list, control_period=cp_values)
    support_rows.sort(key=lambda row: float(row.get("control_period") or 0.0))
    support_by_key = {
        round(float(row.get("control_period") or 0.0), 12): row
        for row in support_rows
    }
    cp_domain = (
        [float(value) for value in (model.get("fit_domain_control_period") or []) if isinstance(value, (int, float))]
        or [float(support_rows[0].get("control_period") or 0.0), float(support_rows[-1].get("control_period") or 0.0)]
    )
    global_domain = (
        [float(value) for value in (model.get("curve_cp_global_domain") or []) if isinstance(value, (int, float))]
        or [float(support_rows[0].get("x_min") or 0.0), float(support_rows[-1].get("x_max") or 0.0)]
    )

    out: list[float] = []
    control_period_values = [float(row.get("control_period") or 0.0) for row in support_rows]
    for raw_x, raw_cp in zip(x_list, cp_values):
        x_num = _td_smart_solver_clamp_scalar(float(raw_x), global_domain)
        cp_num = _td_smart_solver_clamp_scalar(float(raw_cp), cp_domain)
        exact_row = next(
            (
                row
                for row in support_rows
                if abs(float(row.get("control_period") or 0.0) - cp_num) <= 1e-9
            ),
            None,
        )
        if isinstance(exact_row, Mapping):
            out.append(
                float(
                    _td_smart_solver_curve_cp_exact_value(
                        model,
                        support_rows,
                        support_by_key,
                        exact_row,
                        x_num,
                    )
                )
            )
            continue

        upper_index = next(
            (idx for idx, cp_value in enumerate(control_period_values) if cp_num < float(cp_value)),
            len(control_period_values) - 1,
        )
        lower_index = max(0, upper_index - 1)
        if upper_index <= lower_index:
            row = support_rows[lower_index]
            out.append(
                float(
                    _td_smart_solver_curve_cp_exact_value(
                        model,
                        support_rows,
                        support_by_key,
                        row,
                        x_num,
                    )
                )
            )
            continue
        lower_row = support_rows[lower_index]
        upper_row = support_rows[upper_index]
        center_values = td_perf_predict_model(model, [x_num], control_period=[cp_num])
        if not center_values:
            out.append(float("nan"))
            continue
        center_value = float(center_values[0])
        lower_value = _td_smart_solver_curve_cp_pair_value(model, lower_row, upper_row, x_num)
        upper_value = _td_smart_solver_curve_cp_pair_value(model, upper_row, lower_row, x_num)
        lo = min(lower_value, upper_value)
        hi = max(lower_value, upper_value)
        out.append(float(min(max(center_value, lo), hi)))
    return out


def _td_smart_solver_predict_model(
    model: Mapping[str, object],
    x_values: Iterable[float],
    *,
    control_period=None,
) -> list[float]:
    family = td_perf_normalize_fit_mode(model.get("fit_family"))
    if (
        family in TD_PERF_CURVE_CONTROL_PERIOD_FAMILIES
        and str(model.get("smart_solver_boundary_policy") or "").strip().lower()
        == TD_SMART_SOLVER_BOUNDARY_POLICY_BOUNDED_CURVE_CP_V1
    ):
        return _td_smart_solver_predict_curve_cp_bounded(model, x_values, control_period)
    return td_perf_predict_model(model, x_values, control_period=control_period)


def _td_smart_solver_score_predictions(
    actual_values: Sequence[float],
    predicted_values: Sequence[float],
) -> dict[str, float | int]:
    np = _td_perf_import_numpy()
    actual_arr = np.asarray([float(v) for v in (actual_values or [])], dtype=float)
    pred_arr = np.asarray([float(v) for v in (predicted_values or [])], dtype=float)
    if len(actual_arr) != len(pred_arr) or len(actual_arr) <= 0:
        return {
            "rmse": float("inf"),
            "residual_threshold": float("inf"),
            "in_fit_count": 0,
            "fell_out_count": 0,
            "sample_count": int(len(actual_arr)),
        }
    residuals = actual_arr - pred_arr
    abs_residuals = np.abs(residuals)
    rmse = float(np.sqrt(np.mean(residuals**2)))
    mad_abs = float(np.median(abs_residuals)) if abs_residuals.size else 0.0
    residual_threshold = float(3.0 * 1.4826 * mad_abs) if math.isfinite(mad_abs) else 0.0
    if not math.isfinite(residual_threshold) or residual_threshold <= 0.0:
        residual_threshold = float(3.0 * rmse) if math.isfinite(rmse) and rmse > 0.0 else 1e-9
    in_fit_count = int(sum(1 for value in abs_residuals.tolist() if float(value) <= residual_threshold))
    sample_count = int(len(actual_arr))
    return {
        "rmse": float(rmse),
        "residual_threshold": float(residual_threshold),
        "in_fit_count": int(in_fit_count),
        "fell_out_count": int(max(0, sample_count - in_fit_count)),
        "sample_count": int(sample_count),
    }


def _td_smart_solver_residual_std(residual_values: Sequence[object]) -> float:
    residuals = [
        float(value)
        for value in (residual_values or [])
        if isinstance(value, (int, float)) and math.isfinite(float(value))
    ]
    if len(residuals) < 2:
        return 0.0
    mean_value = float(sum(residuals) / len(residuals))
    variance = float(sum((value - mean_value) ** 2 for value in residuals) / len(residuals))
    if not math.isfinite(variance) or variance <= 0.0:
        return 0.0
    std_value = float(math.sqrt(variance))
    return std_value if math.isfinite(std_value) else 0.0


def _td_smart_solver_three_sigma_support_rows(result: Mapping[str, object]) -> list[dict[str, object]]:
    support_rows: list[dict[str, object]] = []
    for raw_row in (result.get("three_sigma_support_rows") or []):
        if not isinstance(raw_row, Mapping):
            continue
        control_period = _td_finite_float(raw_row.get("control_period"))
        if control_period is None:
            continue
        residual_std = _td_finite_float(raw_row.get("residual_std"))
        residual_std = float(residual_std) if residual_std is not None and math.isfinite(float(residual_std)) else 0.0
        offset = _td_finite_float(raw_row.get("three_sigma_offset"))
        if offset is None or not math.isfinite(float(offset)):
            offset = float(3.0 * residual_std)
        support_rows.append(
            {
                "control_period": float(control_period),
                "sample_count": int(raw_row.get("sample_count") or 0),
                "residual_std": float(residual_std),
                "three_sigma_offset": float(offset),
            }
        )
    support_rows.sort(key=lambda row: float(row.get("control_period") or 0.0))
    return support_rows


def _td_smart_solver_build_three_sigma_support(
    points: Sequence[Mapping[str, object]],
    predicted_values: Sequence[object],
    *,
    uses_control_period: bool,
) -> dict[str, object]:
    materialized_points = [dict(point) for point in (points or []) if isinstance(point, Mapping)]
    residual_pairs: list[tuple[dict[str, object], float]] = []
    for index, point in enumerate(materialized_points):
        if index >= len(predicted_values or []):
            break
        actual_value = _td_finite_float(point.get("actual_mean"))
        predicted_value = _td_finite_float(predicted_values[index])
        if actual_value is None or predicted_value is None:
            continue
        residual_pairs.append((point, float(actual_value - predicted_value)))

    if uses_control_period:
        grouped: dict[float, list[float]] = {}
        for point, residual_value in residual_pairs:
            control_period = _td_finite_float(point.get("control_period"))
            if control_period is None:
                continue
            grouped.setdefault(float(control_period), []).append(float(residual_value))
        support_rows: list[dict[str, object]] = []
        for control_period in sorted(grouped):
            residuals = list(grouped.get(control_period) or [])
            residual_std = _td_smart_solver_residual_std(residuals)
            support_rows.append(
                {
                    "control_period": float(control_period),
                    "sample_count": int(len(residuals)),
                    "residual_std": float(residual_std),
                    "three_sigma_offset": float(3.0 * residual_std),
                }
            )
        return {
            "three_sigma_basis": "residual_std",
            "three_sigma_cp_policy": "interpolate_clamp",
            "three_sigma_support_rows": support_rows,
        }

    residual_std = _td_smart_solver_residual_std([value for _point, value in residual_pairs])
    return {
        "three_sigma_basis": "residual_std",
        "three_sigma_cp_policy": "constant",
        "three_sigma_offset": float(3.0 * residual_std),
        "three_sigma_support_rows": [],
    }


def _td_smart_solver_resolve_three_sigma_offset(
    result: Mapping[str, object],
    *,
    control_period: object = None,
) -> float:
    support_rows = _td_smart_solver_three_sigma_support_rows(result)
    if support_rows:
        if len(support_rows) == 1:
            return float(support_rows[0].get("three_sigma_offset") or 0.0)
        cp_value = _td_finite_float(control_period)
        if cp_value is None:
            return float(support_rows[0].get("three_sigma_offset") or 0.0)
        cp_value = float(cp_value)
        first_row = support_rows[0]
        last_row = support_rows[-1]
        first_cp = float(first_row.get("control_period") or 0.0)
        last_cp = float(last_row.get("control_period") or 0.0)
        if cp_value <= first_cp + 1e-9:
            return float(first_row.get("three_sigma_offset") or 0.0)
        if cp_value >= last_cp - 1e-9:
            return float(last_row.get("three_sigma_offset") or 0.0)
        for lower, upper in zip(support_rows, support_rows[1:]):
            lower_cp = float(lower.get("control_period") or 0.0)
            upper_cp = float(upper.get("control_period") or 0.0)
            lower_offset = float(lower.get("three_sigma_offset") or 0.0)
            upper_offset = float(upper.get("three_sigma_offset") or 0.0)
            if abs(cp_value - lower_cp) <= 1e-9:
                return lower_offset
            if abs(cp_value - upper_cp) <= 1e-9:
                return upper_offset
            if cp_value < upper_cp:
                if abs(upper_cp - lower_cp) <= 1e-12:
                    return upper_offset
                weight = float((cp_value - lower_cp) / (upper_cp - lower_cp))
                return float(lower_offset + (weight * (upper_offset - lower_offset)))
        return float(last_row.get("three_sigma_offset") or 0.0)

    offset = _td_finite_float(result.get("three_sigma_offset"))
    if offset is None or not math.isfinite(float(offset)):
        return 0.0
    return float(offset)


def _td_smart_solver_equation_rhs(equation_text: object) -> str:
    text = str(equation_text or "").strip()
    if not text:
        return ""
    final_y_match = re.search(r"(?:^|;\s*)y\s*=\s*(.+)$", text, flags=re.IGNORECASE)
    if final_y_match:
        return str(final_y_match.group(1) or "").strip()
    generic_match = re.match(r"^[A-Za-z_][A-Za-z0-9_]*\s*=\s*(.+)$", text)
    if generic_match:
        return str(generic_match.group(1) or "").strip()
    return text


def _td_smart_solver_three_sigma_vector_text(values: Sequence[object]) -> str:
    formatted = [
        _td_perf_excel_num(value)
        for value in (values or [])
        if isinstance(value, (int, float)) and math.isfinite(float(value))
    ]
    return "[" + ", ".join(formatted) + "]"


def _td_smart_solver_three_sigma_equation_texts(result: Mapping[str, object]) -> dict[str, str]:
    nominal_equation = str(result.get("equation") or "").strip()
    nominal_rhs = _td_smart_solver_equation_rhs(nominal_equation)
    normalization_text = str(result.get("x_norm_equation") or "").strip()
    support_rows = _td_smart_solver_three_sigma_support_rows(result)
    if support_rows:
        cp_text = _td_smart_solver_three_sigma_vector_text([row.get("control_period") for row in support_rows])
        offset_text = _td_smart_solver_three_sigma_vector_text([row.get("three_sigma_offset") for row in support_rows])
        offset_ref = "three_sigma_offset(control_period)"
        offset_equation = (
            f"{offset_ref} = interp_clamp(control_period, {cp_text}, {offset_text})"
        )
    else:
        offset_value = _td_smart_solver_resolve_three_sigma_offset(result)
        offset_ref = "three_sigma_offset"
        offset_equation = f"{offset_ref} = {_td_perf_excel_num(offset_value)}"
    min_equation = (
        f"pred_min_3sigma = ({nominal_rhs}) - ({offset_ref})"
        if nominal_rhs
        else ""
    )
    max_equation = (
        f"pred_max_3sigma = ({nominal_rhs}) + ({offset_ref})"
        if nominal_rhs
        else ""
    )
    return {
        "offset_equation": offset_equation,
        "pred_min_3sigma_equation": min_equation,
        "pred_max_3sigma_equation": max_equation,
        "normalization_text": normalization_text,
    }


def _td_smart_solver_candidate_summary(
    *,
    model: Mapping[str, object] | None,
    actual_values: Sequence[float],
    predicted_values: Sequence[float],
    ignored_control_periods: Sequence[Mapping[str, object]] | None = None,
    clamp_hits: int = 0,
    stage2_fit_source: str = "",
    stage1_rmse: float | None = None,
) -> dict[str, object]:
    available = isinstance(model, Mapping)
    if not available:
        return {
            "available": False,
            "fit_family": "",
            "rmse": None,
            "residual_threshold": None,
            "in_fit_count": 0,
            "fell_out_count": 0,
            "sample_count": int(len(actual_values or [])),
            "fallback_used": False,
            "support_failed": False,
            "stability_ok": False,
            "clamp_hits": int(clamp_hits),
            "stage2_fit_source": str(stage2_fit_source or ""),
            "stage1_rmse": (float(stage1_rmse) if isinstance(stage1_rmse, (int, float)) and math.isfinite(float(stage1_rmse)) else None),
        }
    summary = _td_smart_solver_score_predictions(actual_values, predicted_values)
    ignored = [dict(item) for item in (ignored_control_periods or []) if isinstance(item, Mapping)]
    fallback_used = bool(model.get("fallback_used"))
    support_failed = bool(ignored)
    rmse_value = summary.get("rmse")
    scoring_ok = (
        int(summary.get("sample_count") or 0) > 0
        and len(actual_values or []) == len(predicted_values or [])
        and isinstance(rmse_value, (int, float))
        and math.isfinite(float(rmse_value))
    )
    stability_ok = bool(scoring_ok and (not support_failed) and (not fallback_used) and int(clamp_hits) <= 0)
    return {
        "available": True,
        "fit_family": str(model.get("fit_family") or ""),
        "rmse": (float(rmse_value) if isinstance(rmse_value, (int, float)) and math.isfinite(float(rmse_value)) else None),
        "residual_threshold": summary.get("residual_threshold"),
        "in_fit_count": int(summary.get("in_fit_count") or 0),
        "fell_out_count": int(summary.get("fell_out_count") or 0),
        "sample_count": int(summary.get("sample_count") or 0),
        "fallback_used": bool(fallback_used),
        "support_failed": bool(support_failed),
        "stability_ok": bool(stability_ok),
        "clamp_hits": int(clamp_hits),
        "stage2_fit_source": str(stage2_fit_source or ""),
        "stage1_rmse": (float(stage1_rmse) if isinstance(stage1_rmse, (int, float)) and math.isfinite(float(stage1_rmse)) else None),
    }


def _td_smart_solver_candidate_rmse(summary: Mapping[str, object]) -> float:
    try:
        value = float(summary.get("rmse"))
    except Exception:
        return float("inf")
    return value if math.isfinite(value) else float("inf")


def td_smart_solver_variable_descriptors() -> dict[str, str]:
    return dict(TD_SMART_SOLVER_VARIABLE_DESCRIPTORS)


def _td_smart_solver_export_variables(
    *,
    input1_target: str,
    input1_units: str,
    input2_target: str,
    input2_units: str,
    input3_target: str,
    input3_units: str,
    variable_descriptors: Mapping[str, object] | None = None,
) -> list[dict[str, object]]:
    descriptors = {
        str(key or "").strip().lower(): str(value or "").strip()
        for key, value in dict(variable_descriptors or td_smart_solver_variable_descriptors()).items()
        if str(key or "").strip()
    }
    variables: list[dict[str, object]] = [
        {
            "key": "input_1",
            "target": str(input1_target or "").strip(),
            "units": str(input1_units or "").strip(),
            "role": str(descriptors.get("input1") or ""),
            "is_optional": False,
        }
    ]
    if str(input2_target or "").strip():
        variables.append(
            {
                "key": "input_2",
                "target": str(input2_target or "").strip(),
                "units": str(input2_units or "").strip(),
                "role": str(descriptors.get("input2") or ""),
                "is_optional": True,
            }
        )
    if str(input3_target or "").strip():
        variables.append(
            {
                "key": "input_3",
                "target": str(input3_target or "").strip(),
                "units": str(input3_units or "").strip(),
                "role": str(descriptors.get("input3") or ""),
                "is_optional": True,
            }
        )
    return variables


def td_smart_solver_exportable_model(result: Mapping[str, object]) -> dict[str, object] | None:
    model = (result or {}).get("master_model") if isinstance(result, Mapping) else None
    if not isinstance(model, Mapping):
        return None
    family = td_perf_normalize_fit_mode(model.get("fit_family"))
    if family not in TD_SMART_SOLVER_EXPORTABLE_FIT_FAMILIES:
        return None
    return dict(model)


def _td_smart_solver_sequence_cap_value(value: object) -> int:
    try:
        limit = int(value)
    except Exception:
        return 0
    return limit if limit > 0 else 0


def _td_smart_solver_sequence_identity(point: Mapping[str, object]) -> str:
    source_run_name = str(point.get("source_run_name") or "").strip()
    if source_run_name:
        return source_run_name
    return str(point.get("observation_id") or "").strip()


def _td_smart_solver_sequence_sort_key(value: object) -> tuple[tuple[int, object], ...]:
    text = str(value or "").strip().casefold()
    if not text:
        return ((1, ""),)
    parts = re.split(r"(\d+)", text)
    key: list[tuple[int, object]] = []
    for part in parts:
        if not part:
            continue
        if part.isdigit():
            key.append((0, int(part)))
        else:
            key.append((1, part))
    return tuple(key or [(1, text)])


def _td_smart_solver_apply_sequence_cap(
    points: Sequence[Mapping[str, object]],
    keep_first_sequences_per_serial: object,
) -> tuple[list[dict[str, object]], int, int]:
    limit = _td_smart_solver_sequence_cap_value(keep_first_sequences_per_serial)
    materialized = [dict(point) for point in (points or []) if isinstance(point, Mapping)]
    if limit <= 0 or not materialized:
        return materialized, 0, 0

    kept_by_serial: dict[str, set[str]] = {}
    dropped_sequence_count = 0

    serial_sequences: dict[str, dict[str, str]] = {}
    for point in materialized:
        serial = str(point.get("serial") or "").strip()
        if not serial:
            continue
        sequence_identity = _td_smart_solver_sequence_identity(point)
        sequence_key = sequence_identity.casefold()
        if not sequence_key:
            continue
        serial_sequences.setdefault(serial, {}).setdefault(sequence_key, sequence_identity)

    for serial, sequence_map in serial_sequences.items():
        ordered_keys = sorted(
            sequence_map.keys(),
            key=lambda key: _td_smart_solver_sequence_sort_key(sequence_map.get(key) or key),
        )
        kept_by_serial[serial] = set(ordered_keys[:limit])
        dropped_sequence_count += max(0, len(ordered_keys) - min(limit, len(ordered_keys)))

    filtered_points: list[dict[str, object]] = []
    for point in materialized:
        serial = str(point.get("serial") or "").strip()
        if not serial:
            continue
        sequence_identity = _td_smart_solver_sequence_identity(point)
        sequence_key = sequence_identity.casefold()
        if sequence_key and sequence_key in kept_by_serial.get(serial, set()):
            filtered_points.append(point)
    dropped_point_count = max(0, len(materialized) - len(filtered_points))
    return filtered_points, dropped_sequence_count, dropped_point_count


def td_smart_solver_run(
    db_path: Path,
    *,
    output_target: str,
    input1_target: str,
    input2_target: str = "",
    input3_target: str = "",
    control_period_hard_input: bool = True,
    keep_first_sequences_per_serial: int | None = None,
    run_type_mode: str = "pulsed_mode",
    runs: Sequence[object],
    serials: Sequence[object],
    program_filters: Sequence[object] | None = None,
    suppression_voltage_filters: Sequence[object] | None = None,
    control_period_filters: Sequence[object] | None = None,
    progress_cb: Callable[[str], None] | None = None,
) -> dict[str, object]:
    path = Path(db_path).expanduser()
    if not path.exists():
        raise RuntimeError("Run 'Update Project' first.")
    if not td_smart_solver_has_sequence_rows(path):
        raise RuntimeError(
            "Smart Equation Solver requires sequence-level metrics in td_metrics_calc_sequences. "
            "Run 'Update Project' first."
        )

    output_name = str(output_target or "").strip()
    input1_name = str(input1_target or "").strip()
    input2_name = str(input2_target or "").strip()
    input3_name = str(input3_target or "").strip()
    if not output_name or not input1_name:
        raise RuntimeError("Select Output and Input 1 before running Smart Equation Solver.")
    if input3_name and not input2_name:
        raise RuntimeError("Select Input 2 before using Input 3 in Smart Equation Solver.")
    normalized_run_type_mode = td_perf_normalize_run_type_mode(run_type_mode)
    solver_run_type_mode = "steady_state" if normalized_run_type_mode == "steady_state" else "pulsed_mode"
    uses_control_period = solver_run_type_mode == "pulsed_mode"

    runs_list = [str(value or "").strip() for value in (runs or []) if str(value or "").strip()]
    serial_set = {str(value or "").strip() for value in (serials or []) if str(value or "").strip()}
    if not runs_list:
        raise RuntimeError("No runs are available for Smart Equation Solver.")
    if not serial_set:
        raise RuntimeError("No serials remain after applying the active global filters.")

    program_allowed = {str(value or "").strip() for value in (program_filters or []) if str(value or "").strip()}
    suppression_allowed = {
        _td_smart_solver_compact_value(value)
        for value in (suppression_voltage_filters or [])
        if _td_smart_solver_compact_value(value)
    }
    control_period_allowed = {
        _td_smart_solver_compact_value(value)
        for value in (control_period_filters or [])
        if _td_smart_solver_compact_value(value)
    } if uses_control_period else set()

    output_units = ""
    input1_units = ""
    input2_units = ""
    input3_units = ""
    points: list[dict[str, object]] = []
    keep_sequence_limit = _td_smart_solver_sequence_cap_value(keep_first_sequences_per_serial)
    dropped_sequence_count = 0
    dropped_point_count = 0
    distinct_suppression_voltages: list[str] = []
    seen_suppression_voltages: set[str] = set()
    sequence_metric_source = TD_METRIC_PLOT_SOURCE_ALL_SEQUENCES

    _td_emit_progress(progress_cb, "Loading sequence rows")

    for run_name in runs_list:
        output_col, output_units_candidate = _td_perf_resolve_y_col_units(path, run_name, output_name)
        input1_col, input1_units_candidate = _td_perf_resolve_y_col_units(path, run_name, input1_name)
        input2_col = ""
        input2_units_candidate = ""
        input3_col = ""
        input3_units_candidate = ""
        if input2_name:
            input2_col, input2_units_candidate = _td_perf_resolve_y_col_units(path, run_name, input2_name)
        if input3_name:
            input3_col, input3_units_candidate = _td_perf_resolve_y_col_units(path, run_name, input3_name)
        if not output_col or not input1_col or (input2_name and not input2_col) or (input3_name and not input3_col):
            continue
        output_units = output_units or output_units_candidate
        input1_units = input1_units or input1_units_candidate
        if input2_name:
            input2_units = input2_units or input2_units_candidate
        if input3_name:
            input3_units = input3_units or input3_units_candidate

        x1_rows = td_load_metric_series(
            path,
            run_name,
            input1_col,
            "mean",
            run_type_filter=solver_run_type_mode,
            metric_source=sequence_metric_source,
        )
        x2_rows = (
            td_load_metric_series(
                path,
                run_name,
                input2_col,
                "mean",
                run_type_filter=solver_run_type_mode,
                metric_source=sequence_metric_source,
            )
            if input2_name and input2_col
            else []
        )
        x3_rows = (
            td_load_metric_series(
                path,
                run_name,
                input3_col,
                "mean",
                run_type_filter=solver_run_type_mode,
                metric_source=sequence_metric_source,
            )
            if input3_name and input3_col
            else []
        )
        y_rows = td_load_metric_series(
            path,
            run_name,
            output_col,
            "mean",
            run_type_filter=solver_run_type_mode,
            metric_source=sequence_metric_source,
        )
        if not x1_rows or not y_rows or (input2_name and not x2_rows) or (input3_name and not x3_rows):
            continue

        x1_map = {
            str(row.get("observation_id") or "").strip(): dict(row)
            for row in x1_rows
            if isinstance(row, dict) and str(row.get("observation_id") or "").strip()
        }
        x2_map = {
            str(row.get("observation_id") or "").strip(): dict(row)
            for row in x2_rows
            if isinstance(row, dict) and str(row.get("observation_id") or "").strip()
        }
        x3_map = {
            str(row.get("observation_id") or "").strip(): dict(row)
            for row in x3_rows
            if isinstance(row, dict) and str(row.get("observation_id") or "").strip()
        }
        y_map = {
            str(row.get("observation_id") or "").strip(): dict(row)
            for row in y_rows
            if isinstance(row, dict) and str(row.get("observation_id") or "").strip()
        }
        common_ids = set(x1_map.keys()) & set(y_map.keys())
        if input2_name:
            common_ids &= set(x2_map.keys())
        if input3_name:
            common_ids &= set(x3_map.keys())
        for observation_id in sorted(common_ids):
            row_x1 = x1_map.get(observation_id) or {}
            row_x2 = x2_map.get(observation_id) or {}
            row_x3 = x3_map.get(observation_id) or {}
            row_y = y_map.get(observation_id) or {}
            base_row = row_y or row_x1 or row_x2 or row_x3
            serial = str(base_row.get("serial") or row_x1.get("serial") or row_x2.get("serial") or row_x3.get("serial") or "").strip()
            if not serial or serial not in serial_set:
                continue
            program_title = str(
                base_row.get("program_title")
                or row_x1.get("program_title")
                or row_x2.get("program_title")
                or row_x3.get("program_title")
                or ""
            ).strip()
            if program_allowed and (program_title or "Unknown Program") not in program_allowed:
                continue
            suppression_voltage = base_row.get(
                "suppression_voltage",
                row_x1.get("suppression_voltage", row_x2.get("suppression_voltage", row_x3.get("suppression_voltage"))),
            )
            if not _td_smart_solver_match_filter_value(suppression_voltage, suppression_allowed):
                continue
            control_period = base_row.get(
                "control_period",
                row_x1.get("control_period", row_x2.get("control_period", row_x3.get("control_period"))),
            )
            if uses_control_period and not _td_smart_solver_match_filter_value(control_period, control_period_allowed):
                continue
            x1_value = _td_finite_float(row_x1.get("value_num"))
            x2_value = _td_finite_float(row_x2.get("value_num")) if input2_name else None
            x3_value = _td_finite_float(row_x3.get("value_num")) if input3_name else None
            y_value = _td_finite_float(row_y.get("value_num"))
            cp_value = _td_finite_float(control_period) if uses_control_period else None
            if (
                x1_value is None
                or y_value is None
                or (uses_control_period and cp_value is None)
                or (input2_name and x2_value is None)
                or (input3_name and x3_value is None)
            ):
                continue
            suppression_label = _td_smart_solver_compact_value(suppression_voltage)
            if suppression_label and suppression_label not in seen_suppression_voltages:
                seen_suppression_voltages.add(suppression_label)
                distinct_suppression_voltages.append(suppression_label)
            points.append(
                {
                    "observation_id": observation_id,
                    "run_name": run_name,
                    "serial": serial,
                    "program_title": program_title or "Unknown Program",
                    "source_run_name": str(
                        base_row.get("source_run_name")
                        or row_x1.get("source_run_name")
                        or row_x2.get("source_run_name")
                        or ""
                    ).strip(),
                    "condition_label": _td_perf_export_condition_label(base_row, display_name=str(run_name or "").strip()),
                    "control_period": (float(cp_value) if uses_control_period and cp_value is not None else None),
                    "suppression_voltage": suppression_voltage,
                    "input_1": float(x1_value),
                    "input_2": (float(x2_value) if input2_name and x2_value is not None else None),
                    "input_3": (float(x3_value) if input3_name and x3_value is not None else None),
                    "actual_mean": float(y_value),
                    "sample_count": 1,
                }
            )

    if keep_sequence_limit > 0:
        _td_emit_progress(progress_cb, "Applying sequence cap")
        points, dropped_sequence_count, dropped_point_count = _td_smart_solver_apply_sequence_cap(
            points,
            keep_sequence_limit,
        )

    if not points:
        raise RuntimeError(
            "No qualifying sequence-level mean rows were found for the selected Smart Equation Solver inputs."
        )

    control_period_values = sorted({float(point["control_period"]) for point in points if isinstance(point.get("control_period"), (int, float))})
    if uses_control_period and len(control_period_values) < 2:
        if control_period_allowed:
            raise RuntimeError(
                "Smart Equation Solver requires at least two distinct control periods after filtering. "
                "Broaden the active control-period filter and try again."
            )
        raise RuntimeError("Smart Equation Solver requires at least two distinct control periods.")

    x1_values = [float(point["input_1"]) for point in points]
    y_values = [float(point["actual_mean"]) for point in points]
    cp_values = [float(point["control_period"]) for point in points if isinstance(point.get("control_period"), (int, float))]
    x2_values = [float(point["input_2"]) for point in points if point.get("input_2") not in (None, "")]
    x3_values = [float(point["input_3"]) for point in points if point.get("input_3") not in (None, "")]

    fit_mode = TD_PERF_FIT_MODE_POLYNOMIAL_SURFACE
    variable_descriptors = td_smart_solver_variable_descriptors()
    support: dict[str, object] = {}
    slice_rows: list[dict[str, object]] = []
    selection_reason = "Current solver path selected from configured inputs."
    candidate_scores: dict[str, object] = {}
    selected_candidate_summary: dict[str, object] = {}
    eligible_control_period_values: list[float] = []
    model: dict[str, object] | None = None

    def _cp_slice_rows(raw_rows: Sequence[Mapping[str, object]] | None) -> list[dict[str, object]]:
        rows: list[dict[str, object]] = []
        for raw_row in raw_rows or []:
            if not isinstance(raw_row, Mapping):
                continue
            rows.append(
                {
                    "control_period": raw_row.get("control_period"),
                    "point_count": int(raw_row.get("point_count") or 0),
                    "distinct_input_1": int(raw_row.get("distinct_x1") or raw_row.get("distinct_input_1") or 0),
                    "distinct_input_2": (
                        int(raw_row.get("distinct_x2") or raw_row.get("distinct_input_2") or 0)
                        if input2_name
                        else None
                    ),
                    "distinct_input_3": (
                        int(raw_row.get("distinct_x3") or raw_row.get("distinct_input_3") or 0)
                        if input3_name
                        else None
                    ),
                    "eligible": bool(raw_row.get("eligible")),
                    "reason": str(raw_row.get("reason") or "").strip(),
                }
            )
        return rows

    def _steady_state_scope_rows(*, eligible: bool = True, reason: str = "") -> list[dict[str, object]]:
        def _distinct_count(key: str, enabled: bool) -> int | None:
            if not enabled:
                return None
            return int(
                len(
                    {
                        round(float(point.get(key) or 0.0), 12)
                        for point in points
                        if _td_finite_float(point.get(key)) is not None
                    }
                )
            )

        return [
            {
                "scope": "steady_state",
                "point_count": int(len(points)),
                "distinct_input_1": _distinct_count("input_1", True),
                "distinct_input_2": _distinct_count("input_2", bool(input2_name)),
                "distinct_input_3": _distinct_count("input_3", bool(input3_name)),
                "eligible": bool(eligible),
                "reason": str(reason or "").strip(),
            }
        ]

    if input3_name and uses_control_period:
        direct_support = _td_perf_analyze_quadratic_3input_control_period_fit_support(
            x1_values,
            x2_values,
            x3_values,
            y_values,
            cp_values,
            min_points=TD_SMART_SOLVER_DIRECT_3INPUT_MIN_POINTS,
            min_distinct_x1=TD_SMART_SOLVER_DIRECT_3INPUT_MIN_DISTINCT_X,
            min_distinct_x2=TD_SMART_SOLVER_DIRECT_3INPUT_MIN_DISTINCT_X,
            min_distinct_x3=TD_SMART_SOLVER_DIRECT_3INPUT_MIN_DISTINCT_X,
        )
        direct_eligible_control_period_values = [float(value) for value in (direct_support.get("eligible_control_period_values") or [])]
        direct_model = None
        if len(direct_eligible_control_period_values) >= 2:
            _td_emit_progress(progress_cb, "Fitting 3-input direct control-period slices")
            direct_model = _td_perf_fit_quadratic_3input_control_period_model(
                x1_values,
                x2_values,
                x3_values,
                y_values,
                cp_values,
                min_points=TD_SMART_SOLVER_DIRECT_3INPUT_MIN_POINTS,
                min_distinct_x1=TD_SMART_SOLVER_DIRECT_3INPUT_MIN_DISTINCT_X,
                min_distinct_x2=TD_SMART_SOLVER_DIRECT_3INPUT_MIN_DISTINCT_X,
                min_distinct_x3=TD_SMART_SOLVER_DIRECT_3INPUT_MIN_DISTINCT_X,
            )
        staged_model = None
        _td_emit_progress(progress_cb, "Evaluating staged mediator candidate")
        staged_model = _td_perf_fit_staged_mediator_control_period_model(
            x1_values,
            x2_values,
            x3_values,
            y_values,
            cp_values,
            mediator_target=input3_name,
            fit_mode=fit_mode,
        )
        staged_predictions: list[float] = []
        if isinstance(staged_model, Mapping):
            staged_stage1_model = dict(staged_model.get("stage1_model") or {})
            staged_stage2_model = dict(staged_model.get("stage2_model") or {})
            staged_mediator_predictions = td_perf_predict_surface(
                staged_stage1_model,
                x1_values,
                x2_values,
                control_period=cp_values,
            )
            staged_mediator_domain = _td_smart_solver_numeric_domain(
                staged_model.get("stage2_input_domain") or staged_stage2_model.get("fit_domain") or staged_mediator_predictions
            )
            staged_mediator_clamped, _staged_clamp_hits = _td_smart_solver_clamp_values(staged_mediator_predictions, staged_mediator_domain)
            staged_predictions = td_perf_predict_model(
                staged_stage2_model,
                staged_mediator_clamped,
                control_period=cp_values,
            )
        direct_predictions = (
            _td_perf_predict_quadratic_3input_control_period(direct_model, x1_values, x2_values, x3_values, cp_values)
            if isinstance(direct_model, Mapping)
            else []
        )
        direct_summary = _td_smart_solver_candidate_summary(
            model=direct_model if isinstance(direct_model, Mapping) else None,
            actual_values=y_values,
            predicted_values=direct_predictions,
            ignored_control_periods=[dict(item) for item in (direct_support.get("ignored_control_periods") or []) if isinstance(item, Mapping)],
            clamp_hits=0,
        )
        staged_summary = _td_smart_solver_candidate_summary(
            model=staged_model if isinstance(staged_model, Mapping) else None,
            actual_values=y_values,
            predicted_values=staged_predictions,
            ignored_control_periods=[dict(item) for item in (staged_model.get("ignored_control_periods") or []) if isinstance(item, Mapping)] if isinstance(staged_model, Mapping) else [],
            clamp_hits=int((staged_model or {}).get("mediator_clamp_count") or 0) if isinstance(staged_model, Mapping) else 0,
            stage2_fit_source=str((staged_model or {}).get("stage2_fit_source") or "") if isinstance(staged_model, Mapping) else "",
            stage1_rmse=_td_finite_float((staged_model or {}).get("stage1_rmse")) if isinstance(staged_model, Mapping) else None,
        )
        candidate_scores = {
            "selected": "",
            "direct": {
                **dict(direct_summary),
                "fit_family": str((direct_model or {}).get("fit_family") or TD_PERF_FIT_FAMILY_QUADRATIC_3INPUT_CONTROL_PERIOD),
                "eligible_control_period_count": int(len(direct_eligible_control_period_values)),
            },
            "staged": {
                **dict(staged_summary),
                "fit_family": str((staged_model or {}).get("fit_family") or TD_PERF_FIT_FAMILY_STAGED_MEDIATOR_CONTROL_PERIOD),
                "stage2_fit_source": str((staged_model or {}).get("stage2_fit_source") or "") if isinstance(staged_model, Mapping) else "",
            },
        }

        if isinstance(direct_model, Mapping) and isinstance(staged_model, Mapping):
            direct_stable = bool(direct_summary.get("stability_ok"))
            staged_stable = bool(staged_summary.get("stability_ok"))
            direct_rmse = _td_smart_solver_candidate_rmse(direct_summary)
            staged_rmse = _td_smart_solver_candidate_rmse(staged_summary)
            if staged_stable and not direct_stable:
                model = dict(staged_model)
                support = {}
                slice_rows = [
                    {
                        "control_period": row.get("control_period"),
                        "point_count": int(row.get("point_count") or 0),
                        "distinct_input_1": int(row.get("distinct_x1") or 0),
                        "distinct_input_2": int(row.get("distinct_x2") or 0),
                        "distinct_input_3": int(row.get("distinct_x3") or 0),
                        "eligible": bool(row.get("eligible")),
                        "reason": str(row.get("reason") or "").strip(),
                    }
                    for row in _td_smart_solver_stage_slice_rows(points, stage1_model=model, stage2_model=model)
                ]
                selection_reason = (
                    "Staged mediator branch selected because it was stable while the direct 3-input branch was not."
                )
                selected_candidate_summary = dict(staged_summary)
            elif direct_stable and not staged_stable:
                model = dict(direct_model)
                support = dict(direct_support)
                slice_rows = [
                    {
                        "control_period": row.get("control_period"),
                        "point_count": int(row.get("point_count") or 0),
                        "distinct_input_1": int(row.get("distinct_x1") or 0),
                        "distinct_input_2": int(row.get("distinct_x2") or 0),
                        "distinct_input_3": int(row.get("distinct_x3") or 0),
                        "eligible": bool(row.get("eligible")),
                        "reason": str(row.get("reason") or "").strip(),
                    }
                    for row in (direct_support.get("slice_rows") or [])
                    if isinstance(row, Mapping)
                ]
                selection_reason = (
                    "Direct 3-input branch selected because it was stable while the staged mediator branch was not."
                )
                selected_candidate_summary = dict(direct_summary)
            elif staged_stable and direct_stable:
                if (
                    math.isfinite(direct_rmse)
                    and math.isfinite(staged_rmse)
                    and staged_rmse > 0.0
                    and direct_rmse <= (0.95 * staged_rmse)
                ):
                    model = dict(direct_model)
                    support = dict(direct_support)
                    slice_rows = [
                        {
                            "control_period": row.get("control_period"),
                            "point_count": int(row.get("point_count") or 0),
                            "distinct_input_1": int(row.get("distinct_x1") or 0),
                            "distinct_input_2": int(row.get("distinct_x2") or 0),
                            "distinct_input_3": int(row.get("distinct_x3") or 0),
                            "eligible": bool(row.get("eligible")),
                            "reason": str(row.get("reason") or "").strip(),
                        }
                        for row in (direct_support.get("slice_rows") or [])
                        if isinstance(row, Mapping)
                    ]
                    selection_reason = (
                        "Direct 3-input branch selected because it improved final RMSE by more than 5% over the stable staged mediator branch "
                        f"({direct_rmse:.6g} vs {staged_rmse:.6g})."
                    )
                    selected_candidate_summary = dict(direct_summary)
                else:
                    model = dict(staged_model)
                    support = {}
                    slice_rows = [
                        {
                            "control_period": row.get("control_period"),
                            "point_count": int(row.get("point_count") or 0),
                            "distinct_input_1": int(row.get("distinct_x1") or 0),
                            "distinct_input_2": int(row.get("distinct_x2") or 0),
                            "distinct_input_3": int(row.get("distinct_x3") or 0),
                            "eligible": bool(row.get("eligible")),
                            "reason": str(row.get("reason") or "").strip(),
                        }
                        for row in _td_smart_solver_stage_slice_rows(points, stage1_model=model, stage2_model=model)
                    ]
                    selection_reason = (
                        "Staged mediator branch selected because both candidates were stable and the direct 3-input branch did not improve final RMSE by more than 5%."
                    )
                    selected_candidate_summary = dict(staged_summary)
            else:
                if direct_rmse <= staged_rmse:
                    model = dict(direct_model)
                    support = dict(direct_support)
                    slice_rows = [
                        {
                            "control_period": row.get("control_period"),
                            "point_count": int(row.get("point_count") or 0),
                            "distinct_input_1": int(row.get("distinct_x1") or 0),
                            "distinct_input_2": int(row.get("distinct_x2") or 0),
                            "distinct_input_3": int(row.get("distinct_x3") or 0),
                            "eligible": bool(row.get("eligible")),
                            "reason": str(row.get("reason") or "").strip(),
                        }
                        for row in (direct_support.get("slice_rows") or [])
                        if isinstance(row, Mapping)
                    ]
                    selected_candidate_summary = dict(direct_summary)
                else:
                    model = dict(staged_model)
                    support = {}
                    slice_rows = [
                        {
                            "control_period": row.get("control_period"),
                            "point_count": int(row.get("point_count") or 0),
                            "distinct_input_1": int(row.get("distinct_x1") or 0),
                            "distinct_input_2": int(row.get("distinct_x2") or 0),
                            "distinct_input_3": int(row.get("distinct_x3") or 0),
                            "eligible": bool(row.get("eligible")),
                            "reason": str(row.get("reason") or "").strip(),
                        }
                        for row in _td_smart_solver_stage_slice_rows(points, stage1_model=model, stage2_model=model)
                    ]
                    selected_candidate_summary = dict(staged_summary)
                selection_reason = (
                    "Both direct and staged 3D candidates were unstable; the lower-RMSE branch was retained."
                )
        elif isinstance(direct_model, Mapping):
            model = dict(direct_model)
            support = dict(direct_support)
            slice_rows = [
                {
                    "control_period": row.get("control_period"),
                    "point_count": int(row.get("point_count") or 0),
                    "distinct_input_1": int(row.get("distinct_x1") or 0),
                    "distinct_input_2": int(row.get("distinct_x2") or 0),
                    "distinct_input_3": int(row.get("distinct_x3") or 0),
                    "eligible": bool(row.get("eligible")),
                    "reason": str(row.get("reason") or "").strip(),
                }
                for row in (direct_support.get("slice_rows") or [])
                if isinstance(row, Mapping)
            ]
            selection_reason = "Direct 3-input branch selected because the staged mediator candidate was unavailable."
            selected_candidate_summary = dict(direct_summary)
        elif isinstance(staged_model, Mapping):
            model = dict(staged_model)
            support = {}
            slice_rows = [
                {
                    "control_period": row.get("control_period"),
                    "point_count": int(row.get("point_count") or 0),
                    "distinct_input_1": int(row.get("distinct_x1") or 0),
                    "distinct_input_2": int(row.get("distinct_x2") or 0),
                    "distinct_input_3": int(row.get("distinct_x3") or 0),
                    "eligible": bool(row.get("eligible")),
                    "reason": str(row.get("reason") or "").strip(),
                }
                for row in _td_smart_solver_stage_slice_rows(points, stage1_model=model, stage2_model=model)
            ]
            direct_failure_text = _td_perf_format_three_input_control_period_failure(
                direct_support.get("ignored_control_periods") or [],
                eligible_count=len(direct_eligible_control_period_values),
            )
            selection_reason = f"Staged mediator branch selected because the direct 3-input branch was unavailable. {direct_failure_text}"
            selected_candidate_summary = dict(staged_summary)
        else:
            direct_failure_text = _td_perf_format_three_input_control_period_failure(
                direct_support.get("ignored_control_periods") or [],
                eligible_count=len(direct_eligible_control_period_values),
            )
            raise RuntimeError(f"{direct_failure_text} Staged mediator candidate was also unavailable.")
        candidate_scores["selected"] = str(model.get("fit_family") or "")
    elif input3_name:
        _td_emit_progress(progress_cb, "Fitting steady-state 3-input candidates")
        direct_model = _td_perf_fit_quadratic_3input_model(
            x1_values,
            x2_values,
            x3_values,
            y_values,
            min_points=TD_SMART_SOLVER_DIRECT_3INPUT_MIN_POINTS,
            min_distinct_x1=TD_SMART_SOLVER_DIRECT_3INPUT_MIN_DISTINCT_X,
            min_distinct_x2=TD_SMART_SOLVER_DIRECT_3INPUT_MIN_DISTINCT_X,
            min_distinct_x3=TD_SMART_SOLVER_DIRECT_3INPUT_MIN_DISTINCT_X,
        )
        _td_emit_progress(progress_cb, "Evaluating staged mediator candidate")
        staged_model = _td_perf_fit_staged_mediator_model(
            x1_values,
            x2_values,
            x3_values,
            y_values,
            mediator_target=input3_name,
        )
        direct_predictions = (
            _td_perf_predict_quadratic_3input(direct_model, x1_values, x2_values, x3_values)
            if isinstance(direct_model, Mapping)
            else []
        )
        staged_predictions: list[float] = []
        if isinstance(staged_model, Mapping):
            staged_stage1_model = dict(staged_model.get("stage1_model") or {})
            staged_stage2_model = dict(staged_model.get("stage2_model") or {})
            staged_mediator_predictions = td_perf_predict_surface(staged_stage1_model, x1_values, x2_values)
            staged_mediator_domain = _td_smart_solver_numeric_domain(
                staged_model.get("stage2_input_domain")
                or staged_stage2_model.get("fit_domain")
                or staged_mediator_predictions
            )
            staged_mediator_clamped, _staged_clamp_hits = _td_smart_solver_clamp_values(
                staged_mediator_predictions,
                staged_mediator_domain,
            )
            staged_predictions = td_perf_predict_model(staged_stage2_model, staged_mediator_clamped)
        direct_summary = _td_smart_solver_candidate_summary(
            model=direct_model if isinstance(direct_model, Mapping) else None,
            actual_values=y_values,
            predicted_values=direct_predictions,
            ignored_control_periods=[],
            clamp_hits=0,
        )
        staged_summary = _td_smart_solver_candidate_summary(
            model=staged_model if isinstance(staged_model, Mapping) else None,
            actual_values=y_values,
            predicted_values=staged_predictions,
            ignored_control_periods=[],
            clamp_hits=int((staged_model or {}).get("mediator_clamp_count") or 0)
            if isinstance(staged_model, Mapping)
            else 0,
            stage2_fit_source=str((staged_model or {}).get("stage2_fit_source") or "")
            if isinstance(staged_model, Mapping)
            else "",
            stage1_rmse=_td_finite_float((staged_model or {}).get("stage1_rmse"))
            if isinstance(staged_model, Mapping)
            else None,
        )
        candidate_scores = {
            "selected": "",
            "direct": {
                **dict(direct_summary),
                "fit_family": str((direct_model or {}).get("fit_family") or TD_PERF_FIT_FAMILY_QUADRATIC_3INPUT),
            },
            "staged": {
                **dict(staged_summary),
                "fit_family": str((staged_model or {}).get("fit_family") or TD_PERF_FIT_FAMILY_STAGED_MEDIATOR),
                "stage2_fit_source": str((staged_model or {}).get("stage2_fit_source") or "")
                if isinstance(staged_model, Mapping)
                else "",
            },
        }
        if isinstance(direct_model, Mapping) and isinstance(staged_model, Mapping):
            direct_stable = bool(direct_summary.get("stability_ok"))
            staged_stable = bool(staged_summary.get("stability_ok"))
            direct_rmse = _td_smart_solver_candidate_rmse(direct_summary)
            staged_rmse = _td_smart_solver_candidate_rmse(staged_summary)
            if staged_stable and not direct_stable:
                model = dict(staged_model)
                selection_reason = (
                    "Staged mediator branch selected because it was stable while the direct 3-input branch was not."
                )
                selected_candidate_summary = dict(staged_summary)
            elif direct_stable and not staged_stable:
                model = dict(direct_model)
                selection_reason = (
                    "Direct 3-input branch selected because it was stable while the staged mediator branch was not."
                )
                selected_candidate_summary = dict(direct_summary)
            elif staged_stable and direct_stable:
                if (
                    math.isfinite(direct_rmse)
                    and math.isfinite(staged_rmse)
                    and staged_rmse > 0.0
                    and direct_rmse <= (0.95 * staged_rmse)
                ):
                    model = dict(direct_model)
                    selection_reason = (
                        "Direct 3-input branch selected because it improved final RMSE by more than 5% over the stable staged mediator branch "
                        f"({direct_rmse:.6g} vs {staged_rmse:.6g})."
                    )
                    selected_candidate_summary = dict(direct_summary)
                else:
                    model = dict(staged_model)
                    selection_reason = (
                        "Staged mediator branch selected because both candidates were stable and the direct 3-input branch did not improve final RMSE by more than 5%."
                    )
                    selected_candidate_summary = dict(staged_summary)
            else:
                if direct_rmse <= staged_rmse:
                    model = dict(direct_model)
                    selected_candidate_summary = dict(direct_summary)
                else:
                    model = dict(staged_model)
                    selected_candidate_summary = dict(staged_summary)
                selection_reason = (
                    "Both direct and staged 3D candidates were unstable; the lower-RMSE branch was retained."
                )
        elif isinstance(direct_model, Mapping):
            model = dict(direct_model)
            selection_reason = "Direct 3-input branch selected because the staged mediator candidate was unavailable."
            selected_candidate_summary = dict(direct_summary)
        elif isinstance(staged_model, Mapping):
            model = dict(staged_model)
            selection_reason = "Staged mediator branch selected because the direct 3-input branch was unavailable."
            selected_candidate_summary = dict(staged_summary)
        else:
            raise RuntimeError("Smart Equation Solver could not fit either steady-state 3D candidate.")
        candidate_scores["selected"] = str(model.get("fit_family") or "")
        slice_rows = _steady_state_scope_rows(eligible=True, reason=selection_reason)
    elif uses_control_period and input2_name:
        support = _td_perf_analyze_quadratic_surface_control_period_fit_support(
            x1_values,
            x2_values,
            y_values,
            cp_values,
            fit_mode=fit_mode,
        )
        eligible_control_period_values = [float(value) for value in (support.get("eligible_control_period_values") or [])]
        slice_rows = _cp_slice_rows(support.get("slice_rows") or [])
    elif uses_control_period:
        support = _td_perf_analyze_quadratic_curve_control_period_fit_support(
            x1_values,
            y_values,
            cp_values,
        )
        eligible_control_period_values = [float(value) for value in (support.get("eligible_control_period_values") or [])]
        slice_rows = _cp_slice_rows(support.get("slice_rows") or [])
    else:
        _td_emit_progress(progress_cb, "Fitting steady-state model")
        if input2_name:
            model = td_perf_fit_surface_model(
                x1_values,
                x2_values,
                y_values,
                auto_surface_families=True,
                surface_family=TD_PERF_FIT_MODE_AUTO_SURFACE,
            )
            selected_predictions = (
                td_perf_predict_surface(model, x1_values, x2_values) if isinstance(model, dict) else []
            )
        else:
            model = td_perf_fit_model(
                x1_values,
                y_values,
                fit_mode=TD_PERF_FIT_MODE_AUTO,
            )
            selected_predictions = td_perf_predict_model(model, x1_values) if isinstance(model, dict) else []
        if not isinstance(model, dict):
            raise RuntimeError(
                "Smart Equation Solver could not fit a steady-state model for the filtered sequence rows."
            )
        selected_candidate_summary = _td_smart_solver_candidate_summary(
            model=model,
            actual_values=y_values,
            predicted_values=selected_predictions,
            ignored_control_periods=[],
            clamp_hits=0,
        )
        candidate_scores = {"selected": str(model.get("fit_family") or "")}
        slice_rows = _steady_state_scope_rows()

    if uses_control_period and not input3_name and len(eligible_control_period_values) < 2:
        if input2_name:
            failure_text = _td_perf_format_surface_control_period_failure(
                support.get("ignored_control_periods") or [],
                eligible_count=len(eligible_control_period_values),
            )
        else:
            failure_text = _td_perf_format_curve_control_period_failure(
                support.get("ignored_control_periods") or [],
                eligible_count=len(eligible_control_period_values),
            )
        if control_period_allowed:
            failure_text = f"{failure_text} Broaden the active control-period filter and try again."
        raise RuntimeError(failure_text)

    if uses_control_period and not input3_name:
        _td_emit_progress(progress_cb, "Fitting control-period slices")
        if input2_name:
            model = _td_perf_fit_quadratic_surface_control_period_model(
                x1_values,
                x2_values,
                y_values,
                cp_values,
                fit_mode=fit_mode,
            )
        else:
            legacy_curve_model = _td_perf_fit_quadratic_curve_control_period_model(
                x1_values,
                y_values,
                cp_values,
            )
            model = _td_perf_fit_hybrid_quadratic_residual_control_period_model(
                x1_values,
                y_values,
                cp_values,
                support=support,
                legacy_model=legacy_curve_model,
            )
            if not isinstance(model, dict):
                model = legacy_curve_model
        if not isinstance(model, dict):
            raise RuntimeError(
                "Smart Equation Solver could not fit a control-period-aware model for the filtered sequence rows."
            )
        if not input2_name:
            model = _td_smart_solver_attach_curve_cp_boundary_metadata(
                model,
                x1_values,
                y_values,
                cp_values,
            ) or {}
            if not model:
                raise RuntimeError(
                    "Smart Equation Solver could not apply bounded control-period support to the fitted curve model."
                )
        selected_predictions = (
            td_perf_predict_surface(model, x1_values, x2_values, control_period=cp_values)
            if input2_name
            else _td_smart_solver_predict_model(model, x1_values, control_period=cp_values)
        )
        selected_candidate_summary = _td_smart_solver_candidate_summary(
            model=model,
            actual_values=y_values,
            predicted_values=selected_predictions,
            ignored_control_periods=[dict(item) for item in (support.get("ignored_control_periods") or []) if isinstance(item, Mapping)],
            clamp_hits=0,
        )
        candidate_scores = {"selected": str(model.get("fit_family") or "")}

    model["solver_branch"] = str(model.get("fit_family") or "")
    model["selection_reason"] = selection_reason
    model["candidate_scores"] = dict(candidate_scores)
    model["run_type_mode"] = solver_run_type_mode
    model["uses_control_period"] = bool(uses_control_period)

    _td_emit_progress(progress_cb, "Binding model coefficients")
    stage1_residuals: list[float] = []
    stage1_clamped_predictions: list[float] = []
    mediator_predictions: list[float] = []
    selected_family = str(model.get("fit_family") or "")
    if input3_name and selected_family == TD_PERF_FIT_FAMILY_QUADRATIC_3INPUT_CONTROL_PERIOD:
        predictions = _td_perf_predict_quadratic_3input_control_period(
            model,
            x1_values,
            x2_values,
            x3_values,
            cp_values,
        )
    elif input3_name and selected_family == TD_PERF_FIT_FAMILY_QUADRATIC_3INPUT:
        predictions = _td_perf_predict_quadratic_3input(
            model,
            x1_values,
            x2_values,
            x3_values,
        )
    elif input3_name and selected_family in {
        TD_PERF_FIT_FAMILY_STAGED_MEDIATOR_CONTROL_PERIOD,
        TD_PERF_FIT_FAMILY_STAGED_MEDIATOR,
    }:
        stage1_model = dict(model.get("stage1_model") or {})
        stage2_model = dict(model.get("stage2_model") or {})
        mediator_predictions = (
            td_perf_predict_surface(stage1_model, x1_values, x2_values, control_period=cp_values)
            if selected_family == TD_PERF_FIT_FAMILY_STAGED_MEDIATOR_CONTROL_PERIOD
            else td_perf_predict_surface(stage1_model, x1_values, x2_values)
        )
        if len(mediator_predictions) == len(x3_values):
            stage1_residuals = [
                float(mediator_predictions[idx]) - float(x3_values[idx]) for idx in range(len(mediator_predictions))
            ]
        mediator_domain = _td_smart_solver_numeric_domain(
            model.get("stage2_input_domain") or stage2_model.get("fit_domain") or mediator_predictions
        )
        stage1_clamped_predictions, _mediator_clamp_hits = _td_smart_solver_clamp_values(mediator_predictions, mediator_domain)
        predictions = (
            _td_smart_solver_predict_model(stage2_model, stage1_clamped_predictions, control_period=cp_values)
            if selected_family == TD_PERF_FIT_FAMILY_STAGED_MEDIATOR_CONTROL_PERIOD
            else td_perf_predict_model(stage2_model, stage1_clamped_predictions)
        )
    else:
        predictions = (
            td_perf_predict_surface(
                model,
                x1_values,
                x2_values,
                control_period=cp_values if selected_family in TD_PERF_ANY_CONTROL_PERIOD_FAMILIES else None,
            )
            if input2_name
            else _td_smart_solver_predict_model(
                model,
                x1_values,
                control_period=cp_values if selected_family in TD_PERF_ANY_CONTROL_PERIOD_FAMILIES else None,
            )
        )
    if len(predictions) != len(points):
        raise RuntimeError("Smart Equation Solver could not score the fitted surface.")

    _td_emit_progress(progress_cb, "Scoring residuals")
    summary_stats = _td_smart_solver_score_predictions(y_values, [float(value) for value in predictions])
    rmse = float(summary_stats.get("rmse") or 0.0)
    residual_threshold = float(summary_stats.get("residual_threshold") or 0.0)
    in_fit_count = int(summary_stats.get("in_fit_count") or 0)
    sample_count = int(summary_stats.get("sample_count") or len(points))
    fell_out_count = int(summary_stats.get("fell_out_count") or 0)
    in_fit_percent = float((100.0 * in_fit_count / sample_count) if sample_count > 0 else 0.0)

    if not selected_candidate_summary:
        selected_candidate_summary = _td_smart_solver_candidate_summary(
            model=model,
            actual_values=y_values,
            predicted_values=[float(value) for value in predictions],
            ignored_control_periods=(
                [dict(item) for item in (support.get("ignored_control_periods") or []) if isinstance(item, Mapping)]
                if uses_control_period and support
                else []
            ),
            clamp_hits=int(model.get("mediator_clamp_count") or 0),
            stage2_fit_source=str(model.get("stage2_fit_source") or ""),
            stage1_rmse=_td_finite_float(model.get("stage1_rmse")),
        )
    three_sigma_support = _td_smart_solver_build_three_sigma_support(
        points,
        predictions,
        uses_control_period=uses_control_period,
    )
    for idx, point in enumerate(points):
        pred_mean = float(predictions[idx])
        three_sigma_offset = _td_smart_solver_resolve_three_sigma_offset(
            three_sigma_support,
            control_period=point.get("control_period"),
        )
        point["pred_mean"] = float(pred_mean)
        point["pred_min_3sigma"] = float(pred_mean - three_sigma_offset)
        point["pred_max_3sigma"] = float(pred_mean + three_sigma_offset)
        if stage1_residuals and idx < len(stage1_residuals) and idx < len(mediator_predictions):
            point["stage1_pred_input_3"] = float(mediator_predictions[idx])
            point["stage1_residual_input_3"] = float(stage1_residuals[idx])
        if stage1_clamped_predictions and idx < len(stage1_clamped_predictions):
            point["stage1_clamped_input_3"] = float(stage1_clamped_predictions[idx])

    warning_messages: list[str] = []
    fit_warning_text = str(model.get("fit_warning_text") or "").strip()
    if fit_warning_text:
        warning_messages.append(fit_warning_text)
    mediator_clamp_count = int(model.get("mediator_clamp_count") or 0)
    if mediator_clamp_count > 0:
        warning_messages.append(f"Mediator clamp hits: {mediator_clamp_count}.")
    if len(distinct_suppression_voltages) > 1:
        warning_messages.append(
            "Suppression voltage is not modeled in Smart Equation Solver v1; "
            f"the fitted rows include multiple voltages: {', '.join(distinct_suppression_voltages)}."
        )
    if keep_sequence_limit > 0:
        if dropped_sequence_count > 0 or dropped_point_count > 0:
            warning_messages.append(
                "Sequence cap kept the first "
                f"{keep_sequence_limit} sequence(s) per serial and dropped "
                f"{dropped_sequence_count} later sequence(s) / {dropped_point_count} fit point(s)."
            )
        else:
            warning_messages.append(
                f"Sequence cap kept the first {keep_sequence_limit} sequence(s) per serial; no later sequences were present after filtering."
            )
    if input3_name and not bool(selected_candidate_summary.get("stability_ok")):
        warning_messages.append(
            "Selected 3D branch remained unstable after automatic guardrails; "
            + (
                "review clamp counts and ignored control-period slices."
                if uses_control_period
                else "review clamp counts and candidate diagnostics."
            )
        )

    solver_variables = _td_smart_solver_export_variables(
        input1_target=input1_name,
        input1_units=input1_units,
        input2_target=input2_name,
        input2_units=input2_units,
        input3_target=input3_name,
        input3_units=input3_units,
        variable_descriptors=variable_descriptors,
    )
    uses_staged_mediator = selected_family in {
        TD_PERF_FIT_FAMILY_STAGED_MEDIATOR_CONTROL_PERIOD,
        TD_PERF_FIT_FAMILY_STAGED_MEDIATOR,
    }
    stage_export_spec: dict[str, object] = {}
    if uses_staged_mediator:
        stage_export_spec = {
            "stage1_output_key": "stage1_pred_input_3",
            "stage1_output_target": input3_name,
            "stage1_output_units": input3_units,
            "stage1_input_keys": ["input_1", "input_2"],
            "stage2_input_key": "stage1_pred_input_3",
        }
        if model.get("stage2_input_domain") not in (None, ""):
            stage_export_spec["stage2_input_domain"] = [
                float(value)
                for value in (model.get("stage2_input_domain") or [])
                if isinstance(value, (int, float))
            ][:2]
    three_sigma_equation_texts = _td_smart_solver_three_sigma_equation_texts(
        {
            "equation": str(model.get("equation") or "").strip(),
            "x_norm_equation": str(model.get("x_norm_equation") or "").strip(),
            "three_sigma_offset": _td_finite_float(three_sigma_support.get("three_sigma_offset")),
            "three_sigma_support_rows": _td_smart_solver_three_sigma_support_rows(three_sigma_support),
        }
    )

    return {
        "fit_family": selected_family,
        "equation": str(model.get("equation") or "").strip(),
        "x_norm_equation": str(model.get("x_norm_equation") or "").strip(),
        "master_model": dict(model),
        "fit_points": [dict(point) for point in points],
        "control_period_hard_input": bool(control_period_hard_input),
        "keep_first_sequences_per_serial": int(keep_sequence_limit),
        "dropped_sequence_count": int(dropped_sequence_count),
        "dropped_point_count": int(dropped_point_count),
        "run_type_mode": solver_run_type_mode,
        "rmse": float(rmse),
        "residual_threshold": float(residual_threshold),
        "three_sigma_basis": str(three_sigma_support.get("three_sigma_basis") or ""),
        "three_sigma_cp_policy": str(three_sigma_support.get("three_sigma_cp_policy") or ""),
        "three_sigma_offset": _td_finite_float(three_sigma_support.get("three_sigma_offset")),
        "three_sigma_support_rows": _td_smart_solver_three_sigma_support_rows(three_sigma_support),
        "three_sigma_offset_equation": str(three_sigma_equation_texts.get("offset_equation") or ""),
        "pred_min_3sigma_equation": str(three_sigma_equation_texts.get("pred_min_3sigma_equation") or ""),
        "pred_max_3sigma_equation": str(three_sigma_equation_texts.get("pred_max_3sigma_equation") or ""),
        "in_fit_count": int(in_fit_count),
        "fell_out_count": int(fell_out_count),
        "sample_count": int(sample_count),
        "in_fit_percent": float(in_fit_percent),
        "warning_text": _td_smart_solver_warning_text(warning_messages),
        "ignored_control_periods": (
            [dict(item) for item in (support.get("ignored_control_periods") or []) if isinstance(item, Mapping)]
            if uses_control_period and support
            else ([dict(row) for row in slice_rows if not bool(row.get("eligible"))] if uses_control_period else [])
        ),
        "slice_rows": slice_rows,
        "low_x_breakpoint": _td_finite_float(model.get("low_x_breakpoint")),
        "low_x_window_enabled": bool(model.get("low_x_window_enabled")),
        "stabilization_passes": int(model.get("stabilization_passes") or 0),
        "fallback_used": bool(model.get("fallback_used")),
        "support_profile": (
            dict(model.get("support_profile") or {})
            if isinstance(model.get("support_profile"), Mapping)
            else {}
        ),
        "base_fit_family": str(model.get("base_fit_family") or ""),
        "control_period_domain": (
            [
                float(value)
                for value in (
                    model.get("fit_domain_control_period")
                    or ([min(control_period_values), max(control_period_values)] if control_period_values else [])
                )
                if isinstance(value, (int, float))
            ][:2]
            if uses_control_period
            else []
        ),
        "distinct_suppression_voltages": list(distinct_suppression_voltages),
        "output_target": output_name,
        "output_units": output_units,
        "input1_target": input1_name,
        "input1_units": input1_units,
        "input2_target": input2_name,
        "input2_units": input2_units,
        "input3_target": input3_name,
        "input3_units": input3_units,
        "solver_branch": selected_family,
        "selection_reason": selection_reason,
        "candidate_scores": dict(candidate_scores),
        "stability_ok": bool(selected_candidate_summary.get("stability_ok")),
        "stage1_rmse": _td_finite_float(model.get("stage1_rmse")),
        "stage2_fit_source": str(model.get("stage2_fit_source") or ""),
        "mediator_clamp_count": int(model.get("mediator_clamp_count") or 0),
        "variable_descriptors": variable_descriptors,
        "solver_variables": solver_variables,
        "uses_control_period": bool(uses_control_period),
        "uses_staged_mediator": uses_staged_mediator,
        "stage_export_spec": stage_export_spec,
        "stage1_output_key": str(stage_export_spec.get("stage1_output_key") or ""),
        "stage1_output_target": str(stage_export_spec.get("stage1_output_target") or ""),
        "stage1_output_units": str(stage_export_spec.get("stage1_output_units") or ""),
        "stage1_input_keys": list(stage_export_spec.get("stage1_input_keys") or []),
        "stage2_input_key": str(stage_export_spec.get("stage2_input_key") or ""),
        "run_count": int(len({str(point.get('run_name') or '').strip() for point in points if str(point.get('run_name') or '').strip()})),
        "serial_count": int(len({str(point.get('serial') or '').strip() for point in points if str(point.get('serial') or '').strip()})),
    }


def td_perf_collect_export_rows_for_method(
    db_path: Path,
    *,
    run_specs: Sequence[Mapping[str, object]],
    performance_plot_method: object = None,
    legacy_row_mode: str = "equation",
    control_period_filter: object = None,
    run_type_filter: object = None,
    progress_cb: Callable[[str], None] | None = None,
) -> list[dict[str, object]]:
    normalized_method = td_perf_normalize_plot_method(performance_plot_method)
    if normalized_method == TD_PERF_PLOT_METHOD_CACHED_CONDITION_MEANS:
        return td_perf_collect_cached_condition_mean_export_rows(
            db_path,
            run_specs=run_specs,
            control_period_filter=control_period_filter,
            run_type_filter=run_type_filter,
            progress_cb=progress_cb,
        )
    if str(legacy_row_mode or "").strip().lower() == "condition":
        return td_perf_collect_condition_export_rows(
            db_path,
            run_specs=run_specs,
            control_period_filter=control_period_filter,
            run_type_filter=run_type_filter,
        )
    return td_perf_collect_equation_export_rows(
        db_path,
        run_specs=run_specs,
        control_period_filter=control_period_filter,
        run_type_filter=run_type_filter,
        progress_cb=progress_cb,
    )


